INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(1, 'LaTurbo Avedon', 'laturbo-avedon', 'http://codame.dreamhosters.com/uploaded_images/laturbo-avedon.jpg', '<p><a style=\"box-sizing: border-box; color: #00a4a7; text-decoration: none;\" href=\"http://www.turboavedon.com/\" target=\"_blank\">LaTURBO AVEDON</a>&nbsp;is an artist-render who lives and works on the Internet. An avatar whose identity is only connected to online expression, Avedon&rsquo;s work offers a sensibility that is geometric, architectural, and uniquely digital.</p>\r\n<p>Euphoric to play with&nbsp;LaTURBO at the&nbsp;<a href=\"/?p=5644\" target=\"_blank\">ART+TECH Virtual Reality</a>&nbsp;@ Mozilla! You&rsquo;ll get a chance to visit her studio via an Oculus Rift in the gallery on the night of the event!</p>\r\n<p>LaTurbo Avedon&rsquo;s previous appearance with CODAME:</p>\r\n<ul>\r\n<li><a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>&nbsp;San Francisco, CA</li>\r\n<li><a href=\"/defcon\" target=\"_blank\">DEFCON 21</a>&nbsp;with&nbsp;<a href=\"http://animalnewyork.com/2013/virtual-artist-will-sell-physical-artwork-for-bitcoin/\" target=\"_blank\">&ldquo;3d Idol exploring The Artist Is Not Present</a><a href=\"http://animalnewyork.com/2013/virtual-artist-will-sell-physical-artwork-for-bitcoin/\" target=\"_blank\">&rdquo;</a>&nbsp;, Las Vegas, NE</li>\r\n<li><a href=\"/post/portfolio/adopt-an-artist-showcase-at-autodesk-gallery-apr-16/\">Featured artist at Codame&rsquo;s Adopt an Artist Showcase &ndash; Autodesk Gallery San Francisco</a></li>\r\n<li><a href=\"/adopt\">Adopted</a>&nbsp;by Swissnex for&nbsp;<a href=\"http://swissnexsanfrancisco.org/Ourwork/events/SpatialStories\">Spatial Storytelling</a>: Augmented and Virtual Realities&nbsp;event in&nbsp;San Francisco</li>\r\n<li><a href=\"/post/portfolio/ephemeral-vessels/\">Ephemeral Vessels</a>!</li>\r\n</ul>', '@laturboavedon', 'http://turboavedon.com/', '', 'http://www.codame.com/post/portfolio/laturbo/', '0', '', NULL, NULL),
(2, 'VCO Vault', 'vco-vault', 'http://codame.dreamhosters.com/uploaded_images/vco-vault.gif', '<p>VCO Vault is a VJ + digital artist in San Francisco / CALIFORNIA. Experimental web technology, MIDI devices and video/photo manipulation are at the core of his work. VCO Vault created and performs with<a href=\"http://gifslap.com/\">.gifSlap</a>.</p>', '@vcovault', 'http://www.vcovault.com', 'don@gridwalk.net', '', '0', '1436748084', NULL, NULL),
(3, 'Spectrum Electric', 'spectrum-electric', 'http://codame.dreamhosters.com/uploaded_images/spectrum-electric.jpg', '<p>Spectrum Electric is Donald Hanson and Ian Powell. Based in San Francisco, this AV duo mixes synthesizers, web programming, experimental graphics and dance music to form a creative superforce. With seven years collaboration experience, the duo recently began releasing new music in 2012 on their own netlabel,&nbsp;<a href=\"http://gridwalk.net/\" target=\"_blank\">Gridwalk Labs</a>.</p>', '', 'http://thespectrumelectric.com', 'info@thespectrumelectric.com', 'http://www.codame.com/post/portfolio/the-spectrum-electric-codame-featured/', '0', '', NULL, NULL),
(4, 'd0n.xyz', 'd0n-xyz', 'http://codame.dreamhosters.com/uploaded_images/d0n-xyz.jpg', '<p>Don Hanson (aka d0n.xyz) is an internet artist, electronic musician, hardware hacker, graphic designer, visual jockey, gif maker, label boss and new media art researcher based in Oakland, California. In 2020 Hanson created the online exhibition space newart.city that has been used for major exhibitions of online art by Gray Area and SJSU CADRE.</p>', 'https://twitter.com/d0nxyz', 'https://d0n.xyz', 'don@gridwalk.net', '', '0', '1595202454', '', NULL),
(401, 'Shaghayegh Cyrous', 'shaghayegh-cyrous', 'http://codame.dreamhosters.com/uploaded_images/shaghayegh-cyrous.jpg', '<p dir=\"ltr\">Shaghayegh Cyrous is an Iranian-American artist and curator currently living and working in the bay area. Her work has dealt with cross-cultural communication and translation, addressing predicaments of estrangement and distance caused by political and cultural power dynamics. She incorporates interactive time-based strategies such as socially engaged art, participatory performances, and digital technologies such as live video chats and video installations to explore the compression of time and space resulting from digital technologies, and how digital media plays this critical role in the lives of exiles and immigrants and currently the global physical distancing due to the COVID-19 situation.&nbsp;</p>\r\n<p dir=\"ltr\">She received her BA in Visual Art from Science and Culture University in Tehran and her MFA in Social Practice from California College of the Arts. She is a recipient of Bangkit Arise international art residency and cultural exchange of Clarion Alley Mural Project and the Asian Art Museum, between Indonesia and San Francisco. She has exhibited and performed internationally at venues including Tehran Museum of Contemporary Art, Saba Museum in Tehran, Asian Art Museum, San Francisco Museum of Modern, Jane Addams Hull-House Museum in Chicago, British Museum in London, and Anchorage Museum in Alaska.</p>', 'https://twitter.com/shcyrous', 'https://www.shcyrous.com/', 'shaghayeghcyrous@gmail.com', '', '0', '1597096021', '', NULL),
(378, 'Kristin Henry', 'kristin-henry', 'http://codame.dreamhosters.com/uploaded_images/kristin-henry.jpg', '<p><span style=\"caret-color: #000000; font-family: Arial; font-size: 14.6667px; white-space: pre-wrap; text-size-adjust: auto;\">Kristin Henry is a San Francisco based Data Visualization consultant and Generative Artist, whose work takes inspiration from Science, Nature, and Mathematics.&nbsp;</span></p>', 'https://twitter.com/KristinHenry', 'http://kristinhenry.github.io/', 'galaxygoo@gmail.com', '', '0', '1567889672', NULL, NULL),
(202, 'Nullsleep', 'nullsleep', 'http://codame.dreamhosters.com/uploaded_images/nullsleep.jpg', '<p>Jeremiah Johnson is a computer musician and artist based in New York. He is known for his creative (ab)uses of obsolete consumer electronics and fluency in early Internet vernacular. His work embraces errors and disorder in the man-machine interface, and the importance of failure in breakiâ€âŒ¿âŒžâ€_ .-âŒžâŒ¢âŒ£âŒœng us from expected trajectories in order to provide pÇÉ¹ÇÊ‡×ŸÉ perspectives.</p>\r\n<p>He is the founder of the 8bitpeoples low-tech audio/visual collective and a contributing member of Computers Club Drawing Society, Phone Arts, and â–ˆâ–ˆâ–ˆâ–ˆâ–ˆ â–ˆâ–ˆâ–ˆâ–ˆâ–ˆâ–ˆâ–ˆ. Some of his installations, talks and performances have been presented at Eyebeam: Art+Technology Center (US 2012), Telfair Museum of Art (US 2012), Museum of the Moving Image (US 2011), Museo Regional de Guadalajara (Mexico 2011), Torino Regional Museum of Natural Science (Italy 2010), iMal: Centre for Digital Cultures &amp; Technologies (Belgium 2010), and LABoral: Centro de Arte y Creaci&oacute;n (Spain 2009).</p>', 'http://twitter.com/nullsleep', 'http://www.datacorruption.org/', 'nullsleep@gmail.com', '', '0', '1458024654', NULL, NULL),
(523, 'Layer ll', 'layer-ll', 'http://codame.dreamhosters.com/uploaded_images/layer-ll.jpeg', '<p><span style=\"font-family: Arial; font-size: 13px; white-space: pre-wrap;\">We all share one world. Why can&rsquo;t we share one dream? Introducing Solana Dreams. The next great story to be told on the blockchain starts with you. A creative and innovative Nft marketplace experience. The holders of NFT&rsquo;s enter into this dream and contribute to it. Let us create the next great story on the blockchain. The future is yours. Dreams to be held , to be told. Solana Dreams, what is your vision?</span></p>', 'https://twitter.com/Layer_ll', 'https://www.layerll.com/', 'layerlldesign@gmail.com', '', '0', '1650149757', 'https://codame.threadless.com/collections/layer-ll', 'https://instagram.com/Layer_ll'),
(559, 'Christian Nielsen', 'christian-nielsen', 'http://codame.dreamhosters.com/uploaded_images/christian-nielsen.jpg', '<p>CG / Visual Effects Supervisor with over 20 years of professional experience in commercials</p>', 'https://twitter.com/cbn01', 'https://cnielsennyc.com', '', '', '0', '1679717193', '', 'https://www.linkedin.com/in/cnielsennyc/'),
(564, 'Sasha Leitman', 'sasha-leitman', 'http://codame.dreamhosters.com/uploaded_images/sasha-leitman.jpg', '<p>Sasha Leitman is a composer, artist and inventor from California. She has been making musical instruments, new interfaces for musical expression and sound art installations for the last 15 years. Her work often features elements of field recordings, found objects,&nbsp;DIY&nbsp;craftsmanship, underwater sound and physical play. After spending over a decade teaching courses and managing the Max Lab - an Interface Prototyping Lab, at Stanford University&rsquo;s Center for Computer Research in Music and Acoustics (CCRMA), she decided it was time to try out the other side of the Pacific. She recently began a PhD program in Engineering and Computer Science at Victoria University of Wellington, New Zealand where she is exploring the design of computer music controllers inspired by auditory resonance and the nuanced control of acoustic instruments.</p>', '', 'http://www.sashaleitman.com/', 'sleitman@ccrma.stanford.edu', '', '0', '1683746949', NULL, ''),
(176, 'Anticlockwise Arts', 'anticlockwise-arts', 'http://codame.dreamhosters.com/uploaded_images/anticlockwise-arts.jpg', '<p>Anticlockwise Arts is a group of artists, engineers, scientists, and data explorers. They research emerging interface technologies in computer vision and tactile media for interactive installations, data visualization, and augmented storytelling. They create experiences for museums, professional spaces, festivals and other events on a permanent or rental basis. They are highly collaborative and often work alongside the design and development teams of other organizations and agencies. &nbsp; &nbsp; &nbsp;&nbsp;<iframe src=\"//www.youtube.com/embed/q3R-A6KTCSM\" width=\"425\" height=\"350\"></iframe></p>\r\n<p>&nbsp;</p>', '', 'http://www.anticlockwisearts.com/', '', '', '0', '1476660137', NULL, NULL),
(6, 'Nick Ciontea', 'nick-ciontea', 'http://codame.dreamhosters.com/uploaded_images/nick-ciontea.gif', '<p>Nick Ciontea, aka&nbsp;<a href=\"http://www.brownshoesonly.com/\">BrownShoesOnly</a>, is an analog video designer and manufacturer of synthesizer modules within the LZX Industries design specifications.</p>\r\n<p>&nbsp;</p>\r\n<p>Clients/collaborators include: Alessandro Cortini, Austin Psych Fest, Bassnectar, Big Black Delta, Bitchin Bajas, CAVE, Chandeliers, Cold Cave, Com Truise, DJMREX, Excepter, Good Willsmith, M83, Michael Brown Design, Moss Folk, Neon Indian, North Coast Music Festival, Oscillator Bug, Pretty Lights, Prince Rama, Psychic Ills, RadioEditAV, Richard Devine, Robert A.A. Lowe, Sarah Landau, Soft Speaker, Songs for Gods, Spring Awakening Music Festival, Surachai, The Big Ship, The Black Angels, The Earth is a Man, The Hood Internet, The National, Trash Audio, Verma.</p>\r\n<p>Catch wall hanging prints by the artist at&nbsp;<a href=\"/post/portfolio/art-by-code/\">Art by Code</a></p>', '', 'http://www.brownshoesonly.com/', 'nickciontea@gmail.com', 'http://www.codame.com/post/portfolio/brownshoesonly/', '0', '1436337588', NULL, NULL),
(7, 'Tim Cowley', 'tim-cowley', 'http://codame.dreamhosters.com/uploaded_images/tim-cowley.jpg', '<p>Tim Cowley makes synesthetic, algorithmic art. His current work focuses on touch, vision, and emotion, using love poems by Neruda stamped out in Braille, by hand, on pages pulled from haute-couture fashion magazines. The intersections and near misses of these senses that reflect the emotional landscape of love.</p>\r\n<p>See, touch, and feel this synaesthetic intersection at&nbsp;<a href=\"/?p=6011\">Art by Code</a>.</p>\r\n<p><img src=\"/uploaded_images/1601346_10153106247508694_4637841365710160346_n.jpg\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/10931325_10153106236268694_7966393521693754379_n.jpg\" alt=\"\" /><img src=\"/uploaded_images/10862561_10153065109278694_6826693003260958385_o-1.jpg\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/10896343_10153053223378694_4788104730439500670_o.jpg\" alt=\"\" /></p>', '', '', '', 'http://www.codame.com/post/portfolio/tim-cowley/', '0', '1436337574', NULL, NULL),
(5, 'Joel Cretan', 'joel-cretan', 'http://codame.dreamhosters.com/uploaded_images/joel-cretan.png', '<p>Joel Cretan is a digital artist and Bay Area native now living in San Francisco. He has been coaxing computers to display strange things since discovering Macpaint on his grandmother&rsquo;s computer when he was 4. Computers are deterministic, but their behavior is so complex that it is impossible to anticipate how they will handle all the crazy inputs you can throw at them; this complexity is one reason he enjoys exploring the unexpected results of combining simple and sophisticated algorithms for creating patterns and shapes. Some of his more recent creations reflect the cyberpunk dystopia that the future has turned out to be. He prefers to share most of his work without restriction on the greatest and most troubling communication medium ever imagined, so his more polished works can be found at&nbsp;<a href=\"http://www.laserscorpion.com/\" target=\"_blank\">www.laserscorpion.com</a>, and his latest experiments are at&nbsp;<a href=\"http://laserscorpion.tumblr.com/\" target=\"_blank\">laserscorpion.tumblr.com</a></p>\r\n<p>Come check out Joel&rsquo;s work at our&nbsp;<a href=\"http://www.codame.com/?p=6011\">CODAME Art&nbsp;by Code</a>&nbsp;Gallery in January 2015</p>', '', 'macpaint.org', 'joel@macpaint.org', '', '0', '1436748095', NULL, NULL),
(12, 'Matthew Cella', 'matthew-cella', 'http://codame.dreamhosters.com/uploaded_images/matthew-cella.jpg', '<p dir=\"ltr\">CODAME Featured Artist</p>\r\n<p dir=\"ltr\"><a href=\"/wp-content/uploads/2014/04/cella4.jpg\"><img class=\"alignnone size-medium wp-image-3881\" src=\"/wp-content/uploads/2014/04/cella4-300x200.jpg\" alt=\"cella4\" width=\"300\" height=\"200\" /></a></p>\r\n<p dir=\"ltr\"><a href=\"http://matthewcella.com/words.html\">Matthew Cella</a><span style=\"line-height: 1.5em;\">&nbsp;fabricates multi-media works that are the product of digitally collaged .;::&rsquo;til;ps and //??&gt;s. &nbsp;Influenced by 8-bit aesthetics, Cella&rsquo;s work is characterized by patterned pixels, flat planes of color, playful vibrations.</span></p>\r\n<p dir=\"ltr\">Cella has shown his work in <a href=\"http://www.artslant.com/sf/events/show/282187-art-by-code\">Art by code</a> at the Roll up Gallery at Public Works, <a href=\"http://www.artslant.com/sf/events/show/283619-codame-fashion-art-technology\">CODAME Fashion, Art, &amp; Technology</a> at Public Works, and <a href=\"http://www.artslant.com/sf/events/show/207320-knowhow-a-live-and-silent-auction-to-benefit-royal-nonesuch-gallery\">KNOW/HOW a live and silent auction to benefit Royal NoneSuch Gallery</a>.</p>\r\n<p dir=\"ltr\">Born in 1981, he received his MFA from the San Francisco Art Institute, and currently lives and works in San Francisco. Recent projects include Wasteland at SOAP Gallery in San Francisco, Bay Area Currents 2011 at the Oakland Art Gallery, and CUT/COPY at the Evergreen Valley College Fine Art Gallery in San Jose.</p>\r\n<div id=\"gallery-2\" class=\"gallery galleryid-3877 gallery-columns-3 gallery-size-thumbnail\">\r\n<dl class=\"gallery-item\">\r\n<dt class=\"gallery-icon landscape\"><a href=\"/post/portfolio/matthew-cella/cella3/\"><img class=\"attachment-thumbnail\" src=\"/wp-content/uploads/2014/04/cella3-150x100.jpg\" alt=\"cella3\" width=\"150\" height=\"100\" /></a>&nbsp;<a href=\"/post/portfolio/matthew-cella/cella1/\"><img class=\"attachment-thumbnail\" src=\"/wp-content/uploads/2014/04/cella1-112x150.png\" alt=\"cella1\" width=\"112\" height=\"150\" /></a>&nbsp;<a href=\"/post/portfolio/matthew-cella/cella2/\"><img class=\"attachment-thumbnail\" src=\"/wp-content/uploads/2014/04/cella2-150x99.jpg\" alt=\"cella2\" width=\"150\" height=\"99\" /></a></dt>\r\n</dl>\r\n</div>\r\n<p dir=\"ltr\"><strong>Want to see more? &nbsp;<a href=\"/artists\">Browse CODAME&rsquo;s Other Featured Artists</a></strong></p>', '', 'http://matthewcella.com/', '', 'http://www.codame.com/post/portfolio/matthew-cella/', '0', '1436337552', NULL, NULL),
(13, 'Jordan Gray', 'jordan-gray', 'http://codame.dreamhosters.com/uploaded_images/jordan-gray.png', '<p style=\"text-align: center;\"><em>CODAME Co-Founder + Managing Director</em></p>\r\n<p style=\"text-align: center;\">AKA @staRpauSe</p>\r\n<p style=\"text-align: left;\">Jordan pioneered digital media with online distribution of original music and scanlated manga in the 1990s. Currently, Jordan leads technology, ux, and strategy projects for Fortune 500 companies. His clients include Walmart, AT&amp;T, Wells Fargo, Intel, and Google.</p>\r\n<p>In 2010, Jordan co-founded CODAME to spark visionaries and celebrate the value of playful creativity. CODAME cultivates space for innovation and collaboration with inspiring experiences, including workshops, sales, installations, performances, and the annual ART+TECH Festival.</p>\r\n<p>Jordan\'s releases his music, photography, and multimedia art under the Creative Commons to encourage remix and reuse. He has a daily moving meditation practice and is certified to instruct Wild Goose Qigong by Grandmaster Hui Liu of Wen Wu School in El Cerrito.</p>\r\n<p dir=\"ltr\">If in San Francisco, we encourage you to connect with Jordan and catch a glimpse of this spirit with Jordan\'s free <a href=\"https://goosegong.substack.com/about\">Qigong sessions at Sue Bierman Park</a>, every Saturday at 10:00 am.</p>\r\n<p><img src=\"/uploaded_images/wechat-qr-k9d-large-px-60kb.jpg\" alt=\"\" /></p>\r\n<p><em>Jordan\'s work has featured in New York Times, Vice, Engadget, and more. Some day he\'ll get around to collecting all those artifacts but until then he\'ll continue his third person ramblings to an invisible audience.&nbsp;</em></p>\r\n<p>&nbsp;</p>', 'http://twitter.com/#!/starpause', 'http://starpause.com/', 'jordan@codame.com', '', '0', '1697295437', 'https://codame.threadless.com/collections/jordan-gray', ''),
(434, 'Geoffrey Golden', 'geoffrey-golden', 'http://codame.dreamhosters.com/uploaded_images/geoffrey-golden.jpg', '<p>Geoffrey Golden is a writer and narrative designer living in Los Angeles, CA. In the gaming space, he&rsquo;s worked with Capcom, Ubisoft, Square Enix, and indie studios around the world. Geoffrey loves developing interactive fiction for unexpected mediums, like with <a href=\"http://adventuresnack.com/\">Adventure Snack</a>, his &ldquo;choose your path&rdquo; email RPG, and Facts About the Robot Uprising, the first new game for the Tiger 2-XL in 25 years, which exhibited at IndieCade Anywhere and Everywhere. He&rsquo;s developed projects in &ldquo;multi&rdquo; medias: tabletop games, comics, podcasts, books, and audio fiction.</p>', 'https://twitter.com/geoffreygolden', 'https://www.geoffreygolden.com/', 'geoffrey.golden@gmail.com ', '', '0', '1604953723', '', NULL),
(163, 'Scott Summit ', 'scott-summit', 'http://codame.dreamhosters.com/uploaded_images/scott-summit.png', '<p>&nbsp;Exploring the intersection between the body, human needs, and technology. He founded Bespoke to experiment with impact of design on un-designed products. Opportunities afforded by new technology tools allow the creation of customized products, based on business models previously considered unimaginable. 3D printing, owing to the versatility inherent in the process, allows us to rethink medicine, innovation, space travel, business models, and its potential for improvements in quality of life on a grander scale.</p>\r\n<p>Scott is&nbsp;most excited by the products that result when designer has relinquished agency in the process and product to a variable beyond their immediate control.&nbsp; Whether that variability comes from the integration of an individual human form, sound, algorithms, scripts, the \'crowd\', data, etc - the designer must willingly accept that an outside force will be co-designing their product, often leading to unanticipated and ungovernable results.</p>\r\n<p><img src=\"/uploaded_images/scott-summit1.png\" alt=\"\" />&nbsp;</p>\r\n<p><strong>Current Board of Advisers positions :</strong></p>\r\n<ul>\r\n<li>Made In Space</li>\r\n<li>Keyssa</li>\r\n<li>The Luke Hand</li>\r\n<li>UNYQ</li>\r\n<li>Chicago Museum of Science and Industry (Advisory Board)</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p><strong>Academic Positions :</strong></p>\r\n<ul>\r\n<li>Carnegie Mellon University (2006-7)&nbsp; Visiting Faculty</li>\r\n<li>Stanford University (2009) Visiting Faculty</li>\r\n<li>Singularity University (2010 - present) Faculty</li>\r\n</ul>', '', 'http://www.summitid.com/', 'scott@summitid.com', '', '0', '1602269056', '', NULL),
(14, 'ANI', 'ani', 'http://codame.dreamhosters.com/uploaded_images/ani.jpg', '<p>ANI&nbsp;(Amy Lee), is a Bay Area-based electronic musician and web developer who specializes in&nbsp;building digital&nbsp;instruments to compose&nbsp;improvisational sets&nbsp;using&nbsp;iPads, iPhones, and synthesizers. &nbsp; Every set she plays is a unique&nbsp;blend of beats, chord progressions, and wild synth solos. &nbsp;One thing she&rsquo;s not: a DJ!</p>\r\n<p>More about her sound and how to adopt her: <a href=\"/projects/ani-live-set\">ANI: Live Set</a></p>\r\n<p>ANI started out as a web developer and visual designer, but in the ensuing years, what began (and largely remains) as a lovingly maintained hobby of building iPad instruments became a chance to tour with looping festivals with performers from around the world. &nbsp;She has performed&nbsp;at:&nbsp;<a style=\"box-sizing: border-box; color: #1982d1; text-decoration: none; font-weight: inherit; font-style: inherit;\" href=\"http://y2kloopfest.com/\">Y2K Loopfest</a>,&nbsp;<a style=\"box-sizing: border-box; color: #1982d1; text-decoration: none; font-weight: inherit; font-style: inherit;\" href=\"http://nwloopfest.com/\">NW Loop Fest</a>,&nbsp;and<a style=\"box-sizing: border-box; color: #1982d1; text-decoration: none; font-weight: inherit; font-style: inherit;\" href=\"/\">CODAME</a>. &nbsp;She also serves as a coordinator for&nbsp;the&nbsp;<a style=\"box-sizing: border-box; color: #1982d1; text-decoration: none; font-weight: inherit; font-style: inherit;\" href=\"http://www.sf-emm.org/\">San Francisco Electronic Music Meetup</a>.</p>\r\n<p>She has been an&nbsp;Adopted Artist in Residence at Geekdom &ndash; the first supporters of<a style=\"box-sizing: border-box; color: #00a4a7; text-decoration: none;\" href=\"/post/portfolio/ani/www.codame.com/adopt/%E2%80%8E\">Adopt An Artist &ndash;</a>&nbsp;developing&nbsp;iOS app for iBeacon that she hopes will help extend the CODAME experience directly to audiences by giving them access to a network of digital content about the artwork. &nbsp;In addition, she is also working on an iPad instrument called&nbsp;<a style=\"box-sizing: border-box; color: #00a4a7; text-decoration: none;\" href=\"https://www.google.com/url?sa=t&amp;rct=j&amp;q=&amp;esrc=s&amp;source=web&amp;cd=2&amp;cad=rja&amp;uact=8&amp;ved=0CDMQFjAB&amp;url=https%3A%2F%2Fitunes.apple.com%2Fus%2Fapp%2Fsbassdrum-drum-groove-machine%2Fid793652949%3Fmt%3D8&amp;ei=rkBdU_G6KcSr2wX2nYFA&amp;usg=AFQjCNESpK1iSL1TWaGgHZxPEloGAMa2nQ&amp;sig2=zY7PGwib9pTq6SDExeJ0tg&amp;bvm=bv.65397613,d.b2I\">sBASSdrum</a>&nbsp;(pronounced &ldquo;space drum&rdquo;) which launched in February.</p>\r\n<p>&ldquo;<em style=\"box-sizing: border-box;\">I&rsquo;m part of CODAME because I feel it is one of the best underground art organizations that has a super strong focus on the use of cutting edge technologies like 3D printing, motion-reactive visualizations, iBeacons, and mobile computing. We get to truly unite artists with the best in technology, and expose new tech-based artists to the world.</em>&nbsp;&rdquo; &ndash; ANI</p>\r\n<p>Stay tuned for more of her&nbsp;projects being featured at Geekdom this year!</p>\r\n<p>&nbsp;</p>\r\n<p><iframe src=\"//www.youtube.com/embed/FA5wHWLpJWQ\" width=\"885\" height=\"498\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><iframe src=\"//www.youtube.com/embed/d2l3iXA6rP4\" width=\"885\" height=\"498\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><iframe src=\"//www.youtube.com/embed/0T-0VS2j11c\" width=\"885\" height=\"498\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', 'http://www.twitter.com/animusicsf', 'http://www.ani-web.com/', 'amy@codame.com', '', '0', '1448482900', NULL, NULL),
(15, 'Rich DDT', 'rich-ddt', 'http://codame.dreamhosters.com/uploaded_images/rich-ddt.jpg', '<p>Rich DDT is an interactive installation designer, live electronic music producer/performer, and event organizer. His custom work for museums, public spaces, and art events features emerging technologies to create an awe-inspiring, educational and playful environment for human connection.<br /><br />He has been designing interactions since 2008, curating experiences that encourage collaborative group creativity in digitally augmented spaces. He has mastered sensors and new media software to spark effortless engagement with intuitive &amp; highly responsive interfaces. Rich DDT co-founded the interactive technology design studio Anticlockwise Arts, the live electronic music and arts agency LoveTech, and has created installations for The Exploratorium, The Tech Museum of Innovation, Yerba Buena Center for the Arts and the CA Academy of Sciences.<br /><br />On stage, Rich Detonates Dance Tracks in live music performance, wielding his custom ControlliTAR to make contagiously funky dance music, live looped and electrifying, infused with exotic and nostalgic beats and bass blasted world flavors. In the music studio, his crafts full spectrum sound designs from ambient, dub, techno and orchestral to esoteric sound effects and foley.<br /><br />He has performed at several large events &amp; festivals including Maker Faire, SF MusicTech Summit, Lightning In A Bottle, Symbiosis, Sea of Dreams, Lucidity and Priceless, and been featured in publications such as CNET, Keyboard Magazine,&nbsp;<a href=\"http://controllerism.com/\">Controllerism.com</a>&nbsp;and the SF Bay Guardian &amp; Chronicle.<br /><br />At the core of his multifaceted journey lies a tenacious passion for bringing community, ingenuity, and wondrous new dimensions of expression to the curious among us.</p>\r\n<p>&nbsp;</p>\r\n<p><iframe src=\"https://w.soundcloud.com/player/?url=https%3A//api.soundcloud.com/tracks/21582229&amp;color=ff5500\" width=\"100%\" height=\"166\" frameborder=\"no\" scrolling=\"no\"></iframe></p>', 'https://twitter.com/richddt/', 'http://richddt.com/', 'rich.trapani@gmail.com', '', '0', '1492663564', NULL, NULL),
(241, 'Matt DesLauriers', 'matt-deslauriers', 'http://codame.dreamhosters.com/uploaded_images/matt-deslauriers.jpg', '<p>Matt DesLauriers is a self-taught graphics programmer and media artist with a background in Film &amp; Media at Queen&rsquo;s University. Working at Jam3 in Toronto, he combines his love of art, programming, and technology to build interactive content for the web. Through his Jam3 and freelance experience, Matt has built dozens of large campaigns including VR experiences, mobile applications, 3D games, interactive documentaries, data visualizations, and physical installations. Matt is active in the open source JavaScript community, maintaining hundreds of small modules and libraries to help with creative coding, media arts, and WebGL. He has a passion for generative art, data visualization and motion graphics. When he is not tinkering with code, you might find him in a local espresso shop or rock climbing gym.</p>', 'https://twitter.com/mattdesl', 'http://mattdesl.com/', 'dave.des@gmail.com', '', '0', '1490372273', NULL, NULL),
(16, 'Moldover', 'moldover', 'http://codame.dreamhosters.com/uploaded_images/moldover.jpg', '<p><span style=\"caret-color: #000000; font-family: Helvetica; font-size: 12px; text-size-adjust: auto;\">&rdquo;A musician at heart, inventor born of curiosity, and innovator by necessity, I believe the world&nbsp;calls him the &lsquo;Godfather of Controllerism&rsquo; for damned good reasons.&rdquo;&nbsp;&ndash; John Tackett, Crowd Wire</span><br class=\"\" style=\"caret-color: #000000; font-family: Helvetica; font-size: 12px; text-size-adjust: auto;\" /><br class=\"\" style=\"caret-color: #000000; font-family: Helvetica; font-size: 12px; text-size-adjust: auto;\" /><span style=\"caret-color: #000000; font-family: Helvetica; font-size: 12px; text-size-adjust: auto;\">History only notes a handful of artists who successfully pushed the limits &ndash; both with their music&nbsp;and the design of their musical instruments.&nbsp;What Bach was to the keyboard and Hendrix was to the&nbsp;guitar, Moldover is to the controller.&nbsp;Disillusioned with &ldquo;press play DJs&rdquo;, Moldover fans eagerly&nbsp;welcome electronic music&rsquo;s return to virtuosity, improvisation, and emotional authenticity. Dig&nbsp;deeper into Moldover&rsquo;s world and you&rsquo;ll uncover a subversive cultural icon who is jolting new life&nbsp;into physical media with &ldquo;Playable Packaging&rdquo;, sparking beautiful collaborations with his custom&nbsp;&ldquo;Jamboxes&rdquo;, and drawing wave after wave of followers with an open-source approach to sharing his&nbsp;methods and madness</span></p>\r\n<p><iframe src=\"https://www.youtube.com/embed/BKbvpRtY04A?controls=0&amp;start=24\" width=\"793\" height=\"446\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', 'https://twitter.com/moldover', 'http://moldover.com/', 'moldover@moldover.com', '', '0', '1568087953', NULL, NULL),
(375, 'Didem Coskunseven', 'didem-coskunseven', 'http://codame.dreamhosters.com/uploaded_images/didem-coskunseven.jpg', '<p>Didem Coskunseven is a composer, sound artist and computer musician based in Berkeley, CA. Coskunseven&rsquo;s works vary between acoustic compositions for ensembles, electronic music, installations for gallery spaces and productions for stage focusing on creating multi-sensorial experience. She performs as a computer musician and improvisor collaborating with dancers, choreographers and video designers.</p>\r\n<p>Coskunseven studied visual arts, philosophy and music composition in Istanbul. Since graduating from Center for Advanced Studies in Music, ITU, she participated in several contemporary music festivals and workshops in Europe, Turkey and the United States. She is currently continuing her Ph.D studies at the department of music at UC Berkeley.</p>\r\n<p>&nbsp;</p>', '', '', '', '', '0', '1567489210', NULL, NULL),
(162, 'Paul Ackerman', 'paul-ackerman', 'http://codame.dreamhosters.com/uploaded_images/paul-ackerman.jpg', '<p><iframe style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"https://player.vimeo.com/video/53468482\" width=\"500\" height=\"281\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<h2>Don\'t miss the Body Mapping perfomance&nbsp;from Paul Ackerman at the <a href=\"/events/art-tech-festival-2015\">2015 ART+TECH Festival</a>! &nbsp;</h2>\r\n<p>Paul Ackerman, a degreed media artist with professional backgrounds in Graphical User Interface Design, Graphic Design, 2/3D Illustration, Video pre/post production, Dance Theater, multimedia, Drawing, Motion Graphics, Sculpture, Painting and Photography. Paul holds a BFA in Drawing and Photography from California College of Arts(CCA) in Oakland, CA.</p>\r\n<p>Three years after graduation, his extensive experience as a cross-over media artist hand manipulated media (etched/burned photo/graphic arts film) formatted for slide projectors illuminating movement. .</p>\r\n<p>At first, content was created by perching a hot needle into plastic 2&times;2&Prime; slide blanks to create an animated series of concentric circles. Today a major part of 4,000 original etched film art has been scanned and incorporated with SD/HD digital video motion graphics.</p>\r\n<p>Illustrations via silver point drawings of crumpled paper were some of the first cubist experiments.&nbsp; In international competitions, received high praise and always placed in ranking. Several were lost by UPS so another media was explored to be smaller and portable, &ldquo;film&rdquo;. Experiments started with hot needles, dental tools and retouching knifes in a sumi-e brush technique of controlling the flow when drawing on film. Old school techniques of hand-manipulated &amp; painted film media were scripted for multiple projectors staged in collaboration with professional choreographers for &ldquo;body projections&rdquo; onto ballet, gogo, pole, burlesque dancers, acrobats and aerialists. Content of pattern/texture motifs range from mystical, astrological, tribal, computer forms, numbers, text, crop circles designs to Qabalah and sacred geometry.</p>\r\n<p>In the San Francisco Bay area, his work was presented at the Palace of Fine Arts, Project Artaud, Vorpal Gallery, Oakland Civic Auditorium, Stanford University, College of Marin CA, San Francisco Dance Theater, The Japan Center, and The Intersection in North Beach. In Seattle his work has been presented at Seattle Center&rsquo;s ArtsEdge97, Fremont Arts Council, Best of Choreography Etc., On The Boards, Broadway Performance Hall, Spectrum Dance Theater, Arts in Residence Bellevue, light shows for various bands plus various corporate theaters.</p>\r\n<p><img src=\"/uploaded_images/BodyM-Z-Vector.Aerial-02b_.jpg\" alt=\"\" /></p>\r\n<p>&nbsp;</p>', '', 'http://www.dansebleue.com/', 'dansebleue@gmail.com', '', '0', '1442954623', NULL, NULL),
(17, 'Anouk Wipprecht', 'anouk-wipprecht', 'http://codame.dreamhosters.com/uploaded_images/anouk-wipprecht.jpg', '<p dir=\"ltr\">What does fashion lack? \"Microcontrollers\" according to Dutch based Hi-Tech Fashion Designer and Innovator Anouk Wipprecht. As she is working in the emerging field of \"FashionTech\"; a rare combination of fashion design combined with engineering, science and interaction/user experience design. Producing an impressive body of tech-enhanced designs bringing together fashion and technology in an unusual way: she creates technological couture; with systems around the body that tend towards artificial intelligence; projected as \'host\' systems on the human body, her designs move, breath, and react to the environment around them.&nbsp;<br /><br />Strangely ahead of her time; Anouk combines the latest in science and technology to make fashion an experience that transcends mere appearances. Sensors embedded in the design monitor the space around the wearer, and body-sensors check in on stress levels as comfort or anxiety. Her Intel-Edison based \'Spider Dress\' is an perfect example of this aesthetic, where sensors and moveable arms on the dress help to create an more defined boundary of personal space while employing a fierce style. \"This robotic dress attacks when you come to close\" she mentions. Facilitating and augmenting the interactions we have with ourselves and our surroundings in an bespoke manner. Other than handheld devices, Wipprecht researches how we can interface in new ways with the world around us through our wardrobe.&nbsp;<br /><br />Partnering up with companies such as American multinational technology company INTEL, software producer Autodesk, internet giants Google and Microsoft, car brand AUDI, crystal creator Swarovski,&nbsp;and leading 3D printing innovators amongst others - she researches and develops how our future wardrobe would look as we continue to embed technology into what we wear.&nbsp;&nbsp;<br /><br />She works/travels between San Francisco, Los Angeles, Miami and Amsterdam.&nbsp;</p>\r\n<p><iframe title=\"HARDWARE COUTURE\" src=\"https://player.vimeo.com/video/126998973\" width=\"1120\" height=\"630\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><iframe src=\"http://www.youtube.com/embed/-OU_-DtMj6A\" width=\"917\" height=\"516\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><iframe src=\"http://www.youtube.com/embed/G-0lTP90hVc\" width=\"919\" height=\"517\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe><br /><iframe src=\"http://www.youtube.com/embed/Aybs6rmcjk8?list=UU-udDezXQz8BlkaBRR9Iypw\" width=\"919\" height=\"517\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<div id=\"gallery-2\">&nbsp;</div>', 'https://twitter.com/AnoukWipprecht', 'http://www.anoukwipprecht.nl/', 'satin_candy@hotmail.com', '', '0', '1643926613', '', 'https://www.instagram.com/AnoukWipprecht/'),
(18, 'Reza Ali', 'reza-ali', 'http://codame.dreamhosters.com/uploaded_images/reza-ali.jpg', '<header>\r\n<div>&ldquo;Explore the realm of science and mathematics to make complex phenomena understandable and intuitive&rdquo;</div>\r\n</header>\r\n<div>\r\n<article id=\"post-3853\">\r\n<p dir=\"ltr\">Reza Ali&nbsp;is a computational designer and creative engineer who is interested in art, science, and entrepreneurship. &nbsp;He uses code to express himself visually, and creates tools and libraries to help others create by sharing his methodology.</p>\r\n<p>Ali is the author of&nbsp;ofXUI, one of the most popular&nbsp;addons&nbsp;for&nbsp;openframeworks&nbsp;(an arts-engineering toolkit), POSSIBLE, an audio-visual VJ app for&nbsp;Deadmau5, and&nbsp;iCubist, an ipad app that augmented the Santa Barbara Museum of Art&rsquo;s Analytic Cubist Exhibit. Reza has given presentations at Gigaom, Nokia Design, Google Data Arts Center, NIME (2010), and NIME (2011), GAFFTA, (2013), USF, and Stanford (2014). His work has been&nbsp;featured in two books,&nbsp;Visual Complexity&nbsp;by Manuel Lima and&nbsp;Generative Ar<a href=\"http://www.amazon.com/Generative-Art-Matt-Pearson/dp/1935182625\">t</a>&nbsp;by Matt Pearson and numerous times online at&nbsp;www.creativeapplications.net.</p>\r\n<p dir=\"ltr\">In 2010 Reza earned a Masters of Science in Multimedia Engineering (with a focus in Visual and Spatial Arts) from Media Arts and Technology at the University of California, Santa Barbara. &nbsp;He hopes to change the world by making a difference in how people use technology, design products and experience new media art and entertainment.</p>\r\n<iframe src=\"https://player.vimeo.com/video/42583130\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe>\r\n<p>&nbsp;</p>\r\n<iframe src=\"https://player.vimeo.com/video/30211524\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe>\r\n<p>&nbsp;</p>\r\n</article>\r\n</div>', 'https://twitter.com/rezaali', 'http://www.syedrezaali.com/', '', '', '0', '1600737263', '', NULL),
(430, 'Abhinay Khoparzi', 'abhinay-khoparzi', 'http://codame.dreamhosters.com/uploaded_images/abhinay-khoparzi.jpeg', '<p><span id=\"docs-internal-guid-4cfbca7b-7fff-98c0-b7da-3ebe66c8e53f\">Abhinay Khoparzi is a multidisciplinary creative technologist who maintains a practice across film, video, music and web technologies. He has had a long relationship with the experimental electronic music scene in Mumbai, India with performances at venues and events like The Indian Electronica Festival, (Blue Frog), 6 Foot Oscillator in a 4 foot Room (Zenzi Mills). Since 2018 Khoparzi has been organising and curating computational arts events called &ldquo;Algoraves&rdquo; all India. He has performed live coded music and visuals with TidalCycles and Hydra at Fat Finger Mayhem (Max Mueller Bhavan, Mumbai, 2018 and 2019), Algorave Sheffield (UK, 2018), International Conference of Live Coding (Madrid, 2019), and Algorave Bangalore(2019). He now organises/conducts live coding workshops in collaboration with various maker spaces and artists collectives across India and has been pushing the Algorave scene in the country.</span></p>\r\n<h1 id=\"bbbb\">Interview with Abhinay Khoparzi</h1>\r\n<p id=\"f0ca\" data-selectable-paragraph=\"\"><strong>Tell us about your background</strong></p>\r\n<p id=\"1d12\" data-selectable-paragraph=\"\">I come from a small town in the north India where the only way to look and be successful is become a doctor/lawyer/engineer or teach at a &ldquo;coaching centre&rdquo; to become a doctor/lawyer/engineer. Luckily I had access to technology early on and got the time and space to teach myself to code with web stacks back in the early late nineties and early noughties. I was also lucky to have parents willing to stand a teenager bashing a drumset in his bedroom while he lived with them. Being in a &ldquo;small town&rdquo; (at least what it means in India) also meant that I had to maintain and fix all of the tech I could get my hands on for any &ldquo;creative&rdquo; applications. An amalgamation of spending all of this time building/fixing things ended up helping me narrowly avoid going to medical school and move to Bombay with double diplomas in sound engineering and CGI and visual effects (no one taught these things at Universities in India back in those days).</p>\r\n<p id=\"510c\" data-selectable-paragraph=\"\">After switching through jobs in sales, sound engineering, writing for a technology magazine while helping run an independent artist collective, netlabel and building a IDM/breakcore scene in the city known for churning out vast quantities of Bollywood Music, we quickly realised we had to start working for ourselves. The artist collective went defunct early on but the talent and connections acquired resulted in a micro budget, crowd funded, indie feature film done by a crew of two (friends helped out on weekends) filmed on a borrowed ENG camera and a lot of DIY hardware, software and workflows. The film got rejected from all local festivals but premiered in Chicago and was traveled and celebrated all across the world. Since the mainstream scene didn&rsquo;t get it at the time, I was able to make use of my art+tech aesthetics and tooling for freelancing in the advertising market. By the time the film reached back home and got into theaters I got the opportunity to pack my bags and run off to Birmingham, UK for a Masters in TV Production at BCU. The university and my supportive Course Director helped me redesign the course for freelance work and get me to work on brand films for clients like Hasselblad and Aston Martin Racing.</p>\r\n<p id=\"0909\" data-selectable-paragraph=\"\">Due to my love, drum and bass, footwork and the harder sounds of the electronic music scene and art + technology I also bumped into the still nascent Algorave scene that was starting to take shape in the country. After a brief entrepreneurial stint that was cut short by the economic uncertainties of the Brexit vote, I moved back to my hometown in India. A random connection with an old friend from the scene in Bombay we started Algorave India in 2018. An Indian chapter of the global livecode movement that had deep aesthetic and ideological connections with our &ldquo;underground scene&rdquo; from years ago. I now organize workshops and livecode performance events all over the country and work with creatives and technologists to make experiences for brands, arts organizations and institutions.</p>\r\n<p id=\"34b1\" data-selectable-paragraph=\"\"><strong>What is your definition of art + tech?</strong></p>\r\n<p id=\"333d\" data-selectable-paragraph=\"\">I can&rsquo;t think of making anything without tools, and tools are tech. Whether those tools are digital or physical that is immaterial. Musicians need Instruments, painters, illustrators need brushes/pens, kids need toys to spin up stories from their heads. Somebody has to make those tools, I like making the works as well as the tools that help you make those works. So in the end art needs tech and then making the tech itself becomes the art.</p>\r\n<p id=\"bd50\" data-selectable-paragraph=\"\"><strong>Who, or what, inspires you in your art and in your life?</strong></p>\r\n<p id=\"27ea\" data-selectable-paragraph=\"\">I&rsquo;ve been lucky enough to have been exposed to a lot of art, in sound, visuals, as well in writing so some of the inspiration does come from there. A lot of the time though the study of tools themselves spark ideas for making things.</p>\r\n<p id=\"6402\" data-selectable-paragraph=\"\"><strong>What is your process or techniques for creating your work?</strong></p>\r\n<p id=\"a76b\" data-selectable-paragraph=\"\">You might share some new and emerging technologies that you are excited about working with or that have been a game changer for you.I usually start with throwing ideas around with friends, so even though I like spending a lot of time in a cave, I do find the best ideas while talking to people and teaching them things (I might just be stealing all of their ideas :) ).</p>\r\n<p id=\"db7a\" data-selectable-paragraph=\"\"><strong>What&rsquo;s next for you as an artist?</strong></p>\r\n<p id=\"b664\" data-selectable-paragraph=\"\">I&rsquo;m in the middle of production for an interactive piece that will live with the first ever virtual edition of Serendipity Arts Festival for the next year. Since I can&rsquo;t keep my hands off making tools for people, I am also helping them build the platform to host their festival online from this year onwards.</p>\r\n<p id=\"7e6e\" data-selectable-paragraph=\"\"><strong>What is your dream project?</strong></p>\r\n<p id=\"3bb1\" data-selectable-paragraph=\"\">I&rsquo;ve been meaning to put together a kinetic sculpture driven by data for a whole bunch of years (no one ask me what data yet, I guess that&rsquo;s why I&rsquo;m not ready). I am enamored by the detail in the works of Shohei Fujimoto, the scale of sound + laser works of Robert Henke and sound design and composition of Barcelona based artist Rob Clouth. I guess if someone lets me design an experience that lets me combine the attributes of these I would be done.</p>\r\n<p id=\"05c1\" data-selectable-paragraph=\"\"><strong>What&rsquo;s the greater purpose behind your artwork?</strong></p>\r\n<p id=\"a1db\" data-selectable-paragraph=\"\">I&rsquo;ve never really thought about it much, but most of the time I&rsquo;m building things to help people. Possibly if I had studied my math in school and had gone off to do a proper engineering or industrial design degree I would have made more things for real world use. For now I&rsquo;m content with making things that help me and my fellow artists make other things.</p>\r\n<p id=\"32e8\" data-selectable-paragraph=\"\"><strong>What&rsquo;s the best piece of advice you&rsquo;ve been given?</strong></p>\r\n<p id=\"099a\" data-selectable-paragraph=\"\">There was an interview of Will Wright where he said he likes planting seeds and observing how they grow out. I don&rsquo;t know if its laziness or just fascination with seeing things grow, but I really love that.</p>\r\n<p id=\"8ef7\" data-selectable-paragraph=\"\">And also, this colleague of mine asked me to shut up and listen.</p>', 'http://twitter.com/khoparzi/', 'HTTPS://khoparzi.com', '', '', '0', '1607579313', '', NULL),
(19, 'Robert Allison', 'robert-allison', 'http://codame.dreamhosters.com/uploaded_images/robert-allison.png', '<p><a href=\"http://robertallison.co.uk/\">Robert Allison</a></p>\r\n<p>In Robert&rsquo;s latest&nbsp;work individual colors are defined as &lsquo;genetic sequences&rsquo;, realized digitally as a string of 1s and 0s. Each is a kind of &lsquo;creature&rsquo;, encoded by a binary DNA, but then expressed as the usual RGB or HSV colormap values. Because of this representation, colors can be mutated and crossed with each other within the computer to form new variations. Oversized pixels, rastered onto the image plane, are used to record these colors as they are created.</p>\r\n<p>Visualizing these operations shows how richness and complexity can emerge from simple processes iterated to a massive scale. The potential of the purely computational, the mechanistic, is explored as it approaches the boundary with the natural, the tactile, the &lsquo;real&rsquo;.</p>\r\n<p>Each series investigates a different combination of techniques, rendered for effect. The pieces are randomly seeded, and are a unique result from the process they express. They are titled by their &lsquo;Unix timestamp&rsquo; &ndash; the exact time of creation recorded as the number of milliseconds since 00:00:00 UTC 1st January 1970.</p>\r\n<p>Join us for&nbsp;<a href=\"/?p=6011\">Art by Code</a>&nbsp;to check out Robert Allison&rsquo;s latest work.</p>', '', 'http://robertallison.co.uk/', '', 'http://www.codame.com/post/portfolio/robert-allison/', '0', '1436337522', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(227, 'Fred Goykhman', 'fred-goykhman', 'http://codame.dreamhosters.com/uploaded_images/fred-goykhman.jpg', '<p>Fred <span id=\"m_7969841119983860551:2wp.1\">Goykhman</span> is an artist/designer currently living in San Francisco. His creative direction spins from following threads of presence and presumed trajectories of the possibility. His life long passion and search for patterns has lead him in studies of biology, chemistry, physics, and architecture. He completed his Masters of Architecture in <span id=\"m_7969841119983860551:2wp.3\">USF</span> Tampa, School of Architecture and Community Design. His current work involves Ballpoint pen \'anti-design\' exercises, spiraling flows of trajectories weaving with in each other to make a pattern unique to the physicality of the organic oscillator. His painting direction is based on the referencing history and pop culture, juxtaposing both with mixed media constructs.</p>\r\n<p>Fred specializes in&nbsp;3D modeling/rendering, laser printig, custom architectural design, and art&nbsp;installations&nbsp;based on metal, wood, and explore differenct&nbsp;materials and combinatins to bring it all to life. Some examples of his deversified work can be found here below:</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/wood-ink2.jpg.png\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/SF.jpg\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/ok.jpg\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/final-wall-2-1030x773.jpg\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/1797436_308311259332227_1863367620806368246_n.jpg\" alt=\"\" /></p>', '', '', '', '', '0', '1478820292', NULL, NULL),
(177, 'Jeffrey Yip', 'jeffrey-yip', 'http://codame.dreamhosters.com/uploaded_images/jeffrey-yip.jpg', '<p>Jeffrey Yip is a new media artist in Oakland California. Highly interested in the intersection of art and technology, he creates environments, often utilizing digital media to enhance the overall experience by integrating visualizations in unison with sound. One area of focus currently in his practice is projection mapping. This technique allows Jeffrey to combine the digital world with the physical through light, sound and sculpture. Animation is layered on top of his geometric sculptures, and then joined with organic and synthesized sound to create a symbiosis of the various mediums.</p>\r\n<p><iframe src=\"//www.youtube.com/embed/E-V2VCw2uTA\" width=\"425\" height=\"350\"></iframe></p>\r\n<p>&nbsp;</p>', '', 'https://blabberbytes.wordpress.com/', '', '', '0', '1444273997', NULL, NULL),
(20, 'EMi', 'emi', 'http://codame.dreamhosters.com/uploaded_images/emi.jpg', '<p>EMi is a maker of things, dominatrix, and fetish content creator based in Tokyo. Inspired by her days crammed inside purikura booths in Japan, her interest and practice are rooted in vernaculars, the 2.5th dimension, the harmony and disharmony of art and technology, as well as the moments when analog and digital worlds collide. EMi operates as a formalistic collector, often gathering digital and physical ephemera and translating them into stories that haven&rsquo;t been told before.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/wp-content/uploads/2014/09/pataphysica.gif\" alt=\"pataphysica - eni\" width=\"700\" height=\"497\" /></p>\r\n<p style=\"text-align: center;\">You might have seen&nbsp;EMi&rsquo;s fabric produced from glitches at&nbsp;<a href=\"/post/portfolio/ephemeral-vessels/\" target=\"_blank\">Ephemeral Vessels</a>! Join us for&nbsp;Art by Code&nbsp;to check out EMi&rsquo;s latest work.</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/emi-small1.jpg\" alt=\"\" width=\"739\" height=\"739\" /></p>\r\n<p>&nbsp;</p>\r\n<center></center>', 'https://twitter.com/MistressKinako', 'https://mistresskinako.com', 'emi@emiemiemi.com', '', '0', '1683749348', '', 'https://www.instagram.com/misskinako'),
(161, 'Alex Andre', 'alex-andre', 'http://codame.dreamhosters.com/uploaded_images/alex-andre.png', '<p><a href=\"http://www.atelieralexandre.com/index.html\">Alex Andre</a> is a French &amp; American artist interested in the relation between human consciousness and our modern times.&nbsp;</p>\r\n<p>After moving from Paris to Venice, he worked with a panel of artists and architects in the Venice community on various sculptural pieces and numerous metal works for city &amp; corporate infrastructures.</p>\r\n<p>Alex\'s passion for painting followed him to the US where he applied textures and fundamental geometric shapes to translate his vivid dreamscapes.</p>\r\n<p>Inspired by the geometry embedded in physics and nature, he later dimensionalised the flat symbols and shapes from his paintings into sculptural pieces using raw materials such as, wood, stone, metals and glass.</p>\r\n<p>Through his efforts to express balance and harmony found in universal dualities Alex started combining symmetry with dynamic elements, leading to the creation of a series of functional pieces as well as lighting &amp; interactive site specific public installations.</p>\r\n<p>Alex\'s art is constantly evolving to express deeper levels of connectivity between ourselves, our perception of form and our dimensional surroundings.</p>\r\n<p><img style=\"width: 45%; height: auto;\" src=\"/uploaded_images/Alex_Andre_Metamorphosis_03.jpg\" alt=\"\" /> <img style=\"width: 45%; height: auto;\" src=\"/uploaded_images/Alex_Andre_Metamorphosis_12.jpg\" alt=\"\" /></p>\r\n<h2><strong>Meet Alex and experience his kinetic sculpture&nbsp;<em>Metamorphosis</em> at our <a href=\"/events/art-tech-festival-2015\">2015 ART+TECH Festival</a>.</strong></h2>', '', 'http://www.atelieralexandre.com/', 'info@atelieralexandre.com', '', '0', '1440397839', NULL, NULL),
(21, 'Angat Gaada', 'angat-gaada', 'http://codame.dreamhosters.com/uploaded_images/angat-gaada.jpg', '<p>Angat&nbsp;is an artist that specializes in live video performance. He was born in Dubai, raised in Los Angeles, and is of Indian descent. His background and cultural influences can be found throughout his work. Angat uses a filmmaker&rsquo;s approach to create a visual aesthetic that is very cinematic. Angat&rsquo;s philosophy on live video performance is that when paired with music, visuals should have the power to invoke emotions and memories of moments created with loved ones from the past and the present while developing excitement for the future and of the unknown.</p>\r\n<div id=\"attachment_6124\"><img src=\"http://www.codame.com/wp-content/uploads/2014/12/720311799_5367782518810266168.jpg\" alt=\"CODAME NEON\" width=\"800\" height=\"450\" />\r\n<p>CODAME NEON</p>\r\n</div>\r\n<p>Angat is also the&nbsp;Artist behind the&nbsp;<a href=\"http://www.codame.com/?p=6116\">CODAME NEON</a>, a&nbsp;commissioned project created under Atari\'s artistic vision and inspiration (Artist Canvas): Vicente Montelongo @<a href=\"http://twitter.com/mexist\" target=\"_blank\">Mexist</a>&nbsp;and spiritual&nbsp;support of&nbsp;Amiga&nbsp;(Guru Meditation Handler): Jordan Gray @<a href=\"http://twitter.com/Starpause\" target=\"_blank\">staRpauSe</a>.</p>', '', 'http://angatgaada.com/', '', '', '0', '1683964449', '', ''),
(22, 'Harbour', 'harbour', 'http://codame.dreamhosters.com/uploaded_images/harbour.jpg', '<p><a href=\"https://twitter.com/harboursounds\">Aaron Harbour</a>&nbsp;has released several albums of original material: intricate hiphop influenced beats painstakingly spliced in audacity, catch some on&nbsp;<a href=\"https://timberharbour.bandcamp.com/\">Bandcamp</a>&nbsp;and<a href=\"https://soundcloud.com/harbour\">Soundcloud</a>. Professionally, Harbour gets paid for keeping&nbsp;<a href=\"http://9thfloorradio.com/\">9th Floor Radio</a>&nbsp;running, catch his eclectic&nbsp;<a href=\"https://itunes.apple.com/us/podcast/timber/id938008995?mt=2\">TIMBER</a>&nbsp;show over there.&nbsp;</p>\r\n<p>Aaron Harbour is also a curator, writer, and artist operating out of Oakland, CA. He is co-director of<a href=\"http://etaletc.com/\">&nbsp;Et al.</a>, a gallery program in San Francisco, and has additionally curated exhibitions at The Popular Workshop, Important Projects, MacArthur B Arthur, Liminal Space, and Royal Nonesuch Gallery, and art fair booths at NADA Miami and New York, Dallas Art Fair, and Art Los Angeles Contemporary. He runs<a href=\"http://www.curiouslydirect.com/\">Curiously Direct</a>, an art criticism blog on Facebook, and has additionally written forFillip Magazine, San Francisco Arts Quarterly,&nbsp;Art Practical,&nbsp;Decoy Magazine,&nbsp;Art Cards, and several small publications/artist catalogues.&nbsp;As an artist he has participated in exhibitions at CCA Wattis Institute, City Limits (San Francisco and Oakland) and Southern Exposure.</p>', 'https://twitter.com/harboursounds', 'https://soundcloud.com/harbour', '', '', '0', '1436748146', NULL, NULL),
(160, 'Total Unicorn', 'total-unicorn', 'http://codame.dreamhosters.com/uploaded_images/total-unicorn.jpg', '<h2><img src=\"/uploaded_images/720111645_12373104771956834695.jpg\" alt=\"\" /></h2>\r\n<h2><strong>Total Unicorn will be performing on&nbsp;</strong><strong>October 23rd for the <a href=\"/events/art-tech-festival-2015\">2015 ART+TECH Festival</a>.</strong></h2>\r\n<p><strong><!-- pagebreak --></strong></p>\r\n<div>\r\n<div id=\"pd_rating_holder_4238116_post_154\">\r\n<div id=\"pd_rate_4238116_post_154\">\r\n<div id=\"PDRTJS_4238116_post_154_stars_1\"><em>We enjoin you to become an initiate of the Protocorns, to partake of the unichalace and imbibe the cosmic ambrosia. With every sip, your waves hew closer to ours.</em></div>\r\n</div>\r\n</div>\r\n<p>That&rsquo;s the power of Aesthetic Acid: the primary building block of Inner Beauty. We&rsquo;ve clapped our hooves. We have your attention. We control your cryptognostic cervix. It now pulses congenial multimedia energy and you&rsquo;re in love with The Universe.</p>\r\n<p>That wasn&rsquo;t so hard now, was it?</p>\r\n<p>We&rsquo;ve redesigned your optisonic awareness. It&rsquo;s all purple, green and black with heavy bass.</p>\r\n<p>You know the Unicorn, the Total Unicorn. You&rsquo;ve always known it. You are beyond trash death now. You are in our site. Explore its many mysteries. Know it as it knows you.</p>\r\n<p>Welcome&hellip;.You&rsquo;re welcome.</p>\r\n<p>Bandcamp:</p>\r\n<p><a href=\"http://totalunicorn.bandcamp.com/\" rel=\"nofollow\">http://totalunicorn.bandcamp.com/</a></p>\r\n<p>FB:</p>\r\n<p><a href=\"https://www.facebook.com/pages/Total-Unicorn/121549881201453?ref=ts&amp;fref=ts\" rel=\"nofollow\">https://www.facebook.com/pages/Total-Unicorn/121549881201453?ref=ts&amp;fref=ts</a></p>\r\n</div>', '', 'https://totalunicorn.bandcamp.com/', '', '', '0', '1439422826', NULL, NULL),
(23, 'Inigo Quilez', 'inigo-quilez', 'http://codame.dreamhosters.com/uploaded_images/inigo-quilez.jpg', '<div>\r\n<p><a href=\"http://www.iquilezles.org/\" target=\"_blank\">Inigo Quilez</a></p>\r\n</div>\r\n<p>Inigo decided to focus his life on computer graphics when he discovered the demoscene at the age of 18. Before that he was grew enjoying ski and nature but also programming fractals and other visual experiments, but it was not until he met the underground community of the demoscene that he understood code and maths could build beauty.</p>\r\n<p>Within the demoscene he learnt the basic principles and algorithms of CG first (tunnels, metaballs and the oldschool effects) and soon started to join the creative side of the community where he developed new techniques and ideas himself. He specialized in procedural content creation, where 3d objects, animations, textures and sound would be generated from code and maths instead.</p>\r\n<p>After having worked professionally in virtual reality and realtime rendering of massive data sets, now he is working at Pixar Animation Studios doing what he likes the most &ndash; inventing techniques and formulas and producing procedural imagery.</p>\r\n<p>Join us for&nbsp;<a href=\"/events/art-by-code-reception-2013\">Art by Code</a>&nbsp;to check out Inigo&rsquo;s latest work.</p>\r\n<p><img src=\"http://acko.net/files/fullfrontal/fullfrontal/wdcode/images/brave2.jpg\" alt=\"\" width=\"1890\" height=\"1088\" /></p>', '', 'http://www.iquilezles.org/', '', '', '0', '1437437918', NULL, NULL),
(159, 'Anna Landa', 'anna-landa', 'http://codame.dreamhosters.com/uploaded_images/anna-landa.jpg', '<div>Anna Landa is an artist based in New York City and San Francisco whose more recent work draws inspiration from the intersection of art and science. She creates two-dimensional works and installations reflecting her preoccupation with questions concerning the idea of self, time, and mortality.</div>\r\n<div>&nbsp;</div>\r\n<div>&nbsp;</div>\r\n<div>On display at the Academy of Science&rsquo;s NightLife event will be a new rendition of her sound installation &ldquo;The Fear&rdquo;. Inspired by research observing a fixed number of heartbeats in all mammals, the piece incorporates her own recorded heartbeat in an attempt to quantify human life&rsquo;s finite nature and bring the notion of mortality to the forefront of consciousness. The exhibit will utilize tactile transducers to convert the audio of the installation into a multi-sensory interactive experience for the viewer.</div>\r\n<div>&nbsp;</div>\r\n<p><iframe src=\"https://player.vimeo.com/video/130580627\" width=\"500\" height=\"281\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', '', 'http://annalanda.com', 'anna@annalanda.com', '', '0', '1439344973', NULL, NULL),
(24, 'Ytai Ben-Tsvi', 'ytai-ben-tsvi', 'http://codame.dreamhosters.com/uploaded_images/ytai-ben-tsvi.png', '<p><a href=\"http://ytai-mer.blogspot.com/\" target=\"_blank\">Ytai Ben-Tsvi</a>&nbsp;creates drawings with his flip-chart&nbsp;<a href=\"http://ytai-mer.blogspot.com/2013/05/ioio-plotter-and-motor-control-library.html\">plotter</a>&nbsp;&ndash; a drawing machines that uses an Android tablet and a IOIO-OTG board to capture images then plots the images onto paper.</p>\r\n<p><iframe src=\"http://www.youtube.com/embed/5v_nz6qzoZ4?wmode=transparent&amp;autohide=1&amp;egm=0&amp;hd=1&amp;iv_load_policy=3&amp;modestbranding=1&amp;rel=0&amp;showinfo=0&amp;showsearch=0\" width=\"901\" height=\"507\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>As seen&nbsp;at the 5ENSES&nbsp;<a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival</a>! Check out artist own<a href=\"http://ytai-mer.blogspot.com/2013/11/how-i-became-artist.html\">blog post</a>&nbsp;too!</p>\r\n<p><a href=\"http://ytai-mer.blogspot.com/2013/11/how-i-became-artist.html\"><img src=\"http://3.bp.blogspot.com/-_En3jQbH9x0/UncM6BrPHtI/AAAAAAAAN_A/_a47fC5_2w8/w949-h712-no/IMG_0162.JPG\" alt=\"\" width=\"949\" height=\"712\" /></a></p>', '', '', 'http://ytai-mer.blogspot.com/', '', '0', '1436748159', NULL, NULL),
(25, 'Tiare Ribeaux', 'tiare-ribeaux', 'http://codame.dreamhosters.com/uploaded_images/tiare-ribeaux.png', '<p>Tiare Ribeaux is a Hawaiian-American new media and bio-artist whose work explores the entanglements of human technologies and infrastructures with mythologies, the environment, and non-human species. She is interested in living systems, deep/dark/media ecology, rhizomatic networks, speculative futures, multi-species and collaborative entanglements. She&rsquo;s also grown algae to convert to biofuel in Kona, Hawaii, and studied harmful algal blooms off the coast of Puget Sound.</p>\r\n<p>She recently completed an international artist fellowship as part of the ZERO1 American Arts Incubator in Kyiv, Ukraine, and has shown work both nationally and internationally, including ISEA Hong Kong, Transmediale, IZOLYATSIA and Tokyo Fashion Week. She is currently the Artistic Director of B4BEL4B Gallery, produced the Soundwave 7 Biennial in San Francisco in 2016, and has worked with the de Young Museum, California Academy of Sciences, Fort Mason Center for the Arts, and the Oakland Museum of California, among others.</p>', 'https://twitter.com/tiareribeaux', 'http://www.tiareribeaux.com', 'tiare@codame.com', '', '0', '1629674285', '', 'https://www.instagram.com/tiareribeaux/'),
(308, 'Joe Andolina', 'joe-andolina', 'http://codame.dreamhosters.com/uploaded_images/joe-andolina.jpg', '<p>Director, Product Marketing at Salesforce</p>\r\n<p>Joe Andolina is a Software Engineer by trade, a mad scientist by night and a child at heart.&nbsp;</p>\r\n<p>Passionate about user experience, technology and craftsmanship, his passion is architecting experiences that physically demonstrate intangible software features and concepts. He can make business software as simple to understand as a flame throwing helmet.</p>\r\n<p>With over a decade of UX innovation and just and many trips to the Playa, Joe has a deep understanding of how people consume technology.</p>\r\n<h2 class=\"mt1 t-18 t-black t-normal\" style=\"box-sizing: inherit; padding: 0px; border: 0px; font-size: 1.8rem; vertical-align: baseline; background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; outline: 0px; line-height: 1.33333; font-weight: 400; color: rgba(0, 0, 0, 0.9); font-family: -apple-system, system-ui, system-ui, \'Segoe UI\', Roboto, \'Helvetica Neue\', \'Fira Sans\', Ubuntu, Oxygen, \'Oxygen Sans\', Cantarell, \'Droid Sans\', \'Apple Color Emoji\', \'Segoe UI Emoji\', \'Segoe UI Symbol\', \'Lucida Grande\', Helvetica, Arial, sans-serif; margin: 4px !important 0px 0px 0px;\">&nbsp;</h2>', 'https://twitter.com/JoePhando', 'https://www.behance.net/phando', 'jandolina@salesforce.com', '', '0', '1570759155', NULL, NULL),
(245, 'Eve Weinberg ', 'eve-weinberg', 'http://codame.dreamhosters.com/uploaded_images/eve-weinberg.jpg', '<p>Eve Weinberg is an Interaction Designer II at frog design in San Francisco. She has been animating and designing for over a decade and loves telling stories with animation and interactivity. She ran her own motion graphics studio for 4 years - Never Odd or Even, before pursuing a master\'s in creative coding and HCI. She has directed graphics for countless documentaries that can be seen on Netflix, as well as launched a few prominent start-ups taking on the role of creative director and branding specialist. She loves learning new things, exploring new technology, and making collages in her spare time.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/evejweinberg', 'evejweinberg.com', '', '', '0', '1496949963', NULL, NULL),
(27, 'Eddie Lee', 'eddie-lee', 'http://codame.dreamhosters.com/uploaded_images/eddie-lee.gif', '\r\n						<hr>\r\n<p class=\"p1\"><span class=\"s1\"><a href=\"http://illogictree.com/blog/projects/\">Eddie Lee</a></span>, founder of the funky-fresh independent game development studio <a href=\"http://funktroniclabs.com/\"><span class=\"s1\">Funktronic Labs</span></a>. Eddie had a deep passion for real-time graphics technology and a fascination in mending procedurally generated geometry with digital art. Eddie enjoys seeing procedural algorithms manifest itself in groovy ways. Some <a href=\"http://illogictree.com/projects\"><span class=\"s1\">his work</span></a> has been shown at various exhibitions around the world, including <a href=\"http://grayarea.org/\"><span class=\"s1\">GAFFTA</span></a> in San Francisco, Gates Foundation in Seattle, and <a href=\"http://www.dca.org.uk/\"><span class=\"s1\">Dundee Contemporary Arts</span></a> in Scotland. Recently, he did an audiovisual live performance for TEDxChiyoda, called <span class=\"s2\">SIGMA Project</span>.</p>\r\n<p>Eddie first time at CODAME was at the <a href=\"http://www.codame.com/?p=5644\">ART+TECH Virtual Reality</a> @ Mozilla, San Francisco, Nov. 21st., 2014. We all enjoyed playing with his latest projects <a href=\"http://www.codame.com/?p=5838\">Collider</a>.</p>\r\n<p style=\"text-align: center;\"><a title=\"Adopt an Artist, Support ART+TECH\" href=\"http://codame.com/adopt\"><img class=\"alignnone size-full wp-image-3942\" src=\"http://www.codame.com/wp-content/uploads/2014/04/Codame_Badge_02_AdoptAnArtist_200px.png\" alt=\"Adopt an Artist\" width=\"200\" height=\"145\"></a></p>\r\n<p style=\"text-align: center;\"><a href=\"http://www.codame.com/support/\">Support ART + TECH</a></p>\r\n											', '', 'http://illogictree.com/blog/projects/', '', 'http://www.codame.com/post/portfolio/eddie-lee/', '0', '', NULL, NULL),
(28, 'Eder Cetina', 'eder-cetina', 'http://codame.dreamhosters.com/uploaded_images/eder-cetina.jpg', '\r\n						<hr>\r\n<p><a href=\"http://www.laartcollective.com/artists/eder-cetina/\">Eder Cetina</a> is a Los Angeles muralist, painter, and sculptor. He received his BA from the University of California, Los Angeles. His large murals, installations, and digital projections have exhibited on an international level. In 1997, he was awarded the prestigious Los Angeles Council Arts Fellowship and won the prize of Best in Show. Cetina’s work has been sought after by major museum collections including: Los Angeles County Museum of Art, Notron Simon, Museum of Contemporary Art Chicago, The Autry, UCLA, Skirball Cultural Center, and the J. Paul Getty Museum-where his work is in the permanent collection. He has been commissioned for large-scale projects from the Ludacris show at the L.A. Coliseum, LACMA, Coachella Music and Arts Festival, and the Museum of Contemporary Art. Recently, Eder Cetina was included in the iconic Getty Graffiti Black Book. He also works as a commercial artist using a variety of mediums for Olson Visual, a premier large-scale graphic company. Today, Cetina continues to produce work that represents today’s Los Angeles street art and hip-hop scene.</p>\r\n<p>The <a href=\"http://www.laartcollective.com/\">LAAC</a> is a collective of emerging artists that represent the intricacy and diversity of the Los Angeles culture. Like the freeways that make the terrain of LA, their concepts are driven from their experiences in the urbanization of the city of angels. Together, their distinct voices echo the diversified communities and multifarious architecture.</p>\r\n<p>Our mission is to create large-scale collaborations blurring the boundaries of artist, community, space, medium, and identity. From live mural painting to video projection mapping, these contrasting artists have one mutual theme: their relationship to this massive city.</p>\r\n<hr>\r\n<p>Witness Eder Cetina’s work at CODAME <a href=\"http://codame.eventbrite.com/\"><IN.SECURE></a> ART+TECH Friday Oct. 31st, at Geekdom – 620 Folsom St., San Francisco</p>\r\n											', '', 'http://www.laartcollective.com/artists/eder-cetina/', '', 'http://www.codame.com/post/portfolio/eder-cetina/', '0', '', NULL, NULL),
(29, 'VJ Musashii', 'vj-musashii', 'http://codame.dreamhosters.com/uploaded_images/vj-musashii.jpg', '\r\n						<hr>\r\n<p>VJ Musashii (Chris Crismond) is a Artist/Code samurai who specializes in projection mapping, realtime visuals, interactive installations and virtual reality. Musashii has been coding and doing graphic arts for 18 years now. A veteran circus performer, he turned his sights to video arts back in 2007. He has performed with artists such as BlueTech, Andrelien, GlitchMob, Black Sun Empire, Andy C, Total Science, and Asterix. His current weapons of choice are TouchDesigner, Open Frameworks, and Unity. Currently working on media control/mapping systems in touch designer and assorted projects in virtual reality.</p>\r\n<hr>\r\n<p>VJ Musashii was first time featured at CODAME during the <a href=\"http://codame.eventbrite.com/\"><IN.SECURE></a> ART+TECH, Oct. 31st, 2014 at Geekdom, San Francisco.</p>\r\n											', '', '', '', 'http://www.codame.com/post/portfolio/vj-musashii/', '0', '', NULL, NULL),
(30, 'Owen Mundy', 'owen-mundy', 'http://codame.dreamhosters.com/uploaded_images/owen-mundy.jpg', '<hr />\r\n<p class=\"p1\"><img class=\" wp-image-5738 alignleft\" src=\"http://www.codame.com/wp-content/uploads/2014/10/Owen-Mundy.jpeg\" alt=\"Owen Mundy\" width=\"130\" height=\"130\" /></p>\r\n<p class=\"p1\"><a href=\"http://twitter.com/owenmundy\">Owen Mundy</a> is an artist, designer, and programmer who investigates public space and its relationship to data. His artwork highlights inconspicuous trends and offers tools to make hackers out of everyday users. He has an MFA in Visual Art from the University of California, San Diego and is an Assistant Professor of Art at Florida State University.</p>\r\n<p class=\"p1\">Enjoy Owen&rsquo;s project &ldquo;<a href=\"http://www.codame.com/?p=5721\">I Know Where Your Cat Lives</a>&rdquo;&nbsp;at CODAME &nbsp;ART+TECH Friday Oct. 31st, at&nbsp;Geekdom &ndash; 620&nbsp;Folsom St., San Francisco</p>\r\n<p class=\"p1\">&nbsp;</p>', 'http://twitter.com/owenmundy', '', '', '', '0', '1436747969', NULL, NULL),
(31, 'Josh Nimoy', 'josh-nimoy', 'http://codame.dreamhosters.com/uploaded_images/josh-nimoy.png', '<hr />\r\n<p>Josh is a prolific artist and composer that has created a great deal of work ranging from stunning computer generated art, to playful interactive pieces that allow the user to create fun visuals with a generated audio soundtrack. &nbsp;His work contains a fusion of math and art &ndash; which helped create the visual experience of the blockbuster film, Tron:Legacy as well as a number of gallery shows. &nbsp;<a href=\"http://jtnimoy.net/?q=178\" target=\"_blank\">Read more</a>&nbsp;about Nimoy&rsquo;s work on the film.</p>\r\n<p>Artwork available&nbsp;at&nbsp;<a href=\"/defcon\" target=\"_blank\">DEFCON x CODAME</a>&nbsp;for a Silent Auction</p>\r\n<p>Sublime serendipity, and the universality of biological syntax. Use a chaos game iterative function with slowly shifting transforms, producing painterly smearing. The program takes about as long to render this as a human would need to physically paint it. 2400 DPI prints, coded in Java/Processing, implement an iterative function.</p>\r\n<div><img src=\"/wp-content/uploads/2013/11/42ed51a6433701d3c8207fc83365636f2.png\" alt=\"image\" width=\"903\" height=\"677\" />\r\n<p>Titles:&nbsp;Sky #6 + Sky #7 Medium:&nbsp;Giclee on Archival, acid-free watercolor paper</p>\r\n</div>\r\n<p>Nimoy&rsquo;s <a title=\"Bandwidth\" href=\"http://jtnimoy.net/?q=184\" target=\"_blank\">Bandwidth</a>&nbsp;application is described as a &ldquo;synaesthetic, interactive musical experience&rdquo; which is a fun music creation toy:</p>\r\n<p><iframe src=\"http://player.vimeo.com/video/30941585\" width=\"906\" height=\"567\" frameborder=\"0\"></iframe></p>\r\n<p>His application <a title=\"BallDroppings\" href=\"http://jtnimoy.net/?q=114\" target=\"_blank\">BallDroppings</a>&nbsp;integrates his programming prowess and musical composition by allowing users to play with balls falling while creating music as they bounce. &nbsp;It is a great way to get lost playing with bouncing balls as well as making your own musical compositions. &nbsp;Give it a try!</p>\r\n<p>Josh Nimoy&rsquo;s &lsquo;BallDroppings&rsquo; was the only way I got off my crack habit.</p>\r\n<p>&mdash; James Clar, EyeBeam</p>\r\n<p><img src=\"/wp-content/uploads/2013/11/57c632094767c4514d49b35cb95c0ee02.png\" alt=\"BallDroppings\" width=\"902\" height=\"601\" /></p>', '', 'http://jtnimoy.net/?q=178', '', '', '0', '1436747978', NULL, NULL),
(32, 'Lena Shagieva', 'lena-shagieva', 'http://codame.dreamhosters.com/uploaded_images/lena-shagieva.jpg', '<p class=\"p1\">&nbsp;</p>\r\n<p class=\"p1\">Resident Artist at&nbsp;Adorespace, <a href=\"http://lenashagieva.com/\" target=\"_blank\">Lena Shagieva</a> has a great mantra: &ldquo;do what you want to do &amp; do it&nbsp;<em>now&rdquo;. </em>We are happy that she wants to be part of our&nbsp;<a href=\"/festival\" target=\"_blank\"><strong>CODAME ART+TECH Festival</strong></a>, and will be there with us on October 27th!</p>\r\n<p class=\"p2\">She is a graphic designer, illustrator and also does interactive installations, with work spanning from <a href=\"http://lenashagieva.com/CD-covers\" target=\"_blank\">album art</a> for the Arctic Monkeys to taking art to the streets.</p>', '', 'http://lenashagieva.com/', '', '', '0', '1436747989', NULL, NULL),
(33, 'David OReilly', 'david-oreilly', 'http://codame.dreamhosters.com/uploaded_images/codame-featured-artist-david-o-reilly.gif', '<div>\r\n<p>David OReilly is a multidisciplinary artist based in Los Angeles, California</p>\r\n<p>Born in Kilkenny, Ireland, he began working at age 14 as an animation assistant on The Secret of Kells, which would later be nominated for an Academy Award for Best Animated Feature Film. He studied for a year at Dublin&rsquo;s DL-IADT, then left for London to work with several of the city&rsquo;s most prestigious animation studios as a concept artist, designer and animator. In 2005 he was awarded a scholarship to Fabrica - Benetton&rsquo;s Communication Research Centre, where he began producing 3d animated short films. In 2006 he moved to Berlin to pursue independent animation.</p>\r\n<p>His first short film to hit festivals was RGB XYZ, which premiered at the Berlin International Film Festival in 2008. The following year he was awarded the Golden Bear for Please Say Something, becoming the first animated film to win the prestigious prize. The film was widely regarded as groundbreaking for contemporary animation and went on to be met with worldwide critical acclaim. His next film, The External World, was co-written with Vernon Chatman (Xavier: Renegade Angel, Wonder Showzen). It premiered in Venice Film Festival and went on to win over 40 awards including an IFTA, the Cartoon D&rsquo;Or as well as awards at Sundance and Venice Film Festivals.</p>\r\n<p>In 2012 he wrote, directed and produced a special for Cartoon Network&rsquo;s Emmy Award-winning show Adventure Time - becoming the first guest director in the network&rsquo;s 20 year history. He then served as writer for South Park, and designed and directed several prominent animation sequences in Spike Jonze\'s Academy Award winning film Her, starring Joaquin Phoenix.</p>\r\n<p>In 2014 he produced his first video game Mountain. Offering minimal control and emphasizing ambient nature simulation, it became an underground hit. He spent 3 years developing a follow up, Everything - a model of the universe in which every object was a playable character. Everything launched on PS4, with later releases on Desktop and Nintendo Switch. It went on to win the Golden Nica at Ars Electronica and its trailer became the first game to qualify for Academy Award. It was featured Best Game of the Year lists of The Guardian, the AV Club, Wired, The New Yorker and Polygon, and was listed as Polygon\'s #15 game of the decade.</p>\r\n<p>David\'s work has been exhibited internationally including at the SF MoMA, David Lynch\'s Festival of Disruption, Japan\'s NTT ICC and the Hong Kong Arts Center. His animated works have been the subject of several retrospectives, at theaters in MoMA NY and the Walt Disney Concert Hall. He has given masterclasses at Harvard, Yale, USC, Pixar Animation Studios, CalArts and many other conferences, universities and festivals around the world.</p>\r\n</div>\r\n<div class=\"figure\">&nbsp;</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/658e5d99bf123f0108f750699193fd382.gif\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/82afa310fb61c3b5ccb4b2fb9d5f7c312.gif\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/5fd635bd76bf9698021bb4dd81e0c09e2.gif\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/df6050eb68514a7682f44f98fc9b519a2.gif\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/b97c65255e394541d075fb43dea8401e2.gif\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/5291a88ea0e7e556d0423b72566959102.gif\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/22e0b16a337edc5e71c24328835deed02.gif\" alt=\"\" /></figure>\r\n</div>\r\n<p><strong><a href=\"http://davidoreilly.com/\" target=\"_blank\">David O&rsquo;reilly</a> &ndash; CODAME Featured Artist</strong></p>\r\n<p>David O&rsquo;reilly will be screening a short film at the CODAME ART+TECH Festival Oct27</p>', '', 'http://davidoreilly.com/', '', '', '0', '1632274489', '', 'https://www.instagram.com/davidoreilly/'),
(34, 'Cyriak', 'cyriak', 'http://codame.dreamhosters.com/uploaded_images/cyriak.png', '\r\n						<p><iframe src=\"http://www.youtube.com/embed/FavUpD_IjVY?wmode=transparent&autohide=1&egm=0&hd=1&iv_load_policy=3&modestbranding=1&rel=0&showinfo=0&showsearch=0\" height=\"225\" width=\"400\" allowfullscreen=\"\" frameborder=\"0\"></iframe></p>\r\n<p><strong><a href=\"http://www.cyriak.co.uk\" target=\"_blank\">Cyriak</a> – CODAME Featured Artist</strong></p>\r\n<p>CODAME is going global. Surreal UK-based animator Cyriak has joined the show, offering to screen a piece of work. Cyriak’s work takes the familiar and twists it into something that you’d never expect. From cats, cows and sheep, to St. Paul’s Cathedral and the Queen of England, nothing is what it seems. Here’s a taste of what Cyriak has in store for CODAME.</p>\r\n											', '', 'http://www.cyriak.co.uk', '', 'http://www.codame.com/post/portfolio/cyriak-codame-featured-artist-codame-is-going/', '0', '', NULL, NULL),
(35, 'DJ DIALS', 'dj-dials', 'http://codame.dreamhosters.com/uploaded_images/dj-dials.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"http://www.djdials.com/\" target=\"_blank\">DJ DIALS</a> &ndash; CODAME Music Artist</strong></p>\r\n<p>Extremely pleased to announce <a href=\"http://www.djdials.com/\" target=\"_blank\">DJ DIALS</a> will be joining the CODAME party on OCT27! A legendary DJ/producer in SF and beyond who&rsquo;s first song received accolades as one of the top ten best electronic releases in 2011 by the SF Weekly. He&rsquo;s played alongside Modeselektor, Thom Yorke, The Roots&hellip; the list goes on and on, and now he&rsquo;ll be blasting the sound system at CODAME! Reminder: the event is donation based but <a href=\"http://codame.eventbrite.com/\" target=\"_blank\">RSVP</a> is required to be notified of the exact party location. More of these musician highlights to come as we count down the days!</p>', '', 'http://www.djdials.com/', '', '', '0', '1436748012', NULL, NULL),
(36, 'MANICS', 'manics', 'http://codame.dreamhosters.com/uploaded_images/manics.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"http://manics.bandpage.com/\" target=\"_blank\">MANICS</a> &ndash; CODAME Music Artist</strong></p>\r\n<p>hyped for <a href=\"http://manics.bandpage.com/\" target=\"_blank\">MANICS</a> to play at the party on OCT27! in their own words&hellip; <em>Manics is the result of drunk conversations about making music actually coming to fruition. Jordan Deherrera and Chris Sanders both started as DJ&rsquo;s in the SF underground dance music scene before pairing up to begin production. The duo have developed their set as more of a live performance, programing effects and instruments with live improvisation to set themselves apart from the usual Digital DJ.</em> don&rsquo;t forget to <a href=\"/tickets\" target=\"_blank\">grab a ticket</a> as the exact location of the SOMA venue will be given to RSVP people =)</p>', '', 'http://manics.bandpage.com/', '', '', '0', '1436748019', NULL, NULL),
(37, 'Chris Ritson', 'chris-ritson', 'http://codame.dreamhosters.com/uploaded_images/chris-ritson.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><strong><a href=\"http://www.chrisritson.com/\" target=\"_blank\"><strong>Chris Ritson</strong></a> &ndash; CODAME Featured Artist<br /> </strong></p>\r\n<p class=\"MsoNormal\">CODAME is excited to welcome Chris Ritson to the show. Chris is known for not using traditional art supplies. Actually, he&rsquo;s downright opposed to their use. Instead he draws from other sources. For CODAME, Chris has decided to show some of his masks series. Created out of picture clippings from magazines and blurring the lines between human and beast, the masks take two-dimensional soon-to-be landfill and turn it into three-dimensional art.</p>', '', 'http://www.chrisritson.com/', '', '', '0', '1436748027', NULL, NULL),
(38, 'Sebastien Deux', 'sebastien-deux', 'http://codame.dreamhosters.com/uploaded_images/sebastien-deux.jpg', '\r\n						<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/0145e500ec876506b93ba752f41f46342.jpg\"></figure>\r\n</div>\r\n<p><strong><a href=\"http://soundcloud.com/sebastiendeux\" target=\"_blank\">Sebastien Deux</a> – CODAME featured Musician</strong></p>\r\n<p>Born and raised in the south of France, worked and studied in Paris, and resides now in San Francisco California. He’s best known for his amazing graphic design, but on the sound system at CODAME you’ll become familiar with his amazing taste in dance floor tracks!</p>\r\n<p>the CODAME 2012 party goes down OCT27, <a href=\"http://codame.com/tickets\" target=\"_blank\">grab a ticket</a> to recieve our SOMA venue’s exact address =)</p>\r\n											', '', 'http://soundcloud.com/sebastiendeux', '', 'http://www.codame.com/post/portfolio/sebastien-deux-codame-featured-musician-born/', '0', '', NULL, NULL),
(197, 'Lisa Lang (ElektroCouture)', 'lisa-lang-elektrocouture', 'http://codame.dreamhosters.com/uploaded_images/lisa-lang-elektrocouture.png', '<p>Lisa Lang is known around Berlin as an ambassador for Fashion Technology. Prior to starting ElektroCouture, Lisa worked in tech for 10 years. While her interest in tech satisfied her &lsquo;nerdy&rsquo; side, her fingernails, heels and lipstick told another story. Lisa noticed &lsquo;wearable technology&rsquo; companies lack communication to their community and there was an obvious gap in the market. This frustration lead her to launch her own fashion technology house, and the world&rsquo;s first agency to pioneer innovative electronic wearable technology for the fashion industry.</p>\r\n<p>We are excited to have Lisa&nbsp;as part of&nbsp;our&nbsp;<a href=\"http://labs.codame.com\">CODAME Labs</a>&nbsp;in 2016</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/Lisa_Lang.jpg\" alt=\"\" /></p>', 'https://twitter.com/lilaineurope', 'http://elektrocouture.com/', '', '', '0', '1456210166', NULL, NULL),
(40, 'CRASHFASTER', 'crashfaster', 'http://codame.dreamhosters.com/uploaded_images/crashfaster.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"http://crashfaster.com/\" target=\"_blank\">CRASHFASTER</a> &ndash; CODAME featured Musician</strong></p>\r\n<p>kingpin behind <a href=\"http://monobomb.com/\" target=\"_blank\">MONOBOMB recordings</a> and <a href=\"http://www.8bitsf.com/\" target=\"_blank\">8BITSF</a> promotions, Morgan Tucker aka CRASHFASTER is a keeper. For CODAME he&rsquo;ll be stripping away the band and premiering a slamming dance-floor oriented set. File under 8bit/industrial/goth/chiptune</p>\r\n<p>the CODAME 2012 party goes down OCT27, <a href=\"/tickets\" target=\"_blank\">grab a ticket</a> to recieve our SOMA venue&rsquo;s exact address =)</p>', '', 'http://crashfaster.com/', '', '', '0', '1436747845', NULL, NULL),
(41, 'Demoscene Passivist', 'demoscene-passivist', 'http://codame.dreamhosters.com/uploaded_images/demoscene-passivist.png', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><strong><a href=\"http://copypastaresearch.tumblr.com/\" target=\"_blank\">Demoscene Passivist</a> &ndash; </strong><strong>CODAME Featured Artist</strong></p>\r\n<p class=\"MsoNormal\">This week, CODAME welcomes Demoscene Passivist to the show. Demoscene Passivist raised the bar within the demo art community by creating an amazing, seemingly endless landscape with only 4kB of data. Mesmerizing and simplistic at the same time, passivist has created, coded and compressed grand art on a micro scale by today&rsquo;s standards. We&rsquo;re excited to see how 4kB of data can steal the show at CODAME.</p>\r\n<p class=\"MsoNormal\">CODAME runs on donations, so get your ticket and make a donation. <a href=\"/tickets\" target=\"_blank\">Order Here</a></p>\r\n<p class=\"MsoNormal\"><a href=\"https://twitter.com/ScenePassivist\" target=\"_blank\">Follow Demoscene Passivist on Twitter</a></p>', '', 'http://copypastaresearch.tumblr.com/', '', '', '0', '1436747910', NULL, NULL),
(42, 'George Michael Brower', 'george-michael-brower', 'http://codame.dreamhosters.com/uploaded_images/george-michael-brower.png', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><strong><strong><a href=\"http://www.georgemichaelbrower.com/\" target=\"_blank\"><strong>George </strong>Michael Brower</a> &ndash; </strong>CODAME Featured Artist<br /> </strong></p>\r\n<p class=\"MsoNormal\">You might not know his name, but if you&rsquo;ve been on the internet in the last 6 months, you&rsquo;ve probably seen his creation. CODAME will be displaying art from the creator of Staggering Beauty, George Michael Brower. Beyond just a dancing worm, Brower could be considered a modern renaissance man &ndash; he codes, he chiptunes, he designs, he even sings. CODAME can&rsquo;t wait to see what form his art will take on October 27<sup>th</sup>.</p>\r\n<p class=\"MsoNormal\">Experience Staggering Beauty in person. <a href=\"/tickets\" target=\"_blank\">Get Tickets</a></p>\r\n<p class=\"MsoNormal\"><a href=\"https://twitter.com/georgealways\" target=\"_blank\">Follow George Michael Brower on Twitter</a></p>', 'https://twitter.com/georgealways', 'http://www.georgemichaelbrower.com/', '', '', '0', '1436747926', NULL, NULL),
(164, 'Tim McNeil', 'tim-mcneil', 'http://codame.dreamhosters.com/uploaded_images/tim-mcneil.jpg', '<p><a style=\"box-sizing: border-box; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; color: #00a4a7 !important; background-color: #000000;\" href=\"http://design.ucdavis.edu/faculty/council/McNeil.html\" target=\"_blank\"><strong style=\"box-sizing: border-box;\">Tim McNeil</strong></a><span style=\"color: #ffffff; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; background-color: #000000;\">&nbsp;is so up on museums&nbsp;and design it isn&rsquo;t funny.&nbsp;Never without a vision, he is also a professor of design and director of the Design Museum at the University of California, Davis.&nbsp;An authority on environmentally sustainable design&nbsp;solutions for exhibition environments,&nbsp;he chairs the California Association of Museums&nbsp;Green Museum Initiative, founded&nbsp;the Green Museums Accord, and in 2008&nbsp;was inducted into the National Environmental Hall of Fame for his work on the NRDC&rsquo;s Environmental Action Center.&nbsp;His award winning design research has been featured in multiple publications and he a frequent speaker at museum and design conferences.</span></p>', '', 'http://arts.ucdavis.edu/faculty-profile/tim-mcneil', 'tjmcneil@ucdavis.edu', '', '0', '1440806684', NULL, NULL),
(43, 'Mike BAM Tyau', 'mike-bam-tyau', 'http://codame.dreamhosters.com/uploaded_images/mike-bam-tyau.gif', '<div class=\"figure\" style=\"text-align: center;\">\r\n<figure></figure>\r\n<figure>\r\n<p style=\"text-align: left;\">Originally a graffiti artists that used to run the San Francisco streets, Mike\'s latest work entails color work done on the iPad. He then transfers the visions from computer to large scale walls. Traditionally trained as a graphic designer and having spent most of his career in the videogame industry, Mike has returned to painting large canvas &amp; concrete walls.</p>\r\n<p style=\"text-align: left;\">... and don\'t forget that his&nbsp;last name&nbsp;Tyau&nbsp;rhymes with \"meow.\"&nbsp;</p>\r\n<p style=\"text-align: left;\"><img src=\"http://s3.otherpeoplespixels.com/sites/10444/assets/oZEyH3NsjpRCGI7M.jpg\" alt=\"\" width=\"640\" height=\"480\" /></p>\r\n<p style=\"text-align: left;\">&nbsp;</p>\r\n</figure>\r\n</div>\r\n<p class=\"MsoNormal\" style=\"text-align: left;\">&nbsp;</p>', 'http://twitter.com/MikeTyau ', 'http://miketyau.com/home.html', '', '', '0', '1476464275', NULL, NULL),
(44, 'Mary Franck', 'mary-franck', 'http://codame.dreamhosters.com/uploaded_images/mary-franck.png', '\r\n						<p class=\"MsoNormal\"><strong><a href=\"http://www.maryfranck.net/\" target=\"_blank\">Mary Franck</a> </strong></p>\r\n<p class=\"MsoNormal\">CODAME is excited to have Mary Franck involved with the show. Mary comes from a world of digital projection mapping and has a knack for making surfaces come alive. Mary’s recent work is primarily based in video, crafting luminous, dream-like environments. Mary is sure to show something that will be both beautiful and unsettling. Presently she is a resident artist at <a title=\"Million Fishes\" href=\"http://millionfishes.com/\" target=\"_blank\">Million Fishes Arts Collective</a> and an Interactive Art Engineer at <a href=\"http://obscuradigital.com/\" target=\"_blank\">Obscura Digital</a>.</p>\r\n<p class=\"MsoNormal\"><a href=\"http://codame.com/tickets\" target=\"_blank\">Get a ticket today</a> to make sure you don’t miss out on seeing her work.</p>\r\n											', '', 'http://www.maryfranck.net/', '', 'http://www.codame.com/post/portfolio/mary-franck-codame-featured-artist-codame-is/', '0', '', NULL, NULL),
(45, 'James Paterson (aka Presstube)', 'james-paterson-aka-presstube', 'http://codame.dreamhosters.com/uploaded_images/james-paterson-aka-presstube-.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/789ac258e14f4d09960dcd215f3d0fff2.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/38dc36297233b80de20ca784f1de3e422.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/c016bcbdaa5347d46c1404e1e4dc77bb2.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><strong><a href=\"http://www.presstube.com/\" target=\"_blank\">James Paterson</a> (aka <a href=\"http://twitter.com/presstube\" target=\"_blank\">Presstube</a>) &ndash; CODAME Featured Artist</strong></p>\r\n<p class=\"MsoNormal\">James has been creating art that mixes with technology for years. His art usually consist of surreal animated line drawings, often with an element of whimsy. James will be showing a longform animation compilation during CODAME, definitely something to keep you entertained as you sip on your tasty adult beverage.</p>\r\n<p>CODAME 2012 goes down OCT. 27, <a href=\"/tickets\" target=\"_blank\">grab a ticket</a> to receive our SOMA venue&rsquo;s exact address =)</p>', '', 'http://www.presstube.com/', '', 'http://www.codame.com/post/portfolio/james-paterson-aka-presstube-codame-featured/', '0', '', NULL, NULL),
(47, 'x612', 'x612', 'http://codame.dreamhosters.com/uploaded_images/x612.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"http://darkenergyradio.com/\" target=\"_blank\">x612</a> &ndash; CODAME featured Musician</strong></p>\r\n<p>mysterious force behind <a href=\"http://darkenergyradio.com/\" target=\"_blank\">DarkEnergyRadio</a>, Patrick HAF will provide you a deep dive into dark space, perfectly fitting vibes for the DIMENSION theme of this years CODAME. file under detroit/classic/electro.</p>\r\n<p>don&rsquo;t forget to <a href=\"/tickets\" target=\"_blank\">grab a ticket</a> as the exact location of the SOMA venue will be provided when you RSVP =)</p>', '', 'http://darkenergyradio.com/', '', '', '0', '1436747872', NULL, NULL),
(48, 'Fkir (Dream Shovel)', 'fkir-dream-shovel', 'http://codame.dreamhosters.com/uploaded_images/f-kir-dream-shovel-.jpg', '<div class=\"figure\" style=\"text-align: left;\">&nbsp;</div>\r\n<p><strong><a href=\"http://soundcloud.com/fkir\" target=\"_blank\">F&rsquo;kir (Dream Shovel)</a> &ndash; CODAME featured Musician</strong></p>\r\n<p>F&rsquo;kir Eldercake has been Djing on the West Coast for a decade, and producing music for almost as long. Specializing in music that is psychedelic, edge-pushing and heart-opening, his sets have brought magic to many occasion, and been a refreshing alternative to the same-same. F&rsquo;kir&rsquo;s first full-length album under the moniker Dream Shovel came out in spring of 2012 on False Profit Records.</p>\r\n<p>the CODAME 2012 party goes down OCT27, <a href=\"/tickets\" target=\"_blank\">grab a ticket</a> to recieve our SOMA venue&rsquo;s exact address =)</p>', '', 'http://soundcloud.com/fkir', '', 'http://www.codame.com/post/portfolio/fkir-dream-shovel-codame-featured-musician/', '0', '', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(49, 'Tadashi', 'tadashi', 'http://codame.dreamhosters.com/uploaded_images/tadashi.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"http://soundcloud.com/tadashibeats\" target=\"_blank\">Tadashi</a> &ndash; CODAME Featured Musician</strong></p>\r\n<p>Tadashi (Keith Kubota) is a beatmaker extraordinaire and self-proclaimed genius who is bringing his Ableton set to a CODAME party near you. He&rsquo;s also a member of Broken Figures with Denley (Matthew Holt), a band whose compositions lie comfortably situated between the work of their nineties boom bap production principals and contemporaries from the hulking beat crusades of LA and London.</p>\r\n<p>Want to hear more? You can.&nbsp;<a href=\"/tickets\" target=\"_blank\">Donate and register for party info</a>.</p>', '', 'http://soundcloud.com/tadashibeats', '', '', '0', '1436747889', NULL, NULL),
(50, 'Ian Heisters ', 'ian-heisters', 'http://codame.dreamhosters.com/uploaded_images/ian-heisters.gif', '<div><a href=\"http://heisters.co/\">Ian Heisters</a> uses dance, installation, and data as media for playing with issues around community, technology, and the body. His installations and performances have shown at local and national venues including Yerba Buena Center for the Arts, Crystal Bridges Museum, CounterPULSE, The Asian Art Museum, and The Berkeley Art Museum. In addition to his personal practice, Ian is a researcher and advisor specializing in performance, digital media, data visualization, and sensor systems for various projects with UC Berkeley, the open source community, and others. This research is complemented by teaching art, design, and programming at Gray Area Foundation for the Arts, and work on a range of commercial projects related to his artistic practice with The Sundance Institute, Stamen Design, Pivotal Labs, and Stimulant to name a few. A native of Northern California, he is based in Berkeley, California, where he tries to spend as much time as possible in the outdoors with his wife and son. &nbsp;</div>\r\n<div>&nbsp;</div>\r\n<div>Heisters and <a href=\"http://www.smithwymore.org/\">Disappearing Acts</a> will be performing&nbsp;0&crarr;&nbsp;on Saturday, October 24th during our <a href=\"/events/art-tech-festival-2015\">ART+TECH Festival MOVEMENT</a></div>\r\n<div>&nbsp;</div>\r\n<div><iframe src=\"//player.vimeo.com/video/38932088?title=0&amp;byline=0\" width=\"425\" height=\"350\"></iframe></div>\r\n<div>&nbsp;</div>\r\n<div><a href=\"http://heisters.co/\" target=\"_blank\">http://heisters.co</a>,&nbsp;<a href=\"http://www.smithwymore.org/\" target=\"_blank\">http://<wbr />www.smithwymore.org/</a></div>\r\n<div>&nbsp;</div>\r\n<div>&nbsp;</div>\r\n<div><img src=\"/uploaded_images/hashtag_zero_1_(1).jpg\" alt=\"\" /></div>\r\n<div>&nbsp;</div>\r\n<div>&nbsp;</div>\r\n<p class=\"MsoNormal\">&nbsp;</p>', '', 'http://heisters.co/', '', '', '0', '1445912247', NULL, NULL),
(51, 'Sekitani', 'sekitani', 'http://codame.dreamhosters.com/uploaded_images/sekitani.gif', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><strong><a href=\"http://www.wired.com/table_of_malcontents/2007/02/deviant_artist_/\" target=\"_blank\">Sekitani</a> &ndash; CODAME Featured Artist</strong></p>\r\n<p class=\"MsoNormal\">Sekitani takes the human form and manipulates it, skins it and re-imagines what it could be. A cross between a collage and a cadaver, Sekitani&rsquo;s work explores the textures of our bodies using what lies beneath our skin. For CODAME, Sekitani will be showing one of his animated collages, which might haunt you for the rest of the night. Don&rsquo;t say we didn&rsquo;t warn you!</p>\r\n<p>CODAME 2012 goes down OCT. 27, <a href=\"/tickets\" target=\"_blank\">grab a ticket</a></p>', '', 'http://www.wired.com/table_of_malcontents/2007/02/deviant_artist_/', '', '', '0', '1436747782', NULL, NULL),
(52, 'Superdeux', 'superdeux', 'http://codame.dreamhosters.com/uploaded_images/superdeux.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><a href=\"http://www.deux.me/\" target=\"_blank\">Superdeux</a> &ndash; CODAME Featured Artist</p>\r\n<p class=\"MsoNormal\">Superdeux is going to add a punch of color to CODAME. Sebastian Deux (aka Superdeux) is a Frenchmen living in SF. Superdeux has become known for his cute and playful character art, many characters having a French flair to them. Superdeux art is known to take many forms, from plastic figurines to animated shorts and everything between. Who knows what he&rsquo;ll be showing at CODAME.</p>\r\n<p class=\"MsoNormal\">See Superdeux&rsquo;s work in person on Oct. 27. <a href=\"http://codeme.com/tickets\" target=\"_blank\">Get a Ticket</a></p>\r\n<p class=\"MsoNormal\"><a href=\"https://twitter.com/superdeux\" target=\"_blank\">Follow Superdeux on Twitter</a></p>', 'https://twitter.com/superdeux', 'http://www.deux.me/', '', '', '0', '1436747796', NULL, NULL),
(53, 'Xavi Vives Riba', 'xavi-vives-riba', 'http://codame.dreamhosters.com/uploaded_images/xavi-vives-riba.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><strong><a href=\"https://twitter.com/xavivives\" target=\"_blank\">Xavi Vives Riba</a> &ndash; CODAME Featured Artist</strong></p>\r\n<p class=\"MsoNormal\">Xavi is a developer with an artistic eye. An inventor at heart, Xavi turned to code to see his experiments through. Xavi is working on something very cool for CODAME, mixing animations and music.</p>', 'https://twitter.com/xavivives', '', '', '', '0', '1436743735', NULL, NULL),
(54, 'ENC', 'enc', 'http://codame.dreamhosters.com/uploaded_images/e-n-cowell.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"http://encowell.bandcamp.com/\" target=\"_blank\">E.N.Cowell</a> &ndash; CODAME Featured Musician</strong></p>\r\n<div class=\"mhl\">Pulling off the tangled wires around his body, ENC was born into a room of smashed T.V.s, computers, and static. ENC was a digital ghost trapped in a human body. Come get your electro on at CODAME Oct 27th.</div>\r\n<p>Want to know the party location?&nbsp;<a href=\"/tickets\" target=\"_blank\">Grab a ticket</a>&nbsp;ASAP.</p>', '', 'http://encowell.bandcamp.com/', '', '', '0', '1436747798', NULL, NULL),
(55, 'Exit_Only', 'exit-only', 'http://codame.dreamhosters.com/uploaded_images/exit-only.jpg', '\r\n						<hr>\r\n<p><span>Exit_Only was birthed in winter/spring of 2002 in in the not-smelly part of New Jersey. After a number of demos, an EP, and countless shows, most of the members went their separate ways. But Nick </span><span>Inhofe has carried the the torch on in San Francisco and Oakland. Curious for undiscovered idm coder brain beats? You should be.</span></p>\r\n											', '', 'http://soundcloud.com/exit_only', '', 'http://www.codame.com/post/portfolio/exit-only-codame-featured-musician-exit-only/', '0', '', NULL, NULL),
(56, 'Extent of the Jam', 'extent-of-the-jam', 'http://codame.dreamhosters.com/uploaded_images/extent-of-the-jam.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"http://www.extentofthejam.com/\" target=\"_blank\">EXTENT OF THE JAM</a> &ndash; CODAME featured Musician</strong></p>\r\n<p>Louis Gorenfeld is an artist from San Francisco, CA specializing in hyperactive videogamic funk grooves and original sound design. He has been tracking jams since 1992, and continues the tradition to this day. Louis is also author of the DIGITS, a phase distortion synthesis VST!</p>', '', 'http://www.extentofthejam.com/', '', '', '0', '1436747828', NULL, NULL),
(165, 'Jonathon Keats', 'jonathon-keats', 'http://codame.dreamhosters.com/uploaded_images/jonathon-keats.jpg', '<p><strong style=\"box-sizing: border-box; color: #ffffff; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; background-color: #000000;\"><a style=\"box-sizing: border-box; color: #00a4a7 !important;\" title=\"Jonathon Keats\" href=\"https://en.wikipedia.org/wiki/Jonathon_Keats\" target=\"_blank\">Jonathon Keats</a></strong><span style=\"color: #ffffff; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; background-color: #000000;\">&nbsp;is an experimental philosopher, artist and writer. Exhibited at venues including the Berkeley Art Museum and the Wellcome Collection, his art projects have been documented by PBS, NPR, and the BBC World Service and covered in periodicals ranging from the New Yorker to the Economist to Nature. He is also the art critic for San Francisco Magazine, a visual arts columnist for Forbes.com, and most recently the author of &ldquo;Forged: Why Fakes Are the Great Art of Our Age&rdquo;, published this year by Oxford University Press. He is represented by Modernism Gallery in San Francisco. (Photo by Jen Dessinger).</span></p>', 'https://twitter.com/jonathonkeats', 'https://en.wikipedia.org/wiki/Jonathon_Keats', ' jonathonkeats@gmail.com', '', '0', '1440806648', NULL, NULL),
(57, 'Ryan Alexander', 'ryan-alexander', 'http://codame.dreamhosters.com/uploaded_images/ryan-alexander.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><strong><a href=\"http://onecm.com/\" target=\"_blank\">Ryan Alexander</a> &ndash; CODAME Featured Artist</strong></p>\r\n<p class=\"MsoNormal\">Ryan Alexander is one of those artists who really enjoys programming. Through a mix of data visualization and programs like processing, Ryan finds beauty hidden inside of code. He&rsquo;s created Chrome Experiments and given us a different perspective on the world. We can&rsquo;t wait to see what Ryan will create off the theme of Dimensions.</p>\r\n<p class=\"MsoNormal\"><a href=\"https://twitter.com/notlion\" target=\"_blank\">Follow Ryan on Twitter</a></p>', 'https://twitter.com/notlion', 'http://onecm.com/', '', '', '0', '1436747902', NULL, NULL),
(58, 'MUSHEN', 'mushen', 'http://codame.dreamhosters.com/uploaded_images/mushen.png', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"https://soundcloud.com/mushen\" target=\"_blank\">MUSHEN</a> &ndash; CODAME featured Musician</strong></p>\r\n<p>Mushen is 25-year-old sound arranger and recent SF resident Mushen. He began playing cello in utero, finishing his first five-movement concerto at age -3 months. He has produced styles ranging from breakcore (alter-alias Kallipolis) to wonky hip hop. Mushen is a veteran Renoise user and Max/MSP/Jitter patch maker. He is the creator and operator of the Creative Commons netlabel <a href=\"http://themrecords.com\" target=\"_blank\">THEM Records</a> alongside Manchester&rsquo;s Acidburp.</p>', '', 'https://soundcloud.com/mushen', '', '', '0', '1436747375', NULL, NULL),
(59, 'Elisa Sassi', 'elisa-sassi', 'http://codame.dreamhosters.com/uploaded_images/elisa-sassi.gif', '<div class=\"figure\"><strong>Elisa Sassi</strong>, known for cute bunny art, has teamed up with Perry Chan, code ninja, to create an experience that will be both fun and creative. Bunnies come to life in a multi-screen experience that overloads you with cuteness while wowing with a seemingly impossible feat of connecting art and mobile devices.&nbsp;</div>\r\n<div class=\"figure\">&nbsp;</div>\r\n<div class=\"figure\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/elisa-sassi-perry-chan1.jpg\" alt=\"\" /></div>\r\n<div class=\"figure\">&nbsp;</div>', 'https://twitter.com/elisasassi', 'http://www.elisasassi.com/', '', '', '0', '1485038994', NULL, NULL),
(60, 'Rollin Leonard', 'rollin-leonard', 'http://codame.dreamhosters.com/uploaded_images/rollin-leonard.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><strong><a href=\"http://rollinleonard.com/\" target=\"_blank\">Rollin Leonard </a>&ndash; CODAME Featured Artist</strong></p>\r\n<p class=\"MsoNormal\">Get ready to have your mind blown by the visuals created by Rollin Leonard. Rollin works in animation, but not how you would expect. He finds art in breaking the expected outcomes of a visual, tearing it down and building it up again as an abstract of the original. With a touch of humor and a touch of absurdity, Rollin is sure to keep you intrigued and guessing.</p>\r\n<p class=\"MsoNormal\"><a href=\"https://twitter.com/rollinleonard\" target=\"_blank\">Follow Rollin on Twitter &nbsp;</a></p>', 'https://twitter.com/rollinleonard', 'http://rollinleonard.com/', '', '', '0', '1436747391', NULL, NULL),
(166, 'Kate Sicchio', 'kate-sicchio', 'http://codame.dreamhosters.com/uploaded_images/kate-sicchio.jpg', '<p>Dr. Kate Sicchio is a choreographer, media artist and performer whose work explores the interface between choreography and technology. Her work includes performances, installations, web and video projects&nbsp;has been shown in Philadelphia, New York City, Canada, Germany, Australia, Belgium, and the UK at venues such as Banff New Media Institute (Canada), WAX Brooklyn (New York), FoAM (Brussels) and Arnolfini Arts Centre (UK).</p>\r\n<p>She has presented work at many conferences and symposia including International Society of Electronic Arts (ISEA), ACM Creativity and Cognition, Digital Research in Humanities and Arts, Congress On Research in Dance, and Society of Dance History Scholars. She has given invited talks at EU Parliament (Brussels), Node Code (Frankfurt), Real Time Visuals Conference (Newcastle), Datarama (Newcastle), Times Up (Linz), Thursday Club Goldsmiths (London), Griffith University (Brisbane) and University of the Arts (Philadelphia).</p>\r\n<p>Her PhD focused on the use of real-time video systems within live choreography and the conceptual framework of &lsquo;choreotopolgy&rsquo; a way to describe this work. Her research has been published by Leonardo Electronic Almanac, Computer Music Journal, Media N and Learning Performance Quarterly.</p>\r\n<p>Kate Sicchio has had extensive teaching experience within higher education. She has taught interactive technologies, choreography and many subjects in between to both undergraduate and masters level students. She is a visiting lecturer at University of Malta. She was most recently Senior Lecturer in Dance at University of Lincoln, Lincoln UK. She is currently adjunct faculty at Parsons The New School for Design in New York City.</p>\r\n<p><img src=\"/uploaded_images/HackingChoreo-3-1024x682.jpg\" alt=\"\" /></p>\r\n<p>\"Hacking the Body 2.0\" will be an exploration of live coded electronics and improvisational movement. A dancer wearing a custom garment of haptic actuators be accompanied by a live-coded score by the choreographer. The dancer will explore and interpret this live haptic feedback as a way of generating dance. This piece will explore the live coding of bodies and movement as output rather than a sonic or digital visual output as found in many live coding performances.</p>\r\n<p>Kate will be showcasing a new work \"Hacking the Body 2.0\" at this year\'s <a href=\"/events/art-tech-festival-2015\">ART+TECH Festival MOVEMENT</a>&nbsp;on October 23rd + 24th, 2015.</p>', 'http://twitter.com/sicchio', 'http://blog.sicchio.com/', '', '', '0', '1443657893', NULL, NULL),
(61, 'Subset', 'subset', 'http://codame.dreamhosters.com/uploaded_images/subset.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><strong>Subset &ndash; CODAME Featured Artist</strong></p>\r\n<p class=\"MsoNormal\">We just added another artist to the CODAME lineup. Subset is a group of media artists based in San Francisco, working in creative code, data visualization, and video. &nbsp;They provide live visuals to San Francisco&rsquo;s underground scene. At CODAME they&rsquo;ll stun you with awesome visuals as they VJ along with some of the musicians, all while you get your dance on and your mind blown.</p>\r\n<p>What else are you doing on Oct. 27? <a href=\"/tickets\" target=\"_blank\">Get a ticket.</a></p>', '', '', '', '', '0', '1436747397', NULL, NULL),
(62, 'Bad Unkl Sista', 'bad-unkl-sista', 'http://codame.dreamhosters.com/uploaded_images/bad-unkl-sista.jpg', '<div class=\"figure\">&nbsp;</div>\r\n<p class=\"MsoNormal\"><strong>Bad Unkl Sista &ndash; CODAME Featured Artist</strong></p>\r\n<p class=\"MsoNormal\">Unlike any performance art you&rsquo;ve ever seen, Bad Unkl Sista is a revolutionary physical theater performance ensemble that has been captivating audiences for over a decade with a unique fusion of music, movement, costuming, and theater. Dressed head-to-toe in white and using Butoh-based physical theater, the group of dancers move and interact with their surroundings. They&rsquo;re definitely going to add an extra element of surrealness to the entire evening.</p>', 'https://twitter.com/badunklsista/', 'http://badunklsista.com/', '', '', '0', '1632274171', '', ''),
(63, 'Keisuke Shingu aka VJ KSKA', 'keisuke-shingu-aka-vj-kska', 'http://codame.dreamhosters.com/uploaded_images/keisuke-shingu-aka-vj-kska.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><span class=\"vevent\"><span class=\"description\">Keisuke Shingu aka VJ KSKA &ndash; CODAME Featured Visual Artist</span></span></strong></p>\r\n<p><span class=\"vevent\"><span class=\"description\"><strong>Keisuke</strong><span class=\"fcg\">, Director of Software at <a href=\"http://www.miselu.com/\" target=\"_blank\">Miselu</a>, </span>visualizes the look and feel of what is happening on the dance floor in his abstract and stylish visuals. With his effective use of analogue controller and real time handling of motion graphics, VJ KSKA <strong>syncs</strong> the visuals with the dynamics of the music, building on the excitement generated by audiences.</span></span></p>\r\n<p><span class=\"vevent\"><span class=\"description\">He is the man behind visual art performance at Burning Man at Opulent Temple and Root Society. He is the man who worked with Moby, Kaskade, Avicii, Jay-Z &hellip; just to name a few. KSKA&rsquo;s innovative VJ style is true &ldquo;synesthesia&rdquo;, providing audiences with a totally new audio/visual experience.</span></span></p>\r\n<p><strong><span class=\"vevent\"><span class=\"description\">Meet VJ KSKA at our CODAME FASHION+MUSIC Event June 26th, 2013 from 7pm-2am at Public Works, San Francisco. <a href=\"http://codame-fashion-music.eventbrite.com/\" target=\"_blank\">Grab tickets now</a> to ensure entry, our last music event sold out!</span></span></strong></p>', '', 'http://www.miselu.com/', '', '', '0', '1436747414', NULL, NULL),
(64, 'James Morgan', 'james-morgan', 'http://codame.dreamhosters.com/uploaded_images/james-morgan.jpg', '                <div class=\"figure\">Â </div>\r\n<div class=\"figure\">James Morgan is an artist, educator and researcher. He has an MFA in Digital Media Art from the CADRE Laboratory for New Media. He is the director of Ars Virtua and has worked as a curator for ten years, and shown work nationally and internationally at venues such as 01SJ, ISEA, EMAF, Laguna Art Museum. His work revolves around social structures and coded culture in virtual environments. James\' recent works focuses on working with AI as expert collaborators.</div>\r\n<div class=\"figure\">Â </div>\r\n<div class=\"figure\">Â </div>              ', 'https://twitter.com/rubaiyat', 'http://www.rubaiyat.me/', '', '', '0', '1525189357', NULL, NULL),
(65, 'Kristen Turner', 'kristen-turner', 'http://codame.dreamhosters.com/uploaded_images/kristen-turner.png', '\r\n						<div class=\"figure\"></div>\r\n<p>CODAME Featured Speaker<strong><br>\r\n</strong></p>\r\n<p>Kristen is CMO of <a href=\"https://www.ponoko.com\" target=\"_blank\">Ponoko</a>, an online laser cutting and 3D printing service based in the Bay Area. She’s presented talks on 3D Printing at BarCamp Miami, Girls in Tech Minneapolis, and <a href=\"http://blog.ponoko.com/2011/06/02/how-digital-fabrication-is-democratizing-product-design/\" target=\"_blank\">RAPID</a>. Photo: Ponoko project from Chicago based artist <a href=\"http://blog.ponoko.com/2012/04/19/3d-printing-as-an-art-form/\" target=\"_blank\">Sophie Kahn</a>.<a href=\"http://www.jennyebalisle.com/\" target=\"_blank\"><br>\r\n</a></p>\r\n<p><strong>Meet Kristen </strong><strong><strong>at our <a href=\"http://codame.com/post/44382868990/3dprinting\" target=\"_blank\">CODAME 3D PRINTING Event</a> </strong>May 1, 2013 from 6-9pm </strong><strong><strong><span class=\"pipe\">at </span>Adobe, San Francisco.</strong></strong></p>\r\n<div><a href=\"http://codame.com/post/44382868990/3dprinting\" target=\"_blank\"><img src=\"http://codame.com/wp-content/uploads/2013/11/40e9a1c6fd89a41f03c03bb9cb914d6d.jpg\" alt=\"\"></a></div>\r\n											', '', 'https://www.ponoko.com', '', 'http://www.codame.com/post/portfolio/kristen-turner-codame-featured-speaker-kristen/', '0', '', NULL, NULL),
(66, 'Michael Amundsen', 'michael-amundsen', 'http://codame.dreamhosters.com/uploaded_images/michael-amundsen.jpg', '\r\n						<p>CODAME Featured Artist</p>\r\n<p><a href=\"http://michaelamundsen.com/portfolio/about.html\" target=\"_blank\">Michael Amundsen</a> is a graduating BFA student studying Digital Media Arts and Cultural Anthropology, with the CADRE Laboratory for New Media at San Jose State University. His current work revolves around social interactions in Minecraft and CNC fabrication. More information about his project on <a href=\"http://arsvirtua.com/v2v/\" target=\"_blank\">http://arsvirtua.com/v2v/</a></p>\r\n<p><strong>Meet </strong><strong><strong>Michael</strong> </strong><strong><strong>at our <a href=\"http://codame.com/post/44382868990/3dprinting\" target=\"_blank\">CODAME 3D PRINTING Event</a> </strong>May 1, 2013 from 6-9pm </strong><strong><strong><span class=\"pipe\">at </span>Adobe, San Francisco.</strong></strong></p>\r\n<p><img src=\"http://codame.com/wp-content/uploads/2013/11/3d65ce45009f13ecf81b3a605c8e9e9b.png\" alt=\"\"></p>\r\n											', '', 'http://michaelamundsen.com/portfolio/about.html', '', 'http://www.codame.com/post/portfolio/michael-amundsen-codame-featured-artist/', '0', '', NULL, NULL),
(67, 'Stefano Corazza', 'stefano-corazza', 'http://codame.dreamhosters.com/uploaded_images/stefano-corazza.jpg', '\r\n						<div class=\"figure\"></div>\r\n<p>CODAME Featured Artist</p>\r\n<p><a href=\"https://twitter.com/stefano001\" target=\"_blank\">Stefano Corazza</a> is an entrepreneur and interactive installation artist. He holds a M.Sc. in Design, a PhD in mechanical engineering and a PhD in bioengineering. Former paragliding test-pilot, he spent four years as Researcher at Stanford Biomotion Lab prior to starting <a href=\"http://www.mixamo.com/\" target=\"_blank\">Mixamo</a>, the world’s first online 3D character animation service where he serves as CEO. His most recent works include producing a video for Björk’s album Biophilia and the [I am bird] interactive 3D experience shown as permanent installation at the Nature&Science Museum in Dallas.</p>\r\n<p>Photo from 4D Printing: Multi-Material Shape Change: MIT 2013</p>\r\n<p><strong>Meet </strong><strong><strong>Stefano</strong> </strong><strong><strong>at our <a href=\"http://codame.com/post/44382868990/3dprinting\" target=\"_blank\">CODAME 3D PRINTING Event</a> </strong>May 1, 2013 from 6-9pm </strong><strong><strong><span class=\"pipe\">at </span>Adobe, San Francisco.</strong></strong></p>\r\n<div><img src=\"http://codame.com/wp-content/uploads/2013/11/db1ac6cec4c869544a0d540291b52903.jpg\" alt=\"\"></div>\r\n											', 'https://twitter.com/stefano001', 'http://www.mixamo.com/', '', 'http://www.codame.com/post/portfolio/stefano-corazza-codame-featured-artist-stefano/', '0', '', NULL, NULL),
(68, 'Natacha Merrit', 'natacha-merrit', 'http://codame.dreamhosters.com/uploaded_images/natacha-merrit.jpg', '<div class=\"figure\">CODAME Featured Artist</div>\r\n<p>An accomplished artist and producer, <a href=\"http://www.digitalgirly.com/\" target=\"_blank\">Natacha Merrit </a>was ready for a new challenge and soon developed a passion for biology, \"the ultimate exploration of life,\" she says. She returned to higher education in 2005 to study biology at the San Francisco State University, specialising in Biodiversity and Evolutionary Biology.</p>\r\n<p>In 2008, while deep in her studies of biology, she wrote an \"insect circus\" inspired by her observations of the insect world and celebrating the importance of biodiversity. She licensed the rights to Cirque du Soleil and the circus became OVO, still touring. Merritt\'s recent work highlights how our morphologies are intimately linked to other species through shared and convergent evolution. While proposing a new feminist stance, Merritt incorporates scientific insights with her artistic practice. Her new work unveils an untapped sexual beauty and eroticism hidden within all species.</p>\r\n<p><strong>Meet </strong><strong><strong>Natacha</strong> </strong><strong><strong>at our <a href=\"/post/44382868990/3dprinting\" target=\"_blank\">CODAME 3D PRINTING Event</a> </strong>May 1, 2013 from 6-9pm </strong><strong><strong><span class=\"pipe\">at </span>Adobe, San Francisco.</strong></strong></p>\r\n<p><img src=\"/wp-content/uploads/2013/11/77bd76f79c7cc04b3c36bbe5d4ab5982.png\" alt=\"\" /></p>', '', 'http://www.digitalgirly.com/', '', '', '0', '1470439021', NULL, NULL),
(69, 'Linda Franco', 'linda-franco', 'http://codame.dreamhosters.com/uploaded_images/linda-franco.jpg', '\r\n						<hr>\r\n<p><a href=\"http://twitter.com/LindaLFranco\" target=\"_blank\">Linda Franco</a> – CODAME Featured Fashiontech Industry Insider</p>\r\n<p>Linda Franco, entrepreneurial tech-fashionista, started out studying marketing and strategic design at Centro University in Mexico City. Shortly after, she co-founded The Gyzu Experiement, a web design and development firm,  and alongside this she set up the Plan de Escape prison project which taught male inmates the ins and outs of fashion and trends with the end goal of creating their own fashion label. As for her current projects at <a href=\"http://www.machina.cc/\" target=\"_blank\">Machina Wearable Technology</a>, Linda and her team are taking the industry to the next level with the idea of open source in wearable tech. She is on a cutting edge when it comes to creating interactive wearable tech design that can be worn by anyone, in consideration with its aesthetics and functionality.</p>\r\n<p>Linda will present her current project with <a href=\"http://www.machina.cc/\" target=\"_blank\">Machina Wearable Technology</a>, <a href=\"http://www.kickstarter.com/projects/machina/midi-controller-jacket-v01\" target=\"_blank\">MIDI Controller Jacket v1.0</a>. This jacket allows the user to create music through motion and touch sensors with a mobile app. Linda and her team spent months on research to have the perfect fabrics, that could later interact organically with the chosen technology, the design being functional for the user, and visual identity of a product being appealing to aspiring musicians, fashionistas, and people who like cool lifestyle stuff. Welcome to ORGANICISM, DIGITALIZED GLOBAL BRAIN.</p>\r\n<p><strong>Meet Linda and her team at our <a href=\"http://codame.com/post/47176875119/fashion\" target=\"_blank\">CODAME FASHION+TECH Event</a> June 26th, 2013 from 7pm-2am at Public Works, San Francisco.</strong></p>\r\n<div><img class=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/98af9b3233813106bde807f517b775501.jpg\" alt=\"\" width=\"799\" height=\"948\"></div>\r\n											', 'http://twitter.com/LindaLFranco', '', '', 'http://www.codame.com/post/portfolio/linda-franco/', '0', '', NULL, NULL),
(70, 'Tiffany Trenda', 'tiffany-trenda', 'http://codame.dreamhosters.com/uploaded_images/tiffany-trenda.jpg', '<div>\r\n<div>\r\n<p><a href=\"http://tiffanytrenda.com/\">Tiffany Trenda</a> is a new media performance artist based out of Los Angeles and New York. She received her BFA from Art Center College of Design and her MFA from the University of California Los Angeles, Design and Media Arts program. Trenda won Artist of the Year at the London International Creative Competition Awards and introduced the work, \"Entropy\" at the Los Angeles County Museum of Art.&nbsp; She was invited to perform at the 2010 World\'s Expo, in Shanghai, China at the Heatherwick designed British Pavilion. She also exhibited at Art Hamptons, A+D Museum, Scope Art Fair,&nbsp;Los Angeles Contemporary Art Exhibitions, Boulder Contemporary Art Museum, the Italian Cultural Institute, and Art Miami Context, where she graced the cover of the Miami Herald for the first image of Art Basel 2012. Trenda was included in the performance program at the Metamorphoses of the Virtual&nbsp;&ndash; 100 Years of Art and Freedom during the 55th annual Venice Biennale. More recently, Trenda lectured at the 3D Printshow in New York,&nbsp;exhibited at the Faena Art Center in Buenos Aires, and introduced Ubiquitous States as a special project for Context Art Miami 2015.&nbsp;</p>\r\n<p><img src=\"/uploaded_images/tiffany-trenda1.jpg\" alt=\"\" /></p>\r\n</div>\r\n</div>\r\n<p>Photo (top):&nbsp;<span style=\"font-family: Helvetica; font-size: 12px; text-align: -webkit-auto;\">Tiffany Trenda Ubiquitous States Performance Art with 3D printed pieces, 2015</span></p>\r\n<p><span style=\"font-family: Helvetica; font-size: 12px; text-align: -webkit-auto;\"><img src=\"/uploaded_images/tiffanytrendawhite.jpg\" alt=\"\" />Tiffany Trenda, Body Code, Performance Art with QR codes at Context Art Miami, 2012</span></p>\r\n<div style=\"word-wrap: break-word;\">\r\n<div style=\"font-size: 12px; font-family: Helvetica; text-align: -webkit-auto;\"><img src=\"/uploaded_images/tiffanytrendared.jpg\" alt=\"\" />Tiffany Trenda, Proximity Cin&eacute;ma in The Black Forest, Performance Art with Touch Screens, 2013</div>\r\n<div style=\"font-size: 12px; font-family: Helvetica; text-align: -webkit-auto;\">&nbsp;</div>\r\n<div style=\"font-size: 12px; font-family: Helvetica; text-align: -webkit-auto;\"><strong>Tiffany will be exhibiting work at our <a href=\"http://festival.codame.com/\">INTERFACE Art+Tech Festival</a> running October 5-8th, 2016 at Fort Mason.</strong></div>\r\n</div>\r\n<div>&nbsp;</div>', 'https://twitter.com/tiffanytrenda', 'http://tiffanytrenda.com/', 'tiffany@tiffanytrenda.com ', '', '0', '1460782582', NULL, NULL),
(190, 'Behnaz Farahi ', 'behnaz-farahi', 'http://codame.dreamhosters.com/uploaded_images/behnaz-farahi.gif', '<p><a href=\"http://www.behnazfarahi.com/\">Behnaz Farahi</a> is an architect, and interaction designer, exploring the potential of interactive environments and their relationship to the human body. In particular she is interested in the implementation of emerging technologies in contemporary art/architecture practice. Her goal is to enhance the relationship between human beings and the built environment by implementing design/motion principles inspired by natural systems. Application areas include architecture, fashion and interaction design. She also specializes in additive manufacturing and robotic technologies.&nbsp;<br /><br />Her work has been exhibited internationally in USA, Canada and China, and has been featured in several magazines and online websites including WIRED, The Guardian, BBC, CNN, Motherboard, Dezeen, Frame Magazine, the Creator Project and many more. Behnaz Farahi has won several awards including first prize for the Kinetic Art Organization in 2013, first prize for the best student work at ACADIA conference in 2014, and an honorable mention at Beyond: Pavilion of Innovation in Barcelona in 2015. She is also the recipient of the Madworkshop Grant and the Rock Hudson Fellowship.&nbsp;<br /><br />Behnaz Farahi has worked with leading firms such as Autodesk, Fuksas Studio, and 3DSystems/ will-i-am. She has also collaborated with Professor Behrokh Khoshnevis on two NASA funded research projects developing a robotic fabrication technology to 3D print structures on the Moon and Mars.&nbsp;</p>\r\n<p>She was an Artist in Residence at Autodesk, Pier 9, and is an Annenberg Fellow and PhD candidate in Interdisciplinary Media Arts and Practice at USC School of Cinematic Arts. She has an Undergraduate and two Masters degrees in Architecture.</p>\r\n<p><img src=\"/uploaded_images/behnazprofile.jpg\" alt=\"\" /></p>\r\n<p>&nbsp;<img src=\"/uploaded_images/behnazgazesmall.jpg\" alt=\"\" /></p>', '', 'http://www.behnazfarahi.com/', 'farahibo@gmail.com ', '', '0', '1455679161', NULL, NULL),
(71, 'HUMANIMAL', 'humanimal', 'http://codame.dreamhosters.com/uploaded_images/humanimal.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"https://soundcloud.com/humanimalmusic\" target=\"_blank\">HUMANIMAL</a> &ndash; CODAME Featured Musician</strong></p>\r\n<p>A favorite from our Oct. 2012 event, HUMA&Omega;IM&#8710;L returns to CODAME to unleash his <em>pre- post-apocalyptic maximalist tech-step</em> after the presentations at our FASHION+MUSIC Event June 26th, 2013 from 7pm-2am at Public Works, San Francisco.</p>\r\n<p><strong><a href=\"http://codame.eventbrite.com/\" target=\"_blank\">Grab tickets now</a> to ensure entry, our last music event sold out!</strong></p>', '', 'https://soundcloud.com/humanimalmusic', '', '', '0', '1436747302', NULL, NULL),
(72, 'CSTNG-SHDWS', 'cstng-shdws', 'http://codame.dreamhosters.com/uploaded_images/cstng-shdws.png', '<p><iframe src=\"http://player.vimeo.com/video/26610039\" width=\"400\" height=\"225\" frameborder=\"0\"></iframe></p>\r\n<div class=\"caption clearfix rte\">\r\n<p><strong><a href=\"http://cstng-shdws.com/\" target=\"_blank\">CSTNG-SHDWS</a> &ndash; CODAME Featured Video Artists</strong></p>\r\n<p>CSTNG-SHDWS are Justin Metros &amp; Colin Evoy Sebestyen, two video artists who reside in San Francisco, California.</p>\r\n<p>Their work combines the immediacy of live performance with the multidisciplinary study of design, animation, and code. They utilize strong influences from visual communication systems, typography, video artifacts, and music.</p>\r\n<p>C-S will be performing live visuals alongside our featured musicians at our CODAME FASHION+MUSIC Event June 26th, 2013 from 7pm-2am at Public Works, San Francisco.</p>\r\n<p><strong><a href=\"http://codame.eventbrite.com/\" target=\"_blank\">Grab tickets now</a> to ensure entry, our last music event sold out!</strong></p>\r\n</div>\r\n<div>&nbsp;</div>', '', 'http://cstng-shdws.com/', '', '', '0', '1436747309', NULL, NULL),
(73, 'Yumi Tanaka', 'yumi-tanaka', 'http://codame.dreamhosters.com/uploaded_images/yumi-tanaka.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><a href=\"http://www.artbyyumika.com/\" target=\"_blank\"><strong>Yumika Tanaka</strong></a> &ndash; CODAME Featured Artist</p>\r\n<p>Yumika created<span class=\"apple-converted-space\">&nbsp;</span><em>We Are What We Wear Series<span class=\"apple-converted-space\">&nbsp;</span></em>through the integration of materials and techniques from both old and new. I thus transformed the typical form of the kimonos through the sensory data of a new technological environment, creating contemporary, electronically embodied kimonos.</p>\r\n<p class=\"MsoNormal\">LEDs are programmed with Arduino to play three different traffic conditions randomly that run on a loop of 10 minutes in duration.</p>\r\n<p class=\"MsoNormal\">Title: We are what we wear.</p>\r\n<p><em>Medium: </em>Black Kimono Installation, fabric, thread, paper, and micro-controlled LEDs.</p>\r\n<p>Size: 2012, 75&rdquo; x 169&rdquo; x 5&rdquo; (Width Varies) &ndash; Software/Developer/Company: Arduino &ndash; Contributor: Marek Kapolka (Programmer)</p>\r\n<p class=\"MsoNormal\">Meet Yumika and check her work at <a href=\"http://codame.eventbrite.com/\" target=\"_blank\">CODAME FASHION+MUSIC </a>Event</p>\r\n<p><strong>When: </strong>Wednesday, June 26, 2013 from 7:00 PM to 2:00 AM (Next Day)</p>\r\n<p><strong>Where: </strong><a href=\"http://publicsf.com/\" target=\"_blank\">The Public Works SF</a> 161 Erie St, San Francisco, CA&nbsp; <a href=\"https://maps.google.com/maps?q=Public+Works,+Erie+St,+San+Francisco,+CA+94103&amp;hl=en&amp;sll=37.768963,-122.419461&amp;sspn=0.010924,0.022724&amp;oq=public+wor161+Erie+St+San+Francisco,+CA+94103&amp;t=h&amp;gl=us&amp;hq=Public+Works,&amp;hnear=Erie+St,+San+Francisco,+California+94103&amp;z=15&amp;iwloc=A\" target=\"_blank\">(map)</a></p>\r\n<p class=\"MsoNormal\"><em><strong>RSVP</strong>: on <a href=\"http://codame.eventbrite.com/\" target=\"_blank\">Eventbrite</a></em></p>', '', 'http://www.artbyyumika.com/', '', '', '0', '1436747320', NULL, NULL),
(74, 'Jon Kuzmich', 'jon-kuzmich', 'http://codame.dreamhosters.com/uploaded_images/jon-kuzmich.jpg', '\r\n						<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/11a4c22213ee96ad366e67178590f5211.jpg\"></figure>\r\n</div>\r\n<p><strong><a href=\"http://www.jonkuzmich.com/\" target=\"_blank\">Jon Kuzmich</a> – CODAME Featured Artist<br> </strong></p>\r\n<p>As an artist, Jon creates labor and process-intensive visual systems that involve the conceptually driven organization of small, synthetic units into large and complex patterns.</p>\r\n<p>His work is often inspired by the fact that our perception as human beings is altered and distorted by our belief in systems that we create (religious, economic, scientific, etc.). By virtue of this distortion, systems change our relationship to the world, manipulate our understanding of reality and influence our relationship to the cosmos. In essence, our belief systems keep us confined within a synthetic, human-created world.</p>\r\n<p>Therefore, even though Jon utilizes Op-art, abstraction and conceptual art, He considers my work to be representational because the visual systems he creates alter the perception of the viewer and illustrate that what we see and what we know are questionable.</p>\r\n<p>Meet Jon and see his new work at the <a href=\"http://codame.com/post/52877021929/roll-up-gallery-and-codame-art-tech-will-present\" target=\"_blank\"><strong>“Art by Code” </strong></a>Gallery Opening the same evening of the <strong><a href=\"http://codame.com/post/47176875119/fashion\" target=\"_blank\">CODAME FASHION+MUSIC</a> </strong>Event.</p>\r\n											', '', 'http://www.jonkuzmich.com/', '', 'http://www.codame.com/post/portfolio/jon-kuzmich/', '0', '', NULL, NULL),
(75, 'Nolan Love', 'nolan-love', 'http://codame.dreamhosters.com/uploaded_images/nolan-love.jpg', '\r\n						<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"\"></figure>\r\n</div>\r\n<p><strong><a href=\"https://twitter.com/nolanlove\" target=\"_blank\">Nolan Love</a> – CODAME Featured Artist</strong></p>\r\n<div class=\"post_body\">Nolan Love is a Bay Area visual artist and web entrepreneur. Originally from NH, Love came to SF in 1999 by way of a stint in the Peace Corps in Guinea, West Africa.  This piece – a mosaic portrait of a baby born to his host family in Guinea – renders a subject from the rural, low-tech, developing world using high-tech virtual tools and urban materials.  Love is interested in the emergent properties of ordered systems, the different meanings that exist at different scales, and the tension between them.  Balancing this order are impermanence and entropy, achieved here with movable magnets.Meet Nolan and check his work at the <a href=\"http://codame.com/post/52877021929/roll-up-gallery-and-codame-art-tech-will-present\" target=\"_blank\"><strong>“Art by Code” </strong></a>Gallery Opening the same evening of the <a href=\"http://codame.com/post/47176875119/fashion\" target=\"_blank\">CODAME FASHION+MUSIC</a> Event.</div>\r\n											', 'https://twitter.com/nolanlove', '', '', 'http://www.codame.com/post/portfolio/nolan-love-codame-featured-artist-nolan-love-is/', '0', '', NULL, NULL),
(76, 'Wes Grubbs', 'wes-grubbs', 'http://codame.dreamhosters.com/uploaded_images/wes-grubbs.jpeg', '<div>Founder of data visualization studio Pitch Interactive, technologist, futurist, data artist, traveler, provocateur and aspiring mountaineer. Wesley Grubbs takes overwhelming data sets and turns them into beautiful, easy to understand visuals. His work varies from designs, to user interfaces, to infographics, but there is generally one common thread of political activism underlying it all. Knowing how well he can work with data, we\'re excited what Wesley decides to visualize for CODAME.</div>\r\n<div>&nbsp;</div>\r\n<div>Wes runs Pitch Interactive, a data visualization studio focusing on using new technologies to address complex data. Their work spans illustrations, physical installations, projections, console game user interfaces, software applications, websites and textiles directly with clients Google, Scientific American, The Southern Poverty Law Center, Mozilla, Facebook, eBay, IBM, Dow Jones, GE, The North Face, Propublica, Time Magazine, Twitter, The Wall Streen Journal, Wired Magazine, YouTube and more. Their work has been showcased at San Francisco&rsquo;s Yerbe Buena Ars Center&rsquo;s Bay Area Activism exhibit (2016), Fotofest Sensors exhibit, Houston, Texas (2015), Data Drift exhibit at RIXC The Center for New Media Culture, Riga, Latvia (2015), Tomas Van Houtryve - Blue Sky Days exhibit at the Bayeux awards for War Correspondents Festival, Bayeux, France (2015), Talk to Me at the Museum of Modern Art, New York (2011), Conversations &Eacute;lectriques at La Panac&eacute;e, Montpellier, France (2011), the McKnight Artist Fellowship program&rsquo;s 30th anniversary exhibition, Minneapolis, Minnesota (2012), The Art of Networks, Foosaner Art Museum, Melbourne, Florida (2012), and The Max Planck Science Express Train, Munich (2009) the Data Flow books and many other internationally acclaimed publications.&nbsp;</div>\r\n<div>&nbsp;</div>\r\n<div style=\"text-align: center;\"><img src=\"/uploaded_images/wes-grubbs-small.png\" alt=\"\" /></div>', 'https://twitter.com/wesleygrubbs', 'https://pitchinteractive.com', '', '', '0', '1564529613', NULL, NULL),
(77, 'Cory Barr', 'cory-barr', 'http://codame.dreamhosters.com/uploaded_images/cory-barr.gif', '<hr />\r\n<p>Anticlockwise Arts Co-founder, composer, scientist, programmer. Cory spends his days working on interactive systems, telling stories with data, and exploring modern technology as an artistic medium. Notable pieces he has contributed to include&nbsp;<a href=\"http://www.anticlockwisearts.com/projects/watercolor-walls/\" target=\"_blank\">Watercolor Walls</a>,&nbsp;<a href=\"http://www.anticlockwisearts.com/projects/unearthed/\" target=\"_blank\">Unearthed</a>,&nbsp;<a href=\"http://www.anticlockwisearts.com/projects/sandbox-world/\" target=\"_blank\">Sandbox World</a>, and&nbsp;<a href=\"http://www.syzygryd.com/photos-and-videos/\" target=\"_blank\">Syzygryd</a>. His artwork has been featured at the&nbsp;<a href=\"http://www.calacademy.org/\" target=\"_blank\">California Academy of Sciences</a>,&nbsp;<a href=\"http://www.ybca.org/\" target=\"_blank\">Yerba Buena Center for the Arts</a>, and other festivals and venues. Cory holds a Masters in Computer Science from Stanford and a Masters in Music Theory from the University of Oklahoma.</p>\r\n<p>About&nbsp;<a href=\"http://www.anticlockwisearts.com/\" target=\"_blank\">Anticlockwise Arts</a>:&nbsp;A group of artists, scientists, dancers, musicians, and engineers. We push the boundaries of traditional performances and everyday experiences through cutting-edge technology.</p>\r\n<p>Catch Anticlockwise work &ldquo;<em>Realtime data visualisation of cyber attacks.&rdquo;</em> at CODAME ART+TECH Friday Oct. 31st, at Geekdom &ndash; 620 Folsom St., San Francisco</p>\r\n<p>&nbsp;</p>', '', 'http://www.anticlockwisearts.com/', '', '', '0', '1436747150', NULL, NULL),
(230, 'Phil Spitler', 'phil-spitler', 'http://codame.dreamhosters.com/uploaded_images/phil-spitler.jpeg', '<p>&nbsp;</p>\r\n<p class=\"p1\"><span class=\"s1\">Phil Spitler is a Creative Technologist for Bonfire Labs in San Francisco. He has almost 20 years experience as a motion graphics and visual effects artist. Phil\'s work combines both art and technology, using software and computer controlled tools to make both on screen and physical art.</span></p>', '', 'http://www.philspitler.com', 'phil@bonfirelabs.com', '', '0', '1478630648', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(78, 'Dan Moore', 'dan-moore', 'http://codame.dreamhosters.com/uploaded_images/dan-moore.jpg', '<div class=\"figure\">\r\n<p dir=\"ltr\" style=\"line-height: 1.38; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 10.5pt; font-family: \'Open Sans\', sans-serif; color: #ffffff; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\">Dan Moore is a New York City based Artist,&nbsp; Designer and Technologist currently working at Samsung&rsquo;s Global UX Studio.&nbsp; As a member of the studio, Moore strives to fulfill the studio&rsquo;s mission to Bring Joy To Everyday Experiences by redefining the future of Samsung&rsquo;s mobile ecosystem.&nbsp;&nbsp;</span></p>\r\n<p><span style=\"color: #ffffff;\"><strong id=\"docs-internal-guid-31c080bc-7fff-a571-7afa-1a1d27cd2e61\" style=\"font-weight: normal;\">&nbsp;</strong></span></p>\r\n<p dir=\"ltr\" style=\"line-height: 1.38; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 10.5pt; font-family: \'Open Sans\', sans-serif; color: #ffffff; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\">Prior to joining Samsung,&nbsp; Moore led the Web Concepts Team at Squarespace. The Web Concepts team produced conceptual, experimental work. The team built the nearly impossible, with the hope of uncovering the inevitable. The team took their ideas from hypothesis to prototype using experimentation, and incorporate successful projects into Squarespace&rsquo;s own websites, products, and partnership sites.&nbsp;&nbsp;</span></p>\r\n<p><span style=\"color: #ffffff;\"><strong style=\"font-weight: normal;\">&nbsp;</strong></span></p>\r\n<p dir=\"ltr\" style=\"line-height: 1.38; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 10.5pt; font-family: \'Open Sans\', sans-serif; color: #ffffff; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\">As a Freelancer or as a Lead Creative at the Experiential Agency Fake Love, Dan contributed to award-winning interactive installations for Acura, Google,&nbsp; Lexus, Levi\'s, Master &amp; Dynamic, Microsoft, Samsung, SONOS, YouTube.&nbsp; He has worked with the recording artists Broods, HXXS, Liars, and Rabit.&nbsp; He has contributed to works owned and on display at Deutsche Bank and Google.&nbsp; He has consulted on R&amp;D projects for Google, the Google Creative Lab, Microsoft, Samsung, and TEAGUE.&nbsp; He has created and contributed to works under the direction of or in collaboration with Golan Levin, Zach Lieberman, Theo Watson, Blair Neil, Kyle McDonald, Madeline Gannon, and others.&nbsp; His work has been in many publications including Architectural Digest, Communication Arts, the Verge, VICE,&nbsp; Fast Co., Creativity, PSFK and Adweek.&nbsp; He has contributed to projects featured at Ars Electronica, IDFA, Hot Docs, South by South West, Sundance,&nbsp; Sonar+D, Tribeca Interactive Film Festival, and Toronto International Film Festivals.</span></p>\r\n<p><span style=\"color: #ffffff;\"><strong style=\"font-weight: normal;\">&nbsp;</strong></span></p>\r\n<p dir=\"ltr\" style=\"line-height: 1.38; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 10.5pt; font-family: \'Open Sans\', sans-serif; color: #ffffff; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\">Dan attended Rochester Institute of Technology for Computer Engineering but dropped out.&nbsp; He holds a Masters of Tangible Interaction Design from Carnegie Mellon University&rsquo;s School of Architecture.&nbsp; While pursuing his Master&rsquo;s at CMU, Moore studied: Interaction, Media, Video Game, Experimental Game, and Virtual-Reality, Design.&nbsp; His master&rsquo;s thesis is titled the Fundamental Design Principles of Virtual-Reality: Reinforcing Presence through the manipulation of Space, Distance, and Gaze.&nbsp; Dan has contributed to several open source graphics projects including openFrameworks.&nbsp;&nbsp;</span></p>\r\n<p><span style=\"color: #ffffff;\"><strong style=\"font-weight: normal;\">&nbsp;</strong></span></p>\r\n<p dir=\"ltr\" style=\"line-height: 1.38; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 10.5pt; font-family: \'Open Sans\', sans-serif; color: #ffffff; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\">Dan&nbsp; Moore is a Free Art and Technology Lab Virtual Research Fellow and writes code and makes art at a place called Fake Love.</span></p>\r\n<p><span style=\"color: #ffffff;\"><strong style=\"font-weight: normal;\">&nbsp;</strong></span></p>\r\n<p dir=\"ltr\" style=\"line-height: 1.38; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 10.5pt; font-family: \'Open Sans\', sans-serif; color: #ffffff; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\">checkout:@scratchML# MakeItDoAThing #TopDeveloperStatus from New York makeitdoathing.com</span></p>\r\n<p><span style=\"color: #ffffff;\"><strong style=\"font-weight: normal;\">&nbsp;</strong></span></p>\r\n<p dir=\"ltr\" style=\"line-height: 1.38; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 10.5pt; font-family: \'Open Sans\', sans-serif; color: #ffffff; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\">@theDANtheMAN</span></p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\" style=\"line-height: 1.38; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 10.5pt; font-family: \'Open Sans\', sans-serif; color: #ffffff; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\">Slitscan photobooth will capture your twisted existence for internet and offline consumption.@DEFCON x CODAME</span></p>\r\n</div>', 'https://twitter.com/theDANtheMAN', 'http://makeitdoathing.com/', '', '', '0', '1602989225', '', NULL),
(79, '&#625;&#616;&#409;&#589;&#8635;&#575;&#8634;&#421;&#615;&#427; &#20814;', '625-616-409-589-8635-575-8634-421-615-427-20814', 'http://codame.dreamhosters.com/uploaded_images/625-616-409-589-8635-575-8634-421-615-427-20814.png', '<div>\r\n<figure><img alt=\"\" /></figure>\r\n</div>\r\n<div>\r\n<figure><img src=\"http://www.codame.com/wp-content/uploads/2013/07/screenvortex.gif\" alt=\"\" /></figure>\r\n<figure><img src=\"/wp-content/uploads/2013/11/259363d7c8ddcfff50849190120a1c9c.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div>\r\n<figure><img src=\"/wp-content/uploads/2013/11/7fbe8f5fbe028d4b2027d901cc65226c.png\" alt=\"\" /></figure>\r\n</div>\r\n<p><img src=\"/wp-content/uploads/2013/11/30cf113e71c96101ff9a67b855a52bcb.gif\" alt=\"\" /></p>\r\n<p><a href=\"http://dreamalias.com\" target=\"_blank\">&#625;&#616;&#409;&#589;&#8635;&#575;&#8634;&#421;&#615;&#427; &#20814;</a>&nbsp;&ndash; CODAME Featured Artist</p>\r\n<div>\r\n<p>&ldquo;&hellip;from outer space&hellip;videos, bunny costume, &amp; skateboarding cross-country&hellip;Ben is one of the weirdest people I know, and I mean that as a huge compliment.&rdquo; &mdash; <a href=\"https://twitter.com/djqbot\" target=\"_blank\" rel=\"nofollow\">@djqbot</a></p>\r\n</div>\r\n<p>Come out to Vegas to celebrate, play and hack&nbsp;&#625;&#616;&#409;&#589;&#8635;&#575;&#8634;&#421;&#615;&#427; &#20814;&rsquo;s&nbsp;work &ldquo;Screen Vortex xetorV neercS&rdquo;at&nbsp;<a href=\"/defcon\" target=\"_blank\">DEFCON x CODAME</a></p>\r\n<p>&nbsp;<img src=\"/uploaded_images/-625-616-409-589-8635-575-8634-421-615-427-20814-1.gif\" alt=\"\" /></p>', '', 'http://dreamalias.com', '', 'http://www.codame.com/post/portfolio/1068/', '0', '', NULL, NULL),
(80, 'TIMEFLY', 'timefly', 'http://codame.dreamhosters.com/uploaded_images/timefly.jpg', '<header>\r\n<div>\r\n<p><a href=\"http://shop.timefly-exist.com/\" target=\"_blank\">TIMEFLY</a>&nbsp;- CODAME Featured Artist(s)</p>\r\n<p>Gravity fashion brought to you by&nbsp;Kim Laughton&nbsp;and&nbsp;Kevin Heckart</p>\r\n</div>\r\n</header>\r\n<div>\r\n<article id=\"post-1067\"><br />\r\n<figure><img src=\"/wp-content/uploads/2013/11/21dba61befeb08915beff961b2551ba4.jpg\" alt=\"\" /></figure>\r\n<figure><img src=\"/wp-content/uploads/2013/11/ad00d2c939d6497d514358f1b93c6e53.jpg\" alt=\"\" /></figure>\r\n<figure><img src=\"/wp-content/uploads/2013/11/16fb17ea50a527f66379ca60c3e82d55.jpg\" alt=\"\" /></figure>\r\n<p>&nbsp;</p>\r\n<figure><img src=\"/wp-content/uploads/2013/11/7a35fcecc192492bdcbdee5cae783814.png\" alt=\"\" /></figure>\r\n<p>Check out the TIMEFLY Oculus Rift experience at CODAME&nbsp;<a href=\"http://www.codame.com/?p=5644\">ART+TECH Virtual Reality</a>&nbsp;@ Mozilla, San Francisco, Friday Nov. 21st.</p>\r\n</article>\r\n</div>', '', 'http://shop.timefly-exist.com/', '', '', '0', '1436747270', NULL, NULL),
(167, 'Natasha Singh + TimeBlur', 'natasha-singh-timeblur', 'http://codame.dreamhosters.com/uploaded_images/natasha-singh-timeblur.png', '<p>Natasha Signh believes in the power of art and mathematics, and expresses the same through the medium of technology. She has worked in the areas of Yoga, Architecture of India and Kolam art to bring forward a new wave in Generative Art.<br /><br />As a part of the research and development lab of TimeBlur, a Digital Experience studio, founded by technologist Mike and herself, she explores the scope of disruptive technology to create unique digital sculptures for every audience of hers. Her work in the digital conservation of India&rsquo;s art and culture has been featured in the Discovery Channel and the Creators Project. This Generative artist aims to bridge the gap between the Art and Culture of Ancient India and the cutting edge technology of the modern day world.</p>\r\n<p>TimeBlur wrote their own software and designed a system to make Nadi happen. Techniques like Image processing, Computer Vision, Depth Imaging and Generative Art were applied in the process. The result of which was generative images for each person performing the asana, depending upon his proportion and movement.</p>\r\n<p><span style=\"font-family: arial, sans, sans-serif; font-size: 13px; line-height: 13px; white-space: pre-wrap;\"><img src=\"/uploaded_images/Screen_Shot_2015-09-21_at_4.21_.45_PM_.png\" alt=\"\" /></span></p>', 'http://twitter.com/timeblurindia', 'http://www.timeblur.io', 'natasha@timeblur.io', '', '0', '1476655281', NULL, NULL),
(565, 'Fernando Lopez-Lezcano', 'fernando-lopez-lezcano', 'http://codame.dreamhosters.com/uploaded_images/fernando-lopez-lezcano.jpg', '<p>Fernando Lopez-Lezcano enjoys building things, fixing them when they don\'t work, and improving them even if they seem to work just fine. The word \"things\" scope is very wide and includes computer hardware and software, controllers, music composition, performance, and sound. His music blurs the line between technology and art and is as much about form and sound processing, synthesis, and spatialization, as about algorithms and the custom software he writes for each piece. He has been working in multichannel sound and diffusion techniques for a long time and can hack Linux for a living. At CCRMA since 1993, he has combined his background in music (piano and composition), electronic engineering, and programming with his love of teaching, music composition, and performance. He discovered the intimate workings of sound while building his analog synthesizers a long time ago. Even after over 30 years, \"El Dinosaurio\" is still used in live performances. He was the Edgar Varese Guest Professor at TU Berlin during the Summer of 2008. Fernado is also 2014 winner of Stanford\'s&nbsp;Marsh O\'Neill Award.</p>', '', 'https://ccrma.stanford.edu/~nando/', 'nando@ccrma.stanford.edu', '', '0', '1683747270', NULL, ''),
(82, 'Zebbler Studios', 'zebbler-studios', 'http://codame.dreamhosters.com/uploaded_images/zebbler-studios.jpg', '\r\n						<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/aaf57f152deaf68951d7b067b6bc5789.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/143b135d2c6feeda5bec1c47c63498aa.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/e50ee35b8df16a4cca2bdea1d835f09f.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/b41dedc8cfad917f26270fd2dadbbe51.jpg\"></figure>\r\n</div>\r\n<p><strong><a href=\"http://zebblerstudios.com/\" target=\"_blank\">Zebbler Studios</a> – CODAME Featured Artist </strong></p>\r\n<div class=\"mbl\">\r\n<div class=\"mhl\"><em>Exploring the edge where art and technology collide, to unravel the joyful and unexpected beauty of art in motion.</em></div>\r\n<div class=\"mhl\"> </div>\r\n<div class=\"mhl\"><em>Zebbler Studios is a multimedia design team, specializing in custom video-mapped installations, video editing and animation, interactivity, software design, fabrication and lighting.</em></div>\r\n<div class=\"mhl\"> </div>\r\n<div class=\"mhl\"><em>Zebbler Studios pioneered the design of video-mapped touring concert stages, creating Shpongle(tron) and EOTO Lotus stages, as well as contributing to several other touring productions. Some of our other notable projects include annual large-scale interactive installations for Defcon (hacking conference in Las Vegas) and a permanent video-mapped treatment of Verizon Innovation Center in Boston.</em></div>\r\n<div class=\"mhl\"><span> </span></div>\r\n<div class=\"mhl\"><span>Come out to Vegas to celebrate, play and hack </span><span>Zebbler Studios</span><span> </span><em>Large scale. Video mapped. Suspended structures</em><span> at</span><span> </span><a href=\"http://codame.com/defcon\" target=\"_blank\">DEFCON x CODAME</a></div>\r\n</div>\r\n											', '', 'http://zebblerstudios.com/', '', 'http://www.codame.com/post/portfolio/zebbler-studios-codame-featured/', '0', '', NULL, NULL),
(83, 'Benito', 'benito', 'http://codame.dreamhosters.com/uploaded_images/benito.jpg', '\r\n						<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/895505e9a8e7845fcd10e951b102281f.jpg\"></figure>\r\n</div>\r\n<p><strong><a href=\"http://benito.bandcamp.com/\" target=\"_blank\">Benito</a> – CODAME Featured Musician</strong></p>\r\n<p>You may recognize Benito from the <em><a href=\"http://benito.bandcamp.com/\" target=\"_blank\">My First Trip to Outer Space</a></em> digital album, made using Korg R3, Korg Electribe Es-1, and FL Studio 6. Either way, you won’t want to miss his futurebass set at CODAME this month.</p>\r\n<p><span>Come out to Vegas to celebrate, dance and hack with Benito</span><span> at</span><span> </span><a href=\"http://codame.com/defcon\" target=\"_blank\">DEFCON x CODAME</a></p>\r\n											', '', 'http://benito.bandcamp.com/', '', 'http://www.codame.com/post/portfolio/benito-codame-featured-musician-you-may/', '0', '', NULL, NULL),
(277, 'Ken Goldberg', 'ken-goldberg', 'http://codame.dreamhosters.com/uploaded_images/ken-goldberg.jpg', '<p>&nbsp;</p>\r\n<p>Ken Goldberg is an artist and professor at UC Berkeley. Ken is a pioneer in internet-based robotic telepresence and Cloud-Based Robotics/Automation and has published over 200 peer-reviewed technical papers on algorithms for robotics, automatin, and social information filtering; his inventions have been awarded eight US Patents. He is Editor-in-Chief of the IEEE Transactions on Automation Science and Engineering (T-ASE), Co-Founder of the African Robotics Network (AFRON), Co-Founder of the Berkeley Center for New Media (BCNM), Co-Founder and CTO of Hybrid Wisdom Labs, Co-Founder of the Moxie Institute, and Founding Director of UC Berkeley\'s Art, Technology, and Culture Lecture Series which has hosted over 150 presentations by artists and curators. Kens artwork has been exhibited at Ars Electronica, ZKM, Centre Pompidou, ICC Biennale, Kwangju Biennale, Artists Space, The Kitchen, and the Whitney Biennial. For details on research and art, please visit: http://goldberg.berkeley.edu</p>\r\n<p>&nbsp;</p>', 'http://twitter.com/ken_goldberg', 'http://goldberg.berkeley.edu', '', '', '0', '1517337477', NULL, NULL),
(85, 'Jefferson Shulgin', 'jefferson-shulgin', 'http://codame.dreamhosters.com/uploaded_images/jefferson-shulgin.png', '<p>&nbsp;<br /> <a href=\"http://www.jeffersonshulgin.com/\" target=\"_blank\">Jefferson Shulgin</a> is an Ambient production duo consisting of&nbsp;<a href=\"https://soundcloud.com/dftram\" target=\"_blank\">DFTram</a>&nbsp;(Ambisonic, Sound Capsule) and&nbsp;<a href=\"https://soundcloud.com/strangus\" target=\"_blank\">Deep Cuts</a>&nbsp;(Chocolate Penthouse, Mister Trikonasana), two seasoned San Francisco Electronic Music Producers who bring you the full spectrum of the psychedelic experience through sound.</p>\r\n<p><em>Wiretap</em> is a special AV set by Jefferson Shulgin, a mashup of fount footage diving deep into surveillance vibes. Premiered at DEFCON21, showing in SF for the first time ever!</p>\r\n<p>Catch Jefferson Shulgin at CODAME ART+TECH Friday Oct. 31st, at Geekdom &ndash; 620 Folsom St., San Francisco</p>\r\n<p>&nbsp;</p>', '', 'http://www.jeffersonshulgin.com/', '', '', '0', '1436747040', NULL, NULL),
(86, 'Rhinostrich', 'rhinostrich', 'http://codame.dreamhosters.com/uploaded_images/rhinostrich.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"http://rhinostrich.com/\" target=\"_blank\">Rhinostrich</a>&nbsp;&ndash; CODAME Featured Musician</strong></p>\r\n<p>&nbsp;</p>\r\n<p>rhinostrich is featured on:&nbsp;<br /> <a href=\"http://hexawe.bandcamp.com/album/the-hexawe-catalog\" target=\"_blank\">http://hexawe.bandcamp.com/album/the-hexawe-catalog</a><br /> <a href=\"http://hexawe.bandcamp.com/album/monorave-compo\" target=\"_blank\">http://hexawe.bandcamp.com/album/monorave-compo</a><br /> <a href=\"http://hexawe.bandcamp.com/album/c6-420-09-compo\" target=\"_blank\">http://hexawe.bandcamp.com/album/c6-420-09-compo</a><br /> <a href=\"http://hexawe.bandcamp.com/album/farplite-compo\" target=\"_blank\">http://hexawe.bandcamp.com/album/farplite-compo</a><br /> <a href=\"http://iochipmusic.bandcamp.com/album/i-o-chip-music-compilation-vol-1\" target=\"_blank\">http://iochipmusic.bandcamp.com/album/i-o-chip-music-compilation-vol-1</a><br /> <a href=\"http://www.minusbaby.com/left/1/\" target=\"_blank\">http://www.minusbaby.com/left/1/</a><br /> <a href=\"http://toycompany.bandcamp.com/\" target=\"_blank\">http://toycompany.bandcamp.com/</a></p>\r\n<p>or&hellip;</p>\r\n<p><strong>Come out to Vegas to celebrate, dance and hack with rhinostrich at&nbsp;<a href=\"/defcon\" target=\"_blank\">DEFCON x CODAME</a></strong></p>', '', 'http://rhinostrich.com/', '', '', '0', '1436747060', NULL, NULL),
(87, 'TIMEHEATER', 'timeheater', 'http://codame.dreamhosters.com/uploaded_images/timeheater.gif', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong><a href=\"http://freemusicarchive.org/music/Timeheater/\" target=\"_blank\">TIMEHEATER</a>&nbsp;&ndash; CODAME Featured Musician</strong></p>\r\n<p>&ldquo;if you pour coke on me worms come out&rdquo; &ndash; <a href=\"https://twitter.com/buttcliff\" target=\"_blank\">@buttcliff</a></p>\r\n<p>Come out to Vegas to celebrate, dance and hack with timeheater at&nbsp;<a href=\"/defcon\" target=\"_blank\">DEFCON x CODAME</a></p>', 'https://twitter.com/buttcliff', 'http://freemusicarchive.org/music/Timeheater/', '', '', '0', '1436747119', NULL, NULL),
(88, 'Zen Albatross', 'zen-albatross', 'http://codame.dreamhosters.com/uploaded_images/zen-albatross.gif', '\r\n						<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/6ab1496a17edd389d4880eac56052e4b.gif\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/5452e9845ec80b0f859b775e3a53244e.gif\"></figure>\r\n</div>\r\n<p><strong><a href=\"http://zenalbatross.net/\" target=\"_blank\">Zen Albatross</a> – CODAME Featured Musician</strong></p>\r\n<p>Since 2008, Brooklyn’s Zen Albatross has explored & exploited the waveform synthesis capabilities of antiquated computer systems. <span class=\"less\">Assembling a sonic vernacular derived from minimal hardware and holding a mirror to the complex and oppressive systems which contain us, he strives to maintain a routinely reformatted creative process that seeks varied solutions to the same problems. </span></p>\r\n<p><span class=\"less\">An active member of New York City’s chip music community, he has had dozens of performances in cities across the United States, including New York’s micro-music epicenter, <a href=\"http://blipfestival.org/\" target=\"_blank\">Blip Festival</a>. </span></p>\r\n<p><span class=\"less\">His fearful obsession with technology as an ideological weapon is equaled only by his love of American craft beer.</span></p>\r\n<p><strong><span>Come out to Vegas to celebrate, dance and hack with Zen at </span><a href=\"http://codame.com/defcon\" target=\"_blank\">DEFCON x CODAME</a></strong></p>\r\n											', '', 'http://zenalbatross.net/', '', 'http://www.codame.com/post/portfolio/zen-albatross-codame-featured-musician-since/', '0', '', NULL, NULL),
(89, 'Rafael Rozendaal', 'rafael-rozendaal', 'http://codame.dreamhosters.com/uploaded_images/rafa-l-rozendaal.gif', '<div class=\"figure\">&nbsp;</div>\r\n<div class=\"figure\"><img class=\"alignnone size-full wp-image-1510\" src=\"/wp-content/uploads/2013/08/tumblr_ms8ciyXSBX1qixx7ho4_1280.jpg\" alt=\"tumblr_ms8ciyXSBX1qixx7ho4_1280\" width=\"800\" height=\"800\" /></div>\r\n<div class=\"figure\"><img class=\"alignnone size-full wp-image-1509\" src=\"/wp-content/uploads/2013/08/tumblr_ms8ciyXSBX1qixx7ho3_1280.jpg\" alt=\"tumblr_ms8ciyXSBX1qixx7ho3_1280\" width=\"800\" height=\"800\" /></div>\r\n<div class=\"figure\"><img class=\"alignnone size-full wp-image-1508\" src=\"/wp-content/uploads/2013/08/tumblr_ms8ciyXSBX1qixx7ho2_1280.jpg\" alt=\"tumblr_ms8ciyXSBX1qixx7ho2_1280\" width=\"800\" height=\"800\" /><img class=\"alignnone size-full wp-image-1507\" src=\"/wp-content/uploads/2013/08/tumblr_ms8ciyXSBX1qixx7ho1_1280.jpg\" alt=\"tumblr_ms8ciyXSBX1qixx7ho1_1280\" width=\"612\" height=\"612\" /></div>\r\n<div class=\"figure\">&nbsp;</div>\r\n<p><strong>CODAME Featured Artist:&nbsp;<a href=\"http://coldvoid.kklosangeles.com/\" target=\"_blank\">Rafa&euml;l Rozendaal</a></strong></p>\r\n<p>World renowned multi-media artist Rafa&euml;l Rozendaal and Dutch electronic musician Luuk Bouwman have&nbsp;debuted their music and video project <a href=\"http://coldvoid.kklosangeles.com/\" target=\"_blank\">Cold Void</a>&nbsp;at the KK gallery in L.A. At the heart of the show,&nbsp;a self playing instrument played in sync with the video art pieces that were created for each of the tracks.&nbsp;Purchase one of the few remaining records, before it&rsquo;s too late! This is an unique opportunity!</p>\r\n<p><strong>This limited edition of Cold Void Record comes with a lenticular print cover&nbsp;release by KK Los Angeles and Cassette Recordings.</strong></p>\r\n<p><strong>More on&nbsp;<a href=\"http://coldvoid.kklosangeles.com/\" target=\"_blank\">coldvoid.kklosangeles.com</a></strong></p>', '', 'http://coldvoid.kklosangeles.com/', '', '', '0', '1436746943', NULL, NULL),
(90, 'Cabbibo', 'cabbibo', 'http://codame.dreamhosters.com/uploaded_images/cabbibo.png', '\r\n						<hr>\r\n<p><strong>Isaac Cohen (aka <a href=\"http://cabbibo.com/\" target=\"_blank\">Cabbibo</a>)</strong></p>\r\n<p>Cabbibo is a triptastic, experimental audio/visual adventure. Visitors to the site can wade through a display full of brilliant colors and sparkling tones, as they cursor their way through a music blog universe.</p>\r\n<p>If you like the online version, imagine how crazy the <em>real life</em> version will be!</p>\r\n<p>We hosted Cabbibo work live at <a href=\"http://codame-eorg.eventbrite.com/\" target=\"_blank\">DATAVIZ</a> on October 3.</p>\r\n<p>Join us for <a href=\"http://www.codame.com/?p=6011\">Art by Code</a> to check out Cabbibo’s latest work.</p>\r\n											', '', 'http://cabbibo.com/', '', 'http://www.codame.com/post/portfolio/cabbibo/', '0', '', NULL, NULL),
(91, 'Eric Fickes', 'eric-fickes', 'http://codame.dreamhosters.com/uploaded_images/eric-fickes.png', '<p>&nbsp;</p>\r\n<p>Eric&nbsp;codes art when he&rsquo;s not skateboarding or being a dad.</p>\r\n<p>CODAME will be premiering Eric&rsquo;s latest project which uses processing sketches to generate highly stylized portraits. Come capture your next avatar at the<a href=\"/dataviz\" target=\"_blank\">CODAME DATAVIZ Event</a>&nbsp;(Oct 3)!</p>\r\n<p><img class=\"alignnone size-full wp-image-2209\" src=\"/wp-content/uploads/2013/12/tumblr_mty322GXyT1qixx7ho1_500.jpg\" alt=\"tumblr_mty322GXyT1qixx7ho1_500\" width=\"480\" height=\"640\" /></p>', '', '', '', '', '0', '1436746979', NULL, NULL),
(168, 'Xiaohan Zhang', 'xiaohan-zhang', 'http://codame.dreamhosters.com/uploaded_images/xiaohan-zhang.jpg', '<p>Xiaohan Zhang is a New Media Artist specializing in real-time, interactive, audio-visual digital art installations and web experiences. His work is inspired by physical, chemical, biological and ecological processes of the natural world, combined with aesthetic polish and form. His work is centered around creating iterative loops of play that convey an intuitive understanding of the system. He hopes that in doing so the viewer may find insight, wonder, and an appreciation of the forces that govern our lives.&nbsp;</p>\r\n<p><img src=\"/uploaded_images/xiaohan-zhang_2.gif\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/Screen_Shot_2015-09-22_at_2.42_.05_PM_.png\" alt=\"\" /></p>\r\n<p>Xiaohan will be presenting an interactive installation piece with artist <a href=\"/artists/katherine-frazer\">Katherine Frazer</a> at our <a href=\"/events/art-tech-festival-2015\">ART+TECH Festival MOVEMENT</a> on October 23rd+24th, 2015</p>', 'https://twitter.com/hellocharlien', 'http://www.hellochar.com', 'hellocharlien@hotmail.com', '', '0', '1523646376', NULL, NULL),
(92, 'Ken Murphy', 'ken-murphy', 'http://codame.dreamhosters.com/uploaded_images/ken-murphy.png', '\r\n						<p><iframe src=\"http://www.youtube.com/embed/DAABUwvn6Ow?wmode=transparent&autohide=1&egm=0&hd=1&iv_load_policy=3&modestbranding=1&rel=0&showinfo=0&showsearch=0#t=68\" height=\"225\" width=\"400\" allowfullscreen=\"\" frameborder=\"0\"></iframe></p>\r\n<p><strong>CODAME Featured Artist:</strong> <a href=\"http://www.murphlab.com/\" target=\"_blank\">Ken Murphy</a></p>\r\n<p><span>Musician, programmer, artist, and tinkerer K</span>en Murphy will bring his passion for photography, video, and electronics together with his projected video loop piece.</p>\r\n<p>He is also known for, among many other works of art, his pan-lapse movies of San Francisco.</p>\r\n<p>See for yourself at the 5ENSES experience at the <a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>.</p>\r\n											', '', 'http://www.murphlab.com/', '', 'http://www.codame.com/post/portfolio/codame-featured-artist-ken-murphy-musician/', '0', '', NULL, NULL),
(93, 'Colin Roache', 'colin-roache', 'http://codame.dreamhosters.com/uploaded_images/colin-roache.png', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong>CODAME Featured Artist:</strong>&nbsp;<a href=\"http://colinroache.com/\" target=\"_blank\">Colin Roache</a></p>\r\n<p class=\"p1\">Colin is an Oakland-native artist and independent creative technologist specializing in human-music interaction. <a href=\"http://www.facebook.com/Leftbody\" target=\"_blank\">Leftbody</a>, a music visualization performance, delivers mind-melding music visuals that aim to reveal the shared potential which lays beyond sa&#7747;s&#257;ric constraints.</p>\r\n<p class=\"p1\"><strong>See for yourself at the 5ENSES experience at the&nbsp;<a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>.</strong></p>', '', 'http://colinroache.com/', '', '', '0', '1436746999', NULL, NULL),
(172, 'Zen Cohen', 'zen-cohen', 'http://codame.dreamhosters.com/uploaded_images/zen-cohen.gif', '<p>Zen Cohen received her MFA in Art Studio at the University of California at Davis and&nbsp;her BFA in Media Arts from the California College of the Arts in Oakland, CA. Her work&nbsp;has been seen in venues such as the Yerba Buena Center for the Arts, SFMOMA, de Young Museum, Centro Atl&aacute;ntico Arte Moderno, ARTSpace New Haven, Vanity&nbsp;Projects, Center for New Music &amp; Audio Technologies at UC Berkeley, Recombinant&nbsp;Media Lab, SOMArts, Krowswork, and Artists Television Access (ATA). In 2013, she was awarded a Media Arts grant from the San Francisco Arts Commission to help support the completion of a documentary project that will screen at the deYoung&nbsp;Museum this summer. She has also curated film/video screenings and group installation&nbsp;shows at the Climate Theater in San Francisco. Her art practice utilizes video in&nbsp;combination with photography, sculpture, costuming and performance. Additionally, she&nbsp;works as a freelance videographer, editor, photographer and art director.&nbsp;</p>\r\n<p>Zen has&nbsp;been presenting <a href=\"/projects/transgress\">Trangress</a>&nbsp;in collaboration with artists <a href=\"/artists/zoey-vero\">Zoey Vero</a> and Colton Long at our<a href=\"/events/art-tech-festival-2015\"> ART+TECH Festival \"MOVEMENT\"</a>.</p>', '', 'http://www.zencohenprojects.com', '', '', '0', '1476656836', NULL, NULL),
(94, 'Robert Edgar', 'robert-edgar', 'http://codame.dreamhosters.com/uploaded_images/robert-edgar.png', '\r\n						<p><iframe src=\"http://player.vimeo.com/video/57754162\" height=\"225\" width=\"400\" frameborder=\"0\"></iframe></p>\r\n<p><strong>CODAME Featured Artist:</strong> <a href=\"http://www.robertedgar.com/\" target=\"_blank\">Robert Edgar</a></p>\r\n<p>Robert is a video and video installation artist who uses a mixture of self-coded software and hardware to create unique visual experiences.</p>\r\n<p>Works such as <a href=\"http://www.robertedgar.com/simultaneous-opposites/\" target=\"_blank\">“Simultaneous Opposites”</a> – an experiment in looping algorithms – and the <a href=\"http://www.robertedgar.com/the-duchamp-examinations-2/\" target=\"_blank\">“Duchamp Examination”</a> – a look into dissecting, re-examining, and re-producing a composed work – are two examples of Robert’s many studies in the intersection of sound and vision.</p>\r\n<p><span>In addition… a</span>s a tribute to Lou Reed, Robert and his band <em><strong>“14 Bindlestick Frank”</strong></em> is performing Saturday, Nov 2nd from 6:00 to 7:00 in the main gallery.</p>\r\n<p><strong>See/Hear for yourself at the 5ENSES experience at the <a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>.</strong></p>\r\n											', '', 'http://www.robertedgar.com/', '', 'http://www.codame.com/post/portfolio/codame-featured-artist-robert-edgar-robert-is-a/', '0', '', NULL, NULL),
(95, 'Charlie Levin', 'charlie-levin', 'http://codame.dreamhosters.com/uploaded_images/charlie-levin.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/fd4fc30dd329519905ce41b60e764f8d.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<p><strong>CODAME Featured Artist:&nbsp;</strong><a href=\"http://art.girlcharlie.com\" target=\"_blank\">Charlie Levin</a></p>\r\n<p>Charlie is an interactive visual artist who paint on wax on glass to create a layering effect heightened by changes in light.</p>\r\n<p>These pieces and others in Charlie&rsquo;s collection of work allow audience members to move from viewer to participant, each experiencing something different with the turn of a corner or a flick of a switch.</p>\r\n<p>See for yourself at the 5ENSES experience at the&nbsp;<a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>.</p>', '', 'http://art.girlcharlie.com', '', '', '0', '1436746873', NULL, NULL),
(169, 'Katherine Frazer', 'katherine-frazer', 'http://codame.dreamhosters.com/uploaded_images/katherine-frazer.jpg', '<p>Katherine Frazer is a digital product designer at Apple, interested in exploring the implications of technology as a means of self-expression and identification. Her previous work focused on how marginalized groups have used technology to empower themselves; exhibiting a book documenting the Tumblr eating disorder community, and working as a researcher on a social therapy robot for children with developmental disabilities. She has shown work in galleries in Pittsburgh, Pennsylvania, been featured on NewHive, and has received award recognition from AIGA for her hand-bound book, &ldquo;Seized&rdquo;. She recently graduated from Carnegie Mellon University with a double major in Communication Design and Human-Computer Interaction.</p>\r\n<p><img src=\"/uploaded_images/katherine-frazer_s.png\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/katherine-frazer2_s.png\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/katherine-frazer3_s.png\" alt=\"\" />&nbsp;</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/k___e___f', 'http://www.katherinefrazer.com', 'kfrazer@me.com', '', '0', '1594059690', NULL, NULL),
(96, 'Paul Clipson', 'paul-clipson', 'http://codame.dreamhosters.com/uploaded_images/paul-clipson.png', '\r\n						<p><iframe src=\"http://player.vimeo.com/video/73346777\" height=\"300\" width=\"400\" frameborder=\"0\"></iframe></p>\r\n<p><strong>CODAME Featured Artist:</strong> <a href=\"http://www.withinmirrors.org/\" target=\"_blank\">Paul Clipson</a></p>\r\n<p>Paul is a multi-media artist who specializes in sound/video performanaces and installations, oftentimes collaborating with composers and musicians such as in this year’s <a href=\"http://vimeo.com/62176453\" target=\"_blank\">“DIFFICULT LOVES”</a> (featuring music by Jeffre Cantu-Ledesma).</p>\r\n<p><strong>See and hear for yourself at the 5ENSES experience at the <a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>.</strong></p>\r\n											', '', 'http://www.withinmirrors.org/', '', 'http://www.codame.com/post/portfolio/codame-featured-artist-paul-clipson-paul-is-a/', '0', '', NULL, NULL),
(97, 'Patrick Dintino', 'patrick-dintino', 'http://codame.dreamhosters.com/uploaded_images/patrick-dintino.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong>CODAME Featured Aritst:</strong> <a href=\"http://www.patrickdintino.com/CatalogCollage.html\" target=\"_blank\">Patrick Dintino</a></p>\r\n<p>Patrick breathes new artistic life into originally unwanted junkmail with his multimedia junkmail collages. His works piece together numbers, letters, slices of color, and even faces from advertisements into collages that at times simulate real life glitch art &ndash; picking apart images made by someone else and rearranging into something new.</p>\r\n<p><strong>See for yourself at the 5ENSES experience at the&nbsp;<a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>.</strong></p>', '', 'http://www.patrickdintino.com/CatalogCollage.html', '', '', '0', '1436746905', NULL, NULL),
(98, 'Jeff Cheung', 'jeff-cheung', 'http://codame.dreamhosters.com/uploaded_images/jeff-cheung.gif', '<div class=\"figure\">&nbsp;</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/7fafd83b2133fd4a78c55a8643f5ba68.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/4e1623c37f718bea2b854a9315f0fe8a.gif\" alt=\"\" /></figure>\r\n</div>\r\n<p><strong>CODAME Featured Aritst:&nbsp;</strong><a href=\"http://www.jeffreycheung.com/#!prints/cee5\" target=\"_blank\">Jeff Cheung</a></p>\r\n<p>Jeff is a multi-media artist whose works range from paintings, prints, collages, and drawings in addition to silk screened shirts.</p>\r\n<p>Some of his featured work includes the <a href=\"http://www.fecalface.com/SF/index.php/good-stuff/4457-jeff-cheungs-lino-cuts\" target=\"_blank\">floor-to-ceiling lino cuts</a> displayed at Sticks and Stones Gallery in Oakland. Often depicting heavier-set male figures in various body contortions, Jeff melds the visual with the corporeal.</p>\r\n<p>See for yourself at the 5ENSES experience at the&nbsp;<a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>.</p>', '', 'https://www.instagram.com/jeffcheung1/', '', '', '0', '1593820652', NULL, NULL),
(99, 'Leo Madrid', 'leo-madrid', 'http://codame.dreamhosters.com/uploaded_images/leo-madrid.png', '\r\n						<p><iframe src=\"http://player.vimeo.com/video/3202686\" height=\"266\" width=\"400\" frameborder=\"0\"></iframe></p>\r\n<p><strong>CODAME Featured Artist:</strong> <a href=\"http://www.mind-lamp.com/\" target=\"_blank\">Leo Madrid</a></p>\r\n<p>Leo works in the “6th sense” realm with the Mind Lamp project – bringing together your thoughts and the visual world with a “quantum-based technology that responds to your mind.”</p>\r\n<p>By manipulating electron tunneling phenomena through the Mind Lamp’s random event generator, different colors are displayed in unpredictable sequences.</p>\r\n<p>What makes this even more eerie and exciting is that our minds can influence the Mind Lamp’s display!</p>\r\n<p><strong>See your mind at work with quantum-based technologies at the 5ENSES experience at the <a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>.</strong></p>\r\n											', '', 'http://www.mind-lamp.com/', '', 'http://www.codame.com/post/portfolio/codame-featured-artist-leo-madrid-leo-works-in/', '0', '', NULL, NULL),
(100, 'Tim Thompson', 'tim-thompson', 'http://codame.dreamhosters.com/uploaded_images/tim-thompson.jpg', '<p><strong>CODAME Featured Artist:</strong> <a href=\"http://www.youtube.com/watch?v=M4Xd9TrcPE0\" target=\"_blank\">Tim Thompson</a></p>\r\n<p>Tim Thompson is&nbsp;a software engineer, musician, and installation artist.&nbsp;He worked at Bell Labs and AT&amp;T for 20 years in New Jersey, and for Network Appliance in Silicon Valley for 9 years.&nbsp;Tim&nbsp;is interested in programming languages, algorithmic composition, networked collaboration, atypical controllers, event-driven graphics generation, and realtime video processing. Inspired in recent years by something described in this quote by Larnie Fox:</p>\r\n<table>\r\n<tbody>\r\n<tr>\r\n<td><img src=\"https://nosuch.com/tjt/images/cleardot.gif\" alt=\"\" width=\"2\" height=\"10\" border=\"0\" /></td>\r\n</tr>\r\n<tr>\r\n<td><img src=\"https://nosuch.com/tjt/images/cleardot.gif\" alt=\"\" width=\"20\" border=\"0\" /></td>\r\n<td>\"There is a yet unnamed art movement that may prove to be of some significance, and Burning Man is close to its center. It often manifests itself as circus, ritual, and spectacle. It is a movement away from a dialogue between an individual artist and a sophisticated audience, and towards collaboration amongst a big, wild, free and diverse community. It is a movement away from galleries, schools and other institutions and towards an art produced in and for casual groups of participants, more akin to clans and tribes, based on aesthetic affinities and bonds of friendship. It is a movement away from static gallery art and formal theater and towards site-specific, time-specific installation and performance. It is a rejection of spoon-fed corporate culture and an affirmation of the homemade, the idiosyncratic, the personal. It is profoundly democratic. It is radically inclusive, it is a difficult challenge, and it is beckoning.\"</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p class=\"p1\"><br /><iframe src=\"http://www.youtube.com/embed/M4Xd9TrcPE0?wmode=transparent&amp;autohide=1&amp;egm=0&amp;hd=1&amp;iv_load_policy=3&amp;modestbranding=1&amp;rel=0&amp;showinfo=0&amp;showsearch=0\" width=\"400\" height=\"299\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p class=\"p1\">Photography by&nbsp;<a href=\"http://www.danielgarciaphotography.com/\">Daniel Garcia</a></p>', '', 'http://timthompson.com/', 'me@timthompson.com', '', '0', '1568592110', NULL, NULL),
(101, 'Renetta Sitoy', 'renetta-sitoy', 'http://codame.dreamhosters.com/uploaded_images/renetta-sitoy.png', '\r\n						<p><iframe id=\"tumblr_video_iframe_65415981829\" style=\"display: block; background-color: transparent; overflow: hidden;\" src=\"//www.tumblr.com/video/codame/65415981829/400\" height=\"300\" width=\"400\" allowfullscreen=\"\" frameborder=\"0\" scrolling=\"no\"></iframe></p>\r\n<p><strong>CODAME Featured Artist:</strong> <a href=\"http://www.rsitoy.com/\" target=\"_blank\">Renetta Sitoy</a></p>\r\n<p>Maria Renetta (a.k.a. rsitoy) is a visual artist whose pieces include digital animation video loops, multi-media installations with video projections juxtaposed with typewritten works, feature-length documentary films, and long-form digital videos with sound.</p>\r\n<p><strong>See for yourself at the 5ENSES experience at the <a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>.</strong></p>\r\n											', '', 'http://www.rsitoy.com/', '', 'http://www.codame.com/post/portfolio/codame-featured-artist-renetta-sitoy-maria/', '0', '', NULL, NULL),
(102, 'CDCM', 'cdcm', 'http://codame.dreamhosters.com/uploaded_images/cdcm.jpg', '\r\n						<p><iframe src=\"https://w.soundcloud.com/player/?url=https%3A//api.soundcloud.com/playlists/6188930\" height=\"450\" width=\"100%\" frameborder=\"no\" scrolling=\"no\"></iframe></p>\r\n<p><strong>CODAME Featured Artist:</strong> <a href=\"https://soundcloud.com/cdcm-1\" target=\"_blank\">CDCM</a></p>\r\n<p>CDCM is an ambient musician creating electronic tracks that often begin with a ghostly quiet and often build up into an “orchestrated electronic madness.”</p>\r\n<p><strong><span>Hear for yourself at the 5ENSES experience at the </span><a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a><span>.</span></strong></p>\r\n											', '', 'https://soundcloud.com/cdcm-1', '', 'http://www.codame.com/post/portfolio/codame-featured-artist-cdcm-cdcm-is-an-ambient/', '0', '', NULL, NULL),
(370, 'Brad Wolfe', 'brad-wolfe', 'http://codame.dreamhosters.com/uploaded_images/brad-wolfe.jpg', '<div>\r\n<p>When Brad Wolfe was at Stanford in the early aughts, one of his best friends, Sara LaBoskey, was diagnosed with a pediatric bone cancer called Ewing&rsquo;s sarcoma. Wolfe played guitar, so he wrote a song to celebrate her, and began singing at the hospital. &ldquo;People talk about the power of art. But I realized it was more than just a phrase when I saw the kind of impact that it had in connecting with Sara, and how it had some small impact on her well-being,&rdquo; he says.</p>\r\n</div>\r\n<div>\r\n<p>The artistic expression helped them both because it became a positive way to honor LaBoskey while she was still living, and to remember her after she passed. Nearly 15 years later, Wolfe is trying to take that concept mainstream, as the founder and executive director of Reimagine End of Life, a nonprofit that hosts weeklong community festivals with events, workshops, and performances meant to generate more conversation and connection around the generally taboo topic of death.</p>\r\n<p>&nbsp;</p>\r\n<figure style=\"text-align: center;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"https://images.fastcompany.net/image/upload/w_596,c_limit,q_auto:best,f_auto/wp-cms/uploads/2018/04/1-this-festival-celebrates-death-to-give-life-more-meaning.jpg\" sizes=\"(max-width: 525px) 100vw, 525px\" alt=\"\" width=\"525\" height=\"295\" data-src=\"https://images.fastcompany.net/image/upload/w_596,c_limit,q_auto:best,f_auto/wp-cms/uploads/2018/04/1-this-festival-celebrates-death-to-give-life-more-meaning.jpg\" /><figcaption>[Photo: courtesy Reimagine End of Life]</figcaption></figure>\r\n<p>Wolfe, who eventually earned a masters in sociology, and then an MBA from Berkeley, launched the first festival in 2016. The idea took shape after&nbsp;<a href=\"https://challenges.openideo.com/challenge/end-of-life/brief\">OpenIDEO ran its End of Life Challenge</a>, a public contest that took place that same year and sought new ways to re-humanize the dying process.&nbsp;Wolfe was inspired by the concept, and collaborated with OpenIDEO on a separate effort the explored the relationship between art and the end of life.</p>\r\n<p>While death was once considered a personal, at-home, and inclusive family experience, Americans began outsourcing their family and community responsibilities to hospitals or nursing homes in the 1950s. As OpenIDEO&rsquo;s original contest material notes, about 2.5 million people die each year in the U.S., with less than one-fifth in the privacy of their own home. The process of dying now has become largely institutionalized.</p>\r\n<p>The festival&rsquo;s second year starts April 16 in San Francisco. More than 7,000 people are expected to attend more than 175 events, with subsequent stops scheduled for Cleveland and New York later this year.</p>\r\n<p style=\"text-align: left;\">The event offers both philosophical and practical advice. Reimagine has partnered with San Francisco&rsquo;s&nbsp;<a href=\"https://www.sfhsa.org/about/departments/department-aging-and-adult-services-daas\">Department of Aging and Adult Services</a>and the city&rsquo;s&nbsp;<a href=\"http://www.ltcccsf.org/palliative-care\">Palliative Care Workgroup</a>, to offer free advanced care planning sessions at 25 locations around the city. That includes helping people set up their own end-of-life health directives.</p>\r\n<figure style=\"text-align: center;\"><img src=\"https://images.fastcompany.net/image/upload/w_596,c_limit,q_auto:best,f_auto/wp-cms/uploads/2018/04/3-this-festival-celebrates-death-to-give-life-more-meaning.jpg\" sizes=\"(max-width: 525px) 100vw, 525px\" alt=\"\" width=\"525\" height=\"295\" data-src=\"https://images.fastcompany.net/image/upload/w_596,c_limit,q_auto:best,f_auto/wp-cms/uploads/2018/04/3-this-festival-celebrates-death-to-give-life-more-meaning.jpg\" /><figcaption>[Photo: courtesy Reimagine End of Life]<br /><br /></figcaption></figure>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p>Extract from \"This Festival Wants Us To Rethink How We Die\"&nbsp;<a href=\"https://www.fastcompany.com/40558843/this-festival-wants-us-to-rethink-how-we-die\">@fastcompany</a>&nbsp;by Ben Paynter</p>\r\n</div>', 'https://twitter.com/bigbradwolfe', 'https://www.letsreimagine.org/', '', '', '0', '1566177361', NULL, NULL),
(104, 'Nop Jiarathanakul', 'nop-jiarathanakul', 'http://codame.dreamhosters.com/uploaded_images/nop-jiarathanakul.jpg', '<p>&nbsp;</p>\r\n<p>Nop is 75% technologist, 24% artist, and 100% perfectionist. He loves building interactive 3D for the web with pixel-perfect detail. After spending his early years in animation and games, &nbsp;he now uses his 3D graphics powers for good.</p>', '', 'http://www.iamnop.com/', 'nop.jiarathanakul@autodesk.com', '', '0', '1507226079', NULL, NULL),
(273, 'Apprentice3D', 'apprentice3d', 'http://codame.dreamhosters.com/uploaded_images/apprentice3d.jpg', '<p>&nbsp;</p>\r\n<p>Denis Grigor is a Developer Advocate at Autodesk. Within Autodesk, he provides programming support to 3ds Max and Forge external developers. This mix of desktop and cloud exposure helps him in his endeavor to safely erase the borders between them. Add to this his interest of IoT and IIoT with love for 3D graphics and here you have a cyber alchemist.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '', '', 'denis.grigor@autodesk.com', '', '0', '1507736178', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(274, 'Ponk + Koltes + Fergus', 'ponk-koltes-fergus', 'http://codame.dreamhosters.com/uploaded_images/ponk-koltes-fergus.jpg', '<p style=\"color: #222222; font-family: arial, sans-serif; font-size: 12.8px;\"><span style=\"background-color: #000000; color: #ffffff;\"><span class=\"m_-1513637211721017558m_-3386576195574692216gmail-m_998070584349119696gmail-il\" style=\"font-size: 12.8px;\">L&eacute;on</span><span style=\"font-size: 12.8px;\">&nbsp;Denise (Ponk) is an artist programmer. He uses tools from video games to explore and experiment with new ways of perceiving realities. He dreams about image filters and displacement effects in a land of singing vertices and dancing polygons.</span></span></p>\r\n<p style=\"color: #222222; font-family: arial, sans-serif; font-size: 12.8px;\"><span style=\"font-size: 12.8px; background-color: #000000; color: #ffffff;\">&nbsp;</span></p>\r\n<p style=\"color: #222222; font-family: arial, sans-serif; font-size: 12.8px;\"><span style=\"font-size: 12.8px; background-color: #000000; color: #ffffff;\">Jonathan Giroux (Koltes) is a digital media artist and software engineer. He designs and develops playful experiences, real-time animations, and open-source libraries. Relationships with others and tangible interactions are key aspects of his research.</span></p>\r\n<p style=\"color: #222222; font-family: arial, sans-serif; font-size: 12.8px;\"><span style=\"font-size: 12.8px; background-color: #000000; color: #ffffff;\">&nbsp;</span></p>\r\n<p style=\"color: #222222; font-family: arial, sans-serif; font-size: 12.8px;\"><span style=\"font-size: 12.8px; background-color: #000000; color: #ffffff;\">Simon Larcher (Fergus) is a musician and electronic music composer as well as a programmer. Bits of both music or sounds and code are used in all of his projects from digital art installations to abstract arrhythmic grooves to bare metal microcontrollers.</span></p>', '', '', 'giroux.jo@gmail.com', '', '0', '1507655230', NULL, NULL),
(106, 'Unicorn', 'unicorn', 'http://codame.dreamhosters.com/uploaded_images/unicorn.gif', '<figure>\r\n<p>After so many year traveling around the world, universe and cosmos to find our perfect ART+TECH Unicorn, we are proud to announce to day it was found in Paris and it will be soon in&nbsp;San Francisco&nbsp;!</p>\r\n<p>The Unicorn Paris will create a Museum for a new Renaissance, within the internet culture, at our CODAME&nbsp;<a href=\"/festival\" target=\"_blank\">ART+TECH Festival</a>&nbsp;</p>\r\n<p>Immerse yourself in the&nbsp;Renaissance Full Hd is a virtual museum, be in the internet posterity throughout the web culture,&nbsp;at the&nbsp;<a href=\"http://twitter.com/GeekdomSF\" target=\"_blank\">@GeekdomSF</a></p>\r\n<p>&nbsp;</p>\r\n<iframe src=\"https://player.vimeo.com/video/76472449?color=ffffff&amp;title=0&amp;byline=0&amp;portrait=0\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></figure>', '', 'http://www.unicorn-paris.com/', '', '', '0', '1574364210', NULL, NULL),
(393, 'Jason Wilson', 'jason-wilson', 'http://codame.dreamhosters.com/uploaded_images/jason-wilson.jpg', '<p>Picking up where his 1996 installation The Importance of the I 1 left off, Jason Wilson created The OuterBody Experience Lab in 2012. Its aim was to further explore, in a more interactive incarnation, the ways disembodied vision can impact our sense of self in the contexts of neuroscience, education, creativity, rehabilitation, and of course gaming. In a world that&rsquo;s trying to understand the balance between the individual and the group, the self and the other, and the borders of ourselves, the Lab has had no shortage of territory to explore.</p>\r\n<p>\"One benefit of this maze format is that there is literally no salient touch data interfering with the visual input. When the visual input is relied on most heavily, and isn&rsquo;t contradicted by other sensory information, there&rsquo;s a higher chance of having the feeling of a classic out-of-body experience. That&rsquo;s the origin of this work, designing a way to see what role the sense of sight has over the location of the sense of self, but from an art history perspective it was also concerned with why visual art was so much more widely lauded and revered as the highest form in western civilisation. If we can pull your sense of sight out of your body will your sense of self follow\"</p>', '', '', '', '', '0', '1579760629', NULL, NULL),
(170, 'Leon Eckert', 'leon-eckert', 'http://codame.dreamhosters.com/uploaded_images/leon-eckert.gif', '<p><a href=\"http://geneticdancealgorithm.com\">Leon Eckert</a> is a German designer and photographer, currently based in NYC. The focus of his research is the critical discussion of technological progress and its impact on society at large. His work explores the tension between public&rsquo;s perception of technology&rsquo;s capabilities on the one side, and the reality of it on the other.</p>\r\n<p>While we include more and more devices into our lives everyday, it&rsquo;s only a few people that understand technology&rsquo;s inner workings and fewer still that are in charge of its doing. Leon is interested in both the psychological and sociological process at play as well as in finding ways to encourage everyone to question more actively how technology is used and who creates it. Currently he is pursuing his graduate studies at New York University in the Interactive Telecommunications Program (ITP).</p>\r\n<p><iframe src=\"https://www.youtube.com/embed/t2n9iqvWtW4\" width=\"900\" height=\"531\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>Genetic algorithms, inspired by Darwinian selection theory, symbolise the idea of machines emulating living organisms. This idea, filtered through fiction, news and advertisement, is fundamental to the anxieties connected to technological progress at large and the term Artificial Intelligence (AI) in particular. &nbsp;Reversing this, the Genetic Dance Performance translates the same algorithm back into the form of human movement to show that after all, the machines\' inner processes are not magic, but man-made.</p>\r\n<p><iframe src=\"https://www.youtube.com/embed/mXjbTtN10lA\" width=\"900\" height=\"531\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\">\r\n\r\n<p>Leon will be presentingÂ his \"Genetic Dance Algorithm\" as an installation at this year\'s <a href=\"/events/art-tech-festival-2015\">ART+TECH Festival MOVEMENT</a> on October 23rd+24th. Â </p></iframe></p>\r\n<p>Leon will be presenting his \"Genetic Dance Algorithm\" as an installation during our <a href=\"/events/art-tech-festival-2015\">ART+TECH Fesitval \"MOVEMENT\"</a> on October 23rd and 24th, 2015.</p>', 'https://twitter.com/eckert_leon', 'http://geneticdancealgorithm.com', '', '', '0', '1443675136', NULL, NULL),
(171, 'Zoey Vero', 'zoey-vero', 'http://codame.dreamhosters.com/uploaded_images/zoey-vero.jpg', '<div id=\"hxuro5wx\" class=\"s81\" style=\"margin: 0px; padding: 0px; border: 0px; outline: 0px; vertical-align: baseline; font-family: Arial, Helvetica, sans-serif; font-size: 10px; left: -210px; width: 1388px; position: absolute; top: 9px; height: 42px; background: transparent;\" data-menuborder-y=\"0\" data-menubtn-border=\"2\" data-ribbon-els=\"0\" data-label-pad=\"0\" data-ribbon-extra=\"0\" data-state=\"center notMobile\" data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$hxuro5wx\" data-dropmode=\"dropDown\">\r\n<div id=\"hxuro5wxitemsContainer\" class=\"s81itemsContainer\" style=\"margin: 0px; padding: 0px; border: 0px; outline: 0px; vertical-align: baseline; width: calc(100% - 0px); white-space: nowrap; position: relative; overflow: visible; display: inline-block; text-align: center; height: 42px; background: transparent;\" data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$hxuro5wx.0\"><br />\r\n<div data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$hxuro5wx.0.6.0\">&nbsp;</div>\r\n</div>\r\n<div id=\"hxuro5wxmoreButton\" data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$hxuro5wx.1\">&nbsp;</div>\r\n<div id=\"hxuro5wxdropWrapper\" data-drophposition=\"\" data-dropalign=\"center\" data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$hxuro5wx.2\">&nbsp;</div>\r\n</div>\r\n<div id=\"WPht22-n3l\" title=\"\" data-exact-height=\"NaN\" data-content-padding-horizontal=\"0\" data-content-padding-vertical=\"0\" data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$WPht22-n3l\">\r\n<div id=\"WPht22-n3llink\" data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$WPht22-n3l.0\">\r\n<div id=\"WPht22-n3limg\" data-state=\"loading\" data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$WPht22-n3l.0.0\">\r\n<p>Zoey Vero is a visual and installation artist with a background of a B.A in Architecture from UC Berkeley.</p>\r\n<p>Their current creative practice explores structures and systems, chaotic behaviors, glitches, and sexuality and gender.&nbsp; Immersive and visual environments have become a platform for them to share their artwork and experiment with different concepts ranging from material in motion graphics, photography and video art to generative and interactive art and sound.</p>\r\n<p>Zoey has also performed and displayed works internationally in festivals and galleries such as the Mapping Festival in Geneva, Switzerland, Live Performers Meeting in Eindhoven, Netherlands, Cascina Martesana in Milan, Italy, NGBK and Panke in Berlin and locally at the SkyHigh Odditorium, Mystic Creations, Lumen Labs, CSU Monterey, Nimby, Chabot Space and Science Center, F8, and DNA Lounge. Right now, they are primarily involved with personal projects and freelance work, but are always looking for new inspiration, collaboration, and other creative projects.</p>\r\n<p><iframe src=\"//player.vimeo.com/video/124725136?title=0&amp;byline=0\" width=\"425\" height=\"350\"></iframe></p>\r\n</div>\r\n</div>\r\n</div>\r\n<div id=\"hxusgyfe\" data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$hxusgyfe\">Zoey&nbsp;has&nbsp;been preseting&nbsp;<a href=\"/projects/transgress\">Trangress</a>&nbsp;in collaboration with artists&nbsp;<a href=\"/artists/zoey-vero\">Zoey Vero</a>&nbsp;and Colton Long at our<a href=\"/events/art-tech-festival-2015\">&nbsp;ART+TECH Festival \"MOVEMENT\"</a>.</div>\r\n<div data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$hxusgyfe\">&nbsp;</div>\r\n<div data-reactid=\".0.$SITE_ROOT.$desktop_siteRoot.$PAGES_CONTAINER.1.1.$SITE_PAGES.$c161y.1.$hxusgyfe\">&nbsp;</div>', '', 'http://www.zoeyvero.com/', '', '', '0', '1476656843', NULL, NULL),
(107, 'Gabriel Dunne', 'gabriel-dunne', 'http://codame.dreamhosters.com/uploaded_images/gabriel-dunne.jpg', '<div class=\"figure\">&nbsp;</div>\r\n<p><strong>CODAME Feature Artist: <a href=\"http://gabrieldunne.com\" target=\"_blank\">Gabriel Dunne </a></strong></p>\r\n<p>Gabriel&rsquo;s work spans fine art to design and technology in the mediums of installation, architecture, industrial design, and audio/visual programming. His pursuits insight the exploration of life, music and sound, structure, and systems in the natural world. His projects have been shown in internationally at conferences and exhibitions including New York MoMA, SIGGRAPH, Japan Media Arts Festival, Barcelona Festival Sonar, Interferenze Italia, and numerous publications. He is a San Francisco native, and holds a B.A. in Design | Media Arts from UCLA.</p>\r\n<p>Gabriel will be projection-mapping audio-reactive visuals onto a wall-sculpture.</p>\r\n<p>Immerse yourself into the <strong>Audio</strong> and <strong>Visual</strong> <strong>Senses</strong> explorations at the <a href=\"/events/art-tech-festival-2013\" target=\"_blank\">CODAME 2013 ART+TECH Festival</a> (Nov 1-2) with Gabriel.</p>', '', 'http://gabrieldunne.com', '', '', '0', '1563863619', NULL, NULL),
(108, 'Nonagon', 'nonagon', 'http://codame.dreamhosters.com/uploaded_images/nonagon.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p>CODAME Featured Artist:&nbsp;<strong>Nonagon</strong></p>\r\n<div>\r\n<div>As a producer, Nonagon is at once technical, intuitive, and expressive. His focus on marrying emotion and beauty to the raw core of underground dance music has led to a large body of original work running the gamut from grimy hip hop to cinematic drum &lsquo;n bass. He is also the production half of the new trip-hop / downtempo duo &ldquo;Dust Red Skies&rdquo; with vocalist Angie Donkin.</div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<div>As a performer, Nonagon brings the skill and technique of a traditional instrumentalist to the cutting-edge of electronic music performance. His live sets &mdash; always composed entirely of original music &mdash; are heavily improvised through hands-on manipulation of a carefully-curated combination of commercial and hand-built hardware and software. An engineer and contributor to live electronic music site&nbsp;<a href=\"http://controllerism.com/\" target=\"_blank\">Controllerism.com</a>, Nonagon is constantly pushing the state-of-the-art and setting new standards for electronic music performance.</div>\r\n<p><strong>Hear him yourself&nbsp;at the&nbsp;<a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival</a>&nbsp;(Nov 1-2)!</strong></p>\r\n</div>\r\n</div>', '', 'http://controllerism.com/', '', '', '0', '1436746738', NULL, NULL),
(109, 'Dust Red Skies', 'dust-red-skies', 'http://codame.dreamhosters.com/uploaded_images/dust-red-skies.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p>CODAME Featured Artist:&nbsp;<a href=\"http://dustredskies.bandcamp.com/\" target=\"_blank\"><strong>Dust Red Skies</strong></a></p>\r\n<div>Gritty and delicate by turns, <a href=\"http://dustredskies.bandcamp.com/\" target=\"_blank\">Dust Red Skies</a> paint emotional landscapes at the intersection of human experience and machine precision. A collaborative project from vocalist Angie Donkin and producer Nonagon, the duo fuse downtempo beats and atmospherics with cutting edge sound design to bring life to their forward-thinking musical vision.</div>\r\n<div>&nbsp;</div>\r\n<div>Check them out at the&nbsp;<a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival</a>&nbsp;(Nov 1-2)!</div>', '', 'http://dustredskies.bandcamp.com/', '', '', '0', '1436746711', NULL, NULL),
(110, 'Andrew Benson', 'andrew-benson', 'http://codame.dreamhosters.com/uploaded_images/andrew-benson.png', '\r\n						<p><strong>CODAME Featured Artist:</strong> <a href=\"http://pixlpa.com/\" target=\"_blank\">Andrew Benson</a></p>\r\n<p>Andrew is a visual artist who modifies pixels, creates video loops, animates, draws, and combines it all into live performances.</p>\r\n<p>Combining live action video captures with glitch art, fifth generation video game, and 8bit music, Andrew creates trippy video loops and then launches them both online and in person during his live performances.</p>\r\n<p><iframe src=\"http://player.vimeo.com/video/63948025\" width=\"917\" height=\"688\" frameborder=\"0\"></iframe></p>\r\n<p><strong>See for yourself at the 5ENSES Experience at the <a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival</a> (Nov 1-2)!</strong></p>\r\n											', '', 'http://pixlpa.com/', '', 'http://www.codame.com/post/portfolio/andrew-benson/', '0', '', NULL, NULL),
(111, 'Dolores Joya', 'dolores-joya', 'http://codame.dreamhosters.com/uploaded_images/dolores-joya.png', '\r\n						<p><iframe src=\"http://player.vimeo.com/video/63537186\" height=\"225\" width=\"400\" frameborder=\"0\"></iframe></p>\r\n<p><strong>CODAME Featured Artist:</strong> <a href=\"http://vimeo.com/user2662946\" target=\"_blank\">Dolores Joya</a></p>\r\n<p>Dolores is a UX Designer/Artist. She makes sculptures with projection mapping.</p>\r\n<p>She is working to integrate Arduino sensors. Currently, she integrates live camera feed and the visuals are audio responsive in a VJ fashion.</p>\r\n<p><strong>See for yourself at the 5ENSES Experience at the <a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival</a> (Nov 1-2)!</strong></p>\r\n											', '', 'http://vimeo.com/user2662946', '', 'http://www.codame.com/post/portfolio/codame-featured-artist-dolores-joya-dolores-is-a/', '0', '', NULL, NULL),
(112, 'Alexandernaut', 'alexandernaut', 'http://codame.dreamhosters.com/uploaded_images/alexandernaut.jpg', '<div class=\"figure\">\r\n<figure></figure>\r\n</div>\r\n<p><strong>CODAME Featured Artist:</strong> <a href=\"http://www.alexandernaut.com\" target=\"_blank\">Alexandernaut</a></p>\r\n<p>Alexandernaut is an electrical engineer, software developer, and computer musician. He designs hardware controllers, develops professional iPad music applications, and composes music that sounds like you survived the apocalypse.&nbsp;</p>\r\n<p>See for yourself at the 5ENSES Experience&nbsp;at the&nbsp;<a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival</a>&nbsp;(Nov 1-2)!</p>', '', 'http://www.alexandernaut.com', '', '', '0', '1436744593', NULL, NULL),
(113, 'CCRMA', 'ccrma', 'http://codame.dreamhosters.com/uploaded_images/ccrma.png', '\r\n						<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"\"></figure>\r\n</div>\r\n<p><strong>CODAME Featured Artists:</strong> <a href=\"https://ccrma.stanford.edu/\" target=\"_blank\">CCRMA</a></p>\r\n<p><span>The Stanford Center for Computer Research in Music and Acoustics (CCRMA, pronounced “karma”) is a multi-disciplinary facility where musicians and researchers work together using computer-based technology both as an artistic medium and as a research tool. </span></p>\r\n<p><span>CCRMA Members Performing at 5ENSES Include:</span></p>\r\n<p><span><a href=\"http://www.artinventionmusic.com/\" target=\"_blank\">Sasha Leitman</a> </span></p>\r\n<p id=\"docs-internal-guid-6ecc578d-169a-ca45-d559-74b156a47648\"><span>Sasha Leitman is a musician, artist, teacher and inventor. She currently runs the “Max Lab – an Interface Prototyping Lab” at Stanford University’s Center for Computer Research in Music and Acoustics (CCRMA) where she has collaborated and co-taught with Jonathan Abel, Trimpin, and the late Max Matthews. She has been making musical instruments, new interfaces for musical expression and sound art installations for ten years.</span></p>\r\n<p><span><a href=\"https://ccrma.stanford.edu/~nando/\" target=\"_blank\">Fernando Lopez-Lezcano</a> </span></p>\r\n<p><span id=\"docs-internal-guid-6ecc578d-169a-e608-08a1-1c88131d63f1\">Fernando Lopez-Lezcano – </span><span>composer, performer, lecturer & sysadmin at CCRMA, his music blurs the line between technology and art, and is as much about form and sound processing, synthesis and spatialization, as about algorithms and custom software he writes for each piece. </span></p>\r\n<p><span><a href=\"https://ccrma.stanford.edu/people/carr-wilkerson\" target=\"_blank\">Carr Wilkerson</a> </span></p>\r\n<p id=\"docs-internal-guid-6ecc578d-169b-1044-fbb1-4fba08b16249\"><span>Carr Wilkerson is a System Administrator at CCRMA specializing in Linux and Mac OS systems.  He is a controller and software system builder and sometime performer/impresario, instructor and researcher.</span></p>\r\n<p><span><a href=\"http://brunoruviaro.com\" target=\"_blank\">Bruno Ruviaro</a> </span></p>\r\n<p><span id=\"docs-internal-guid-6ecc578d-169a-9358-4273-b073f31288a7\">Bruno Ruviaro is a San Francisco based electronic musician from São Paulo, Brazil. He will be performing live-electronics in the audio tent of the 5ENSES room. Bruno’s interests range from electronic and acoustic music composition, theater, Linux, SuperCollider, and Erik Satie.</span></p>\r\n<p><span><a href=\"https://ccrma.stanford.edu/~lukedahl/\" target=\"_blank\">Luke Dahl</a>  </span></p>\r\n<p id=\"docs-internal-guid-6ecc578d-169b-216c-1ce0-b7f912772f7a\"><span>Luke Dahl is a computer musician and PhD student at CCRMA where he conducts research into new musical interactions and music-related movement. He has composed works for the Stanford Laptop and Mobile Phone Orchestras, an interactive piece for live Twitter data, and enjoys making electronic dance music. He will be performing live textural improvisations in the audio room at 5enses.</span></p>\r\n<p><span><a href=\"https://ccrma.stanford.edu/~colinsul/\" target=\"_blank\">Colin Sullivan</a><br> </span></p>\r\n<p id=\"docs-internal-guid-6ecc578d-169a-b74d-a6b4-8d3928a05463\"><span>Colin Sullivan is a recent Master’s student in Music, Science, and Technology at CCRMA where he researched and developed systems for algorithmic music composition, audio synthesis, and collaborative musical applications.  He will be performing original electronic music in the audio room at 5ENSES.</span></p>\r\n<p><strong>Hear them yourself at the <a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival</a> (Nov 1-2)!</strong></p>\r\n											', '', 'https://ccrma.stanford.edu/', '', 'http://www.codame.com/post/portfolio/codame-featured-artists-ccrma-the-stanford/', '0', '', NULL, NULL),
(114, 'E Dyer', 'e-dyer', 'http://codame.dreamhosters.com/uploaded_images/e-dyer.jpg', '<div class=\"figure\">E Dyer is a Bay Area artist. His work could mean a lot of things. It doesn&rsquo;t have to mean anything, because it&rsquo;s not what you look at that matters, it&rsquo;s what you see. He primarily creates installations using bright fabrics, household objects, and paintings he makes with frames he finds on the streets of San Francisco.&nbsp;</div>', 'https://twitter.com/edyerart', 'https://edyerart.com/', 'edyerart@gmail.com', '', '0', '1669741212', '', 'https://www.instagram.com/edyer.art/'),
(115, 'Andrea Starr', 'andrea-starr', 'http://codame.dreamhosters.com/uploaded_images/andrea-starr.jpg', '\r\n						<p><img alt=\"\" src=\"http://starpause.com/gfx/clonicoptics/C02.gif\"></p>\r\n<p>CODAME Featured Artist:<a href=\"http://clonicoptics.tumblr.com\" target=\"_blank\"> Andrea Starr</a></p>\r\n<p><span>Drea enjoys playing with voltages to create shapes and patterns, connected with multiple cables, while </span>manipulating frequencies by twisting nobs; this is done through an analog video synthesizer. Considering there are often flashing lights, as this synthesizer is sound reactive, it came to her surprise when she found it soothing, not seizures provoking, considering she deals with generalized epileptic seizures. More about Drea’s stories on dealing with epilepsy at <a href=\"http://anstarrdrea.wordpress.com/2013/10/30/sf/\" target=\"_blank\">Keppra Nation blog</a>. <a href=\"https://twitter.com/KeppraNation\">@KeppraNation</a></p>\r\n<p>Currently she is working on a project called <a href=\"http://clonicoptics.tumblr.com\" target=\"_blank\">Clonic Optics</a> using the video synthesizer and with the back story of her epilepsy.</p>\r\n<p> </p>\r\n<p><strong>Join us for a 5ENSES (+ sixth sense mystery experience) with <a href=\"http://anstarrdrea.wordpress.com/\" target=\"_blank\">Andrea Starr</a> at <a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a></strong></p>\r\n											', '', 'http://clonicoptics.tumblr.com', '', 'http://www.codame.com/post/portfolio/codame-featured-artist-andrea-starr-andrea-starr/', '0', '', NULL, NULL),
(116, 'Max Capacity', 'max-capacity', 'http://codame.dreamhosters.com/uploaded_images/max-capacity.gif', '<div class=\"figure\">&nbsp;</div>\r\n<p><strong>CODAME Featured Artist:</strong> <a href=\"http://maxcapacity.tumblr.com/\" target=\"_blank\">Max Capacity</a></p>\r\n<p>Max Capacity suffers from a severe but well documented case of data-addiction, as well as a fetish for obsolete media and electronics. He currently lives and works on the outskirts of Silicon Valley, California, planning super-villain style revenge on the world.</p>\r\n<p><strong>Join us for a&nbsp;5ENSES&nbsp;(+ sixth sense&nbsp;mystery&nbsp;experience)&nbsp;with <a href=\"http://maxcapacity.tumblr.com/\" target=\"_blank\">MAX CAPACITY</a>&nbsp;at&nbsp;<a href=\"/festival\" target=\"_blank\">CODAME 2013&nbsp;ART+TECH&nbsp;Festival (Nov 1-2)</a></strong></p>', '', 'http://maxcapacity.tumblr.com/', '', '', '0', '1436746561', NULL, NULL),
(117, 'Bill Hsu / Ollie Bown / raven', 'bill-hsu-ollie-bown-raven', 'http://codame.dreamhosters.com/uploaded_images/bill-hsu-ollie-bown-raven.jpg', '\r\n						<p><strong>CODAME Featured Artists: </strong>Bill Hsu/Ollie Bown/raven Ollie Bown & raven are 2/5 of the Sydney-based improv quintet Tangents. As a duo their live set consists of long-form improvisations around Bown’s software that loops, layers and resamples raven’s cello along with beats and sounds. Sets frequently move in abstract directions, but keep a melodic and rhythmic core. For their ATA set, Bill Hsu will work with interactive video that combines real-world footage with generative processes. Ollie Bown: <a href=\"http://olliebown.com\" target=\"_blank\">http://olliebown.com</a> Bill Hsu: <a href=\"http://unixlab.sfsu.edu/~whsu/art.html\" target=\"_blank\">http://unixlab.sfsu.edu/~whsu/art.html</a> Join us for a 5ENSES (+ sixth sense mystery experience) with Bill Hsu, Ollie Bown and Raven at <a href=\"http://codame.com/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a> <iframe src=\"//player.vimeo.com/video/28094161?title=0&byline=0&portrait=0\" width=\"800\" height=\"590\" frameborder=\"0\" webkitallowfullscreen=\"\" mozallowfullscreen=\"\" allowfullscreen=\"\"></iframe></p>\r\n											', '', '', '', 'http://www.codame.com/post/portfolio/codame-featured-artists-bill-hsu-ollie/', '0', '', NULL, NULL),
(118, 'Beeple', 'beeple', 'http://codame.dreamhosters.com/uploaded_images/beeple.png', '<p><strong>CODAME Featured Artist:</strong> <a href=\"http://www.beeple-crap.com\" target=\"_blank\">Beeple</a></p>\r\n<p>Beeple is Mike Winkelmann.</p>\r\n<p>Mike Winkelmann is currently a graphic designer living and working in Neenah, Wisconsin, USA. Beeple is the pseudonym for his personal work that includes short films, live visuals, graphic design, music and drawings. Most of his current work focuses on ways to visual music through video. His work has screened at onedotzero, Siggraph, Optronica, the Ann Arbor Film Festival, the Milwaukee Art Museum, the Chicago Underground Film Festival, and many more. He has also released work on Flying Lotus Brainfeeder label.</p>\r\n<p><strong>See for yourself at the 5ENSES Experience at the <a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival</a>&nbsp;(Nov 1-2)!</strong></p>\r\n<p style=\"text-align: center;\"><iframe src=\"http://player.vimeo.com/video/15572863\" width=\"800\" height=\"550\" frameborder=\"0\"></iframe></p>', 'https://twitter.com/beeple', 'http://www.beeple-crap.com', 'winkelmm@gmail.com ', '', '0', '1615593710', '', 'https://www.instagram.com/beeple_crap/'),
(119, 'Jonathan Wallraven', 'jonathan-wallraven', 'http://codame.dreamhosters.com/uploaded_images/jonathan-wallraven.jpg', '<p class=\"p1\"><span class=\"s1\">\"Anything could happen to you anytime and you cannot do nothing about that\"</span></p>\r\n<p class=\"p2\"><span class=\"s2\"><a href=\"http://jonathanwallraven.com/\">Jonathan Wallraven</a></span><span class=\"s1\">&nbsp;is a San Francisco-based artist who uses intricate, stark black-and-white sumi ink installations to overwhelm his audiences in immersive experiences. Wallraven uses manic, flowing lines and audio-visual projections to depict anamorphically distorted arrangements of friends, lovers and symbols.</span></p>\r\n<p class=\"p3\"><span class=\"s3\">Wallraven&rsquo;s work has been exhibited in the&nbsp;<a href=\"about:blank\"><span class=\"s2\">Dissident Futures Arts &amp; Ideas Festival</span></a>&nbsp;at YBCA, &nbsp;<a href=\"http://www.artslant.com/sf/events/show/261819-the-moment-for-ink-shaking-off-tradition\"><span class=\"s2\">the San Francisco&rsquo;s Chinese Culture Foundation</span></a>, and&nbsp;<a href=\"http://kokorostudio.us/\"><span class=\"s2\">Kokoro Studio</span></a>.</span></p>\r\n<p class=\"p2\"><span class=\"s1\">Wallraven was trained in printmaking, drawing, and sculpture at Middle Tennessee State University, and has recently received his MFA from California College of the Arts (CCA). &nbsp;&nbsp;He is currently curating the&nbsp;<a href=\"http://www.codame.com/post/portfolio/call-for-entries-codame-arttech-film-fest/\"><span class=\"s4\">CODAME ART+TECH &ldquo;Film&rdquo; Fest</span></a>, which is still seeking entries.</span></p>', '', 'http://jonathanwallraven.com/', '', '', '0', '1436744538', NULL, NULL),
(228, 'Cam Altamura', 'cam-altamura', 'http://codame.dreamhosters.com/uploaded_images/cam-altamura.jpg', '<p>MoGrapher, Graphic and 3D Designer. Vegan Cyclist.&nbsp;</p>', 'https://twitter.com/camaltamura', 'http://www.camaltamura.com/', 'starpause@gmail.com', '', '0', '1476714818', NULL, NULL),
(280, 'Rachel Sowa', 'rachel-sowa', 'http://codame.dreamhosters.com/uploaded_images/rachel-sowa.jpg', '<p>Rachel Sowa is a graduate of the College of Creative Studies at UC Santa Barbara, where she studied Computer Science with an emphasis in media arts and music technology. When she isn&rsquo;t working, she enjoys tinkering around with Arduinos and Max/MSP and exploring how technology can help people interact with music and art in new and creative ways. Some of her projects include a voice synthesizer in Max/MSP controlled by a glove with velostat pressure sensors, a vocoder programmed in Python using linear predictive coding, and an interactive Neopixel light display controlled over the internet via an Arduino Wi-Fi shield. Rachel grew up in the San Francisco Bay Area, but she is currently based in Seattle.</p>', '', '', 'r55sowa@gmail.com', '', '0', '1517941250', NULL, NULL),
(229, 'Victoria Mara Heilweil', 'victoria-mara-heilweil', 'http://codame.dreamhosters.com/uploaded_images/victoria-mara-heilweil.jpeg', '<p class=\"p1\"><span class=\"s1\">Victoria Mara Heilweil is a nationally exhibited photographic artist, curator and educator.</span></p>\r\n<p class=\"p1\"><span class=\"s1\">She received her Masters of Fine Arts from California College of the Arts in 1995. Her work has been included in exhibitions at the de Young Museum, San Jose Institute&nbsp;for Contemporary Art, Intersection for the Arts, Southern Exposure, California Academy of Sciences, Art Works Downtown, PHOTO Fine Art and Rayko Photo Gallery in the Bay Area, wall space gallery and Robert V. Fullerton Art Museum in Southern&nbsp;California, University Art Gallery at California State Chico, Minneapolis Photo Center, Visual Arts Center in Portsmouth, VA and Washington Square Art Galleries in New York City. She has also created public and community based art works in conjunction with&nbsp;the ZERO1 Biennial in San Jose, CA and the Bayview Opera House in San Francisco, CA.&nbsp;&nbsp;</span></p>\r\n<p class=\"p1\"><span class=\"s1\">In 2014 Victoria was awarded a grant from the Puffin Foundation.</span></p>', '', 'http://www.victoriaheilweil.com', 'victoriaheilweil@gmail.com', '', '0', '1478630666', NULL, NULL),
(120, 'DC Spensley', 'dc-spensley', 'http://codame.dreamhosters.com/uploaded_images/dc-spensley.png', '<p dir=\"ltr\">DC Spensley Bio 2021 Artist, writer, technologist, and musician best known for pioneering art and performances in social virtual worlds that push the boundaries of art experience by inventing new ways to use code, theater, and performance to transform simulated space into a more human place. DC&rsquo;s work has been exhibited internationally at venues like Ars Electronica, where he received a UNESCO award for virtual architecture, Boston Cyber Arts, Dutch Electronic Arts Festival, Yerba Buena Center for the Arts, ISEA, and many others. A graduate of the San Francisco Art Institute, and alum of the CADRE Laboratory for New Media in Silicon Valley, Spensley&rsquo;s work has been written about in the New York Times, Reuters, Fibre Culture Journal, Step Inside Design, and myriad blogs, books, and academic journals. Professional engagements include Principle Illustrator for The Center for Science Education at Space Sciences Laboratory at UC Berkeley, Co-chair of NASA&rsquo;s Sun Earth Connection Education Forum, contributing writer for Art21 online, and most recently as artistic director for the 2020 Lumen Prize virtual exhibition catalog presented by Leonardo.&nbsp;</p>', '', 'http://www.dcspensley.com/', '', '', '0', '1625532998', 'https://codame.threadless.com/collections/dc-spensley', ''),
(246, 'Diego Marcos', 'diego-marcos', 'http://codame.dreamhosters.com/uploaded_images/diego-marcos.jpg', '<p>Diego specializes in&nbsp;User Centered Design, Human Interfaces design, Usability, Scientific Software, Data Analysis andVisualization, Open Source, Community and collaborative development. He finely crafts tweets about VR, <a href=\"https://aframe.io/\" target=\"_blank\">A-Frame</a> and the struggle of software creation.</p>', 'http://twitter.com/dmarcos/', 'https://www.linkedin.com/in/diegomarcos/', 'dmarcos@mozilla.com', '', '0', '1494536803', NULL, NULL),
(121, 'Justin Kinder', 'justin-kinder', 'http://codame.dreamhosters.com/uploaded_images/justin-kinder.jpg', '<header>\r\n<div>&ldquo;3d art for games and printing&rdquo;</div>\r\n</header>\r\n<div>\r\n<article id=\"post-2892\">\r\n<p dir=\"ltr\"><img src=\"/uploaded_images/justin-kinder-starwars-character-design.jpg\" alt=\"\" /></p>\r\n<p dir=\"ltr\">CODAME Featured Artist:&nbsp;<a href=\"http://www.justinkinderart.com/\">Justin Kinder</a>&nbsp;is an emerging 3d prop artist, specializing in hand-painted modelling and texturing for video games. Since November of 2013, he&rsquo;s been using applications such as: Maya, Zbrush, 3D Coat, Photoshop, Marmoset, Unity, and XNormal to develop his work.</p>\r\n<p dir=\"ltr\">Currently he resides in San Francisco, and is working with&nbsp;<a href=\"http://codame.tumblr.com/\">CODAME</a>&nbsp;to re-design a the <a href=\"/projects/art-tech-mascot\">art+tech-mascot</a>&nbsp;inspired by the&nbsp;<a href=\"http://www.jam-factory.com/droplet/\">Droplet.</a></p>\r\n<p dir=\"ltr\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/justin-kinder-hp-orc.jpg\" alt=\"\" /></p>\r\n<p>Want to see more? &nbsp;<a href=\"/artists\">Browse CODAME&rsquo;s Other Featured Artists</a></p>\r\n</article>\r\n</div>', '', 'http://www.justinkinderart.com/', '', '', '0', '1472524704', NULL, NULL),
(210, 'Gary Boodhoo', 'gary-boodhoo', 'http://codame.dreamhosters.com/uploaded_images/gary-boodhoo.jpg', '<p dir=\"ltr\">Gary Boodhoo is an interface designer and game developer whose creative practice uncovers emotional connections with smart objects in social spaces. &ldquo;I glimpsed the Self within the computer and wondered if others would see it too\", Boodhoo ventures. He describes his current work as science fiction cave painting owing to its spontaneous creation of ritual imagery.</p>\r\n<p dir=\"ltr\">His work has been featured at the Game Developers Conference, Stanford Linear Accelerator and California Academy of Sciences. Since 2018, his workshop series, Make Art with AI has introduced participants to the robot uprising through hands on experience and play.</p>\r\n<p dir=\"ltr\"><iframe src=\"https://player.vimeo.com/video/313419542?color=ffcc00&amp;title=0&amp;byline=0&amp;portrait=0\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe>&nbsp;</p>\r\n<h2 dir=\"ltr\">Interview with Gary Boodhoo</h2>\r\n<p id=\"1966\" data-selectable-paragraph=\"\">CODAME Featured Artist&nbsp;Gary Boodhoo&nbsp;is an interaction designer who draws on his digital training as well as a longtime fascination with psychedelic experiences to create his artworks. Under the label,&nbsp;DeepDreamVisionQuest, he explores the nature of games and perception, producing what he refers to as &ldquo;science fiction cave paintings.&rdquo; Recalling the ancient images at Lascaux, this term is one way to describe the primal human expression he seeks to make possible using cutting edge visualization technology.</p>\r\n<p id=\"147b\" data-selectable-paragraph=\"\">In my recent conversation with Boodhoo, we discussed his technical background and the multiple threads of inquiry that led him to DeepDreamVisionQuest. We also examined the aesthetic and intellectual challenges that inevitably occur when enlisting artificial intelligence and machine learning in creating original artwork.</p>\r\n<p id=\"7889\" data-selectable-paragraph=\"\">A Starting Point in Computational Graphics</p>\r\n<p id=\"12a7\" data-selectable-paragraph=\"\">Boodhoo has been using computers to program or perform art since his first machine in 1979 (a TRS-80 Model 1). As a digital designer, Boodhoo has been creating visual graphics and interfaces for over two decades. A lifelong student and practitioner of interactive media, he studied Computer Graphics, Interactive Media, and Performance Art at the Massachusetts College of Art.</p>\r\n<p id=\"9a3d\" data-selectable-paragraph=\"\">He was drawn to music as a child, but he also had an early interest in computer graphics, and he excelled at drawing. While he enrolled in art school with the intent of practicing illustration, he says, the &ldquo;musical way of thinking&rdquo; never left him, and he frequently returns to music as a metaphor or method for exploring ideas.</p>\r\n<p id=\"1e36\" data-selectable-paragraph=\"\">Once enrolled at MassArt, he followed the most interesting people he could find, which led him to the&nbsp;The Studio for Interrelated Media. While there, he gained a deep education in multimedia art practices and history, often learning firsthand from the other students and faculty around him. Some of them had been working with computers in art since the 1960s, decades before they were mainstream. Before long, he says, &ldquo;I was spending most of my time, sometimes even sleeping, in the computer lab.&rdquo;</p>\r\n<p id=\"24df\" data-selectable-paragraph=\"\">After graduation, he began his career in digital graphics. &ldquo;I was a broadcast designer, where I worked in local Orlando TV, The Golf Channel, and at post production boutiques in Atlanta, doing motion graphics,&rdquo; he says. Around 2000, though, the work dried up. Once again, interesting people helped point him in the right direction, when some friends at Electronic Arts tapped him to work on sports games.</p>\r\n<p id=\"cba5\" data-selectable-paragraph=\"\">That move turned out to be fateful. Though Boodhoo&rsquo;s experience creating real-time graphics for sports broadcast was only superficially related to his new game design work, he found himself pondering some fundamental questions about what he was making: &ldquo;How are people responding to and interacting with graphics?&rdquo;</p>\r\n<p id=\"78d4\" data-selectable-paragraph=\"\">The switch from broadcast to interactive design was an important jump from creating data displays (infographics for decoration or advertising) to creating interactive displays that that directly affected players moment to moment. &ldquo;I started thinking a lot about player reactions to responsive graphics and how user interfaces supported the larger narratives of the games we were making,&rdquo; he says. &ldquo;I&rsquo;ve been hacking that problem for some 20 years with no end in sight. Humans are complicated.&rdquo;</p>\r\n<p id=\"fb3b\" data-selectable-paragraph=\"\">Ultimately, the problem of designing game interfaces often rests on a single, simple question: &ldquo;What is the smallest bit of [visual] information I can give you that&rsquo;s meaningful, and that expands into a greater meaning?&rdquo;</p>\r\n<p id=\"c617\" data-selectable-paragraph=\"\">This question continues to resonate throughout his work.</p>\r\n<p id=\"1468\" data-selectable-paragraph=\"\">Discovering Deep Dream</p>\r\n<p id=\"8042\" data-selectable-paragraph=\"\">As a learner, Boodhoo is curious, voracious, and highly self-directed. Embarking on his game design career, he realized that programming was often the best way to show and tell, and threw himself into improving that skill. Similarly, when he first encountered Deep Dream, a computer vision program created by a&nbsp;Google&nbsp;engineer named&nbsp;Alexander Mordvintsev, he was hooked and quickly driven to learn everything about it.</p>\r\n<p id=\"e224\" data-selectable-paragraph=\"\">&ldquo;About two years ago, I started seeing this Deep Dream imagery on the internet. Honestly, it blew my mind,&rdquo; he says. He was immediately struck by the way Deep Dream images seemed to illustrate the impossibly surreal visions that one might have during a psychedelic experience.</p>\r\n<blockquote>\r\n<p id=\"7b81\" data-selectable-paragraph=\"\">&ldquo;I had no idea how it was made. I didn&rsquo;t know much about machine learning at the time. &hellip;I dove deeper. I especially appreciated resources like&nbsp;GitHub, which is such a vital repository of technical knowledge, encouragement and workarounds during this time.&rdquo;</p>\r\n</blockquote>\r\n<p id=\"1bec\" data-selectable-paragraph=\"\">The Deep Dream software was originally developed to visualize the internal states of neural networks used for classifying images. Boodhoo describes Deep Dream as &ldquo;an amplifier.&rdquo;</p>\r\n<figure>\r\n<div>&nbsp;</div>\r\n<img src=\"https://miro.medium.com/max/1300/1*Lk8bm8G0k7JJHMNRJWPAKA.gif\" sizes=\"650px\" srcset=\"https://miro.medium.com/max/552/1*Lk8bm8G0k7JJHMNRJWPAKA.gif 276w, https://miro.medium.com/max/1104/1*Lk8bm8G0k7JJHMNRJWPAKA.gif 552w, https://miro.medium.com/max/1280/1*Lk8bm8G0k7JJHMNRJWPAKA.gif 640w, https://miro.medium.com/max/1300/1*Lk8bm8G0k7JJHMNRJWPAKA.gif 650w\" alt=\"Image for post\" width=\"650\" height=\"366\" /></figure>\r\n<blockquote>\r\n<p id=\"0412\" data-selectable-paragraph=\"\">&ldquo;A neural network is a bit of a black box,&rdquo; he says. &ldquo;It&rsquo;s not that any one neuron is difficult to understand, it&rsquo;s just a linear equation, but imagine a million neurons working together. That&rsquo;s more than the human mind can understand. These engineers started creating tools to look inside neural networks and see what they were doing. DeepDreamVisionQuest came out of that.&rdquo;</p>\r\n</blockquote>\r\n<p id=\"8435\" data-selectable-paragraph=\"\">When asked to describe the process more precisely, Boodhoo says,</p>\r\n<blockquote>\r\n<p id=\"78f8\" data-selectable-paragraph=\"\">&ldquo;Instead of putting an image in and getting an answer, we listen to the signals. Neural activity is drawn on top of the picture that caused the activity. Next, we present the network with this new picture, creating a feedback loop. This ends up exaggerating any features it detects.&rdquo;</p>\r\n</blockquote>\r\n<p id=\"49dd\" data-selectable-paragraph=\"\">The result of this process, he explains, is nothing short of incredible.&nbsp;&ldquo;The software doesn&rsquo;t generate fully realized images all at once. Instead the neural network&nbsp;dreams&nbsp;repeatedly, building an image from statistics. It&rsquo;s similar to imagining faces and other shapes in clouds.&nbsp;It&rsquo;s just noise, but our tendency to see patterns is overwhelming and self-reinforcing.&rdquo;</p>\r\n<p id=\"9b4a\" data-selectable-paragraph=\"\">While the software creates feedback loops by exploiting and manipulating what is occurring in the neural network, an artist like Boodhoo skillfully influences this process of reverse engineering images, to create subtle and varied outputs.</p>\r\n<figure>\r\n<div>\r\n<div>&nbsp;</div>\r\n<img src=\"https://miro.medium.com/max/1280/0*YMzWD7TqZX1REzOI.\" sizes=\"640px\" srcset=\"https://miro.medium.com/max/552/0*YMzWD7TqZX1REzOI. 276w, https://miro.medium.com/max/1104/0*YMzWD7TqZX1REzOI. 552w, https://miro.medium.com/max/1280/0*YMzWD7TqZX1REzOI. 640w\" alt=\"Image for post\" width=\"640\" height=\"640\" /></div>\r\n<figcaption data-selectable-paragraph=\"\">A participant encounters DeepDreamVisionQuest by Gary Boodhoo, installation view.</figcaption></figure>\r\n<p id=\"589b\" data-selectable-paragraph=\"\">Boodhoo raises the level of complexity by adding real time interactivity into his installations with a webcam. Participants are able to approach the camera and provide live input for the software, then watch their images transformed on a screen.</p>\r\n<blockquote>\r\n<p id=\"14e2\" data-selectable-paragraph=\"\">&ldquo;These networks are deterministic,&rdquo; Boodhoo points out. &ldquo;If I just take one image, just a photograph, and run it through [the software], I&rsquo;ll always get the same result. I can change the parameters and I&rsquo;ll get different results, but&hellip;it&rsquo;s just an effect. I realized I needed to show it something unpredictable, and that&rsquo;s why I added the camera.&rdquo;</p>\r\n</blockquote>\r\n<p id=\"24c9\" data-selectable-paragraph=\"\">Because live video will never provide the same image twice, the output is always changing, creating an unending stream of machine-hallucinated live imagery. The addition of the camera also brings a game-like quality to the experience.</p>\r\n<blockquote>\r\n<p id=\"237d\" data-selectable-paragraph=\"\">&ldquo;I wouldn&rsquo;t really call it a video game,&rdquo; Boodhoo says, &ldquo;but some people really anticipate and lead it in ways I myself am unable to.&rdquo;</p>\r\n</blockquote>\r\n<p id=\"ee6d\" data-selectable-paragraph=\"\">For Boodhoo, the most enjoyable video games are those without clear points, winners, or losers &mdash; games that present intriguing interactive experiences and ask, &ldquo;What if?&rdquo; By this definition of a game, DeepDreamVisionQuest certainly qualifies.</p>\r\n<p id=\"2e62\" data-selectable-paragraph=\"\">Science Fiction Cave Paintings</p>\r\n<p id=\"62f9\" data-selectable-paragraph=\"\">Boodhoo began to think about his work as &ldquo;cave painting&rdquo; after he realized that the imagery was resonating with viewers and participants in a visceral way.</p>\r\n<blockquote>\r\n<p id=\"911e\" data-selectable-paragraph=\"\">&ldquo;The imagery was not new,&rdquo; he says. &ldquo;It was ancient. I enjoy Jungian psychology quite a bit, so I started thinking about archetypes and collective consciousness. I came to realize that these things aren&rsquo;t being generated by the computer. Instead, we&rsquo;re creating poetry together. You complete the circuit.&rdquo;</p>\r\n</blockquote>\r\n<p id=\"326a\" data-selectable-paragraph=\"\">When viewers first encounter Deep Dream-generated images, one of the most common reactions is to liken the images to a drug trip. Boodhoo does the same, and yet, he questions whether that reaction is in itself &ldquo;an initial non-acceptance&rdquo; as an almost defensive psychological reaction: it can be tempting to dissemble, to blame something external, like an intoxicant, for what one sees, but hallucinogenic drugs often serve to uncover images that already exist in the mind, not wholly create them.</p>\r\n<blockquote>\r\n<p id=\"fe9f\" data-selectable-paragraph=\"\">&ldquo;To dig deeper than that,&rdquo; he continues, &ldquo;Why these images? Why is this one leading to that one? Why does this one creep me out while another makes me laugh? As a designer, most of what I do is inception: reducing ideas to easily graspable forms. I began to see the memories represented in neural networks as a kind of universal language.&rdquo;</p>\r\n</blockquote>\r\n<p id=\"4ac0\" data-selectable-paragraph=\"\">When asked about the state of technology, and the way artists will incorporate AI into creative practice, Boodhoo is optimistic.</p>\r\n<blockquote>\r\n<p id=\"d7f6\" data-selectable-paragraph=\"\">&ldquo;I think of cave paintings, and I think of people taking a torch, huddling, crawling into a very inaccessible place that opens up and becomes a holodeck&hellip;so to speak.&rdquo;</p>\r\n</blockquote>\r\n<p id=\"c53e\" data-selectable-paragraph=\"\">It&rsquo;s an inspiring, dream-like vision.</p>\r\n<figure style=\"text-align: center;\">\r\n<div tabindex=\"0\">\r\n<div>&nbsp;</div>\r\n<img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"https://miro.medium.com/max/2800/0*O5EuDQ9Sf5c4LgbI.\" sizes=\"700px\" srcset=\"https://miro.medium.com/max/552/0*O5EuDQ9Sf5c4LgbI. 276w, https://miro.medium.com/max/1104/0*O5EuDQ9Sf5c4LgbI. 552w, https://miro.medium.com/max/1280/0*O5EuDQ9Sf5c4LgbI. 640w, https://miro.medium.com/max/1400/0*O5EuDQ9Sf5c4LgbI. 700w\" alt=\"Image for post\" width=\"1400\" height=\"1050\" /></div>\r\n<figcaption data-selectable-paragraph=\"\">Find Gary Boodhoo at CODAME ART+TECH Festival 2018</figcaption></figure>\r\n<p id=\"3dd7\" data-selectable-paragraph=\"\">&nbsp;</p>\r\n<p>&nbsp;</p>', '', 'https://www.garyboodhoo.world/', 'gboodhoo@skinjester.com', '', '0', '1607816707', '', NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(122, 'Micah Scott', 'micah-scott', 'http://codame.dreamhosters.com/uploaded_images/micah-scott.png', '<p style=\"text-align: left;\"><strong>CODAME Featured Artist:&nbsp;</strong><a href=\"http://scanlime.org/\">Micah Elizabeth Scott</a>&nbsp;has been doing unconventional things with technology for her whole life &mdash; exploring the boundaries between hardware and software. She&rsquo;s built satellites, robots, virtual machines, graphics drivers, CPU emulators, networking stacks, USB controllers, reverse engineering tools, and pretty much everything in between.</p>\r\n<p dir=\"ltr\" style=\"text-align: left;\">Recently, Scott won the <a href=\"https://developer.mozilla.org/demos/devderby/2013/april\">Web Workers Dev Derby</a> with <a href=\"https://developer.mozilla.org/demos/detail/zen-photon-garden\">Zen photon garden</a>, her impressive, and fun, interactive web raytracer. Her current work explores light, perception, and human interconnectedness. &nbsp;Her interests include interactive sculpture, control loops, emergent behavior, unconventional human interfaces, and using technology to help illuminate what makes us human.</p>\r\n<p><iframe src=\"//www.youtube.com/embed/obbew_7_Xo8?feature=player_embedded\" width=\"800\" height=\"450\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Want to see more? &nbsp;<a href=\"/artists\">Browse CODAME&rsquo;s Other Featured Artists</a></strong></p>', '', 'http://scanlime.org/', '', '', '0', '1436746529', NULL, NULL),
(123, 'Carl Pisaturo', 'carl-pisaturo', 'http://codame.dreamhosters.com/uploaded_images/carl-pisaturo.jpg', '<header>\r\n<div>&ldquo;The truth may be as simple as a rotation or proportion, or as complex as chaos in a fluid&rdquo;</div>\r\n</header>\r\n<div>\r\n<div>\r\n<article id=\"post-3768\">\r\n<p dir=\"ltr\">CODAME Featured Artist:&nbsp;<a href=\"http://carlpisaturo.com/\">Carl Pisaturo</a>&nbsp;is a LuminoKinetic sculptor who specializes in designing and creating robotic pieces from scratch with traditional machine building techniques. Ranging from animatronic figures, kinetic light sculptures, and even a 3D strobe illusion device (dubbed the&nbsp;<a href=\"http://carlpisaturo.com/TScope_MAIN.html\">Transmutoscope</a>). &nbsp;Pisaturo&rsquo;s work follows and fuses the traditions of scientific demonstration, structural design, sensualist kinetic sculpture, as well as technical amusement, for inverse profit. (alt: &ldquo;Science design, movement, as well as amusement, all funded out of his own pocket&rdquo;).</p>\r\n<p dir=\"ltr\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/Slave1ArmPicPlan.jpg\" alt=\"Slave1ArmPic&amp;Plan\" width=\"1923\" height=\"1185\" /></p>\r\n<p dir=\"ltr\">Pisaturo&rsquo;s work has been featured in events such as:&nbsp;<a href=\"https://www.facebook.com/events/99297492648/\">Maker Faire</a>,&nbsp;<a href=\"http://www.redpoppyarthouse.org/mappabout.html\">Mission Arts and Performance Project&nbsp;</a>(MAPP) and&nbsp;<a href=\"http://dorkbot.org/dorkbotsf/archive/200809/%E2%80%8E\">Dorkbot</a>. &nbsp;He has also collaborated on the fabrication of a damage-resistant robot with&nbsp;<a href=\"http://mekabot.com/\">MEKA robotics</a>, opened his workspace in the Mission, Area 2881, for studio visits, and been interviewed for&nbsp;<a href=\"http://www.wired.com/2009/02/artist-creates/\">WIRED</a>.</p>\r\n<p dir=\"ltr\">Pisaturo currently works as an applications engineer at Stanford University, and continues to generously share detailed&nbsp;<a href=\"http://carlpisaturo.com/index.html\">material, design and electrical notes</a>&nbsp;for his work on his website.</p>\r\n<p><iframe src=\"http://player.vimeo.com/video/72599653?title=0&amp;byline=0&amp;portrait=0\" width=\"800\" height=\"450\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><iframe src=\"http://www.youtube.com/embed/Pkyklgm-N10\" width=\"800\" height=\"450\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>&nbsp;</p>\r\n<div id=\"gallery-2\">\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/carl-pisaturo/carl1/\"><img style=\"float: left;\" src=\"http://www.codame.com/wp-content/uploads/2014/04/carl1-109x150.jpg\" alt=\"ORBIT 2.  2006.  Design &amp; Construction: Carl Pisaturo.  Materials: machined aluminum, stainless steel, brass &amp; epoxy; LEDs, DC motors, ball bearings, custom electronics.   34\" width=\"109\" height=\"150\" /></a></dt>\r\n<dd id=\"gallery-2-3771\">ORBIT 2. 2006. Design &amp; Construction: Carl Pisaturo. Materials: machined aluminum, stainless steel, brass &amp; epoxy; LEDs, DC motors, ball bearings, custom electronics. 34&Prime; high, 26&Prime; sweep diameter.</dd>\r\n</dl>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/carl-pisaturo/carl2/\"><img style=\"float: left;\" src=\"http://www.codame.com/wp-content/uploads/2014/04/carl2-150x119.jpg\" alt=\"Serpentine Robot Arm with Tendon Transmission  With 8 main joints, continuously rotating base, and wine glass gripping hand.  Mainly 2001-2003.  Max Height = 96\" width=\"150\" height=\"119\" /></a></dt>\r\n<dd id=\"gallery-2-3772\">Serpentine Robot Arm with Tendon Transmission With 8 main joints, continuously rotating base, and wine glass gripping hand. Mainly 2001-2003. Max Height = 96&Prime;. Actual arm length above platter = 48&Prime;.</dd>\r\n</dl>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/carl-pisaturo/carl3/\"><img style=\"float: left;\" src=\"http://www.codame.com/wp-content/uploads/2014/04/carl3-118x150.jpg\" alt=\"TRABANT  Kinetic Sculpture with Lighting Design, Electronics, Fabrication - Carl Pisaturo 2005 Machined and Rolled Aluminum, Polycarbonate, LEDs, Lamps, Ball Bearings, Motors, Custom Electronics, etc  30\" width=\"118\" height=\"150\" /></a></dt>\r\n<dd id=\"gallery-2-3774\">TRABANT Kinetic Sculpture with Lighting Design, Electronics, Fabrication &ndash; Carl Pisaturo 2005 Machined and Rolled Aluminum, Polycarbonate, LEDs, Lamps, Ball Bearings, Motors, Custom Electronics, etc 30&Prime; high x 22&Prime; wide.</dd>\r\n</dl>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;&nbsp;</p>\r\n</div>\r\n<p><img src=\"http://www.codame.com/wp-content/uploads/2014/04/Octo_LitesMotion.jpg\" alt=\"Octo_Lites&amp;Motion\" width=\"700\" height=\"834\" /><img src=\"http://www.codame.com/wp-content/uploads/2014/04/IMG_0011.jpg\" alt=\"IMG_0011\" width=\"1200\" height=\"870\" />Want to see more? &nbsp;<a href=\"/artists\">Browse CODAME&rsquo;s Other Featured Artists</a></p>\r\n</article>\r\n</div>\r\n</div>', '', 'http://carlpisaturo.com/', '', '', '0', '1458003084', NULL, NULL),
(125, 'Dr. Woohoo!', 'dr-woohoo', 'http://codame.dreamhosters.com/uploaded_images/dr-woohoo.gif', '<header>\r\n<div>&ldquo;Fusing the best of art, technology, and design to find new techniques to create works of art, and products that capture the imagination&rdquo;</div>\r\n</header>\r\n<div>\r\n<article id=\"post-3781\">\r\n<p dir=\"ltr\">CODAME Featured Artist</p>\r\n<p dir=\"ltr\"><a href=\"http://www.codame.com/wp-content/uploads/2014/04/woohoo.jpg\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/woohoo.jpg\" alt=\"woohoo\" width=\"240\" height=\"240\" /></a></p>\r\n<p dir=\"ltr\"><a href=\"http://drwoohoo.com/\" target=\"_blank\">Dr. Woohoo!</a>&nbsp;is a hybrid artist, designer and creative roboticist searching for the sweet spot between CNC machines, 3d printing, robots, artists, and designers. &nbsp;Although his early background was in traditional mediums, and later developing scripts, plug-ins and stand-alone creative applications to make pixels dance on screens, he is now connecting the dots between the former and the latter.</p>\r\n<p dir=\"ltr\">Woohoo! currently works at Autodesk in the Office of the CTO, and can be found playing with robots, exploring how a robot can enhance the creative process in conjunction with &mdash; or beyond &mdash; CNC machines and 3d printers. Teaching the robot how to paint, chisel and weave on multi-dimensional surfaces that are CNC&rsquo;d or 3d printed occupies his current imagination. He is interested in collaborating with either an industrial design group like IDEO or a fashion design company interested in applying current and future techniques to create something beautiful.</p>\r\n<p><iframe src=\"http://player.vimeo.com/video/88789175\" width=\"500\" height=\"281\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><a href=\"http://vimeo.com/88789175\">Turbulence: Watercolor + Magic</a>&nbsp;from&nbsp;<a href=\"http://vimeo.com/drwoohoo\">Dr. Woohoo!</a>&nbsp;on&nbsp;<a href=\"https://vimeo.com/\">Vimeo</a>.</p>\r\n<div id=\"gallery-2\">\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/dr-woohoo/img_0740/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/IMG_0740-150x84.jpg\" alt=\"IMG_0740\" width=\"150\" height=\"84\" /></a>&nbsp;<a href=\"http://www.codame.com/post/portfolio/dr-woohoo/img_0719/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/IMG_0719-150x99.jpg\" alt=\"IMG_0719\" width=\"150\" height=\"99\" /></a>&nbsp;<a href=\"http://www.codame.com/post/portfolio/dr-woohoo/img_0718/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/IMG_0718-150x99.jpg\" alt=\"IMG_0718\" width=\"150\" height=\"99\" /></a>&nbsp;<a href=\"http://www.codame.com/post/portfolio/dr-woohoo/flow/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/flow-150x150.png\" alt=\"flow\" width=\"150\" height=\"150\" /></a><a href=\"http://www.codame.com/post/portfolio/dr-woohoo/orbit/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/orbit-150x150.jpg\" alt=\"orbit\" width=\"150\" height=\"150\" /></a>&nbsp;<a href=\"http://www.codame.com/post/portfolio/dr-woohoo/stitch/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/stitch-150x150.png\" alt=\"stitch\" width=\"150\" height=\"150\" /></a></dt>\r\n</dl>\r\n</div>\r\n</article>\r\n</div>', '', 'http://drwoohoo.com/', '', '', '0', '1436744480', NULL, NULL),
(126, 'David Glowacki', 'david-glowacki', 'http://codame.dreamhosters.com/uploaded_images/david-glowacki.jpg', '<header>\r\n<div>&ldquo;Theoretical chemist, author, inventor, and creator&rdquo;</div>\r\n</header>\r\n<div>\r\n<div>\r\n<article id=\"post-3787\">\r\n<p>CODAME Featured Artist</p>\r\n<p><img src=\"http://davidglowacki.files.wordpress.com/2010/07/glowacki-photo-vi.jpg\" alt=\"\" width=\"346\" height=\"413\" /></p>\r\n<p dir=\"ltr\">Dr.&nbsp;<a href=\"http://glow-wacky.com/\">David Glowacki</a>&nbsp;is a theoretical chemist, author, inventor, and the creator of<a href=\"http://danceroom-spec.com/\">danceroom spectroscopy</a>, an interactive science-meets-art installation that has introduced the beauty and complexity of the atomic world to thousands of people across the UK and Europe. &nbsp;He has collaborations across several areas of chemistry, using tools from classical and quantum mechanics to understand a range of nano-physics relevant to gases, solids, and liquids.</p>\r\n<p dir=\"ltr\">Glowacki has been an artist in residency in Bristol&rsquo;s&nbsp;<a href=\"http://www.watershed.co.uk/pmstudio/\">Pervasive Media Studio</a>, and shown work&nbsp;<a href=\"http://www.arnolfini.org.uk/\">Arnolfini</a>, the 2012 Cultural Olympiad, and London&rsquo;s&nbsp;<a href=\"http://www.barbican.org.uk/education/event-detail.asp?ID=13912\">Barbican Arts Centre</a>.</p>\r\n<p dir=\"ltr\">Originally from Milwaukee, David moved to the UK in 2003 on a&nbsp;<a href=\"http://glow-wacky.com/2013/12/06/royal-society-research-fellowship/\">Fulbright scholarship&nbsp;</a>to study cultural theory at the University of Manchester, subsequently completing a PhD in physical chemistry at Leeds before arriving at Bristol. &nbsp;He has been published across&nbsp;<a href=\"http://glow-wacky.com/publications/\">a range of subjects and publications</a>, including several prominent scientific journals.</p>\r\n<p><iframe src=\"http://player.vimeo.com/video/54523219?title=0&amp;byline=0&amp;portrait=0\" width=\"500\" height=\"281\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><a href=\"http://vimeo.com/54523219\">Quantum Collision. A meeting of Science, Art, Dance and Music.</a>&nbsp;from&nbsp;<a href=\"http://vimeo.com/yohomedia\">Mark Whatmore, Yoho Media</a>&nbsp;on&nbsp;<a href=\"https://vimeo.com/\">Vimeo</a>.</p>\r\n<div id=\"gallery-2\">\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/david-glowacki/david3/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/david3-150x102.jpg\" alt=\"Hidden Fields dance performance, the &lsquo;whirlpool&rsquo; scene\" width=\"150\" height=\"102\" /></a></dt>\r\n<dd id=\"gallery-2-3789\">Hidden Fields dance performance, the &lsquo;whirlpool&rsquo; scene</dd>\r\n</dl>\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/david-glowacki/david1/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/david1-150x99.jpg\" alt=\"Hidden Fields dance performance, the &lsquo;whirlpool&rsquo; scene\" width=\"150\" height=\"99\" /></a></dt>\r\n<dd id=\"gallery-2-3790\">Hidden Fields dance performance, the &lsquo;whirlpool&rsquo; scene</dd>\r\n</dl>\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/david-glowacki/david2/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/david2-150x99.jpg\" alt=\"dS Fest, Bristol, in the 21m diameter 360 projection dome\" width=\"150\" height=\"99\" /></a></dt>\r\n<dd id=\"gallery-2-3791\">dS Fest, Bristol, in the 21m diameter 360 projection dome</dd>\r\n</dl>\r\n<p>&nbsp;</p>\r\n</div>\r\n</article>\r\n</div>\r\n</div>', '', 'http://glow-wacky.com/', '', 'http://www.codame.com/post/portfolio/david-glowacki/', '0', '', NULL, NULL),
(127, 'Paolo Salvagione', 'paolo-salvagione', 'http://codame.dreamhosters.com/uploaded_images/paolo-salvagione.jpg', '<header>\r\n<div>&ldquo;Grounded in the practice of thinking about thinking about things&ldquo;</div>\r\n</header>\r\n<div>\r\n<div>\r\n<article id=\"post-3844\">\r\n<p dir=\"ltr\">CODAME Featured Artist</p>\r\n<p dir=\"ltr\"><a href=\"http://www.codame.com/wp-content/uploads/2014/04/Paulo-face.jpg\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/Paulo-face.jpg\" alt=\"Paulo face\" width=\"227\" height=\"222\" /></a></p>\r\n<p dir=\"ltr\"><a href=\"http://salvagione.com/%E2%80%8E\">Paolo Salvagione</a>&nbsp;is an artist who works at the intersection of engineering, participation, and levity. All his works balance humor and craftsmanship, the novel and the banal, the tactile and the conceptual.</p>\r\n<p dir=\"ltr\">Salvagione spent a half a decade circling the world setting up bicycle factories from Italy to Indonesia, mastering titanium fabrication after hours at Martin Marietta in Colorado, working on next-generation paint-application systems for Boeing, employing CAD software for hi-tech bike design in Marin &mdash; and even designing an atmospheric-dust collection tool for NASA. He has worked, for over a decade, as lead engineer on the&nbsp;<a href=\"about:blank\">10000 Year Clock of the Long Now Foundation</a>.</p>\r\n<p dir=\"ltr\">Salvagione was born in Chicago and at an early age moved with his family to Southern France, where he developed an affection for bullfighting. He spent his teen years in Albuquerque, New Mexico, living around the corner from Joel-Peter Witkin, whom he occasionally assisted with set construction and corpse transportation. He spent his college years in Manhattan reading philosophy.</p>\r\n<p><iframe src=\"http://player.vimeo.com/video/22716239?portrait=0\" width=\"500\" height=\"281\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><a href=\"http://vimeo.com/22716239\">Competitive Swinging</a>&nbsp;from&nbsp;<a href=\"http://vimeo.com/salvagione\">Paolo Salvagione</a>&nbsp;on&nbsp;<a href=\"https://vimeo.com/\">Vimeo</a>.</p>\r\n<div id=\"gallery-2\">\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/paolo-salvagione/paolo2/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/paolo2-150x100.jpg\" alt=\"Orbit\" width=\"150\" height=\"100\" /></a></dt>\r\n<dd id=\"gallery-2-3849\">Orbit</dd>\r\n</dl>\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/paolo-salvagione/paolo-1/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/paolo-1-150x131.jpg\" alt=\"Blackwork\" width=\"150\" height=\"131\" /></a></dt>\r\n<dd id=\"gallery-2-3850\">Blackwork</dd>\r\n</dl>\r\n</div>\r\n</article>\r\n</div>\r\n</div>', '', 'http://salvagione.com/', '', 'http://www.codame.com/post/portfolio/paolo-salvagione/', '0', '', NULL, NULL),
(128, 'Scott Kildall', 'scott-kildall', 'http://codame.dreamhosters.com/uploaded_images/scott-kildall.jpg', '<header>\r\n<div>&nbsp;</div>\r\n</header>\r\n<div>\r\n<article id=\"post-3856\">\r\n<p>Scott Kildall has been working with art + technology + education for over 15 years. In 2017, he worked as an American Arts Incubator Artist, where he led a 1-month workshop in Bangkok to teach data-visualization and sculptural techniques to local Thai educators and students involving water quality in that city. Additionally, he has worked as a New Media Exhibit Developer (2012-13) at The Exploratorium in the Life Sciences Gallery. He has also taught coursework involving data-visualization and digital mapping at the University of San Francisco.</p>\r\n<p>He has received fellowships, awards and residencies from organizations including the SETI Institute, ZERO1, Santa Fe Art Institute, Impakt Works, Autodesk,&nbsp;&nbsp;<a href=\"http://www.recology.com\">Recology San Francisco</a>&nbsp;(2011),&nbsp;<a href=\"http://turbulence.org\">&nbsp;Turbulence.org</a>&nbsp;(2010, 2009),&nbsp;<a href=\"https://eyebeam.org/\">Eyebeam Art + Technology Center</a>(2009), Kala Art Institute (2007) and The Banff Centre for the Arts.</p>\r\n<p dir=\"ltr\">Kildall&rsquo;s work has been exhibited internationally at venues including the New York Hall of Science, Transmediale (Berlin), the Venice Biennale (Internet Pavilion), Vancouver Art Gallery, Furtherfield (London) and the San Jose Museum of Art. &nbsp;</p>\r\n<p dir=\"ltr\">He currently resides in San Francisco.&nbsp;</p>\r\n<p dir=\"ltr\"><iframe src=\"//player.vimeo.com/video/291364857?title=0&amp;byline=0\" width=\"425\" height=\"350\"></iframe></p>\r\n<p dir=\"ltr\"><img src=\"/uploaded_images/kildall3.jpg\" alt=\"\" /></p>\r\n<p dir=\"ltr\">Strewn Fields (2016)</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><img src=\"/uploaded_images/main_datacrystal_crime.jpg\" alt=\"\" /></p>\r\n<div id=\"gallery-2\">\r\n<dl>\r\n<dt></dt>\r\n<dt>Data Crystals (2014) &mdash; Algorithmically-generated 3D Prints</dt>\r\n</dl>\r\n<p>&nbsp;</p>\r\n</div>\r\n</article>\r\n</div>', 'http://www.twitter.com/kildall', 'http://www.kildall.com/', '', '', '0', '1566784461', NULL, NULL),
(129, 'Antonio Cortez', 'antonio-cortez', 'http://codame.dreamhosters.com/uploaded_images/antonio-cortez.jpg', '<header>\r\n<div>&ldquo;Abstract mathematical functions and their intersection with art&rdquo;</div>\r\n</header>\r\n<div>\r\n<div>\r\n<article id=\"post-3869\">\r\n<p>CODAME Featured Artist</p>\r\n<div id=\"attachment_3871\"><a href=\"http://www.codame.com/wp-content/uploads/2014/04/antonio2.jpg\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/antonio2-300x199.jpg\" alt=\"Elliptical Field Zero, 2010, UV Light Cured Pigment Ink Print on Aluminum Plate\" width=\"300\" height=\"199\" /></a>\r\n<p>Elliptical Field Zero, 2010, UV Light Cured Pigment Ink Print on Aluminum Plate</p>\r\n</div>\r\n<p dir=\"ltr\"><a href=\"http://www.antoniocortezdesign.com/\">Antonio Cortez</a>&nbsp;&nbsp;is a multimedia artist working in conceptual installation art projects integrating photography, media arts and para-design known for developing Mathematical Formulations in the Service of Art, a series of renderings and prints that explores geometries from abstract mathematical functions and art.</p>\r\n<p dir=\"ltr\">SF Chronicle&rsquo;s Kenneth Baker who wrote:</p>\r\n<blockquote>\r\n<p dir=\"ltr\">&ldquo;In composing music and making or staging visual art, Cage frequently used the I Ching, the traditional Chinese divination system, as a means to give randomness to decisions. Several pieces here make explicit reference to it, notably a work by Antonio Cortez in both static and digital display. By adept use of design software, Cortez translated the 64 two-dimensional hexagrams of the I Ching into colorful 3-D models, referencing, as Cage typically did not, the hexagrams&rsquo; metaphorical associations.&rdquo;</p>\r\n</blockquote>\r\n<p dir=\"ltr\">Mr. Cortez was born in Caracas, Venezuela. &nbsp;He holds a BS in Materials Science Engineering. During his college years, he studied photography at The Newman Foundation, a design school that followed Bauhaus principles. In 1995, Mr. Cortez earned a Graduate Certificate in Administration and Management from Harvard University. Continuing his interest in the visual arts, he pursued course work at The School of the Museum of Fine Arts Boston, Emerson College, and New England School of Photography.</p>\r\n<p><iframe src=\"http://player.vimeo.com/video/32991515\" width=\"500\" height=\"375\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><a href=\"http://vimeo.com/32991515\">3 Dimensional I Ching Movie</a>&nbsp;from&nbsp;<a href=\"http://vimeo.com/user9484641\">Antonio Cortez</a>&nbsp;on&nbsp;<a href=\"https://vimeo.com/\">Vimeo</a>.</p>\r\n<div id=\"gallery-2\">\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/antonio-cortez/antonio2/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/antonio2-150x99.jpg\" alt=\"Elliptical Field Zero, 2010, UV Light Cured Pigment Ink Print on Aluminum Plate\" width=\"150\" height=\"99\" /></a></dt>\r\n<dd id=\"gallery-2-3871\">Elliptical Field Zero, 2010, UV Light Cured Pigment Ink Print on Aluminum Plate</dd>\r\n</dl>\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/antonio-cortez/antonio1/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/antonio1-125x150.jpg\" alt=\"3D I CHING CHART\" width=\"125\" height=\"150\" /></a></dt>\r\n<dd id=\"gallery-2-3872\">3D I CHING CHART</dd>\r\n</dl>\r\n<dl>\r\n<dt><a href=\"http://www.codame.com/post/portfolio/antonio-cortez/antonio3/\"><img src=\"http://www.codame.com/wp-content/uploads/2014/04/antonio3-100x150.jpg\" alt=\"Elliptical Field # 4, 2010  UV Light Cured Pigment Ink Print on Aluminum Slab\" width=\"100\" height=\"150\" /></a></dt>\r\n<dd id=\"gallery-2-3873\">Elliptical Field # 4, 2010 UV Light Cured Pigment Ink Print on Aluminum Slab</dd>\r\n</dl>\r\n</div>\r\n</article>\r\n</div>\r\n</div>', '', 'http://www.antoniocortezdesign.com/', '', 'http://www.codame.com/post/portfolio/antonio-cortez/', '0', '', NULL, NULL),
(130, 'Vinit Patil', 'vinit-patil', 'http://codame.dreamhosters.com/uploaded_images/vinit-patil.jpeg', '<p>CODAME Featured Artist:&nbsp;<a href=\"http://vinitpatil.tumblr.com/\" target=\"_blank\">Vinit Patil</a></p>\r\n<p id=\"edc4\">Vinit is an industrial electronics engineer who didn&rsquo;t quite succeed at industrial electronics. In fact, he doesn&rsquo;t know if micro-controllers are hyphenated.&nbsp;</p>\r\n<p id=\"b759\">After quitting his first job at his uncle&rsquo;s servo motor factory (much to his uncle&rsquo;s delight) he pursued more creative interests, but technology always reared it&rsquo;s nerdy head in every endeavor, darn!&nbsp;</p>\r\n<p id=\"31f1\">Vinit has since worked in the creative capacity at digital agencies and as well as startups like file sharing company Box where he brought in the Codame flavor with a beautiful storytelling in data visualization.&nbsp;</p>\r\n<p id=\"29cb\">The video below is an installation of how workers at a large companies are interconnected with each other and where the gaps are for improvement, made with artists&nbsp;<a href=\"/artists/kinetech-arts\" data-href=\"https://medium.com/u/ca59d3222e1\" data-anchor-type=\"2\" data-user-id=\"ca59d3222e1\" data-action=\"show-user-card\" data-action-type=\"hover\">Kinetech Arts</a>.</p>\r\n<p><iframe src=\"//player.vimeo.com/video/120116662?title=0&amp;byline=0\" width=\"752\" height=\"471\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p id=\"486c\">He also started&nbsp;<a href=\"https://medium.com/r/?url=http%3A%2F%2Fthewhiteout.org\" rel=\"nofollow\" data-href=\"/r/?url=http%3A%2F%2Fthewhiteout.org\">The Whiteout</a>&nbsp;Collective with fellow Codame artist <a href=\"https://twitter.com/mexist\">@mexist</a> The mission was to create a world where nothing is ever discarded. In subsequent art shows, they took discarded objects, spray painted them white and used them as a canvas for pen and ink illustrations. In the header above, the glasses used to be oversized $2 party sunglasses.&nbsp;</p>\r\n<p id=\"e60a\">Vinit also likes to go really low tech. For a recent Codame show, he worked with artist Rudi Anggono and photographer Michael Kennedy to create app icons that are less dribbb-ly and more representative of what they really mean. The show app.ropriate was a print display among high tech shenanigans.&nbsp;</p>\r\n<p><img src=\"https://cdn-images-1.medium.com/max/1600/1*Fl3CzaEMWG0GXXE4HHf_kQ.jpeg\" alt=\"\" width=\"749\" height=\"350\" data-src=\"https://cdn-images-1.medium.com/max/1600/1*Fl3CzaEMWG0GXXE4HHf_kQ.jpeg\" /></p>\r\n<p id=\"1f57\">Vinit is currently the co-founder of&nbsp;<a href=\"https://medium.com/r/?url=http%3A%2F%2Fskue.co\" rel=\"nofollow\" data-href=\"/r/?url=http%3A%2F%2Fskue.co\">SKUE</a>, a wholesale marketplace where indie retailers offer retail guidance and buy products from the top 3% designers. The goal is to fulfill every designer&rsquo;s dream to get into their favorite retail store.&nbsp;</p>\r\n<p id=\"ca02\">Vinit fully embraces technology now after making peace with his engineering years. If you drew up a Venn diagram of art and tech, you will find him at the intersection, trying not to get run over by either circle.&nbsp;</p>\r\n<p>&nbsp;</p>', '', 'http://vinitpatil.tumblr.com/', '', '', '0', '1454113265', NULL, NULL),
(173, 'Foxxy Newport', 'foxxy-newport', 'http://codame.dreamhosters.com/uploaded_images/foxxy-newport.jpg', '<p>FoxxyNewport is an internationally recognized recording artist and songwriter based out of Oakland, California. The protege of Mr.Kitty, he is known for pioneering a sound that blends 80\'s Synthpop/Darkwave with 90\'s Dance and other modern styles. He has launched a second career into DJing to better learn about the craft of music. Specializing in House, Techno, and Vogue he aims to make you feel and move whether he holds a microphone or a turntable.</p>\r\n<p>Foxxy will be DJing at the <a href=\"/events/art-tech-festival-2015\">ART+TECH Festival MOVEMENT</a> on Oct 23rd and 24th, 2015.</p>', 'http://www.twitter.com/foxxynewport', 'http://www.soundcloud.com/foxxynewport', '', '', '0', '1444530032', NULL, NULL),
(131, 'IDEOMUX', 'ideomux', 'http://codame.dreamhosters.com/uploaded_images/ideomux.jpg', '<p>CODAME Featured Artist: ideomux</p>\r\n<p class=\"p1\">Bedroom recluse and ghost producer ideomux (aka idmx) is an enigmatic figure within the ever-evolving audible environment. We spoke with ideomux briefly via telephone upon his request stating, &ldquo;The telephone reduces the entirety of human conversation to the audible dimension. It&rsquo;s amazing how much of a conversation is in the tempo and color of one&rsquo;s voice&rdquo;. He happily answered questions regarding his current work. &ldquo;I have two interests, the syntax and the semantics of sound. That&rsquo;s the simplest way I can phrase my work without describing it [laughs]&rdquo;. Ideomux has released content spanning from left-field avant-experimental, to the limits of popular musical perversions, remixes, reworks, and refixes. &ldquo;ideomux is a process of&nbsp;novelty-seeking and artificial selection between elements of popular culture and producer culture&rdquo;</p>\r\n<p><iframe src=\"//player.vimeo.com/video/78698379?byline=0&amp;portrait=0&amp;color=c9ff23\" width=\"1024\" height=\"575\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', '', '', '', '', '0', '1436744285', NULL, NULL),
(194, 'Giacomo Carmagnola', 'giacomo-carmagnola', 'http://codame.dreamhosters.com/uploaded_images/giacomo-carmagnola.jpg', '<p>Giacomo Carmagnola is an Italian graphic designer who disagrees with the current state of Glitch Art. He shakes up the field by exchanging digital computation with human intuition. Mixing the occult with the emotional with a dedicated eye he is able to abstract and curate sinister images that give you raw phychological thrills when you look at them. Often with an face replaced by bleeding pixels, the entities tell their story miraculously without an mouth or expression.</p>\r\n<p>He started his study being interested in psychology, and is not shy on displaying an more emotional state of being. As he calls himself \'a person who analysis himself a lot\', and equipped with an introverted mindset, his pieces are an expression of his thoughts. &ldquo;In dark times they are a bit darker, in happy times a bit happier&rdquo; he states, but all with an engaging angle to it which he displays through the entities in his photo montages. As if a window into heir soul. An interface into their lives.</p>\r\n<p>Adobe Photoshop and Processing Pixel sorting scripts are his medium. Using old or in his view iconic pictures which he partially destroys through software replacing faces with. But other than regular glitch art, he does care where the pixels are being placed, and in fact &ndash; carefully modifies them to create an imperfect perfection that leaves room for interpretaton.&nbsp;<span lang=\"en\">An intriguing series is full of photographic portraits exhumed from the early twentieth century, where the stride of monochromatic photographic plate with the explosion of digital color creating an unusual combination that disrupts and disorients.&nbsp;</span>Creating a captivating photo montage that leaves you to wonder...<br /><br />Giacomo&nbsp;will be exhibiting work at our&nbsp;<a href=\"http://festival.codame.com/\" target=\"_blank\">INTERFACE Art+Tech Festival</a>&nbsp;running&nbsp;<span tabindex=\"0\" data-term=\"goog_2116897653\">October 5-8th, 2016</span>&nbsp;at Fort Mason. His work has been featured in a&nbsp;poster for the festival.</p>\r\n<p><img src=\"/uploaded_images/tumblr_nl5v16oFQ51u59jvro1_1280.jpg\" alt=\"\" width=\"570\" height=\"689\" /></p>\r\n<p><img src=\"/uploaded_images/tumblr_nmpiz797vx1u59jvro1_1280.jpg\" alt=\"\" width=\"570\" height=\"726\" /></p>\r\n<p><img src=\"/uploaded_images/tumblr_nskn9eOoyt1u59jvro1_1280.jpg\" alt=\"\" width=\"570\" height=\"813\" /></p>\r\n<p>&nbsp;</p>', '', 'http://giacomocarmagnola.tumblr.com/', '', '', '0', '1456025356', NULL, NULL),
(132, 'C-REX', 'c-rex', 'http://codame.dreamhosters.com/uploaded_images/c-rex.jpg', '<p>CODAME Featured Artist</p>\r\n<p>C&eacute;sar Hamilton is a 17 year old producer, recording artist and singer/songwriter. He works under the name C-rex to blend club-oriented electronic music with guitar and vocals. His music encompasses a wide array of genres, from IDM and post-dubstep to guitar centered pop, combining the new and the old in unique ways. He has had airplay and has worked with a number of record labels in Europe. You can hear more music at:</p>\r\n<p><a href=\"http://iamcrex.com/\" target=\"_blank\">http://iamcrex.com/</a></p>\r\n<p><a href=\"https://soundcloud.com/cesar_hamilton\" target=\"_blank\">https://soundcloud.com/cesar_hamilton</a></p>\r\n<p><a href=\"https://twitter.com/iamthecrex\" target=\"_blank\">https://twitter.com/iamthecrex</a></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/iamthecrex', 'http://iamcrex.com/', '', '', '0', '1436744290', NULL, NULL),
(133, 'Mike Hales', 'mike-hales', 'http://codame.dreamhosters.com/uploaded_images/mike-hales.gif', '<p>CODAME&nbsp;Featured Artist</p>\r\n<p><a href=\"http://www.codame.com/wp-content/uploads/2014/05/mh14_burgerbird.gif\"><img class=\"alignnone  wp-image-4096\" src=\"http://www.codame.com/wp-content/uploads/2014/05/mh14_burgerbird.gif\" alt=\"mh14_burgerbird\" width=\"147\" height=\"179\" /></a>&nbsp;<a href=\"http://www.codame.com/wp-content/uploads/2014/05/10275372345_42bba18876.jpg\"><img class=\"alignnone  wp-image-4097\" src=\"http://www.codame.com/wp-content/uploads/2014/05/10275372345_42bba18876.jpg\" alt=\"10275372345_42bba18876\" width=\"181\" height=\"181\" />&nbsp;</a></p>\r\n<p><em>Mike Hales&nbsp;is an artist based in San Francisco, California. Mike&nbsp;self-publish comics and design characters for video games.</em></p>\r\n<p><a href=\"http://wobblyart.com\">www.wobblyart.com</a>.</p>\r\n<p>Mike&rsquo;s GIF art&nbsp;will be featured at <a href=\"http://gifhappyhour.com\">Gif Happy Hour</a> on May 22nd.</p>\r\n<p>Also check out Mike&rsquo;s art in the new game <a href=\"http://stratolab.com\">Electropocalypse</a>, and his contributions to the <a href=\"http://gifaweek.tumblr.com\">Gif A Week project</a>.</p>', '', 'http://wobblyart.com/', '', '', '0', '1436744295', NULL, NULL),
(134, 'THISISSAMI', 'thisissami', 'http://codame.dreamhosters.com/uploaded_images/thisissami.png', '<p>CODAME&nbsp;Featured Artist</p>\r\n<p><a><img class=\"alignnone  wp-image-4102\" src=\"http://www.codame.com/wp-content/uploads/2014/05/Screen-Shot-2014-05-05-at-7.20.20-PM.png\" alt=\"Screen Shot 2014-05-05 at 7.20.20 PM\" width=\"234\" height=\"179\" /></a>&nbsp;<a href=\"http://www.codame.com/wp-content/uploads/2014/05/Screen-Shot-2014-05-05-at-7.24.00-PM.png\"><img class=\"alignnone  wp-image-4101\" src=\"http://www.codame.com/wp-content/uploads/2014/05/Screen-Shot-2014-05-05-at-7.24.00-PM.png\" alt=\"Screen Shot 2014-05-05 at 7.24.00 PM\" width=\"240\" height=\"178\" /></a><br /> <em>I love to improvise. If you catch me live, you&rsquo;ll be treated to a show where you can both see and hear what I create right in front of your eyes and ears.</em></p>\r\n<p><em>I&rsquo;ve made animations in the past (hand-&#8203;drawn, 3D, and programmed). I&rsquo;ve also developed and continue to develop&nbsp;various fun web apps. Check out my latest project that lets you remix the web into an animated collage:&nbsp;<a href=\"http://animakeit.com/\" target=\"_blank\">http://animakeit.com</a>.</em></p>\r\n<p><em>The video below showcases what I do on stage.</em></p>\r\n<p><iframe src=\"//www.youtube.com/embed/0eTHiNc9IxY\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>Catch a performance by THISISSAMI at&nbsp;<a href=\"http://gifhappyhour.com\" target=\"_blank\">Gif Happy Hour on May 22nd.</a></p>\r\n<p><a href=\"http://www.thisissami.net\">http://www.thisissami.net</a></p>', '', 'http://www.thisissami.net/', '', '', '0', '1436744300', NULL, NULL),
(135, 'Lenny Kiser', 'lenny-kiser', 'http://codame.dreamhosters.com/uploaded_images/lenny-kiser.jpg', '\r\n						<p>CODAME Featured Artist</p>\r\n<p><a href=\"http://www.lennykiser.com/\" target=\"_blank\">Lenny Kiser</a> is an artist and Ableton Live Certified Trainer. Currently teaching music production classes, workshops and train with individuals privately out of my studio here in San Francisco.  Lenny also organizes the SF – Bay Area Ableton Live User Group Monthly Meetup. His technical knowledge about audio and music production comes from training and education through the Master Recording Program II of the Conservatory of Recording Arts and Sciences in Phoenix, Arizona. Everything else he learned through over 10 years of music production experience.</p>\r\n<p>Join Lenny at our ART+TECH Rendezvous this May 22nd, 2014 for an evening of MUSIC, LEARN and PLAY @GeekdomSF</p>\r\n<p><img class=\"alignnone size-full wp-image-4170 hoverZoomLink\" src=\"http://www.codame.com/wp-content/uploads/2014/05/Lenny_Kiser_Ableton_Profile-680x1024.jpg\" alt=\"Lenny Kiser Ableton Live\" width=\"680\" height=\"1024\"></p>\r\n<p><strong>Want to see more?  <a href=\"http://codame.com/artists\">Browse CODAME’s Other Featured Artists</a></strong></p>\r\n											', '', 'http://www.lennykiser.com/', '', 'http://www.codame.com/post/portfolio/lenny-kiser/', '0', '', NULL, NULL),
(136, 'Danielle Siembieda', 'danielle-siembieda', 'http://codame.dreamhosters.com/uploaded_images/danielle-siembieda.jpg', '<p>As the founder of <a href=\"http://artinspector.org\">Art Inspector: Saving the Earth by Changing Art</a>, Siembieda has turned this social practice project into a business acquiring funding from Silicon Valley Energy Watch and working with the City of San Francisco Department of Environment to help artists work healthier and safer. She defines her art at &ldquo;Alter-Eco Art&rdquo; bridging Eco-Art practice and New Media focusing on intersection of environment, technology and community. Danielle Siembieda is the Managing Director of Leonardo/The International Society for the Arts, Sciences and Technology (Leonardo/ISAST). As an active leader in the art, science, and technology community, she has served on the board of the Women Eco Art Dialogue and held the leadership role as Communications Director of Emerging Arts Professionals. She has served the art &amp; tech community with multiple roles including Community Engagement Manager for ZERO1: The Art &amp; Technology Network; Co-Project Manager of the San Jose Climate Clock Initiative; Managing Editor of SWITCH the online Journal of New Media (no longer in publication); and member of the San Jose Public Art Advisory Committee. Siembieda has an MFA in Digital Media Art at San Jose State University at the CADRE Laboratory for New Media with a focus on green technology and sustainable materials.&nbsp;</p>\r\n<p>&nbsp;</p>', '@Art_Inspector', 'http://www.siembieda.com', '', '', '0', '1520355014', NULL, NULL),
(292, 'Raphael Arar', 'raphael-arar', 'http://codame.dreamhosters.com/uploaded_images/raphael-arar.jpg', '<p>Raphael Arar is an award-winning artist, designer and technologist whose work seeks to trace the trajectories of interpersonal and intrapersonal interaction in light of progress. These works manifest themselves in a variety of forms encompassing a synthesis of nostalgia and novelty often informed by scientific systems and humanistic research.</p>\r\n<p>His artwork has been shown at museums, conferences, festivals and galleries internationally including the International Symposium on Electronic Art (ISEA), ACM CHI Conference on Human Factors in Computing Systems, Gamble House Museum, Boston Cyberarts Gallery, and Athens Video Art Festival.</p>\r\n<p>Commercially, he has worked with clients including Apple, Google, The Smithsonian and Children&rsquo;s Hospital. His design work has been awarded through MITX and The Webby Awards and has been featured in sources including The New York Times, The Los Angeles Times, Communication Arts Magazine and Forbes. Arar holds an MFA from the California Institute of the Arts and a BA from Boston University.</p>\r\n<p>Arar is currently a Designer &amp; Researcher at IBM Research, Adjunct Faculty at San Jose State University&rsquo;s CADRE Laboratory for New Media and a recent Forbes 30 Under 30 awardee in Enterprise Technology. Previously he was the Lead UX Designer for the Apple + IBM Partnership, Lecturer at the University of Southern California&rsquo;s Media Arts + Practice Division and an Art &amp; Technology Fellow at CalArts.</p>\r\n<p>&nbsp;</p>', '@rarar', 'http://raphaelarar.com/', '', '', '0', '1520355228', NULL, NULL),
(137, 'Kinetech Arts', 'kinetech-arts', 'http://codame.dreamhosters.com/uploaded_images/kinetech-arts.jpg', '<p>Founded by Artistic Directors <a href=\"/artists/weidong-yang\">Weidong Yang</a> and Daiane Lopes da Silva in January 2013, Kinetech Arts is a collective of artists and scientists striving to challenge possibility through collaborative creativity, creating performances that combine dance, performance, painting, and and sound with the newest interactive technology, to create unique and beautiful experiences. Kinetech Arts has performed at ODC theatre, Yerba Buena Gardens Festival, The Garage, KUNST-STOFF arts, L.A.S.T festival, Geekdom, Moscone Center, Marine Headlands Center for the Arts, among others. Together with&nbsp;CODAME, Kinetech Arts held the first <a href=\"/events/code-dance-hack-codame\">Hack + Dance Marathon</a> in San Francisco. It was recognized by the SF WEEKLY as \"Best Genre-Defying Sci-Artistic Collaboration of 2014\".</p>\r\n<p><img src=\"/wp-content/uploads/2013/09/tumblr_mteuwqFCVL1qixx7ho7_1280.jpg\" alt=\"tumblr_mteuwqFCVL1qixx7ho7_1280\" width=\"1280\" height=\"854\" /></p>\r\n<p><img src=\"/wp-content/uploads/2013/09/tumblr_mteuwqFCVL1qixx7ho4_1280.jpg\" alt=\"tumblr_mteuwqFCVL1qixx7ho4_1280\" width=\"1280\" height=\"797\" /></p>\r\n<p><img src=\"/wp-content/uploads/2013/09/tumblr_mteuwqFCVL1qixx7ho1_1280.jpg\" alt=\"tumblr_mteuwqFCVL1qixx7ho1_1280\" width=\"1280\" height=\"719\" /></p>\r\n<p><img src=\"/wp-content/uploads/2013/09/tumblr_mteuwqFCVL1qixx7ho5_1280.jpg\" alt=\"tumblr_mteuwqFCVL1qixx7ho5_1280\" width=\"1280\" height=\"854\" /></p>\r\n<p><img src=\"/wp-content/uploads/2013/09/tumblr_mteuwqFCVL1qixx7ho3_1280.jpg\" alt=\"tumblr_mteuwqFCVL1qixx7ho3_1280\" width=\"960\" height=\"641\" /></p>\r\n<p><img src=\"/wp-content/uploads/2013/09/tumblr_mteuwqFCVL1qixx7ho2_1280.jpg\" alt=\"tumblr_mteuwqFCVL1qixx7ho2_1280\" width=\"1280\" height=\"720\" /></p>\r\n<p>&nbsp;</p>', '', 'http://kine-tech.org/#!About.html', '', '', '0', '1539548605', NULL, NULL),
(138, 'Ian Winters', 'ian-winters', 'http://codame.dreamhosters.com/uploaded_images/ian-winters.jpg', '\r\n						<p><strong>CODAME Featured Artist:</strong> <a href=\"http://www.ianwinters.com/\" target=\"_blank\">Ian Winters</a>, originally trained as a photographer and filmmaker, has over the past decade bridged collaborative and individual projects encompassing photography, video and installation-based performance work.</p>\r\n<p>Much of Winter’s recent work has centered around collaborative devised projects with choreographers, performers, and musicians in both staged projects and site specific installations.  He is currently pursuing conceptual interests in how imagery formed at certain perceptual limits, such as very low-resolution video, subtly changing series of images, and temporal distortions such as extreme time lapse / compression change our experience of social spaces, and, seemingly private experience.</p>\r\n<p>As an artist Winters strives to make technology (if used) an essential, inseparable tool — but still to be fundamentally a tool for exploration rather than a means in itself.  Even when the conceptual or political material may be complex — such as explorations of memory & series; temporality, scale, and physical sites; exploration of the complex social relationship of technology and the landscape; and the intersections of live performance; the social and technology — Winters sees the emerging role of technology as one of a fundamental democratization and opening of individual and social possibility.</p>\r\n											', '', 'http://www.ianwinters.com/', '', 'http://www.codame.com/post/portfolio/ian-winters/', '0', '', NULL, NULL),
(139, 'Florian Hoenig', 'florian-hoenig', 'http://codame.dreamhosters.com/uploaded_images/florian-hoenig.jpg', '<p>CODAME Featured Artist:&nbsp;<a href=\"https://twitter.com/rianflo\" target=\"_blank\">Florian Hoenig</a></p>\r\n<div>Florian first discovered the expressive power of computer programming in early childhood. The not so uncommon encounter with video game worlds and the possibility of creating interactive spaces modeled after shear imagination was naturally motivating to learn programming.</div>\r\n<div>&nbsp;</div>\r\n<div>Today Florian recognizes the utilitarian superficialities and functionally biased applications of computer programming. The overemphasis on rational processes that is surrounding his western culture and upbringing he sees as a limitation to the technological world&rsquo;s emergent need to grow awareness for the magical. He predicts a widening gap between experiences enabled by technology and sustainable holistic growth; an ultimate detriment to progress.</div>\r\n<div>&nbsp;</div>\r\n<div>As a consequence and to explore solutions to this problem, Florian is determined to create immersive virtual spaces that allow for limitless creativity by transforming tools into an intuitive and expressive new medium that genuine and deep experiences can be drawn from and shared. It constitutes a search for nature inside the machine.</div>\r\n<div>&nbsp;</div>\r\n<div>Florian holds an advanced in Computer Science from Johannes Kepler University in Linz, Austria, has passionately contributed to the academic field of Computational Aesthetics and is an accomplished entrepreneur.</div>\r\n<div>&nbsp;</div>\r\n<div>Twitter: @rianflo</div>\r\n<div><a href=\"http://rianflo.com/\" target=\"_blank\">rianflo.com</a></div>', 'https://twitter.com/rianflo', 'http://rianflo.com/', '', '', '0', '1436744076', NULL, NULL),
(333, 'Anna Frants', 'anna-frants', 'http://codame.dreamhosters.com/uploaded_images/anna-frants.jpg', '<p>Anna Frants is an internationally renowned New Media artist and curator who co-founded both CYLAND Media Art Lab and the St. Petersburg Art Project. CYLAND is one of the most active New Media art nonprofit organizations, and houses the largest archive of Eastern European video art online. As Co-Founder of Cyland, Frants organizes exhibitions at top art and technology institutions around the world; as a curator and artist, Frants is an important voice in the cultural dialogue surrounding experimental and new media art. Frants has served as a contributing writer to NYArts Magazine as Art and Antiques Magazines and contributed to symposiums and panels for universities, festivals, and exhibitions worldwide.</p>\r\n<p>Anna Frants&rsquo; interactive art installations have been exhibited at top venues around the world including the Venice Biennale, the St. Petersburg Biennial, Moscow Biennial and Polish Biennial, The State Hermitage Museum (St. Petersburg, Russia), Pratt Institute (New York, USA), The Chelsea Art Museum (New York, USA), Convergence (London, UK), RSProjects (Berlin, Germany), VAP / Gogolfest (Kiev, Ukraine) and Transmediale (Berlin, Germany), and Frants has participated in an exclusive 17 day expedition to The Arctic Circle with The Farm Foundation of Arts and Sciences.</p>\r\n<p>Frants is represented by Borey Gallery (St. Petersburg, Russia), Dam, Stuhltrager Gallery (Brooklyn, USA &amp; Berlin, Germany) and Barbarian Gallery (Zurich, Switzerland). Her works can be found in collections of The Museum of Art and Design, The State Russian Museum, Kolodzei Art Foundation, The Sergey Kuryokhin Center for Modern Art and numerous private collections around the world.</p>\r\n<p>This artist is supported by Leonardo/ISAST.</p>', '', 'http://annafrants.net/index.htm', '', '', '0', '1539548110', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(174, 'Saturn Rising', 'saturn-rising', 'http://codame.dreamhosters.com/uploaded_images/saturn-rising.jpg', '<p>&nbsp;</p>\r\n<p>Saturn\'s Manifesto:</p>\r\n<p>&ldquo;I am not just a dancer, I am a performance artist. King Saturn is the grisly aftermath of the death of my fear. Vogue just happened to be my weapon of choice. Now, as I remove my crown, I intend also to rise from my throne. Saturn Rising thus transcends, enlightens and emboldens, seeking to empower you and my psyche. I will reset your mind and demolish your social constructs. I will dance from my spirit and channel David&rsquo;s unlikely triumph over Goliath. I will be so sick, that you die from your illness on the dance floor. And, most importantly, I will cleanse your soul of the weight of this world and demand that you rise with me into the otherworldly.&rdquo;</p>\r\n<p>THE EXPERIENCE</p>\r\n<p>Buzz single, &ldquo;Better 4 U,&rdquo;&mdash;a collaboration between King Saturn and famed Bay Area producer and DJ, Loud Mouth (Demsuckaz)&mdash;is a pulsating, tribal imploration to dance, to feel, to free. Follow up, &ldquo;Young Forever,&rdquo; Friends with Benefits records&rsquo; forthcoming single featuring the sexy &ldquo;4 on the floor&rdquo; production of San Francisco&rsquo;s David Sylvester recalls 1970S &ldquo;Queen of Disco&rdquo; Sylvester at his very best, and as such is sure to become a pride anthem for the ages. Both songs are the anchor for the live show&mdash;a high art and even higher energy nod to drama, power and sex that intersperses fierce vogue work.</p>\r\n<p><iframe src=\"//www.youtube.com/embed/99P-dv9Uolg\" width=\"425\" height=\"350\"></iframe></p>\r\n<p>In 2014, Saturn Rising took the Afropunk and Stargayzer festivals by storm, opened for Big Freedia, Le1F, and Brenmar in San Francisco, made the SF Guardian\'s famed Hot Pink List, headlined SF Pride and MOMA\'s Modern Art Ball, collaborated with Alice Glass and toured extensively with Double Duchess. This year after well received turns at Snowglobe Music Festival, GayBiGayGay and a host of club performances on the books, \"the goal is to rise faster and further, and have the world bear witness to the explosion to come, and reap the benefits of its essence raining down form the cosmos for years to come.\"</p>\r\n<p><img src=\"/uploaded_images/12083889_10207494679982421_799701094_n3.jpg\" alt=\"\" /></p>\r\n<p>Saturn will be performing at our&nbsp;<a href=\"/events/art-tech-festival-2015\">ART+TECH Festival \"MOVEMENT\"</a>&nbsp;on October 24th.</p>\r\n<p><iframe src=\"//www.youtube.com/embed/Qt0jXHMunEw\" width=\"425\" height=\"350\"></iframe></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/saturnjones', 'https://www.facebook.com/saturnjones', '', '', '0', '1444247692', NULL, NULL),
(140, 'Chris Birke', 'chris-birke', 'http://codame.dreamhosters.com/uploaded_images/chris-birke.png', '<p><em>&ldquo;Ultimately, play is the most effective form of creation, and through it we can design the future for the better.&rdquo;</em></p>\r\n<p>CODAME Featured Artist:&nbsp;<a href=\"http://www.chrisbirke.com/\" target=\"_blank\">Chris Birke</a>&nbsp;&nbsp;first&nbsp;sunk his design-teeth&nbsp;into&nbsp;the internet, modding Doom and Quake and downloading any video game he could boot. &nbsp;Today, Birke&nbsp;has emerged as an innovative&nbsp;graphics programming, game design, and production artist, adept at spanning different aspects of digital media to promote connectivity and education. &nbsp;With the Rangers he created the first &ldquo;<a href=\"http://www.walkerart.org/gallery9/qds/rgb.html\">Quake Movies</a>,&rdquo; popularizing what would eventually become known as &ldquo;<a href=\"http://en.wikipedia.org/wiki/Machinima\">Machinema</a>,&rdquo; &nbsp;or cinematic productions made from computer graphics. &nbsp;His passion for furthering technology can be seen in his research, innovation, and creation; he is&nbsp;always holistically drawing inspiration from&nbsp;the world of games&nbsp;&ndash;&nbsp;from their technological foundations to the great ethical implications they have on our future society.</p>\r\n<p>Birke, who has a degree in Multimedia Art from the University of Oregon,&nbsp;was actively &nbsp;involved with the production release of <a href=\"/admin/www.counter-strike.net/\">Counter Strike</a>&nbsp;&nbsp;and worked as a developer at Buzzmonkey Software.</p>', '', 'http://www.chrisbirke.com/', '', '', '0', '1436744062', NULL, NULL),
(141, 'Weidong Yang', 'weidong-yang', 'http://codame.dreamhosters.com/uploaded_images/weidong-yang.jpeg', '<p><a href=\"http://kine-tech.org/#!Artists.html\">Weidong Yang</a> has indulged in the fields of science (he holds a Ph.D in Physics and MCS Computer Science, 11 US patents, and 20+ peer reviewed publications), dance, photography, and Taiji. &nbsp;Having grown up in China and received his high education in US, he has experienced two drastically different cultures. &nbsp; As founder and director of Kinetech, he draws upon&nbsp;his eclectic&nbsp;&nbsp;interests and experiences. &nbsp;Yang&nbsp;envisions Kinetech to be a place for synergy of art and technology, as well as for people with vast different background and training, working together creatively, making beauty that is beyond what&rsquo;s possible by a single person. &nbsp;Aside from Kinetech, Weidong also enjoys his work as data scientist.</p>', '', 'http://kine-tech.org/#!Artists.html', '', '', '0', '1436744044', NULL, NULL),
(142, 'Nicole Zvarik', 'nicole-zvarik', 'http://codame.dreamhosters.com/uploaded_images/nicole-zvarik.jpg', '<p><a href=\"https://sites.google.com/site/nicolezvarik/\">Nicole Zvarik</a>, Co-founder of Deep Root Dance Collective in 2005, is an independent choreographer and performance artist in the San Francisco Bay Area. She has an MFA in Choreography from Mills College, where she studied with Molissa Fenley, Kathleen McClintock, Sonia Delwaide-Nichols, and Anne Westwick. Originally from the East Coast, Nicole received her Bachelor\'s degree in Dance and Sociology from Wilson College. She has danced with Chambersburg Ballet Theatre, performed and choreographed for Wilson\'s Modern Dance Ensemble, including performing for Italia Dance Festival in Cesena, Italy. In the Bay, she has collaborated with a wide variety of interdisciplinary mediums. Nicole has worked with scientists, teachers, musicians, video artists and more including the Intermedia Group,&nbsp;<a href=\"http://www.double-vision.org/\" target=\"_blank\" rel=\"nofollow\">Double Vision</a>&nbsp;and&nbsp;<a href=\"http://liquidneon.net/\" target=\"_blank\" rel=\"nofollow\">C + JGomula&nbsp; &nbsp;Kruzic</a>. Recently she has acted as Resident Artist for California State University Stanislaus, Wilson College, Pennsylvania and the Garage Theater in San Francisco. Nicole has been professionally presenting dance and performance art since 2003, she is currently producing her own work throughout the Bay Area.</p>\r\n<p><iframe src=\"//www.youtube.com/embed/RvZgTi9uiT4\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', '', 'https://sites.google.com/site/nicolezvarik/', '', '', '0', '1587097773', NULL, NULL),
(143, 'Matt Langlois', 'matt-langlois', 'http://codame.dreamhosters.com/uploaded_images/matt-langlois.jpg', '<p>CODAME Featured Artist:&nbsp;<a href=\"http://www.welcomemattsf.com/\">Matt Langlois</a>, aka The Welcome Matt, is a&nbsp;Bay Area-via-New England folk/indie-pop&nbsp;musician who&nbsp;collaborates, tours and composes in San Francisco. &nbsp;He has been featured on KFOG&rsquo;s popular Local Scene CD, teamed up with renowned modern dance choreographer Christine Cali, and recently signed a publishing deal with Wixen Publishing. In 2011, he co-wrote a top-40 European hit &ldquo;San Francisco,&rdquo; by eurodance group Cascada. &nbsp;In 2013, Langlois recorded and released a video for his cover of David Bowie&rsquo;s &lsquo;DJ&rsquo;, collaborated with Cali on another three-day production, &lsquo;L.O.A.D.E.D.&rsquo;</p>\r\n<p>Langlois is currently a member of the multimedia collective, <a href=\"http://kine-tech.org/#!About.html\">Kinetech</a>, and released&nbsp;his&nbsp;self-produced albums, &ldquo;POP JUNK FLUFF and HYPE,&rdquo; earlier&nbsp;this year.<br /> <iframe src=\"//www.youtube.com/embed/rWcuR12GHwE?list=PL8FAB505FC58FC06F\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>His latest single: &ldquo;Let it Lead You&rdquo;</p>', '', 'http://www.welcomemattsf.com/', '', '', '0', '1436744027', NULL, NULL),
(144, 'Sustainable Magic', 'sustainable-magic', 'http://codame.dreamhosters.com/uploaded_images/sustainable-magic.gif', '<p>CODAME Featured Artists: <a href=\"http://www.sustainablemagic.org/\">Sustainable Magic</a> is a creative partnership between best friends&nbsp;<a href=\"http://www.sustainablemagic.org/sean-stevens-about.html\">Sean Stevens</a>&nbsp;and&nbsp;<a href=\"http://www.sustainablemagic.org/ashley-newton-about.html\">Ashley Newton</a>. &nbsp;Using art and technology, the duo creates engaging, interactive art with the aim to evoke&nbsp;surprise, wonder, delight, magic, and playfulness in their viewers, leading them to question their conception what what is possible.</p>\r\n<p>They actively want to help others learn to harness their creative potential through teaching workshops that blend creativity with engineering through the use of emerging fabrication technologies, such as 3D printers, laser cutters, CNC machines, and embedded electronics (e.g. Arduino). &nbsp;And underpinning all their&nbsp;work, they incorporate the&nbsp;important message of sustainability and renewable energy, creating art with low power consumption, that is able to be powered from our renewable energy technology / infrastructure (primarily solar and&nbsp;human-power).</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/23575051766_23513c30e2_z.jpg\" alt=\"\" />&nbsp;</p>', '', 'http://www.sustainablemagic.org/', '', '', '0', '1458011569', NULL, NULL),
(145, 'Ian Baker', 'ian-baker', 'http://codame.dreamhosters.com/uploaded_images/ian-baker.jpg', '<p>&nbsp;</p>\r\n<center><strong>CODAME Featured Artist: Ian Baker</strong></center><center>from Ardent Heavy Industries</center><center>speaking about the&nbsp;<a href=\"/projects/mobile-cloud-platform\" target=\"_blank\">Mobile Cloud Platform</a></center><center>June 26, 2014 at the</center><center><a href=\"http://www.codame.com/post/portfolio/arttech-rendezvous-geekdomsf-june-26th/\">ART+TECH Rendezvous @GeekdomSF</a></center>\r\n<p>&nbsp;</p>\r\n<div style=\"width: 100%; text-align: left;\">\r\n<p><iframe src=\"//player.vimeo.com/video/99602382?title=0&amp;byline=0&amp;portrait=0\" width=\"800\" height=\"450\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><img class=\"alignnone size-full wp-image-4668\" src=\"http://www.codame.com/wp-content/uploads/2014/06/9629221503_a3643d1740_o.jpg\" alt=\"The Ardent Mobile Cloud Platform rains on the DPW Parade, Burnin\" width=\"1500\" height=\"1000\" /></p>\r\n</div>', '', 'http://amcp.ardentheavyindustries.com/', '', '', '0', '1500064289', NULL, NULL),
(146, 'Al Linke', 'al-linke', 'http://codame.dreamhosters.com/uploaded_images/al-linke.jpg', '<hr />\r\n<p>CODAME Featured Artist: Al Linke, is a tech-savvy IT director, cool Dad, and mastermind behind, <a href=\"http://ledpixelart.com/\">PIXEL</a>.</p>\r\n<p>Linke uses a programmable LED matrix array to create pieces of pixel art that is customizable and remote-controlled through mobile phones&rsquo; bluetooth feature.&nbsp;His first project&nbsp;surpassed its fundraising goal on Kickstarter in less than 48 hours. Read more about PIXEL in this&nbsp;<a href=\"https://www.facebook.com/techcrunch/posts/10202269495913599\">Post</a>&nbsp;by&nbsp;<a href=\"https://www.facebook.com/techcrunch\">TechCrunch</a>!</p>\r\n<p>Linke is currently Director of Information Technology at a Fortune 500 company with 20 years of experience in the IT industry. Outside of his day job, Al is an active member in the open source hardware community, including working as a&nbsp;<a href=\"http://www.seeedstudio.com/blog/2012/06/26/face-to-face-with-the-designer-al-linke/\">cooperative designer at Seeed</a>. In addition to PIXEL, Al maintains two other open source projects, the&nbsp;<a href=\"http://diymagicmirror.com\">DIY Magic Mirror</a>&nbsp;and the&nbsp;<a href=\"http://droidalyzer.com/&lrm;\">Droidalyzer</a>, an Android based Breathalyzer.</p>\r\n<p>As seen&nbsp;at CODAME &nbsp;ART+TECH Festival Oct. 31st, 2014 at&nbsp;Geekdom, San Francisco</p>\r\n<p><iframe src=\"//www.youtube.com/embed/aMMqp370_K0\" width=\"816\" height=\"408\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><iframe src=\"http://www.youtube.com/embed/axQk5EEInvE?wmode=transparent&amp;autohide=1&amp;egm=0&amp;hd=1&amp;iv_load_policy=3&amp;modestbranding=1&amp;rel=0&amp;showinfo=0&amp;showsearch=0\" width=\"816\" height=\"408\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', '', 'http://ledpixelart.com/', '', '', '0', '1440398045', NULL, NULL),
(147, 'William S. Braintree', 'william-s-braintree', 'http://codame.dreamhosters.com/uploaded_images/william-s-braintree.png', '<div class=\"figure\"><strong><a href=\"http://soundcloud.com/william-s-braintree\" target=\"_blank\">William S. Braintree</a>&nbsp;CODAME featured Musician</strong></div>\r\n<div class=\"figure\">&nbsp;</div>\r\n<div class=\"figure\">William S. Braintree is a composer/producer stationed in San Francisco, CA. Often frenetic and colorful, he borrows from many genres such as drum n bass, acid, and chiptune.</div>\r\n<div class=\"figure\">&nbsp;</div>', '', 'http://soundcloud.com/william-s-braintree', '', '', '0', '1527208122', NULL, NULL),
(329, 'Mailee Hung ', 'mailee-hung', 'http://codame.dreamhosters.com/uploaded_images/mailee-hung.jpg', '<p>&nbsp;</p>\r\n<p>Mailee Hung is a writer, editor, and cultural critic based out of San Francisco, California. She earned her MA in Visual and Critical Studies at California College of the Arts in 2016, where she wrote her thesis on prosthetics in Western contemporary pop culture. Her work focuses on the discursive and material intersections of technology and the human body. In 2015 she received the All College Honors Graduate Award from CCA in Critical Nonfiction for her essay &ldquo;Decolonizing the Future: The Black Cyborg in Art and Culture.&rdquo; She has presented her work at the 2015 Science Fiction Research Association Symposium, the 2015 Association of Independent Colleges of Art and Design Symposium&mdash;Exploring Science in the Studio, and was the 2017 Bitch Media Writing&mdash;Technology Fellow. Her published writing can be found in Bitch, Utne Reader, Art Practical, Daily Serving, and Alpinist Magazine. When she\'s not reading or watching sci-fi, she can usually be found climbing somewhere in or near the Sierras.</p>\r\n<p>&nbsp;</p>', '', 'http://www.maileehung.com/', '', '', '0', '1527780842', NULL, NULL),
(328, 'misterinterrupt', 'misterinterrupt', 'http://codame.dreamhosters.com/uploaded_images/misterinterrupt.jpg', '<p>Unknown by various haunted household names: interrupt, ruin mechanic, the inimitable mAd sWitCh. A purveyor of sonic drugs, producer of infinitesimal wavelet influences in oceans of sound, an octagonal dimensional vortex of wrung out samples, making extra-ordinary hardware brain-dance and psychotronic rhythmic rainbows.&nbsp;</p>\r\n<p>&nbsp;<a href=\"http://soundcloud.com/misterinterrupt\">http://soundcloud.com/misterinterrupt</a>&nbsp;</p>\r\n<p>Performing TraumaOS&trade; public firmware uninstall</p>\r\n<p>TraumaOS&trade; is a newly discovered modular augmented perception mind bios firmware developed for psychological warfare. It has been installed in a growing number of humans. misterinterrupt will guide infected cybernetic souls into a sonic space fit for uninstalling any TraumaOS&trade; cultural malware modules.</p>\r\n<p>&nbsp;</p>', '', 'http://soundcloud.com/misterinterrupt', '', '', '0', '1527208160', NULL, NULL),
(148, 'Doctor Popular', 'doctor-popular', 'http://codame.dreamhosters.com/uploaded_images/doctor-popular.jpeg', '<p>Doctor Popular <strong>Codame Featured Artist</strong></p>\r\n<p><a href=\"http://docpop.org\" target=\"_blank\">Doc Pop</a> is a multimedia artist who\'s been blending the lines between analog and digital art. Guitars and chiptunes. Glitches and film. Gifs and watercolors. Puppies and rainbows. Make sure to stay in touch with Doctor Popular on&nbsp;<a href=\"https://www.facebook.com/DoctorPopular\" target=\"_blank\">Facebook</a>&nbsp;and follow him on&nbsp;<a href=\"https://twitter.com/docpop\" target=\"_blank\">Twitter</a></p>\r\n<p>Doctor Popular\'s gif series, 3D City will be shown at the <a href=\"http://www.codame.com/post/portfolio/rendezvous-july-18th/\">July 2014 Art+Tech Rendezvous / Gif Happy Hour</a>.</p>', 'https://twitter.com/docpop', 'http://docpop.org', '', '', '0', '1587097871', NULL, NULL),
(400, 'Jody Stillwater', 'jody-stillwater', 'http://codame.dreamhosters.com/uploaded_images/jody-stillwater.png', '<p>Jody Stillwater å‘¨é’æµ· is a writer, director and creative technologist from the San Francisco Bay Area.&nbsp; His film and interdisciplinary project themes are based in dream logic and tactile reality, with a modern, transformative approach to visual semiotics &amp; archetype, grounded in Eastern rhizomatic systems and Western classical narrative.&nbsp; His cultural background as a Chinese/Norwegian/Cherokee-American amidst colliding waves of post-temporal diaspora and arhythmic, intertidal class structures has influenced a value of justice, representation and the ethereal, and allowed him to express these values in experimental film, immersive installation and narrative cinema.</p>\r\n<p><span id=\"docs-internal-guid-9225d874-7fff-b89a-3452-a8fcaca75b00\">&nbsp;</span></p>\r\n<p>He was a finalist for the SFFILM Kenneth Rainin Screenwriting Grant and his work has been featured at the de Young museum, YBCA, Mutek, Transfer Gallery and ISEA</p>', 'https://twitter.com/jodystillwater', 'https://jodystillwater.com/', '', '', '0', '1629174061', 'https://codame.threadless.com/collections/jody-stillwater', 'https://www.instagram.com/jodystillwater/'),
(149, 'TR&#923;CER', 'tr-923-cer', '//codame.com/uploaded_images/tr-923-cer.jpg', '\r\n						<p><a href=\"http://tracervision.com/\" target=\"_blank\">TR&#923;CER </a>is the alias of Chris Osborn, an experimental game designer, techno DJ/producer, and digital artist. Equally suited for the dancefloor, headphones, or interactive experiences, TR&#923;CER echoes lo-fi cyberpunk fantasies and jacking paranoid surrealism.</p>\r\n<p>Exploring the intersections of psychedelic dubstep, dark techno, and experimental video games, the project is the evolution of Chris’ previous work as the programmer for Gaijin Games’ critically-acclaimed synesthetic music game series <a href=\"http://bittripgame.com/\" target=\"_blank\">BIT.TRIP</a>. (for Wii, PC/Mac, and iOS)</p>\r\n<p>Check out his <a title=\"TR&#155;CER: echo.x\" href=\"http://soundcloud.com/tracergames/echo-1\" target=\"_blank\">echo.x</a> mixtape below, and come out to TR&#923;CER in-person at CODAME!</p>\r\n<p><iframe src=\"https://w.soundcloud.com/player/?url=http%3A%2F%2Fapi.soundcloud.com%2Ftracks%2F15559336&show_artwork=true\" width=\"100%\" height=\"166\" frameborder=\"no\" scrolling=\"no\"></iframe></p>\r\n											', '', 'http://tracervision.com/', '', 'http://www.codame.com/post/portfolio/tracer-aka-chris-osborn/', '0', '', NULL, NULL),
(150, '.Jpeg Artifacts', 'jpeg-artifacts', 'http://codame.dreamhosters.com/uploaded_images/jpeg-artifacts.jpg', '<p>Vaporbabes represents the collective effort of .Jpeg Artifacts, otherwise known as Trevor McBride. A retrospective look at obsolete virtual art and the empty, artless soundscapes that provide their soundtrack. Find the work at&nbsp;<a href=\"http://vaporbabes.bandcamp.com/\">vaporbabes.bandcamp.com</a></p>\r\n<p>Catch a DJ Set from .Jpeg Artifacts at our&nbsp;<a href=\"http://www.codame.com/post/portfolio/arttech-rendezvous-geekdomsf-sept-19-2014/\">Art+Tech Rendezvous on September 19, 2014</a>.</p>\r\n<p><img src=\"http://www.codame.com/wp-content/uploads/2014/09/a0701717758_10.jpg\" alt=\"a0701717758_10\" width=\"1000\" height=\"1000\" /></p>\r\n<p><img src=\"http://www.codame.com/wp-content/uploads/2014/09/a1517782392_10.jpg\" alt=\"a1517782392_10\" width=\"800\" height=\"800\" /></p>', '', 'http://vaporbabes.bandcamp.com/', '', '', '0', '1436743885', NULL, NULL),
(506, 'Rendezhous', 'rendezhous', 'http://codame.dreamhosters.com/uploaded_images/rendezhous.jpg', '<p>Based out of San Francisco, CA, she is drawn to energy of dance music and female vocals, her mixes blend the sounds of dance, electronic and deep house music.</p>', '', '', 'jiawen.zhou0627@gmail.com', '', '0', '1634141720', '', 'https://www.instagram.com/rendezhous/'),
(507, 'Alissa Christine', 'alissa-christine', 'http://codame.dreamhosters.com/uploaded_images/alissa-christine.jpg', '<p>Alissa Christine channels the essence of beauty through her creations and draws inspiration from the pure and simple joys of life. Florida International Magazine called her a \"Power Player\" as one of 100 individuals pushing Florida into the future.&nbsp;</p>\r\n<p>For this Brazilian-American artist, expression through visual media connects with inner consciousness as an inspiration to be transmitted to the receiver. Her creations are multidisciplinary fusions of virtual reality, photography, lighting, movement, dimension, painting, sculpture and display... sometimes performed live.&nbsp;&nbsp;It is her steadfast commitment to her own evolution and the evolution of her art that allows her to transcend the individual disciplines and just create. She is a Miami-based professional photographer, author and exhibiting visionary artist that is illuminated by nature, permaculture and the healing arts.</p>\r\n<p>Alissa Christine is a pioneering virtual reality artist. She began VR painting live at Tamarindo Art Wave Festival in 2018 and continues to create 3-dimensional vibrating sculptures of light to be interactively experienced. The art of this innovative virtual technology is blending the boundaries of what\'s inside and outside in the literal and figurative sense. Alissa\'s joy is sharing the magic of light, energy and information, congruent with her wellness practices in the healing arts... Some of her paintings are conceptualized with an intention of guiding the explorer toward states of elevation... and they may also discover hidden treasures inside and out.</p>\r\n<p>In 2015 Alissa self-published a photography coffee-table book entitled &ldquo;i love miami 365&rdquo;, a 366 page, daily yearlong meditative journey of gratitude,&nbsp;celebrating the soul of Miami from the inside out. In it, her love for the everyday beauty is on display as an offering to the world.</p>\r\n<p>Her illuminated lightbox mixed media series,&nbsp;&ldquo;miami music chroma&rdquo; is a 3-dimensional lightbox project that was commissioned for display in each of the guest rooms at The Marlin Hotel in Miami Beach. It is a contemporary body of work featuring her original photos of musicians, producers and DJs combined with illustration and light, encased with translucent colors.&nbsp;</p>\r\n<p>Her art and photography have been featured on albums for recording artists, book covers and editorial publications, such as Ocean Drive&rsquo;s Art Basel Magazine, Florida Inside Out, Elle, Haute Living, 944, Miami Modern Luxury, Ego Trip, Latina Magazine, Sabores and more.</p>\r\n<p>Alissa&rsquo;s intention is to share the light so all can see the light and be the light. And she contributes to the pulse of the community through creating, curating and promoting art, wellness, permaculture and music events.&nbsp;</p>\r\n<p>Alissa Christine is open to art and photography commissions, collaborations, travel projects, wellness/permaculture workshops and holistic retreats.</p>', 'https://twitter.com/LUVRworldwide/', 'https://www.alissachristine.love/', 'alissa@codame.com', '', '0', '1640737703', '', 'https://www.instagram.com/alissachristineloves/'),
(151, 'Teeps', 'teeps', 'http://codame.dreamhosters.com/uploaded_images/teeps.jpeg', '<p class=\"p1\">CODAME Featured Artist</p>\r\n<p class=\"p1\"><a href=\"http://www.steveteeps.com/\" target=\"_blank\">Steve Teeple</a> (better known as Teeps) is a digital artist and DJ currently residing in the the city of Oakland, CA where he dreams of vast 3D worlds, mind bending creatures, and large quantities of Yerba Mate tea. His</p>\r\n<p class=\"p1\">work explores the continuously developing relationship between sight and sound, investigating the ideas of stepping away from the usual formats, to explore 3D spaces and study visual perception. Inspired by neo-tokyo, sci-fi, tech, video games, and psychedelia, Steve gives us a glimpse of what it may be like to not just see and hear within our normal range, but to push our senses to see beyond standard limitations and witness a glimpse of the otherworldly.</p>\r\n<p class=\"p1\"><img src=\"/uploaded_images/teeps1.png\" alt=\"\" /></p>\r\n<p class=\"p1\">Steve Teeple is doing both visuals and a live music set for <a href=\"http://www.codame.com/post/portfolio/ephemeral-vessels/\">Ephemeral Vessels</a>! Get your <a href=\"http://www.eventbrite.com/e/ephemeral-vessels-tickets-13112422609\" target=\"_blank\">ticket now</a>, support ART+TECH, CODAME and the Artists</p>\r\n<p><iframe src=\"//player.vimeo.com/video/87840819?title=0&amp;byline=0&amp;portrait=0\" width=\"900\" height=\"506\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><iframe src=\"//player.vimeo.com/video/86386174?title=0&amp;byline=0&amp;portrait=0\" width=\"900\" height=\"506\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>Check out more&nbsp;<a href=\"/artists\">CODAME Featured Artists</a>!</p>', 'https://twitter.com/steveteeps', 'http://www.steveteeps.com/', '', '', '0', '1587100616', NULL, NULL),
(152, 'Elia Vargas', 'elia-vargas', 'http://codame.dreamhosters.com/uploaded_images/elia-vargas.jpg', '<p>&nbsp;</p>\r\n<p>Elia Vargas is an Oakland based artist, curator, and researcher. He works across multiple mediums, including video, sound, projection, and performance. He is co-founder and co-curator of the Living Room Light Exchange, a monthly salon on new media art and digital culture; half of improvisational modular synthesis duo systemritual; board member of the Soundwave Biennial; and a PhD student in Film and Digital Media at UC Santa Cruz. He is currently investigating the materiality of crude oil and light transmission in relationship to temporalities, flows, and cultural formulation.</p>\r\n<p><iframe src=\"//player.vimeo.com/video/65712807?title=0&amp;byline=0&amp;portrait=0\" width=\"900\" height=\"506\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', 'http://twitter.com/eliavargas', 'http://eliavargas.com/', '', '', '0', '1539408384', NULL, NULL),
(290, 'Catie Cuan', 'catie-cuan', 'http://codame.dreamhosters.com/uploaded_images/catie-cuan.jpg', '<p>&nbsp;</p>\r\n<p>Catie Cuan is a performer, choreographer, and technologist. She is a 2018 Ted Resident. She is currently the Artist-in-Residence at the Robotics, Automation, and Dance (RAD) Lab at the University of Illinois, Urbana-Champaign. This collaboration with lab director and mechanical engineering professor Amy LaViers has resulted in a performance work in progress, currently titled Time to Compile, and research on contextual influence in human-robot interaction. Her performing credits include the Metropolitan Opera, the Lyric Opera of Chicago, and numerous Off-Broadway shows. Her photography has appeared in Variety magazine, Contrast Magazine, and on the TV show, Nashville. She was also previously the Vice President at Color + Information, a digital creative agency, after roles at Bain &amp; Company, Google, and YouTube.&nbsp;</p>', 'https://twitter.com/CatieCuan', 'http://www.catiecuan.com', 'catiecuan@gmail.com', '', '0', '1520111715', NULL, NULL),
(157, 'Ami Wang', 'ami-wang', 'http://codame.dreamhosters.com/uploaded_images/ami-wang.jpg', '<p>Born and raised in Taiwan, Ami came to the USA to study interior design at CCA. She uses&nbsp;3D printing, CNC and laser cutting fabrication techniques to make art. Ami is inspired by&nbsp;photography and graphic design.</p>\r\n<p style=\"margin: 0px; font-size: 12px; line-height: normal; font-family: Helvetica;\">&nbsp;</p>', 'https://twitter.com/my_dove18', 'https://www.behance.net/awang18', '', '', '0', '1472412679', NULL, NULL),
(154, 'TheUriah', 'theuriah', 'http://codame.dreamhosters.com/uploaded_images/theuriah.jpg', '<hr />\r\n<p>Intricate, polished IDM from one of the minds behind the Jejune Institute and all the surrounding Games of Nonchalance. Equal parts creative and technical, and immersed in the world of audio production, music, and transmedia.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><strong><a href=\"http://www.codame.com/support/\">Support Art and Technology</a></strong></p>', '', 'http://theuriah.bandcamp.com/', '', '', '0', '1472417091', NULL, NULL),
(214, 'Raktor', 'raktor', 'http://codame.dreamhosters.com/uploaded_images/raktor.jpg', '<p>TECHNOLOGY+PERFORMANCE:&nbsp;Projection Mapping, 3d Motion Tracking, Virtual Reality and Mixed Reality for Live Events</p>\r\n<p>Raktor is an art collective that does live interactive theatre experience with new technology. We believe the future of virtual reality isn&rsquo;t just video games or film, but for enabling live interactive performance &ndash; we blur the line between audience member and performer.</p>\r\n<p>We are experienced performers, directors, game designers and builders. We apply new technology to live and immersive experience maximize emotional response. We apply this technology We&rsquo;ve been doing performance in digital domains for over a decade each. We have experience building and working with low-level APIs of new hardware, in a research and industrial setting.</p>', '', 'http://raktor.org/', '', '', '1', '1476335960', NULL, NULL),
(211, 'Real DJ Heroes', 'real-dj-heroes', 'http://codame.dreamhosters.com/uploaded_images/real-dj-heros.jpg', '<p>Donald and Ian are Real DJ Heroes.</p>\r\n<p>We are a DJ duo with years of music history and live performance experience&nbsp;from central California, split between&nbsp;Sacramento&nbsp;and&nbsp;San Francisco. Real DJ Heroes has an&nbsp;extensive music libraries and online databases we can always provide the right mix to suit your guests and atmosphere. They&nbsp;are known for going above and beyond to make events unforgettable.&nbsp;</p>\r\n<p>&nbsp;</p>', '', 'http://realdjheros.com/', 'powian@gmail.com', '', '0', '1478982129', NULL, NULL),
(155, 'Josh Carpenter', 'josh-carpenter', 'http://codame.dreamhosters.com/uploaded_images/josh-carpenter.jpg', '<hr />\r\n<p>Josh Carpenter&nbsp;is a San Francisco-based UX Designer currently focused on VR Research with Mozilla. He has spent a career focused on the intersection between digital design and the built environment. First as a student at Vancouver Film School working with NASA to reconstruct Cold War submarine interiors, then using 3DS Max to bring buildings to life for architecture and real estate clients, and as Creative Director of a Vancouver based building automation firm, augmenting homes and offices with sensor technology. Most recently he led the Firefox OS UX team to design the world\'s first web based mobile operating system.</p>\r\n<p><img src=\"/uploaded_images/josh-carpenter-small1.jpg\" alt=\"\" /></p>\r\n<p>Carpente for a chat on<strong>&nbsp;Virtual Reality - The Future of the Web </strong>Nov. 21 for <a href=\"http://www.codame.com/post/portfolio/virtual-reality-at-mozilla/\">CODAME ART+TECH Virtual Reality</a>&nbsp;@ Mozilla</p>\r\n<p>What is VR? Why is it special? What will happen when we combine it spatial, immersive, and performance intensive with the wild and eclectic web? What creative possibilities will open up? Which web values will be strengthened interoperability, user privacy, security, etc&nbsp; and which will change? Virtual reality is a new medium. It presents us with challenges and opportunities completely unlike anything we ve encountered in mobile or desktop.</p>\r\n<p><br /> In this talk we will explore the bleeding edge of the VR web: what you can create today, what the emerging best practices are, and what we as creative professionals can learn (need to learn) from peers in parallel fields like game design, visual effects and architecture.</p>', 'https://twitter.com/joshcarpenter', '', '', '', '0', '1587098222', NULL, NULL),
(399, 'Kenny Myers', 'kenny-myers', 'http://codame.dreamhosters.com/uploaded_images/kenny-myers.jpg', '<p>Kenny Myers is a deaf digital artist, curator and founder of DOS.exe gallery, experimenting and creating digital artwork with a dark sci-fi fantasy aesthetic and technological style, working in formats of graphic design, 3D animation, game engines, web design and web development.</p>', '', 'http://3dpcx.com/', '', '', '0', '1590257155', NULL, NULL),
(196, 'Kristin Neidlinger ', 'kristin-neidlinger', 'http://codame.dreamhosters.com/uploaded_images/kristin-neidlinger.jpg', '<p>Kristin Neidlinger is SENSOREE founder,&nbsp;future concepts designer&nbsp;&mdash; endeavors to craft phenomenal technology to enhance and expand physical embodiment. She has a background in dance, kinetic costumes, and in physical therapies as a Dance Medicine Specialist. With her MFA in Interaction Design from California College of the Arts, 2010, she became curious as to how wearable computers could be therapeutic, emotive, and enhance sensory awareness.</p>\r\n<p>We are excited to have Kristin Neidlinger&nbsp;as part of&nbsp;our&nbsp;<a href=\"http://labs.codame.com\">CODAME Labs</a>&nbsp;in 2016</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/MOODsweaterJael.jpg\" alt=\"\" /></p>', 'http://twitter.com/sensoree', 'http://sensoree.com/', '', '', '0', '1456208447', NULL, NULL),
(179, 'JÃ¤rmark Â­', 'j-rmark', 'http://codame.dreamhosters.com/uploaded_images/j-rmark.png', '<p>J&auml;rmark &shy;- a collaborative work by Steina and Woody Vasulka, and Rob Shaw</p>\r\n<p><span class=\"s1\">Steina and Woody Vasulka are early pioneers of video art, and have been producing work since&nbsp;the early 1960s. The couple met in the early 1960s and moved to New York City in 1965, where&nbsp;they began showing video art at the Whitney Museum and founded The Kitchen in 1971.&nbsp;Recognition for the Vasulkas work range from dual Guggenheim Fellowships in the 1970\'s to a Fullbright Fellowship in 2015.</span></p>\r\n<p class=\"p1\"><span class=\"s1\">Rob Shaw is one of the pioneers of chaos theory. His work at University of California, Santa Cruz&nbsp;on the ability of chaotic systems to spontaneously generate complex behavior was the subject of&nbsp;his landmark PhD thesis, and led to a MacArthur Fellowship for his contribution to the field.</span></p>\r\n<p class=\"p1\"><span class=\"s1\"><img src=\"/uploaded_images/jarmark11.jpg\" alt=\"\" /></span></p>\r\n<p class=\"p1\">&nbsp;</p>\r\n<p class=\"p1\">Jarmark will be presented as an interactive installation during our <a href=\"/events/art-tech-festival-2015\">ART+TECH Festival</a> on October 23rd and 24th, 2015.</p>\r\n<p class=\"p1\"><img src=\"/uploaded_images/Screen_Shot_2015-10-07_at_8.29_.23_PM_1.png\" alt=\"\" /></p>\r\n<p class=\"p1\">&nbsp;</p>', '', 'http://www.axleart.com/#!jarmark/c1qet', '', '', '0', '1444275228', NULL, NULL),
(191, 'Alex Glow', 'alex-glow', 'http://codame.dreamhosters.com/uploaded_images/alex-glow.jpeg', '<p>Alex Glow plays with robots, music, language, EEG, and wearable tech. Former boardmember at the AHA and Noisebridge hackerspaces, and later an Artist in Residence at&nbsp;Autodesk\'s Pier 9, she is currently the Hacker Advocate at Hackster &ndash;&nbsp;the community for hardware makers to learn and share electronics.</p>\r\n<p><img src=\"/uploaded_images/alex-glow1.jpg\" alt=\"\" /></p>\r\n<p>Photo (Top):&nbsp;Spinning Up: A \"reverse lullaby\" for life on Earth, currently orbiting us on a Planet Labs Dove satellite.&nbsp;<a href=\"http://www.alexglow.com/space-music-art-spinning-up/\" target=\"_blank\">http://www.<wbr />alexglow.com/space-music-art-<wbr />spinning-up/</a></p>\r\n<p><img src=\"/uploaded_images/nautilus.jpg\" alt=\"\" /></p>\r\n<p>Nautilus Mind pendant:&nbsp;A wearable that helps you harness the creativity of hypnagogic thought.&nbsp;<a href=\"https://www.hackster.io/glowascii/nautilus-5699c5\" target=\"_blank\">https://www.hackster.<wbr />io/glowascii/nautilus-5699c5</a></p>\r\n<p><img src=\"/uploaded_images/luminary.JPG\" alt=\"\" /></p>\r\n<p>Luminary pendant: Lighted leaf pendant made almost entirely of LEDs.</p>', 'https://twitter.com/glowascii', 'http://www.alexglow.com/', 'alex.glowaski@gmail.com ', '', '0', '1500503588', NULL, NULL),
(192, 'Mirabelle Jones', 'mirabelle-jones', 'http://codame.dreamhosters.com/uploaded_images/mirabelle-jones.jpg', '<p>Mirabelle Jones is a creative technologist, writer and interdisciplinary artist from Oakland currently living in Copenhagen. Recently,&nbsp;she served as the Senior Designer / Developer for Meow Wolf&lsquo;s interactive technology team with a specialization in interactive and immersive storytelling using sensors, responsive lighting and sound, 3D modeling / 3D printed sculpture, augmented and mixed reality, and computer vision.</p>\r\n<p>Her&nbsp;works have been acquired by the ONE National Gay &amp; Lesbian Archives, the Center on Contemporary Art, UC Berkeley, the School of the Art Institute in Chicago, Syracuse University, UC Berkeley, and more.</p>\r\n<p>She&nbsp;have held residencies at Women&rsquo;s Studio Workshop, KALA Arts Institute, Codame, Arts Everywhere and Unit One.</p>\r\n<p>Her&nbsp;works have been exhibited at museums and galleries around the world including most recently the Museum Meermanno, The Center for Performance Research and the Finnish National Opera and Ballet.</p>\r\n<p>Her&nbsp;performances and visual works have been heralded by the Huffington Post, ArtNet, Bustle, ATTN, Refinery29, Inquisitr, Mic., Sleek Magazine, Feminist Magazine, Google and Yahoo News, and elsewhere.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"/uploaded_images/015.jpg\" alt=\"\" /></p>\r\n<p>&nbsp;</p>', 'https://twitter.com/mirabelle_jones', 'http://www.mirabellejones.com/', 'mirabellejones@gmail.com ', '', '0', '1629592510', '', ''),
(209, 'Wave Chair Ghost', 'wave-chair-ghost', 'http://codame.dreamhosters.com/uploaded_images/wave-chair-ghost.png', '<p>Allison Hughes and Max Goodman belong to Wave Chair Ghost, an artist collective. We are artists living in San Francisco.</p>', '', 'http://wavechairghost.club', 'allison.n.hughes@gmail.com', '', '0', '1475011869', NULL, NULL),
(193, 'Ricardo O\'Nascimento ', 'ricardo-o-nascimento', 'http://codame.dreamhosters.com/uploaded_images/ricardo-o-nascimento.jpg', '<div>Ricardo O\'Nascimento is an artist and researcher on the field of new media and interactive art. He investigates body-environment relations focused on interface development for worn devices, interactive installations and hybrid environments.&nbsp;He is the founder of&nbsp;<a href=\"http://www.popkalab.com/\" target=\"_blank\">POPKALAB</a>&nbsp;- a design/research studio focused on innovation on the field of wearable technology.</div>\r\n<p>His accolades include&nbsp;CYNETART award 2012 and Rumos Arte Cibern&eacute;tica. His works have been featured in several museums, galleries and art festivals like Ars Electronica, FILE, LABoral, V2, Instituto Ita&uacute; Cultural, Soft Galleri, Transmediale and MAC - Coru&ntilde;a, among others.</p>\r\n<p>Ricardo will be joining us at <a href=\"/admin/labs.codame.com\">CODAME Labs</a> and at the <a href=\"/admin/festival.codame.com\">INTERFACE Art+Tech Festival</a> in 2016.</p>\r\n<p>Photo (Top): &ldquo;Paparazzi Lover&rdquo; (2012) with Anbaja Blanken; Photographer: Peter grilmar</p>\r\n<p>&nbsp;</p>\r\n<div style=\"word-wrap: break-word;\"><span style=\"color: rgba(51, 51, 51, 0.901961); font-family: effra; font-size: 14px; line-height: 22.4px; background-color: #fcfcfc;\"><img src=\"/uploaded_images/PastedGraphic-5.jpg\" alt=\"\" /></span></div>\r\n<div>&ldquo;Feather tales&rdquo; (2012) with Ebru Kurbak</div>\r\n<div>Photographer: Sergio Reduelo</div>\r\n<div style=\"word-wrap: break-word;\">&nbsp;&nbsp;</div>\r\n<div style=\"word-wrap: break-word;\">&nbsp;</div>\r\n<div style=\"word-wrap: break-word;\"><img src=\"/uploaded_images/PastedGraphic-1.jpg\" alt=\"\" />&ldquo;be loved&rdquo; 2015 with Iria do Castelo</div>\r\n<div style=\"word-wrap: break-word;\">Photographer:&nbsp;Lidia Vevi</div>', '', 'http://www.onascimento.com/', 'popkalab@gmail.com', '', '0', '1456196082', NULL, NULL),
(183, 'CAPSVLE', 'capsvle', 'http://codame.dreamhosters.com/uploaded_images/capsvle.jpg', '<p>CAPSVLE is an art collective consisting of artists, engineers, and researchers that aim to bridge the gap between art and technology through unique perceptual experiences.&nbsp;</p>\r\n<p>Don\'t miss <a href=\"/projects/windows-by-capsvle\"><em>Windows</em> by CAPSVLE</a> at the 2015 CODAME Art+Tech Festival&nbsp;on October 23-24!</p>\r\n<p><img src=\"/uploaded_images/unnamed-3.jpg\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/unnamed-2.jpg\" alt=\"\" /></p>', '', 'https://facebook.com/capsvle', '', '', '0', '1452120576', NULL, NULL),
(184, 'CRUISE í¬ë£¨ì¦ˆ', 'cruise', 'http://codame.dreamhosters.com/uploaded_images/cruise.jpg', '<p>CRUISE&nbsp;<span lang=\"KO\">í¬ë£¨ì¦ˆ</span>&nbsp;is a multimedia artist whose work focuses on the nature of duality and non-duality, the relationship between the form and the formless, and the use art as a means to explore the unconscious. Additionally, he conducts research in art psychology and works as a creative director and designer.</p>\r\n<p><a href=\"https://instagram.com/cruisewifi\" target=\"_blank\">https://instagram.com/<wbr />cruisewifi</a></p>\r\n<p><a href=\"https://facebook.com/cruisewifi\" target=\"_blank\">https://facebook.com/<wbr />cruisewifi</a></p>\r\n<p>CRUISE&nbsp;<span lang=\"KO\">í¬ë£¨ì¦ˆ is a member of <a href=\"/artists/capsvle\">CAPSVLE</a> will be showing&nbsp;<a href=\"/projects/windows-by-capsvle\">Windows by CAPSVLE</a> at the 2015 <a href=\"/events/art-tech-festival-2015\">CODAME Art+Tech Festival</a> on October 23-24.</span></p>\r\n<p style=\"color: #222222; font-family: arial, sans-serif; font-size: 12.8px;\"><span style=\"font-family: Helvetica;\"><img src=\"/uploaded_images/unnamed-21.jpg\" alt=\"\" /></span></p>\r\n<p style=\"color: #222222; font-family: arial, sans-serif; font-size: 12.8px;\">&nbsp;</p>\r\n<p style=\"color: #222222; font-family: arial, sans-serif; font-size: 12.8px;\"><img src=\"/uploaded_images/unnamed-1.jpg\" alt=\"\" /></p>', '', 'https://instagram.com/cruisewifi', '', '', '0', '1445216855', NULL, NULL),
(185, 'OOGGEE', 'ooggee', 'http://codame.dreamhosters.com/uploaded_images/ooggee.jpg', '<p>OOGGEE is a conceptual and visual artist living on the Internet. His work consistently serves to disorient and dissociate viewers from their comfortable reality. His focus is helping people see the novel within the familiar, as well as using the familiar as a platform to create new meaning. &nbsp;</p>\r\n<p>OOGGEE<span lang=\"KO\">&nbsp;is a member of <a href=\"/artists/capsvle\">CAPSVLE</a> will be showing&nbsp;<a href=\"/projects/windows-by-capsvle\">Windows&nbsp;by CAPSVLE</a>&nbsp;at the 2015&nbsp;<a href=\"/events/art-tech-festival-2015\">CODAME Art+Tech Festival</a>&nbsp;on October 23-24.</span></p>\r\n<p><img src=\"/uploaded_images/unnamed-11.jpg\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"/uploaded_images/unnamed-22.jpg\" alt=\"\" /></p>', '', 'https://instagram.com/ooggee/', '', '', '0', '1445219596', NULL, NULL),
(336, 'Yoon Chung Han', 'yoon-chung-han', 'http://codame.dreamhosters.com/uploaded_images/yoon-chung-han.jpg', '<p>Yoon C Han is an interaction designer, multimedia artist, and researcher based in the SF bay area. Her researches include data visualization, biometric data visualization and sonification, new interface for musical expression, and mobile user experience design. Her works have been presented in solo and numerous international group shows including SIGGRAPH, Japan media arts festival, IEEE VIS, CHI, ISEA, NIME, London Science Museum, ZKM where she has received multiple awards and grants. In addition, she served on the SIGGRAPH organizing committees as a jury member and was on the IEEE VIS program committees as a co exhibition-chair. She studied Graphic Design and Interaction Design at Seoul National University and achieved two Master degrees at SNU and Design | Media Arts in UCLA. She worked at Samsung Electronics, Experimental Visualization Lab in UCSB and SENSEable City Lab in MIT as a Visiting Researcher. She taught interaction design and computer programming at the Academy of Art University, the University of San Francisco and California State University, Fullerton. She holds Ph.D. at the Media Arts and Technology, UC Santa Barbara, and currently an assistant professor in the department of design, San Jose State University.</p>\r\n<p>&nbsp;</p>', '', 'http://www.yoonchunghan.com', '', '', '0', '1537897014', NULL, NULL),
(195, 'Valerie Lamontagne', 'valerie-lamontagne', 'http://codame.dreamhosters.com/uploaded_images/valerie-lamontagne.jpg', '<p>Val&eacute;rie Lamontagne is an artist-designer, theorist, curator, and PhD scholar researching &ldquo;Performative Wearables: Bodies, Fashion and Technology&rdquo; at Concordia University where she teaches in the Department of Design &amp; Computation Arts. She is the owner &amp; designer at 3lectromode, a wearable electronics atelier and founder-director of Agence Simultan&eacute;e, a post-digital design lab. She is also the Principal Investigator at VestechPro, an apparel research and innovation centre, and holds the position of Creative Lead at Cirque du Soleil&rsquo;s C:Lab.&nbsp;</p>\r\n<p>Photo (Top): Strokes&amp;Dots Photography: Julia Marois</p>\r\n<p><img src=\"/uploaded_images/06_3lectromode_StrokesDots.jpg\" alt=\"\" />Strokes&amp;Dots Photography: Julia Marois</p>\r\n<p><img src=\"/uploaded_images/08_3lectromode_Future_Matter.jpg\" alt=\"\" />Future Matter Photography: Jamie Lablanc</p>\r\n<p class=\"p1\"><img src=\"/uploaded_images/07_3lectromode_Future_Matter.jpg\" alt=\"\" />Future Matter Photography: Jamie Lablanc</p>\r\n<p>&nbsp;</p>', '', 'http://3lectromode.com/', 'valerie@3lectromode.com', '', '0', '1455943238', NULL, NULL),
(189, 'Jeffrey Bryant ', 'jeffrey-bryant', 'http://codame.dreamhosters.com/uploaded_images/jeffrey-bryant.gif', '<div>Jeffrey Bryant&nbsp;(aka Ecco Screen) is a San Francisco based installation artist and creative coder who is interested in the intersection of art and technology in order to envelop people in an immersive experience. His work focuses on the way people perceive each other by allowing a user to take on the perspective of another individual who they may not entirely understand in order to bring human beings closer together. He recently graduated from the Gray Area Art &amp; Technology\'s Creative Code immersive in the spring of 2015 and has since done three installations in just a short amount of time with many more currently in the works.&nbsp;</div>', 'https://twitter.com/eccoscreen', 'https://eccoscreen.xyz/about', '', '', '0', '1556255647', NULL, NULL),
(198, 'Neil Mendoza', 'neil-mendoza', 'http://codame.dreamhosters.com/uploaded_images/neil-mendoza.jpg', '<p>&nbsp;</p>\r\n<p class=\"p1\"><span class=\"s1\">Neil Mendoza&rsquo;s&nbsp;work uses digital and mechanical technologies to bring inanimate objects and spaces to life. Using this medium,&nbsp;he&nbsp;explores the absurd, the humorous, the futile and the surreal.&nbsp;He was born and raised in the UK and is currently based in Los Angeles. His work has been exhibited by The Science Museum, The V&amp;A, Watermans, PICNIC Festival, The AND Festival, ISEA, Kinetica, The Nottingham Playhouse, The Barbican, BBC Big Screens and The Museum of London, Oi Futuro, among others.</span></p>\r\n<p class=\"p1\"><span class=\"s1\">We are thrilled&nbsp;to have Neil\'s work&nbsp;as part of&nbsp;our&nbsp;<a href=\"http://labs.codame.com\">CODAME Labs</a>&nbsp;in 2016</span></p>\r\n<p class=\"p1\"><span class=\"s1\"><img src=\"/uploaded_images/unspecified1.jpg\" alt=\"\" /></span></p>\r\n<p class=\"p1\">&nbsp;<img src=\"/uploaded_images/unspecified.jpg\" alt=\"\" /></p>\r\n<p class=\"p1\">&nbsp;</p>\r\n<p class=\"p1\"><img src=\"/uploaded_images/slack-imgs.com_.jpg\" alt=\"\" /></p>', 'http://twitter.com/neilmendoza', 'http://neilmendoza.com', '', '', '0', '1467401166', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(199, 'Maartje Dijkstra', 'maartje-dijkstra', 'http://codame.dreamhosters.com/uploaded_images/maartje-dijkstra.jpg', '<p>Maartje Dijkstra is Dutch fashion designer based in Rotterdam.&nbsp;</p>\r\n<p>She studied at ARTEZ/HKA Arnhem The Netherlands, where she graduated as a Bachelor in Fashion Design in 2006. In 2005 she did an internship at the company of Alexander McQueen in London, where her interests in High fashion developed. In 2007 she started her own High fashion/couture label, where she designs and creates individualistic, sculptural, progressive, hand-crafted fashion collections, accessories and illustrations.&nbsp;</p>\r\n<p>The designs of her (small) spherical collections are all handcrafted, unique, high fashion pieces, designed with the future in mind, made by her only. Her work has many manual details and is also very recognisable by her surreal hand-drawn illustrations. Imagination, electronic music, progressiveness and individuality are a big source of inspiration for her. Especially music/sounds are an important factor in creating her work and became more important because of the environment she now works in. A house with studio\'s where music composers create amazing sounds like jungle/breakcore and ambient, so it becomes almost a melancholic place to work.&nbsp;</p>\r\n<p>Next to showing her pieces on the runway, for her the ultimate exhibition place, she is very much focused combining fashion with technology. Because of her interest in the time consuming manual way of creating fashion and designs her pieces with a progressive mind, technology connects very well within her work. The technical and music parts she always does in collaboration with other great artists.&nbsp;</p>\r\n<p>We are excited to have&nbsp;Maartje&nbsp;joining&nbsp;our&nbsp;<a href=\"http://labs.codame.com\">CODAME Labs</a>.</p>\r\n<p>&nbsp;<img src=\"/uploaded_images/maartje-dijkstra1.jpg\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/shoot41.jpg\" alt=\"\" /></p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\"><strong>-Braindrain- 2016</strong></p>\r\n<p dir=\"ltr\">Braindrain (information/knowledge that is spreading to different places) is the new fashion technology piece from fashion designer Maartje Dijkstra (NL).</p>\r\n<p dir=\"ltr\">Important in her work is the combination between technology/progressiveness, styling and manual craftsmanship, that stands for individualism and uniqueness. The golden parts of the design, are connected to small robotics/motors with LED\'s that move and flicker like a stroboscope, on the rhythms, breaks &nbsp;and beats of electronic music by music composer Newk. The technical parts are developed in cooperation with technology artists Neon&amp;Nanda.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\">The bombastic/sculptural design is build up in two different layers, melted into one story.</p>\r\n<p dir=\"ltr\">The black parts of the dress are totally manual 3D printed with a 3Doodler (flexible filament), with a structure that is inspired by Chitin, the building material of exoskeletons like insects. The parts are connected by hand with black polyester wires. The golden elements, inspired by a Dutch golden ear-iron from 1850, are 3D printed (designed together with Vincent Mensink, 3D printed by Oceanz ) out of white Nylon filament, finished with a special golden spray paint. The golden elements are looking smooth but they have a extra effect/dimension. They are semi transparent, with an even more transparent detail of lines inside, that are only visible when the lights turn on. The robotics/moving parts give the design a animal-like feeling, like its breathing, taking in in the sounds and sending it back into the world.</p>\r\n<p><br /><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/a6483837-779b-4276-aa43-21ddfc892190.jpg\" alt=\"\" /></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/0376b59f-4462-4d82-9d7a-95dadcaab8b9.jpg\" alt=\"\" /><br /><br /></p>\r\n<p dir=\"ltr\" style=\"line-height: 1.2; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 16px; font-family: \'Liberation Serif\'; color: #000000; background-color: transparent; font-weight: 400; font-style: normal; font-variant: normal; text-decoration: none; vertical-align: baseline; white-space: pre-wrap;\"> &nbsp;</span></p>', 'http://twitter.com/maartjedijkstra', 'http://maartjedijkstra.com', '', '', '0', '1461439948', NULL, NULL),
(200, 'Igor Knezevic', 'igor-knezevic', 'http://codame.dreamhosters.com/uploaded_images/igor-knezevic.jpeg', '<p><span class=\"s1\">Los Angeles based architect specialized in creating 3D environments and concept designs using a variety of 3D and 2D digital tools. Before he laid his hands on 3D tools and computer graphics, Igor was trained in traditional painting media and crew comics and illustrations by hand. His brand name Alienology, is a design studio and consultancy, active in the areas of Product Design, Architecture, Concept Design for film themed environments - all done with expert 2D and 3D CGI skills.&nbsp;</span></p>\r\n<p class=\"p1\"><span class=\"s1\"><img src=\"/uploaded_images/slack-imgs.com_.png\" alt=\"\" /></span></p>', '', 'http://www.alienology.com/catalog/', '', '', '0', '1456614170', NULL, NULL),
(201, 'Alex Murray-Leslie', 'alex-murray-leslie', 'http://codame.dreamhosters.com/uploaded_images/alex-murray-leslie.jpg', '<div>Alex&nbsp;Murray-Leslie is an artist/researcher and curator, working in the areas of computational foot-wearables, digital music instrument design, Pop Music &amp; Live-Art. She is founder of Chicks on Speed, an internationally renowned art band.<br /><br />Alex&nbsp;is currently PhD candidate in the Faculty of Engineering and IT, Creativity and Cognition Studios, The University of Technology Sydney and research fellow at Art and Design Research Incubator, Department of Sports Science, The Pennsylvania State University and Music Technology Group, University Pompeu Fabre, Barcelona.</div>\r\n<div><br />She worked as Entertainment Manager at The 34th America\'s Cup World Series sporting event in San Francisco, her current curatorial project:&nbsp;Curator of the worlds first wearable technology in Fashion Film competition, Diane Pernet presents ASVOFF 9, Centre Pompidou, Paris, Nov, 2016.</div>\r\n<div>&nbsp;</div>\r\n<div>Alex&nbsp;performs, curates, lectures &amp; exhibits internationally, along side writing for scientific journal and book publications.</div>\r\n<p>Photo (Top):&nbsp;E-Shoe, A High Heeled Shoe guitar, (Chicks on Speed,&nbsp;Alex&nbsp;Murray-Leslie and Max Kibardin)</p>\r\n<p><img src=\"/uploaded_images/ShoeCOSforweb.jpg\" alt=\"\" />Computer Enhanced Foot-Wearable by&nbsp;Alex&nbsp;Murray-Leslie, 2016. Developed in collaboration with Jeff Hong, ADM, Nanyang Technological University, Centre for Contemporary Art, Singapore, 2015 and Dr. Sam Ferguson, Creativity and Cognition Studios, The University of Technology, Sydney, kindly supported by The Australia Council for the Arts.</p>\r\n<p><img src=\"/uploaded_images/getty_image.jpg\" alt=\"\" />Alex&nbsp;Murray-Leslie, performing with Chicks on Speed, Isle of Wight, 2015</p>\r\n<div><img src=\"/uploaded_images/alex_lagerfeld_performance.jpg\" alt=\"\" /></div>\r\n<div>Chicks on Speed ARTSTRAVAGANZA for Karl Lagerfeld, &ldquo;Modemethode&rdquo;, Bundeskunsthalle, Bonn, 13t Sept, 2015</div>\r\n<p>&nbsp;</p>', 'https://twitter.com/alxmurrayleslie', 'www.chicksonspeed.com', 'amurrayleslie@mac.com', '', '0', '1456872639', NULL, NULL),
(203, 'Katia Vega', 'katia-vega', 'http://codame.dreamhosters.com/uploaded_images/katia-vega.jpg', '<p class=\"MsoNormal\" style=\"margin: 0px 0px 0.0001pt; font-family: arial, sans-serif; font-size: 12.8px; line-height: 19.2px;\"><span lang=\"EN-GB\" style=\"font-size: 10pt; line-height: 20px; font-family: Arial;\">Katia Vega is a&nbsp;Beauty&nbsp;Tech Designer. Inspired by invisible computing, wearables and magic, she proposes novel ways to move from traditional to interactive cosmetics. Conductive Makeup, Tech Nails, Hairware and FX e-makeup are her&nbsp;Beauty&nbsp;Technologies&nbsp;that transform the body in an interactive platform.</span></p>\r\n<p class=\"MsoNormal\" style=\"margin: 0px 0px 0.0001pt; font-family: arial, sans-serif; font-size: 12.8px; line-height: 19.2px;\">&nbsp;</p>\r\n<p class=\"MsoNormal\" style=\"margin: 0px 0px 0.0001pt; font-family: arial, sans-serif; font-size: 12.8px; line-height: 19.2px;\"><span lang=\"EN-GB\" style=\"font-size: 10pt; line-height: 20px; font-family: Arial;\">She is a postdoc at the MIT Media Lab (USA). She got her PhD and master degree in Computer Science at PUC-Rio (Brazil). She received a BS from UNMSM (Peru). She was a Research Assistant at HKBU (Hong Kong).</span></p>\r\n<p class=\"MsoNormal\" style=\"margin: 0px 0px 0.0001pt; font-family: arial, sans-serif; font-size: 12.8px; line-height: 19.2px;\"><span lang=\"EN-GB\" style=\"font-size: 10pt; line-height: 20px; font-family: Arial;\">Her work was covered by New Scientist, Wired, Discovery, CNN, PSFK and others.</span></p>\r\n<p class=\"MsoNormal\" style=\"margin: 0px 0px 0.0001pt; font-family: arial, sans-serif; font-size: 12.8px; line-height: 19.2px;\">&nbsp;</p>\r\n<p class=\"MsoNormal\" style=\"margin: 0px 0px 0.0001pt; font-family: arial, sans-serif; font-size: 12.8px; line-height: 19.2px;\"><a href=\"http://katiavega.com/\">http://katiavega.com/</a></p>', '', 'http://katiavega.com/', 'katia@katiavega.com', '', '0', '1458419050', NULL, NULL),
(204, 'Bruno Fonzi', 'bruno-fonzi', 'http://codame.dreamhosters.com/uploaded_images/bruno-fonzi.jpg', '<p>CODAME ART+TECH Commodore and co-founder.</p>\r\n<p>Technologist and Creative Leader,&nbsp;entrepreneur, and supporter of the arts. Bruno started&nbsp;CODAME&nbsp;in 2010 in San Francisco to fulfill his passion for exploring the intersection of art and technology. CODAME has been an&nbsp;opportunity to support and cultivate art and innovation and bring people together from different backgrounds and skill sets:&nbsp;Artists, Designers, Developers, and Engineers to explore the future by using an artistic&nbsp;mindset in a playful, experimental way.</p>\r\n<p>Bruno sold his first software application to a school when he was 15 with&nbsp;his first computer (TI 99/a) as part of a bundle to make enough money to live and study for a year in high school in the United States. This experience had a great positive impact on his personal life and career.</p>\r\n<p>As part of his final BSc Computer Science&nbsp;academic&nbsp;thesis at the&nbsp;London Metropolitan University, he built a photo manipulation software application. This was before Abobe had Photoshop. A project that enabled him to combine his passion for software, photography, art, and design early in his career led him to work with industry leaders&nbsp;companies such as Quark, Adobe, MuleSoft, and Salesforce.</p>\r\n<p>He then worked as a consultant building an Artificial Intelligent system for Siemens, Telecom Italia, and the European Space Agency(ESA). Satellites,&nbsp;robots, and space shuttles were his first job; it was a great start!&nbsp;After getting&nbsp;his Master in Business and Technology at UNSW Sydney, Australia, he eventually landed in Silicon Valley, worked for a start-up, and decided to fund his own, Lanica,&nbsp;a&nbsp;state-of-art native cross-platform mobile gaming solution for JavaScript developers.</p>\r\n<p>As an Executive&nbsp;Independent Consultant, Bruno&nbsp;continues bringing CODAME spirit, experiences, and&nbsp;inspiration&nbsp;back to work.</p>', 'https://www.linkedin.com/in/fonzi/', 'https://fonzi.com', 'bruno@codame.com', '', '0', '1683600774', '', ''),
(205, 'Kyuin Shim', 'kyuin-shim', 'http://codame.dreamhosters.com/uploaded_images/kyuin-shim.jpg', '<p>Based in Seoul, Korea,&nbsp;<a href=\"https://www.behance.net/shimkyuin\" target=\"_blank\">Kyuin Shim</a>&nbsp;is a digital artist and sculptor who executes dark and poignant visions by altering the human body. His latest sculptural series &ldquo;Black Black&rdquo; features several monochromatic renditions of mannequin-like figures whose bodies seem to disintegrate before one&rsquo;s eyes. In Korean, the title of the series has two meanings: &ldquo;Black&rdquo; and &ldquo;Sound of Crying.&rdquo; The characters&rsquo; flesh becomes consumed by bubbling matter that eventually turns into a downpour of water from their limbs and orifices. A recent series of digital 3D renderings, &ldquo;Small Place,&rdquo; similarly abstracts the human body, this time in all white. Featuring different groupings of feet sticking out from under a cubicle-like prism, the piece evokes the smothering closeness of an unhealthy relationship. Take a look at some of Shim&rsquo;s work below.</p>\r\n<p><span style=\"color: #373737; font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-size: 15px; line-height: 21px;\"><img src=\"/uploaded_images/kyuin_shim_5.jpg\" alt=\"\" /></span></p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"/uploaded_images/kyuin_shim_8.jpg\" alt=\"\" /></p>', '', 'https://www.behance.net/shimkyuin', '', '', '0', '1467175489', NULL, NULL),
(206, 'Bart Hess', 'bart-hess', 'http://codame.dreamhosters.com/uploaded_images/bart-hess.jpg', '<p id=\"u1431-2\">The work of Bart Hess is of the most tactile and intuitive nature. He first delved into instinctive textiles when studying at the Design Academy Eindhoven, where he created A Hunt for High Tech, a collection of materials that mimicked the bestial outer layers of unfamiliar hybrid species, accompanied by an evocative film that brilliantly brought his concepts to life.</p>\r\n<p id=\"u1431-3\">&nbsp;</p>\r\n<p id=\"u1431-5\">Over the past six years, Hess has developed an impressive roster of work. He has pinned, stretched, slimed and scraped materials in relation to the human body, and collaborated with the likes of Lucy McRae, Nick Knight, Lady Gaga, Iris van Herpen and Walter van Beirendonck. In 2013, he is the recipient of the Stichting Profiel prize and his work is the subject of a mid-career survey at the Rijksmuseum Enschede. The exhibition notes explain that Hess creates another world, one &ldquo;in which technology melds body and object&hellip; when we don the materials and applications that Hess has created, we are transformed into a new but completely logical creature.&rdquo;</p>\r\n<p id=\"u1431-6\">&nbsp;</p>\r\n<p id=\"u1431-8\">Hess feels that our bodies are increasingly becoming a platform for sensitive and interactive technology, and has constantly exposed the intimate relationship materials have upon our skin, including a concept for Philips Design that mounted an electronic tattoo underneath the skin&rsquo;s surface. &ldquo;It felt like a natural instinct for me to start working on the body. When I create a new design I always place it on my own skin even-though it originally was created as, for example, a flooring material. The fascinating thing about it for me is the combination of a skin and a material. By using a material on the body that is not the body&rsquo;s own, but making it look like it could possibly be, I create a tension between the body and material.&rdquo;[1]</p>\r\n<p id=\"u1431-9\">&nbsp;</p>\r\n<p id=\"u1431-11\">Foamy, sweaty, blobular and molecular are the kinds of surfaces that Hess concocts. Flirting with a touch of the grotesque and the macabre, he explains that he tries &ldquo;to find a balance between beauty and disgust or horror. I think the darker side of beauty has less restrictions because it hasn\'t been explored that much, which makes it more interesting for me to show to my audience&rdquo;.[2] Through the use of design, film, photography and installation, Hess has found intimate ways for his textiles to communicate with their &ldquo;audience&rdquo;, and in 2012&rsquo;s Work With Me pop-up studio, he was even able to involve some of them in the making process.</p>\r\n<p id=\"u1431-12\">&nbsp;</p>\r\n<p id=\"u1431-14\">If Hess is on the hunt for tactilities that can transform the design landscape, he is definitely on the right track. By innovating materials that braise, coat or titillate the body, he has opened up a sensual and sexually-charged discourse about the future of smart textiles. Hess introduces materials to our primal needs and innate sense of touch, showing that fabrications will first need to seduce us before they can become part of us.</p>\r\n<p id=\"u1431-15\">&nbsp;</p>\r\n<p id=\"u1431-17\">Text by Philip Fimmano</p>\r\n<p id=\"u1431-19\">Taken from the publication Fetishism in Fashion</p>\r\n<p><img src=\"/uploaded_images/maxresdefault.jpg\" alt=\"\" /><img src=\"/uploaded_images/001-bart-hess-theredlist.jpg\" alt=\"\" /></p>', '', 'http://barthess.nl/', 'info@barthess.nl', '', '0', '1467350100', NULL, NULL),
(207, 'Yagiz Mungan', 'yagiz-mungan', 'http://codame.dreamhosters.com/uploaded_images/yagiz-mungan.jpg', '<div>R. Yagiz Mungan is an interdisciplinary artist whose practice is located at the intersection of VR/AR, sound/music, interaction, performance, virtual worlds and gaming. His works ranges from linear musical pieces to art games to installations to generative systems to alternate realities but in general integrates technology as an active agent of the experience. He uses his works to pose questions about various aspects of the daily life, or investigate new aesthetics of sound, interaction and visuals</div>\r\n<p>His solo and collaborative works have been exhibited and performed internationally in United States, Turkey, Germany and Czech Republic. He holds MSc in computer engineering and MFA in interactive arts. He currently lives in San Francisco and is mostly busy with creating interactive experiences for independent projects or AKQA, where he works.</p>\r\n<p>---</p>\r\n<p><strong>You can learn more&nbsp;about&nbsp;Yagiz&nbsp;on this post on our ART+TECH Collection on Medium:</strong></p>\r\n<p><a href=\"http://medium.com/codame-art-tech/a-conversation-with-yagiz-mungan-codame-artist-9213cf8d73d9\">Interview with Yagiz Mungan</a></p>\r\n<p>Interdisciplinary artist&nbsp;<a href=\"/artists/yagiz-mungan\" target=\"_blank\" rel=\"nofollow noopener\" data-href=\"http://codame.com/artists/yagiz-mungan\">Yagiz Mungan</a>&nbsp;creates work that blends VR/AR, sound/music, interaction, performance, virtual worlds and gaming. He is especially interested in generative strategies of creating visuals and sound, and ways to use technology to push the boundaries of human perception and emotional response. His work often aims to recontextualize familiar experiences, or addresses uncanny technological encounters in modern life....&nbsp;[read more&nbsp;<a href=\"https://medium.com/codame-art-tech/a-conversation-with-yagiz-mungan-codame-artist-9213cf8d73d9\">here</a>]</p>\r\n<p><img src=\"/uploaded_images/unnamed-1.png\" alt=\"\" /></p>', 'http://twitter.com/yagizmungan', 'http://www.yagizmungan.com/', 'yagizmungan@gmail.com', '', '0', '1523519516', NULL, NULL),
(208, 'Chun Wang', 'chun-wang', 'http://codame.dreamhosters.com/uploaded_images/chun-wang.jpg', '<div><a href=\"http://thisisjusttodraw.wordpress.com/\" target=\"_blank\" data-saferedirecturl=\"https://www.google.com/url?hl=en&amp;q=http://thisisjusttodraw.wordpress.com/&amp;source=gmail&amp;ust=1472101918870000&amp;usg=AFQjCNFa25Za1Kjl5pN40XyOSZkI382G-w\">Chun Wang</a>&nbsp;is a&nbsp;coder and&nbsp;mixed media&nbsp;artist&nbsp;whose day job is to create&nbsp;interactive data visualizations for&nbsp;commercial software. Her&nbsp;artworks span across&nbsp;watercolor and acrylic&nbsp;paintings,&nbsp;collages,&nbsp;i<wbr />nstallations, and digital arts.&nbsp;She embraces technology as a medium for artistic expression and to enrich the way her art is perceived and understood by its audience.&nbsp;Her latest works piece together fine arts, creative coding, and augmented reality to invent multilayered&nbsp;aesthetic&nbsp;experie<wbr />nces.</div>', '', 'http://thisisjusttodraw.wordpress.com/', 'cw8df@virginia.edu', '', '0', '1472054443', NULL, NULL),
(233, 'Jesse Hewit', 'jesse-hewit', 'http://codame.dreamhosters.com/uploaded_images/jesse-hewit.png', '<p><br />Jesse Hewit is an American performance and dance artist, currently based in San Francisco.<br /><br />Jesse&rsquo;s work is an attempt to synthesize unlikely contexts into a singular experience that unsettles dominant ideas about power, narrative, safety, and beauty.<br /><br />He attended NYU&rsquo;s Tisch School of the Arts, where he studied with Annie B Parson, Steve Wangh, Raina Von Waldenburg, Karen Finley, KJ Holmes, and Mary Overlie. In 2005, Jesse moved from New York to San Francisco to pursue graduate study in cross-disciplinary sociology, and upon graduating in 2007, began making work under the moniker Strong Behavior. Since 2007, five longer works and many shorter works have been created, and over time, Jesse has collaborated on the making of multiple works with Keith Hennessy, and with Sara Shelton Mann, among others. He has also, taught, written about, and curated dance and performance practices extensively up and down the U.S. West Coast and throughout Western Europe.<br /><br />Jesse&rsquo;s work has been supported by residencies from CounterPulse, Headlands Center for the Arts, Z Space, and Ponderosa Tanzland, as well as grants and awards from Theatre Bay Area&rsquo;s CA$H Grant, The Zellerbach Family Foundation, The Kenneth Rainin Foundation, The New Stages for Dance Initiative, MAP Fund, and many amazing individual donors. Recent Honors include a 2010 San Francisco Bay Guardian Award for performance and a 2014 Isadora Duncan Dance Award nomination for Individual Performance.</p>', '', 'http://www.strongbehavior.com', 'jesse.hewit@gmail.com', '', '0', '1479148749', NULL, NULL),
(212, 'Yagmur Uyanik', 'yagmur-uyanik', 'http://codame.dreamhosters.com/uploaded_images/yagmur-uyanik.jpg', '<p>YaÄŸmur UyanÄ±k is a Turkish artist based in San Francisco with backgrounds in architecture, new media and music. Her work explores repetition, process and intangibility through creating instruments of displacement. She aims to extend the digital media to a point that it becomes a physical experience.&nbsp;</p>\r\n<p>UyanÄ±k&rsquo;s work strolls on the edges of unde ned gaps using network of time, memory and perception and is centered around creating a range of installations that take on the expected but what is not seen by the eye easily, what hangs between meaningful and outside-of-meaning. She is interested in the tension between real and synthesized with an aspiration to think about the dynamic perception of space.UyanÄ±k has received her Bachelor&rsquo;s degree in Architecture with a minor in Music and her Master&rsquo;s degree in Art &amp; Technology from San Francisco Art Institute as a Fulbright scholar. Her work was shown internationally at institutions including Ars Electronica Linz; Sonar D+ Barcelona; Signal Light Festival Prague; Geneva International Film Festival; Art Futura Rome; Exploratorium, Swell Gallery and Diego Rivera Gallery, San Francisco and was written about in publications such as Archinet, Designcollector, Design Milk, FRAME Magazine and Earmilk</p>', '', '', 'yagmuruyanik@gmail.com', '', '0', '1625532802', 'https://codame.threadless.com/collections/yagmur-uyanik-and-joey-verbeke', 'https://www.instagram.com/yagmuruyanik'),
(213, 'Joey Verbeke', 'joey-verbeke', 'http://codame.dreamhosters.com/uploaded_images/joey-verbeke.jpg', '<p>Joey Verbeke is a New Media Artist and the Head of AI Innovation, with a background in music and computer science. He focuses his work on imbuing qualities of surreality, curiosity, frisson, and exploring our ephemeral and finite sensory-limited existence. Leveraging technology as a medium, he searches for tangents from its linear progression to explore alternative and innovative applications, approaches, and perspectives. His work extends beyond subjective limits and gives the viewer a chance to question the reconstructed reality he creates. Verbeke&rsquo;s work has been exhibited at galleries and institutions including Denver International Airport, Sundance Film Festival, SIGGRAPH, SXSW, TED, and Future of Storytelling.</p>', '', 'http://www.joeyverbeke.com/', 'joeyverbeke@gmail.com', '', '0', '1625532845', 'https://codame.threadless.com/collections/yagmur-uyanik-and-joey-verbeke', ''),
(215, 'Dustin Freeman', 'dustin-freeman', 'http://codame.dreamhosters.com/uploaded_images/dustin-freeman.jpg', '<p>Dustin Freeman has built several low- and high-level technologies for immersive experiences. His doctoral work was Improv Remix - a Kinect interface for improv performers to create video mashups on the fly. At Microsoft Research, he did interaction design for Kinect Fusion. Most recently, he worked at Occipital on the scripting system and components of their Bridge Mixed Reality platform.</p>', 'http://twitter.com/dustinfreeman', '', 'dustin@raktor.org', '', '0', '1475991892', NULL, NULL),
(216, 'Yanling He', 'yanling-he', 'http://codame.dreamhosters.com/uploaded_images/yaning-he.jpg', '<p class=\"graf graf--p\">Yanling He is a computer engineer and experience designer by day, and a photographer and computer graphics artist by night. She discovered her love of art while exploring computer graphics, and feels fascinated about how our real world is being constructed and rendered. Her work is always trying to connect between the virtual and the real. She currently works at Adobe Design Lab.</p>', 'https://twitter.com/heyl0822', 'http://yanlinghe.com/', 'h@yanlinghe.com', '', '0', '1498077306', NULL, NULL),
(217, 'Bill Hsu', 'bill-hsu', 'http://codame.dreamhosters.com/uploaded_images/bill-hsu.jpg', '<div dir=\"ltr\">&nbsp;</div>\r\n<div dir=\"ltr\">Bill Hsu&nbsp;works with electronics and real-time video. He works with gestural interfaces to control animation and sound synthesis, and builds real-time audio-visual systems that interact with human performers. He is a founding member of the Beanbender&rsquo;s collective, which organized over 150 concerts of new music in the San Francisco Bay area. He teaches and does research in the Department of Computer Science at San Francisco State University.</div>', '', 'http://unixlab.sfsu.edu/~whsu/art.html ', 'oneofmanyhsus@yahoo.com', '', '0', '1539587526', NULL, NULL),
(218, 'Yosun', 'yosun', 'http://codame.dreamhosters.com/uploaded_images/yosun.jpg', '<p>A hacker\'s take on augmented reality, 3d graphics, mobile iOS and Android dev, startups, COOL STUFF and life.</p>', 'https://twitter.com/yosun', 'http://yosun.me/', 'yosofun@gmail.com ', '', '0', '1475263251', NULL, NULL),
(219, 'v21', 'v21', 'http://codame.dreamhosters.com/uploaded_images/v21.jpg', '<p>v21 is the creator of Cheap Bots, Done Quick!, a radically accessible botmaking tool, as well as many bots of their own, such a @unicode_garden, @softlandscapes and <a href=\"http://dkmfxr0axh7rumhs3ppv.tumblr.com/\" target=\"_blank\">dkmfxr0axh7rumhs3ppv.tumblr.com</a>. They are also a game maker (currently the designer on Beasts of Balance, a digital-physical block stacking game) and digital curator of Now Play This, a festival of games and play at Somerset House.</p>', 'https://twitter.com/v21', 'http://v21.io/', 'v.twenty.one@gmail.com', '', '0', '1475265603', NULL, NULL),
(220, 'Erica Anderson', 'erica-anderson', 'http://codame.dreamhosters.com/uploaded_images/erica-anderson.gif', '<p>&nbsp;</p>\r\n<div title=\"Page 1\">\r\n<p>Erica Anderson is on a quest to make Fine Art that moves. Heavily inspired by abstract expressionists and music, she has been animating GIFs in After Effects as a way to bridge the gap between audio and visual art.</p>\r\n<p>In 2016, she collaborated with Donald Hanson and provided GIFs to be used with his VJ software gifSlap, as her first step toward realizing her dream of blending abstract visuals and the rhythms of music.</p>\r\n<p><img src=\"/uploaded_images/molten_tumblr.gif\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/collapsing_star_tumblr.gif\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/edge_of_the_world_tumblr.gif\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/distraction_tumblr.gif\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n</div>', 'https://twitter.com/ericaofanderson', 'http://ericaofanderson.tumblr.com/', 'ericaofanderson@gmail.com', '', '0', '1606162070', '', NULL),
(221, 'UltraBianka', 'ultrabianka', 'http://codame.dreamhosters.com/uploaded_images/ultra-bianka.jpg', '<p>She is a self-generating visual thinker and manifesto, with the aim to process a unique visual language via the usage of creative developments in art, science and technology. &nbsp;She feels a drive to use and abuse all kinds of tools and situations in order to show constant progress. Her work is a series of digital pieces with aesthetic and communicative purposes. Over the years she developed a paradigm system that always expands and defines her current style.</p>\r\n<p>&nbsp;</p>', '', 'http://www.crashcrackcrush.tumblr.com/', 'bianka.oravecz@gmail.com', '', '0', '1475436053', NULL, NULL),
(222, 'Ahree Lee', 'ahree-lee', 'http://codame.dreamhosters.com/uploaded_images/ahree-lee.jpg', '<p>Ahree Lee (born Seoul, South Korea) is a multi-media artist working in video, photography, sound and interactive installations.</p>\r\n<p>Lee received her B.A. from Yale University and M.F.A. from Yale School of Art.</p>\r\n<p>Her many commissions include the Asian Art Museum in San Francisco, the 01SJ Biennial, the Orange County Center for Contemporary Art, the 2006 International Short Film Festival in Leuven, Belgium; the International Festival of Video Art of Casablanca and the Sundance Channel. Her Webby-nominated video Me was shown by Steve Jobs as a demo for YouTube on Apple TV, and is in the permanent collection of the Museum of the Moving Image, New York. Me currently has over 9 million views.</p>\r\n<p>Lee\'s awards include an Artist Fellowship Grant in film and video from the state of Connecticut; a second place Audience Award for Experimental Short Film and a honorable mention Jury Award for Experimental Short Film at Film Fest New Haven, Connecticut; and an artistic career development grant from Asian American Renaissance funded by the Jerome Foundation.&nbsp;</p>\r\n<p>Lee lives and works in Los Angeles with her daughter and husband, Nathan Melsted, an electronic musician, who composes musical scores for much of Lee\'s work.</p>', 'http://twitter.com/ahreelee', 'http://www.ahreelee.com', 'mail@ahreelee.com', '', '0', '1476161592', NULL, NULL),
(344, 'Matt Ingalls', 'matt-ingalls', 'http://codame.dreamhosters.com/uploaded_images/matt-ingalls.jpg', '<p>Reviled for his \"shapeless sonic tinkering\" by the Los Angeles Times, oakland musician Matt Ingalls&nbsp;is a composer, clarinetist, concert producer, and computer music programmer. Often incorporating elements of improvisation, his music is heavily influenced by his long involvement in computer music. His composerly solo improvisations explore extended clarinet techniques that interact with the acoustic space, often as combination tones. Matt is the founder and co-director of&nbsp;sfSound, a new music series, ensemble, and internet radio station devoted to new ideas and traditions of experimental music, performance art, live electronic music, Bay Area composition, and the various facets of contemporary improvisation.&nbsp;</p>\r\n<p><strong>long bio</strong><br /><br />Reviled for his \"shapeless sonic tinkering\" by the Los Angeles Times, oakland musician&nbsp;matt ingalls&nbsp;(b. 1970) is a composer, clarinetist, concert producer, and computer music programmer.<br /><br />Ingalls is most active as a clarinetist, specializing in contemporary and experimental music. He is a prominent figure in the San Francisco Bay Area Improv Scene, and is known for his \"composerly\" solo improvisations that explore extended techniques on his instrument that interact with the acoustic space, often as combination tones. Ingalls has worked with a diverse range of composers such as Mark Applebaum, Anthony Braxton, John Butcher, Helmut Lachenmann, George Lewis, Miya Masaoka, Meredith Monk, Hyo-shin Na, Pauline Oliveros, Stefano Scodanibbio, Chinary Ung, and numerous Bay Area composers.<br /><br />Ingalls has written compositions for acoustic instruments, voices, computer generated tape, interactive electronics, dance, theater, and freely improvising big band. His compositions have been recorded and performed in the United States and abroad, receiving many awards and recognitions. In 1994, he received 1st Finalist in the Bourges Concours International de Musique Electronique Electroacoustic (Categorie Humor - Puy). The following year, Ingalls was awarded the very first ASCAP/SEAMUS Student Commission Prize. Ingalls has also received New Langton Art\'s \"Bay Area Award\", two California Artist Honorary Fellowship Residency at the Djerassi Artist Program, two A.H. Miller prizes, and numerous Meet The Composer Fund/Creative Connections Grants.<br /><br />Ingalls is the founder and co-director of&nbsp;sfSound, a new music series, ensemble, and internet radio station devoted to new ideas and traditions of experimental music, performance art, live electronic music, Bay Area composition, and the various facets of contemporary improvisation. sfSound produces an average of ten concerts a year, mostly taking place at the ODC Theater in the Mission District of San Francisco. In 2008, sfSound received an \"ASCAP Award for Adventurous Programming\" from Chamber Music America. sfSound is the umbrella organization of the San Francisco Tape Music Collective/Festival.<br /><br />As a computer programmer, Ingalls has worked for Bay Area computer music companies such as Cycling 74, Bias, Arboretum, and MuscleFish. He is also the developer of MacCsound a real-time Macintosh version of the classic music synthesis program, Csound. MacCsound won a 2004 \"Editor\'s Choice\" Award from Electronic Musician Magazine. He is also the creator of the Soundflower Mac OS X utility for routing audio among multiple applications. From 2005-2009, Ingalls was the lead programmer for GVOX, primarily developing the Encore music notation program.<br /><br />Ingalls holds degrees in composition from The University of Texas at Austin and Mills College. He studied composition and computer music with George Lewis, Alvin Curran, Chris Brown, Russell Pinkston, Dan Welcher, and Karl Korte. Ingalls has taught music courses at The University of San Francisco and Dartmouth College.&nbsp;<br /><br /></p>\r\n<p><strong>electroacoustic bio</strong><br /><br />matt ingalls&nbsp;(b. 1970) is a composer, clarinetist, and computer musician from Oakland. He is the founder and co-director of the&nbsp;San Francisco Tape Music Collective&nbsp;and its parent organization,&nbsp;sfSound. Matt received the Deu xieÌme Prix (CateÌgorie Humour - Puy) in the 1994 Concours International de Musique Electroacoustique de Bourges and was the first recipient of the ASCAP/SEAMUS Commission and Recording Prize. Matt is also well known for his computer music software. He created the Soundflower audio routing tool for cycling74 and his Csound version for Macintosh, MacCsound won an Electronic Musician Magazine \"Editor\'s Choice Award\" in 2004. Matt\'s software can be downloaded at&nbsp;sonomatics.com.</p>', 'https://twitter.com/sonomatics?', 'http://mattingalls.com/', '', '', '0', '1539588028', NULL, NULL),
(223, 'Elaine Cheung', 'elaine-cheung', 'http://codame.dreamhosters.com/uploaded_images/elaine-cheung.jpg', '<p>Elaine Miu Cheung works at the intersection of art, design, computing and technology. Originally from Los Angeles, she explores themes relating to our embodiment of tech, future systems, and experiential interactions. As a Chinese-American, she bridges ideologies from Eastern and Western perspectives and practices which feeds into her most recent work on the nature on consciousness through wearable technologies.</p>\r\n<p>In 2013, she completed her BFA at University of California, San Diego majoring in Interdisciplinary Computing and the Arts and is completing an MFA in Media Design Practices from Art Center College of Design.</p>\r\n<p>Most recently she traveled to Myanmar as a summer researcher and UX designer at Proximity Designs, developing strategies for brand identity and joining a collaborative research team exploring Betel farmers and the potential for technological and smart systems in rural farming. This Fellowship was sponsored by Designmatters.</p>\r\n<p>Her work has been exhibited in San Diego, Los Angeles and Grinnell, Iowa.</p>', '', 'http://www.elainemcheung.com/', 'elainecheung4@gmail.com', '', '0', '1475445512', NULL, NULL),
(224, 'Myles Thompson', 'myles-thompson', 'http://codame.dreamhosters.com/uploaded_images/myles-thompson.jpg', '<p class=\"p1\"><span class=\"s1\">Myles Thompson is a versatile graphic designer and creative thinker from Brooklyn NY. Growing up in NYC, Myles was surrounded by a plethora of cultures and color which inspires his design work. He attributes skateboarding as one of his reason for becoming a designer. To Myles skateboarding and design share interesting parallels in terms of progression and possibility.&nbsp;&nbsp;</span></p>\r\n<p class=\"p1\"><span class=\"s1\">Myles writes: &ldquo;Everyday we as designers look to create visual syntax that creates an unspoken connection with our audience. In addition, we look to attribute something to a greater conversation with a purpose. Design has allowed me to think differently and change the way I communicate an important message to the audience.&rdquo;</span><span class=\"s2\">&nbsp;</span></p>\r\n<p>&nbsp;</p>', 'https://twitter.com/kilomyles', 'http://www.mylesthompsoncreative.com/', '', '', '0', '1477183812', NULL, NULL),
(225, 'Dat Phan', 'dat-phan', 'http://codame.dreamhosters.com/uploaded_images/dat-phan.jpg', '<p>Experimenter of art, design and technology. Physical world enthusiast.</p>\r\n<p>He keeps a pulse on the San Francisco ART+TECH culture events&nbsp;at <a href=\"http://supwithdat.com\" target=\"_blank\">supwithdat.com</a></p>', 'https://twitter.com/datphan', 'http://www.supwithdat.com/', 'digitalaudiotape@gmail.com', '', '0', '1476330448', NULL, NULL),
(231, 'Philippe Jestin', 'philippe-jestin', 'http://codame.dreamhosters.com/uploaded_images/philippe-jestin.jpg', '<p>In my work I often use drawings relating to the human figure, lines around the body, fabric structures applied to the body, my goal is to produce an object offering different lectures between the figurative and the abstract, going back and forth, unresolved and open to the potential of a fluid perception, go figure...&nbsp;&nbsp;The finished work has a sculptural dimension with a decisive edge much like in a bas-relief.\"</p>\r\n<p><iframe src=\"//www.youtube.com/embed/ebSTcmXINUs\" width=\"425\" height=\"350\"></iframe></p>\r\n<p>Over the years I produced works with wood, metal, paper, wire and charcoals. One material constant in my works is the resin which is applied with different casting techniques, often born out of experimentation and necessity to bring forth the initial idea.</p>\r\n<p>As a visual artist I am open to different series of work, keeping the creative process fluid with ideas and explorations, unattached to a partcular style, the challenge I seek is often in the nature of the craft.</p>\r\n<p><iframe src=\"//www.youtube.com/embed/KscupqckBlE\" width=\"425\" height=\"350\"></iframe></p>', '', 'http://www.philippejestin.com/', 'phijes@earthlink.net', '', '0', '1478876902', NULL, NULL),
(226, 'Jamie Kosoy', 'jamie-kosoy', 'http://codame.dreamhosters.com/uploaded_images/jamie-kosoy.jpg', '<p>Making weird + awesome stuff&nbsp;<a dir=\"ltr\" href=\"https://twitter.com/ArbitraryCo\" rel=\"nofollow\" data-mentioned-user-id=\"0\">@ArbitraryCo</a>. Sandwich purist. Coffee enthusiast. My favorite&nbsp;<a dir=\"ltr\" href=\"https://twitter.com/PlayMelodyJams\" rel=\"nofollow\" data-mentioned-user-id=\"0\">@PlayMelodyJams</a>&nbsp;monster is Mel.</p>', 'https://twitter.com/jkosoy', 'http://arbitrary.io/', '', '', '0', '1476329353', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(232, 'Mark Klink', 'mark-klink', 'http://codame.dreamhosters.com/uploaded_images/mark-klink.jpg', '<p>Mark Klink.. teacher; sometime artist and occasional programmer...&nbsp;Mark has been and done many things: Swept floors, worked in a factory, been an athlete, a minor government official, a life guard, a computer programmer, and a traditional print maker. For twenty years he taught children and other educators how to use computers. But the thing he likes best (besides family) is making curious pictures.&nbsp;Studied Art at UC Davis and Berkeley.</p>\r\n<p>---</p>\r\n<div>\r\n<h1 id=\"9b62\">Interview with Mark Klink</h1>\r\n<div>\r\n<div>\r\n<div>\r\n<div>A series of interviews of Artists and Speakers featured at the&nbsp;<a href=\"http://codame.com/events/art-tech-festival-2018\" target=\"_blank\" rel=\"noopener nofollow\">CODAME ART+TECH Festival</a>&nbsp;[2018] by&nbsp;Irene Malatesta on <a href=\"https://medium.com/codame-art-tech/interview-with-mark-klink-de407a014a2c\">Medium</a>:</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<figure style=\"text-align: center;\">\r\n<div>\r\n<div>\r\n<div>\r\n<div><img src=\"https://miro.medium.com/max/2800/0*W_nZG9GQY-DjMaPX.\" sizes=\"700px\" srcset=\"https://miro.medium.com/max/552/0*W_nZG9GQY-DjMaPX. 276w, https://miro.medium.com/max/1104/0*W_nZG9GQY-DjMaPX. 552w, https://miro.medium.com/max/1280/0*W_nZG9GQY-DjMaPX. 640w, https://miro.medium.com/max/1400/0*W_nZG9GQY-DjMaPX. 700w\" alt=\"Image for post\" width=\"1400\" height=\"1320\" /></div>\r\n</div>\r\n</div>\r\n</div>\r\n<figcaption data-selectable-paragraph=\"\">head 3.034 detail 1, by Mark Klink, 2017.</figcaption></figure>\r\n<p id=\"98b1\" data-selectable-paragraph=\"\">Visual artist&nbsp;<a href=\"https://medium.com/u/3c1c7c9759bb?source=post_page-----de407a014a2c----------------------\" target=\"_blank\" rel=\"noopener\">Mark A Klink</a>&nbsp;is interested in robots, artificial intelligence, and how we humans handle encounters with the unreal. From his early digital experiments to his current 3D work, he&rsquo;s focused on manipulating and stretching modern technologies, often subverting them to produce unexpected aesthetic results.</p>\r\n<p id=\"b4ca\" data-selectable-paragraph=\"\">Klink will be bringing some of his recent 3D work to the upcoming&nbsp;<a href=\"http://codame.com/events/art-tech-festival-2018\" target=\"_blank\" rel=\"noopener nofollow\">CODAME ART+TECH Festival</a>&nbsp;this June, making this a perfect time to catch up with him. I had the pleasure of engaging in a lengthy, enlightening email conversation with Klink over the past few weeks. In that time, we dug into his background as a multi-occupation self-taught technologist and longtime multimedia artist, as well as his reactions to the state of pop culture as it depicts and relates to robots and artificial intelligence, two enduring themes in his work.</p>\r\n<p id=\"30e4\" data-selectable-paragraph=\"\">This year&rsquo;s CODAME ART+TECH Festival, codenamed #ARTOBOTS, examines the increasingly tangible sphere of robotics, automation, and artificial intelligence in the modern world. Through 4 days of installations, workshops, and lectures, this conference will showcase developments from the vanguard of art and technology. In this conversation, Klink discusses a few of the questions and themes at the center of this year&rsquo;s conference, and of his own unique work.</p>\r\n<figure style=\"text-align: center;\">\r\n<div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"https://miro.medium.com/max/2800/0*rQaguQziMwSifWXV.\" sizes=\"700px\" srcset=\"https://miro.medium.com/max/552/0*rQaguQziMwSifWXV. 276w, https://miro.medium.com/max/1104/0*rQaguQziMwSifWXV. 552w, https://miro.medium.com/max/1280/0*rQaguQziMwSifWXV. 640w, https://miro.medium.com/max/1400/0*rQaguQziMwSifWXV. 700w\" alt=\"Image for post\" width=\"1400\" height=\"1120\" /></div>\r\n<figcaption data-selectable-paragraph=\"\">Heads, 6 variations, by Mark Klink. 2017</figcaption></figure>\r\n<p id=\"fc1c\" data-selectable-paragraph=\"\">IM: Hi Mark, thanks for chatting with me. We&rsquo;re really excited to have you involved with the CODAME festival. Briefly, can you start by introducing who are you and what do you do?</p>\r\n<p id=\"4e18\" data-selectable-paragraph=\"\">MK: I&rsquo;m a typical bearded, gray-haired geek. Happily married, with a wonderful, successful, adult daughter. I&rsquo;m fascinated by technology, art, philosophy, literature, movies, nature, people. I spend most of my free time experimenting with digital art.</p>\r\n<p id=\"df38\" data-selectable-paragraph=\"\">On your website, you describe yourself as a &ldquo;teacher; sometime artist and occasional programmer&rdquo; &mdash; how do these occupations work together? How do these different pursuits all inform each other?</p>\r\n<p id=\"f852\" data-selectable-paragraph=\"\">I actually retired from my &ldquo;day job&rdquo; as a teacher over a year ago! Those three occupations (teacher, artist and programmer) worked together very well. I&rsquo;ve always considered myself to be a visual artist. Early on, I was fortunate to exhibit my work in various gallery settings. Sometimes I would take a higher paying full time job, then, after I&rsquo;d saved enough, quit and focus exclusively on my art until the money ran out!</p>\r\n<p id=\"eccb\" data-selectable-paragraph=\"\">All that changed when my daughter was born. Originally, my plan was to stay home as a house dad, but continue to work on my art. But I discovered that I couldn&rsquo;t do justice to the two jobs. While some people are absolutely able to focus on a young child and work at the same time, I just couldn&rsquo;t personally do it, so for a while, I stopped making art. Eventually I began to pursue teaching as a way back into the workforce.</p>\r\n<p id=\"f400\" data-selectable-paragraph=\"\">Around this time, I discovered programming. Keep in mind this is during the early 1990s. Most people did not have a personal computer, and only a subset of those people would &ldquo;go online&rdquo; by connecting to AOL or Compuserve using a buzzing, crackling modem plugged into a telephone line. In order to complete my studies for my teaching credential I purchased my first computer, a Macintosh LC.</p>\r\n<p id=\"1f8e\" data-selectable-paragraph=\"\">A few years prior, I had encountered a computer for the first time while taking my daughter to a museum. At the side of the exhibit was some early Macintosh, and on it was running one of Rand and Robyn Miller&rsquo;s early Hypercard-based click and explore games. I was fascinated. Before this I had regarded computers as simply glorified calculators, but now I knew there was more to discover.</p>\r\n<p id=\"bc2b\" data-selectable-paragraph=\"\">So when I got my first Macintosh the first thing I did was to start exploring Hypercard. In short order I became something of an expert with the scripting language it used, Hypertalk. I started making my own Hypercard games, and I taught myself C in order to make code extensions to Hypercard (XCMDs and XFCNs). To my surprise, some of these proved to be very useful for others, and I started licensing them.</p>\r\n<p id=\"e971\" data-selectable-paragraph=\"\">Soon, I had several offers to work full time as a programmer. However, I knew that wasn&rsquo;t really for me. I really only wanted to use computers for fun, to be creative.</p>\r\n<p id=\"d581\" data-selectable-paragraph=\"\">So instead, I became a teacher. The great thing was that my school district was unusual in that they staffed their computer labs with fully credential specialist teachers. It was a perfect match for me. I did continue to keep a hand in programming, so I was creating scripts and utilities that saved a great deal of labor in managing the lab and with other tasks.</p>\r\n<p id=\"d3b2\" data-selectable-paragraph=\"\">As much as was practical, I incorporated art in my curriculum. I also continued to explore digital art, and that really took off when I discovered the open source 3D modeling and rendering application, Blender.</p>\r\n<p id=\"62a7\" data-selectable-paragraph=\"\">What was your early background like? Did you have formal training in fine art and technology, or did you learn another way?</p>\r\n<p id=\"c46e\" data-selectable-paragraph=\"\">I was born in Salt Lake City, Utah, but my family moved to Sacramento when I was 12 years old. I was very fortunate to attend a high school with exceptional arts education and some impressive connections. For example, before he moved to the Bay Area, pop artist&nbsp;<a href=\"http://www.artnet.com/artists/mel-ramos/\" target=\"_blank\" rel=\"noopener nofollow\">Mel Ramos</a>&nbsp;was the head of the high school art department where I attended school. The teacher with whom I had the most contact,&nbsp;<a href=\"http://kenwaterstreet.com/\" target=\"_blank\" rel=\"noopener nofollow\">Ken Waterstreet</a>, has work in several major museum collections. All this to say, I was really lucky and had some great examples and mentors early on.</p>\r\n<p id=\"13c9\" data-selectable-paragraph=\"\">In college, I majored in Art; first at UC Berkeley, then at UC Davis. There was an outstanding line up of teachers at Davis while I was there. Wayne Thiebaud, William T. Wiley, Roy De Forest were among my professors. I think the teacher who was the greatest influence, both in his approach to art and as a person, was ceramics artist&nbsp;<a href=\"https://www.sfmoma.org/artist/Robert_Arneson\" target=\"_blank\" rel=\"noopener nofollow\">Bob Arneson</a>. I was never a ceramicist, but Bob&rsquo;s playful, thoughtful attitude, his lack of pretense, his openness to his students, and his modesty all impressed me deeply.</p>\r\n<p id=\"9998\" data-selectable-paragraph=\"\">When it comes to technology, I&rsquo;m completely self-taught. In some ways, I feel fortunate about this, because I became involved in tech at a time when things were truly wide open. At the time I began learning, everything felt so new that there could be few &ldquo;experts.&rdquo; Anyone with sufficient curiosity and drive could dive into almost any area of tech and, if they performed, could be taken seriously. Certainly some of that continues today. But I suspect we are quite a ways past that raw frontier stage.</p>\r\n<p id=\"2a93\" data-selectable-paragraph=\"\">How did you begin making art and what influenced you, early on? Were there particular artists or projects that really inspired you?</p>\r\n<p id=\"50ea\" data-selectable-paragraph=\"\">I have always loved art and loved making art. Somewhere I have a copy of my kindergarten report card in which my teacher notes that little Mark takes great delight in making complex, detailed drawings.</p>\r\n<p id=\"fc63\" data-selectable-paragraph=\"\">I can&rsquo;t begin to list all the artists who have influenced me. I want to say the work of every artist I have ever encountered has had its impact. At this point, I feel as though they have all come together in some deep synthesis, so that I can&rsquo;t single out any one. Whatever comes out of that synthesis is now my own.</p>\r\n<p id=\"a38e\" data-selectable-paragraph=\"\">When it comes to digital art, specifically, I think the beauty of it is that it is so new. There are no &ldquo;Old Masters&rdquo; or &ldquo;Masters&rdquo; of any kind who dominate our sense of what is good and what is possible. We are truly free to make this whatever we want.</p>\r\n<figure style=\"text-align: center;\">\r\n<div>\r\n<div>&nbsp;</div>\r\n<img src=\"https://miro.medium.com/max/2800/0*73r9Z14BSkA2vIbH.\" sizes=\"700px\" srcset=\"https://miro.medium.com/max/552/0*73r9Z14BSkA2vIbH. 276w, https://miro.medium.com/max/1104/0*73r9Z14BSkA2vIbH. 552w, https://miro.medium.com/max/1280/0*73r9Z14BSkA2vIbH. 640w, https://miro.medium.com/max/1400/0*73r9Z14BSkA2vIbH. 700w\" alt=\"Image for post\" width=\"1400\" height=\"780\" /></div>\r\n<figcaption data-selectable-paragraph=\"\">Still image from the development of Fools Paradise II, an Immersive Environment by Paul Hertz, with Music by Stephen Dembskii, Masks by Mark Klink, and Calligraphy by Koy Suntichotinun. To be published and exhbited by DiMoDA,&nbsp;<a href=\"https://dimoda.art/\" target=\"_blank\" rel=\"noopener nofollow\">https://dimoda.art/</a>&nbsp;The work, Fools Paradise, is based on the Proverbs of Hell by William Blake, and was originally staged in 2004 as a VR performance with live musicians conducted by Stephen Dembski. See&nbsp;<a href=\"http://paulhertz.net/paradise/index.html\" target=\"_blank\" rel=\"noopener nofollow\">http://paulhertz.net/paradise/index.html</a>&nbsp;for more on the 2004 production and the intermedia collaboration Hertz and Dembski developed to create the world and the music.</figcaption></figure>\r\n<p id=\"2ad7\" data-selectable-paragraph=\"\">Let&rsquo;s talk about the work you are making now. Could you explain a bit about your current creative process? Why you&rsquo;re making them and what you most wish to communicate?</p>\r\n<p id=\"aa13\" data-selectable-paragraph=\"\">I&rsquo;m really interested in the ways 3D objects and scenes can be represented in a file format, and how that can be exploited to create novel effects. Over time, I&rsquo;ve become more interested in art works that are multi-layered &mdash; that work on many levels, aesthetic, ideational, emotional.</p>\r\n<p id=\"7ad1\" data-selectable-paragraph=\"\">I think people started paying attention to my work a few years back when I developed some methods to glitch 3D files.</p>\r\n<p id=\"d04f\" data-selectable-paragraph=\"\">&ldquo;Glitch&rdquo; art &mdash; referring to the use of digital errors or corrupted data for aesthetic expressive purposes &mdash; has been around for decades. For years, people have been fascinated by accidental glitches, particularly video glitches, that often popped up when early computer systems misbehaved.</p>\r\n<p id=\"8096\" data-selectable-paragraph=\"\">Eventually artists began looking for ways to induce those effects. Normally, you take a 2d image file and use an image editing program, Photoshop for example, to manipulate the image. Of course, all image and video files are just long lists of ones and zeros. You can manipulate that data directly rather than using a dedicated editor. Often people will open image files with text or hex editors, then use &ldquo;find and replace&rdquo; or &ldquo;copy and paste&rdquo; to change the content of the files. That might wreck the file, change it so that it no longer can be recognized as an image.</p>\r\n<p id=\"f736\" data-selectable-paragraph=\"\">But if you&rsquo;re lucky and knowledgeable, the result of the operation might be some strange and unexpected alteration of the image&hellip;weird, interesting deformations and color shifts. At this point, Glitch Art may have become something of a clich&eacute;. However there are still people deeply immersed in exploring the arcana of file formats and who continue to discover novel effects. There were quite a few prior examples of glitched 3D files, but the specific things I did and the tutorials I posted seemed to have influenced other artists.</p>\r\n<p id=\"2fab\" data-selectable-paragraph=\"\">The software that we use now to make digital art is so powerful. There are so many controls and options, the permutations and the effects that result are unlimited.&nbsp;It is ridiculously easy to make stunning eye candy, so easy, that our various feeds are overflowing with visual novelties. If you unlock your phone it just comes pouring out. And, just as quickly those images are forgotten, replaced by whatever comes next on your social media feed.</p>\r\n<p id=\"477e\" data-selectable-paragraph=\"\">It is far more difficult to make a work of art that requires some deeper consideration, that reveals something new each time you visit it. Making artwork like that is my goal.</p>\r\n<p id=\"0873\" data-selectable-paragraph=\"\">Can you talk a bit about the medium and tools you use to create your work? Is there a &ldquo;most important&rdquo; tool you use? If so what is it and why is it important?</p>\r\n<p id=\"555e\" data-selectable-paragraph=\"\">I use everything I can get my hands on! The most important piece of software, for me, is Blender. It is a complete open source modeler, renderer, video editor, compositor. It even has a built in game engine for interactive content.</p>\r\n<p id=\"d9ad\" data-selectable-paragraph=\"\">For artists interested in experimental 3D, I definitely recommend Blender. There are other proprietary tools that are industry standards when it comes to content production. If that is your goal, that is what you should use. However, I am an open-source advocate.</p>\r\n<p id=\"de7a\" data-selectable-paragraph=\"\">What about the work you will be bringing to the upcoming CODAME festival &mdash; what will we see?</p>\r\n<p id=\"1a01\" data-selectable-paragraph=\"\">I&rsquo;m working on a video. It will consist of heavily modified clips from classic (and not-so-classic) movies, tv shows, and documentaries having to do with robots. These will be interleaved with original 3D animations that I&rsquo;m creating, also involving robots. There will be an interplay between the themes, explicit and implicit, in the &ldquo;found&rdquo; video and the animations.</p>\r\n<figure style=\"text-align: center;\">\r\n<div>\r\n<div>&nbsp;</div>\r\n<img src=\"https://miro.medium.com/max/2800/0*mz1qh1gEUDzLxCqD.\" sizes=\"700px\" srcset=\"https://miro.medium.com/max/552/0*mz1qh1gEUDzLxCqD. 276w, https://miro.medium.com/max/1104/0*mz1qh1gEUDzLxCqD. 552w, https://miro.medium.com/max/1280/0*mz1qh1gEUDzLxCqD. 640w, https://miro.medium.com/max/1400/0*mz1qh1gEUDzLxCqD. 700w\" alt=\"Image for post\" width=\"1400\" height=\"787\" /></div>\r\n<figcaption data-selectable-paragraph=\"\">Still from a recent animation by Mark Klink</figcaption></figure>\r\n<p id=\"55de\" data-selectable-paragraph=\"\">You&rsquo;re very interested in robots, AI and the nature of consciousness/humanity in your work. Can you talk about this a little bit, as well as CODAME&rsquo;s #ARTOBOTS theme, what you find important about this theme, how you approach it?</p>\r\n<p id=\"659f\" data-selectable-paragraph=\"\">Despite what I said about wanting to make artworks that also work on an &ldquo;ideational&rdquo; level, I&rsquo;m reluctant to say too much. Nevertheless, I&rsquo;ll say a few things, which should be regarded as vague notions that might, somehow, emerge out of what I&rsquo;m making.</p>\r\n<p id=\"8429\" data-selectable-paragraph=\"\">I&rsquo;m very interested in our complex and changing attitudes towards &ldquo;artificial beings.&rdquo;&nbsp;When they&rsquo;re not presented as simple monsters, robots (usually humanoid robots) seem, often, to stand in for humans, whose oppression is taken for granted to the extent that they are regarded as some dehumanized other. In fictional situations like these, robots function as a prop within a parable about man&rsquo;s inhumanity towards man.</p>\r\n<p id=\"7e92\" data-selectable-paragraph=\"\">We tend to project onto robots the anxieties we have about our own nature and value.&nbsp;Humans have been undergoing a progressive demotion. At one time, we could confidently regard ourselves as the center of the universe, a special creation above and apart from everything else. But, from Copernicus to Darwin, belief in that special status has been continually undermined. The prospect of artificial intelligence draws the curve to its logical conclusion. A corollary to this line of thought is that we humans are, in fact, nothing more than mechanisms.</p>\r\n<p id=\"3266\" data-selectable-paragraph=\"\">How do you view recent pop culture dealing with this theme? (For example: Blade Runner, Ex Machina, etc.)</p>\r\n<p id=\"d1df\" data-selectable-paragraph=\"\">It&rsquo;s interesting how this has played out in popular culture. The originator of so much of this, of course, is Mary Shelley. Many people have drawn a parallel between the Frankenstein monster and Roy Batty in&nbsp;Blade Runner. Both are the product of a kind of hubris on the part of a creator/scientist. Both confront that &ldquo;creator,&rdquo; demanding that he fix what he has broken.</p>\r\n<p id=\"278d\" data-selectable-paragraph=\"\">In the Kubrick/Spielberg movie&nbsp;AI, we get another image of robots as exploited and reviled &ldquo;others.&rdquo; This is heightened by the pathos of the child robot, &ldquo;David,&rdquo; whose love is more intense and pure than that of which any human is capable. This film gives us another take on the issue of &ldquo;creator vs. created.&rdquo; The race of advanced robots that revive David at the end of the movie are fascinated by him precisely because his direct connection to their &ldquo;creators&rdquo; &mdash; the now extinct humans. It is clear, despite their advancement, they are as baffled and awed by the mystery of sentience and creation as we are.</p>\r\n<p id=\"14d6\" data-selectable-paragraph=\"\">There is another take worth mentioning. I see it , to a degree, in a movie like&nbsp;Ex_Machina. Here the artificial being, Ava, unlike the androids of Blade Runner, successfully escapes her keepers. However, her behavior is very different from Roy Batty, who, at the end, proves himself more humane than the humans who have been hunting him. As his last act, Roy chooses to save Deckard. In&nbsp;Ex_Machina, Ava ignores the screams of Caleb, the human she&rsquo;s been manipulating, and leaves him to die. Ava is not a monster, but while she can perfectly simulate the affect and appearance of a sympathetic human, there is something essentially alien about her. Apart from the desire to survive and to be unconstrained, her motivation is a mystery.</p>\r\n<p id=\"ba97\" data-selectable-paragraph=\"\">We see some of this in the robot David in the&nbsp;Prometheus/Alien Covenant&nbsp;movies, who would also destroy his creators. But the best examples of what I am getting at are in the Strugatsky novel&nbsp;Roadside Picnic&nbsp;(the inspiration for the movie&nbsp;Stalker) or some of the work of Stanislaw Lem, which deal, not with robots, but with profoundly alien intelligences and the impossibility of understanding or communicating with them.</p>\r\n<p id=\"5abc\" data-selectable-paragraph=\"\">We naturally anthropomorphize robots, but it seems very plausible that artificial intelligence could develop along lines that are incomprehensible to humans. That artificial intelligence might be, not necessarily hostile to humans, but, perhaps, utterly indifferent to us.</p>\r\n<p id=\"767f\" data-selectable-paragraph=\"\">Ex Machina&nbsp;is a really interesting film. I noticed that many people who watch it get angry with Ava &mdash; expecting her to have &ldquo;empathy&rdquo; as you put it. Yet, isn&rsquo;t the whole point of the film that she can&rsquo;t have empathy because she is a machine and not a human? Even when we know that we&rsquo;re dealing with a non-human, non-living thing, it&rsquo;s difficult to change our expectations from a humanoid face.</p>\r\n<p id=\"7fd8\" data-selectable-paragraph=\"\">Yes! We&rsquo;re &ldquo;programmed&rdquo; (an especially ironic &mdash; or apt! &mdash; term in this context!) to respond to faces. I&rsquo;m sure that the negative reaction to the closing of&nbsp;Ex Machina&nbsp;comes because all along we&rsquo;ve been set up (as much as Caleb) to see Ava as a sympathetic human female. We contrast her with Nathan, for whom &ldquo;others&rdquo; only exist as instruments, and it&rsquo;s a shock when she doesn&rsquo;t behave according to our expectations.</p>\r\n<p id=\"d41c\" data-selectable-paragraph=\"\">I haven&rsquo;t even mentioned all the stereotypes the movie plays with: Nathan as the manipulative/genius Silicon Valley CEO type who uses his robots as sex dolls, vs. Caleb as the earnest nerd. Ava might be a manifestation of the deep anxieties both those male stereotypes could harbor regarding women!</p>\r\n<p id=\"9f7f\" data-selectable-paragraph=\"\">Robots and AI do stir a lot of emotions and reactions! Do you think art can help people deal with the transition to a world where we have to interact with both robots and humans &mdash; that all look like humans? I wonder sometimes, how human beings will cope with this, emotionally speaking.</p>\r\n<p id=\"650f\" data-selectable-paragraph=\"\">I think art does help us adjust to new realities, for better or worse.&nbsp;As individuals, our nightly dreams supposedly help us to assimilate what we encounter during our waking life. I think of movies, and other forms of art, as a sort of collective dreamwork.</p>\r\n<p id=\"44ec\" data-selectable-paragraph=\"\">I don&rsquo;t subscribe to the romantic notion of artists as the unacknowledged legislators of the world or antennae of the race. I don&rsquo;t think artists have any special power or responsibility for leading people in the &ldquo;right&rdquo; direction. But, artworks can act as a catalyst through which the audience discovers or creates whatever meaning the world holds.</p>\r\n<p id=\"8282\" data-selectable-paragraph=\"\">We may be getting close to the point when AI directed language comprehension and speech become difficult to distinguish from that of a &ldquo;real&rdquo; human, at least for mundane interactions. When that happens, I believe it won&rsquo;t be especially jarring. At some level, we&rsquo;ll still regard those robotic agents as &ldquo;un-real&rdquo; in the same way that we understand that characters in movies aren&rsquo;t &ldquo;real.&rdquo;</p>\r\n<p id=\"687c\" data-selectable-paragraph=\"\">I suspect that something as convincing and perplexing as Ava is still in the far distant future. How we will react to that, or how we&nbsp;should&nbsp;react to that, I really don&rsquo;t know. I suppose we&rsquo;re just beginning to work on that problem now.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/srcxor', 'http://www.srcxor.org/', '', '', '0', '1625532962', 'https://codame.threadless.com/collections/mark-klink', ''),
(234, 'Norma Jeane', 'norma-jeane', 'http://codame.dreamhosters.com/uploaded_images/norma-jeane.jpg', '<p>AMERICAN, B. 1962, LOS ANGELES, CA</p>\r\n<div title=\"Page 3\">\r\n<p>Norma Jeane is the alias of an artist who does not wish to be identified.</p>\r\n<p>The biography reads as follows, &ldquo;born in Los Angeles in the early hours of the morning of 5 June 1962&rdquo;, which happens to be exactly when Marilyn Monroe died.</p>\r\n<p>However, in spite of having chosen the most photographed woman in history (the American actress who was christened Norma Jeane Baker), Norma Jeane (the artist) does the opposite &mdash; and opts for a total physical absence. In fact, Norma Jeane never appears in public. If the artist is staging an event, a version of Norma Jeane appears or usually someone who the artist has been collaborating with &mdash; from professional dancers to economics professors. Norma Jeane can be everyone and no-one. For each new project, Norma Jeane conceives and co-ordinates collaborative works, installations and performance art that is the antithesis of celebrity and glamour (that was integral to Monroe&rsquo;s image), and opts for work that has a strong social message.</p>\r\n<p>Norma Jeane\'s work has been featured in solo and group exhibiAons worldwide including, among others: MoMA, P.S.1 and Swiss InsAtute, New York; Palais de Tokyo, Paris; Helmhaus, Zurich; Frieze Project, London; Schirn Kunsthalle, Frankfurt; MarAn Gropius Bau, Berlin; Culture StaAon 284, Seoul; Galleria ConAnua, Beijing; Biennale de Lyon, Venice Biennale and Liverpool Biennial.&nbsp;</p>\r\n<p><strong>---</strong></p>\r\n<p><strong>You can learn more&nbsp;about Norma Jeane on this post on our ART+TECH Collection on Medium:</strong></p>\r\n<p>\"Exploring the Unseen\"<br /><a href=\"https://medium.com/codame-art-tech/exploring-the-unseen-42e1775e3b13\">Interview with&nbsp;Norma Jeane</a></p>\r\n<p id=\"b089\">When considering multimedia artist&nbsp;<a href=\"/artists/norma-jeane\" target=\"_blank\" rel=\"nofollow noopener nofollow noopener\" data-href=\"http://codame.com/artists/norma-jeane\">Norma Jeane</a>, the first impression that strikes is one of mystery and denial. Norma Jeane is the pseudonym of an Italian artist who does not wish to be identified. Where many discussions of an artist&rsquo;s body of work might begin with personal biography in an attempt to understand the human experience that led to creating the work, that won&rsquo;t do in the case of the elusive, cerebral, and multi-talented Norma Jeane....&nbsp;[read more&nbsp;<a href=\"https://medium.com/codame-art-tech/exploring-the-unseen-42e1775e3b13\">here</a>]</p>\r\n</div>', '', 'http://www.normajeane-contemporary.com/', 'norma62@gmail.com', '', '0', '1523519383', NULL, NULL),
(235, 'Jeremy Sachs', 'jeremy-sachs', 'http://codame.dreamhosters.com/uploaded_images/jeremy-sachs.png', '<p>Jeremy Sachs (aka REZMASON)<br /> <br /> Rezmason is a migratory ungulate native to the semantic plains between bedroom programmer and office clown. Subsisting off of deadpan humor, cosmic horror and incorrigible curiosity, Rezmason has occasionally produced small digital commodities intended to mezmerize, to pay homage to natural phenomena, or to creatively communicate a concept. Its natural predators vary seasonally between a fear of failure and work / life imbalance. Rezmason is also known to harbor a species of programming language known as the Haxe, which is fast, versatile, open source, cross-platform and sports powerful macro features. When approached, Rezmason will usually describe something excitedly. However, if mid-encounter Rezmason should unfold into an unresolvable sillhouette, pulsing with the non-light of impossible suns, it is already too late.<br /> <br /> Rezmason is in Oakland, California.</p>', 'https://twitter.com/rezmason', 'http://www.rezmason.net/blog/', 'jeremysachs@rezmason.net', '', '0', '1669602995', '', ''),
(236, 'Mica Sigourney', 'mica-sigourney', 'http://codame.dreamhosters.com/uploaded_images/mica-sigourney.jpg', '<p>Mica Sigourney is a performance artist, drag queen, curator, gogo dancer, instigator, emcee, and nightlife enthusiast. Utilizing 15 years of performance training Sigourney creates drag numbers, performance installations, gogo happenings, and theater pieces that ride the tension between artifice/construct and vulnerability/authenticity. Sigourney took part in the danceWEB scholarship in 2014 and has a degree in art from Antioch University. He founded OX in 2008, and has curated, &nbsp;produced works and collaborations with the organization since that time.</p>', '', 'http://www.micasigourney.com', '', '', '0', '1484527745', NULL, NULL),
(237, 'Ben Lerchin', 'ben-lerchin', 'http://codame.dreamhosters.com/uploaded_images/ben-lerchin.jpg', '<p>Ben Lerchin is a multidisciplinary artist &amp; software engineer who has spent nearly a decade building multimedia experiences with emerging technologies. His creations run the gamut from functional to imaginary, exploring the field of knowledge produced by human-machine collaboration.</p>\r\n<p>Born and raised in the Bay Area, Ben runs a freelance digital consultancy in Oakland, where he works on web apps, autonomous vehicles, and experimental imaging devices.</p>', '', 'http://benlerchin.com', '', '', '0', '1485065336', NULL, NULL),
(238, 'Eric Hanson', 'eric-hanson', 'http://codame.dreamhosters.com/uploaded_images/eric-hanson.jpg', '<p>\"Every act of creation is first an act of destruction.\"&nbsp;- Pablo Picasso</p>\r\n<p>This paradox drives designer Eric Hanson to explore the relationship between technology and living things. He appreciates learning about the societal impacts of technology, including topics such as automation of human labor, sustainability, and the balance between creating something new with the seemingly necessary destruction that our creations bring.&nbsp;</p>\r\n<p>He has explored these philosophical intersections professionally - designing literal human-machine interfaces such as seating and controls at machinery companies Crown Equipment and Caterpillar, and most recently software experiences at Salesforce and Uber. Eric holds both Industrial Design and Philosophy degrees from Purdue University and an M.B.A. from Valparaiso University.</p>\r\n<p><img src=\"/uploaded_images/Shybot-5.jpg\" alt=\"\" /></p>', '', 'http://www.erichansondesign.com/work', 'erichansondesign@gmail.com', '', '0', '1489213093', NULL, NULL),
(239, 'Xandra Ibarra', 'xandra-ibarra', 'http://codame.dreamhosters.com/uploaded_images/xandra-ibarra.png', '<p>Xandra Ibarra is an Oakland-based performance artist from the&nbsp;El Paso/Juarez border who performs and works under the alias of La Chica Boom.&nbsp;Ibarra&nbsp;uses hyperbolized modes of racialization&nbsp;and sexualization to test the boundaries between her own body&nbsp;and coloniality, compulsory whiteness, and Mexicanidad. Her practice integrates performance, sex acts, and burlesque with video, photography, and objects. Throughout her multiple works, she teeters between abjection and joy and problematizes the borders between proper and improper racial, gender, and queer subject.</p>\r\n<p>Ibarra&rsquo;s work has been featured at El Museo de Arte Contempora&ntilde;eo (Bogot&aacute;, Colombia), Broad Museum (LA, USA), Popa Gallery (Buenos Aires, Argentina), Joe&rsquo;s Pub (NYC), PPOW Gallery (NYC), and Yerba Buena Center for the Arts (SF) to name a few. &nbsp;Recent residencies include Fort Mason Center for Arts and Culture, National Performance Network, the Atlantic Center for the Arts, and CounterPulse. &nbsp;She has been&nbsp;awarded the Art Matters Grant, NALAC Fund for the Arts, Yerba Buena Center for the Arts Away Award, ReGen Artist Fund,&nbsp;Theater Bay Area Grant and the Franklin Furnace Performance and Variable Media Award.</p>\r\n<p>As a community organizer, Ibarra&rsquo;s work is located within immigrant, anti-rape and prison abolitionist movements. Since 2003, she has actively participated in organizing with INCITE!, a national feminist of color organization dedicated to creating interventions at the intersection of state and interpersonal violence. Ibarra is also a lecturer within the Critical Studies program at California College of the Arts.</p>\r\n<p style=\"text-align: center;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/6b9IDWaZl6izvUysvhLBAQAOw.gif\" alt=\"\" /><a href=\"http://www.xandraibarra.com/trainingforexhaustion/\">Training for Exhaustion</a></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/2Q.jpg\" alt=\"\" /><a href=\"http://www.xandraibarra.com/spic-ecdysis/\">Spic Ecdysis</a></p>\r\n<p>&nbsp;</p>', '', 'http://www.xandraibarra.com/', 'lachicaboom@gmail.com', '', '0', '1488503244', NULL, NULL),
(240, 'Hope Mohr ', 'hope-mohr', 'http://codame.dreamhosters.com/uploaded_images/hope-mohr.jpg', '<p>Hope Mohr is a curator, choreographer and writer. She trained at S.F. Ballet School, studied theater at Yale and earned her B.A.&nbsp;at Stanford, where she wrote her honors thesis on the women\'s movement in Nicaragua. After working as an Americorps Team Leader in South Central LA, Mohr moved to NYC to train on scholarship at the Merce Cunningham and Trisha Brown Studios. She performed in the companies of dance pioneers Lucinda Childs and Trisha Brown. Passionate about pursuing both community organizing and dance, Mohr earned a J.D. from Columbia Law School, where she was a Columbia Human Rights Fellow. In 2007, Mohr returned to San Francisco to establish Hope Mohr Dance to create, present and foster outstanding art at the intersection of critical thinking and the body. HMD\'s signature curatorial platform the Bridge Project approaches curating as community organizing to convene cultural conversations that cross discipline, geography, and perspective. Mohr has held residencies at Stanford Arts Institute, ODC Theater, Montalvo Arts Center, and the Interdisciplinary Laboratory for Art, Nature and Dance. She is a 2016 Fellow at Yerba Buena Center for the Arts.&nbsp;</p>\r\n<p><img src=\"/uploaded_images/HopeMohr_745.jpg\" alt=\"\" /></p>', '', 'http://www.hopemohr.org/artisticdirector/', '', '', '0', '1489729096', NULL, NULL),
(242, 'Will Eastcott', 'will-eastcott', 'http://codame.dreamhosters.com/uploaded_images/will-eastcott.jpg', '<p>Will Eastcott is the CEO of PlayCanvas, the leading platform for building WebGL content. Will is a veteran of the video game industry with credits in Call of Duty, DJ Hero, Max Payne and many more. Will is obsessed with driving the web forwards by making it more beautiful and ever more interactive.</p>', 'https://twitter.com/willeastcott', '', '', '', '0', '1491090645', NULL, NULL),
(243, 'Sheltron', 'sheltron', 'http://codame.dreamhosters.com/uploaded_images/sheltron.jpg', '<p>Sheltron is a graphics programmer from Austin currently located in San Francisco. His work uses real time graphics as an education and communication medium, believing that vast amounts of information can be transmitted through computer-generated imagery. Data, audio and natural phenomena can be visualized using 3D graphics in ways not possible until recent history. A graphics programmer by trade, he pushes the envelope using custom GPU programming and rendering systems, pushing maximum bandwidth data straight into your eyeballs. Sheltron can be found experimenting with mixed reality rendering at Occipital, VJing warehouses (and VR) with audio reactive shaders, or creating interactive data visuals for museums.</p>', 'https://twitter.com/sheltron3030', 'sheltron.co', 'nshelton@gmail.com', '', '0', '1491541556', NULL, NULL),
(244, 'Can Buyukberber', 'can-buyukberber', 'http://codame.dreamhosters.com/uploaded_images/can-buyukberber.jpg', '<p>Can Buyukberber is a visual artist working on immersive audiovisual experiences that&rsquo;s embodied both in physical and digital spaces. His practice consists of experiments with different mediums and display technologies, such as projection mapping, virtual reality, geodesic domes and digital fabrication methods. Driven by an interdisciplinary thinking which extends to art, design and science, Buyukberber&rsquo;s work often focuses on human perception, exploring new methods for non-linear narratives, geometrical order, synergetics and emergent forms. He has exhibited in international media art festivals, conferences and galleries in Europe, Canada and United States, including collaborations with Grammy-Award winning rock band Tool and Czech Philharmonic Orchestra. He is currently studying at San Francisco Art Institute\'s Art and Technology MFA program as a Fulbright Grantee and is a resident artist at Autodesk&rsquo;s Pier 9 AiR Program.</p>', '', 'http://canbuyukberber.com/', 'canbuyukberber@gmail.com', '', '0', '1491542373', NULL, NULL),
(247, 'Pol Clarissou', 'pol-clarissou', 'http://codame.dreamhosters.com/uploaded_images/pol-clarissou.png', '<p>Pol Clarissou &middot; developer and artist, likes to experiment with games as a medium, and play with the tools and processes of digital arts. Currently focusing on interactivity, procedural generation and finding visual aesthetic in unexpected places (text, gizmos, data visualisations etc.).</p>\r\n<p>Main tools: Unity (C#), Photoshop, 3Ds Max. Additional knowledge of Unreal Engine, Illustrator, After Effects, Flash, Zbrush, HTML, CSS &amp; Javascript, Processing.</p>', 'https://twitter.com/PolClarissou', 'http://polclarissou.com/', 'contact@polclarissou.com', '', '0', '1494746150', NULL, NULL),
(248, 'Izaak Meckler', 'izaak-meckler', 'http://codame.dreamhosters.com/uploaded_images/izaak-meckler.jpg', '<p>Izaak is a PhD student in&nbsp;<a href=\"https://math.berkeley.edu/~izaak/\" target=\"_blank\" data-saferedirecturl=\"https://www.google.com/url?hl=en&amp;q=https://math.berkeley.edu/~izaak/&amp;source=gmail&amp;ust=1496952221668000&amp;usg=AFQjCNGWWY4AcPa9nMiwrELRdjJNMpS2Eg\">math at UC Berkeley</a>, mostly studying theoretical computer science. He writes about complexity theory, geometry, and programming languages at&nbsp;<a href=\"https://parametricity.com/\" target=\"_blank\" data-saferedirecturl=\"https://www.google.com/url?hl=en&amp;q=https://parametricity.com/&amp;source=gmail&amp;ust=1496952221668000&amp;usg=AFQjCNEWUt8f42pZJ2IqwAnY-LA2ntmGXg\">parametricity.com</a>&nbsp;and makes comics and other art at&nbsp;<a href=\"https://newchickens.com/\" target=\"_blank\" data-saferedirecturl=\"https://www.google.com/url?hl=en&amp;q=https://newchickens.com/&amp;source=gmail&amp;ust=1496952221668000&amp;usg=AFQjCNHVSNCaAoI7C70ldAzxxONPAr8kxg\">newchickens.com</a>.</p>\r\n<div id=\"m_-8659083923115148539m_5253506588302978051bloop_sign_1494953711048787968\">&nbsp;</div>\r\n<div id=\"m_-8659083923115148539m_5253506588302978051bloop_sign_1494953711048787968\">He is currently interested in the limits of communication, \"negative\" emotions, and VR both as an artistic medium and as a tool for creatives and scientists. He also is interested in the dangers of emerging technologies as tools of increased manipulation (both intentional and unintentional).</div>\r\n<div id=\"m_-8659083923115148539m_5253506588302978051bloop_sign_1494953711048787968\">&nbsp;</div>\r\n<div id=\"m_-8659083923115148539m_5253506588302978051bloop_sign_1494953711048787968\">And he loves a good joke, so if you know any new ones please tell him.</div>', 'https://twitter.com/ihmeckler', 'http://newchickens.com/', 'izaak@berkeley.edu', '', '0', '1496865948', NULL, NULL),
(249, 'Mr. Doob', 'mr-doob', 'http://codame.dreamhosters.com/uploaded_images/mr-doob.png', '<p>Born&nbsp;Ricardo Cabello, mr.doob is often recognised as the creator of <a href=\"https://github.com/mrdoob/three.js\" target=\"_blank\">three.js</a>, a Javascript 3D library. A self proclaimed \"Award losing non creative junior developer\" with over&nbsp;2,112 contributions on github last year but little online presence, mr.doob is a myserious&nbsp;mastermind cooking up the special sauce powering the majority of browser based 3D experiences.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/mrdoob', 'http://mrdoob.com/', 'ricardo.cabello@gmail.com', '', '0', '1496969260', NULL, NULL),
(250, 'jonobr1', 'jonobr1', 'http://codame.dreamhosters.com/uploaded_images/jonobr1.jpg', '<p>Jono Brandel (b. May 22, 1986) relies on the combination of two fundamental disciplines:&nbsp;graphic design&nbsp;and&nbsp;computer programming. The results of this mixture vary in form but usually have a screen-based component. He explores procedural aesthetics.</p>\r\n<p>Jono studied&nbsp;Design | Media Arts&nbsp;with a minor in&nbsp;Latin&nbsp;at&nbsp;UCLA. He went on to receive artist grants at&nbsp;cheLA&nbsp;and&nbsp;Fabrica. He is now a member of&nbsp;Within. His work has been showcased at the&nbsp;Tate Modern,&nbsp;Siggraph,&nbsp;FITC, and the&nbsp;Japan Media Arts Festival&nbsp;as well as featured in publications like&nbsp;The New Yorker&nbsp;and&nbsp;Wired Magazine.</p>\r\n<p>He has also had the pleasure to create work alongside&nbsp;Kimbra,&nbsp;Plaid,&nbsp;the Arcade Fire, and many others accompanying their music with moving images.</p>', 'https://twitter.com/jonofyi', 'https://jono.fyi/', '', '', '0', '1648521456', '', ''),
(521, 'Marta Zubieta', 'marta-zubieta', 'http://codame.dreamhosters.com/uploaded_images/marta-zubieta.jpg', '<p><span style=\"font-family: Arial; font-size: 13px; white-space: pre-wrap;\">Specialized in illustration, graphic design and mural she inspires herself from the 90s cartoons, sci fi, pop surrealist art and latin folclore to create her adult illustrations for forever teenagers. Bringing vibrant colour to often bleak subjects, Zubieta explores the millennial culture and its issues through pink tinted glasses, neon colours and dreamy characters. </span></p>', 'https://twitter.com/oniricalZubieta', 'https://www.martazubieta.com/project/alice-in-lockdown', 'hello@martazubieta.com', '', '0', '1670530977', '', 'https://www.instagram.com/oniricalzubieta/'),
(522, 'Hiyo Glow', 'hiyo-glow', 'http://codame.dreamhosters.com/uploaded_images/hiyo-glow.jpg', '<p><span style=\"font-family: Arial; font-size: 13px; white-space: pre-wrap;\">Hiyo Glow is an experimental artist who creates colorful art through a variety of mediums like interactive coding, alcohol ink painting and long-exposure photography. She gets inspiration from her kitten and everything glowy.</span></p>', 'https://twitter.com/hotcoa', 'https://hiyoglow.com/', 'hotcoa@gmail.com', '', '0', '1650149756', 'https://codame.threadless.com/collections/hiyo-glow', 'https://www.instagram.com/hiyoglow/'),
(251, 'Kyttenjanae', 'kyttenjanae', 'http://codame.dreamhosters.com/uploaded_images/kyttenjanae.jpg', '<p>kyttenjanae is an artist and director based in los angeles, california.<br /><br />she creates experiences, short films, memes, live concert visuals, VR, and more.&nbsp;<br /><br />her work can be seen online, on television, and at some museums and sometimes on tour or at festivals.<br /><br />selected press:<br /><br /><a href=\"http://nesthq.com/installation-017-kyttenjanae\">NestHQ</a><br /><a href=\"https://killscreen.com/articles/deformed-lonely-bodies-kyttenjanaes-colorful-worlds/\" target=\"_blank\">KillScreen</a><br /><a href=\"http://thecreatorsproject.vice.com/article/gsearch?query=kyttenjanae\">CreatorsProject</a><br /><a href=\"https://zine.electricobjects.com/interviews/kytten-janae\" target=\"_blank\">ElectricObjects</a></p>\r\n<p>&nbsp;</p>', 'https://twitter.com/kyttenjanae', 'https://kyttenjanae.persona.co/', 'kytten@kyttenjanae.com', '', '1', '1496972235', NULL, NULL),
(252, 'Philip Rugo', 'philip-rugo', 'http://codame.dreamhosters.com/uploaded_images/philip-rugo.jpg', '<p>Philip Rugo is a media artist, animator, art director,&nbsp;and designer living in Los Angeles.&nbsp;</p>\r\n<p>2015 graduate of the UCLA Department of Design and Media Arts who has&nbsp;always been cautious about consuming and sharing information online.</p>\r\n<p>Inventor of Game Poems: small,&nbsp;focused experiences&nbsp;played like normal video games, each only a few minutes long.</p>', 'https://twitter.com/philiprugo', 'http://philiprugo.com/', 'thomrugo@gmail.com', '', '1', '1496973173', NULL, NULL),
(253, 'Juan Miguel de Joya', 'juan-miguel-de-joya', 'http://codame.dreamhosters.com/uploaded_images/juan-miguel-de-joya.jpg', '<p>VR Technical Director for DigitalFish and Google Spotlight Stories, software developer for machine learning and mixed reality at The Luke Hand Project, part of ACM SIGGRAPH in multiple leadership roles leading into 2019, and on the ACM Practitioner\'s Board Professional Development Committee. Though Juan\'s&nbsp;primary field of work has been in physics simulations and animation, he\'s currently engaged with VR/AR, machine learning, low-level graphics programming, and the human, social, and artistic impact of computing.<br /><br />Juan&nbsp;is heavily invested in understanding the human impact of computing technologies and practices through his work with the ACM, and continually aspire to learn more about both the technical and aesthetic applications of computer graphics and interactive techniques.</p>\r\n<p><a href=\"http://www.siggraph.org/discover/inspiration/member-profiles/juan-miguel-de-joya\" target=\"_blank\">SIGGRAPH member profile</a></p>', 'https://twitter.com/nojuanhere', 'https://www.linkedin.com/in/juandejoya/', 'juandejoya@gmail.com', '', '0', '1496981485', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(254, 'George Hurd', 'george-hurd', 'http://codame.dreamhosters.com/uploaded_images/george-hurd.jpg', '<p>George Hurd is a San Francisco-based composer whose work focuses&nbsp;on chamber music,&nbsp;electronic music, and the fascinating world where they intersect. He heads&nbsp;<a href=\"http://www.hurdensemble.com/\" target=\"_blank\">The Hurd Ensemble</a>, an electro-acoustic chamber group made up of some of the&nbsp;Bay Area&rsquo;s best musicians, dedicated to performing his compositions for chamber&nbsp;ensemble and electronics. His work often fixates on the role of memory in music, using electronic&nbsp;sounds that are made entirely by him, recorded from his life and on his travels, each&nbsp;encapsulating a memory from the place and time they were recorded.</p>\r\n<p>He writes extensively for dance, including&nbsp;a score for LEVYdance/Loni Landon Dance Projects called&nbsp;Meet Me Normal,&nbsp;and a solo electronics piece for Kinetech Arts called&nbsp;the murmur of yearning.&nbsp;In addition to his work with his ensemble, he has composed over a dozen electro-acoustic pieces, many acoustic chamber music pieces, and&nbsp;a sprawling catalog of works for solo electronics.</p>\r\n<p>His debut album with The Hurd Ensemble,&nbsp;Navigation Without Numbers, was released on&nbsp;<a href=\"http://www.innova.mu/albums/george-hurd/navigation-without-numbers\" target=\"_blank\">Innova Recordings</a>&nbsp;and&nbsp;includes a composition for violin&nbsp;and electronics written for the&nbsp;brilliant&nbsp;violinist/composer&nbsp;<a href=\"http://www.carlakihlstedt.com/\" target=\"_blank\">Carla Kihlstedt</a>. He has written numerous film scores including the feature-length doc&nbsp;Freeing Bernie Baran, and is currently co-composing film scores with composer&nbsp;<a href=\"http://www.markortonmusic.com/\" target=\"_blank\">Mark Orton.</a>&nbsp;He recently began&nbsp;an all-electronic duo with fellow composer Joel St. Julien called&nbsp;<a href=\"http://www.nightmarelight.bandcamp.com/\" target=\"_blank\">Nightmare Light</a>&nbsp;that just released its debut EP.</p>', 'https://twitter.com/georgehurd', 'http://www.georgehurd.com/', 'george@georgehurd.com', '', '0', '1497975184', NULL, NULL),
(259, 'Travis Bennett', 'travis-bennett', 'http://codame.dreamhosters.com/uploaded_images/travis-bennett.png', '<p>&nbsp;</p>\r\n<p>Travis Bennett is an interactive technology artist who&rsquo;s work explores the complex nature of society&rsquo;s relationship with emerging technologies such as AI, VR, Computer Vision, Real-Time Motion Capture, Brain Computer Interfaces, and 3d Imaging.</p>\r\n<p>He is the co-founder and Creative Director of Kineviz (a data design firm specializing in building cutting edge visualization systems in Virtual Reality) and is also an advisor and \"Chief Troublemaker\" at Kinetech Arts, where he harnesses his crazy ideas to build art and technology for live interactive installations and performances.</p>', '', 'kineviz.com', '', '', '0', '1498002353', NULL, NULL),
(255, 'Delia Otetea', 'delia-otetea', 'http://codame.dreamhosters.com/uploaded_images/plus-360-degrees.jpg', '<p>Delia Otetea is a&nbsp;3D and graphical artist. She was born and raised in Romania, and now&nbsp;lives in Germany. Delia&nbsp;did a Master\'s Degree in Digital Media where she first teamed up with Ivan in doing 3D interactive applications.&nbsp;</p>\r\n<p><a href=\"https://thefwa.com/interviews/ivan-moreno-and-delia-otetea\" target=\"_blank\">FWA Interview</a></p>', 'https://twitter.com/plus360degrees/', 'https://www.linkedin.com/in/deliaotetea/', 'ivan@plus360degrees.com', '', '0', '1496985936', NULL, NULL),
(258, 'Ivan Moreno', 'ivan-moreno', 'http://codame.dreamhosters.com/uploaded_images/ivan-moreno.jpg', '<p>Ivan Moreno is an artist and programmer from Colombia living in Germany, who is currently interested in Computer Graphics, Quantum Computing, Quantum Physics at the intersection of science and art. His work has been focused on photorealistic realtime rendering and parallel computing, to reach the next generation of imaginary composition. He is the co-founder of Plus 360 Degrees.</p>', 'https://twitter.com/ivanmoreno_xyz', 'http://www.plus360degrees.com/', 'ivan@plus360degrees.com', '', '0', '1607737683', '', NULL),
(454, 'Hufo', 'hufo', 'http://codame.dreamhosters.com/uploaded_images/hufo.png', '<p dir=\"ltr\">Hufo enjoys coding in C/C++ for fun!</p>\r\n<p dir=\"ltr\">Unity, Minecraft and Visual Studio are his playgrounds.</p>\r\n<p dir=\"ltr\">His curiosity and experiments allow him to learn more every day.</p>\r\n<p dir=\"ltr\">He also enjoys memes and anime.</p>', 'https://twitter.com/hufo_me', 'http://hufo.me', 'codame@hufo.me', '', '0', '1627848612', '', 'https://www.instagram.com/hufo.me/'),
(256, 'Anastasiia Vedernikova', 'anastasiia-vedernikova', 'http://codame.dreamhosters.com/uploaded_images/anastasiia-vedernikova.jpg', '<p>Anastasiia Vedernikova is passionate about design when she isn\'t on the dance floor.&nbsp;She&nbsp;specializes in design thinking, problem solutions, sketching, modeling, branding, typography, and illustration.&nbsp;Anastasiia&nbsp;has&nbsp;lived in Russia, Germany and the United States which helped her&nbsp;gain international experience that she uses in her projects. She loves to experiment with innovative new art directions that have not been explored much before.&nbsp;</p>\r\n<p>&nbsp;</p>', 'http://twitter.com/vedernikova', 'https://www.anastasiiadesign.com/', 'vnastasia@gmail.com', '', '0', '1498781802', NULL, NULL),
(257, 'Joe Pea', 'joe-pea', 'http://codame.dreamhosters.com/uploaded_images/joe-pea.jpg', '<p>Joe Pea is a skateboarder who is in love with 3D programming. He is passionate about the intersection of art and technology and loves applying the randomness of nature to his creations. If Joe is not busy coding in Javascript he can show you a couple of skateboard tricks!</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/trusktr', 'https://trusktr.io/', 'trusktr@gmail.com', '', '0', '1497311799', NULL, NULL),
(260, 'Natalie Sun', 'natalie-sun', 'http://codame.dreamhosters.com/uploaded_images/natalie-sun.jpg', '<p><a href=\"http://nextart.tech/\" target=\"_blank\">Next Art</a> founder Natalie Sun is a creative technologist and art tech curator/producer. An artist herself, she was a previous recipient of the Eyeo Festival Artist Fellowship and studied Contemporary Curation with Goldsmiths, University of London at The British School in Rome.</p>\r\n<p>Previously, as a creative technologist in the ad industry, she worked with clients like Google and Target as a technical creative to integrate artful uses of technology in interactive campaigns. During this time, she realized the creative industry&rsquo;s lack of exposure to truly interesting, cutting-edge creativity in tech.</p>\r\n<p>As a result, she began curating and producing shows to inspire the creative community with the artistic possibilities of technology. Next Art was born out of her passion for integrating art with technology and supporting the artists working in the new digital space.</p>', 'https://twitter.com/onattyso', 'http://onattyso.com/', '', '', '0', '1498502079', NULL, NULL),
(261, 'LiL PDF', 'lil-pdf', 'http://codame.dreamhosters.com/uploaded_images/lil-pdf.jpg', '<p style=\"text-align: left;\">LiL PDF\'s work exists at the confluence of art and science. From 3d printing torus knots into wearable fashion pieces to creating enthralling and bizarre digital landscapes and animations for the underground.</p>\r\n<p><a href=\"http://3glitch.com/\" target=\"_blank\">LiL PDF</a> is Michael Baur, a Digital Mason from California.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/uploaded_images/lil-pdf-clean.jpg\" alt=\"\" /></p>', '', 'http://3glitch.com', '', '', '0', '1527041986', NULL, NULL),
(262, 'Shiya Luo', 'shiya-luo', 'http://codame.dreamhosters.com/uploaded_images/shiya-luo.jpg', '<p>Shiya Luo is a software engineer&nbsp;@ Autodesk by day and artist telepresence pioneer by night. For three consecutive years she has collaborated with artists to bring their works to life on stage at #3dWebFest. In the past Shiya has worked as a developer evangelist and in the present she spends free time playing videogames and posting food pics.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/ShiyaLuo', 'http://www.shiyaluo.com/', 'shiya.luo@autodesk.com ', '', '0', '1498776148', NULL, NULL),
(263, 'Kawandeep Virdee', 'kawandeep-virdee', 'http://codame.dreamhosters.com/uploaded_images/kawandeep-virdee.jpg', '<p>Kawandeep Virdee uses technology and art to explore ways we can create meaning and joy collectively. He co-founded New American Public Art to build interactive art that makes public spaces more communal and welcoming. Similarly, his internet art strives to encourage collaboration, play, and creativity. His works have shown in venues including the Massachusetts College of Art and Design, Facebook, Rose Fitzgerald Kennedy Greenway, Boston Convention Center, Sculpture Visions in Chapel Hill, SFMOMA, Detroit Design Festival, Art &amp; Sol in Saginaw, Suffolk University, Transmediale in Berlin, the MIT Media Lab, and EYEO/Northern Spark. Talks and workshops include MIT, Google Creative Lab, Facebook, Society of News Design, EYEO, FITC, INST-INT, International Conference on Complex Systems, Connected Communities Symposium in Newcastle, Art Institute of Boston, Tech@State, Betascape at MICA, A Better World By Design at Brown/RISD, Robotsconf, IstanbulHS, Makerland in Warsaw, and JSConf. His works have been covered in publications including the Atlantic, Science, Vice, NewScientist, Make, Core77, the New York Times, the Globe, and Art Digital Magazine.</p>', 'https://twitter.com/whichlight', 'http://whichlight.com/', 'Whichlight@gmail.com ', '', '0', '1499475426', NULL, NULL),
(264, 'Clement Goldberg', 'clement-goldberg', 'http://codame.dreamhosters.com/uploaded_images/clement-goldberg.jpg', '<p>Clement Hil Goldberg is a multidisciplinary artist primarily working in film, sculpture and stop motion animation to create a fabulous extinction aesthetic. Their visual art and live performance project <a href=\"http://www.counterpulse.org/our-future-ends-_-in-residence/\" target=\"_blank\">Our Future Ends</a> will premiere at CounterPulse in October 2017.&nbsp;</p>', '', 'clementhilgoldberg.com', 'clementhilgoldberg@gmail.com', '', '0', '1499820263', NULL, NULL),
(265, 'Evan Johnson', 'evan-johnson', 'http://codame.dreamhosters.com/uploaded_images/evan-johnson.jpg', '<p>EVAN JOHNSON is a theatre artist living in San Francisco. He has collaborated locally with Hope Mohr (<em>Ride the Rhythm</em>), Jesse Hewitt (<em>FREEDOM</em>), Liz Tenuto (<em>The Two Legits</em>) and Xandra Ibarra/La Chica BOOM (<em>FML</em>) on performance works. He&rsquo;s the writer/performer of two solo plays, <em>Pansy</em> and <em>Don&rsquo;t Feel: The Death of Dahmer</em>.</p>\r\n<p>&nbsp;</p>\r\n<p>Photo credit: Robbie Sweeny&nbsp;</p>', '@EvanLJohnson', '1111artgroup.com', 'lotsofevan@gmail.com', '', '0', '1499894194', NULL, NULL),
(266, 'RANDY REYES', 'randy-reyes', 'http://codame.dreamhosters.com/uploaded_images/randy-reyes.jpg', '<p>Randy is a queer Latinx choreographer-dance artist-curanderx with roots connecting the geographies of Guatemala, Massachusetts, NYC, Germany, Chile, Ecuador, &amp; Nicaragua. During their time in NYC, Randy worked closely with choreographer/master teacher, Daria Fa&iuml;n, studying Chinese Energetics &amp; Systems of Improvisation as an ensemble member of her collective The Commons Choir, co-facilitated with Robert Kocik. In NYC, Randy developed the ritual-accion Never Arriving as a selected emerging choreographer for the Work Up 2.0 series at Gibney Dance Center, was a cohort member in the Hemispheric Institute for Performance &amp; Politics EMERGENYC program, and interned with Movement Research, all between Aug. 2015 - July 2016. Currently, Randy will be excavating a new piece this summer as part of the Performing Diaspora ARC program at CounterPulse and will relocate to Los Angeles to begin an MFA in Dance program at UCLA this fall with the intention to continue weaving together the places-mentors-magick that has inspired them.</p>', '', '', 'randy.reyes05@gmail.com', '', '0', '1499892651', NULL, NULL),
(267, 'Javier Fresquez', 'javier-fresquez', 'http://codame.dreamhosters.com/uploaded_images/javier-fresquez.jpg', '<p>Since his first Mexican folkloric dance class at age 5, dance has always been a major part of Javier&rsquo;s education and mental/emotional/spiritual growth. Across his life, he has garnered experience in multiple genres, including Flamenco, ballet, contemporary, social partner dance (salsa, cumbia, swing, blues), vogue, and danza azteca. &nbsp;His a part of The House of Prolific, a San Francisco vogue house led by several of the SF Bay Area&rsquo;s most seasoned and ovah Vogue performers, including, Soul Nubian (father) and Jocquese Whitfield (prince).&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>Javier will present &ldquo;<a href=\"https://www.facebook.com/MotherTheVerb/\" target=\"_blank\">Mother the Verb</a>&rdquo; at Counterpulse this December, as a Performing Diaspora Aritist-in-Residence.</p>', '', '', 'javier.fresquez@gmail.com', '', '0', '1499973037', NULL, NULL),
(268, 'Maryam Farnaz Rostami', 'maryam-farnaz-rostami', 'http://codame.dreamhosters.com/uploaded_images/maryam-farnaz-rostami.jpg', '<p>Maryam Farnaz Rostami has made performance-based work in San Francisco for the last 8 years, both solo and ensemble. She is a co-founder of Nicole Kidman is Fucking Gorgeous and founder of MFR Productions. Her latest one-woman show, Late Stage San Francisco, played at the ACT Costume Shop in August 2015. In addition to writing and creating movement, she works in the world of architecture as a designer, and has been a maker for as long as she can remember.</p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"/uploaded_images/MFR-by-Robbie-Sweeney-2-low.jpg\" alt=\"\" /></p>\r\n<p>Photos by Robbie Sweeney</p>\r\n<p><img src=\"/uploaded_images/MFR-by-robbie-sweeney-low.jpg\" alt=\"\" /></p>\r\n<p>Profile photo by Mark&nbsp;Mcbeth</p>', '@maryamopolis', 'maryamrostami.com', 'maryamopolis@gmail.com', '', '0', '1499979353', NULL, NULL),
(269, 'Raegan Truax', 'raegan-truax', 'http://codame.dreamhosters.com/uploaded_images/raegan-leann-truax.jpg', '<p style=\"text-align: center;\"><em>Photo Credit: Jeremiah Barber</em></p>\r\n<p>An artist and scholar, Raegan Truax&rsquo;s durational performances have been included within The Marina Abramovic Institute&rsquo;s Immaterial archive and presented at Zentrum fuÌˆr Kunst und Urbanistik (ZKU) in Berlin, SOMarts in San Francisco, gruÌˆntaler9 in Berlin, Berlin Art Week, and Performance Studies International. She has additionally performed at Centro Negra with AADK in Blanca Spain, Dance Theatre Workshop in New York City, the Performance Arts Institute in San Francisco, and The New Museum in New York City. &nbsp;Her most recent work, Sloughing, occurred across 19 different locations in the Bay Area over 28-days. &nbsp; In September 2017, Truax will partner with CounterPulse to mount a 37-hour durational performance titled Citation.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/RaeTruax', 'http://www.raegantruax.com/', 'rtruax@stanford.edu', '', '0', '1500335621', NULL, NULL),
(270, 'Allen Larson ', 'allen-larson', 'http://codame.dreamhosters.com/uploaded_images/allen-larson.jpg', '<p>Allen has been making digital art since 2006. Starting with a fascination for printmaking he deeply explored the world of screen printing and laser engraving as a vector artist. In 2015 he purchased a Wacom tablet to bridge the gap between his love of digital art and the connection of holding the brush or tool in hand to create. He has since focused on CNC fabrication using the digital painting process to create his designs. Allen still screen prints T-shirts live at Bay Area events under #RemixedInk. He currently spends his artistic time learning to animate and render in 3D and is involved in a not-for-profit group intending&nbsp;to deliver mobile maker spaces to disaster and poverty zones. IG <a href=\"https://www.instagram.com/allentic/\">@allentic</a></p>', '', '', 'saflaser@gmail.com', '', '0', '1501276566', NULL, NULL),
(271, 'Zizhou Chen', 'zizhou-chen', 'http://codame.dreamhosters.com/uploaded_images/zizhou-chen.jpg', '<p>Illustrator/ graphic artist/ cover deisgn/ inforgraphic illustration</p>\r\n<p>Intersted in music, film, and every retro or old school elements.</p>', '', 'www.bigchem7316.com', 'czz7316@gmail.com', '', '0', '1501362786', NULL, NULL),
(272, 'Felix Woitzel', 'felix-woitzel', 'http://codame.dreamhosters.com/uploaded_images/felix-woitzel.jpg', '<p>Felix Woitzel learned programming with Logo turtle graphics as soon as he became a teenager. In the late 90s he got introduced to HTML and he jumped directly to Javascript which he taught himself in Internet Explorer 4. Dynamic HTML just became possible and he got obsessed with programming interactive effects not later than the year 2000. While his classmates learned to edit Flash movies, he experimented with 3D animations in the browser with SVG and DOM manipulations. Later he turned to animating live music visualizations, hardware-accelerated animations and real-time simulations on the Gpu. In 2010 Felix graduated from University Rostock in Computer Science, majoring in object-oriented systems and software architecture. For three years he has been employed at the imaging science department of the biomedical software company arivis where he works as a full-time software engineer.&nbsp;</p>\r\n<p>&nbsp;</p>', 'http://twitter.com/flexi23', '', '', '', '0', '1502816058', NULL, NULL),
(275, 'Lauren Bedal', 'lauren-bedal', 'http://codame.dreamhosters.com/uploaded_images/lauren-bedal.png', '<p>&nbsp;</p>\r\n<p>Lauren Bedal is a designer, dancer, and filmmaker based in San Francisco, California. Lauren currently works at Matter, a design and innovation firm focused on the intersection of industrial, digital, and service design. Outside of Matter, Lauren is currently working on Open Kinect, an open source platform for generating real-time, virtual dance performance with motion capture technology as well as other motion capture VR films. She believes her multi-disciplinary background gives her a unique understanding of story, experience, and people.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '', '', '', '', '0', '1507839789', NULL, NULL),
(276, 'Amy Warehouse', 'amy-warehouse', 'http://codame.dreamhosters.com/uploaded_images/amy-warehoue.jpg', '<p>Fidget spinner haircuts targeted for CEO\'s and executives of fortune 500 companies. Scumbags, cum rags, hard drugs and loaded weapons. Criminals that dress cool, turn the tables by asking you the truth. This one goes out to lunch with lunch meat. Open a bible and man up. I\'m not just in the barn I\'m one of the animals.</p>', '', 'http://www.bbpwc.com/', 'albertelmore@gmail.com', '', '0', '1508008769', NULL, NULL),
(279, 'Cindy Clark', 'cindy-clark', 'http://codame.dreamhosters.com/uploaded_images/cindy-clark.jpeg', '<p>Cindy is a Product Designer based in San Francisco, I bring a successful background in fine jewelry and a passion for exploring how technology can enhance and transform the industry. My fascination with the intersection of jewelry and technology led me to study UX Design at San Francisco State University. With technology, the world becomes your canvas, and you can create experiences ranging from subtle to immersive, which captivated me.</p>\r\n<p>Combining my love of jewelry with technology, I have developed a deep understanding of the opportunities and challenges of designing for wearables. Although wearable tech is a niche market, I see tremendous potential for growth and am excited about its possibilities.</p>\r\n<p>Throughout my career, I have worked on innovative projects that blend technology with the traditional world of fine jewelry. I help presented CAD technology to the American jewelry industry, revolutionizing how jewelry is designed and produced at the Fashion Institute of Technology in NYC. Recently, I introduced augmented reality (AR) virtual try-on technology to a jewelry company, combining my expertise in jewelry with my passion in technology.</p>\r\n<p>Let\'s bring your vision to life through interactive experiences and engaging storytelling. Together, we can create something innovative and impactful, regardless of whether it fits neatly into a predefined box. Beauty and functionality can come together in the digital world.</p>', 'https://twitter.com/conceptcindy', 'http://www.conceptcindy.com/', 'cindy@codame.com', '', '0', '1684257987', '', ''),
(281, 'Alex Reben', 'alex-reben', 'http://codame.dreamhosters.com/uploaded_images/alex-reben.jpg', '<p>Alexander Reben is an artist and roboticist, who explores humanity through the lens of art and technology. His work deals with human-machine relationships, synthetic psychology, artificial philosophy, and robot ethics, among other topics. Using &ldquo;art as experiment,&rdquo; his work allows for the viewer to experience the future within metaphorical contexts. Reben&rsquo;s artwork and research have been shown and published internationally, and he consults with major companies, guiding innovation for the social machine future. He has exhibited at venues including The Vitra Design Museum, The Vienna Biennale, ARS Electronica, VOLTA, The Whitney Biennial, TFI Interactive, IDFA, ArtBots, The Tribeca Film Festival, The Camden Film Festival, Doc/Fest, and The Boston Cyberarts Gallery. His work has been covered by&nbsp;NPR, The Wall Street Journal, The New York Times, Washington Post, Fast Company, Filmmaker Magazine, New Scientist, BBC, PBS, Discovery Channel, Cool Hunting&nbsp;and&nbsp;WIRED,&nbsp;among others. He has lectured at TED, SXSW, TTI Vanguard, Google, UC Berkeley, SMFA, CCA, MIT, and other universities. Reben has built robots for NASA, and is a graduate of the MIT Media Lab, where he studied human-robot symbiosis and art. He was a 2016-2017 WIRED innovation fellow, and is the Director of Research and Technology at Stochastic Labs Resident.</p>\r\n<p><iframe src=\"https://www.youtube.com/embed/8Lw-j5ybZak\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe> <iframe src=\"https://player.vimeo.com/video/99558592\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', 'https://twitter.com/artboffin', 'http://areben.com/', '', '', '0', '1524433957', NULL, NULL),
(282, 'Piero Scaruffi', 'piero-scaruffi', 'http://codame.dreamhosters.com/uploaded_images/piero-scaruffi.jpg', '<p>Piero Scaruffi&nbsp;is a cultural historian who has lectured in three continents and published several books on Artificial Intelligence and Cognitive Science, the latest one being \"The Nature of Consciousness\" (2006). He pioneered Internet applications in the early 1980s and the use of the World-Wide Web for cultural purposes in the mid 1990s. His poetry has been awarded several national prizes in Italy and the USA. His latest book of poems and meditations is \"Synthesis\"(2009). As a music historian, he has published ten books, the latest ones being \"A History of Rock and Dance Music\" (2009) and \"A History of Jazz Music\" (2007). His latest book of history is \"A History of Silicon Valley\" (2011). The first volume of his free ebook \"A Visual History of the Visual Arts\" appeared in 2012. His latest book is \"Intelligence is not Artificial\" (2013). He has also written extensively about cinema and literature. He founded the Leonardo Art Science Evening Rendezvous (LASER) in 2008 and the Life Art Science Tech (LAST) festival in 2014. Since 2015 he has been commuting between California and China, where several of his books have been translated.</p>', 'https://twitter.com/pscaruffi', 'https://www.scaruffi.com/', '', '', '0', '1598721523', '', NULL),
(283, 'Meredith Tromble', 'meredith-tromble', 'http://codame.dreamhosters.com/uploaded_images/meredith-tromble.jpg', '<p>&nbsp;</p>\r\n<p>Meredith Tromble is an artist and writer who has worked in \"in-between\" spaces throughout her career: mixing drawing, performance, and installation; writing about her own creative process and the work of others; and engaging crossover points between art and science. She has been artist-in-residence at the Complexity Sciences Center at the University of California, Davis&nbsp; (UCD), since 2011. Her ongoing collaboration with UCD geobiologist Dawn Sumner, the interactive 3-D art installation \"Dream Vortex,\" has been presented internationally at ISEA2015, Vancouver and Creativity &amp; Cognition, Glasgow School of Art, 2015, and nationally at more than a dozen public lectures at American universities ranging from Stanford University in Palo Alto to Brown University in Providence. A related dance performance &ldquo;The Vortex,\" a collaboration with choreographer Donna Sternberg, will debut at The Odyssey in Los Angeles April 20-21, 2018. Tromble is also the co-editor, with Charissa Terranova, of \"The Routledge Companion to Biology in Art &amp; Architecture; editor of &ldquo;The Art and Films of Lynn Hershman Leeson,&rdquo; from University of California Press; and author of hundreds of short form writings on art including a paper for the Artnodes Journal special issue on Art &amp; Research, Winter, 2018.</p>', '', 'http://meredithtromble.net/', 'meredith@meredithtromble.net', '', '0', '1518219446', NULL, NULL),
(284, 'Amy LaViers', 'amy-laviers', 'http://codame.dreamhosters.com/uploaded_images/amy-laviers-minnick.jpg', '<p>Amy LaViers is an assistant professor in the Mechanical Science and Engineering Department at the University of Illinois at Urbana-Champaign and director of the Robotics, Automation, and Dance (RAD) Lab where she develops robotic algorithms inspired by movement and dance theory. She is the recipient of a 2015 DARPA Young Faculty Award (YFA).&nbsp; She has worked in the area of advanced manufacturing, through an industry-university consortium, the Commonwealth Center for Advanced Manufacturing (CCAM), defense, and healthcare, and forged interdisciplinary ties with the UVA and UIUC Dance Programs and the Laban/Bartenieff Institute for Movement Studies, where she completed a Certification in Movement Analysis (CMA) in 2016. Prior to UIUC she held a position as an assistant professor for two years in systems and information engineering at the University of Virginia.&nbsp; She completed her Ph.D. in electrical and computer engineering at Georgia Tech where she was the recipient of the ECE Graduate Teaching Excellence Award and a finalist for the CETL/BP Outstanding Graduate Teaching Award.&nbsp; Her dissertation included a live performance exploring the concepts of style she developed there.&nbsp; Her research began at Princeton University where she earned a certificate in dance and a degree in mechanical and aerospace engineering.&nbsp; Her senior thesis, which quantitatively compared two styles of dance, earned top honors in the MAE department, the School of Engineering and Applied Science, and the Lewis Center for the Arts.</p>', 'https://twitter.com/@alaviers', 'http://www.amylaviers.com/', '', '', '0', '1518219323', NULL, NULL),
(285, 'Andra Keay', 'andra-keay', 'http://codame.dreamhosters.com/uploaded_images/andar-keay.jpg', '<p>Andra Keay is a human systems engineer, Founder of Robot Launchpad, Managing Director of Silicon Valley Robotics and CoFounder of Robot Garden, a new robotics hackerspace. Andra is also Treasurer of the Robots Association and contributor to Robohub, the global site for news and views on robotics.</p>\r\n<p>Andra graduated as an ABC film, television and radio technician in 1986 and obtained a BA in Communication from the University of Technology, Sydney (UTS) Australia, in 1998, where she taught interaction design from 2009 to 2010, and interaction theory in 2016 at CCA in San Francisco. She obtained her MA in Human-Robot Culture/Cultural Theory at the University of Sydney, Australia in 2011, building on a background as a robot hobbyist, STEM educator and film-maker.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/robotlaunch', '', 'andra@svrobo.org', '', '1', '1518390126', NULL, NULL),
(286, 'Laetitia Sonami ', 'laetitia-sonami', 'http://codame.dreamhosters.com/uploaded_images/laetitia-sonami.jpg', '<p>Laetitia Sonami is a sound artist, performer and researcher.</p>\r\n<p>Sonami\'s sound performances, live-&shy;â€film collaborations and sound installations focus on issues of presence and participation.&nbsp; She has devised new gestural controllers for performance and applies new technologies and appropriated media to achieve an expression of immediacy through sound, place and objects.</p>\r\n<p>Best known for her unique instrument, the elbow-&shy;â€length lady\'s glove, which is fitted with an array of sensors tracking the slightest motion of her hand and body, she has performed worldwide and earned substantial international renown.&nbsp;&nbsp;</p>\r\n<p>Recent projects include the design of a new instrument, the Spring Spyre, based on the application of neural networks to real-time audio synthesis; an improvisation duo, Sparrows and Ortolans, with James Fei; and Le Corps Sonore, a fully immersive sound installation on six floors of the Rubin Museum, NYC in collaboration with Eliane Radigue and Bob Bielecki.&nbsp;</p>\r\n<p>Upcoming projects include Peripheral Vision, a text based performance piece and a new live film project with Sue-C based on Italo Calvino Cosmicomics.&nbsp;</p>\r\n<p>Sonami has received numerous awards among which the Herb Alpert Awards in the Arts and the Foundation for Contemporary Performance Awards.&nbsp;&nbsp;</p>\r\n<p>&ldquo;...she sometimes looked like a human antenna searching the air for sounds, or like a deity summoning earth-shaking rumbles with a brusque gesture&rdquo;. NY TIMES</p>\r\n<p>&ldquo;Experimental music is rarely this visceral and engaging&rdquo; &ndash; Los Angeles Times</p>\r\n<p>&ldquo;Working since the 1980s, Laetitia Sonami continues to serve as an important figure for female artists working with technology. Her lady&rsquo;s glove made her a well-&shy;â€known name within the performance art scene, particularly because she was one of a few women experimenting with sound and technology.&ldquo; Complex Mag- One of 10 San Francisco personalities you should know in 2014</p>\r\n<p>&nbsp;</p>', '', 'http://sonami.net/', '', '', '0', '1518543540', NULL, NULL),
(287, 'Vanessa Chang', 'vanessa-chang', 'http://codame.dreamhosters.com/uploaded_images/vanessa-chang.jpg', '<p>Vanessa Chang writes, organizes, curates and and teaches about new and old media, literature, comics, animation, sound, circuses and more. She is a lecturer at <a href=\"https://www.cca.edu/academics/critical-studies\" target=\"_blank\" rel=\"undefined noopener\" data-href=\"https://www.cca.edu/academics/critical-studies\">California College of the Arts</a>, and a curator with <a href=\"/\" target=\"_blank\" rel=\"undefined noopener\" data-href=\"http://codame.com/\">CODAME ART+TECH</a>. She holds a Ph.D. in <a href=\"http://modthought.stanford.edu/\" target=\"_blank\" rel=\"undefined noopener\" data-href=\"http://modthought.stanford.edu/\">Modern Thought and Literature</a> from <a href=\"https://medium.com/u/1022fa5dee6d\" target=\"_blank\" data-href=\"https://medium.com/u/1022fa5dee6d\" data-anchor-type=\"2\" data-user-id=\"1022fa5dee6d\" data-action-value=\"1022fa5dee6d\" data-action=\"show-user-card\" data-action-type=\"hover\">Stanford University</a>, where she researched electronic gesture across the arts. At Stanford, she was a Geballe Fellow at the Stanford Humanities Center. She also coordinated the Graphic Narrative Project, a research workshop supported by the Stanford Humanities Center.</p>\r\n<p>As the choreographer William Forsythe has insisted, &ldquo;if dance only does what we assume it can do, it will&nbsp;expire.&rdquo;&nbsp;</p>\r\n<p>Vanessa&rsquo;s work brings that belief into our embodied encounters with new media and technology.</p>\r\n<p>She works with artists, dancers, scholars, technologists, coders and musicians to understand how we might live and move in a technologically mediated world with humor, grace, deliberation, responsibility, innovation and a sense of fun.</p>\r\n<p>We are thrilled to have Vanessa as part of the CODAME Team.</p>', 'https://twitter.com/vxchang', 'https://www.vanessa-chang.com/', '', '', '0', '1520111916', NULL, NULL),
(291, 'BlinkPopShift', 'blinkpopshift', 'http://codame.dreamhosters.com/uploaded_images/m-eifler.jpg', '<p>M Eifler makes chimeras. Using sculpture, performance, costume, drawing, video, and immersive/wearable technology they mix different modes of thought and making in an effort to blur the strict categories of knowledge and identity and geography humans are so fond of in order to rediscover the underlying complex and holistic ecosystems our taxonomies truncate and pin down. Their goal is to center intersectional, anti-disciplinary, and systems-oriented thought as the most important tools for human progress.</p>', 'http://twitter.com/blinkpopshift', 'http://www.blinkpopshift.com/', 'blinkpopshift@gmail.com', '', '0', '1539407673', NULL, NULL),
(288, 'John Campbell', 'john-campbell', 'http://codame.dreamhosters.com/uploaded_images/john-campbell.jpg', '<p>&nbsp;</p>\r\n<p>John Campbell is currently the Willis S. and Marion Slusser Professor of Philosophy at the University of California, Berkeley, and before that, Wilde Professor of Mental Philosophy at the University of Oxford. His main interests are in the philosophies of psychology and psychiatry, with a developing interest in social robots.&nbsp; He&rsquo;s written three books, Past, Space and Self (1994), Reference and Consciousness (2002), and (with Quassim Cassam), Berkeley\'s Puzzle (2014).&nbsp; He&rsquo;s held Guggenheim and NEH Fellowships, and was awarded the Jean Nicod Prize in 2017.&nbsp;&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '', '', '', '', '0', '1519164093', NULL, NULL),
(289, 'Liat Berdugo', 'liat-berdugo', 'http://codame.dreamhosters.com/uploaded_images/liat-berdugo.jpg', '<p><span id=\"gmail-docs-internal-guid-014544c8-e008-4657-a0d8-b17689382930\">Liat Berdugo is an artist, writer, and curator whose work -- which focuses on embodiment and digitality, archive theory, and new economies -- interweaves video, writing, performance, and computer programming to form a considerate and critical lens on digital culture. Berdugo has been exhibited in galleries and festivals internationally, and she collaborates widely with individuals and archives. She is the co-founder and curator of the Bay Area&rsquo;s <a href=\"http://www.livingroomlightexchange.com/\">Living Room Light Exchange</a>, a monthly new media art salon; co-founder and curator of <a href=\"http://worldwidewest.net/\">World Wide West</a>, an annual summit, exhibit, and performative new media event, among others. Her writing appears in Rhizome, Temporary Art Review, Real Life magazine, and others, and her book, <a href=\"http://www.spdbooks.org/Producte/9781939781031/the-everyday-maths.aspx\">The Everyday Maths</a>, was published by Anomalous Press in 2013. Berdugo received an MFA from RISD and a BA from Brown University. She is currently an assistant professor of Art + Architecture at the University of San Francisco. </span></p>', 'https://twitter.com/whatliat', 'http://www.liatberdugo.com/', 'liat.berdugo@gmail.com', '', '0', '1519976207', NULL, NULL),
(293, 'Marta di Francesco', 'marta-di-francesco', 'http://codame.dreamhosters.com/uploaded_images/marta-di-francesco.jpeg', '<p>Marta Di Francesco(1978) is a London based visual artist, exploring new aesthetics, merging poetics with code.In her practice, she investigates digital identity and its fragmentation, exploring and questioning it through digital bleed, time displacement, processing, and through the sculptural quality of time in volumetric aesthetics.</p>\r\n<p>For nearly a decade she has been merging a conceptual, critical approach with a search for metaphysical, poetic correspondences between the body, the spirit and the metaverse, writing and creating radical pieces that inhabit and crossover poetry, dance and code, and working through multidisciplinary collaborations to explore new expressions and conversations.</p>\r\n<p>Di Francesco&rsquo;s latest screenings and exhibitions include THE WRONG New Digital Art Biennale (2018), Back to the PostFutureExhibition curated by ADAF Venice (2018), POOL Internationales TANZFilmFestival Berlin (2017), VECTOR Festival Toronto (2017), The Third Culture Film Festival Hong Kong (2017), ADAF Athens Digital Arts Festival (2017) and ADAF #PostFuture Journey Digital Art Exhibition at Athens International Airport (2017), RETUNE Festival Berlin (2016), NEW AESTHETIC: Future Bodies programme at Film Festival Cologne (2016) and NEW AESTHETIC programme at KFFK Cologne (2016), the Psych Space screening at EEF Festival, part of Norman McLaren retrospective at the Whitechapel Art Gallery London (2016), the Dream:ON Digital Art screening at the G&ouml;ethe-Institut curated by Alpha-ville London (2014), the RGBD screening at the New York Museum of Arts and Design for NY Makers: the MAD Biennale (2014), the Echoes AV Installation commissioned by Mother for Digital Shoreditch London (2012).</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/CUCCURUCU', 'http://martadifrancesco.com/', '', '', '0', '1528076902', NULL, NULL),
(294, 'Snow Yunxue Fu', 'snow-yunxue-fu', 'http://codame.dreamhosters.com/uploaded_images/snow-yunxue-fu.jpg', '<p>Snow Yunxue Fu is a US-based Chinese-born New Media artist, Curator, and Assistant Arts Professor in the Department of Photography and Imaging at New York University Tisch School of the Arts. Using topographical computer-rendered images and installations, her practice merges historical, post-photographic, philosophical, and painterly explorations into the universal aesthetic and definitive nature of the techno sublime.&nbsp;</p>\r\n<p>With a background in painting, Fu remains the youngest artist collected by the National Art Museum of China. She sees her transition into new media as a natural extension of her conceptual research in which she draws parallels between the physical, metaphysical, digital, and multi-dimensional spaces.&nbsp;</p>\r\n<p>Fu&rsquo;s artwork has been shown internationally in solo shows, group exhibitions, screenings, and festivals including:</p>\r\n<ul>\r\n<li>The New York Gallery of Chinese Art, New York;</li>\r\n<li>Venice Architecture Biennale, Venice, Italy;</li>\r\n<li>Pioneer Works, New York;</li>\r\n<li>NADA Art Fair, New York;</li>\r\n<li>Sediton, Hong Kong;</li>\r\n<li>Arebyte Gallery, London, UK;</li>\r\n<li>Shenzhen Independent Animation Biennale, Shenzhen, China;</li>\r\n<li>Current Museum of Art, New York;</li>\r\n<li>Thoma Art House, Santa Fe;</li>\r\n<li>Currents Santa Fe New Media Art Festival, New Mexico;</li>\r\n<li>The Wrong Biennale, the Internet, and etc.&nbsp;</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p>Her work has also been collected by the Currents Museum of Art in New York. Her work reviews and interviews have been covered in the New York Times, the Boston Globe, Arebyte on Screen, Sedition, the St. Louis Magazine Art Review, Guangzhou Today&rsquo;s Focus in China, and etc.&nbsp;</p>\r\n<p>She participated in residencies such as the Hatch Residency through the Chicago Artist Coalition, Biocultura Residency in Santa Fe NM, Lexington and Concord Artist Residency in Illinois, and Estudio N&oacute;mada&rsquo;s Mas els Igols Residency in Barcelona, Spain.</p>\r\n<p>She has given lectures and presented on her work and research in conferences, symposiums, and institutions around the world including International Symposium on Electronic Art (ISEA), SIGGRAPH, SIGGRAPH Asia in Brisbane Australia, the Chinese-American Art Faculty Symposium, Veritas Forum, the School of the Art Institute of Chicago, University of Chicago, and China Academy of Art.</p>\r\n<p><img src=\"/uploaded_images/snow-yunxue-fu1.png\" alt=\"\" /></p>', 'https://twitter.com/snow_fu', 'http://snowyunxuefu.com/home.html', 'snowyunxuefu@gmail.com', '', '0', '1629673111', 'https://codame.threadless.com/collections/snow-yunxue-fu', 'https://www.instagram.com/snowyunxuefu/'),
(295, 'Deanna Hood', 'deanna-hood', 'http://codame.dreamhosters.com/uploaded_images/deanna-hood.jpg', '<p>Deanna Hood is an electrical engineer whose work focuses on humanitarian applications of engineering and robotics, with projects spanning accessibility, education and healthcare. Examples of her work include a brain-controlled car, with applications for people living with paralysis, and a low-cost USB stethoscope for diagnosing childhood pneumonia in developing countries. In collaboration with teachers she developed the first robotic partner for children with handwriting difficulties, which children teach how to write so that they can benefit from &ldquo;learning by teaching&rdquo;. This innovative twist on the use of robotics in education has resulted in a number of academic publications in addition to international media coverage such as by Reuters, Discovery Channel, the Sydney Morning Herald, and Fast Company.</p>\r\n<p>Deanna loves exploring other cultures: over the course of her studies (B. Mathematics, B. Electrical Engineering, M.Sc. Robotics and Computer Vision) she lived in five different countries, and separately she has undertaken projects in another four countries. These include developing educational technologies in Columbia and repairing medical equipment in rural Nicaragua. Deanna now works at the Open Source Robotics Foundation on the Robot Operating System (ROS), a software framework that fosters collaboration among the robotics community by enabling roboticists to leverage each other&rsquo;s algorithms and contribute to a global ecosystem. OSRF also develops Gazebo, a free and open source multi-robot simulator that removes the need for owning (or damaging) expensive hardware during robotics development. Originally developed for researchers but also widely used in industry, education and by hobbyists and artists, these tools are lowering the technical and financial barriers to robotics for everyone.</p>\r\n<p>For her efforts in advancing society&rsquo;s perception of science and engineering Deanna has been recognised as a Google Anita Borg Memorial Scholar, on Shoestring Magazine&rsquo;s Young &amp; Influential List, as a finalist for the Pride of Australia Young Leader Medal, as an Erasmus Mundus Scholar, and as a finalist for TED2013.</p>\r\n<p>&nbsp;<em>Talk:</em></p>\r\n<p><strong>Creative approaches to human-robot interaction challenges needed for developing a robot partner for children learning handwriting</strong></p>\r\n<p>Historically the use of robotics in classrooms has been limited to the teaching of robotics itself in STEM classrooms, and with good reason: keeping kids entertained in long-term human-robot interactions is no easy feat. There&rsquo;s a great opportunity for robots to be used in classes teaching other subjects, particularly those teaching physical skills, but the cost of robots capable of complex physical movements can be a significant limitation. This talk presents the CoWriter Project that is based around one role that robots are well-suited for when it comes to teaching non-robotics subjects: helping children with handwriting difficulties. Given the aforementioned challenges, the project wouldn&rsquo;t have been possible without quite a bit of creativity in its approach to addressing them. We&rsquo;ll explore some twists needed to make the use of a humanoid robotic partner in this context viable, for example the fact that the children are actually the ones teaching the robot, and the out-of-the-box thinking that made it possible for schools to afford a robot capable of &ldquo;writing&rdquo;.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/deanna_hood', '', 'deanna.m.hood@gmail.com', '', '0', '1525798976', NULL, NULL),
(296, 'Cynthia X. Hua ', 'cynthia-x-hua', 'http://codame.dreamhosters.com/uploaded_images/cynthia-x-hua.jpg', '<p>Cynthia X. Hua produces installations that solicit mass user participation via the web. She explores how contributions from diverse groups of people can be clustered, collaged or computed together into works of the collective imagination. Hua has displayed work in Los Angeles, Berlin and San Francisco. She is currently an Incubator Member at the Gray Area Foundation for the Arts. She has previously been awarded fellowships from the Yerba Buena Center for the Arts, Signal Culture, The LAB as well as the Nieman Foundation at Harvard. Her work has been featured on VentureBeat and CCTV, and she has presented about computer-based art at outlets such as Theorizing the Web, Creative Tech Week and NYU. Hua received her B.A. at Yale, focusing on Internet media.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/cynthiaxhua', 'http://cynthiaxhua.com', '', '', '0', '1529036815', NULL, NULL),
(297, 'VJ Um Amel ', 'vj-um-amel', 'http://codame.dreamhosters.com/uploaded_images/vj-um-amel.png', '<p>Laila Shereen Sakr (a.k.a. VJ Um Amel) is Assistant Professor of Media Theory &amp; Practice at University of California, Santa Barbara. At UCSB, she has co-founded Wireframe, a new digital media studio that supports critical game design, data visualization, VR/augmented realities, digital arts and activism. Her current book project theorizes the &ldquo;glitch&rdquo; at the intersection of digital protocols (rules that seek standardization and stabilization) and exploits (interventions that seek to upstage/subvert protocols for their own agendas, most often associated with the realms of hacktivism and piracy). Shereen Sakr has shown in solo and group exhibitions and performances at galleries and museums including the San Francisco MoMA, National Gallery of Art in Jordan, Camera Austria, Cultura Digital in Brazil, DC Fridge Art Gallery, 100 Copies in Egypt, among other venues. Her journal articles appear in <em>Middle East Critique, Cinema Journal Teaching Dossier, Networking Knowledge: Journal of the Media, Communication, and Cultural Studies, Parson&rsquo;s Journal for Information Mapping, Thoughtmesh: Critical Code Journal, </em>and<em> Feminist Debates in Digital Humanities</em> (forthcoming).</p>\r\n<p>Over the last two decades, she has been a leading voice in the open source movement, in particular for Arabic localization. She is Co-Editor for the open access journal: <em>Media Theory</em>, and also for <em>After Video</em> published by Open Humanities Press. In addition, she is Research Collaborator in the Global Media Technologies &amp; Cultures Lab at MIT. Professor Shereen Sakr holds an M.F.A. in Digital Arts and New Media from University of California, Santa Cruz, an M.A. in Arab Studies from Georgetown University, and a PhD in Media Arts + Practice from the University of Southern California. Reviews of her work appear in <em>The Wall Street Journal, Science, The Chronicle of Higher Education, Fast Company, The Huffington Post, The Guardian, Voice of America, The Monocle, Art Territories, Digital Media and Learning, Egypt Independent, Mada Masr, Jadaliyya, </em>and<em> The Creators Project.</em></p>\r\n<p>&nbsp;</p>', 'https://twitter.com/vj_um_amel', 'http://vjumamel.com', 'lailashereensakr@ucsb.edu', '', '0', '1526917640', NULL, NULL),
(298, 'Tanya Gayer', 'tanya-gayer', 'http://codame.dreamhosters.com/uploaded_images/tanya-gayer.jpg', '<p>Tanya Gayer is a curator and writer based in Oakland, CA. Her curatorial projects and research examine the state of the archive in mobile and web-based media, algorithmic manipulation of culture and identity, and performance-based new media. Gayer received her dual masters degree in Curatorial Practice and Visual + Critical Studies from California College of the Arts and her BFA from University of Nevada, Reno.</p>\r\n<p>Her previous curatorial projects have been exhibited at Gray Area, San Francisco, CA; CTRL + SHFT Gallery, Oakland, CA; Wattis Institute for Contemporary Arts, San Francisco, CA; Pro Arts Gallery, Oakland, CA; Hayes Valley Art Works, San Francisco, CA; Embark Gallery, San Francisco, CA; Some Thing Spacious, Oakland, CA; and Adobe Books Backroom Gallery, San Francisco, CA. She has been in residence at Picture Berlin, Berlin, Germany and Signal Culture, Owego, New York. Her writing has been published in Daily Serving, in exhibition catalogs from CULT Exhibitions, San Francisco, CA; Holland Project, Reno, NV; Pro Arts, Oakland, CA, Wattis Institute for Contemporary Arts, San Francisco, CA, and co-produced a one-off audio podcast for a Living Room Light Exchange publication. Gayer has lectured at UC Santa Barbara and UC San Diego. She is currently the Exhibitions Manager at Sonoma Valley Museum of Art in Sonoma, California.</p>', '', 'http://tanyagayer.com/', '', '', '0', '1521410756', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(299, 'Brian Christian ', 'brian-christian', 'http://codame.dreamhosters.com/uploaded_images/brian-christian.jpg', '<p>Brian Christian is the author of <em>The Most Human Human</em>, which was named a Wall Street Journal bestseller, a New York Times Editors&rsquo; Choice, and a New Yorker favorite book of the year. He is the coauthor, with Tom Griffiths, of <em>Algorithms to Live By</em>, a #1 Audible bestseller, Amazon best science book of the year and MIT Technology Review best book of the year.</p>\r\n<p>Christian&rsquo;s writing has been translated into eighteen languages, and has appeared in The New Yorker, The Atlantic, Wired, The Wall Street Journal, The Guardian, The Paris Review, and in scientific journals such as Cognitive Science. Christian has been featured on The Daily Show with Jon Stewart, Radiolab, and The Charlie Rose Show, and has lectured at Google, Facebook, Microsoft, the Santa Fe Institute, and the London School of Economics. His work has won several awards, including fellowships at Yaddo and the MacDowell Colony, publication in Best American Science &amp; Nature Writing, and an award from the Academy of American Poets.</p>\r\n<p>Born in Wilmington, Delaware, Christian holds degrees in philosophy, computer science, and poetry from Brown University and the University of Washington. A Visiting Scholar at the University of Californa, Berkeley, the Director of Technology at McSweeney&rsquo;s Publishing, and an active open-source contributor to projects such as Ruby on Rails, he lives in San Francisco.</p>\r\n<p>&nbsp;</p>', '', 'https://brianchristian.org', '', '', '0', '1521411150', NULL, NULL),
(300, 'Jean-Philippe CÃ´tÃ©', 'jean-philippe-c-t', 'http://codame.dreamhosters.com/uploaded_images/jean-philippe-c-t.png', '<p>Jean-Philippe C&ocirc;t&eacute; is an artist based in Montreal (Qu&eacute;bec, Canada). His visual and interactive work is always driven by algorithms. Using open source software and pieces of &ldquo;obsolete&rdquo; hardware, he puts together interactive installations that bring back a sense of tangibility to this otherwise artificial, virtual and augmented world of ours.</p>\r\n<p>Jean-Philippe leverages his early years as an award-winning developer to devise algorithmic approaches to creating art and re-shaping reality. This makes him a respected contributor to the open source community, especially in the fields of creative coding and physical computing.</p>\r\n<p>His subject of choice is the human face which he usually draws using micro or macro line segments. While figurative, his work challenges perception. The viewer&rsquo;s brain is asked to fill in the gaps and one often needs to change his point of view to fully appreciate the work.</p>\r\n<p>His work has been featured during events such as FITC, Chromatic and Eyeo and presented at venues such as the Walker Art Center, Soci&eacute;t&eacute; des arts technologiques (SAT) and Infopresse.</p>\r\n<p>Going back to school to complete a master&rsquo;s degree (2009-2013) is probably what brought him to visual arts. His research work yielded an interactive platform for non-musicians to play music together called Mmm. Mmm was presented publicly during the Sennheiser Sound Creation and New Media Concert (2013) and during ChaosM&eacute;dia (2013). A mobile spin-off platform, named MMMM, was also developed via public funding. While these projects were relatively short-lived, they did demonstrate how powerful software as a prosthetic could be.</p>\r\n<p>It did not take long before Jean-Philippe realized he could apply this same approach to visual arts. Having, himself, no formal training in drawing, he could use his programming skills to devise software and hardware contraptions that would help him create visual art. This has been his approach ever since.</p>\r\n<p>His first algorithmically-generated pieces have been displayed at Soci&eacute;t&eacute; des arts technologiques (SAT) during the G&eacute;n&eacute;rations d&rsquo;id&eacute;es symposium. He was then invited to speak about his process during various local events.</p>\r\n<p>The momentum brought on by these early public presentations allowed him to present Y&ouml;ti &ndash; The Algorithmic Portrait Artist at various festivals and events:</p>\r\n<p>FITC (Toronto)</p>\r\n<p>Composite #10 (Montreal)</p>\r\n<p>Eyeo (Minneapolis)</p>\r\n<p>Jean-Philippe teaches in the Multimedia Department of Coll&egrave;ge Edouard-Montpetit. He holds a master&rsquo;s degree in communication (with a specialization in experimental media) from Universit&eacute; du Qu&eacute;bec &agrave; Montr&eacute;al.</p>\r\n<p>He also is a speaker and workshop host and used to be a drummer and street photographer. He enjoys Japanese, Thai and Indian cuisine just as much as colorful cocktails.</p>', 'https://twitter.com/djipco', 'http://cote.cc', '', '', '0', '1528235215', NULL, NULL),
(301, 'Lewis Rapkin', 'lewis-rapkin', 'http://codame.dreamhosters.com/uploaded_images/lewis-rapkin.jpg', '<p>Lewis has spent the past decade working as an editor, producer and/or composer on documentaries for HBO, VICE, PBS, Tribeca Productions, Discovery, NBC and BBC among others.&nbsp; He directed the feature documentary <em>LIVE FROM TOKYO</em> about the underground music scene in Tokyo and is currently editing an upcoming feature for Tribeca Productions.&nbsp;</p>\r\n<p>In collaboration with Dolby Laboratories, he directed and composed the score for the short documentary <em>Automatic On The Road</em>, which was one of the first soundtracks to ever be conceived of and mixed in Dolby Atmos surround.&nbsp;</p>\r\n<p>He was an associate editor on the Emmy award winning documentary <em>Marina Abramovic: The Artist is Present</em>, as well as a lead editor on the founding team to launch VICE News in 2013, editing award-winning documentaries.&nbsp;</p>\r\n<p>&nbsp;</p>', '', 'www.oscillatormedia.com', '', '', '0', '1521937193', NULL, NULL),
(302, 'Happy Valley Band', 'happy-valley-band', 'http://codame.dreamhosters.com/uploaded_images/happy-valley-band.jpeg', '<p>The Happy Valley Band is pop music as heard by a computer algorithm. Bay Area composer and performer David Kant translates machine learning analyses of pop songs into music notation in order to explore the biases and assumptions inherent in digital automation. The transcriptions, which are impossibly over-specific, microtonal, and brimming with artifacts of the machine listening process, are performed by the Happy Valley Band, a group of Bay Area and New York City musicians.</p>\r\n<p>The project has been described as &ldquo;a shitty MP3 to MIDI converter,&rdquo; &ldquo;the Shaggs meets Guitar Hero,&rdquo; &ldquo;James Brown backed by Sun Ra,&rdquo; &ldquo;the best executed worst idea,&rdquo; and &ldquo;generally distressing to listen to.&rdquo; According to Kant, &ldquo;it&rsquo;s not exactly about getting machines to hear like (we presume) humans do. Machines hear in as many different ways as we design and build them. We should use machines to hear differently, not to reinforce our expectations --- because whose expectations are they anyway?\" The project is about highlighting the assumptions implicit in algorithm design.</p>\r\n<p>Formed in 2011, the Happy Valley band released their debut album, ORGANVM PERCEPTVS, in 2017 on Santa Cruz based record label Indexical. The recording features interpretations of pop icons from Madonna to Patsy Cline to Phil Collins.</p>\r\n<p style=\"text-align: center;\">&nbsp;<iframe src=\"//player.vimeo.com/video/170204430?title=0&amp;byline=0\" width=\"425\" height=\"350\"></iframe></p>\r\n<p><a href=\"https://happyvalleyband.bandcamp.com/album/organvm-perceptvs\">Stream ORGANVM PERCEPTVS</a> on Bandcamp</p>\r\n<p>Further Explanations:</p>\r\n<p><a href=\"http://www.algorithmiclistening.org/introductions/HVB/\">Making music through machine ears</a></p>\r\n<p><a href=\"http://media.experimentalmusicyearbook.com/emymedia/2016/davidkant/ORGANVM%20PERCEPTVS%20-%20Liner%20Notes%20Booklet.pdf\">ORGANVM PERCEPTVS liner notes</a></p>\r\n<p>Press:</p>\r\n<p><a href=\"https://www.thewire.co.uk/in-writing/interviews/listen-to-the-happy-valley-band-s-new-album-and-read-an-interview-with-its-founder\">Interview with The Wire</a></p>\r\n<p><a href=\"https://daily.bandcamp.com/2018/01/25/music-ai-coding-algorithms/\">Bandamp AI List</a></p>', '', 'https://www.happyvalleyband.com', '', '', '0', '1522174838', NULL, NULL),
(303, 'Vicente Montelongo', 'vicente-montelongo', 'http://codame.dreamhosters.com/uploaded_images/vicente.jpg', '<p>Hi I&rsquo;m Vince, a Creative and Art Director focused on culture and technology. I&rsquo;ve created brand identities, developed content, art directed campaigns, curated art+tech experiences, and designed across the print and digital spectrum. I&rsquo;m also obsessed with subcultures and can work on poly-cultural / bilingual projects for Latin American audiences.&nbsp;</p>', 'https://twitter.com/mexist', 'vicentemontelongo.com', '', '', '0', '1697372147', '', ''),
(304, 'Christopher Willits', 'christopher-willits', 'http://codame.dreamhosters.com/uploaded_images/christopher-willits.jpg', '<h3>BIO</h3>\r\n<p>Christopher Willits is a musician, artist and teacher based in San Francisco who believes that music and art can catalyze inner change. Willits creates meditative ambient electronic music created with guitar and voice, that is designed to overlap with his own cinematic film and video work. These immersive audiovisual experiences speak to a global audience on a universal level. His music on labels such as Ghostly International has garnered critical acclaim, sending him on continuous tours around the world. Multiple solo albums and collaborations with the likes of Ryuichi Sakamoto, Tycho, and Taylor Deupree have accounted for a diverse catalog with over 27 releases over the last 15 years. Christopher is the founder of the creative collective Overlap, and also Envelop, a spatial audio organization that creates listening spaces and open-source software tools. As an experienced teacher, Christopher strives to illuminate people&rsquo;s vision and creativity in music and art and life, and has lectured at many leading institutions in the world.</p>\r\n<h3>ARTIST STATEMENT</h3>\r\n<p>I believe that music and art can catalyze inner change and that changes in our world occur when we change ourselves.&nbsp; As an artist, I design immersive experiences of sound and light, with the intention of creating a space for opening, reflection and transformation. As a teacher, I show others how to do this for themselves and aid them in creating what they love. The experiences I share are informed by my practices of meditation and Tai Chi. I express the gratitude, wonder and inspiration of being on this planet with you, right now.</p>', 'https://twitter.com/Willits', '', 'willits@overlap.org', '', '0', '1523042086', NULL, NULL),
(305, 'Evo Heyning ', 'evo-heyning', 'http://codame.dreamhosters.com/uploaded_images/evo-heyning.jpg', '<p>Called on as a Magicmaker for New Ventures, Evo is a creative force of nature connecting brilliant visionaries and teams with resources, ideas and opportunities for exponential impact. With 20+ years experience inside major companies, NGOs, media networks, startups and now as a producer Evo brings INTEGRATION, insight and inspiration to new ventures. Current residencies and projects connect VR and Mixed Reality, AI and nanotech R&amp;D with a wide mix of interactive product teams in edtech, personalized product delivery, media, health and impact mapping across fields and sectors.</p>\r\n<p>Evonne (Evo) Heyning is a 2012 graduate of Singularity University GSP and consults on human connection: engagement strategy and community development, transparency, trust and blockchains for opening access, emerging trends in media arts, social and playful communications, demystifying change management for new systems and economic opportunities for learning and participation. In the last decade she co-founded tech teams including Toyshoppe Systems, a full service FX media R&amp;D studio creating robots, wearables and spacecraft for film, touring and broadcast partners worldwide. Evo is available for strategy hikes in Oakland or LA, writes speculative fiction and nonfiction series and produces mixed reality experiences.</p>\r\n<p>A visionary interactive producer, Evonne Heyning (Evo) has worked at the intersection of learning, meaningful media and creative campaigns for 20 years. In social enterprises she designs experiences, community ecosystems and new ventures. As a creative producer she weaves together mixed reality, events, live broadcast, vital impact resources and social media engagement. For the last two decades she has been weaving tech, media and impact for national and local government, major networks, universities and global nonprofits.</p>\r\n<p>Evonne delivers inspiration and insight, opening learning opportunities and access for everyone. With over 30 years experience as an exhibiting artist and programmer Evo has spent over a decade designing tools to connect media, learning and experiences. In 2014 she won the NBCNews hackathon creating RealAction, an app to generate emergency news push reports with maps and vital info to all devices within minutes of any crisis. In the past few years she has focused on gaming including AR and Mixed Reality, serving as CoFounder &amp; Former Chair of Grow Games to blend collaborative play with healthy ecosystems.</p>\r\n<p>In 2015 she received an Innovation award from Hershey&rsquo;s to invest the future of chocolate, connecting makers and consumers through the happiness and joy of creating new chocolate products. By using tech tools from AI, biotech engineering of personalized medicine, 3D printing and free learning delivery we can rapidly change the way products and services are delivered to each other, connecting a new world of opportunity. For more read this article from Singularity Hub on tech, innovation and the future of chocolate.</p>\r\n<p>Evo specializes in using technology to create solutions for dynamic play. She works extensively with governments to facilitate rapid change, from creating a clean GHG-free vision with Palo Alto to redesigning mobility and transit in Medellin, Colombia. Her work with ExO.Works currently has Evo guiding innovation sprints in cities around the world.</p>\r\n<p>In Hollywood and beyond she weaves thousands of social posts into extraordinary live event broadcasts for clients such as Allstate with Imagine Dragons, SpiderMan2, White House with Ogilvy for the Affordable Care Act and Wisdom 2.0. She has previously worked with diverse teams at TechSoup, the US Department of State and as a teacher creating new curricula within special education schools and libraries.&nbsp;</p>\r\n<p>Evo is passionate about creating personalized learning apps and tools for knowledge sharing across all types of media and experiences to deliver a personal map for lifelong learning. Evonne started a homegrown incubator for new ventures after graduating from Singularity University and she guides interactive tech teams connecting experiences as a board member, co-founder and advisor.</p>\r\n<p>Evo is a frequent event speaker, host and producer on topics including Social Action Gaming, Insight and Inspiration,&nbsp; Engagement and Participation in Media and the Future of Learning, Interactivity and Play.&nbsp; She published the virtual to live art book Visions of Global Justice with USC and the MacArthur Foundation in 2009 and is now developing a workbook on engagement strategy while building new communities around the world. She is producing a new immersion work as a futurist tech game show for global livestreaming and participatory play.&nbsp;</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/EvoHeyning', '', 'evoamo@gmail.com', '', '0', '1631581384', '', ''),
(306, 'Scot Gresham-Lancaster', 'scot-gresham-lancaster', 'http://codame.dreamhosters.com/uploaded_images/scot-gresham-lancaster.jpg', '<p>&nbsp;</p>\r\n<p>Scot Gresham-Lancaster is a composer, performer, instrument builder, educator and educational technology specialist with over three decades of professional experience. He is dedicated to research and performance using the expanding capabilities of computer networks to create new environments for musical and cross discipline expression. As a member of The Hub (band), he is one of the early pioneers of \"computer network\" music which uses the behavior of interconnected music machines to create innovative ways for performers and computers to interact. He has recently performed in a series of \"co-located\" performances collaborating in real time with live and distant dancers, video artists and musicians in network based performances. For over two decades, he has worked with multimedia prototyping and user interface theory and its relationship to new markets as an independent consultant and at Interval Research, SEGA-USA, and Muse Communications.</p>\r\n<p>He was a student of Roy Harris, Darius Milhaud, John Chowning, Robert Ashley, Terry Riley, \"Blue\" Gene Tyrany, David Cope among others.&nbsp;</p>\r\n<p>He is currently a Visiting Researcher at CNMAT, UC Berkeley. He is also a Research Scientist at the ArtSci Lab at ATEC. The focus of his current research is on the unrealized potential of sonification.</p>\r\n<p>Since 2006 he has collaborated with media artist Stephan Bull in a series of &ldquo;cellphone operas&rdquo;. Cellphonia explores the social, technological, and creative possibilities of cell phones with bias to encourage new applications for cultural growth.&nbsp;</p>\r\n<p>&nbsp;</p>', 'http://www.twitter.com/scotgl', 'https://about.me/scotgl', '', '', '0', '1524433611', NULL, NULL),
(307, 'daevron', 'daevron', 'http://codame.dreamhosters.com/uploaded_images/daevron.jpg', '<p>d&aelig;vron (they/them) is a visual artist, hardware hacker and digital media developer. A graduate of Gray Area\'s Creative Coding Program and Artistic Director with We Inventing the Real, they are an artist-in-residence with Combustible at CounterPulse. daevron has produced new media, experimental video and immersive digital experiences with support from the SF Arts Commission, California Arts Council and Peace Point Entertainment. Their works have been exhibited at venues including Rock Paper Scissors Gallery, Tempest Studio, SOMarts, Bayview Opera House, AAACC, Elemental and SF LGBT Center.</p>', '', 'http://daevron.com', '', '', '0', '1524437625', NULL, NULL),
(364, 'Chelsea Simmons', 'chelsea-simmons', 'http://codame.dreamhosters.com/uploaded_images/chelsea-simmons.jpg', '<p>Chelsea Simmons was born in Walnut Creek, California. She currently lives in Danville, California. She was raised as an only child by her parents in Concord. Oftentimes, she would entertain herself as a child with an overactive imagination. This overactive imagination often translates in work that is playful in nature by its exploration of nostalgia and toylike elements.&nbsp;</p>\r\n<p>She attended Acalanes High School in Lafayette and studied her undergraduate in Graphic Design at CSU Stanislaus. She later went on to study Digital Media at San Jose State.</p>\r\n<p>She became inspired to work in an art field due to her upbringing of her parents, an architect and an artist.</p>\r\n<p>&nbsp;Chelsea works mostly in Adobe Premiere, Maya and Adobe After Effects but also enjoys hardware application and game design. While creating a project in a digital platform, Chelsea utilizes her fine art background first to help&nbsp; her plan the final piece. She has special interests in city planning and enjoys exploring themes in time across space, artificial intelligence, virtual reality in its application to therapy. Her work strives to make the intangible , tangible, explore the ethereal and build connections within communities.&nbsp;</p>', 'https://www.instagram.com/pollo.dulce/', 'http://ChelseaSimmonsArt.com', '', '', '0', '1587100345', NULL, NULL),
(309, 'Yiying Lu', 'yiying-lu', 'http://codame.dreamhosters.com/uploaded_images/yiying-lu.jpg', '<p>Yiying Lu is an award-winning bilingual artist, entrepreneur, and speaker with 10+ years of experience in Branding, Design &amp; Cross-Cultural Creativity &amp; Innovation Education. She was born in Shanghai China, educated in Sydney Australia &amp; London UK, Yiying is currently based in San Francisco. Yiying was named a Fast Company\'s Most Creative People in Business, a \"Top 10 Emerging Leader in Innovation\" by Microsoft, and the first Shorty Awards winner in Design.&nbsp;Yiying discovered the deep connection between art and technology through her high school&nbsp;<span id=\"gmail-3569\">years</span>&nbsp;and followed her passion to lead cross-cultural design practice for global brands and businesses such as Disney, Microsoft, and Twitter.&nbsp;Her projects have been featured in many publications, including The New York Times, Forbes, The Atlantic, Fast Company, TIME, CNN, BBC and so on. She was the first artist to join IDEO China for its Creative Collaboration Program&nbsp;in Shanghai. Previously, Yiying was the Creative Director at 500 Startups, the world\'s most active venture capital firm and startup accelerator, where she provided creative user acquisition &amp; branding strategies for hundreds of startups to improve their business.&nbsp;She is fascinated by unifying the dualities between art &amp; tech, business &amp; humor, work &amp; life; and be a cultural bridge between the East &amp; the West.&nbsp;&nbsp;</p>', 'https://twitter.com/YiyingLu', 'http://www.yiyinglu.com/', '', '', '0', '1532388962', NULL, NULL),
(310, 'Anina Net', 'anina-net', 'http://codame.dreamhosters.com/uploaded_images/anina-net.jpg', '<p>A former international model now based in San Francisco and Beijing with 10 years&rsquo; experience creating a bridge between the east and west, fashion and tech. Anina recently created 162 smart gloves using gesture recognition for Intel\'s cooperation with CCTV Spring Festival Gala. She is invited to speak at the top global technology conferences, along with fashion and social media events.</p>\r\n<p>Working together with the China National Garment Association over the last five years, Anina has successfully produced large-scale exhibitions, roundtable discussions, and fashion tech runway shows, which feature wearable technology and IOT fashion solutions.&nbsp;</p>\r\n<p>Anina is a worldwide public speaker on fashion technology, known for her new product developments and her vision for the future technological lifestyle. She has been speaking at the top technology conferences such as Mobile World Congress, Le Web, LIFT, DLD, China Fashion Week, China Fashion Forum, Huawei Innovation, Dutch Week of Innovation, TechNode, PingWest SYNC,&nbsp; and more.&nbsp;</p>\r\n<p>Anina is an expert at integrating technology into fashion clothing. She works with fashion designers and technicians to create new wearable technology in clothing and accessories.</p>', '', '', 'anina2@360fashion.net ', '', '0', '1526069241', NULL, NULL),
(311, 'Nolan Lem', 'nolan-lem', 'http://codame.dreamhosters.com/uploaded_images/nolan-lem.jpg', '<p>Nolan Lem is an artist and researcher whose work reflects a broad range of influences and mediums. His arts practice integrates research related to emergent dynamics, machine learning and perception, and the synchronization of auditory phenomena.&nbsp;</p>\r\n<p>He has premiered his work and research at a number of spaces both in the US and abroad including the Hayden Planetarium at the Natural History Museum, Pioneer Works, L\'HOSTE Art Contemporain, and the NIME (New Interfaces for Musical Expression) Conference among others. He has held residencies at IRCAM (France), MassMoCA (MA, USA) and Cit&eacute; Internationale des Arts (FRANCE). He holds degrees in saxophone performance, Electrical Engineering, and received his MFA at Columbia University where he studied at the Computer Music Center.&nbsp;</p>\r\n<p>Nolan is currently a PhD candidate at Stanford University where he studies at the Center for Computer Research in Music and Acoustics (CCRMA) .&nbsp;</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/no_lem', 'http://www.nolanlem.com', '', '', '0', '1524180179', NULL, NULL),
(312, 'Laura Sydell', 'laura-sydell', 'http://codame.dreamhosters.com/uploaded_images/laura-sydell.jpg', '<p>Laura Sydell fell in love with the intimate storytelling qualities of radio, which combined her passion for theatre and writing with her addiction to news. Over her career she has covered politics, arts, media, religion, and entrepreneurship. Currently Sydell is the Digital Culture Correspondent for NPR\'s All Things Considered, Morning Edition, Weekend Edition, and NPR.org.</p>\r\n<p>Sydell\'s work focuses on the ways in which technology is transforming our culture and how we live. For example, she reported on robotic orchestras and independent musicians who find the Internet is a better friend than a record label as well as ways technology is changing human relationships.</p>\r\n<p>Sydell has traveled through India and China to look at the impact of technology on developing nations. In China, she reported how American television programs like Lost broke past China\'s censors and found a devoted following among the emerging Chinese middle class. She found in India that cell phones are the computer of the masses.</p>\r\n<p>Sydell teamed up with Alex Bloomberg of NPR\'s Planet Money team and reported on the impact of patent trolls on business and innovations particular to the tech world. The results were a series of pieces that appeared on This American Life and All Things Considered. The hour long program on This American Life \"When Patents Attack! - Part 1,\" was honored with a Gerald Loeb Award and accolades from Investigative Reporters and Editors. A transcript of the entire show was included in The Best Business Writing of 2011 published by Columbia University Press.</p>\r\n<p>Before joining NPR in 2003, Sydell served as a senior technology reporter for American Public Media\'s Marketplace, where her reporting focused on the human impact of new technologies and the personalities behind the Silicon Valley boom and bust.</p>\r\n<p>Sydell is a proud native of New Jersey and prior to making a pilgrimage to California and taking up yoga she worked as a reporter for NPR Member Station WNYC in New York. Her reporting on race relations, city politics, and arts was honored with numerous awards from organizations such as The Newswomen\'s Club of New York, The New York Press Club, and The Society of Professional Journalists.</p>\r\n<p>American Women in Radio and Television, The National Federation of Community Broadcasters, and Women in Communications have all honored Sydell for her long-form radio documentary work focused on individuals whose life experiences turned them into activists.</p>\r\n<p>After finishing a one-year fellowship with the National Arts Journalism Program at Columbia University, Sydell came to San Francisco as a teaching fellow at the Graduate School of Journalism at University of California, Berkeley.</p>\r\n<p>Sydell graduated Magna Cum Laude with a bachelor\'s degree from William Smith College in Geneva, New York, and earned a J.D. from Yeshiva University\'s Cardozo School of Law.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/Sydell', 'https://www.npr.org/people/2101272/laura-sydell', '', '', '0', '1524246460', NULL, NULL),
(313, 'Cesar & Lois', 'cesar-lois', 'http://codame.dreamhosters.com/uploaded_images/cesar-lois.jpg', '<p>Cesar &amp; Lois posit new systems that integrate natural and technological networks. In their various bodies of work, Cesar Baio (cesarbaio.net) subverts the algorithms of autonomous systems, while Lois (imaginaryscience.org) infuses art with nature&rsquo;s data. Together they create fungal systems that tweet and posit nature-based economies. Cesar &amp; Lois is comprised of a collective with a collective. Lois refers to The League of Imaginary Scientists, an artist group that creates digital intermediaries with nature, often as interactive object-based experiences. For &ldquo;Degenerative Cultures,&rdquo; Lois artists Lucy HG Solomon and Jeremy Schwartz collaborated with Brazilian artist/theorist Cesar Baio. Cesar Baio&rsquo;s work invites viewers to renegotiate their interactions within systems, challenging the systems&rsquo; inherent logic models. Cesar &amp; Lois nurture bhiobrid cultures, ranging from the fungal colonization of books to microbiological mappings, with the objective of learning from the overlapping patterns of human-based knowledge and the wisdom of nature&rsquo;s growth algorithms. Works by Cesar &amp; Lois have exhibited at Generative Art at the Ravenna Art Museum in Italy and the L.A.S.T. Festival at the SLAC National Accelerator Laboratory at Stanford. Cesar &amp; Lois acknowledge the contributions of biologist Scott Morgans, undergraduate researcher Kodie Gerritsen and Professor Sandra Doller\'s Literature &amp; Writing Studies 325 Creative Writing Workshop at California State University San Marcos in the development of &ldquo;Degenerative Cultures&rdquo; for CODAME.</p>', '', 'http://www.imaginaryscience.org', '', '', '0', '1528236232', NULL, NULL),
(314, 'Noa Kaplan', 'noa-kaplan', 'http://codame.dreamhosters.com/uploaded_images/noa-kaplan.jpg', '<p>Noa P. Kaplan is an artist, researcher, and educator based in Los Angeles. She analyzes and reconstructs overlooked, disappearing, and forgotten collections. Through virtual simulations, physical artifacts, and environments, she invites viewers to inhabit these collections, often at unfamiliar orders of magnitude.â€‹ Noa has exhibited recent work at Ars Electronica, ACME. Gallery, and the Hammer Museum. She has participated in residencies and fellowships at IDEO, Autodesk, Electric Objects, and Eyeo and her work has been featured in Business Insider, Wired Magazine, Discovery VR, and the Huffington Post. Noa has taught as a Lecturer in the School of Arts and Architecture at UCLA since 2012 and is currently an Annenberg Fellow in the School of Cinematic Arts at USC.</p>', 'https://twitter.com/nokap', 'http://www.noapkaplan.com', '', '', '0', '1563896235', NULL, NULL),
(316, 'Pierluigi Dalla Rosa', 'pierluigi-dalla-rosa', 'http://codame.dreamhosters.com/uploaded_images/pierluigi-dalla-rosa.png', '<p>Pierluigi is a designer and researcher who has been working at the intersection between industry and institutions creating innovative and engaging interactive products and media pieces.</p>\r\n<p>He chases in his work the convergence of nature and synthetic systems and he is constantly refining his process of including the natural in the technological; this process involves thoughtful stimulation of human senses, inducing suspense and magic using tools like animation, coding, physical computing and photography.</p>\r\n<p>Pierluigi is the developer of Tramontana and libreTSPSWP, open source tools for prototyping environments and interactive objects; these tools are used in different workshops at Strelka Institute in Moscow, the Copenhagen Institute of Interaction Design.</p>\r\n<p>He is currently part of the design team of NIO, inventing new solutions in the world of transportation. He holds a master degree in Cinema and Media Engineering from Politecnico di Torino and a double degree from the excellence program Alta Scuola Politecnica. He is an alumni of the Interaction design program at CIID.</p>\r\n<p>&nbsp;</p>', '', 'http://www.pierdr.com', '', '', '0', '1528126211', NULL, NULL),
(317, 'Duri Long', 'duri-long', 'http://codame.dreamhosters.com/uploaded_images/duri-long.jpeg', '<p>Duri Long is a third year Human Centered Computing Ph.D. Student at Georgia Tech. She has a background in computer science and performance art. Her work has involved investigations into embodied movement AI and installation design/evaluation.</p>\r\n<p>Duri\'s current research interests lie at the intersection of creativity and computation. She builds and studies interactive technological systems that bring people joy and help them create together.</p>\r\n<p>Duri previously studied at UNC-Chapel Hill, where she received a BS in Computer Science with a second major in Dramatic Art. At UNC-CH, her research explored performance art for social change and computer-supported cooperative learning. Duri\'s previous professional experience includes working as a software developer, a performance artist, and a producer.</p>\r\n<p>Duri is one of the lead artists for the LuminAI project. She is a member of the Adaptive Digital Media (ADAM) Lab at Georgia Tech. The ADAM Lab explores questions that center on cognition, creativity, and computation through the study of creative human endeavors and by building public-facing digital media artifacts representing their findings. Applications of the ADAM Lab\'s findings range from AI-based digital performance to interactive narrative experiences to educational media. Their work has been shown internationally at galleries, museums, and conferences, and collectively the ADAM lab members have authored over 70 peer-reviewed articles related to cognition, creativity, computation, music technology, and installation design.</p>\r\n<p>&nbsp;</p>', 'http://twitter.com/duri_long', 'http://www.durilong.com/', '', '', '0', '1524769254', NULL, NULL),
(318, 'Brian Magerko', 'brian-magerko', 'http://codame.dreamhosters.com/uploaded_images/brian-magerko.jpg', '<p>Dr. Brian Magerko is a Professor of Digital Media in the School of Literature, Media, and Culture and a Human-Centered Computing faculty member in the School of Interactive Computing at Georgia Tech.</p>\r\n<p>He earned a B.S. in Cognitive Science from Carnegie Mellon University and a Ph.D. in Computer Science and Engineering from the University of Michigan. He taught as Assistant Professor in Digital Games at Michigan State University before joining the Georgia Institute of Technology in 2008.</p>\r\n<p>Dr. Magerko&rsquo;s work intertwines cognitive science, computer science, and computational media research, focusing on three concerns: a) better understanding social collaboration and creativity between humans and artificial intelligence; b) designing and developing computational media experiences that inform and/or entertain; c) using personal expression as a means of engaging the public&mdash;especially underrepresented populations&mdash;in computing. His study of creativity includes developing better formal representations of human creative socio-cognitive processes, and designing and developing technologies that represent and accommodate those processes.&nbsp;&nbsp;</p>\r\n<p>Highlights of this work include:</p>\r\n<p>&middot;&nbsp; &nbsp; &nbsp; The design and development of an internationally-used STEAM (science, technology, engineering, art, and mathematics) learning environment for learning computer programming through making music with computer code. EarSketch has been widely adopted across all 50 U.S. states, has over 140,000 users, and has been empirically shown to increase positive attitudes towards computing, especially in students from underrepresented populations.</p>\r\n<p>&middot;&nbsp; &nbsp; &nbsp; The advancement of computational media research, which has yielded new software technologies, design practices, and embodied computational media experiences centered on creative expression and computing.</p>\r\n<p>&middot;&nbsp; &nbsp; &nbsp; The design and development of multiple collaborative works with graduate and undergraduate students. These interactive installations focus on co-creative experiences (i.e., collaborative, improvisational meaning-making between humans and/or computers) that have been accepted to festivals and museums such as the ACC Creativity and Innovation Festival at the Smithsonian, the ArtScience Museum of Singapore, and the MoogFest music technology festival.</p>\r\n<p>&middot;&nbsp; &nbsp; &nbsp; Multiple studies of the socio-cognitive processes of creativity during improvisation, which has introduced new theories of human cognition and empirical tools for quantifying creativity at an individual and social level.</p>\r\n<p>&middot;&nbsp; &nbsp; &nbsp; Foundational work in the use of drama management and artificial intelligence within interactive narrative experiences.</p>\r\n<p>Dr. Magerko\'s research has significantly advanced scholarship in his field as evidenced by academic publications (&gt; 100 peer reviewed publications in peer-reviewed technical conferences and journals), multiple keynote presentations and top paper awards, and federal grant support (&gt; $10 million in federal funding). His research has also yielded computational media artifacts in the form of software and interactive installations that have been featured in museums, schools, and other learning settings worldwide.</p>\r\n<p>&nbsp;</p>', 'http://twitter.com/thatmagerko', 'https://sites.google.com/view/magerko/home', '', '', '0', '1524678715', NULL, NULL),
(319, 'Praba Pilar', 'praba-pilar', 'http://codame.dreamhosters.com/uploaded_images/praba-pilar.jpg', '<p>Praba Pilar is a diasporic Colombian artist disrupting the overwhelmingly passive participation in the contemporary &lsquo;cult of the techno-logic.&rsquo; Over the last two decades Pilar has presented cultural productions integrating performance art, street theatre, invisible theatre, electronic installations, radio programming, digital works, video, websites and writing. These projects have traveled widely to museums, galleries, universities, performance festivals, conferences, public streets, political meetings, bookstores, bars, and radio airwaves around the world.</p>\r\n<p>Shaped by resistance to the colonial project throughout the Americas, Pilar focuses her solo practice on projects challenging complex state/corporate systems of control, domination and death. She is also embarked on an all-encompassing post-human/microbiomial multi-species journey with Anuj Vaidya titled Larval Rock Stars; is working with Ignacio Valero on a digital humanities initiative, and collaborates extensively on one time events. Some of the artists and scholars she has worked with include Alex Wilson, Balitronica Gomez and Pocha, John Jota Leanos, Rene Garcia, Erika Hannes, Larry Bogad, Adam Zaretsky, Freya Olafson, Mia S. van Leeuwen, Theo Pelmus, Luna, Lyndsay Ladobruk, Martin Franco and various photographers and videographers who have helped document her work. She is immeasurably helped by Janet Sarson on numerous aspects of her practices.</p>\r\n<p>Pilar is the recipient of numerous awards, including a Post-Doctoral Fellowship in Digital Humanities and New Media with the Hub for Innovative Exchange at the University of Winnipeg, the UC Davis Presidential Pre-Doctoral Fellowship, the Puffin Foundation Award, the Creative Capital Award, the Creative Work Fund Award, and the Potrero Nuevo Fund Award and two nominations for a Rockefeller Award.&nbsp; Her most recent writing has been featured in Performance, Religion and Spirituality; ROAR; Feminist &amp; Scholar Online; Lateral Journal of the Cultural Studies Association, Women\'s Eco Artists Dialogue; Dance Current, KATALOG, localflux, and h+Magazine. She has co-written and solo authored book chapters dating back to 2001. Her work has been written about in journals and books, and she was featured in a book on inspirational women by Cathleen Rountree, On Women Turning Thirty: Making Choices, Finding Meaning (2000).</p>\r\n<p>Pilar has a PhD in Performance Studies, with designated emphases in Studies in Performance Practice as Research and in Feminist Theory and Research from the University of California, Davis; a Bachelor of Arts in Intermedia Arts from Mills College; studied Max/MSP/Jitter with Bob Ostertag at UC Davis; took workshops in electronic circuitry and PureData programming with artists Ken Gregory and Andy Rudolph, and electronics principles with artist Andrew Milne at Video Pool in Winnipeg. In much earlier chapter of life, she studied economics, political science and development at NYU for three years.</p>', '', 'https://www.prabapilar.com/', '', '', '0', '1524769716', NULL, NULL),
(320, 'Eryk Salvaggio', 'eryk-salvaggio', 'http://codame.dreamhosters.com/uploaded_images/eryk-salvaggio.png', '<p>Eryk Salvaggio is responsible for Research &amp; Content Strategy for swissnex San Francisco, which connects people and ideas from Switzerland to the Bay Area and beyond. Eryk is an internet artist whose work was covered in The New York Times and NBC News. He serves as a program manager for swissnex San Francisco\'s Pier 17 Science Studio, where he is focused on communicating insights from the intersections of art, science, and technology.&nbsp;</p>', 'http://twitter.com/e_salvaggio', '', '', '', '0', '1525473674', NULL, NULL),
(321, 'Remixed Ink', 'remixed-ink', 'http://codame.dreamhosters.com/uploaded_images/remixed-ink.jpg', '<p>Remixed Ink started in 2008 when artists + designers Christopher Breedlove &amp; Tobias Paquet decided to combine their distinct design aesthetics + love for live screen printing.&nbsp; Since then Remixed Ink has been booked at Conferences, Music Festivals, Private Events, Art Galleries and more.</p>\r\n<p>Providing a fresh take on the live printing technique Remixed Ink is a mixture of Art Installation, Performance Art and Interactive Educational Resource. Focusing on quality experience over factory-like turn around, our printers provide a unique one-on-one printing experience. We tap into each individuals personal creative juices to drive the experience resulting in a wearable piece of art; guaranteed to leave lasting impressions for your brand or event.&nbsp;</p>\r\n<p>Providing everything needed for a clean, fun, and memorable screen printing experience, Remixed Ink prides itself on professional service, quality printing, and epic designs.</p>\r\n<p>Remixed Ink has been featured at:&nbsp; Oracle OpenWorld, Red Bull Red Mondays, Lollapalooza, Symbiosis, InfraSound, High Sierra Music Festival, Brooklyn Boulders + more!</p>\r\n<p><img src=\"/uploaded_images/screens_2.jpg\" alt=\"\" /></p>', '', 'http://www.mrbreedlove.com/remixed-ink/', '', '', '0', '1526965269', NULL, NULL),
(322, 'VaZa', 'vaza', 'http://codame.dreamhosters.com/uploaded_images/vaza.jpg', '<p id=\"yui_3_17_2_1_1525905224928_160\">I&rsquo;m VAZA --&nbsp;mom, wife, yoga instructor, traveler, free spirit, mostly sleep deprived and usually over caffeinated.</p>\r\n<p>I&rsquo;m a believer in love, freedom, delicious food and that we are all connected with each other. And I&rsquo;m here to support you on your postpartum journey.</p>\r\n<p>As moms, we try to do it all, to be there for everyone, be everything for everyone, but along the way we forget to take care of ourselves -- which in return doesn&rsquo;t serve anyone.</p>\r\n<p>Does this sound familiar to you? Mornings don&rsquo;t have structure; you&rsquo;re rushing around, multitasking in a pure survival mode and routine? You are just trying to meet ends while also dealing with low energy and lack of physical and emotional strength.</p>\r\n<p>But you would rather be a calm, healthy and compassionate role model for your kids, who would like to bring back the play and fun into your life?</p>\r\n<p>I felt all of this. I have been there.</p>\r\n<p>After I gave birth to my daughter, I felt completely disconnected to my body. I had no control over my pelvic floor (peed my pants when I sneezed, laughed or coughed), I also had a big gap between my rectus abdominis also called diastasis recti, and I couldn&rsquo;t identify at all with my new body after birth. My OBGYN wasn&rsquo;t a big help either, &nbsp;so I decided to help myself to recover my body and mind. My expertise in Yoga and Occupational Therapy surely helped a lot, but I had to dig even deeper to truly understand the anatomy of the pelvic floor and why the diastasis recti didn&rsquo;t heal in my case on its own. I did lots of research, watched endless videos, talked to midwives and found a great pelvic floor specialist to help me restore my body and mindset. After three years I finally feel home in my body again. The whole experience helped me reconnect with myself again and made me who I am today.</p>\r\n<p>To save other women from the same experience, I am creating prenatal and postpartum online classes to support women on their journey.</p>\r\n<p><br />With my expertise in yoga and OT, nutrition and holistic approach to the human body, I made it my mission to guide you through your own personal transformations to restore your health, &nbsp;rebuild self-confidence, culture positive body image and have a mindful awareness of the strengths we all have inside.</p>\r\n<p>After all, there\'s a Wonder Woman in each of us, and the only thing holding us back is our own limiting beliefs. By connecting the mind, body &amp; soul through conscious awareness, I provide changes that will last a lifetime with the perfect blend of physical activity, spiritual healing, and nutritional support to address the rising needs and concerns of working moms today.</p>\r\n<p>Let&rsquo;s do this together.</p>\r\n<p>Love, VAZA</p>', '', 'http://www.vazayoga.com/', '', '', '0', '1527722740', NULL, NULL),
(323, 'PrzemysÅ‚aw Jasielski', 'przemys-aw-jasielski', 'http://codame.dreamhosters.com/uploaded_images/przemys-aw-jasielski.jpg', '<p>PrzemysÅ‚aw Jasielski (born 1970), artist, researcher, experimenter based in Poznan, Poland combining art with science and technology. Member of HAT Research Center at Adam Mickiewicz University. He creates installations, objects, drawings and photographs.</p>\r\n<p>In the creative process he approaches work with the attitude of an engineer, adapting the precise planning and scientific research, with the main focus on the conceptual content.&nbsp;</p>\r\n<p>Many of these works explore rituals of the everyday reality taking up a specific game with the imagination and wisdom of a viewer, with his habits shaped by daily routine of the contemporary world and his own presence in it. Most of them are both in close relation to the space and interactive &ndash; the spectator is allowed to play with them or even to change their shape. His works confront the actual present reality with its transformation to allow the viewer to observe it in a new, fresh way. They often try to take actions commonly seen as impossible, useless or ineffective. Also, they usually contain a specific, critical sense of humour.&nbsp;</p>\r\n<p>Jasielski took part in several exhibitions all over the world &ndash; among others, one man shows such as Paper Bridge Over Stone Water at Tokyo Wonder Site (Tokyo, Japan, 2012), Analog Immigration at CSU Galleries (Cleveland OH, USA, 2013), and group shows - Apparat. Retrogression Through Technological Progress at The Sculpture Center (Cleveland OH, USA, 2016), L&rsquo;arte differente: MOCAK al MAXXI at MAXXI (Rome, Italy, 2016), Draft Systems at WRO Media Art Biennale 2017 (Wroclaw, Poland, 2017), Nonsense Technologies (Krakow, Poland, 2017).</p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"/uploaded_images/Oracle_01.jpg\" alt=\"\" /></p>\r\n<p><strong>Artificial Unintelligence. Stubborn Machines and Sneaky Robots.</strong></p>\r\n<p>Since 2015, in a series of artworks (Emotions Control Unit, Photo Robotoid, Oracle), I conducted several experiments on Human-Robot Interaction. I was trying to test an experience of people jumping right into a relationship with artificial beings, even if they behave in an unexpected way. We are about to entrust their actions more than ourselves. We begin to treat them as individual beings with their own rights, and analyse their feelings. Yet, their social intelligence is only simulated by the program and does not reciprocate human&rsquo;s emotions.</p>\r\n<p>Critics call robots as &ldquo;relational artifacts&rdquo;: designed to work on producing our emotions towards them, that may be not yet recognised. Even by now they are obscured, artificial and one-way, which makes us wonder if they are psychologically satisfying.&nbsp;</p>\r\n<p>Technology becomes unseen, and makes us modify our behaviour to match it up.&nbsp;</p>\r\n<p>In my view, art should question consequences of enhancing technological development. I found out that my own idea passes with a very current research of Meredith Broussard. In her book \"Artificial Unintelligence\", she calls us to set limits of letting technology steer our lives. This concept appears to be the clue of my point of view on implementing technology into our existence. Our will to load most of everyday jobs and activities on robots, drives us to bring-in foolish technology massively. We don&rsquo;t control how it exactly works anymore, and whether it&rsquo;s proficient in the exact needed way.</p>\r\n<p><img src=\"/uploaded_images/Photo_Robotoid_04.jpg\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '', 'http://www.jasielski.com', 'przemoj@zero2.pl', '', '0', '1526069117', NULL, NULL),
(324, 'Jorge Stamatio ', 'jorge-stamatio', 'http://codame.dreamhosters.com/uploaded_images/jorge-stamatio.jpg', '<p>Born in Mexico with a quarter Greek in the genes, Jorge Stamatio has lived in Lausanne, Switzerland since 2006. Jorge is a creative hacker who has taught himself some computer languages (and dialects), web development, photography, and coffee brewing. The life lessons that have come from being the Head of Technology at Mental Work, tackling the technological (and practical!) challenges of breaking that Art and Science sound barrier for the first time (and there have been a lot of firsts!) have greatly improved his coffee brewing techniques.</p>', '', '', '', '', '0', '1526076131', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(325, 'Kitty Yeung', 'kitty-yeung', 'http://codame.dreamhosters.com/uploaded_images/kitty-yeung.jpg', '<p>Kitty Yeung is a physicist, artist, maker, fashion designer and musician based in Silicon Valley, California. She currently works as a creative technologist and senior program manager at the Garage, Microsoft.</p>\r\n<p>Kitty&rsquo;s earlier career had been focused on hardcore scientific research and academic training while pursuing artistic endeavors through painting, music and graphic novel creations. It has been her dream since childhood to work in the three intellectual fields: science, music and art. Being a scientist, she also experienced how arts influence people culturally and how different fields inspire each other.</p>\r\n<p>After finishing her PhD in Applied Physics from Harvard University and conducting research at Intel, Kitty found the perfect way to integrate art/design with science/technology via tech-fashion design. Her work focuses on applying cutting-edge technologies to both garments and manufacturing processes.</p>\r\n<p>Talk:</p>\r\n<p><strong>Tech-Fashion Designs and the Wearables Industry</strong></p>\r\n<p>With the development of open-source hardware, fashion designers and creative technologists have started to include electronics as part of their designs, adding decorative and/or functional elements to garments. Driven by creative designs, the industry has tremendous opportunities but also faces significant challenges in scaling and scientific research. This talk gives an overview of the wearables industry with demos of programmable garments and discusses a few ideas for future development through automation.&nbsp; &nbsp;&nbsp;</p>\r\n<p>&nbsp;</p>', '', 'https://artbyphysicistkittyyeung.com/', '', '', '0', '1526315053', NULL, NULL),
(326, 'Ashes Monroe ', 'ashes-monroe', 'http://codame.dreamhosters.com/uploaded_images/ashes-monroe.jpg', '<p>Ashes Monroe is a Technologist, Researcher, Designer and Artist interested in memory, ritual, existential questioning, and pushing the perceived limits of our humanity.&nbsp; She currently works with several performance &amp; art groups that blend the usage of technology, theater, immersive experience and circus arts.&nbsp; WitchTech and its performances are an exploratory response to the contextually contradicted law from Arthur C. Clarke that \"Any sufficiently advanced technology is indistinguishable from magic.\" wherein technology and ritual are intertwined and blended to further confuse the semantic limits of both.</p>', '', 'http://www.witchtek.com/', 'info@figure8labs.com', '', '0', '1526350671', NULL, NULL),
(327, 'Benjamin Newman', 'benjamin-newman', 'http://codame.dreamhosters.com/uploaded_images/benjamin-newman.jpg', '<p>Benjamin Newman reimagines vintage industrial parts by placing them in dynamic sculptural settings. Most of his pieces began their journey on the open road where early engineers demonstrated their own artistic vision. Fragments of their work are given the chance to live again in these sculptures, albeit in a newly cast order.&nbsp;&nbsp;</p>\r\n<p>Now residing in Northern California, Benjamin learned his craft while foraging for parts in the historic cities of Boston, Providence, and New York. At the time, searching junkyards had more to do with maintaining mobility than artistic expression. Now, he seeks to highlight the beauty of nature by subjecting mans creation to the forms which preceded us.&nbsp;</p>\r\n<p>&nbsp;</p>', '', '', 'bjn2020@gmail.com', '', '0', '1563863948', NULL, NULL),
(359, 'Jiabao Li', 'jiabao-li', 'http://codame.dreamhosters.com/uploaded_images/jiabao-li.jpg', '<p>Jiabao Li works at the intersection of emerging technology, art and design. Her work opens questions about technology\'s influence on human perception, identity, and emotion. Her research-based projects range from wearables, projections, drones, installations to scientific experiments. She holds a Master of Design in Technology degree with Distinction from Harvard GSD. Jiabao\'s work has been featured in Domus, TechCrunch, Yahoo, CCTV, Yanko Design. Her work has been shown in Milan and Dubai Design Week, ISEA, CHI, SIGGRAPH, AR in Action, and PRIMER. She is the winner of Core77, FastCoDesign, iF Design Award, Future Cities Contest, and ISWC Design Award.</p>', 'https://twitter.com/6yao', 'https://www.jiabaoli.org/', '', '', '0', '1586324412', NULL, NULL),
(331, 'Zaza', 'zaza', 'http://codame.dreamhosters.com/uploaded_images/zaza.jpg', '<p>Zaza is a designer of interactive spaces, objects and systems. She is currently Lead Designer at Tellart, an Experience Design agency, for whom she worked on several award winning projects.&nbsp;</p>\r\n<p>Her favourites include: the Museum of the Future, an interactive exhibition that immerses its visitors in near term future visions; S7 Imagination Machine, where people fly a virtual airplane with the power of their brain; Moral Machine, an installation at World Economic Forum questioning the role of AI in governance.&nbsp;</p>\r\n<p>In her spare time she loves to dabble into the related fields of technology arts and crafts, with emphasis on bridging the physical and the virtual.</p>\r\n<p>&nbsp;</p>', '', '', 'zazazuilhof@gmail.com', '', '0', '1528126163', NULL, NULL),
(332, 'Yiyue Chen_iota', 'yiyue-chen-iota', 'http://codame.dreamhosters.com/uploaded_images/yiyue-chen.jpg', '<p>Yiyue Chen, iota to friends, is a Architect&nbsp;// Artist // Virtual Space constructor&nbsp;// NFT community BUIDL.&nbsp;<br /><br />Yiyue grew up in a property developer&nbsp;family. An early exposure to design and build environments spurred Yiyue&rsquo;s initial interest in architecture. As a witness of fast urbanism in China,&nbsp;she&nbsp;is fascinated how urban typology adapts and evolves based on political, cultural and economic factors. Yiyue Chen\'s Master&rsquo;s thesis, TENACITY, has been featured in The_Best_New_Architects, Archisource Digital Magazine, and more.</p>', 'https://twitter.com/IothaP', 'https://www.linkedin.com/in/yiyue-chen-3b88a79a/', '', '', '0', '1630195176', 'https://paras.id/iotha.near/creation', 'https://www.instagram.com/ycppi/'),
(334, 'Cere Davis', 'cere-davis', 'http://codame.dreamhosters.com/uploaded_images/cere-davis.jpg', '<p>Cere Davis is a science-artist, kinetic sculptor and science educator based in the bay area of California. She has a degree in Physics from the University of Alaska, Fairbanks and early career working in scientific fields ranging from volcanic lighting to liquid crystals to research at the South Pole station of Antarctica. Her past work influences her current art work bridging the the worlds of interactive art, kinetic sculpture creating new media which foregrounds tactile and physical relationships directly through analog means.&nbsp; Through her cross-disciplinary work she reveals hidden dynamics and material response which emerge from unseen forces present in our everyday world.&nbsp; As a part of her work she collaborates with scientists and artists to inspire scientific curiosity and participatory learning through interactive art and critical making.&nbsp; She is the artistic director at Counter Culture Labs, Artist in Residence in Chabot Space &amp; Science Center, and member of the Thingamajigs performance group.&nbsp; She produces, collaborates and participates in projects ranging from dance performance to science fairs and art exhibits. Her works have shown in galleries, science festivals, conferences and public outreach events internationally. She has been awarded the People\'s Choice award in 2015 at Oakland Aeolian Day for her acousto-kinetic sculpture and in 2018 by the Awesome Foundation for her opto-kinetic sculpture, Liquid Loom.</p>\r\n<p>Through her exhibits, lectures and exploratory research, Cere shifts our normative utilitarian frame of reference by finding hidden affordances inherent in materials common to our everyday experience.&nbsp; Her practice stems from an interest in revealing what is hidden in plain sight and re-connecting seemingly disparate realms which broaden our normative utilitarian view of nature.&nbsp; Her work are best described as a form of neonaturalism, whereby inherent material properties are re-contextualized to reveal their natural response to surroundings.&nbsp; She aims to inspire creative learning through her interactive exhibits and offer a refreshing counterbalance to our increasingly isolating and sterile urban environments.</p>', '', 'http://www.ceredavis.com', '', '', '0', '1539801107', NULL, NULL),
(335, 'Matthias DÃ¶rfelt', 'matthias-d-rfelt', 'http://codame.dreamhosters.com/uploaded_images/matthias-d-rfelt.jpeg', '<p>Matthias D&ouml;rfelt (1987, Hamburg, Germany) is a Los Angeles-based artist. He mainly works in software producing artifacts ranging from drawings, prints, animation, videos and interactive installations to robotics. In his works he often trades control in favor of surprise because he strongly believes in computation as an expressive, playful and humorous tool. Matthias will continue to explore these aspects by infusing technology with flaws, naivety and weirdness. He believes in a media arts practice that favors spontaneity over streamlining and hopes that his works contribute to shape our relationship to machines in a similar way.</p>\r\n<p>Matthias studied at the Muthesius Kunsthochschule in Kiel and holds a Masters of Fine Arts from the University of California in Los Angeles.</p>\r\n<p>This artist is supported by the Lumen Prize and Leonardo/ISAST.</p>\r\n<p>&nbsp;</p>', '', 'https://www.mokafolio.de/', '', '', '0', '1539548220', NULL, NULL),
(337, 'Jiayi Young', 'jiayi-young', 'http://codame.dreamhosters.com/uploaded_images/jiayi-young.jpg', '<p>Jiayi Young is an Assistant Professor of Design at the University of California, Davis. Her inquiries lie within the emergent and experimental field of digital media with an emphasis on the cross-disciplinary areas of design that integrates the arts, the sciences with cutting-edge technology. Her current research and creative work are focused on constructing data-driven sensor-enabled interfaces, installations, real-time projection graphics, participatory performances, and immersive environments in cultural and public places with a goal of creating generative energy to engage the public in social dialogue. Using multidisciplinary approaches, her work examines contemporary society including the culture of consumption, the programming and exploitation of the feminine, cultural assimilation, and personal identity. Leveraging social media, crowd-sourced media, and user-created content, she sets up scenarios and creates conditions to make a visible empathetic relationship between people in the presence of contemporary culture. Her work invites the public to participate to come in close contact with an experience that engages the rethinking of the human condition.</p>\r\n<p>Young has published and exhibited nationally and internationally, including Ars Electronica, the International Symposium of Electronic Art (ISEA); the Leonardo Electronic Almanac (LEA); Hall of Science, New York; the United Nation&rsquo;s Fourth Conference on Women, Beijing, China; the Hermitage Museum, St. Petersburg, Russia; and Moltkerei Werkstatt, Cologne, Germany.</p>\r\n<p>This artist is supported by Leonardo/ISAST.&nbsp;</p>\r\n<p>&nbsp;</p>', '', 'https://www.jiayiyoung.info/', '', '', '0', '1539548556', NULL, NULL),
(338, 'Chris Henschke', 'chris-henschke', 'http://codame.dreamhosters.com/uploaded_images/chris-henschke.jpg', '<p>Chris Henschke is an artist who works with digital and analogue media, sound and light, and high-energy physics. Since the end of the 20th Century, he has been exhibiting around Australia and internationally. A key component of his practice is in interdisciplinary and collaborative projects, and he has undertaken a variety of art residencies, including an online artist residency at the National Gallery of Australia, 2004, an Asialink residency, 2007, and two residencies at the Australian Synchrotron, both made possible by the Australian Network for Art and Technology (ANAT) with the support of Arts Victoria (2007) and the Australia Council for the Arts (2010).</p>\r\n<p>He has recently completed a Doctorate of Philosophy at Monash University, which included on-site work at the European Organisation for Nuclear Research (CERN), Switzerland, as part of the &lsquo;art@CMS&rsquo; collaboration. Exhibitions of the work he has produced at CERN include the following: &lsquo;How Everything Began&rsquo; a group show at the Natural History Museum, Vienna, Austria, 2016; the &lsquo;Symmetries&rsquo; group show at the &lsquo;SUSY&rsquo; conference on supersymmetry in particle physics at the University of Melbourne, 2015, which he produced and curated; &lsquo;Circulez&rsquo;, on site at the European Organisation for Nuclear Research (CERN), Switzerland.</p>\r\n<p>&nbsp;</p>', '', 'http://henschke2010.anat.org.au/', '', '', '0', '1540272673', NULL, NULL),
(339, 'Sean Mulholland', 'sean-mulholland', 'http://codame.dreamhosters.com/uploaded_images/sean-mulholland.jpg', '<p>Sean is fascinated by the ways the internet acts as both a conduit and a medium for stories, ideas, and culture. He loves to think about human computer interaction and how technology affects human to human interaction.&nbsp;</p>\r\n<p>At IDEO his work focuses on user experience, product design, and strategy, where he researches and prototypes how emerging technologies can be leveraged in ways that are human-centered. He writes code by hand but went to art school and holds a BFA. His personal work has been exhibited in the US+UK and published in The New Yorker.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/Illah', 'https://sean.digital/', '', '', '0', '1538498237', NULL, NULL),
(340, 'Yasushi Matsui', 'yasushi-matsui', 'http://codame.dreamhosters.com/uploaded_images/yasushi-matsui.jpg', '<p>Born in Oregon, US, raised in Shizuoka, Japan, and currently based in Oakland, California.&nbsp;</p>\r\n<p>Yasushi Matsui has been seeking an expression of Live Painting through painting at a number of events and festivals, and collaborating with different styles of various artists. Alongside, he stays active by joining group exhibitions, providing illustrations, painting murals, and collaborating with fashion brands.&nbsp;</p>\r\n<p>In late 2013, He started the project, &ldquo;EToOto&rdquo;, to explore a new form of a unity through painting with sound by using the technology. He produced videos, &ldquo;onnon (2014) and &ldquo;OnNoN in Spectrum scale&rdquo; (2016), and performed with Dakim and Tamura Fumitake (Bun) along their Japan tour in 2014, and at the experimental beat event, Smart Bomb in Oakland, California. Recently he shared DIY programs and tutorial videos on online for people to experiment with his ideas, and a new demo performance video, \"oNnOn in RGB\".</p>\r\n<p>&nbsp;<iframe src=\"//www.youtube.com/embed/7vAYdQPdbFU\" width=\"425\" height=\"350\"></iframe></p>', '', 'http://yenatdollar.net/', '', '', '0', '1543274503', NULL, NULL),
(341, 'Ryan Huber', 'ryan-huber', 'http://codame.dreamhosters.com/uploaded_images/ryan-huber.png', '<p>Ryan Huber creates audio and visuals for dance groups in the Bay Area, including UC Berkeley, Mills College, Project Agora, Little Seismic Dance Company, USF and Lick Wilmerding. Hidden among surreal music videos on his YouTube channel is a short-film tone-poem about sea life surrounding the Farallon Islands, which he made in collaboration with Remora. He plays drums in the San Francisco band Battlehooch.&nbsp; &nbsp; &nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '', '', '', '', '0', '1538756263', NULL, NULL),
(342, 'Dylan Chapple', 'dylan-chapple', 'http://codame.dreamhosters.com/uploaded_images/dylan-chapple.jpg', '<p>Dylan Chapple holds a PhD in Environmental Science, Policy and Management from UC Berkeley with an emphasis on tidal wetland restoration. He has made music that explores the relationship between humans, nature and sound as a member of the bands VVD WNDWS, Pine and Swanifant.&nbsp;&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '', '', '', '', '0', '1538756383', NULL, NULL),
(343, 'Angela Ferraiolo', 'angela-ferraiolo', 'http://codame.dreamhosters.com/uploaded_images/angela-ferraiolo.jpg', '<p>Angela Ferraiolo is a visual artist working with adaptive systems, noise, randomness, and generative processes. Her work has been screened internationally including Nabi Art Center (Seoul), SIGGRAPH (Los Angeles), ISEA (Vancouver, Hong Kong), the New York Film Festival (New York), Courtisane Film Festival (Ghent), the Australian Experimental Film Festival (Melbourne), and the International Conference of Generative Art (Rome, Venice). New projects include further experiments in systems, urban screen, generative art, and ambient media.&nbsp;</p>', '', 'http://littleumbrellas.net/', '', '', '0', '1539589046', NULL, NULL),
(345, 'John Shiurba', 'john-shiurba', 'http://codame.dreamhosters.com/uploaded_images/john-shiurba.jpg', '<p>John Shiurba is a composer and guitarist whose musical pursuits include improvisation, art-rock, modern composition and noise. Shiurba has recorded and toured the U.S. and Europe as a member of the bands Eskimo, The Molecules and Spezza Rotto, as a member of the Merce Cunningham Dance Company, Anthony Braxton\'s ensemble and the SFSound Group, and as an improvisor.</p>\r\n<p>Shiurba has conducted the premieres of his compositions at ODC in 2005 (\"Moon Cycle\" for SFSound) at New Langton Arts in 2002 (\"Triplicate\") and at SFAlt in 2002 (\"5x5 1.4\" for SFSound). Shiurba was invited to play at the Seattle Improvised Music Festival in 1998, at the High Zero Festival in Baltimore in 1999, at the SFAlt Festival in 2004 and at the Olympia Experimental Music Festival in 2002 and 2004, and at the Push International Performing Arts Festival in Vancouver in 2007.<br />As a guitarist Shiurba has developed a unique and personalized approach to the guitar. Through the use of extended techniques and unusual preparations, he expands the traditional sound range of the instrument, producing stunning, often unrecognizable results. Cadence Magazine calls Shiurba a \'wildly creative guitarist... anti-jazz, anti-everything else, yet utterly compelling.\'</p>\r\n<p>&nbsp;</p>', '', 'http://www.shiurba.com/', '', '', '0', '1539588333', NULL, NULL),
(346, 'Steven J. Oscherwitz', 'steven-j-oscherwitz', 'http://codame.dreamhosters.com/uploaded_images/steven-j-oscherwitz.png', '<p>Steven J. Oscherwitz holds a BA in philosophy from Miami University, Oxford, Ohio, and a BFA and MFA from the School of the Art Institute of Chicago, where he also taught. He is an inventive draftsman, having produced a large body of work, which he terms architectonic studies.</p>\r\n<p>Steven has had his work exhibited in a central gallery of the Smithsonian Institution and the Art Institute of Chicago, as well as internationally.</p>\r\n<p>He has explored and studied the interrelated histories of philosophy, science, art, optics, and technology intensely while studying at the University of Chicago, the Fred Hutchinson Cancer Research Institute, and, more recently, at Stanford\'s Linear Accelerator. He has participated in the development of art/science integration at The Society for Literature, Science, and the Arts, where he has presented his art/science research on a periodic basis.</p>\r\n<p>He explores the historical and conceptual evolution of the integration of art, science, and technology, philosophy of mathematics relating it to the mainstream philosophical schematics of evolving concepts of time&mdash;related to its subjectivity, objectivity, and phenomenological and post-phenomenological visualization.</p>\r\n<blockquote>\r\n<p>&ldquo;Artists cannot be artists without being thinkers. I am, if anything, a thinker first, then an artist.&rdquo; - Steven Oscherwitz, Statement of Intent for IDSVA (2021)</p>\r\n</blockquote>\r\n<p>&nbsp;<img title=\"\" src=\"https://itsartlaw.org/wp-content/uploads/2022/11/a-picture-containing-text-colorful-fabric-descr.jpeg\" sizes=\"(max-width: 1307px) 100vw, 1307px\" srcset=\"https://i0.wp.com/itsartlaw.org/wp-content/uploads/2022/11/a-picture-containing-text-colorful-fabric-descr.jpeg?w=1307&amp;ssl=1 1307w, https://i0.wp.com/itsartlaw.org/wp-content/uploads/2022/11/a-picture-containing-text-colorful-fabric-descr.jpeg?resize=300%2C233&amp;ssl=1 300w, https://i0.wp.com/itsartlaw.org/wp-content/uploads/2022/11/a-picture-containing-text-colorful-fabric-descr.jpeg?resize=1024%2C794&amp;ssl=1 1024w, https://i0.wp.com/itsartlaw.org/wp-content/uploads/2022/11/a-picture-containing-text-colorful-fabric-descr.jpeg?resize=768%2C596&amp;ssl=1 768w\" alt=\"\" width=\"1307\" height=\"1014\" data-attachment-id=\"3171\" data-permalink=\"https://itsartlaw.org/2022/04/05/artist-feature-series-in-conversation-with-steven-j-oscherwitz/a-picture-containing-text-colorful-fabric-descr/\" data-orig-file=\"https://i0.wp.com/itsartlaw.org/wp-content/uploads/2022/11/a-picture-containing-text-colorful-fabric-descr.jpeg?fit=1307%2C1014&amp;ssl=1\" data-orig-size=\"1307,1014\" data-comments-opened=\"1\" data-image-meta=\"{\" data-image-title=\"a-picture-containing-text-colorful-fabric-descr\" data-image-description=\"\" data-image-caption=\"\" data-medium-file=\"https://i0.wp.com/itsartlaw.org/wp-content/uploads/2022/11/a-picture-containing-text-colorful-fabric-descr.jpeg?fit=300%2C233&amp;ssl=1\" data-large-file=\"https://i0.wp.com/itsartlaw.org/wp-content/uploads/2022/11/a-picture-containing-text-colorful-fabric-descr.jpeg?fit=640%2C496&amp;ssl=1\" /></p>\r\n<p style=\"text-align: center;\">Steven Oscherwitz,&nbsp;Untitled&nbsp;(2010)</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '', '', 'sjoscherwitz@gmail.com', '', '0', '1683235857', '', ''),
(347, 'Matthew Sergeant', 'matthew-sergeant', 'http://codame.dreamhosters.com/uploaded_images/matthew-sergeant.jpg', '<p style=\"text-align: center;\">The joy of imagination</p>\r\n<p style=\"text-align: center;\">Twists and turns in a design</p>\r\n<p style=\"text-align: center;\">Honing, crafting, sharing</p>\r\n<p>&nbsp;</p>\r\n<p>In 1995 Matthew Sergeant began creating experimental camera designs. The initial intention was to challenge the camera\'s status as an \'apparatus of the real\' by creating photographs free from the conventions of fixed viewpoint, geometric perspective, and split second exposure times.</p>\r\n<p>Matthew explains, \"When taking a conventional photograph, the camera occupies a fixed point in a single moment. In some respects the camera\'s mode of operation mimics visual perception. Rather than complete with the eye, much of my work explores a uniquely photographic vision, emphasizing interpretation rather than emulation.\"</p>\r\n<p>Whilst still at school Matthew worked as a news photographer before training as a carpenter and joiner. Later, he pursued undergraduate studies in Photography at the Surrey Institute of Art &amp; Design, and completed a Masters in Teaching Visual Culture, Middlesex University.</p>\r\n<p>In 2014, following a career in education teaching at College and University level, Matthew and his family relocated from the UK to Vermont. The move provided the impetus to invest time and energy in new projects one more weaving together technical, craft, and aesthetic skills in the productions of unique images. By modifying the way photographic images are made Matthew is able to find a visual space in the interplay between movement, time and perspective.&nbsp;</p>', '', 'http://www.mattsergeant.com', '', '', '0', '1540838609', NULL, NULL),
(348, 'Manu Luksch', 'manu-luksch', 'http://codame.dreamhosters.com/uploaded_images/manu-luksch.jpg', '<p>&nbsp;</p>\r\n<p>Over the past 20 years, Manu Luksch has been researching the effects of emerging technologies on daily life, social relations, urban space, and political structures. Currently, as Resident Artist at Somerset House, Open Society Fellow and visiting Fellow at Goldsmiths, University of London, she is investigating the rise of the &lsquo;Algorithmic City&rsquo;, with a focus on corporate-governmental relationships and the social effects of predictive analytics. She presents her findings through film and intermedia art, and by creating tools for other citizens. Her work is included, amongst other, in the Collection de Centre Pompidou, the BFI National Archive, and the Core Collection at the Academy of Motion Picture Arts &amp; Sciences and was awarded with Best Feature Documentary at Moscow International Documentary Film Festival 2016, Best Artivist at Elevate Festival 2015, M. v. Willemer Prize by Ars Electronica Centre and City of Linz, et al.</p>', 'https://twitter.com/ManuLuksch', 'http://www.manuluksch.com', '', '', '0', '1625532879', 'https://codame.threadless.com/collections/manu-luksch', ''),
(349, 'Refik Anadol', 'refik-anadol', 'http://codame.dreamhosters.com/uploaded_images/refik-anadol.jpg', '<p>Refik Anadol is a media artist and director born in Istanbul, Turkey in 1985. Currently lives and works in Los Angeles, California. He is a lecturer and visiting researcher in UCLA&rsquo;s Department of Design Media Arts.</p>\r\n<p>He is working in the fields of site-specific public art with parametric data sculpture approach and live audio/visual performance with immersive installation approach, particularly his works explore the space among digital and physical entities by creating a hybrid relationship between architecture and media arts with machine intelligence. He holds a master of fine arts degree from University of California, Los Angeles in Media Arts, master of fine arts degree from Istanbul Bilgi University in Visual Communication Design as well as bachelors of arts degree with summa cum laude in Photography and Video. Co-founder and Creative director at Antilop.</p>\r\n<p>As a media artist, designer and spatial thinker, Refik Anadol is intrigued by the ways in which the transformation of the subject of contemporary culture requires rethinking of the new aesthetic, technique and dynamic perception of space. Anadol builds his works on the nomadic subject&rsquo;s reaction to and interactions with unconventional spatial orientations with data and machine intelligence. Embedding media arts into architecture, he questions the possibility of a post digital architectural future in which there are no more non-digital realities. He invites the viewers to visualize alternative realities by presenting them the possibility of re-defining the functionalities of both interior and exterior architectural formations. Anadol&rsquo;s work suggests that all spaces and facades have potentials to be utilized as the media artists&rsquo; canvases.</p>\r\n<p>Privileging difference rather than singularity and movement rather than stasis, Anadol faces all the new challenges that the gradual development of an enriched immersive environment and ubiquitous computing impose on architects, media artists and engineers. How is our experience of space changing, now that digital objects ranging from smart phones to urban screens have all but colonized our everyday lives? How have media technologies changed our conceptualizations of space, and how has architecture embraced these shifting conceptualizations? These are the three main questions that Anadol tackles by not simply integrating media into built forms, but by translating the logic of a new media technology into spatial design.</p>\r\n<p>He has been given awards, residencies and has served as a guest lecturer. He is the recipient of a number of awards, prizes including Microsoft Research&rsquo;s Best Vision Award, German Design Award, UCLA Art+Architecture Moss Award, University of California Institute for Research in the Arts Award, SEGD Global Design Awards and Google&rsquo;s Art and Machine Intelligence Artist Residency Award. His site-specific audio/visual performances have been seen in Walt Disney Concert Hall (USA), Hammer Museum (USA), International Digital Arts Biennial Montreal (Canada), Ars Electronica Festival (Austria), l&rsquo;Usine | Gen&egrave;ve (Switzerland), Arc De Triomf (Spain), Zollverein | SANAA&rsquo;s School of Design Building (Germany), santralistanbul Contemporary Art Center (Turkey), Outdoor Vision Festival SantaFe New Mexico (USA), Istanbul Design Biennial (Turkey), Sydney City Art (Australia), Lichtrouten (Germany).</p>\r\n<p>To learn more abiut&nbsp;Refik Anadol read this <a href=\"https://medium.com/codame-art-tech/refik-anadols-sci-fi-utopianism-7c49c53a5cf1\">CODAME interview&nbsp;</a></p>', 'https://twitter.com/refikanadol', 'http://www.refikanadol.com', '', '', '0', '1565823014', NULL, NULL),
(350, 'Kuan-Ju Wu ', 'kuan-ju-wu', 'http://codame.dreamhosters.com/uploaded_images/kuan-ju-wu.jpg', '<p>&nbsp;</p>\r\n<p>New Media Artist, Creative Technologist, Interaction De- signer, Playful Educator.</p>\r\n<p>Kuan-Ju Wu is interested in creating delightful interactions between humans, machines, and environments. He builds kinetic sculptures and tangible in- terfaces that borrow facets from the shapes and movements of nature, from the stories about the future machines, and the perceptual memories from our early childhood, those intuitive, rich and satisfying experiences. He has shown work in such venues as Frame Gallery, Pittsburgh; Assem- ble Gallery, Pittsburgh; the Nook Gallery, Los Angeles, and Interaccio&Igrave;n I/O/I, Disseny Hub Barcelona,</p>\r\n<p>Kuan-Ju currently works as a lab manager at CITRIS Invention lab and teaches at Jacobs Institute for Design Innovation, UC Berkeley.</p>\r\n<p>Kuan-Ju Wu received his Master&rsquo;s in Tangible Interaction Design from Carnegie Mellon University, Pittsburgh, PA and his Bachelor in Electronics Engineering from National Chiao Tung University in Taiwan.</p>', '', 'https://wukuanju.com/', 'kjwu.co@gmail.com', '', '0', '1652045543', '', 'https://www.instagram.com/wu.kj/'),
(351, 'Szilvia Ruszev', 'szilvia-ruszev', 'http://codame.dreamhosters.com/uploaded_images/szilvia-ruszev.jpg', '<p>Szilvia Ruszev is media practitioner and scholar focusing on the notion of montage. Her artistic work relates to very personal moments, certain states of emotional solitude in relation to the Other. Her professional work as film editor represents a comprehensive approach to independent filmmaking with more than 30 films to her credit. Her broader research interest focuses on nonverbal forms of knowledge acquisition, montage theories, and politics of post-cinema. Szilvia, born and raised in Hungary and Bulgaria, studied Film Theory at the E&ouml;tv&ouml;s Lor&aacute;nd University (Hungary) and Film Editing at the Film University Babelsberg (Germany), where she worked as a faculty member for six years. As editor, she collaborated with internationally acclaimed directors such as Peter Greenaway, Anders &Oslash;stergaard, and J&aacute;nos Sz&aacute;sz. Her award-winning work has been part of numerous international film festivals and exhibitions such as Karlovy Vary IFF, TIFF Toronto, Berlin IFF. Currently, she is pursuing a Ph. D. degree in Media Arts + Practice at the University of Southern California.</p>', '', '', '', '', '0', '1560222855', NULL, NULL),
(352, 'Axel Cuevas Santamaria ', 'axel-cuevas-santamaria', 'http://codame.dreamhosters.com/uploaded_images/axel-cuevas-santamaria.jpg', '<p>Axel Cuevas Santamar&iacute;a received his MFA in Art &amp; Technology at The Ohio State University. He works and exhibits at various places from venues, conferences, theaters, galleries, and festivals such as the Digital Arts Biennial Brazil, Digital Graffiti Arts Festival Florida, Wexner Center for the Arts Columbus, New York Arts Magazine, Politics of the Machine Denmark, and Participatory Design Conference Belgium.</p>\r\n<p>His work focuses on BioArt through immersive installation, audiovisual environments, projection mapping, and full-dome audiovisuals for geodesic domes.</p>\r\n<p>His research primarily concerns the current intersection between Biology, immersive technologies, and real-time audiovisuals. His independent productions have reached audiences in Belgium, Brazil, Costa Rica, China, Denmark, Mexico, Portugal, and USA.</p>\r\n<p><img src=\"/uploaded_images/axel-cuevas-santamaria1.jpg\" alt=\"\" /></p>\r\n<p>&nbsp;</p>', '', 'http://axelcuevassantamaria.com', '', '', '0', '1670529931', '', 'https://www.instagram.com/axelacs/'),
(353, 'Virgil Widrich', 'virgil-widrich', 'http://codame.dreamhosters.com/uploaded_images/virgil-widrich.jpeg', '<p>Virgil Widrich, born 1967 in Salzburg, works on numerous multimedia and film productions. He is one of the founders and Managing Directors of the multimedia company checkpointmedia GmbH, University Professor of Art &amp; Science at the University of Applied Arts Vienna and owner and Managing Director of Virgil Widrich Film- und Multimediaproduktions G.m.b.H.</p>\r\n<p>His first feature film is \"Heller als der Mond\" (\"Brighter than the Moon\"). His short film \"Copy Shop\" won 37 international awards and was nominated for the Oscar. \"Fast Film\" premiered in Cannes 2003 and won 36 awards until today. His most recent feature film is \"Night of a 1000 Hours\" (2016). In 2018 he directed his first music video \"Nena &amp; Dave Stewart: Be my Rebel\".</p>\r\n<p>Virgil Widrich lives in Vienna.</p>', 'https://twitter.com/widrichfilm', 'https://www.widrichfilm.com/en', '', '', '0', '1561743509', NULL, NULL),
(354, 'Red Wolf', 'red-wolf', 'http://codame.dreamhosters.com/uploaded_images/red-wolf.jpg', '<p><em>&ldquo;Art style follows something that exists.&nbsp;</em><em>When you use an art form that already exists, its art style. But when you invent a new way to depict an image, its art movement.&rdquo;&nbsp; -&nbsp;</em>Paula Popescu</p>\r\n<p><em>&ldquo;When works of art exhibit common visual characteristics, they may be said to belong to an artistic style. When a group of artists tend toward or immerse themselves in a particular style based on common goals or philosophies, this can be called a movement.&rdquo;&nbsp; &nbsp;-&nbsp;</em>Michael Kodysz</p>\r\n<p>Shifting the primary focus in creating a work of art from the pigmented paints used in rendering a painting, to becoming more aware of the optics involved of light interacting with structures within a painting, presents an opportunity to advance the age old art of painting in directions that have not been fully explored.</p>\r\n<p><img src=\"/uploaded_images/7R302802.jpg\" alt=\"\" width=\"805\" height=\"537\" /></p>\r\n<p>The most historically exciting development in the understanding of the creation of colors has happened here in the last 50 years. With the advent of the electron microscope in the late 1960&rsquo;s we for the first time began to unlock the physics behind the mysteries of Structural Color.</p>\r\n<p>In nature there are numerous examples of these colors that until recently defied our attempts to mimic. Select hummingbird feathers, butterfly wings, beetle shells, and even the simple soap bubble all generate colors structurally. These effects that we perceive as having such intense beautiful colors are diffraction of light rays. Particle sizes too small even for a microscope to image underlie the creation of this optical color effect. The very surfaces of these objects are latticed with precisely spaced tiny 3 dimensional structures that redirect the light rays to create brilliantly diffracted colors. These colors are thus optically generated and not made from pigments as we have come to expect in creation of color.</p>\r\n<p><img src=\"/uploaded_images/AB504A5E-3776-45B3-83E5-C5DF886FC079-17842-00000840AA62EBF8.jpg\" alt=\"\" width=\"791\" height=\"445\" /></p>\r\n<p>Since the earliest recorded history of humans making colors in art, tracing back 30,000 to 40,000 years, to this very moment in history, colors have been achieved from grinding material of one kind or another to extract their desired properties.</p>\r\n<p>Today&rsquo;s photonics nano particle research in physics enables new abilities to mimic and create Structural Color materials that have never, in all of prior human history, been possible to achieve. We see this in security features on our currencies, in true holograms, and in an array of other thin film materials.</p>\r\n<p>An optical based approach to painting also lends itself to new substrates. Aluminum panels provide an opportunity to control the reflection of light off the surface of the metal. How light enters and exits the picture plane and at what directions these beams of light are directed becomes an integral aspect to building an image. Studies into aspects of the physics of standing wave front patterning inform how carefully conceived etching can be made to evoke a stereoscopic 3 dimensional visual effect. What is being evoked in these ways is related to some of the fundamental underlying wave front principles in Holography.</p>\r\n<p><img src=\"/uploaded_images/IMG_7491.jpg\" alt=\"\" width=\"765\" height=\"765\" /></p>\r\n<p>Advancements in photonics physics and material science are being reimagined to inform new possible approaches to art making. Increasingly assembling diffractive materials and processes become the primary means to creating an image in this approach to painting.</p>\r\n<p>Principals inherent to the fundamental dual particle and wave nature of light and the ability to manipulate the course of light entering and exciting the picture plane underlies everything in this approach to image making.</p>\r\n<p>&ldquo;The feat, achieved by observing the interference of two intersecting light beams, is an important insight into the fundamental quantum nature of light.&rdquo;</p>\r\n<p>&ldquo;One thing you can count on is a steady stream of innovation that will likely lead to new movements. This always happens when you get crossover talents - people who are experts in one thing then apply it to another.&rdquo;</p>', '', 'http://www.redwolffineart.com/Welcome.html', '', '', '0', '1582439028', NULL, NULL),
(355, 'Emma Lefley', 'emma-lefley', 'http://codame.dreamhosters.com/uploaded_images/emma-lefley.jpg', '<p>Emma Lefley is an Oakland based artist, specializing in the intersection of art and technology. Emma is currently working on Out of This World Advice, an interactive musical installation, as awakening.io. She practices computer music, lighting animations, sculptural design and fabrication. Emma is inspired by art, technology, music, collaboration, and exploring the way those things impact life. Emma also teaches art and technology to children ages K-5th grade.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '', 'https://emmalefley.com', 'eclefley@gmail.com', '', '0', '1562012979', NULL, NULL),
(356, 'Colin Sullivan', 'colin-sullivan', 'http://codame.dreamhosters.com/uploaded_images/colin-sullivan.jpg', '<p>Colin Sullivan is an Oakland based creative developer &amp; artist specializing in interactive musical systems, web technologies, and generative music.&nbsp; Colin is developing interactive installation work as awakening.io, has released improvisational electronic music as Colin Sullivan and Mountains in Space, and maintains an independent contractor software development practice.</p>', '', 'https://colin-sullivan.ne', 'colin@colin-sullivan.net', '', '0', '1683748790', '', ''),
(357, 'Jules Litman-Cleper', 'jules-litman-cleper', 'http://codame.dreamhosters.com/uploaded_images/jules-litman-cleper.jpg', '<p>Jules Litman-Cleper (b.1989) is a new media artist and theorist born and raised in the Bay Area, interested in unpacking simulation as a way of knowing,&nbsp; the formation and deformation of patterns in organic systems, natural computation, perceptual aspects of randomness, and ecologies: their flows of information, spatial dynamics and protection. These inquiries unfold through writing, visual art, mixed-media installation, sound, research and experimentation.&nbsp;</p>', '', '', '', '', '0', '1563214792', NULL, NULL),
(358, 'Grant Patterson ', 'grant-patterson', 'http://codame.dreamhosters.com/uploaded_images/grant-patterson.jpg', '<p>Grant Patterson creates interactive computer-mediated art inspired by scientific principles. He graduated from Stanford University with a BS in Computer Science and has over a decade of hardware/software industry experience in circuit design, embedded systems programming, Linux sysadmin, web user interfaces, and mobile apps with internet-of-things connectivity. Grant left the corporate world in 2018 to make art full-time.</p>\r\n<p>Grant believes we should use the fruits of society\'s technological progress to produce beautiful, magical things. With all the mind-blowing technology out there, too much of it is put towards the service of simply making more money. Instead, we can use our godlike powers to create things of transcendent beauty and splendor&mdash;things that shake observers to their core, challenging their beliefs and assumptions.&nbsp;</p>\r\n<p>Grant is fascinated by light and its potential for expression. This drives him to create art pieces large and small, from LED wearables to warehouse-scale installations. He engages viewers to control and participate in the art. His work appears in art festivals, corporate events, permanent installations, and private collections. His latest pieces harness the precision and power of laser fabrication technology.</p>', 'http://www.twitter.com/grantpatterson', 'http://revoltlabs.co', '', '', '0', '1563482523', NULL, NULL),
(360, 'Honghao Deng ', 'honghao-deng', 'http://codame.dreamhosters.com/uploaded_images/honghao-deng.jpg', '<p>Honghao Deng (é‚“é¸¿æµ©) is a computational designer focusing on building hyper-performance built-environment with the integration of tangible Interface, IoT, AR, and VR. He holds a Master of Design Studies in Technology degree with Distinction at Harvard GSD and a Bachelor of Architecture from Tianjin University. He is the principal of Radical Department. He is also a researcher at City Science Group, MIT Media Lab and Responsive Environments and Artifacts Lab at Harvard, developing spatial experience interface that enables users to customize their working and living spaces intuitively and effortlessly.</p>\r\n<p>Honghao has won multiple international design awards in interaction, product, and architecture, including Golden A\' Design Award, iF Design Award, 1st Place Future Cities Contest, 1st place CHI Play Game Design Award, Ubicomp/ISWC Design Award. His work has been covered by Domus, CCTV, ArchDaily,&nbsp; Arab News, the National and Metropolis Magazine.</p>\r\n<p>&nbsp;</p>', '', 'http://www.honghao.gallery/about', '', '', '0', '1564451406', NULL, NULL),
(361, 'Sergiu Ardelean ', 'sergiu-ardelean', 'http://codame.dreamhosters.com/uploaded_images/sergiu-ardelean.png', '<p dir=\"ltr\">&ldquo;Imagine if your artwork could express not only the singularity, but the entire journey?&rdquo;</p>\r\n<p dir=\"ltr\">~ Sergiu Ardelean&nbsp;</p>\r\n<p dir=\"ltr\">Sergiu Ardelan is CEO and co-founder of ARTIVIVE, a downloadable visualisation tool which will take your end canvas and allow viewers to unlock the augmented realities hidden within. His platform empowers artists to build the future of analog and digital art. His vision is to change how art is created and consumed by forming a global community of Augmented Reality artists that bring Art to life.</p>\r\n<p dir=\"ltr\">Currently based in San Francisco, he is on a mission is to democratize augmented reality by simplifying the technical process so artists can do what they do best, create! An Austrian native, he developed the application from the ground up including product development, identifying artistic consumer need and providing tailored specifications to take Artivive to market. The platform now has a global reach currently used on 3 continents by a network of 10,000+ artists and creatives.&nbsp;</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/ArtiviveApp', 'https://artivive.com/', 'sergiu@artivive.com ', '', '0', '1564503777', NULL, NULL),
(390, 'Martin Rauchbauer', 'martin-rauchbauer', 'http://codame.dreamhosters.com/uploaded_images/martin-rauchbauer.jpg', '<p>Martin Rauchbauer is the Austrian Consul in San Francisco and Co-Director of Open Austria.</p>\r\n<p>Before coming to San Francisco,&nbsp;Martin was Deputy Director of the Business&nbsp;Support Service and Head of the&nbsp;UNESCO unit at the Austrian Foreign Ministry&nbsp;in Vienna. In 2014, he was briefly CEO at&nbsp;the &Ouml;sterreich Institut GmbH in Vienna.&nbsp;Between 2011 and 2014 he was Director of&nbsp;Deutsches Haus at NYU in New York City. From 2007 until&nbsp;January 2011 he was the Deputy Director of&nbsp;the Austrian Cultural Forum in New York.</p>\r\n<p>Martin also served as Director of the Austrian&nbsp;Cultural Forum in Mexico City and as Desk Officer at the Austrian Foreign Ministry. Throughout his career, Martin&nbsp;designed and implemented&nbsp;numerous high-profile&nbsp;academic, cultural and&nbsp;business-related events in North America.&nbsp;He also worked as a journalist for Austrian&nbsp;Radio and Television (ORF) and the Viennese&nbsp;weekly news magazine &ldquo;Format&rdquo;.</p>\r\n<p>Martin&nbsp;received his M.A. in International Relations and International Economics from the&nbsp;School of Advanced International Studies&nbsp;(SAIS) at the Johns Hopkins University in Bologna,&nbsp;Italy and Washington D.C.&nbsp;He&nbsp;also holds a degree in&nbsp;Philosophy and German Studies from the University of Vienna.</p>', 'https://twitter.com/mrauchbauer', 'http://www.open-austria.com/', 'Martin.RAUCHBAUER@bmeia.gv.at', '', '0', '1572039306', NULL, NULL),
(363, 'Irene Malatesta', 'irene-malatesta', 'http://codame.dreamhosters.com/uploaded_images/irene-malatesta.jpeg', '<p>Irene Malatesta is a writer, marketer, and content strategist with over a decade of experience working with entrepreneurs and mission-driven businesses to create authentic connections through shared creativity and storytelling. She received her BA in Art History from Columbia University, her digital design training from Parsons, and her education in high-tech high-growth businesses from working in early-stage startups in San Francisco.&nbsp;</p>', 'https://twitter.com/irenekaoru', 'http://irenekaoru.com', 'irene@codame.com', '', '0', '1565109628', NULL, NULL),
(365, 'James Proctor', 'james-proctor', 'http://codame.dreamhosters.com/uploaded_images/james-proctor.png', '<p>James Proctor is a software artist and data visualization engineer at Pitch Interactive. He uses software systems to investigate the physical, social, and political systems that shape our world. Specifically, the ways our values as a society are encoded into the environment we build. His work has been featured in group shows at NY Media Center, CICA, Harvest Works, XXXI, Plexus Projects, Gallery Aferro, and Human NYC.</p>\r\n<p>Pitch Interactive is a data visualization studio that focuses on using new technologies to address complex data. Their work spans illustrations, physical installations, projections, software applications, websites and textiles. Their work has been showcased at Fotofest Sensors exhibit, Houston, Texas (2015), Data Drift exhibit at RIXC The Center for New Media Culture, Riga, Latvia (2015), Tomas Van Houtryve - Blue Sky Days exhibit at the Bayeux awards for War Correspondents Festival, Bayeux, France (2015), Talk to Me at the Museum of Modern Art, New York (2011), Conversations &Eacute;lectriques at La Panac&eacute;e, Montpellier, France (2011), the McKnight Artist Fellowship program&rsquo;s 30th anniversary exhibition, Minneapolis, Minnesota (2012), The Art of Networks, Foosaner Art Museum, Melbourne, Florida (2012), and The Max Planck Science Express Train, Munich (2009) the Data Flow books and many other internationally acclaimed publications.</p>', '', 'http://jamesaproctor.com', 'mail@jamesaproctor.com', '', '0', '1565326147', NULL, NULL),
(366, 'Clea T. Waite', 'clea-t-waite', 'http://codame.dreamhosters.com/uploaded_images/clea-t-waite.jpg', '<p>Clea T. Waite is an intermedia artist, engineer, and filmmaker whose artworks investigate the materiality and poetics emerging at the intersection of art and science. She creates immersive, cinematic works engaging embodied perception, dynamic composition, and sensual interfaces &ndash; as well as one inter-species collaboration with several hundred tropical spiders. Her most recent project is &ldquo;Ice-Time,&rdquo; an immersive, multi-projection video and sound installation combining art and science in a creative response to the accelerating changes we are currently observing in Earth\'s ecosystem, eliciting the poetics contained within frozen water as revealed by current climate research. Waite has a Ph.D. from USC in Media Arts + Practice, combining a background in physics and computer graphics from the MIT Media Lab with research in media art theory. Waite&rsquo;s artworks have recently been exhibited on the ICC Hong Kong, the Miraikan Museum, Tokyo, and the Boston CyberArts Festival. She has been a Humboldt Fellow, a Radcliffe Fellow, CERN artist-in-residence, and fellow at the Academy of Media Arts Cologne.</p>\r\n<p>&nbsp;</p>', 'http://www.twitter.com/clea-t-waite', 'http://www.clea-t.de/', '', '', '0', '1565369457', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(367, 'Haein Kang', 'haein-kang', 'http://codame.dreamhosters.com/uploaded_images/haein-kang.jpg', '<p>Haein Kang is a multimedia artist, a creative technologist, and currently a doctoral candidate in DXARTS at the University of Washington. She explores the infinite possibilities of artistic expression by employing advanced technology. Her artwork engages poetically with technology. She received Honorary Mention at Prix Ars Electronica and presented her artworks at various international venues, including SOMA Museum, Seoul Museum of Art, ICMC, IEEE-GEM, and ISEA.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '', 'https://www.haeinkang.org', '', '', '0', '1565654844', NULL, NULL),
