riority=\"50\" Name=\"List Table 5 Dark Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"51\"\r\n   Name=\"List Table 6 Colorful Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"52\"\r\n   Name=\"List Table 7 Colorful Accent 5\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"46\"\r\n   Name=\"List Table 1 Light Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"47\" Name=\"List Table 2 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"48\" Name=\"List Table 3 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"49\" Name=\"List Table 4 Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"50\" Name=\"List Table 5 Dark Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"51\"\r\n   Name=\"List Table 6 Colorful Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" Priority=\"52\"\r\n   Name=\"List Table 7 Colorful Accent 6\"/>\r\n  <w:LsdException Locked=\"false\" SemiHidden=\"true\" UnhideWhenUsed=\"true\"\r\n   Name=\"Mention\"/>\r\n  <w:LsdException Locked=\"false\" SemiHidden=\"true\" UnhideWhenUsed=\"true\"\r\n   Name=\"Smart Hyperlink\"/>\r\n  <w:LsdException Locked=\"false\" SemiHidden=\"true\" UnhideWhenUsed=\"true\"\r\n   Name=\"Hashtag\"/>\r\n  <w:LsdException Locked=\"false\" SemiHidden=\"true\" UnhideWhenUsed=\"true\"\r\n   Name=\"Unresolved Mention\"/>\r\n </w:LatentStyles>\r\n</xml><![endif]--><!-- [if gte mso 10]>\r\n<style>\r\n /* Style Definitions */\r\n table.MsoNormalTable\r\n	{mso-style-name:\"Table Normal\";\r\n	mso-tstyle-rowband-size:0;\r\n	mso-tstyle-colband-size:0;\r\n	mso-style-noshow:yes;\r\n	mso-style-priority:99;\r\n	mso-style-parent:\"\";\r\n	mso-padding-alt:0in 5.4pt 0in 5.4pt;\r\n	mso-para-margin:0in;\r\n	mso-para-margin-bottom:.0001pt;\r\n	mso-pagination:widow-orphan;\r\n	font-size:12.0pt;\r\n	font-family:\"Cambria\",serif;\r\n	mso-ascii-font-family:Cambria;\r\n	mso-ascii-theme-font:minor-latin;\r\n	mso-hansi-font-family:Cambria;\r\n	mso-hansi-theme-font:minor-latin;\r\n	mso-ansi-language:EN-CA;}\r\n</style>\r\n<![endif]--> <!--StartFragment--></p>\r\n<p>Judit Navratil&rsquo;s practice is multivalent, engaging performance, social practices, drawing, as well as video and VR. The relationship between the real and virtual is personally significant to Judit, as she has moved between several different countries and cultures in her lifetime, and relies on digital means to connect to people and places in an attempt to construct &ldquo;home.&rdquo; Her projects are as much affective mappings of what it means to continuously oscillate between analog and digital, past and present. Navratil uses her body-device to keep balance through her compass-meditation: the Long Distance Somersault career. Rolling as far as she can helps her seeking higher alternatives and to gaze in the Eye of the Hurricane.</p>\r\n<p>Navratil earned an MFA in Painting at the Hungarian University of Fine Arts in 2008 and an MFA at the California College of the Arts in San Francisco in 2019. <span lang=\"EN-CA\">She has been exhibiting in Hungary, Canada, France, Korea and the Bay Area. </span>Her work has been recognized through awards and residencies including the Cadogan Art Award, a residency at Cit&eacute; Internationale des Arts (Paris), the Dennis Leon and Christin Nelson Scholarship and a Presidential Scholarship for Anderson Ranch.</p>\r\n<p><span lang=\"EN-CA\">She is currently an affiliate artist at the Headlands Center for the Arts. </span></p>\r\n<p><!--EndFragment--></p>', 'https://twitter.com/navratiljudit', 'https://www.works.io/judit-navratil', '', '', '0', '1659574442', 'https://foundation.app/@juditnavratil/foundation/26522', 'https://www.instagram.com/juditnavratil/'),
(369, 'Peter Burr', 'peter-burr', 'http://codame.dreamhosters.com/uploaded_images/peter-burr.jpg', '<p>Peter Burr (b. 1980) is an artist from Brooklyn, NY. A master of computer animation with a gift for creating images and environments that hover on the boundary between abstraction and figuration, Burr has in recent years devoted himself to exploring the concept of an endlessly mutating labyrinth. His practice often engages with tools of the video game industry in the form of immersive cinematic artworks. These pieces have been presented internationally by various institutions including Documenta 14, Athens; MoMA PS1, New York; and The Barbican Centre, London.</p>\r\n<p>Previously Burr worked under the alias Hooliganship and founded the video label Cartune Xprez through which he produced hundreds of live multimedia exhibitions and touring programs showcasing a multi-generational group of artists at the forefront of experimental animation. His practice has been recognized through grants and awards including a Guggenheim Fellowship (2018), a Creative Capital Grant (2016), and a Sundance New Frontier Fellowship (2016).</p>\r\n<p>He is currently a visiting artist at the School of the Art Institute of Chicago.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 'http://twitter.com/petereburr', 'http://www.peterburr.org/', '', '', '0', '1565749208', NULL, NULL),
(371, 'Rosemarie Truman', 'rosemarie-truman', 'http://codame.dreamhosters.com/uploaded_images/rosemarie-truman.jpg', '<p>Rosemarie Truman is an entrepreneur, growth strategist, distinguished corporate executive, angel investor and prolific startup catalyst.&nbsp; Rosemarie&rsquo;s specialty is growth and investment strategy, having led growth strategies for 50 of the global Fortune 100 companies in over 15 countries. The strategies that Rosemarie led have resulted in $300+ billion in &ldquo;net new&rdquo; top line yearly revenue and 190+ new products on the market.</p>\r\n<p>Currently, Rosemarie is the Founder and CEO of the Center for Advancing Innovation (CAI), a 501c3 non-profit which has been coined &ldquo;<a href=\"https://t.sidekickopen70.com/e1t/c/5/f18dQhb0SmZ58dDMPbW2n0x6l2B9nMJW7sM9dn7dK_MMdBzM2-04?te=W3R5hFj26QkHmW4mKDt83K1KJJW4hCVj23Fbt5SW3zgF8D3F9c0hW1L687-1Q2RZ6W1LBDwK1N5Z8Zf1G9vq004&amp;si=8000000000583213&amp;pi=cee8574f-b34c-4792-e501-bfe2cebf26f3\" target=\"_blank\">Tinder for Startups</a>&rdquo; and &ldquo;<a href=\"https://t.sidekickopen70.com/e1t/c/5/f18dQhb0SmZ58dDMPbW2n0x6l2B9nMJW7sM9dn7dK_MMdBzM2-04?te=W3R5hFj4cm2zwW4rCvX64hcdn5W1Lj9Xb3gwX3Lf4plXNJ04&amp;si=8000000000583213&amp;pi=cee8574f-b34c-4792-e501-bfe2cebf26f3\" target=\"_blank\">Shark Tank on Steroids</a>.&rdquo; CAI&rsquo;s mission to identify breakthrough inventions and maximize their commercial potential. Under Rosemarie&rsquo;s leadership, CAI has earned numerous awards and recognition from Health and Human Services, the&nbsp;<a href=\"https://t.sidekickopen70.com/e1t/c/5/f18dQhb0SmZ58dDMPbW2n0x6l2B9nMJW7sM9dn7dK_MMdBzM2-04?te=W3R5hFj4cm2zwW43NBZ73zjJtVW4fGBw94hLZmMW3zgCH03T4FNJW1Jz9RP1LF6VGW1GGnT94cPNt5W3M2m0L3JFRzdW1Q5krP1-X7WyW1Lyz5F3z8p13W49KwbL49RFqpW1N4gYk4px636W3ZVdqD45TQptW3SZ8dg4fdhxTW3zdx6B1GDJQZW3H4TkJ3R0K29F4cHc7hPbG-1&amp;si=8000000000583213&amp;pi=cee8574f-b34c-4792-e501-bfe2cebf26f3\" target=\"_blank\">White House</a>, the Federal Laboratory Consortium and more. CAI has partnered with 100 organizations across the US to gain access to 170,000 inventions and has launched 300+ startups over the last 4 years; created 3500 knowledge-based jobs. For its notable work, CAI has also been featured in the Washington Post,&nbsp;<a href=\"https://t.sidekickopen70.com/e1t/c/5/f18dQhb0SmZ58dDMPbW2n0x6l2B9nMJW7sM9dn7dK_MMdBzM2-04?te=W3R5hFj26QkHmW3K22rh49JGyrW4kCBqB49Ldr_W3K22w81N4K4XW1Q2RNw1S2cGFW1-XdGP4fM4GSW4mKLS-4mCWPtW3GGYWV1JH05kW41RkQf1LvdM3W3R0KBG1L6zDGW1WZcNt1L687_W3Cf8ly4cQ9YwW3zdYNr49hb0gW41Wvst4fJg0T0&amp;si=8000000000583213&amp;pi=cee8574f-b34c-4792-e501-bfe2cebf26f3\" target=\"_blank\">Wired</a>, Huffington Post, Nature, and several other publications. Rosemarie also serves as Director of the DC-metro chapter of the Founder Institute, the world&rsquo;s largest startup accelerator program and severs on multiple boards such as Mindshare.&nbsp;<a href=\"https://t.sidekickopen70.com/e1t/c/5/f18dQhb0SmZ58dDMPbW2n0x6l2B9nMJW7sM9dn7dK_MMdBzM2-04?te=W3R5hFj4cm2zwW4mKLS-3_VrpFW4cKgQM3K76ZYW4mGpFm1JDwVNW1Lvclr4hMgZcW4cgyMz43XxC_W3_VrpF4cKgQM21V3&amp;si=8000000000583213&amp;pi=cee8574f-b34c-4792-e501-bfe2cebf26f3\" target=\"_blank\">Mindshare</a>&nbsp;is an&nbsp;exclusive, invitation-only network of chief executive officers (CEOs) from the most promising emerging and high growth technology companies.</p>\r\n<p>Prior to launching her own firm, Rosemarie spearheaded IBM&rsquo;s Innovation strategy practice globally. At IBM, she was awarded IBM&rsquo;s most laudable honor, the Golden Circle Award. In addition, she has also held notable leadership roles at Booz Allen Hamilton, Oracle, PRTM, and Marsh &amp; McLennan, where she served as VP of global strategy. Rosemarie began her career at Goldman Sachs. Her core competencies are in leadership, strategy consulting, investment banking and entrepreneurship. In Rosemarie\'s spare time, she writes for Forbes.</p>', 'https://twitter.com/rosemarietruman', 'https://www.thecenterforadvancinginnovation.org/about-us.html', '', '', '0', '1566877979', NULL, NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(372, 'Michael Scherotter', 'michael-scherotter', 'http://codame.dreamhosters.com/uploaded_images/michael-scherotter.jpg', '<p>Travel/Art/Journalist and Principal Technical Program Manager, Microsoft Corp.</p>\r\n<p>Michael&nbsp;works&nbsp;on&nbsp;Sketch 360, an app he built and shipped through the Microsoft Garage to help architects, VR designers and artists create 360 drawings that can be on viewed on tablets, phones and in VR headsets.&nbsp; Educated as an architect, Michael has made his career in software development with a particular interest in creative tools.&nbsp; While pursuing his career, Michael has chronicled his journeys across the world in rich travel/art journals with watercoloring, sketching, collage, and even circuitry.&nbsp; At Microsoft for the past 12 years, Michael has focused on helping partners build apps, experiences, and services using Microsoft developer technologies like Windows, Azure, Office, Xbox, and HoloLens.</p>\r\n<p>&nbsp;</p>\r\n<h1 id=\"bbbb\">Interview with&nbsp;Michael Scherotter</h1>\r\n<p dir=\"ltr\"><strong>Tell us about your background</strong></p>\r\n<p dir=\"ltr\">Educated as an architect, I\'ve made my career in software combing technology in interesting ways, with a particular interest in crafting tools that help with the creative process.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What is your definition of art + tech?</strong></p>\r\n<p>Technology enables artists to create and share in new ways using their existing creative processes and workflows.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>Who, or what, inspires you in your art and in your life?</strong></p>\r\n<p>Artists like Picasso, Miro, Escher, architects like Gaudi and Gehry, engineers like Buckminster Fuller, and technologists like John Maeda who discover and cultivate the undiscovered connections between things and express those connections artistically.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What is your process or techniques for creating your work?&nbsp;</strong></p>\r\n<p dir=\"ltr\">I take two things that interest me and explore what kinds of connections can be made with them, whether that is with technology like VR, AI, blockchain or quantum computing, an activity like urban sketching or painting, or something happening in the world like COVID. I want to discover and cultivate the connections between them and possibly find a creative, artistic intersection.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\">An example is that I before the pandemic, I loved to travel and sketch. That has shut down for me, as it has most people. I saw the opportunity with the new Microsoft Flight Simulator\'s amazing 3D imagery to be a way that I could create a new genre: virtual flight sketching: https://charette.com/2020/09/20/virtual-flight-sketching/</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What is your dream project?&nbsp;</strong></p>\r\n<p dir=\"ltr\">My dream is to travel as \"Journalist\" with Yusaku Maesawa as he takes a group of artists to the moon in 2023 (https://dearmoon.earth/), keeping a visual log of the journey with my analog and digital journaling tools to inspire others to chronicle their journeys near and far: https://sway.office.com/36E11ctNaVCF6G8E?ref=Link&amp;loc=play</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s the greater purpose behind your artwork?</strong></p>\r\n<p>I discover and craft connections linking creative processes that delight me with technologies that fascinate me, sharing the results to inspire and motivate others.hat is possible to artists and creators on the web and for open source projects and communities.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s the best piece of advice you&rsquo;ve been given?</strong></p>\r\n<p dir=\"ltr\">Find what you love and become the best at it. Charles Albanese, FAIA (architecture professor)</p>', 'https://twitter.com/synergist', '(https://adobe.ly/2GpnWYN', 'mischero@microsoft.com', '', '0', '1607580750', '', NULL),
(373, 'Laura Greene', 'laura-greene', 'http://codame.dreamhosters.com/uploaded_images/laura-greene.png', '<p>I am an Interaction Designer and Artist with a passion for remixing media. With a background in painting, sculpture and photography, I am now translating these analog signals into digital currents. If you ask me what my medium is, I will simply say ENERGY!</p>', '', 'https://www.mindtapcreative.com/', '', '', '0', '1566761733', NULL, NULL),
(374, 'Sandrine Deumier ', 'sandrine-deumier', 'http://codame.dreamhosters.com/uploaded_images/sandrine-deumier.jpg', '<p>With her dual philosophical and artistic training, Sandrine Deumier constructed a multifaceted poetry focused on the issue of technological change and the performative place of poetry conceived through new technologies. Using material from the word as image and the image as a word vector, she also works at the junction of video and sound poetry considering them as sensitive devices to express a form of unconscious material itself. The process of writing and the mobile material of the image function as underlying meanings of reflux which refer to the real flickering and to their reality transfers via unconscious thought structures. Her work consists mainly of texts, digital poetry, multimedia installations and audiovisual performances in collaboration with composers.</p>', '', 'http://sandrinedeumier.com', '', '', '0', '1566762317', NULL, NULL),
(376, 'Engin Daglik', 'engin-daglik', 'http://codame.dreamhosters.com/uploaded_images/engin-daglik.jpg', '<p>Engin Daglik is a composer, sound artist and performer who essentially explores the potential of space by combining different fields of art in his works. He is mostly interested in producing works that aim to re-create and re-shape the perception of space in order to make viewers and listeners re- imagine the site transformed by the work. He enjoys designing and producing works for concert, gallery and public spaces by implying different immersive audio techniques, using concrete materials to create explicit structures. Since graduating with a Bachelor of Music from the Istanbul Bilgi University in 2017, Engin has participated several festivals, workshops and exhibitions around Europe and Turkey. After completing Master of Arts in Music at Bilkent University, he is currently pursuing his DMA at Stanford University. Besides composing and producing, he regularly performs in various projects and free improvisation sessions as a drummer.</p>\r\n<p>&nbsp;</p>', '', '', '', '', '0', '1567489273', NULL, NULL),
(377, 'Jasmine Roberts', 'jasmine-roberts', 'http://codame.dreamhosters.com/uploaded_images/jasmine-roberts.png', '<p>Jasmine Roberts is a researcher, engineer and lecturer in the field of immersive computing (specifically VR/AR). Originally a physicist studying laser optics and holography, she was drawn to the totality of mixed-reality to utilize the creative aspect of her character.&nbsp;&nbsp;Roberts has a Bachelor in Applied Physics, a Masters in Electrical Engineering and Computer Science and a Master of Design. Although, spiritual and emotive in her off-time, she is very pragmatic concerning her work and creates the necessary tools and pipelines to help creators build immersive content.&nbsp;</p>\r\n<p>Currently she is building systems for affective computing, assembling workflows of real time capture systems for avatars and navigating web-based cloud streaming for 3D experiences and games. Recently, Jasmine worked as an engineer in Intel&rsquo;s RealSense team in 2016, Sony PlayStation R&amp;D in 2017 and NASA and Unity in 2018. She has lectured at SCI_Arc, Strelka, NYU, Harvard, UMass and other institutions. She serves as the chair of UN Women in VR and is on the steering committee for IEEEVR.&nbsp;&nbsp;Her dream is to eventually go back finish her PhD and have a lab of her own where she can mentor students while researching emerging phenomena.&nbsp;</p>', 'https://twitter.com/ladykillmonger', 'https://www.jasmineroberts.org/', 'jasminearvr@gmail.com', '', '0', '1570550254', NULL, NULL),
(379, 'Cat Maguire', 'cat-maguire', 'http://codame.dreamhosters.com/uploaded_images/cat-maguire.jpeg', '<p>Catherine (Cat) Maguire is a movement educator, dance artist, Certified Movement Analyst (CMA), Registered Somatic Movement Educator through ISMETA (International Somatic Movement Education and Therapy Association), and a master teacher of the Laban/Bartenieff Movement System (LBMS). She is a member of WholeMovement, a coterie of Movement Analysts working together to promote the LBMS globally, and has taught and co-coordinated Movement Analysis Certification Programs in the US, Europe, Mexico and China. Cat is also a collaborator and consultant for the Robotics, Automation and Dance (RAD) Lab at the University of Illinois Urbana- Champaign under the direction of Dr. Amy LaViers where she works with roboticists on embodied movement training and analysis to support the development of expressive robotic systems.&nbsp;&nbsp;</p>\r\n<p>After graduating Phi Beta Kappa from Wesleyan University with honors in dance and psychology, Cat earned a Certified Movement Analyst degree from the Laban/Bartenieff Institute of Movement Studies in New York City. For the next eight years, she was the artistic director of Offspring Dance Company in New York City and the founder and head of the dance program at Drew University in Madison, NJ. While executive director of Piedmont Council of the Arts in Charlottesville, Cat continued to teach, choreograph and perform throughout Central Virginia and internationally. From 2003 to 2010, Cat was assistant professor of dance at Piedmont Virginia Community College (PVCC), where she was an integral part of the development and implementation of the associate&rsquo;s degree in dance, the only one of its kind in the Virginia Community College System.</p>\r\n<p>Currently, Cat teaches group classes and individual sessions in the Charlottesville VA area designed to foster self-expression, body connectivity and transformation through movement.</p>', '', '', '', '', '0', '1568843741', NULL, NULL),
(387, 'Jihee Hwang', 'jihee-hwang', 'http://codame.dreamhosters.com/uploaded_images/jihee-hwang.jpg', '<p>Jihee is a programmer, artist, polyglot, audiophile, singer, and a tea connoisseur. Born and raised in Seoul, South Korea, they are currently a Master\'s student in Stanford. Jihee studies languages and plays indie games in free time.</p>', '', 'https://jiheehwang.com', 'alarmringing@gmail.com', '', '0', '1571889831', NULL, NULL),
(388, 'Angeli Clarisse Lata', 'angeli-clarisse-lata', 'http://codame.dreamhosters.com/uploaded_images/angeli-clarisse-lata.png', '<p>Angeli is a Bay Area based mixed media (painting, video, digital design) and augmented reality artist passionate about connecting people through art and technology to share raw and authentic stories.&nbsp;&nbsp;As a result, she has hosted pop-up AR gallery shows and taught workshops for the up-and-coming, internationally-acclaimed Augmented Reality Art company, Artivive.</p>', '', 'https://www.instagram.com/augmentedrealityartist/', 'angelisartstudio@gmail.com', '', '0', '1571715771', NULL, NULL),
(389, 'Polychroma', 'polychroma', 'http://codame.dreamhosters.com/uploaded_images/polychroma.jpg', '<div style=\"font-size: small; font-family: arial, sans-serif;\">Ted Petsas is a San Francisco based visual artist, musician, DJ, and solar energy professional. He experiments with audio reactive lumia and video feedback techniques, making use&nbsp;<span class=\"il\">of</span>&nbsp;hardware equipment such as retired surveillance cameras, vintage broadcast equipment, and other recycled electronics.</div>\r\n<div style=\"font-size: small; font-family: arial, sans-serif;\">&nbsp;</div>\r\n<div style=\"font-size: small; font-family: arial, sans-serif;\">&nbsp;</div>\r\n<div style=\"font-size: small; font-family: arial, sans-serif;\">&nbsp;</div>', 'https://instagram.com/tedpetsas/', 'https://hismastersvoicesf.bandcamp.com/', '', '', '0', '1571889724', NULL, NULL),
(381, 'Sara ElShafie', 'sara-elshafie', 'http://codame.dreamhosters.com/uploaded_images/sara-elshafie-2.jpg', '<p>&nbsp;Sara ElShafie is a global change biologist and science communication specialist. ElShafie collaborates with artists in entertainment industries to uncover the potential of storytelling to engage broad audiences with complex topics. She created a workshop series, Science Through Story, which she runs for groups ranging from graduate students to NASA scientists to theme park executives. ElShafie also organized a symposium, Science Through Narrative: Engaging Broad Audiences, with speakers from the scientific community as well as arts and entertainment industries, and curated a resulting published volume of papers. She is completing her PhD in Integrative Biology with the Museum of Paleontology at the University of California, Berkeley.</p>', 'https://twitter.com/elshafie_sara', 'https://www.sara-elshafie.com/', 'sciencethrustory@gmail.com', '', '0', '1593500188', NULL, NULL),
(384, 'Rosalie Barnes', 'rosalie-barnes', 'http://codame.dreamhosters.com/uploaded_images/rosalie-barnes.jpg', '<p>Rosalie Barnes explores the intersection of art and end of life through storytelling, tech, and hands-on art-making. She serves as the manager for the evolving Data Meditations: An Abstract Koi Pond.</p>\r\n<p>Rosalie received a Bachelor of Arts in Theater from Brandeis University and in 2009, she received a double Masters from Harvard, focusing on Technology, Media and Learning.&nbsp;</p>', 'https://twitter.com/rosaliefayb', '', 'rosalie@codame.com', '', '0', '1570308174', NULL, NULL),
(385, 'Janeann Dill', 'janeann-dill', 'http://codame.dreamhosters.com/uploaded_images/janeann-dill.jpg', '<p>An artist, filmmaker, and scholar in the critical art history and philosophy of Experimental Animation, Janeann Dill earned her Ph.D. (magna cum laude) from the&nbsp;Europ&auml;ische Universit&auml;t f&uuml;r Interdisziplinare Studien (EGS)&nbsp;in&nbsp;Switzerland, and her M.F.A. in Experimental Animation from the&nbsp;California Institute of the Arts, School of Film and Video where Jules Engel was her Mentor. Dill was also awarded a Certificate in Film Direction from the University of California Los Angeles; and her MA and BA in Fine Arts (Painting) from Vanderbilt University.</p>\r\n<p>When living in France as an Artist-In-Resident for the&nbsp;American Center In Paris, Dill was inspired to extend the boundaries of her creative work as an abstract painter into film. She describes her work as &ldquo;painting in time.&rdquo;</p>\r\n<p>&ldquo;I was walking from the Pompidou Center to Les Halles on the plaza of the Fountain des Innocents and had a vision of my paintings moving in time. My artistic research had consistently wrapped itself around the synthesis of dreamlike atmospheres with harsh angular realities. In that moment I realized the imperative to marry the elements of &lsquo;reality&rsquo; and &lsquo;illusion&rsquo; in my paintings to a time-based art. My interest in provoking narrative through abstraction had expanded into a revelatory experience of a deep and abiding desire to move concepts through the fourth dimension to create a broader spectrum of work. I, literally, saw my paintings move in time and I imagined this was called &lsquo;film&rsquo; &hellip; or is that called &lsquo;animation&rsquo;?&rdquo;</p>\r\n<p>Dill&rsquo;s oeuvre in experimental animation is realized in a 16mm, black and white experimental film,&nbsp;Paris Is A Woman.&nbsp;This film has screened internationally, been exhibited as a monumental installation in&nbsp;Urban Lightworks&nbsp;projection on a 140&prime; exterior wall of a city building, and broadcast on the premiere program of&nbsp;scanLINE, PBS.&nbsp;Paris Is A Woman&nbsp;has been screened internationally and across venues of museum exhibitions and film festivals, including the Bass Museum of Art in Miami, curated by Elizabeth Hall; Agnes Scott Art Gallery, curated by Richard Gess, NO AGENDA BUT THEIR OWN; California Institute of the Arts&rsquo; SCREAM, curated, New Music; in Switzerland, Italy, France, Japan, New York and Los Angeles film festivals.&nbsp;Paris Is A Woman&nbsp;was also awarded&nbsp;Best Directorial Debut&nbsp;in the Short Film Category and&nbsp;Best Experimental Short Film.</p>\r\n<p>As one of the original team of interviewers of holocaust survivors, Dill was recruited to join the staff of Steven Spielberg&rsquo;s non-profit, visual history archive,&nbsp;Survivors of the Shoah Foundation, where she was one of twelve founding members of the historical cataloguing department. Professionally, she worked as an Animation Timing Director within the industry during her nine years living in Los Angeles. The daughter of two academics, Dr. Dill has numerous years of experience as a faculty in higher education and international conference presenter of her research in the visual arts.</p>\r\n<p>Dill&rsquo;s films are widely exhibited in the USA, and internationally in Spain, Italy, United Kingdom, Germany, South Africa, Saudi Arabia, Japan, Croatia, Ivory Coast and Switzerland. She has been awarded grants from the&nbsp;Ahmanson Foundation&nbsp;and the&nbsp;Irvine Foundation, and was one of ten American recipients of an Independent Media Grant awarded by the&nbsp;Annenberg Foundation.&nbsp;In&nbsp;addition to her extended artist residency at the&nbsp;American Center in Paris&nbsp;in painting, Dill received three Artist-In-the-Schools Grants from the&nbsp;National Endowment for the Arts.</p>\r\n<p><span style=\"border: 0px; font-family: inherit; font-style: inherit; font-weight: inherit; margin: 0px; outline: 0px; padding: 0px; vertical-align: baseline;\">&nbsp;</span></p>', 'https://twitter.com/DrD3455', 'http://www.jules-engel.com', '', '', '0', '1570759973', NULL, NULL),
(386, 'Diana Ayton-Shenker', 'diana-ayton-shenker', 'http://codame.dreamhosters.com/uploaded_images/diana-ayton-shenker.png', '<p>Diana Ayton-Shenker is the new Chief Executive Officer&nbsp;of the Leonardo/ISAST and ASU partnership. This partnership provides leadership for the advancement of the university&rsquo;s work in the area of art-science research and creative activity&nbsp;and amplifies ASU\'s international profile in the field. The partnership launches Leonardo and its constituent programs to a new level of growth and market presence and provides long-term continuity for the organization.</p>\r\n<p>Diana is also founding CEO of Global Momenta, a philanthropic strategy and impact innovation firm, and the Global Catalyst Senior Fellow at The New School. She is the author of four books, including &ldquo;A New Global Agenda: Priorities, Practices, &amp; Pathways of the International Community;&rdquo; her work has been featured in the World Economic Forum Agenda, Huffington Post, NPR. Before joining The New School, Ayton-Shenker founded the Fast Forward Fund, was honored by President Bill Clinton at the Clinton Global Initiative University (CGIU), and was selected as a Social Venture Network Social Innovation Award finalist. She served as the inaugural Nazarian Social Innovator in Residence at the Wharton School of Business, was named one of \"25 Leading Women Changing the World\" by Good Business New York, and was featured among &ldquo;31 Inspiring Women in Nonprofit Management&rdquo; by the University of North Carolina.</p>\r\n<p>Her United Nations briefing paper &ldquo;The Challenge of Universal Human Rights and Cultural Diversity&rdquo; has been translated into all six official languages of the U.N. and cited in more than 100 books, articles, papers, and policies worldwide. She holds an L.L.M. in International Human Rights Law (University of Essex) and an Honors B.A. in International Relations (University of Pennsylvania). She has offered guest lectures at Columbia University, Harvard, Yale, University of Pennsylvania, Northwestern, University of Chicago, Lewis &amp; Clark Law School, and taught courses at The New School, Bard College, the American University of Paris, and at Hunter College where she directed the first undergraduate human rights program in the country. She has served as a Mentor with CGIU, Unreasonable Institute, Social Good Startups, Global Engagement Summit, and PresenTense; and has served on advisory boards of the Hydration Foundation, Earth Economics, Inspired Capital, and Human &amp; Kind (formerly affiliated with Jane Goodall Institute).</p>\r\n<p><iframe src=\"https://www.youtube.com/embed/gDjwNNMYz38\" width=\"798\" height=\"449\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', 'https://twitter.com/DAytonShenker', 'http://dianaaytonshenker.com', '', '', '0', '1570760377', NULL, NULL),
(391, 'Tom Liguori', 'tom-liguori', 'http://codame.dreamhosters.com/uploaded_images/tom-liguori.png', '<p>Tom grew up in The Bronx, New York and graduated with a degree in Mechanical Engineering before relocating to the west coast to earn an MBA from San Diego State University. He and his father founded a mail order manufacturing business that grew to over 2,000 employees during his 32-year tenure of leadership. His dual responsibilities of research and development and marketing catalyzed an interest in developing new art techniques as a creative outlet.</p>\r\n<p>Through over 6 years of R&amp;D, he developed a resin and technique that achieved the effect he was looking for in his cellular art. He then looked to other unique, unusual mediums, and eventually built his &ldquo;cave&rdquo; - a vibration-free zone needed for the delicate process of producing holographs. Tom derives great joy from seeing scientific phenomena come to life in an art form that is extremely unique, vibrant, and plain fun.</p>\r\n<p>When he&rsquo;s not creating in his cave, Tom manages a venture capital business and spends a lot of time on the tennis court. He has&nbsp;been married to his wife, Sue, for 46 years, and has three children:&nbsp;Lisa, Catherine, and Daniel.</p>\r\n<p>In addition to the pure joy it brings to produce the art and have others enjoy it, Tom&rsquo;s passion&nbsp;is to help others. 100% of all proceeds from the artwork is donated to these select causes, chosen specifically for the diverse populations they serve &ndash; from kids to our military, veterans, and first responders to people in impoverished countries. Over $175,000 has been raised to date to help these amazing organizations including CODAME</p>\r\n<p><strong>100% of all proceeds from Tom&rsquo;s artwork benefits, shown at our events, go to CODAME.</strong></p>\r\n<p><img src=\"/uploaded_images/IMG_0095.jpg\" alt=\"\" width=\"795\" height=\"1060\" /></p>\r\n<p style=\"text-align: center;\">Infinity Mirror - $8000 [SOLD]</p>\r\n<p><img src=\"/uploaded_images/IMG_0092.jpg\" alt=\"\" width=\"798\" height=\"1065\" /></p>\r\n<p><img src=\"/uploaded_images/IMG_0096.jpg\" alt=\"\" width=\"796\" height=\"1062\" /></p>\r\n<p><img src=\"/uploaded_images/IMG_0090.jpg\" alt=\"\" width=\"799\" height=\"1066\" /></p>', 'https://twitter.com/tomliguoriart', 'https://www.tomliguori.com/', '', '', '0', '1582437620', NULL, NULL),
(392, 'Alistair Alexander', 'alistair-alexander', 'http://codame.dreamhosters.com/uploaded_images/alistair-alexander.jpg', '<p>Alistair&nbsp;is currently&nbsp;workong at Tactical Tech on numerous digital projects, including Securityinabox.org, myshadow.org, holistic-security.org, as well as led trainings, events and workshops with activists and campaigners around the world. In October 2016 Alistair was project lead on The Glass Room in New York - theglassroomnyc.org - an exhibition on data and privacy visited by 10,000 people in 3 weeks and will be bringing the project to London in October 2017. Last year he also helped set up an encrypted broadband communication network for the Ende Gel&Atilde;&curren;nde climate camp in Germany, in which 3,000 people shut down a coal mine and power station.</p>', 'https://twitter.com/alicma', 'https://tacticaltech.org', 'alistair@tacticaltech.org', '', '0', '1572293452', NULL, NULL),
(395, 'Nadav Hochman', 'nadav-hochman', 'http://codame.dreamhosters.com/uploaded_images/nadav-hochman.jpg', '<p>Nadav is the Associate Director of Gray Area Foundation for the Arts, San Francisco&rsquo;s premier center for promoting the intersections of art, technology, and community through exhibits, music events, an R&amp;D incubator, and educational programs.</p>', 'https://twitter.com/nadavho', 'https://www.nadavhochman.com/', 'h.nadav@gmail.com', '', '0', '1580837809', NULL, NULL),
(394, 'E. Hernandez', 'e-hernandez', 'http://codame.dreamhosters.com/uploaded_images/e-hernandez.png', '<p>E.Hernandez is a Producer and DJ living on Ohlone Land known as Oakland. They have helped throw the party &ldquo;Mutante&rdquo; which ran for almost two years as a weekly; and, &ldquo;Sucia Beat&rdquo; a monthly party focusing on Latinx music with an open format style. E.Hernandez also produces and has performed on lineups with a wide range of performers &amp; DJ&rsquo;s including: Galcher Lustwerk, Romy, Yan Cook, Xuxa Santamaria, Dax Pierson and more.</p>', '', 'https://soundcloud.com/ehernandezmusic', '', '', '0', '1579667401', NULL, NULL),
(396, 'Sheri Sobrato Brisson', 'sheri-sobrato-brisson', 'http://codame.dreamhosters.com/uploaded_images/sheri-sobrato-brisson.jpg', '<p>Sheri Sobrato Brisson - Founder of the Digging Deep Project</p>\r\n<p>Sheri Sobrato Brisson comes from a family of philanthropists. The Sobrato family started a private foundation, the Sobrato Family Foundation, 20 years ago.</p>\r\n<p>In addition to supporting other nonprofits, Sheri realized her own philanthropic vision through the creation of a project aimed at supporting the emotional needs of seriously and chronically ill children and their families.</p>\r\n<p>Sheri survived brain cancer as a young adult. Sheri is founder of the Digging Deep Project, coauthor of Digging Deep: A Journal for Young People Facing Health Challenges, and creator of Shadow&rsquo;s Edge, a mobile game for teens with medical conditions. Sheri is now on a mission to help more young people through developing electronic products. She has a long-term passion for working with kids and teens facing health challenges and holds a Masters in Counseling Psychology. Sheri is a member of The Philanthropy Workshop as well</p>', 'https://twitter.com/ssobrato', 'https://www.sobrato.com/people/sheri-sobrato/', '', '', '0', '1580838018', NULL, NULL),
(397, 'Jodi Lomask', 'jodi-lomask', 'http://codame.dreamhosters.com/uploaded_images/jodi-lomask.jpg', '<div dir=\"ltr\">\r\n<p dir=\"ltr\">Upon founding Capacitor in 1997, Jodi Lomask began exploring the intersection of science, environmentalism and new technology through movement, sound and sculpture.&nbsp; She designs motion sculptures that are only complete when the human body interacts with them. She has toured nationally and internationally with her company, creating shows inspired by the deep Earth and ocean, the forest canopy and creativity in the brain, outer space and flower sexuality, and the people who research them. Apple, NASA, TED, SFO and the Discovery Channel have commissioned her to create original works. She was recently awarded the Isadora Duncan Award for Sustained Achievement and named an Ocean Luminary by the Museum of Natural History. Her speaking engagements center around creative problem solving and interdisciplinary collaboration between artists and scientists. She will be in residence later this year at the Kennedy Center in DC. Nature Magazine, Wired, TechTV, NPR, as well as The New York Times, Time out, the Smithsonian Magazine and Dance Magazine have reported upon her work. She considers herself an experiential tour guide - making dances and environments that affect how people feel their bodies and minds.</p>\r\n</div>\r\n<div dir=\"ltr\">&nbsp;</div>', 'https://twitter.com/jodilomask', 'http://jodilomask.com/', 'jodi@capacitor.org', '', '0', '1582159278', NULL, NULL),
(398, 'Char Stiles', 'char-stiles', 'http://codame.dreamhosters.com/uploaded_images/char-stiles.png', '<p>Char Stiles is a multidisciplinary digital artist. She works using emerging technologies as tools for expression. Using computational systems and algorithms she is producing pieces that span disciplines such as video, dance, interactive installation, performance and online works. Currently, she is performing livecode around Brooklyn and teaching creative coding workshops at institutions including Carnegie Mellon University, Parsons School of Design, Massachusetts Institute of Technology and New York University.&nbsp; She graduated from Carnegie Mellon University with a Bachelor of Computer Science and Fine Art and a minor in media design.</p>', 'https://twitter.com/charstiles', 'http://charstiles.com/', '', '', '0', '1625532384', 'https://codame.threadless.com/collections/char-stiles', ''),
(402, 'Shirley Wu', 'shirley-wu', 'http://codame.dreamhosters.com/uploaded_images/shirley-wu.png', '<p><span id=\"docs-internal-guid-28df4beb-7fff-1888-160b-ebc82e478bb1\">Shirl</span>Shirley Wu is an award-winning creative focused on data-driven art and visualizations. She has worked with clients such as Google, The Guardian, SFMOMA, and NBC Universal to develop custom, highly interactive data visualizations. She combines her love of art, math, and code into colorful, compelling narratives that push the boundaries of the web.</p>', 'https://twitter.com/sxywu', 'sxywu.com', 'shirleyxueyangwu@gmail.com', '', '0', '1590347348', NULL, NULL),
(403, 'Quinn Keck', 'quinn-keck', 'http://codame.dreamhosters.com/uploaded_images/quinn-keck.jpg', '<p id=\"docs-internal-guid-66f5b99a-7fff-f3ed-92fe-55ffcc96a970\" dir=\"ltr\" style=\"line-height: 1.38; margin-top: 0pt; margin-bottom: 8pt;\"><span style=\"font-size: 8.5pt; font-family: Verdana; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">Quinn Keck (they/them) is a multidisciplinary artist working across traditional and digital mediums.&nbsp; Trained in painting and printmaking, Quinn also combines writing and code in their work and hosted poetry open mics at their openings.&nbsp; Instead of portraying the physical form of people, places and themselves, Quinn portrays their inner layers and dimensions through abstractions. &nbsp; Their work has been displayed across the United States, and are an artist in residence Kala Arts.&nbsp; They hold a Bachelor\'s in Studio Art and Human Rights from Hampshire College and a Masters of Data Science from the University of San Francisco.&nbsp;</span></p>\r\n<p><br /><span style=\"font-size: 8.5pt; font-family: Verdana; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">Participate in their Image Iterator project by filling out this <a href=\"https://forms.gle/BfJe1kPmJCvXxrhE8\">short questionnaire</a>! </span></p>\r\n<p><span style=\"font-size: 8.5pt; font-family: Verdana; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"><img src=\"/uploaded_images/compostie_still_3x5_crop.png\" alt=\"\" /></span></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/quinn_keck', 'http://www.quinnkeck.com', 'keck.quinn@gmail.com', '', '0', '1629675273', 'https://codame.threadless.com/collections/quinn-keck', 'https://www.instagram.com/quinn_tessentialy/'),
(404, 'Ash Herr', 'ash-herr', 'http://codame.dreamhosters.com/uploaded_images/ashley-herr.jpg', '<p>Ash is an artist based in sf</p>\r\n<p>&nbsp;</p>\r\n<h2>Interview with&nbsp;Ash Herr</h2>\r\n<p>I\'m a multimedia artist and creative technologist from Texas! I moved to San Francisco after university and started heading towards the intersection of art &amp; technology. Haven\'t looked back since.</p>\r\n<p><strong>What is your definition of art + tech?</strong></p>\r\n<p>fluid!</p>\r\n<p dir=\"ltr\"><strong>Who, or what, inspires you in your art and in your life?</strong></p>\r\n<p>I love art that enhances our perceptual information and sensory modalities - like how behavior can shift in a certain setting, how energy moves around us, how we change over time.</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s next for you as an artist?&nbsp;</strong></p>\r\n<p>I\'m working on several interactive installations! stay tuned :~)</p>\r\n<p><strong>Are there any technologies that you are excited about working with or that have been a game changer for you?</strong></p>\r\n<p>I have really enjoyed working in augmented reality! i think augmented reality is an incredible medium for artists, especially as it facilitates the breaking down of boundaries between our natural and artificial realities.</p>\r\n<p><strong>What&rsquo;s the best piece of advice you&rsquo;ve been given?</strong></p>\r\n<p>The Ira Glass quote on the taste gap - &ldquo;Nobody tells this to people who are beginners, I wish someone told me. All of us who do creative work, we get into it because we have good taste. But there is this gap. For the first couple years you make stuff, it&rsquo;s just not that good. It&rsquo;s trying to be good, it has potential, but it&rsquo;s not. But your taste, the thing that got you into the game, is still killer. And your taste is why your work disappoints you. A lot of people never get past this phase, they quit. Most people I know who do interesting, creative work went through years of this. We know our work doesn&rsquo;t have this special thing that we want it to have. We all go through this. And if you are just starting out or you are still in this phase, you gotta know it\'s normal and the most important thing you can do is do a lot of work. Put yourself on a deadline so that every week you will finish one story. It is only by going through a volume of work that you will close that gap, and your work will be as good as your ambitions. And I took longer to figure out how to do this than anyone I&rsquo;ve ever met. It&rsquo;s gonna take awhile. It&rsquo;s normal to take a while. You&rsquo;ve just gotta fight your way through.&rdquo;<br /><br /></p>', '', 'https://www.instagram.com/empowa/', 'ashleyjherr@gmail.com', '', '0', '1607825240', '', NULL),
(405, 'Ilithya', 'ilithya', 'http://codame.dreamhosters.com/uploaded_images/ilithya.jpg', '<div>ilithya is a digital artist, creative developer, and designer from M&eacute;xico, based in Hamburg, Germany. Her work is highly inspired by emotions, illustration, music, and street art. She&rsquo;s currently exploring a variety of new media art technologies ranging from 3DCG, generative art, and audio-reactive visuals to music videos and video art. She\'s interested in creating captivating interactive experiences for the web and installation work.</div>\r\n<div><br /> For some years, she\'s been involved in encouraging diversity in Hamburg\'s tech community by organizing meetups and workshops supporting the participation of women and minorities. She\'s also an occasional speaker and moderator.</div>\r\n<div>&nbsp;</div>\r\n<div>&nbsp;</div>\r\n<div style=\"font-family: Helvetica; font-size: 12px;\">&nbsp;</div>', 'https://twitter.com/ilithya_rocks/', 'https://www.ilithya.rocks', '', '', '0', '1616091977', 'https://shop.codame.com/collections/iiithya', ''),
(414, 'Mobina Nouri', 'mobina-nouri', 'http://codame.dreamhosters.com/uploaded_images/mobina-nouri.jpg', '<p>Mobina Nouri is a cross-disciplinary scholar and artist who is currently living and working in San Francisco. Working across a variety of media, Nouri mines her country&rsquo;s tradition of storytelling. She often turns to Persia&rsquo;s philosophies and mysticism to contemplate and reconsider the complexities which she is witness in the contemporary moment including the social connection, collective consciousness and creativity. Her practice reflects her personal history as a female immigrant who left Iran to live in the UK and later in the US.</p>\r\n<p>Nouri pursued a variety of her interests in creativity by completing her B.A. in Theatre at Fine Art Tehran University, her M.A. in Art and Design at Art University Tehran; before moving to London where she awarded her Ph.D. in <em>&ldquo;Creativity Science&rdquo;</em> at City University London in conjunction with the London Center of Creativity and Leadership, the Cass Business School and the School of Psychology. Nouri specializes in the research of emotional design (Kansei), complex creative problem solving and design thinking. She has given keynote speeches at the international conferences on creativity, innovation and design education. Nouri has been a lecturer and researcher in design and creativity.</p>', 'http://www.instagram.com/mobina.nouri.art', 'http://www.mobinanouri.com/', '', '', '0', '1598251591', '', NULL),
(406, 'Natasha Murray', 'natasha-murray', 'http://codame.dreamhosters.com/uploaded_images/natasha-murray.png', '<p>Natasha Murray&nbsp;(aka&nbsp;Illuminatty) is a VR DJ who is known for her shows in Altspace VR, Wave XR, Sansar, Neos, Twitch, and Mixer. She has been spinning with Tribe XR for just over a year, remotely bringing an eclectic mix of tech house and breaks to real-life venues around the world. She is currently a resident DJ&nbsp;for VirtualSports, an entertainment center located near Seattle, about 800 miles away from her home in Oakland, CA. Also known for her artwork, she is a featured Oculus Medium artist, and appeared in their global sculpting battle, Road To Tokyo, Episode 2. With a love of blending art and music, she designs her own stages for her resident performances at Wave XR, often using storytelling to embellish her designs and DJ sets.&nbsp;&nbsp;</p>', 'https://twitter.com/illuminattyvr', 'https://www.facebook.com/illuminatty33', '', '', '0', '1594504811', '', NULL),
(408, 'PSKL', 'pskl', 'http://codame.dreamhosters.com/uploaded_images/pascal-lamouric.jpg', '<p>PSKL (b. 1990, Vannes) is embracing a noise-driven creative exploration, creating his own tools and autonomous systems for visual creation. His interest is based on passively repurposing internet material into new works of art. Coming from an engineering background, his skill set lies at the intersection of automation and visual creation. Pascal works and lives in Berlin.</p>', '', '', 'pascal.lamouric@gmail.com', '', '0', '1684956635', 'https://codame.threadless.com/collections/pskl', ''),
(407, 'DJ Celeste', 'dj-celeste', 'http://codame.dreamhosters.com/uploaded_images/dj-celeste.png', '<p>DJ celeste is one of the first few of a new generation of djs to learn how to dj &amp; perform in virtual reality. She is currently working with a new team to design exciting 3D VR environments for future performances in TheWave, TribeXR, Second Life and AltspaceVR.</p>', 'https://twitter.com/celestelear', 'https://www.djcelestelear.com', 'oneearlear@gmail.com', '', '0', '1594756438', NULL, NULL),
(409, 'Eric Joyner', 'eric-joyner', 'http://codame.dreamhosters.com/uploaded_images/eric-joyner.jpg', '<div>\r\n<p>Joyner grew up in&nbsp;San Mateo, California, and spent some time in&nbsp;Medford, Oregon, after his family moved there.&nbsp;He was always interested in art and attended the&nbsp;Academy of Art University&nbsp;in&nbsp;San Francisco.&nbsp;He began working as a commercial illustrator in 1984&nbsp;and created the cover art for several video games, such as&nbsp;Tales of the Unknown, Volume I: The Bard\'s Tale,&nbsp;Realm of Impossibility, and&nbsp;Archon II: Adept.</p>\r\n<p>In 1999, he chose to focus only on topics that he likes. He started painting with four different elements: Mexican&nbsp;masks,&nbsp;San Francisco&nbsp;city life, old newspaper&nbsp;cartoons&nbsp;and&nbsp;<a title=\"Japanese robots\" href=\"https://en.wikipedia.org/wiki/Japanese_robots\">J</a>apanese robots. He found that the robots were the most popular feature with his friends.&nbsp;He had been collecting toy robots for about 20 years and wanted to bring them to life. In 2002, he felt that he needed another element to work off of.&nbsp;Inspired by the film&nbsp;Pleasantville, in which&nbsp;Jeff Daniels&nbsp;paints donuts, Joyner added donuts. The donuts have been featured as both objects of desire and adversaries to the robots.</p>\r\n<p>George Lucas&nbsp;is one of his most famous buyers. Several of his paintings are used as set pieces in the TV show&nbsp;The Big Bang Theory.An adaptation of his 2007 work \"The Collator\", \"Submerged\", is featured on the album cover for the&nbsp;Ben Folds Five&nbsp;album&nbsp;The Sound of the Life of the Mind. His painting \"Malfunction\" is used on the cover of&nbsp;Robot Law, a scholarly volume on robotics law and policy edited by Ryan Calo, A. Michael Froomkin, and&nbsp;Ian Kerr.</p>\r\n<p>Joyner has two books about his paintings including&nbsp;Robots and Donuts&nbsp;(2008) and&nbsp;Robotic Existentialism: The Art of Eric Joyner&nbsp;(2018).</p>\r\n<iframe src=\"https://www.youtube.com/embed/mqYSD6xlgVw\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></div>\r\n<div>&nbsp;</div>\r\n<div style=\"text-align: center;\">Eric interview about his show &ldquo;Sweet Dominion&rdquo; at Corey Helford Gallery in Los Angeles, CA.</div>', 'https://twitter.com/RobotsAndDonuts', 'https://ericjoyner.com/', 'eric@ericjoyner.com', '', '0', '1595544240', '', NULL),
(410, 'Samarth Gulati', 'samarth-gulati', 'http://codame.dreamhosters.com/uploaded_images/samarth-gulati.jpg', '<p>Samarth is a creative coder based out of India. He comes with 3 years of experience working in Adobe San Francisco, where he built custom interfaces and prototypes for their AI/ML team. He is currently building interactive online experiences for museums and galleries, and creates generative art and animated optical illusions using vanilla Javascript in the browser. At times he brings these digital creations to the physical world using a pen plotter or a 3D printer.</p>', 'https://twitter.com/samarthishere', 'https://samarthgulati.com', 'samarthgulati@outlook.com', '', '0', '1596174351', '', NULL),
(411, 'Kevin Bednar ', 'kevin-bednar', 'http://codame.dreamhosters.com/uploaded_images/kevin-bednar.jpg', '<p>Kevin Bednar is an experimental sound artist and programmer whose output ranges from ambient soundscapes to mangled percussion. As a software engineer by trade, Spednar performances are live-coded sets using tidalcycles, puredata, and other experimental software packages. In 2018, he began developing and performing with a custom software package \'Audiot\' along with Danielle Rager. Kevin is a co-founder of Cosmic Sound, a Pittsburgh-based online radio station and event production collective. He has recently helped to create the BXC Collective and Live Code Pittsburgh groups.&nbsp;&nbsp;</p>', '', 'http://spednar.com', 'spednar@gmail.com', '', '0', '1596691854', '', NULL),
(412, 'Danielle Rager', 'danielle-rager', 'http://codame.dreamhosters.com/uploaded_images/danielle-rager.jpg', '<p>Danielle Rager is an experimental composer and computational scientist. Her solo music project {arsonist} collages raucous electronics that are algorithmically manipulated using tools like TidalCycles with orchestral textures and her own violin performances. Together these elements kindle a unique symphonic form of computer music that The Wire Magazine praised as &ldquo;digital soundscapes that step into the fantastical.&rdquo; Rager&rsquo;s neuroscience research career drives her interest in multisensory integration and creation of real-time, immersive audio-visual experiences using openFrameworks and GLSL. She co-directs the Pittsburgh-based online radio platform and A/V event production collective Cosmic Sound with Kevin Bednar.&nbsp;</p>', '', 'https://thesetofarsonist.bandcamp.com/', 'dmrager@gmail.com', '', '0', '1596478540', NULL, NULL),
(413, 'Janessa Robinson', 'janessa-robinson', 'http://codame.dreamhosters.com/uploaded_images/janessa-robinson.jpg', '<p>Janessa Robinson is a multi-disciplinary artist whose work brings audiences along as she explores her life\'s journey. She has a fancy for writing poetry, music, film, graphic design, modeling, and live performance. Janessa is a singer/songwriter and rapper by the stage name WPK (Warrior Princess King).</p>\r\n<p>Janessa has hosted virtual game shows to ServiceNow&rsquo;s audience of 12,000+ people as well as performed music and poetry in virtual fundraisers for Root &amp; Rebound. Her short film Through the Fire appears in TIME magazine&rsquo;s Optimist Issue as part of Ava Duvernay&rsquo;s video project.</p>\r\n<p>Having spent years studying communication, sociology, philosophy, and law then later working in advocacy in Washington, D.C., Janessa developed a resonating voice on issues of social affairs. She has 50+ pieces of social commentary content published in TIME magazine, The Guardian, Huffington Post, EBONY, NAACP&rsquo;s The Crisis Magazine, Chopra Center and many more.</p>', 'https://twitter.com/JanessaArtist', 'https://www.janessarobinson.com/book-wpk', 'boomerangqueen@gmail.com', '', '0', '1625532721', 'https://codame.threadless.com/collections/janessa-robinson', ''),
(415, 'Cathy Laughlin', 'cathy-laughlin', 'http://codame.dreamhosters.com/uploaded_images/cathy-laughlin.jpg', '<p>As a Senior Exhibitions Creative Engineer, Cathy Laughlin designs &amp; programs generative, large scale interactive LED &amp; DMX lighting installations for Meow Wolf in Santa Fe, New Mexico. She specializes in Arduino / Teensy / FastLED installations as well as installations driven by TouchDesigner via sACN. Her professional background also includes writing industrial control software in C, C++, C#, and Python.</p>', '', '', '', '', '0', '1599457849', NULL, NULL),
(416, 'Kat Mustatea', 'kat-mustatea', 'http://codame.dreamhosters.com/uploaded_images/kat-mustatea.jpg', '<p>Kat Mustatea is an imagination engine whose tech-native storytelling stretches theater into the digital age. She has written plays in which people turn into lizards, a woman has a sexual relationship with a swan, and a one-eyed cyclops tries to fit into Manhattan society by getting a second eye surgically implanted in his head.<br />Her&nbsp;TED talk&nbsp;originates a thesis about the meaning of machines making art as society shifts radically toward autonomous, algorithmic systems. She is currently a member of&nbsp;NEW INC, the art and tech incubator at The New Museum of Contemporary Art in New York City, and a co-curator of&nbsp;EdgeCut, a live performance series that explores our complex relationship to the digital. She speaks frequently about the intersection of cutting edge technology and art (most recently at SXSW, The Pompidou Center in Paris, and Creative Tech Week in NYC).<br />Her most recent work with synthetic language and AI, including the Instagram-based performance&nbsp;Voidopolis, was&nbsp;profiled&nbsp;by Cueva Gallery.</p>', 'https://twitter.com/kmustatea', 'https://www.mustatea.com/', '\\k@mustatea.com', '', '0', '1670346885', '', 'https://www.instagram.com/kmustatea/'),
(417, 'OoakosiMo', 'ooakosimo', 'http://codame.dreamhosters.com/uploaded_images/ooakosimo.gif', '<p>Life was a video game walking among mortals masked as demons and demigods as if i was one of them shape-shifting between forms and flowing like water deeply seeping inside the deep cracks of humanity.</p>', 'https://twitter.com/OoakosiM', 'https://www.artstation.com/mohini/profile', 'mohini.ochangco@gmail.com', '', '0', '1599616761', '', NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(418, ' Rulan Tangen', 'rulan-tangen', 'http://codame.dreamhosters.com/uploaded_images/rulan-tangen.jpg', '<p><em><strong>Dancing Earth</strong> Founding Artistic Director</em></p>\r\n<p>&nbsp;</p>\r\n<p>Rulan Tangen\'s dance journey centers around the founding of DANCING EARTH CREATIONS (DE) in 2004. After years of teaching dance workshops to reservation youth, she strove to create hope and opportunity for aspiring performers, theater artists and technicians, who also serve as culture carriers, art educators, and leaders. Dancing Earth has thus inspired a new generation of Indigenous performers to express their culture in vital contemporary and experimental forms.</p>\r\n<p>Her professional experience spans international ballet, modern dance, opera, circus, film and television production including includes NYC&rsquo;s Michael Mao Dance, and Peridance Ensemble; Canada&rsquo;s Karen Jamieson Dance and Banff Aboriginal Arts; Littleglobe&rsquo;s Memorylines Opera; and Wise Fool New Mexico&rsquo;s One Solstice Circus; Marin Ballet, Catskill Ballet Theater, Redwood Empire Ballet and New York Grand Opera. Native productions include Bones Dance Opera, Ordway Theater&rsquo;s TRIBE, and Northern Plains traditional powwow dancing. She has danced, acted or choreographed for TV including PBS&rsquo;s &ldquo;Music From a Painted Cave&rdquo; and &ldquo;We Shall Remain&rdquo; series, Much Music command performance for HRH Princes Charles, and films Apocalypto, The New World,Woman Walks Ahead, Drunktown&rsquo;s Finest, and Ancestor Eyes, for which she received an Action On Film nomination for Best Actress.</p>\r\n<p>Surviving cancer to discover her leadership purpose, Tangen continues to teach extensively in Native communities across the Americas, as well as institutes of higher learning. With a vision for inclusion, she cultivates a new generation of Native dancers, through creative practice that explores intertribal diversity. Many of her students have danced with the company, crediting the work to have empowered their identity as well as their scope of artistic aspiration. Her teaching credentials include Washington University\'s Visiting Distinguished Scholar; guest artist instructor at Stanford University\'s Institute for Diversity in the Arts for \"RACE AND ENVIRONMENT;\" Native Wellness Institute Leadership Academy; Artistic Residencies at UC Riverside, Santa Fe Art Institute, and Arizona State University; and New Zealand&rsquo;s Intercreate symposium.</p>\r\n<p>Her vision is recognized through honors including the first dance fellowship for Artistic Innovation by the Native Arts and Cultures Foundation, the Costo Medal for Education, Research and Service by UC Riverside\'s Chair of Native Affairs, and as Dance Magazine\'s pick as one of &ldquo;25 To Watch,&rdquo; the New Mexico School for the Arts&lsquo; Community Arts Leadership award, the 2015 Arts &amp; Social Change Award from Arts and Healing Network, and was honored as a top ten finalist across all disciplines for the Nathan Cummings Fellowship for Social Change.</p>\r\n<p>Her work values movement as an expression of indigenous worldview, honoring matriarchal leadership, dance as functional ritual for transformation and healing, the process of decolonizing the body, and the animistic energetic connection with all forms of life on earth. She has recruited and nurtured a new generation of Indigenous contemporary dancers and holds the belief that \"to dance is to live, to live is to dance.\"</p>', 'https://twitter.com/Dancing_Earth', 'www.dancingearth.org', 'rulanova@gmail.com', '', '0', '1599608684', '', NULL),
(419, 'Claudia Alick', 'claudia-alick', 'http://codame.dreamhosters.com/uploaded_images/claudia-alick.jpg', '<p><strong><em>Calling Up Justice&nbsp;</em></strong><em>Founding Executive Producer</em></p>\r\n<p>Claudia Alick is a cultural producer, performer, and inclusion expert. Named by American Theater Magazine as one of 25 theater artists who will shape American Theater in the next 25 years, Alick has served as the founding Artistic Director of Smokin\' Word Productions, is a NY Neofuturist alum, published playwright, recipient of NYC Fresh Fruit directing award, TedXFargo speaker, the Lilla Jewel Award for Women Artists, featured on HBO&rsquo;s Def Poetry Jam and former Community Producer at the Oregon Shakespeare Festival. At OSF for ten years she produced events such as &ldquo;The Every 28 Hours Plays&rdquo;, \"The Green Show\", The Daedalus Project, OSF Open Mics as well as producing/directing audio-plays with OSF such as the Grammy nominated \"Hamlet\". Her personal projects include her podcast &ldquo;Hold On&hellip;Wait for it&rdquo;, vlog &ldquo;This Week in Cultural Appropriation&rdquo;, StreetPoetry, and one-person Show &ldquo;Fill in the Blank&rdquo; exploring disability and the medical industry. Claudia served on Oregon Arts Leaders in Inclusion, the steering committee of The Ghostlight Project, the steering committee for Black Theater Commons.&nbsp; &nbsp;She is currently managing content with The Crew Revolution black female leadership, serves as Co-president of the board of Network of Ensemble Theater, collaborated on Unsettling Dramaturgy (crip and indigenous international digital colloquium) and is on the advisory councils for the National Disability Theater, Howlround, and NW Arts Streaming Hub.&nbsp; &nbsp;Claudia Alick serves as founding executive producer of the transmedia social justice company CALLING UP whose projects include The Justice Quilt, We Charge Genocide TV, Co-artistic direction of The FURY Factory Festival, and consulting and advising funders and companies around the country.</p>', 'https://twitter.com/claudiaalick', 'http://claudiaalick.com', '', '', '0', '1599615819', '', NULL),
(420, 'Ian Garrett', 'ian-garrett', 'http://codame.dreamhosters.com/uploaded_images/ian-garrett.jpg', '<p><em><strong>Toasterlab</strong> Executive Producer</em></p>\r\n<p>&nbsp;</p>\r\n<p>Ian Garrett is an artist, designer, producer, educator, and researcher in the field of sustainability in arts and culture. Ian is Associate Professor of Ecological Design for Performance at York University in Toronto, is the co-founder and director of the Center for Sustainable Practice in the Arts (CSPA), Executive Producer at ToasterLab, and resident designer at the Indy Convergence. He is a member of Associated Designer of Canada, where he serves on the Board of Directors, He is a member of the US Institute of Theatre Technology (USITT), where he currently serves as the Curator for the United States&rsquo; entry for the 2019 Prague Quadrennial, and chairs the Education Committee for the Broadway Green Alliance.</p>\r\n<p>&nbsp;</p>\r\n<p>Ian maintains a practice focused on the integration of sustainability, design, and technology in performance and performing environments. His current work is similarly focused on the concept of Technological Haunting, using immersive media to time-shift the experience of site-specific performance. His most recent project was the multi-site-specific mixed reality project Transmission at the FuturePlay festival (Edinburgh, August 2017) and Future of Storytelling festival (New York, October 2017.</p>\r\n<p>&nbsp;</p>\r\n<p>Other recent work includes Theatre Panik&rsquo;s durational performance, Peep, at Scotiabank Nuit Blanche 2015; Erika Batdorf&rsquo;s Micro-theatre for Burnish at the Theatre Centre and Venice Biennale, and&nbsp; the set and energy capture systems for Zata Omm Dance Projects&rsquo; Vox:Lumen at the Harbourfront Centre. He has worked on installations such as DTAH Architects&rsquo; installation Ravine Portal for the Storefront for Art and Architecture&rsquo;s Toronto Site in 2014 and on the lighting team for the Crimson Collective&rsquo;s Ascension, a 150&rsquo; wide, origami-style crane sculpture at the 2010 Coachella Music Festival. He has been involved with hundreds of theatre productions as a lighting and media designer, having received the 2006 LA Weekly Theater Award for best lighting for Permanent Collection at the Kirk Douglas Theatre, and having been the lighting designer for Song of Extinction with Moving Arts, which won the 2008 LA Weekly Theater Award for Production of the Year. This work includes work as a producer having worked on the premiere of Richard Foreman and Michael Gordon&rsquo;s What to Wear at REDCAT, the Prague tour for Torry Bend&rsquo;s puppet adaptation of Aimee Bender&rsquo;s Loser, dozens of shows at the Edinburgh Festival Fringe including At Sundown&mdash;a physical theatre piece on aging and memory that he initiated, and was an associate producer on The Medea Project, a cross-cultural production of Medea in Athens and Los Angeles.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>He has spoken and consulted on the arts and the environment around the world. His writing on the topic includes the monograph Arts, the Environment, and Sustainability for the Americans for the Arts&rsquo;s New Community Visions Initiative; The Carbon Footprint of Theatrical Production, published in Readings in Performance and Ecology, from Palgrave McMilian, and the paper Theatre is No Place for a Plant in Landing Stages from the Ashden Directory. Garrett chaired the conferences Sustainability in Theatre and Staging Sustainability, 2014, and served as sustainability programme coordinator for World Stage Design in Cardiff, Wales. At WSD 2013 he led the selection committee for the temporary sustainable theatre project built for that event, the Willow Theatre.</p>', 'http://twitter.com/ToasterDog', 'https://www.toasterlab.com/', '', '', '0', '1599608775', NULL, NULL),
(421, 'Annastina Haapasaari', 'annastina-haapasaari', 'http://codame.dreamhosters.com/uploaded_images/annastina-haapasaari.jpg', '<p><em><strong>Finnish National opera and Ballet</strong> Project Manager</em></p>\r\n<p>Annastina Haapasaari is a specialist working at the crossroads of arts and technology. Currently, she is leading the Finnish National Opera and Ballet&rsquo;s Opera Beyond project that explores the possibilities of new technology for performing arts and develops the digital strategy of the organization. Having a background in cinema and in communications, Annastina has worked with the new, immersive mediums for several years and holds a major interest also in the larger societal impact of technology and digitalization.</p>', 'https://twitter.com/annastinaelisab', 'https://operabeyond.com/', '', '', '0', '1599608888', NULL, NULL),
(422, 'Drew Lichtenberg', 'drew-lichtenberg', 'http://codame.dreamhosters.com/uploaded_images/drew-lichtenberg.jpg', '<p><em><strong>Shakespeare Theatre Company</strong> Literary Manager and Resident Dramaturg</em></p>\r\n<p>&nbsp;</p>\r\n<p>Drew Lichtenberg is the Resident Dramaturg and Literary Manager at the Shakespeare Theatre Company in Washington, D.C. He has worked as a dramaturg at the National Theatre of Great Britain, the Roundabout Theatre Company on Broadway, and regional theatres across America. He currently teaches at the Catholic University of America and has taught at Eugene Lang College at the New School, among others. He holds a Doctor of Fine Arts from Yale School of Drama.</p>', 'https://twitter.com/drewlichtenberg', 'https://drewlichtenberg.com/', '', '', '0', '1599608988', NULL, NULL),
(423, 'Marcus Lobbes', 'marcus-lobbes', 'http://codame.dreamhosters.com/uploaded_images/marcus-lobbes.jpg', '<p><em><strong>Academy for Theatre and Digitality</strong> Artistic Director</em></p>\r\n<p>&nbsp;</p>\r\n<p>Marcus Lobbes has been working as a director and designer in drama and music theatre in the major German theatres since 1995. New collective working forms with the ensembles and his close contact to contemporary authors are the hallmarks of his artistic signature.</p>\r\n<p>&nbsp;</p>\r\n<p>In addition to numerous invitations and awards, his approach also finds its way into the training of young talent: he has recently been invited as a guest lecturer and speaker at the Academy of Performing Arts in Ludwigsburg, the Salzburg Mozarteum, the University of Rostock, the University of Applied Sciences in Mainz, the University of Art in Graz and the Robert Schumann Music Academy in D&uuml;sseldorf.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<div style=\"padding: 56.25% 0 0 0; position: relative;\"><iframe style=\"position: absolute; top: 0; left: 0; width: 100%; height: 100%;\" src=\"https://player.vimeo.com/video/412230037?title=0&amp;byline=0&amp;portrait=0\" width=\"300\" height=\"150\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></div>\r\n<script src=\"https://player.vimeo.com/api/player.js\"></script>', '', '', '', '', '0', '1599609188', NULL, NULL),
(424, 'Tim Nelson', 'tim-nelson', 'http://codame.dreamhosters.com/uploaded_images/tim-nelson.jpg', '<p><em><strong>In Series</strong> Artistic Director</em></p>\r\n<p>&nbsp;</p>\r\n<p>Timothy Nelson is beginning his third season as Artistic Director of DC&rsquo;s IN Series and has previously&nbsp;served in this role for the Netherlands Opera Studio and American Opera Theater, among&nbsp;others. Timothy is active in North America and Europe as a director, designer, and conductor, having&nbsp;recently created new productions for Opera Grand Rapids, Rotterdam Opera, and IN Series. Early on in&nbsp;the pandemic, Tim and the IN Series announced INVISION, The Logan Opera House Without Walls, an&nbsp;online platform &ldquo;modelled on the thrilling experience of a physical performing arts space.&rdquo; INVISION will&nbsp;offer myriad virtual venues tailored to suit a diverse and inventive slate of programming, from live-streamed performances to radio plays and opening night parties. IN Series launched INVISION with a&nbsp;virtual collaboration with the Tehran Symphony; this project, which weaves together the finale of&nbsp;Handel&rsquo;s Serse with the poetry of Rumi, has been featured on Operawire, Broadway World, and CNN.</p>', 'https://twitter.com/theinseries_ad', 'http://www.inseries.org/', '', '', '0', '1599609437', NULL, NULL),
(425, 'Christine Standfest', 'christine-standfest', 'http://codame.dreamhosters.com/uploaded_images/christine-standfest.jpg', '<p><em><strong>Impulstanz</strong> Artistic Co-Director</em></p>\r\n<p>&nbsp;</p>\r\n<p>Christine Standfest holds the position of a dramaturge at ImPulsTanz, is artistic co-director of its [8:tension] Young Choreographers\' Series and curates cooperation programs between ImPulsTanz and mumok &ndash; Museum of Modern Art Stiftung Ludwig Vienna. Besides, she is a temporary lecturer at the University of Vienna. She studied literature, linguistics and education at the FU Berlin and cultural and gender studies at the University of Lancashire, GB and has joined ImPulsTanz after a long-standing career as a performer and dramaturge with the independent scene.</p>', 'https://twitter.com/hashtag/impulstanz?lang=de', 'https://impulstanz.com/', '', '', '0', '1599609656', NULL, NULL),
(426, 'Vans Design', 'vans-design', 'http://codame.dreamhosters.com/uploaded_images/vans.jpg', '<p>Digital artist and graphic designer from Italy with an interest in abstract digital art, whose work showcases new ways to mix and blend design and art with a touch of bright contrast colors.</p>', 'https://twitter.com/VansDesign_', 'https://vansdesign.net/', 'infovansdesign@gmail.com', '', '0', '1599614809', '', NULL),
(427, 'Judit Bekker', 'judit-bekker', 'http://codame.dreamhosters.com/uploaded_images/judit-bekker.jpg', '<p>Judit is a Data Visualization Designer specialized in working with Tableau and Adobe Illustrator - but not exclusively. Her passion is mixing data analysis and graphics with UI/UX design. In 2020 she was selected as a Tableau Public Ambassador.</p>', 'https://twitter.com/juditbekker', 'https://datasorcery.wordpress.com', 'bekkerjudka@gmail.com', '', '0', '1599853354', NULL, NULL),
(428, 'Andy Cotgreave', 'andy-cotgreave', 'http://codame.dreamhosters.com/uploaded_images/andy-cotgreave.jpg', '<p>I\'ve been working in data and analytics for 15 yrs and am passionate that data visualization is as important for creative people as it is for analysts.</p>', 'https://twitter.com/acotgreave', 'https://gravyanecdote.com', 'acotgreave@tableau.com', '', '0', '1599853445', NULL, NULL),
(429, 'Neil Richards', 'neil-richards', 'http://codame.dreamhosters.com/uploaded_images/neil-richards.jpeg', '<p>Data visualisation and Tableau. I&rsquo;m a slow learner and late starter, and won&rsquo;t get everything right, but happy to be part of the community. And I&rsquo;ll always spell the full for &ldquo;visualisation&rdquo; with an &ldquo;s&rdquo; &ndash; the only zeds here will be from my afternoon nap.</p>', 'https://twitter.com/theneilrichards', 'https://questionsindataviz.com/', '', '', '0', '1599853567', NULL, NULL),
(431, 'Skipper Gemx', 'skipper-gemx', 'http://codame.dreamhosters.com/uploaded_images/skipper-gemx.png', '<p>ðŸ’ŽFounder&nbsp;<a dir=\"ltr\" href=\"https://twitter.com/mycryptogems\" data-focusable=\"true\">@mycryptogems</a></p>\r\n<p>ðŸ’Ž&nbsp;<a dir=\"ltr\" href=\"https://twitter.com/DrakonsIO\" data-focusable=\"true\">@DrakonsIO</a>&nbsp;Player</p>\r\n<div>ðŸ’Ž Positivity work of art</div>\r\n<div>&nbsp;</div>\r\n<div>ðŸ’Ž 3d GLB NFT Artist&nbsp;ðŸ‡µðŸ‡­</div>\r\n<div>&nbsp;</div>\r\n<div>ðŸ’Ž&nbsp;<a dir=\"ltr\" title=\"http://app.rarible.com/sgx\" href=\"https://t.co/ZL5sB2qbn9?amp=1\" target=\"_blank\" rel=\" noopener noreferrer\" data-focusable=\"true\">http://app.rarible.com/sgx</a></div>\r\n<p>ðŸ’Ž&nbsp;<a dir=\"ltr\" title=\"http://makersplace.com/sgx\" href=\"https://t.co/oclxPTZN8T?amp=1\" target=\"_blank\" rel=\" noopener noreferrer\" data-focusable=\"true\">http://makersplace.com/sgx</a></p>\r\n<p>&nbsp;</p>\r\n<p>An ever-learning graphic artist, always a student, a believer of the Almighty. Best selling on Rarible cryptoart market place. From the Philippines.&nbsp;</p>', 'https://twitter.com/SkipperGemx', '', '', '', '0', '1601835096', '', NULL),
(432, 'JJ', 'jj', 'http://codame.dreamhosters.com/uploaded_images/jj.png', '<p>Twentysomething design fanatics who want to push your brand to its visual best.</p>', 'https://www.instagram.com/', 'https://jjagcaoili.com/', 'jgcagcaoili@gmail.com', '', '0', '1607737916', '', NULL),
(433, 'Edith Viau', 'edith-viau', 'http://codame.dreamhosters.com/uploaded_images/edith.jpg', '<p>Edith (Montr&eacute;al, Qc) is an artist interested in systems as a medium. With an academic background in mathematics and finance, she spends her creative time exploring how to systematize creative processes. She is interested in how uncertainty manifests itself in different field of life, and how financial markets deals with this uncertainty. Founder of ARTificial MTL, she was a participant in the 2020 MUTEK AI Art Lab held in Montreal.&nbsp;</p>\r\n<h2>A quick interview with Edith</h2>\r\n<p dir=\"ltr\">After studying mathematics, I started working on my own arts projects - mostly projects about the markets and some involving artificial intelligence. I am also interested in esolangs and in electronic literature.</p>\r\n<p dir=\"ltr\"><strong>Who, or what, inspires you in your art and in your life?</strong></p>\r\n<p>Systems - how we interact with them as humans, how we build them - and how they affect us in response. For this current workshop ( the e-lit, playing with words workshop), I am interested in building systems - ways to interact with words - that helps people in their creative writings projects.</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s next for you as an artist?&nbsp;</strong></p>\r\n<p>I&nbsp;am currently evolving my practice from working with data to working with concepts. The question I am currently working on is: \"what is a market? \" Where do markets come from, and what are the principles underlying them are at the center of my exploration. For now, this involves a lot of research and reading various perspectives - I have one or two projects I am working on that go deeper into these questions.</p>', '', 'http://finartcialist.com ', 'finartcialist@gmail.com', '', '0', '1607827876', '', NULL),
(435, 'Ouchhh', 'ouchhh', 'http://codame.dreamhosters.com/uploaded_images/ouchhh.jpg', '<p><strong>Ferdi ALICI - Director and New Media Artist</strong><br /><strong>Eylul ALICI - Creative&nbsp;Director and New Media Artist</strong><br /><br />Ouchhh studio is a belief in data paintings&amp;sculptures, a mind-driven approach, discovering new technological models to reflect the variety of context and experience that shape their futuristic perspective. Consists of varied talent, from Ai Artists, engineers, academicians, creative coders, designers, motion graphic, and media artists all with one synced vision that knowledge creates an epic public experience. Ouchhh has an office in Istanbul, and partnerships in Los Angeles, Vienna, Barcelona, Paris and Berlin. They consider themselves to be a multidisciplinary creative hub focused on interactive new media platforms, data paintings, artificial intelligence, data-driven sculptures, kinetic public arts, immersive experiences, offering direction, art direction and producing A/V architectural facade performances, Ouchhh is pushing the boundaries of art by discovering architecture, art, science, technology, new media arts, and artificial intelligence. They consider each project as a challenge and take a fresh and unique approach to all their work. <br /><br />Ouchhh&nbsp;created approximately 50 public art projects for every continent like Tokyo, New York, LA, Mexico, Seattle, Chicago, Miami, Abu Dhabi, Milano, Paris, Melbourne, Shanghai, Beijing, Washington DC, Montreal, SaÌƒo Paulo, Seoul, Roma, Moscow, Prague, Brussels, Hong Kong, Jakarta, Scotland, Singapore, Las Vegas, London, Barcelona, Berlin, etc... for too many festivals and institutes such as Ars Electronica, CERN, NASA, Google, Signal, iMapp, Mutek, Melbourne&nbsp;Light Festival, Singapore Art and Science Museum, Frost Miami Science Museum, SAT Soci&eacute;t&eacute; des arts technologiques&nbsp; Montreal, Canada National Space Center UK, American Indian Arts, Atelier Des Lumiere, LLUM Light Festival Barcelona and much more...&nbsp;&nbsp;Studio works have received multiple accolades and awards in the international arena such as Reddot Best of the Best awards, German Design Award, MUSE Awards (USA) 10th Annual IDA Awards (The International Design Awards) and ADC Awards ( The Art Directors Club).</p>\r\n<p>Ouchhh always creates questions the truth behind the observation, art, science, technology, data, artificial intelligence, natural phenomena. They discover the intersection of the multidimensional worlds as a hybrid environment that redefines the future of art. Their main goal is not just to create an iconic landmark but also to create a data-driven public art to inspire and create a sense of marvel to everyone who experiences it through awe-inspiring arts.&nbsp;</p>', 'https://twitter.com/hello_ouchhh', 'http://ouchhh.tv', 'hello@ouchhh.tv', '', '0', '1605137177', '', NULL),
(439, 'Fabin Rasheed', 'fabin-rasheed', 'http://codame.dreamhosters.com/uploaded_images/fabin-rasheed.jpg', '<div>Fabin Rasheed is an India based Artist, Designer, Innovator and Technologist working in the intersection of Creativity and Technology. He has previously worked with companies like Xerox Research and Adobe as an innovator, where he had invented new expressions of creativity and had filed multiple patents in art and creativity. He holds a Masters Degree in Design from the Indian Institute of Technology Hyderabad.<br /><br />Fabin\'s works revolve around either creating tools for creativity or using technology to augment creativity and make art. Interestingly enough his works span a wide variety of technology like Artificial Intelligence, AR/VR, Gestures, Voice, Generative arts etc. His works have been featured in multiple international venues like the Florence Biennale (Florence, Italy), Ars Electronica Global Gallery,&nbsp;NeurIPS Creativity Gallery (Vancouver, Canada),&nbsp;Contemporary And Digital Art Fair (CADAF), Cueva Gallery,&nbsp;Raritan Gallery, &nbsp;Cobalt Gallery (Bangalore, India), Re.Work AI Summit (San Francisco, USA),&nbsp; etc.&nbsp;His works have also been featured in national and international media like Mashable, Popular Science, SlashGear, BuzzFeed, Indian Express, Business Standard etc.</div>\r\n<p><span style=\"font-family: arial, sans-serif;\"><span style=\"box-sizing: border-box; color: #101010;\">&nbsp;</span></span></p>', 'https://twitter.com/fabinrasheed', 'https://nurecas.com/', '', '', '0', '1605506538', '', NULL),
(436, 'Eliza Struthers-Jobin', 'eliza-struthers-jobin', 'http://codame.dreamhosters.com/uploaded_images/eliza-struthers-jobin.jpg', '<p><span style=\"color: #ffffff;\">Eliza is an artist and programmer from Montreal, Canada, currently based in Paris, France. She creates artwork with code. Her work explores our sense of play, presence, and perception through interactive audio visual installations and web-based playgrounds. She uses sound analysis, body tracking technology, machine learning and movement sensors to transpose participants into a parallel digital space in real-time. <br /><br />How does it feel to be in two places at once? How can you feel something you can\'t quite touch? She likes to imagine the hidden spaces that exist in the overlap between here and there, IRL and URL.</span></p>\r\n<h4><span style=\"color: #000000;\">&nbsp;</span></h4>', 'https://twitter.com/iamelizasj', 'https://www.elizasj.com/', 'eliza.struthersjobin@gmail.com', '', '0', '1605136744', '', NULL),
(437, 'luluxXX', 'luluxxx', 'http://codame.dreamhosters.com/uploaded_images/luluxxx.jpg', '<h4>I am working in the Visual Effects Industry as a cgi/3d artist. I&rsquo;m also a photographer and a software developer. I started using Machine Learning and Neural Network based Artificial Intelligence technology around 2015. I&rsquo;m using optical flow analysis tools to capture and manipulate motion from moving footage. I&rsquo;m building and using my own tools using Open-sourced and custom code. LuluxXX is a personal project to explore my taste and creativity and to refine my code. I enjoy manipulating still digital images and motion sequences in a transformative or generative way.</h4>', 'https://twitter.com/luluixixix', 'https://linktr.ee/luluxXX', 'luluixixix@gmail.com', '', '0', '1605137048', '', NULL),
(438, 'Michelle Brown', 'michelle-brown', 'http://codame.dreamhosters.com/uploaded_images/michelle-brown---the-bad-lament.png', '<p>Michelle Brown is a Brisbane based new media artist focused on virtual and augmented reality and creating storytelling experiences in the digital space. Michelle has produced documentary series for Australian television, created music videos and visuals for a variety of artists and festivals and has exhibited work internationally and around Australia.</p>\r\n<p>As an artist, designer and spatial thinker, their work explores the combined digital and physical space by creating site-specific relationships between virtual media and the environment.</p>\r\n<p>Michelle&rsquo;s work has been featured at Sundance Film Festival, SXSW, Cannes XR, Toronto New Wave Festival, Github Universe and they have worked with Snapchat, Google, Brisbane Festival, Curiocity plus many more.</p>\r\n<p>Michelle delivers training and mentorship programs and has presented XR workshops for arts practitioners and film-makers, working with Brisbane International Film Festival, State Library of Queensland, the Australian VR Film Festival and more.</p>', 'https://twitter.com/thebadlament', 'https://www.thebadlament.com/', '', '', '0', '1606590788', '', ''),
(440, 'Lia Coleman', 'lia-coleman', 'http://codame.dreamhosters.com/uploaded_images/lia-coleman.jpg', '<p><span data-sheets-value=\"{\" data-sheets-userformat=\"{\">Lia Coleman is an artist, AI researcher, and educator based in Puebla, Mexico. Her interests lie in AI for artwork, online education, and public murals. These days, she helps others learn how to create artwork with AI, and teaches online workshops on creating AI art with Derrick Schultz.<br /><br />Lia has taught at RISD as a visiting AI artist and researcher in ML art. Recently, she collaborated with the Partnership on AI to create a field guide for artists to use ML in an ethical manner. In 2019, Lia\'s AI research and artwork were accepted to the NeurIPS Machine Learning for Creativity And Design Workshop, where she presented a poster of her research. Lia\'s writing on AI artwork and new media art have been published in Neocha Magazine, and her work has been exhibited in Vancouver, Seattle, NYC, and Boston.<br /><br />Lia is an alumni of the School for Poetic Computation in NYC, and holds a Bsc in Computer Science from the Massachusetts Institute of Technology.</span></p>\r\n<h1 id=\"bbbb\">Interview with&nbsp;Lia Coleman</h1>\r\n<p dir=\"ltr\"><strong>Tell us about your background</strong></p>\r\n<p dir=\"ltr\">I\'m trained in machine learning and computer science. At the same time, I\'ve been a lifelong artist and been creating as far back as I can remember. For a year and a half, I worked as a machine learning engineer before realizing that I needed to have more creativity in my day-to-day. It sounds cheesy, but I realized that I can\'t exist without art as a daily part of my life. Creating is as essential as water and air to me. For me, living a life without art is suffocating.</p>\r\n<p dir=\"ltr\"><span data-sheets-value=\"{\" data-sheets-userformat=\"{\">&nbsp;</span></p>\r\n<p dir=\"ltr\"><strong>What is your definition of art + tech?</strong></p>\r\n<p dir=\"ltr\">Art and tech are just two different ways of framing and perceiving the world around us. The union of art+tech is what is created when these two modes of thinking merge in a symbiotic way. Art carries creativity, expression, a voice, a message. And tech brings tools to play with, techniques and mediums to explore, and beauty and elegance. There is a lot of room for them to bolster the other up, in a symbiotic, potentiating way. And when you look through both of these lenses, something powerful and beautiful is created.</p>\r\n<p><span data-sheets-value=\"{\" data-sheets-userformat=\"{\">&nbsp;</span></p>\r\n<p dir=\"ltr\"><strong>Who, or what, inspires you in your art and in your life?</strong></p>\r\n<p dir=\"ltr\">I\'m inspired by Derrick Schultz, my co-teacher in our AI art classes. I\'m amazed by him-- his auto-didacticism, his technical knowledge, and his natural ability to teach and empathize with others. In our classes, we try to foster a environment of care where you feel completely at ease, where these high and lofty ideas like \"machine learning\" are made approachable. Derrick and I work really well together because we agree wholeheartedly in creating an environment of care in our classes.</p>\r\n<p>For art that moves me-- Daito Manabe\'s drone work with Elevenplay was the first time I saw something so beautiful, and at the same time, extremely technically challenging. There\'s something indescribably poetic about it. My favorite piece is his collaboration with Nosaj Thing, which, without fail, always makes me tear up.&nbsp;</p>\r\n<p style=\"text-align: center;\"><iframe src=\"https://www.youtube.com/embed/qwNwl6Hm7zQ\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p dir=\"ltr\">In my personal life, Daito\'s work was crucial in giving me the push to leave my job and take the plunge into creating art full-time. It opened my eyes to what was possible. So I\'m forever thankful for that, and to him.</p>\r\n<p>As for AI influences, I really love the work of <a href=\"https://www.instagram.com/obake_ai\">Kishi Yuma</a>, <a href=\"https://www.instagram.com/salyaku_ai/\">Esteban Salgado</a>, and <a href=\"https://www.instagram.com/meooowko/\">Naoko Hara</a>. Kishi Yuma is a Japanese AI artist, whose work inspires my own work, and who I had the pleasure of <a href=\"http://neocha.com/magazine/art-ificial/\">interviewing</a> earlier this year. Esteban and Naoko are two of my former students, who are now my colleagues, who both do really amazing work. I love how they bring their own existing styles as a collage artist and motion designer, respectively, into their AI artwork. It\'s beautiful.</p>\r\n<p><span data-sheets-value=\"{\" data-sheets-userformat=\"{\">&nbsp;</span></p>\r\n<p dir=\"ltr\"><strong>What is your process or techniques for creating your work?&nbsp;</strong></p>\r\n<p dir=\"ltr\">I\'ve been using generative ML models, with a focus on StyleGAN. My artistic process starts off with collecting a dataset of a few thousand images. Next, I train the model on Google Colab or another cloud GPU service. Then, once I have a trained model, I spend the majority of my artistic process doing manipulations on that trained model&mdash; generating new images, doing latent space walks, fleshdigressions (a technique from <a href=\"https://twitter.com/AydaoGMan\">@AydaoGMan</a>, etc.</p>\r\n<p dir=\"ltr\">I almost always try to sync up my generated videos to audio as well, because music adds a completely different shape and dimension to the work. Music helps fill my work out and making it feel more whole.</p>\r\n<p dir=\"ltr\">Aside from the post-training manipulations that I mentioned, the creation and cleaning of the dataset is the other most-lengthy part of my artistic process. It\'s laborious and repetitive, but well worth the work!</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>Are there any technologies that you are excited about working with or that have been a game changer for you?</strong></p>\r\n<p dir=\"ltr\">Recently I\'ve been moving towards using my own work in my datasets instead of scraping images from the internet. I\'m currently working with a dataset of I filmed of my own face and body. I\'m also now collaborating with a few musicians in the spirit of keeping everything in-house.</p>\r\n<p dir=\"ltr\">Next, I\'m interested in trying out StyleTransfer on video, a la the work of Lulu xXX</p>\r\n<p style=\"text-align: center;\"><iframe src=\"https://www.youtube.com/embed/yDuJngoNLcw\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s next for you as an artist?</strong></p>\r\n<p>I\'ve been doing a lot of teaching lately, and haven\'t had a lot of free time for my own production, exploration, and expression. Don\'t get me wrong, I absolutely love teaching, and I always get inspired by the creative directions that my students take&mdash; but I do want to devote more time to my own production of art.</p>\r\n<p>What does this look like?</p>\r\n<p dir=\"ltr\">First, I want to produce a lot more AI artwork. Playing with new datasets that I film myself, collaborating with musicians, finding new and fun ways to interact with ML models, like with audio or with controllers.</p>\r\n<p dir=\"ltr\">Second, I like art that lives somewhere&mdash; on a wall, on a body. (Aside from making AI art, I\'ve been painting murals and designing tattoos.) So maybe in terms of my AI art this looks like projection mapping on the side of a building, or VJ-ing with an ML model during a live concert. I\'d also love to play with different real-time interaction methods, like Kinect or audio/voice input to control and manipulate a model, so people can play and interact with these models and see their effects immediately.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What is your dream project?</strong></p>\r\n<p dir=\"ltr\">On the longer-term scale, once we can go out in public again, I want to create site-specific public art happenings&mdash; aka quick-deployed shelters and inflatables for everybody to play with, touch, and climb on. Two or three months before the pandemic hit, I installed a reactive inflatable shelter for a showcase at School for Poetic Computation. Back then, I had the intention of spending a good portion of 2020 elaborating more on the themes of care, quick-shelter, and connection. Specifically, I was planning to design and fabricate quick-deploy inflatable shelters for guerilla art installations or Burning Man, but my direction changed when the world changed. However, I\'m determined to make inflatable shelters happen one way or another, once the world atmosphere is allowing!</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>Anything you\'ve thought of exploring if you had the freedom of an anonymous alias?</strong></p>\r\n<p dir=\"ltr\">There\'s not really anything I would feel more comfortable doing hidden and anonymous. I feel like I\'m pretty above board and upfront. I believe in the good of the art that I want to create. So there would be no reason to need to hide behind a moniker. If I had to pick something though, it\'d probably be VJing (to get over stage fright) or putting guerilla art on the sides of buildings like projection mapping or overnight pop-up wheat-pasted murals.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s the greater purpose behind your artwork?</strong></p>\r\n<p>That\'s a tough question. It\'s hard to see the forest from amidst the trees. But as you create more work, you see what themes you always return to as an artist.</p>\r\n<p>Over the years, I\'ve seen myself making work that is calming, playful, and aims to foster feelings of child-like wonder, entrancement, and connection through touch. Generally, I want people to be have experiences of sheer joy, fun, and surprise, and I want that to be available and accessible for anyone to enjoy. So making public art or giving away my art is really important, and so is sharing my art through teaching.</p>\r\n<p>My artist statement says it best:</p>\r\n<p dir=\"ltr\">I think about what happens when two things meet. &ldquo;With whom is my art co-habitating?&rdquo; I ask, whether I am working on a mural for a living space, or conceiving a tattoo that will sit on a friend&rsquo;s shoulder. I consider art in conversation with the space in which it lives&mdash;its home&mdash;and the people with whom it lives&mdash;its friends and family.</p>\r\n<p dir=\"ltr\">I aim to give my work an unmistakable backbone and a gentle hand. My work is characterized by clear-cut solid lines, but also pirouettes, and colors that tickle. It reaches out and invites you to play, tap, handle, press, and unfold.</p>\r\n<p dir=\"ltr\">I often give away my art and consider teaching a part of my practice. I value increased access, community ownership, and public art. Educators, community leaders, and parents are my role models.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s the best piece of advice you&rsquo;ve been given?</strong></p>\r\n<p dir=\"ltr\">\"People walk around like, \'Someone has my dream life...\'</p>\r\n<p dir=\"ltr\">Bitch, if it\'s your dream life, no one can do it better than YOU can. Your reality is all up to you. Your misery, your dreams... You have the option to change your reality at any moment that you want. If you really want something, you\'ll seek it through. You can do anything you want in this world, you really can... I don\'t doubt anything anymore.\"</p>\r\n<p dir=\"ltr\">This is a quote from the 1-year reflections of <a href=\"https://www.instagram.com/barelyawakekalee\">Kalee Choiniere</a>, a muralist and painter in Seattle, on the 1-year anniversary of her decision to stop solo-hiking after 6 months in the woods and devote her time to painting when she came back. I encourage everyone to listen to them. (It\'s up on her IG highlights.)</p>\r\n<p>I agree 100% with her&mdash; For me, it\'s beautiful that I have free will, and the agency to forge my own future. Something that\'s easy to forget in our daily lives is that we\'re here walking on this path of life, and you can choose to turn and recalibrate whenever you want, because it\'s all for you. And you don\'t need to feel guilty about that. There\'s no one else that this life is for. The decision to quit your job, to move to a different country (hell, I\'m living in Mexico right now!), to change your career, to change your life&mdash; it\'s yours.</p>\r\n<p dir=\"ltr\">Of course, you might have dependents, kids, family, a pet, or other obligations that make certain decisions more complicated, of course, but things can be worked out and compromises can always be found. There\'s always a way. We have a lot more agency than we give ourselves credit for.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/Lialialiacole/', 'http://www.liacoleman.com', '', '', '0', '1607743657', 'https://www.patreon.com/liacole', NULL),
(470, 'Jonathan Lowe', 'jonathan-lowe', 'http://codame.dreamhosters.com/uploaded_images/jonathan-lowe.jpg', '<p>Jonathan Lowe is currently collaborating with Doppel Real on a VR project that celebrates the sister-city relationship between San Francisco and Kiel, Germany. He also organizes the Narrative XR group for folks interested in immersive tech for storytelling.</p>', '', 'https://www.thevisibletheater.org/lowe/', '', '', '0', '1607459777', NULL, NULL),
(471, 'Claire Abdulla', 'claire-abdulla', 'http://codame.dreamhosters.com/uploaded_images/claire-abdulla.jpg', '<div>Claire Abdulla (or \"Claire Bear\" for fun) uses Virtual Reality Technology to create experiences. Pioneering in the new world of VR produced music videos and social media content. She also co-hosts a Virtual Reality Podcast Show called SoTech!! as well as managing Social Media Video creation platform - Tasty Loops Video.<em><br /></em></div>\r\n<div>&nbsp;</div>', '', 'http://claireabdulla.com/', '', '', '0', '1607491438', NULL, NULL),
(441, 'Lynette Lee', 'lynette-lee', 'http://codame.dreamhosters.com/uploaded_images/lynette-lee.jpg', '<p dir=\"ltr\">Lynette designs experiences that encourage play, curiosity, and empathy. Her current projects focus on bringing people together through experiential art.</p>\r\n<p>She co-founded the Flatiron coworking site Galaspace, was an editor at the art magazine, Even, and was the sole founder and operator of the award-winning specialty coffee subscription, Collected Coffee.</p>\r\n<p>Lynette received an A.B. in Government from Harvard College, an M.A. in Political Science from Columbia University, and an M.F.A. in Creative Writing from the University of Hong Kong.</p>', 'https://twitter.com/lynettexyz', 'http://www.lynettelee.com/', '', '', '0', '1613622726', '', NULL),
(442, 'Weidi Zhang', 'weidi-zhang', 'http://codame.dreamhosters.com/uploaded_images/weidi-zhang.jpeg', '<p>Weidi Zhang&nbsp;is a new media artist, visual designer, researcher, and educator.&nbsp;Her current research and media art practice interest is investigating&nbsp;the possibilities of non-linear narrativity and semantic meanings through intelligent system design and spatial&nbsp;visualization&nbsp;in immersive environments.</p>\r\n<p>Her works are featured at different venues internationally, such as the SIGGRAPH, SIGGRAPH Asia,&nbsp;Japan Media Arts Festival \'Juried Selections\',&nbsp;Times Art Museum, IEEE VIS art program, SwissNex Gallery, and among others.&nbsp;Currently, she is a Ph.D. candidate in the&nbsp;Media Arts and Technology Program, researcher in&nbsp;Experimental Visualization Lab, instructor in&nbsp;School of Art&nbsp;at the University of California, Santa Barbara. She holds her MFA degree in Art + Technology at&nbsp;California Institute of the Arts.</p>', '', 'http://www.zhangweidi.com', 'weidizhang@ucsb.edu', '', '0', '1606968277', '', NULL),
(460, 'Alex Shortt', 'alex-shortt', 'http://codame.dreamhosters.com/uploaded_images/alex-shortt.jpg', '<p>Developer and artist, looking to realize realities</p>', 'https://twitter.com/_alexshortt', 'https://www.alexshortt.com/', '', '', '0', '1607022150', NULL, NULL),
(445, 'Sam Wray', 'sam-wray', 'http://codame.dreamhosters.com/uploaded_images/sam-wray.jpg', '<p>Sam is a Creative Coder, Musician and Visualist living in London, Sam has an unstoppable interest in interactive arts, emerging technologies, their place in the every day and beyond.</p>\r\n<h1 id=\"bbbb\">Interview with Sam Wray</h1>\r\n<p dir=\"ltr\"><strong>Tell us about your background</strong></p>\r\n<p>I\'m 27, a graduate of Digital Art and Technology from Plymouth University, UK.&nbsp;I grew up in Plymouth, but now live in London.</p>\r\n<p>For the longest time I\'ve loved the fusion between art and technology. When I started creating music at age 14 I chose to use my Nintendo DS as I could load homebrew software NitroTracker onto an M3 cart, this was magical to me.</p>\r\n<p>Alongside this interest in creating using hardware, I\'ve always been an avid fan of the web and how people can access things so easily. I grew up when the transition to broadband was happening, I remember the roads being dug-up outside our house. The late 90s was such a brilliant time to be getting into technology I think, everything was shrinking and becoming more advanced in leaps-and-bounds.</p>\r\n<p>Fast-forward a few years, now my full-time work is in Brand Experience. I help shape ideas and technology choices when brands are looking to build interactive experiences. Recently I\'ve had work shown and used on the BAFTAs 2020 red carpet opening and London\'s Piccadilly Lights.</p>\r\n<p>Outside of work I like to create music using old games consoles and develop my open source audio visualisation project, modV.</p>\r\n<p>modV is my longest running project and has been my playground for all the exciting edge web APIs.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What is your definition of art + tech?</strong></p>\r\n<p>art + tech = naturally combined</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>Who, or what, inspires you in your art and in your life?</strong></p>\r\n<p>My largest inspiration to create live performance visuals came from the chiptune scene. Artists such as hellocatfood, Lazer Sausage, Dan Hett and DIY Destruction all had a profound impact on me. Seeing their visual setups, all different, mostly custom, was a huge eye-opener for me.</p>\r\n<p>Lazer Sausage\'s Processing-based visuals at the last Analog Attack in London (2014) prompted me to develop a small hack-project further, which grew into modV.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What is your process or techniques for creating your work?&nbsp;</strong></p>\r\n<p>Usually I create my pieces all within modV. I generally mix and match with what\'s available and each time I\'ve discovered some new and interesting combination.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s next for you as an artist?&nbsp;</strong></p>\r\n<p>My dream project would be to work on modV full-time. I\'d love to create a platform for people to share their own modules and presets for the software.<br /><br /><br /></p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s the greater purpose behind your artwork?</strong></p>\r\n<p>To push the limits of what is possible to artists and creators on the web and for open source projects and communities.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s the best piece of advice you&rsquo;ve been given?</strong></p>\r\n<p>Limits foster creativity.</p>', 'https://twitter.com/_2xaa', 'https://wray.pro/', 'sam@wray.pro', '', '0', '1607579812', '', NULL),
(447, 'Ben Ha', 'ben-ha', 'http://codame.dreamhosters.com/uploaded_images/ben-ha.jpg', '<p>\"Passionate about the intersection of technology, art, and culture.</p>\r\n<p>&nbsp;</p>\r\n<p>Avid surfer and chef.</p>\r\n<p>&nbsp;</p>\r\n<p>Lets build the new internet, Web 3.0\"</p>', 'https://twitter.com/itsbenha', 'http://spacesvr.io', '', '', '0', '1607450178', '', NULL),
(448, 'Sven Eberwein', 'sven-eberwein', 'http://codame.dreamhosters.com/uploaded_images/sven-eberwein.png', '<p>Sven Eberwein&nbsp;is a new media artist working at the intersection of&nbsp;computer graphics &amp; internet pop culture. His&nbsp;digital&nbsp;works are emerging from references collected all around the web, set out to explore their impact and relevance in a new context. Works of the internet, by the internet, for the internet.</p>', 'https://twitter.com/sven_eberwein', '', '', '', '0', '1606258248', NULL, NULL),
(444, 'Tim Pietrusky', 'tim-pietrusky', 'http://codame.dreamhosters.com/uploaded_images/tim-pietrusky.jpg', '<p>Tim is a digital artist, open source hacker, co-founder of LiveJS, 1/2 of schickmalzwo, mentor, visual spectacular, lightweaver and loop-drop-rookie living in Germany.&nbsp;</p>', 'https://twitter.com/timpietrusky', 'https://nerddis.co/', 'timpietrusky@gmail.com', '', '0', '1606362035', '', NULL);
INSERT INTO `artists` (`id`, `name`, `slug`, `pic`, `description`, `twitter`, `website`, `email`, `old_url`, `hidden`, `edited`, `shop_url`, `instagram`) VALUES
(443, 'Donghao Ren', 'donghao-ren', 'http://codame.dreamhosters.com/uploaded_images/donghao-ren.jpg', '<p>&nbsp;Donghao Ren received a B.S. from Peking University, then a Ph.D.<br />degree in Computer Science from the University of California, Santa<br />Barbara. His research focus is on information visualization and<br />machine learning. During his time at UC Santa Barbara, he worked on<br />user interfaces for visualization authoring, as well as visualizations<br />for machine learning.<span style=\"margin: 0px; padding: 0px; border: 0px; outline: 0px; vertical-align: baseline; background: transparent;\"><span style=\"margin: 0px; padding: 0px; border: 0px; outline: 0px; vertical-align: baseline; background: transparent;\"><span style=\"margin: 0px; padding: 0px; border: 0px; outline: 0px; vertical-align: baseline; background: transparent;\"><span style=\"margin: 0px; padding: 0px; border: 0px; outline: 0px; vertical-align: baseline; background: transparent; letter-spacing: 0.05em;\"><span style=\"color: #000000; font-family: arial, sans-serif;\"><br /></span></span></span></span></span></p>', '', 'https://donghaoren.org/', 'donghao.ren@gmail.com', '', '0', '1607467678', '', NULL),
(446, 'Marc-O-Matic', 'marc-o-matic', 'http://codame.dreamhosters.com/uploaded_images/marc-o-matic.gif', '<p>Marc O Matic is a Multidisciplinary Artist, Animator, Storyteller,<br />Director, and XR Technologist from Melbourne, Australia. As an independent Creator,<br />Marco is an Auteur of emerging tech, pioneering his creative approaches and techniques<br />to Augmented Reality storytelling with a focus on fusing AR/VR with more traditional<br />analogue art mediums. Described as Augmented Storytelling Canvases, Marc creates<br />and transforms static art, physical objects and spaces into interactive, animated and<br />experiential pieces; allowing audiences to intimately explore, understand and engage with<br />subject matter. Breaking from conventional norms of storytelling his work has aimed to<br />provide a benchmark of creative and commercial applications with immersive media.</p>\r\n<p>Marc has showcased internationally, in South Korea, Japan, Denmark and the United<br />States including events such as South by South West San Francisco&rsquo;s Game Developer&rsquo;s<br />Conference, Silicon Valley&rsquo;s VR Association, ACM Siggraph Asia and Adobe Symposium.<br />Possessing a highly intricate visual art style and attention to detail Marc continues to work<br />closely with tech companies, educational institutions and city councils to explore<br />intersections between the arts, education and entertainment; transforming complex<br />topics into engaging and immersive visual narratives and experiences.&nbsp;</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/marc0matic', 'https://www.marcomatic.com/', 'studio@marcomatic.com', '', '0', '1606594409', '', NULL),
(449, 'Qiuwen Li', 'qiuwen-li', 'http://codame.dreamhosters.com/uploaded_images/qiuwen-li.png', '<p><span id=\"docs-internal-guid-95268d2b-7fff-5e65-33fb-e99f7d9b1cf3\"><span style=\"font-size: 11pt; font-family: Arial; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">Qiuwen Li is an assistant professor of graphic design in the <a href=\"https://www.scu.edu/art/\">Department of Art and Art History</a></span><span style=\"font-size: 11pt; font-family: Arial; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"> at Santa Clara University in CA, U.S. She also is the co-founder of <a href=\"https://www.emotionlab.org/\">emotionlab</a></span><span style=\"font-size: 11pt; font-family: Arial; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">, a progressive research lab to create positive emotional experiences for people through innovative design approaches to human problems. Born in China, Qiuwen received her B.F.A. in Graphic Design from St. Cloud State University and received her MFA in Visual Studies from the Minneapolis College of Art and Design. As a Chinese woman living in the U.S., Qiuwen is in an in-between position, which also brings a distinctive perspective for her thinking, being and making. In Qiuwen&rsquo;s designs, graphic elements (shapes, color, pattern, type) are constructed, deconstructed and then reconstructed in order to create a richer experience and extend their meaning.</span></span></p>', '', 'http://qiuwenli.com/', 'qiuwendesign@gmail.com', '', '0', '1606275628', '', NULL),
(450, 'Bruno Ruviaro', 'bruno-ruviaro', 'http://codame.dreamhosters.com/uploaded_images/bruno-ruviaro.jpg', '<p>Bruno Tucunduva Ruviaro is a Brazilian composer and electronic music performer.</p>\r\n<div id=\"line-3\">&nbsp;</div>\r\n<div id=\"line-5\">Main fields of research: Music Composition, with an emphasis in Electronic Music. Related interests: electronic music composition, laptop orchestras, live-electronics, acousmatic music, sampling &amp; musical borrowing; theater, dance, linguistics, speech, radio art, linux, intellectual (im)property, music &amp; politics.</div>\r\n<div id=\"line-7\">&nbsp;</div>\r\n<div id=\"line-9\">M.A. in Electro-Acoustic Music from Dartmouth College (2004)</div>\r\n<div id=\"line-11\">D.M.A. in Music Composition from Stanford University (2010)</div>\r\n<div id=\"line-13\">Post-Doc in Electronic Music at CCRMA (2012)</div>\r\n<div id=\"line-15\">Associate Professor of Music at Santa Clara University (2012-present)</div>', 'https://twitter.com/brunoruviaro', 'https://brunoruviaro.com', '', '', '0', '1683747959', '', ''),
(451, 'Aastha Chawla', 'aastha-chawla', 'http://codame.dreamhosters.com/uploaded_images/aastha-chawla.jpg', '<p><span style=\"font-family: Arial;\"><span style=\"font-size: 14.6667px; white-space: pre-wrap;\">Aastha Chawla is currently a junior Computer Science &amp; Engineering major and Music minor at Santa Clara University. Intrigued by the ability to combine her passion for music production and coding through app development, she joined the Santa Clara Laptop Orchestra (SCLOrk) ensemble in January 2020. With SCLOrk, she discovered a newfound love for storytelling through experimental music. Earlier this fall, she released an experimental EP, titled &ldquo;SLEEPLESS,&rdquo; documenting one\'s mental progression and gradual desensitivity in regard to the global pandemic. A passionate programmer and musician, she is a strong advocate for women in STEM and women in electronic music, and is building her own niche between music and tech through her work.</span></span></p>', '', '', '', '', '0', '1606276269', NULL, NULL),
(452, 'Michael Noonan', 'michael-noonan', 'http://codame.dreamhosters.com/uploaded_images/michael-noonan.jpg', '<p>Michael Noonan is a senior at Santa Clara University studying music and mathematics. He is a classical pianist and has been working with SCLOrk since January.</p>', '', '', '', '', '0', '1606276367', NULL, NULL),
(453, 'Josh Mitchell', 'josh-mitchell', 'http://codame.dreamhosters.com/uploaded_images/josh-mitchell.jpg', '<p>Josh Mitchell is a senior majoring in physics and music at Santa Clara University. He joined SCLOrk a few years ago while looking to understand how to make guitar effects on a budget. Instead, it opened up a whole new world of wacky noises! Lately he has been interested in physical modeling synthesis methods. They form a really cool crossover between music and physics that can teach a lot about both.</p>', '', '', '', '', '0', '1606276558', NULL, NULL),
(455, 'Soliman Lopez', 'soliman-lopez', 'http://codame.dreamhosters.com/uploaded_images/soliman-lopez.jpg', '<p>Solim&aacute;n L&oacute;pez, born in Burgos, Spain in 1981, develops his artistic production between his studio in Paris, France (UAS, Updated Art Studio) and ESAT LAB, Innovation department that he runs at ESAT, Escuela Superior de Arte y Tecnolog&iacute;a de Valencia, Spain.</p>\r\n<p dir=\"ltr\">His career as an art historian and master&rsquo;s degree in Art and Communication have conditioned his artistic evolution toward what we could call conceptual, technological art.</p>\r\n<p>His work with the meaning and nature of digital archives, as shown by some pieces such as the Harddiskmuseum, an art museum on a hard disk, Framed Memory Card, Host-in, Langpath or File Genesis or more recent works in which virtual and analog worlds are connected through photogrammetry as in High Meshes, are examples of his interest in human presence and its impact in this era of communication and digitalization.</p>\r\n<p>In line with this breaking down of the two frontiers, we can find pieces such as GRID, an audiovisual symphony modulated in real-time by the wifi signal of nearby devices, Celeste, which connects the digitized skies of different places in the world also, in real-time, or Bioma, a sculpture that creates digital abstractions through biometric data of its environment.</p>\r\n<p>Technically, his works are achieved thanks to the combination of 3D techniques, electronics, software programming, artificial intelligence, virtual and augmented reality, and digital synchronization.</p>\r\n<p>His career has been built on festivals, biennials, art centers, events, and museums in Spain, USA, China, South Korea, France, Argentina, Brazil, Venezuela, Colombia, El Salvador, Nicaragua, Greece, Uruguay, Germany, England, Italy, Portugal, and Switzerland among other locations, highlighting the events of the Biennial of Digital Art in Brazil, the Biennial Nemo de Paris (Variations Art Fair), the Chronus Art Center in Shanghai, ISSEA 2019, the ZKM of Karlsruhe, Art Santa M&oacute;nica of Barcelona, the CCCC of Valencia, the IVAM of Valencia, Etopia of Zaragoza, the CAB of Burgos, the CEART of Fuenlabrada in Madrid, La Lonja of Alicante, Cigarreras of Alicante, CAC of M&aacute;laga, Es Baluard museum of Mallorca or the Nuit Blanche of Paris 2019.</p>\r\n<p>&nbsp;His work as a researcher in new media has been shared in several universities such as the UFSM in Brazil, the University Carlos III in Madrid, the Google Campus in Madrid, the UPV in Valencia, the Bancaja Fundaci&oacute;n, the Injuve, TEDx Valladolid, the Universidad de Cuenca, the Universidad Nacional de C&oacute;rdoba, Argentina, MediaLab Prado, Madrid or Technarte Bilbao, among others.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/solimanlopez', 'https://solimanlopez.com/', 'sl@solimanlopez.com', '', '0', '1684173733', '', ''),
(568, 'Vitaly Friedmann', 'vitaly-friedmann', 'http://codame.dreamhosters.com/uploaded_images/vitaly-friedmann.png', '<p>Vitaly&nbsp;loves beautiful content and does not give up easily. Born in Minsk, Belarus, he studied computer science and mathematics in Germany. While writing algebra proofs and preparing for software engineering at night in the kitchen, at the same time, he discovered a passion for typography, interface design, and writing. After working as a freelance designer and developer for 6 years, he co-founded Smashing Magazine in 2006, a leading online magazine for designers and developers. His curiosity drove him from interface design to front-end to performance optimization to accessibility and back to user experience over the years.</p>\r\n<p>Vitaly is the author, co-author, and editor of&nbsp;all Smashing books and a curator of all&nbsp;Smashing Conferences. He works as the creative lead of&nbsp;Smashing Magazine&nbsp;and front-end/UX consultant in Europe and abroad, working with European Parliament, Haufe-Lexware, Axel-Springer, and a few other companies.</p>', 'https://twitter.com/vitalyf', 'https://smart-interface-design-patterns.com/', '', '', '0', '1684177097', '', ''),
(458, 'Torin Blankensmith', 'torin-blankensmith', 'http://codame.dreamhosters.com/uploaded_images/torin-blankensmith.jpg', '<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">Torin Blankensmith is a freelance creative technologist and real-time graphics artist based out of NEW INC in New York City. He channels a multidisciplinary approach drawing on his background in human-centered design and computer science to build immersive installations, interactive experiences, and communities that encourage creativity, connectivity, empathy, expression, and play. Torin&rsquo;s work explores emerging techniques in real-time graphics pulling inspiration from systems and patterns of emergent behavior in nature. This work has translated into creating large scale environments for medical professionals to alleviate stress/burnout, for patients in clinical studies aiding in neuroscience research on brain recovery, and for commercial spaces bringing sanctuary to the urban landscape.Throughout his career, Torin has been passionate about demystifying technology through teachable moments and developing open-source tools empowering people to make their own creative work. He currently teaches creative code at Parsons School of Design. Previous clients include Mt. Sinai Hospital, Nobel Foundation, Google Creative Lab, Lab at Rockwell Group, Vice, Adobe, and Microsoft.</span></p>', 'http://twitter.com/tblankensmith', 'www.torinblankensmith.com', 'torin.blankensmith@gmail.com', '', '0', '1607100555', '', NULL),
(456, 'Mark Savage', 'mark-savage', 'http://codame.dreamhosters.com/uploaded_images/mark-savage.jpg', '<p>American native that was born with a purpose to empower and shine light where necessary. Innovation wholistic storyteller. aka&nbsp;Bitsavage</p>\r\n<h2 dir=\"ltr\">A quick chat with&nbsp;Mark Savage</h2>\r\n<p dir=\"ltr\"><strong>What is your definition of art + tech?</strong></p>\r\n<p>To me art + tech is using multiple mediums to convey a story.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>Who, or what, inspires you in your art and in your life?</strong></p>\r\n<p dir=\"ltr\">The universe and my dreams are the spark to my creations.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What is your process or techniques for creating your work?&nbsp;</strong>&nbsp;</p>\r\n<p dir=\"ltr\">Currently I paint and use Blender to create profound works!</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s next for you as an artist?&nbsp;</strong>&nbsp;</p>\r\n<p dir=\"ltr\">My next venture is to start a movement for empowered creatives globally.&nbsp;</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s the greater purpose behind your artwork?</strong></p>\r\n<p>My work emotes the reality I desire to experience moment to moment.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\"><strong>Are there any technologies that you are excited about working with or that have been a game changer for you?</strong></p>\r\n<p dir=\"ltr\">Blender is the true game changer for me!</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What is your dream project?&nbsp;</strong></p>\r\n<p dir=\"ltr\">My dream project is an NFT film with top artists collaborating.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>Anything you\'ve thought of exploring if you had the freedom of an anonymous alias?</strong></p>\r\n<p dir=\"ltr\">If I had an ANON alias I would bring more love &amp; equality to the \"ADULT\" space.&nbsp;</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\"><strong>What&rsquo;s the best piece of advice you&rsquo;ve been given?</strong></p>\r\n<p dir=\"ltr\">The best piece of advice is to not act like you know everything.</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/PhenomenalMark', 'http://www.adors.org', 'adorsorg@gmail.com', '', '0', '1608182247', '', NULL),
(457, 'Sukanya Aneja', 'sukanya-aneja', 'http://codame.dreamhosters.com/uploaded_images/sukanya-aneja.jpg', '<p><span style=\"font-family: Roboto, RobotoDraft, Helvetica, Arial, sans-serif; font-size: 13px; white-space: pre-wrap;\">Sukanya Aneja is an engineer and artist from India currently based in New York. She is interested in using code as a tool for creative expression and as a craft in itself. Her work explores the emergent quality of rule-based systems, the complex spaces between humans and computers, and technical tools and infrastructure that are often taken for granted. She currently works as a software engineer at the New York Times R&amp;D, and is a graduate of the Interactive Telecommunications Program (ITP) at NYU. She\'s an alumnus of SFPC and the Recurse Center, and her work has been exhibited at Radical Networks, NYC Media Lab Summit, Cinekid Festival, and NeurIPS.</span></p>', 'https://twitter.com/playdo_', 'http://playdo.io/', ' sukanya.aneja@gmail.com', '', '0', '1606899399', NULL, NULL),
(461, 'Kevin Smuggles', 'kevin-smuggles', 'http://codame.dreamhosters.com/uploaded_images/kevin-smuggles.png', '<p>Kevin is currently majoring in condensed matter physics at the University of Pisa, Italy; his studies involve solid-state matter and novelty designs of laser radiation emitters. Always keeping the computer work to the bare minimum, he focused on the analog side of signal shaping and metrology, deepening his knowledge in circuit bending, oscillators, and feedback systems.<br /><br />The recent encounter with the TOPLAP algorave community has given him a brand new relationship with the machine, bringing his attention to creative coding and embracing the open-source philosophy.<br /><br />He performed as a DJ in local pubs and as a live coder in the Hydra environment.<br /><br /><br /></p>', 'https://www.instagram.com/kevinsmuggles', '', 'albertobertocci@live.it', '', '0', '1607737837', '', NULL),
(463, 'Elena Kauffmann', 'elena-kauffmann', 'http://codame.dreamhosters.com/uploaded_images/elena-kauffmann.png', '<p>Kauffmann is an art-tech creative catalyst - director, producer, curator - and founder of art-tech agency D2D Art and WOW zone, the first experiential innovative and creative XR space and concept of its kind in Egypt and MENA.&nbsp;<br /><br />She enjoys working with a global network of multidisciplinary visionary creatives, artists, innovators, and art-tech experts while targeting the greater public in innovative immersive, and participatory ways. As a creative director, she specializes in projects/ cross-collaborations focused on combining creativity, art, technology, and experiential art. She seeks to push the boundaries of what is possible and pave the way for new engaging, inspiring, and empowering human-centered experiences.<br /><br />Her aim is to redefine public engagement by placing the public at the center of compelling and inspiring activations&nbsp;while simultaneously giving a voice and platform for creative thinkers, dreamers, and creators to share their visions and innovations with the world in the process.<br /><br />She belongs to a family of artists, has worked in the arts field (from development, promotion, curating, partnership-building to business development) in multiple countries and for various organizations, curated a number of art shows (exhibitions, booths at art fairs and festivals) and has developed over the years a strong and unique local and international circle of collaborators and partners.<br /><br /><a style=\"color: #1155cc; font-family: Arial, Helvetica, sans-serif; font-size: small;\" href=\"https://www.behance.net/gallery/93026491/Creative-Direction-Production-Samples\" target=\"_blank\" data-saferedirecturl=\"https://www.google.com/url?q=https://www.behance.net/gallery/93026491/Creative-Direction-Production-Samples&amp;source=gmail&amp;ust=1607232900804000&amp;usg=AFQjCNETKaeW2ekUDcLKyOf58y_mXiqzMQ\">https://www.behance.net/<wbr />gallery/93026491/Creative-<wbr />Direction-Production-Samples</a><br /><a style=\"color: #1155cc; font-family: Arial, Helvetica, sans-serif; font-size: small;\" href=\"https://www.instagram.com/d2dart/\" target=\"_blank\" data-saferedirecturl=\"https://www.google.com/url?q=https://www.instagram.com/d2dart/&amp;source=gmail&amp;ust=1607232900804000&amp;usg=AFQjCNEi4q9T7W2BOpdeHZRb0p4fiRvDnA\">https://www.instagram.com/<wbr />d2dart</a></p>', '', '', '', '', '0', '1607150624', '', NULL),
(459, 'Peter Whidden', 'peter-whidden', 'http://codame.dreamhosters.com/uploaded_images/peter-whidden.jpeg', '<p><span style=\"font-size: 11pt; font-family: \'Proxima Nova\', Arial;\" data-sheets-value=\"{&quot;1&quot;:2,&quot;2&quot;:&quot;Peter is a creative software engineer whose work spans physics, astronomy, machine learning, and computer graphics. He currently works at Amazon in Seattle on video classification technology. Peter has also worked with engineers from CERN to build interactive 3D visualizations used in particle physics. In recent years he developed software with the Data Intensive Research in Astrophysics and Cosmology (DIRAC) Institute which enabled the discovery of over 30 new minor planets in the Kuiper belt. Recently his artistic collaborations with Alex Miller of SpaceFiller have been featured in galleries and in a permanent installation in Seattle.&quot;}\" data-sheets-userformat=\"{&quot;2&quot;:14849,&quot;3&quot;:{&quot;1&quot;:0},&quot;12&quot;:0,&quot;14&quot;:[null,2,0],&quot;15&quot;:&quot;\\&quot;Proxima Nova\\&quot;, sans-serif&quot;,&quot;16&quot;:11}\">Peter is a creative software engineer whose work spans physics, astronomy, machine learning, and computer graphics. He currently works at Amazon in Seattle on video classification technology. Peter has also worked with engineers from CERN to build interactive 3D visualizations used in particle physics. In recent years he developed software with the Data Intensive Research in Astrophysics and Cosmology (DIRAC) Institute which enabled the discovery of over 30 new minor planets in the Kuiper belt. Recently his artistic collaborations with Alex Miller of SpaceFiller have been featured in galleries and in a permanent installation in Seattle.</span></p>', '', 'http://peterwhidden.com/', '14petewhidden@gmail.com', '', '0', '1606938873', NULL, NULL),
(462, 'Illest Preacha', 'illest-preacha', 'http://codame.dreamhosters.com/uploaded_images/illest-preacha.jpg', '<p>Kofi Oduro(Illestpreacha) is a Creative Coder &amp; Experience Enhancer, who merges an array of mediums&nbsp;to provide unique experiences that promote discussion, reflection, and interaction. With over 10 years of performance, event production, and audiovisual output globally, he takes inspiration from creative endeavors that are not normally seen together to create a harmonic experience for audience and users alike.</p>\r\n<div>&nbsp;</div>\r\n<div>His artistic practice is an observation of the world around us that he puts into artworks for others to relate to or disagree with. Through Videography, Poetry, and Creative Coding, He tries to highlight the realms of human performance and the human mind in different scenarios. These situations can be described as social, internal, or even biological, which we face in our everyday lives. Adding music and visuals often helps to perceive one\'s own feelings, and to highlight the different subtleties that make us human. With a dose of technology, there is an endless range of progress in human creative endeavors.</div>', 'https://twitter.com/illestpreacha', 'https://portfolio.illestpreacha.com', 'illestpreacha@outlook.com ', '', '0', '1645462562', '', 'https://www.instagram.com/illestpreacha'),
(464, 'Naoto Hieda', 'naoto-hieda', 'http://codame.dreamhosters.com/uploaded_images/naoto-hieda.jpg', '<p>Naoto Hieda is an artist from Japan based in Germany, challenging the current paradigm of productive coding to speculate its new form, namely post-coding, through their neurodiverse perspective and live-coding experiences. Currently, Hieda is a fellow of Yoshino Gypsum Art Foundation. Together with Olivia Jack, the duo founded and are organizing Hydra live coding community meetups.<br /><br /><a href=\"https://www.instagram.com/micuat\">https://www.instagram.com/micuat</a></p>', 'https://twitter.com/naoto_hieda', 'https://naotohieda.com/', '', '', '0', '1607468297', '', NULL),
(465, 'Flor de Fuego', 'flor-de-fuego', 'http://codame.dreamhosters.com/uploaded_images/flor-de-fuego.jpg', '<p>Flor de Fuego investigates digital image and media, producing images and sounds related to live coding, animation, video and the Internet. She has produced projections for full dome live coding at the Planetarium of the City of Buenos Aires and Bogota, and at the Domo Lleno 2019 festival with Iris Saladino. Recently was part of Mutek\'s Montreal Festival as part of Amplify DAI.</p>', 'https://www.instagram.com/flordefuega', 'https://flordefuego.github.io/', 'imagenesyprocesosdigitales@gmail.com', '', '0', '1607737942', '', NULL),
(466, 'GOSH Studio', 'gosh-studio', 'http://codame.dreamhosters.com/uploaded_images/gosh-studio.jpg', '<p style=\"text-align: left;\">Gosh is a visual creation studio dedicated to experiential contents and new media art.&nbsp;<br /><br />Created by Bonjour Lab and les Gentils Garcons, Gosh aims to design and produce new storytelling approaches by blending real time technologies and visual poetry.<br /><br />Passionate about space design and architecture, the studio brings a very special care to imagine meaningful immersive concepts that foster connections with audiences.<br /><br /><br /><strong>The Team:<br /><br /></strong><em>Jean-Philippe Jacquot<br /></em>Founder and CEO of Bonjour Interactive Lab and GOSH Studio<em><br /><br /></em><em>Alexandre Rivaud<br /></em>Co-founder &amp; Creative Director Art + Technology @ BonjourLab <br />Technical Art Director @GoshStudio<em><br /></em><br /><em>Benjamin Menager<br /></em>Founder and Art Supervisor, Gosh Studio<em><br /><img src=\"https://mail.google.com/mail/u/4/#inbox/FMfcgxwKjnSvzprsNfKJwKllpHJFVVjr?projector=1&amp;messagePartId=0.1\" alt=\"\" /><br /></em><br /><img src=\"https://mail.google.com/mail/u/4/#inbox/FMfcgxwKjnSvzprsNfKJwKllpHJFVVjr?projector=1&amp;messagePartId=0.1\" alt=\"\" /><br /><br /><br /></p>\r\n<p style=\"text-align: center;\"><br /><br /></p>', 'https://twitter.com/StudioGosh', 'https://gosh.studio/', '', '', '0', '1607630901', '', NULL),
(468, 'Ozan Serim', 'ozan-serim', 'http://codame.dreamhosters.com/uploaded_images/ozan-serim.png', '<p>Ozan Serim has extensive experience in Character Animation, Product and Project Management, having spent three years as Technical Director of High Fidelity, and 7 years with Pixar, working on Academy Award-winning films such as Brave and Toy Story 3. He is leading the development of a virtual reality experience TribeXR that allows people to learn, create, and share music.</p>\r\n<p>Ozan is a graduate of the San Francisco Art Institute. He is a keen tennis player and musician.</p>', '', '', '', '', '0', '1608007821', '', NULL),
(475, 'Max Zsol', 'max-zsol', 'http://codame.dreamhosters.com/uploaded_images/max-zsol.jpg', '<p>My name is Max Zsol and I&rsquo;m sharing my journey into fiction writing and self-publishing.</p>\r\n<p>I have a masters in computer engineering, and a background in marketing and advertising. I love reading fiction and non-fiction about&nbsp;robots&nbsp;and&nbsp;artificial intelligence. I have particular interest in stories that deal with the mysteries of the&nbsp;human mind&nbsp;and our&nbsp;perception of reality.</p>\r\n<p>I blog about everything related to writing in the digital age, self-publishing, marketing, and of course, sci-fi and other fiction writing. I also use&nbsp;<a href=\"https://twitter.com/maxzsol\">twitter</a>&nbsp;and&nbsp;<a href=\"https://www.instagram.com/maxzsol/\">instagram</a>.</p>\r\n<p>I believe that&nbsp;<a href=\"https://medium.learningbyshipping.com/writing-is-thinking-an-annotated-twitter-thread-2a75fe07fade\">&ldquo;writing is thinking&rdquo;</a>. And that&rsquo;s, really, the spirit behind this blog.</p>', 'https://twitter.com/maxzsol', 'https://maxzsol.com/', 'omarrr@gmail.com', '', '0', '1608015915', NULL, NULL),
(469, 'Crystal Glass', 'crystal-glass', 'http://codame.dreamhosters.com/uploaded_images/crystal-glass.jpg', '<p><a href=\"https://twitter.com/neondeathcat\" target=\"_blank\">@NeonDeathCat</a> Next-gen console // Digital Art + Design // Visual art for your Blood Rave</p>\r\n<p>music <a dir=\"ltr\" href=\"https://twitter.com/hexlitemusic\" target=\"_blank\" data-focusable=\"true\">@hexlitemusic</a>&nbsp;</p>\r\n<div><a dir=\"ltr\" href=\"https://twitter.com/8bitLA\" target=\"_blank\" data-focusable=\"true\">@8bitLA</a>&nbsp;bb&nbsp;</div>', 'https://twitter.com/neondeathcat', '', '', '', '0', '1607459298', NULL, NULL),
(467, 'William \"Bear\" Idressi', 'william-bear-idressi', 'http://codame.dreamhosters.com/uploaded_images/william-bear-idressi.jpeg', '<p>I\'m a full stack software engineer, experienced growth leader, and strategist with a demonstrated history of working in the Sales, Business development and marketing industries.</p>\r\n<p>Blockchain, tech, and real estate are my passions.</p>\r\n<p>I am motivated by Nonprofit Organizations, International Relations, Fundraising, and Policy Analysis.</p>\r\n<p>&nbsp;</p>', '', 'https://www.linkedin.com/in/williamidrissi/', '', '', '0', '1607392235', NULL, NULL),
(472, 'Pikio', 'pikio', 'http://codame.dreamhosters.com/uploaded_images/pikio.jpeg', '<p>illustrator, all sales/commission go directly to helping me afford university :)</p>', 'https://twitter.com/pikioart', 'https://pikio.com/', 'sofia@pikio.com', '', '0', '1643577667', 'https://codame.threadless.com/designs/fish-stew-pikio', 'https://www.instagram.com/pikioart/'),
(473, 'Sam Brukhman', 'sam-brukhman', 'http://codame.dreamhosters.com/uploaded_images/sam-brukhman.jpg', '<p>Sam Brukhman is the business&nbsp;development manager at&nbsp;Async Art&nbsp;and the artistic director of&nbsp;Verdigris Ensemble. With a background in classical choral music and a passion for artistic innovation, he uses both mediums to create connections between blockchain and traditional spaces through unique storytelling narratives.</p>', 'https://twitter.com/verdigrisensemb', 'https://www.verdigrismusic.org/', '', '', '0', '1607970498', '', NULL),
(474, 'Lisa Kolb', 'lisa-kolb', 'http://codame.dreamhosters.com/uploaded_images/lisa-kolb.jpg', '<p>CODAME Art+Tech Curator/Program Director</p>\r\n<p>Brand Strategist | Creative Producer | Digital Art Curator | AR/VR (XR) | Sculptural/Digital Artist showcasing #virtualbranding #DigitalArt #NFT #CryptoArt #immersive #AR #VR</p>\r\n<p>Lisa has spent her career at the intersection of brand, design, and technology. She has produced and created brand and technology initiatives for Microsoft, TiVo, Mutual of Omaha, Airstream and HBO.</p>\r\n<p>For the last two years, she has been focused on the way art is created and transformed&nbsp;by technology as well as new ways to view, experience and purchase these works. She created the Art Tech Pavilion for the 2019 Sausalito Art Festival, created and curated a Virtual Gallery and Store for CODAME Artists, onboarded several CODAME artists on to Crypto Art platforms and curated the 2020 JOYNT Festival for CODAME.</p>', 'https://twitter.com/brandsinvr', '', '', '', '0', '1608270958', '', NULL),
(476, 'Danica Sapit', 'danica-sapit', 'http://codame.dreamhosters.com/uploaded_images/danica-sapit.jpg', '<p>Full-stack web engineer, team lead at Adobe, hobbyist illustrator. I\'ve been passionate about interdisciplinary STEAM (STEM x Arts) education for a while (founded a University section + artist in residence program + course/program for it) and love&nbsp;digital and interactive storytelling methods that use creative code. I\'m also passionate about making sure that visualizations and interactivity&nbsp;all contribute to a narrative or greater social cause, such as with my work in March for Science NYC. <br /><br />I&nbsp;love to think of all the ways that technology and art/animation can be on equal footing as methods of play!<a href=\"https://www.linkedin.com/in/danica-sapit-0bb9b983/\"><br /><br /></a></p>\r\n<div id=\"gtx-trans\" style=\"position: absolute; left: -332px; top: -4.09722px;\">&nbsp;</div>', 'https://www.instagram.com/sinasapit/', 'https://danisapit.myportfolio.com/hello', 'danicasapit@gmail.com', '', '0', '1608781365', '', NULL),
(477, 'Jilt', 'jilt', 'http://codame.dreamhosters.com/uploaded_images/jilt.jpg', '<p>a 3D modeller and teacher. you can reach my last works:</p>\r\n<p>on the hive blockchain <a href=\"https://peakd.com/@jilt\">https://peakd.com/@jilt</a> (peakd blog is full of personal works)</p>\r\n<p><a tabindex=\"0\" title=\"https://behance.net/jeeltcraft\" href=\"https://behance.net/jeeltcraft\" target=\"_blank\" rel=\"noreferrer noopener\">https://behance.net/jeeltcraft</a>&nbsp;(find only the selected ones ðŸ˜‰)</p>\r\n<p>curator <a href=\"http://www.nestedneons.zone\">nestedneons.zone cyberpunk blog</a></p>\r\n<p><a href=\"https://peakd.com/@jilt\" target=\"_blank\">https://peakd.com/@jilt</a></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 'https://twitter.com/jeeltcraft', 'nestedneons.zone', 'jeeltcraft@gmail.com', '', '0', '1616107342', '', ''),
(478, 'Nataliia Frank', 'nataliia-frank', 'http://codame.dreamhosters.com/uploaded_images/nataliia-frank.jpg', '<p>Web developer with a passion for creative coding, virtual reality and all the artsy things.</p>', 'https://twitter.com/nataliiafrank', 'https://nataliiafrank.com/', '', '', '0', '1608421592', '', NULL),
(479, 'Nick Pannuto', 'nick-pannuto', 'http://codame.dreamhosters.com/uploaded_images/nick-pannuto.png', '<p>Nick Pannuto (aka Sneakyness) is an artist, producer, and programmer based in the US. He specializes in native iOS development and real-time streaming media.</p>\r\n<p>Nick is self taught, and credits most of what he knows to growing up on Internet Relay Chat (IRC) \"back when freenode was still good\"</p>', 'https://twitter.com/Sneakyness', '', '', '', '0', '1611106748', NULL, NULL),
(480, 'Colin Hunt', 'colin-hunt', 'http://codame.dreamhosters.com/uploaded_images/colin-hunt.jpg', '<p>Colin Hunt is a multimedia artist and technologist based out of Oakland, CA. His creative interests include illustration, writing, industrial fabrication, and tech art using tools such as Photoshop and Processing. Most recently, he has worked on Entwined Meadow, Charles Gadeken\'s latest sculpture in Golden Gate Park, coding LED patterns in Java. He has a passion for comic books and runs the Bradbury 52, a challenge to write a short story every week for an entire year.</p>', 'https://twitter.com/cfhhunt', '', 'cfhhunt@gmail.com', '', '0', '1612642213', '', NULL),
(481, 'Xinran Yuan', 'xinran-yuan', 'http://codame.dreamhosters.com/uploaded_images/xinran-yuan.jpg', '<p>Head of Global Partnerships, VIVE Arts Lives and works in New York</p>\r\n<p>M.F.A. in Sculpture/Studio, University of Illinois, Urbana-Champaign, 2014</p>\r\n<p>A.B. in Visual and Environmental Studies, Harvard University, 2010</p>\r\n<h2>Xinran Yuan\'s Project Highlights at VIVE Arts</h2>\r\n<p><img src=\"https://media-exp1.licdn.com/dms/image/C4D2DAQG9aLIy0PKlRQ/profile-treasury-image-shrink_8192_8192/0/1601697375783?e=1613689200&amp;v=beta&amp;t=ijbwGWMshsupnaLQXK-cOmkr7KP2iDV2L9lXT-nISpU\" alt=\"\" /></p>\r\n<p style=\"text-align: center;\">Mus&eacute;e du Louvre, Mona Lisa Beyond the Glass</p>\r\n<p>Mus&eacute;e du Louvre\'s first VR experience, an integral component of the Leonardo da Vinci landmark exhibition on view Oct 24, 2019-Feb 24, 2020 Articles:&nbsp;<a href=\"https://www.nytimes.com/2019/10/15/arts/design/mona-lisa-vr-louvre.html\">New York Times</a>&nbsp;and&nbsp;<a href=\"https://news.artnet.com/exhibitions/louvre-embraced-virtual-reality-leonardo-blockbuster-1686169\">Artnet</a></p>\r\n<p><img src=\"https://media-exp1.licdn.com/dms/image/C4D2DAQH2Wwrf0V6pTA/profile-treasury-image-shrink_800_800/0/1601703495865?e=1613689200&amp;v=beta&amp;t=9ngrObwos7Ct6xderdV0ZSqyP-mgq4thE7E5ulnxOc0\" alt=\"\" /></p>\r\n<p style=\"text-align: center;\">Venice Biennale 2019, Endodrome by Dominique Gonzalez-Foerster</p>\r\n<p>First official VR commission of the Venice Biennale\'s main exhibition. On view at the Arsenale as part of \"May You Live in Interesting Times\" curated by Ralph Rugoff. <a href=\"https://www.youtube.com/watch?v=AZu2YKgUqww\">https://www.youtube.com/watch?v=AZu2YKgUqww</a></p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"https://media-exp1.licdn.com/dms/image/C4D2DAQEoX62NQMOzzg/profile-treasury-image-shrink_1920_1920/0/1596573950017?e=1613689200&amp;v=beta&amp;t=bb9utzFjwOYWOMh8EHiECHHHUqRjd78F19DdML6bQYU\" alt=\"\" /></p>\r\n<p style=\"text-align: center;\">AMNH\'s T. rex: Skeleton Crew</p>\r\n<p>AMNH\'s first multi-player interactive VR exhibition, as part of the blockbuster exhibition T. rex: The Ultimate Predator, on view March 11, 2019 - August 9, 2020. Behind the Scenes: <a href=\"https://www.youtube.com/watch?v=y35HlzdcEgE\">https://www.youtube.com/watch?v=y35HlzdcEgE</a></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', '', 'http://xinranyuan.com/', 'xinranyuan@gmail.com', '', '0', '1613618396', '', NULL),
(482, 'Jenny Guo', 'jenny-guo', 'http://codame.dreamhosters.com/uploaded_images/jenny-guo.jpg', '<p style=\"margin-top: 0px; margin-bottom: 0px; display: inline;\">Jenny Guo is a co-founder of LumiereVR, which is dedicated to using Virtual Reality (VR) to bridge the gaps between tech, arts, and design. She is a cross-border creative producer, art collector and tech entrepreneur. She has been named on Forbes 30 under 30 twice for Asia and China in 2018 and was voted in the top 10 women in VR in China in 2016.</p>\r\n<p style=\"margin-top: 0px; display: inline;\">Backed by HTC ViveX and TechStars, her company LumiereVR won the top 10 VR projects in 2016 in China. The VR films she had worked on have also won multiple awards in both Asia and U.S including a prestigious Lumiere award from The Advanced Imaging Society.</p>\r\n<p>She majored in Electronic Art and Political Studies at Bard College and later studied Creative Producing at Columbia University. Prior to joining the VR industry, Ms. Guo had extensive experience in auction houses and art dealing between China, and U.S.</p>\r\n<p style=\"margin-bottom: 0px;\">She has spoken at multiple conferences including Harvard Graduate School of Design, J.P Morgan, VREdEx, TEDxBohaibay, and Wharton School of Business.</p>', '', '', '', '', '0', '1613938080', '', 'https://www.instagram.com/littlejnewyork/'),
(484, 'Xin Liu', 'xin-liu', 'http://codame.dreamhosters.com/uploaded_images/xin-liu.jpg', '<p>Xin Liu (b. 1991, Xinjiang/China) is an artist and engineer.</p>\r\n<p>In her practice, Xin creates experiences/experiments to take measurements in our personal, social and technological spaces in a post-metaphysical world: between gravity and homeland, sorrow and the composition of tear, gene sequencing and astrology. She examine the discourse-power nexus as an active practitioner, an experimenter and a performer. Her recent research and interest center around the verticality of space, extraterrestrial explorations and cosmic metabolism.</p>\r\n<p>Xin is the Arts Curator in the Space Exploration Initiative in MIT Media Lab, a member of New INC in New Museum and a studio resident in Queens Museum. She is also an artist-in-residence in SETI Institute. She is recipient of numerous awards and residencies, including Forbes 30 under 30 Asia, the Van Lier Fellowship from Museum of Arts and Design, Sundance New Frontier Story Lab, Huayu Youth Award Finalist, Creative Capital On Our Radar, inaugural Europe ARTificial Intelligence Lab residency, inaugural ONX studio program (founded by New Museum and Onassis NY) and Pioneer Works Tech Residency. She has been commissioned by institutions including Abandon Normal Devices Festival (UK), Ars Electronica (Austria), Media Art Xploration Festival (US) and Onassis Foundation Enter Program. She is an advisor for LACMA Art+Tech Lab and a faculty member at The Terraforming, a new research program at Strelka Institute in 2020.</p>\r\n<p>Xin graduated from MIT Media Lab with a master degree in Media Arts and Sciences after her M.F.A from Rhode Island School of Design and B.E from Tsinghua University in Beijing (Measurement, Control Technology, and Instrument).</p>\r\n<p>åˆ˜æ˜•ï¼ˆ1991å¹´ç”ŸäºŽæ–°ç–†ï¼Œä¸­å›½ï¼‰æ˜¯ä¸€ä½è‰ºæœ¯å®¶å’Œå·¥ç¨‹å¸ˆï¼Œä½œå“å½¢å¼åŒ…å«è¡¨æ¼”ï¼Œå™¨æ¢°ï¼Œè£…ç½®ï¼Œç§‘å­¦å®žéªŒå’Œå­¦æœ¯è®ºæ–‡ã€‚åœ¨å¥¹çš„å®žè·µé‡Œï¼Œä½“éªŒäº¦å®žéªŒ &mdash;&mdash; åœ¨åŽå½¢è€Œä¸Šçš„ä¸–ç•Œé‡Œï¼Œæµ‹é‡ä¸ªä½“ï¼Œç¤¾ä¼šå’ŒæŠ€æœ¯ä¹‹é—´çš„è·ç¦»å’Œå¼ åŠ›ã€‚å¥¹æœ€è¿‘çš„ç ”ç©¶é›†ä¸­åœ¨ï¼šåž‚ç›´ç©ºé—´ï¼Œåœ°å¤–æŽ¢ç´¢å’Œå®‡å®™ä»£è°¢ã€‚</p>\r\n<p>åˆ˜æ˜•ç›®å‰æ‹…ä»»éº»çœç†å·¥å­¦é™¢åª’ä½“å®žéªŒå®¤å¤ªç©ºæŽ¢ç´¢è®¡åˆ’çš„è‰ºæœ¯ç­–å±•äººï¼Œçº½çº¦æ–°ç¾Žæœ¯é¦†New INCè®¡åˆ’çš„æˆå‘˜ï¼Œä¹Ÿæ˜¯çº½çº¦çš‡åŽç¾Žæœ¯é¦†çš„é©»åœ°è‰ºæœ¯å®¶ã€‚2019ç§‹å­£èµ·ï¼Œå¥¹å°†ä½œä¸ºSETIé©»åœ°è‰ºæœ¯å®¶å¼€å§‹ä¸¤å¹´çš„æžåœ°ç ”ç©¶ã€‚å¥¹æ›¾èŽ·å¾—çº½çº¦Museum of Arts and Designçš„Van Lierå¥–é‡‘ï¼ŒSXSWäº¤äº’åˆ›æ–°å¥–ï¼ŒFastCoDesignå’ŒCore77å¥–é¡¹ï¼Œå…¥å›´åŽå®‡é’å¹´å¥–å†³èµ›ã€‚å¥¹çš„ä½œå“æ›¾åœ¨å¥¥åœ°åˆ©ç”µå­è‰ºæœ¯èŠ‚ï¼ˆ2017-2019ï¼‰ï¼Œæ³¢å£«é¡¿ç¾Žæœ¯é¦†ï¼ˆ2016ï¼Œ2017ï¼‰ï¼Œåœ£ä¸¹æ–¯ç”µå½±èŠ‚ï¼ˆ2017,2020ï¼‰ï¼Œç¿ è´å¡ç”µå½±èŠ‚ï¼ˆ2017ï¼‰ï¼ŒåŒ—äº¬æ°‘ç”Ÿç¾Žæœ¯é¦†ï¼ˆ2017.2018ï¼‰ï¼Œä¸­å¤®ç¾Žæœ¯å­¦é™¢ç¾Žæœ¯é¦†ï¼ˆ2018ï¼‰ï¼ŒOCATä¸Šæµ·ï¼ˆ2015ï¼‰ç­‰æœºæž„å±•å‡ºï¼Œå¹¶åœ¨è¯¸å¤šç¾Žå›½è®¡ç®—æœºåä¼š(ACM)ä¼šè®®å‘è¡¨ã€‚ä½œä¸ºç ”ç©¶é™¢ï¼Œå¥¹æ›¾åœ¨å¾®è½¯ç ”ç©¶é™¢ï¼ˆçº½çº¦ã€äºšæ´²åŒ—äº¬ï¼‰ï¼Œè°·æ­Œå…ˆè¿›æŠ€æœ¯éƒ¨é—¨(Google ATAP)å·¥ä½œã€‚åˆ˜æ˜•æ¯•ä¸šäºŽæ¸…åŽå¤§å­¦ç²¾å¯†ä»ªå™¨ä¸Žæœºæ¢°å­¦ä¸“ä¸šï¼Œåœ¨ç½—å¾·å²›è®¾è®¡å­¦é™¢èŽ·å¾—çº¯è‰ºæœ¯ç¡•å£«å­¦ä½ï¼Œéº»çœç†å·¥åª’ä½“å®žéªŒå®¤ç¡•å£«å­¦ä½ã€‚</p>\r\n<p>&nbsp;</p>\r\n<p>EDUCATION</p>\r\n<p>Massachusetts Institute of Technology, Cambridge, MA, USA - Master of Science, in Media Arts and Sciences</p>\r\n<p>Rhode Island School of Design, Providence, RI, USA - Master of Fine Arts, in Digital+Media</p>\r\n<p>Tsinghua University, Beijing, CHINA - Bachelor of Engineering, in Measurement, Control Technology, and Instrument &amp; Bachelor of Arts, in Interaction Design (Second Major)</p>', '', 'https://www.xxxxxxxxxinliu.com/', '', '', '0', '1613868189', '', 'https://www.instagram.com/xin_liu_studio/'),
