(174, 'Wild Goose Moving Meditation', 'wild-goose-moving-meditation', '2020-12-16', 'http://codame.dreamhosters.com/uploaded_images/wild-goose-moving-meditation.png', '<center>Wed, Dec 16th @ 6:00PM&nbsp;PST (<a href=\"https://time.is/6:00PM_16_December_2020_in_San_Francisco/New_York/Berlin/Hyderabad/Shanghai?CODAME\" target=\"_blank\">timezone converter</a>)</center>\r\n<p><!-- Ticket Tailor Widget. Paste this in to your website where you want the widget to appear. Do no change the code or the widget may not work properly. --------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------></p>\r\n<center>\r\n<p id=\"&rdquo;fest-10&rdquo;\"><em>Part of the&nbsp;<strong>10th</strong> annual <a href=\"/events/art-tech-festival-2020-joynt\">CODAME ART+TECH Festival</a></em></p>\r\n<p>&nbsp;</p>\r\n</center>\r\n<h3>Wild Goose Moving Meditation is a rough translation of Dayan Qigong (å¤§é›æ°—åŠŸ). This Qigong is focused on well being, balance, flexibility, mind-body connection, and play. The form is easy to learn and adaptable for students of all ages and fitness levels. There\'s no need for mats or special clothes, making it a perfect break around the office or anywhere you can pause for presence.</h3>\r\n<h3>&nbsp;</h3>\r\n<p>&nbsp;</p>\r\n<!-- TicketTailor BUTTON (start) ----------------------------------------------------------------------------\r\n-------------------------------------------------------------------------------------------------------------------->\r\n<table style=\"background-color: #351e58; width: 100%; margin-left: auto; margin-right: auto;\" cellpadding=\"10px\">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/463353#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; color: #00a4a7; background-color: #000000; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Festival 2020\" /></a></p>\r\n<p style=\"text-align: center;\"><em><strong>Or get the&nbsp;<a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\">ALL ACCESS pass</a> to CODAME ART+TECH Festival 2020 #JOYNT </strong></em><em>for 10 days of Workshops, Live Events, and Anytime Experiences!</em></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<!-- TicketTailor BUTTON (end) ----------------------------------------------------------------------------\r\n-------------------------------------------------------------------------------------------------------------------->\r\n<p>&nbsp;</p>\r\n<h3>ã€Ž SKILL LEVEL ã€</h3>\r\n<ul>\r\n<li>Beginner.&nbsp;No previous experience with meditation required.&nbsp;</li>\r\n<li>Great for all age levels! Kids can enjoy mimicing the movements of animals &amp; qigong is popular with older practitioners who are looking for a gentle, adaptable alternative to other practices like yoga, dance, and gymnastics.&nbsp;</li>\r\n</ul>\r\n<h3>ã€Ž WORKSHOP OUTLINE ã€</h3>\r\n<ul>\r\n<li>TBA</li>\r\n</ul>\r\n<h3>ã€Ž ATTENDES BRING ã€</h3>\r\n<ul>\r\n<li>Wear clothse that are comfortable and provide a full range of motion.</li>\r\n<li>Have water or some green tea at hand to stay hydrated.</li>\r\n</ul>\r\n<h3>ã€Ž CODAME PROVIDES ã€</h3>\r\n<p>Slides TBA</p>\r\n<h3>ã€Ž SCHEDULE ã€</h3>\r\n<ul>\r\n<li>Wed, Dec 17</li>\r\n<li>6:00 PM</li>\r\n<li>1.5 hours</li>\r\n</ul>\r\n<h3>&nbsp;&nbsp;</h3>\r\n<!-- TicketTailor BUTTON (start) ----------------------------------------------------------------------------\r\n-------------------------------------------------------------------------------------------------------------------->\r\n<table style=\"background-color: #351e58; width: 100%; margin-left: auto; margin-right: auto;\" cellpadding=\"10px\">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/463353#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; color: #00a4a7; background-color: #000000; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Festival 2020\" /></a></p>\r\n<p style=\"text-align: center;\"><em><strong>Or get the&nbsp;<a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\">ALL ACCESS pass</a> to CODAME ART+TECH Festival 2020 #JOYNT </strong></em><em>for 10 days of Workshops, Live Events, and Anytime Experiences!</em></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<!-- TicketTailor BUTTON (end) ----------------------------------------------------------------------------\r\n-------------------------------------------------------------------------------------------------------------------->\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<h3 style=\"text-align: left;\">ã€Ž CODAME&nbsp;#CodeArtTogether Workshops ã€</h3>\r\n<p>&nbsp;</p>\r\n<table style=\"height: 101px;\" width=\"100%\">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p dir=\"ltr\" style=\"line-height: 1.2; text-align: center; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 36pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">ðŸ§ âœ¨</span>&nbsp;<span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"><br /></span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">Connect</span></p>\r\n</td>\r\n<td style=\"text-align: center;\"><span id=\"docs-internal-guid-81f37ba5-7fff-97be-c713-6edc787897a0\"><span style=\"font-size: 36pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">ðŸš§ðŸŽ¨</span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"><br /></span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">Create</span></span></td>\r\n<td>\r\n<p dir=\"ltr\" style=\"line-height: 1.2; margin-top: 0pt; margin-bottom: 0pt; text-align: center;\"><span style=\"font-size: 36pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">ðŸ¤©ðŸ’¬ </span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"><br /></span><span style=\"font-family: \'Source Serif Pro\', serif;\"><span style=\"font-size: 24px; white-space: pre-wrap;\">Celebrate</span></span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style=\"text-align: start;\">Connecting, Creating, and Celebrating&nbsp;are pillars of the&nbsp;<a href=\"/projects/code-art-together\">CODAME #CodeArtTogether workshops</a>!&nbsp;</p>\r\n<p style=\"text-align: start;\">Workshops are great for team building, remote or IRL. They cultivate space to play, which guides sense-making and sparks innovation. Attendees become featured artists with the option to show their workshop creations in CODAME galleries.&nbsp;<a href=\"/projects/code-art-together\">Learn more about this exciting offering</a><a href=\"https://www.tickettailor.com/checkout/view-event/id/486392/chk/4cfa/?modal_widget=true&amp;widget=true&amp;d\">!</a></p>\r\n<p style=\"text-align: start;\">What topics grab your curiosity to learn or teach?&nbsp;Let us know through our&nbsp;<a href=\"/pages/call-for-workshops\">call for workshops</a>&nbsp;and&nbsp;<a href=\"/pages/join-us\">#JOYNT US</a>&nbsp;as a sponsor, volunteer, or workshop leader!</p>\r\n<p style=\"text-align: start;\">&nbsp;</p>\r\n<p style=\"text-align: start;\">&nbsp;</p>\r\n<center>ðŸ’Ÿ ðŸ‘¾ ðŸ’œ ðŸ‘¾ ðŸ’Ÿ</center>\r\n<p style=\"text-align: center;\">CODAME is a member of Intersection for the Arts&nbsp;<br />a non profit 501(c)(3)&nbsp;organization.</p>\r\n<p style=\"text-align: center;\">All proceeds will be split with the participating artists.</p>\r\n<p style=\"text-align: center;\"><a href=\"https://www.flipcause.com/secure/cause_pdetails/NjU0OA==\">Donations</a>&nbsp;are always welcome.</p>\r\n<p style=\"text-align: center;\">Thank you for your support for ART &hearts;ï¸ TECH !!!</p>\r\n<p style=\"text-align: center;\"><a href=\"/pages/code-of-conduct\">Code of Conduct</a>&nbsp;for all attendees.&nbsp;</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p>&nbsp;</p>', 'jordan-gray', 'wild-goose-moving-meditation,art-tech-festival-2020-joynt', '', '', '', '', '0', 'workshop', 'https://www.tickettailor.com/events/codame/463353#ticket_selection', ''),
(175, 'Make AR Holiday Cards', 'make-ar-holiday-cards', '2020-12-15', 'http://codame.dreamhosters.com/uploaded_images/make-ar-holiday-cards.png', '<p dir=\"ltr\" style=\"text-align: center;\">Part of the 10th annual&nbsp;<a href=\"/events/art-tech-festival-2020-joynt\" target=\"_blank\">CODAME ART+TECH Festival</a></p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">Tuesday, Dec 15, 2020, 6:00 PM PST (1 hour 45 min) (check your&nbsp;<a style=\"box-sizing: border-box; color: #00a4a7 !important;\" href=\"https://time.is/1000AM_12_December_2020_in_San_Francisco/New_York/London/Berlin/Hyderabad?CODAME\">timezone</a>)<span id=\"docs-internal-guid-a7336780-7fff-43db-e918-f1975363585d\" style=\"box-sizing: border-box;\">&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p>Personalize a template to create a holiday greeting card with an interactive experience where 3D objects are seemingly placed in the real world. (Augmented reality). Create a fun combination of the real and virtual world as an original way to greet your friends and family. The result can be viewed on modern smartphones (iPhone SE and newer.) This workshop is accessible for those with no coding or 3d modeling experience. Those with HTML/CSS or Blender skills will be able to further customize. Proceeds from this workshop will benefit Rainbow Railroad, helping to resettle LGBT folks from unsafe countries.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<table style=\"background-color: #351e58; width: 100%; margin-left: auto; margin-right: auto;\" cellpadding=\"10px\">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/463376#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; color: #00a4a7; background-color: #000000; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Festival 2020\" /></a></p>\r\n<p style=\"text-align: center;\"><em><strong>Or get the&nbsp;<a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\">ALL ACCESS pass</a>&nbsp;to CODAME ART+TECH Festival 2020 #JOYNT&nbsp;</strong></em><em>for 10 days of Workshops, Live Events, and Anytime Experiences!</em></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>&nbsp;&nbsp;</p>\r\n<p><iframe src=\"https://www.youtube-nocookie.com/embed/VkZdfgrTqhs\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<h3>ã€Ž SKILL LEVEL ã€</h3>\r\n<ul>\r\n<li style=\"box-sizing: border-box;\">Open to all levels.</li>\r\n<li style=\"box-sizing: border-box;\">No specific background required for this workshop, just bring your curiosity!&nbsp;</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h3>ã€Ž WORKSHOP OUTLINE ã€</h3>\r\n<ul>\r\n<li><span style=\"font-family: Arial;\"><span style=\"font-size: 13px; white-space: pre-wrap;\">TBA</span></span></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h3>ã€Ž ATTENDES BRING ã€</h3>\r\n<p>&nbsp; Environment Setup:</p>\r\n<ul>\r\n<li>Please open a&nbsp;<a href=\"https://glitch.com/\">Glitch account</a>&nbsp;(free)</li>\r\n<li>If possible, bring a 3d model in both <strong>.glb</strong> and <strong>.usdz</strong> formats. You can find free 3d models on&nbsp;<a href=\"https://sketchfab.com/feed\">Sketchfab</a></li>\r\n</ul>\r\n<p>&nbsp; and as usual:</p>\r\n<ul>\r\n<li>Computer &amp; power/charger.</li>\r\n<li><span style=\"font-family: Arial; font-size: 13px; white-space: pre-wrap;\">Zoom installed ahead of time.</span></li>\r\n<li>Optional: 2nd monitor or screen so you can see the Zoom while working.</li>\r\n<li>Hop on the&nbsp;<a href=\"https://discord.gg/pk3C8DB\">CODAME Discord</a>&nbsp;if you have questions!</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h3>ã€Ž CODAME PROVIDES ã€</h3>\r\n<ul>\r\n<li>Slides TBA</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h3>ã€Ž SCHEDULE ã€</h3>\r\n<ul>\r\n<li><span style=\"text-align: center;\">Tue, Dec 15th</span>, 2020</li>\r\n<li><span style=\"text-align: center;\">6:00 PM to 7:45 PM</span>&nbsp;PST&nbsp;<a href=\"https://time.is/11:30AM_19_December_2020_in_San_Francisco/New_York/Berlin/Hyderabad/Shanghai?CODAME\">Check your timezone</a></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h3>ã€Ž CODAME&nbsp;#CodeArtTogether Workshops ã€</h3>\r\n<p>&nbsp;</p>\r\n<table style=\"height: 101px;\" width=\"100%\">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p dir=\"ltr\" style=\"line-height: 1.2; text-align: center; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 36pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">ðŸ§ âœ¨</span>&nbsp;<span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"><br /></span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">Connect</span></p>\r\n</td>\r\n<td style=\"text-align: center;\"><span id=\"docs-internal-guid-81f37ba5-7fff-97be-c713-6edc787897a0\"><span style=\"font-size: 36pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">ðŸš§ðŸŽ¨</span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"><br /></span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">Create</span></span></td>\r\n<td>\r\n<p dir=\"ltr\" style=\"line-height: 1.2; margin-top: 0pt; margin-bottom: 0pt; text-align: center;\"><span style=\"font-size: 36pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">ðŸ¤©ðŸ’¬ </span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"><br /></span><span style=\"font-family: \'Source Serif Pro\', serif;\"><span style=\"font-size: 24px; white-space: pre-wrap;\">Celebrate</span></span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>Connecting, Creating, and Celebrating&nbsp;are pillars of the&nbsp;<a href=\"/projects/code-art-together\">CODAME #CodeArtTogether workshops</a>!&nbsp;</p>\r\n<p>Workshops are great for team building, remote or IRL. They cultivate space to play, which guides sense-making and sparks innovation. Attendees become featured artists with the option to show their workshop creations in CODAME galleries.&nbsp;<a href=\"/projects/code-art-together\">Learn more about this exciting offering</a><a href=\"https://www.tickettailor.com/checkout/view-event/id/486392/chk/4cfa/?modal_widget=true&amp;widget=true&amp;d\">!</a></p>\r\n<p>What topics grab your curiosity to learn or teach?&nbsp;Let us know through our&nbsp;<a href=\"/pages/call-for-workshops\">call for workshops</a>&nbsp;and&nbsp;<a href=\"/pages/join-us\">#JOYNT US</a>&nbsp;as a sponsor, volunteer, or workshop leader!</p>\r\n<h3>&nbsp;</h3>\r\n<p>&nbsp;</p>\r\n<table style=\"background-color: #351e58; width: 100%; margin-left: auto; margin-right: auto;\" cellpadding=\"10px\">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/463376#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; color: #00a4a7; background-color: #000000; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Festival 2020\" /></a></p>\r\n<p style=\"text-align: center;\"><em><strong>Or get the&nbsp;<a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\">ALL ACCESS pass</a>&nbsp;to CODAME ART+TECH Festival 2020 #JOYNT&nbsp;</strong></em><em>for 10 days of Workshops, Live Events, and Anytime Experiences!</em></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<center>ðŸ’Ÿ ðŸ‘¾ ðŸ’œ ðŸ‘¾ ðŸ’Ÿ</center>\r\n<p style=\"text-align: center;\">CODAME is a member of Intersection for the Arts&nbsp;<br />a non profit 501(c)(3)&nbsp;organization.</p>\r\n<p style=\"text-align: center;\">All proceeds will be split with the participating artists.</p>\r\n<p style=\"text-align: center;\"><a href=\"https://www.flipcause.com/secure/cause_pdetails/NjU0OA==\">Donations</a>&nbsp;are always welcome.</p>\r\n<p style=\"text-align: center;\">Thank you for your support for ART &hearts;ï¸ TECH !!!</p>\r\n<p style=\"text-align: center;\"><a href=\"/pages/code-of-conduct\">Code of Conduct</a>&nbsp;for all attendees.&nbsp;</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 'jonathan-lowe', '', '', '', '', '', '0', 'workshop', 'https://www.tickettailor.com/events/codame/463376#ticket_selection', 'art-tech-festival-2020-joynt'),
(177, 'How to Integrate Art, Science, Technology & AI into Public Spaces', 'how-to-integrate-art-science-technology-ai-into-public-spaces', '2020-12-11', 'http://codame.dreamhosters.com/uploaded_images/how-to-integrate-art-science-technology-ai-into-public-spaces.png', '<p style=\"text-align: center;\">Part of the 10th annual <a href=\"/events/art-tech-festival-2020-joynt\" target=\"_blank\">CODAME ART+TECH Festival</a> (included in the</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">&nbsp;<a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\" target=\"_blank\">Festival Pass and All Access Pass</a>&nbsp;)</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">Friday, Dec 11, 2020, 10:00 AM PST (1 hour) (check your&nbsp;<a style=\"box-sizing: border-box; color: #00a4a7 !important;\" href=\"https://time.is/1000AM_12_December_2020_in_San_Francisco/New_York/London/Berlin/Hyderabad?CODAME\">timezone</a>)<span id=\"docs-internal-guid-a7336780-7fff-43db-e918-f1975363585d\" style=\"box-sizing: border-box;\">&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p>Ouchhhh will present their artistic vision, innovative techniques and some of their latest creations with AI followed by a Q&amp;A session.&nbsp;</p>\r\n<p>From the very first moments of Ouchhh&rsquo;s journey as a studio, the relationship between the individual and the environment has been a main focus on how technology can inform and bridge our understanding of the physical and virtual worlds. The studio will touch on their journey and its experiential practices in different mediums by using art, science, technology and artificial intelligence.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; color: #00a4a7; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\">&nbsp;<img src=\"/uploaded_images/ouchhh-1.png\" alt=\"\" /></p>\r\n<p dir=\"ltr\"><img src=\"/uploaded_images/ouchhh-2.jpg\" alt=\"\" /></p>', 'ouchhh', '', '', '', '', '', '0', 'event', 'https://www.tickettailor.com/events/codame/442122/#ticket_selection', 'art-tech-festival-2020-joynt'),
(179, '2020ã€Ž JOYNT ã€Festival Grounds Opening', '2020-joynt-festival-grounds-opening', '2020-12-13', 'http://codame.dreamhosters.com/uploaded_images/festival-grounds-opening.png', '<p dir=\"ltr\" style=\"text-align: center;\">Part of the 10th annual&nbsp;<a href=\"/events/art-tech-festival-2020-joynt\" target=\"_blank\">CODAME ART+TECH Festival</a></p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">(included in the&nbsp;<a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\" target=\"_blank\">Festival Pass and All Access Pass</a>&nbsp;)</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">Sunday 12/13 (2020) 3:00 PM PST (<a href=\"https://time.is/300PM_13_December_2020_in_San_Francisco/New_York/London/Berlin/Hyderabad?CODAME\" target=\"_blank\">check your timezone</a>)</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">Visit us Online Gallery&nbsp;<a href=\"https://newart.city/show/codame-festival\">&nbsp;2020 [JOYNT] Virtual Gallery<br /></a></p>\r\n<h2>Experience the art of CODAME ART+TECH Festival 2020ã€Ž JOYNT ã€in a playful, game-like, multiplayer environment.</h2>\r\n<p>Built in New Art City, a virtual exhibition space with a focus on copresence and native web technology.</p>\r\n<p>Join the Zoom to where d0n.xyz and Yiyue Chen will share their inspirations and learnings from building New Art City and the Festival Grounds architecture. Lisa Kolb will share her initial vision to create a Festival Ground environment to house the Art+Tech experiences she curated for the Festival.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; color: #00a4a7; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>', 'd0n-xyz,lisa-kolb,yiyue-chen-iota', 'art-tech-festival-2020-joynt', '', 'newart-city', '', '', '0', 'event', 'https://www.tickettailor.com/events/codame/442122/#ticket_selection', 'https://codame.com/events/art-tech-festival-2020-joynt'),
(180, 'Async Art Cryptovoxels Tour', 'async-art-cryptovoxels-tour', '2020-12-16', 'http://codame.dreamhosters.com/uploaded_images/async-art-cryptovoxels-tour.png', '<p>Go on a tour of the Async Art Gallery in Cryptovoxels! We will also be livestreaming this event if you want to watch from Twitch.&nbsp;</p>\r\n<p>Sam Brukhman&nbsp;from Async Art will be your tour guide.&nbsp;</p>\r\n<p><strong>About&nbsp;Cryptovoxels&nbsp;</strong></p>\r\n<p>A virtual world powered by the Ethereum blockchain. Players can&nbsp;buy land&nbsp;and build stores and art galleries. Editing tools, avatars and text chat are built in. There are over 300 art galleries to explore in Cryptovoxels.</p>\r\n<p><strong>About&nbsp;Async Art&nbsp;</strong></p>\r\n<p>A&nbsp;new art movement built on the blockchain. Create, collect, and trade programmable art: digital paintings split into \"Layers\", which you can use to affect the overall image.</p>\r\n<p>Art that can evolve over time, react to its owners, or follow a stock price is now all possible with programmable art.</p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; color: #00a4a7; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p dir=\"ltr\">&nbsp;</p>', 'sam-brukhman', 'the-creation', '', 'async-art', '', '', '0', 'event', 'https://www.tickettailor.com/events/codame/442122/#ticket_selection', 'art-tech-festival-2020-joynt'),
(184, 'Clubhouse: ðŸ‘¾ VR Art exhibitions and future âœ¨', 'clubhouse-vr-art-exhibitions-and-future', '2021-02-19', 'http://codame.dreamhosters.com/uploaded_images/clubhouse-vr-art-exhibitions-and-future.png', '<div>\r\n<div style=\"text-align: center;\">FRI&nbsp;Feb 19,&nbsp;5 PM PST (<a href=\"https://time.is/0500PM_19_Feb_2021_in_San_Francisco/New_York/London/Berlin/Hyderabad/Sydney/Hong_Kong/South_Korea/Brazil/Mexico/Vietnam/Moscow?CODAME\">check your timezone</a>)</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\">\r\n<div style=\"text-align: left;\">Join us for a conversation on the state of VR art around the world. We&rsquo;ll be talking about the VR art market, creating VR art exhibitions, and the future of this exciting space.</div>\r\n<div style=\"text-align: left;\">&nbsp;</div>\r\n<div style=\"text-align: left;\">w/ Lynette Lee, Xinran Yuan, jenny Guo, Bruno Fonzi, Xin Liu and you!</div>\r\n</div>\r\n<div>\r\n<div>&nbsp;</div>\r\n<div>&nbsp;</div>\r\n</div>\r\n<div style=\"text-align: center;\">Register for this event on Clubhouse:&nbsp;</div>\r\n<div style=\"text-align: center;\"><a href=\"https://www.joinclubhouse.com/event/mWVVe1VD\" target=\"_blank\">https://www.joinclubhouse.com/event/mWVVe1VD</a></div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\">---</div>\r\n</div>\r\n<div style=\"text-align: center;\">Don&rsquo;t have a Clubhouse account?</div>\r\n<div style=\"text-align: center;\">Get the app to reserve your username and request access!</div>\r\n<div style=\"text-align: center;\">Download the Clubhouse app&nbsp;<a href=\"https://ios.joinclubhouse.com/event/mWVVe1VD\">here</a></div>\r\n<div style=\"text-align: left;\">&nbsp;</div>', 'lynette-lee,bruno-fonzi,xinran-yuan,jenny-guo,x,xin-liu', '', '', '', '', '', '0', 'event', 'https://www.joinclubhouse.com/event/mWVVe1VD', ''),
(182, 'JOYNT Fireside Chat', 'joynt-fireside-chat', '2020-12-20', 'http://codame.dreamhosters.com/uploaded_images/joynt-fireside-chat.jpg', '<p dir=\"ltr\" style=\"text-align: center;\">Part of the 10th annual&nbsp;<a href=\"/events/art-tech-festival-2020-joynt\" target=\"_blank\">CODAME ART+TECH Festival</a>&nbsp;(included in the</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">&nbsp;<a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\" target=\"_blank\">Festival Pass and All Access Pass</a>&nbsp;)</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">Sunday, Dec 20, 2020, 03:00 PM PST (1 hour) (check your&nbsp;<a href=\"https://time.is/0300PM_20_December_2020_in_San_Francisco/New_York/London/Berlin/Hyderabad?CODAME\">timezone</a>)<span id=\"docs-internal-guid-a7336780-7fff-43db-e918-f1975363585d\">&nbsp;</span></p>\r\n<p>We are closing the Festival and our 2020 CODAME program with our&nbsp;traditional Fireside chat&nbsp;with CODAME Founders&nbsp;Bruno Fonzi &amp; Jordan Gray, Art Curator&nbsp;Lisa Kolb, artists, and volunteers making&nbsp;this Festival&nbsp;happen!&nbsp;</p>\r\n<p>We will Connect, Create, and Celebrate by making space for dialog, creative positive feedback loops, and shape CODAME&rsquo;s future!</p>\r\n<p><br />&nbsp;<a href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 'bruno-fonzi,lisa-kolb,quinn-keck,jordan-gray', '', '', '', '', '', '0', 'event', 'https://www.tickettailor.com/events/codame/442122/#ticket_selection', 'art-tech-festival-2020-joynt'),
(188, 'Entwined Live Demo (Final Showing)', 'entwined-live-demo-final-showing', '2021-04-02', 'http://codame.dreamhosters.com/uploaded_images/entwined-live-demo-final-showing.jpeg', '<div style=\"text-align: center;\"><strong>Friday April 2nd&nbsp;&nbsp;</strong>from 7:30-9pm (PT)</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div>Back by popular demand, we\'re doing a 3rd and final showing of the patterns you all created for&nbsp;<em>Entwined</em>&nbsp;at our workshop!&nbsp;This is the perfect chance to drop by and enjoy the installation during its final month of exhibition.&nbsp; Come chat with like-minded tech artists and LED enthusiasts.</div>\r\n<div>&nbsp;</div>\r\n<div>We\'ll have a controller so you can play around with the patterns live (even if you hadn\'t created one in the workshop ðŸ˜‰). The Sculpture is also interactive if you scan certain LED cubes with QR codes on them ðŸ‘€. Patterns by class alumnae Lindsay, Jason, Mattaniah, Sydney, and Quinn have been quite a hit with&nbsp;<em>Entwined</em>&nbsp;crew, so we\'re excited to show them off for the whole city to see!&nbsp;</div>\r\n<div><br />Meet Colin and the CODAME Team&nbsp;at the&nbsp;San Francisco&nbsp;Golden&nbsp;Gate Park,&nbsp;Peacock Meadow, underneath the main tree. Dress warmly: The meadow can get surprisingly chilly at night!</div>', 'colin-hunt,charles-gadeken', '', '', '', '', '', '0', 'event', NULL, ''),
(209, 'Goose Gong', 'goose-gong', '2023-10-16', 'http://codame.dreamhosters.com/uploaded_images/goose-gong.jpg', '<p>Explore the graceful movements and healing energy of Dayan (Wild Goose) Qigong, a centuries-old practice that harmonizes body, mind, and spirit. Practice with us on Saturdays in San Francisco and every day online!</p>\r\n<p dir=\"ltr\">Our co-founder, Jordan Gray, exemplifies this ethos, whose Qigong journey since his certification in 2015 has deeply influenced CODAME\'s playful and personal approach. If in San Francisco, we encourage you to connect with Jordan and catch a glimpse of this spirit with Jordan\'s free <a href=\"https://goosegong.substack.com/about\">Qigong sessions at Sue Bierman Park</a>, every Saturday at 10:00 am.</p>', 'jordan-gray', '', '', '', '', '', '0', 'event', 'https://goosegong.substack.com/', ''),
(210, 'ART+TECH Festival Builders', 'art-tech-festival-builders', '2023-12-21', 'http://codame.dreamhosters.com/uploaded_images/art-tech-festival-builders.png', '<div style=\"text-align: center;\"><strong>Shape the </strong></div>\r\n<div style=\"text-align: center;\"><strong>ART+TECH Festival 2024 </strong></div>\r\n<div style=\"text-align: center;\"><strong>#ESSENCE<br />Join Us for a Night of Collaboration and Creativity</strong></div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\">December 21st&nbsp;(Thursday), 6-9pm</div>\r\n<div style=\"text-align: center;\">@ Homebrew (11th and Folsom, SF)</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\"><a href=\"https://app.tickettailor.com/events/codame/1072946?modal_widget=true\" target=\"_blank\">RSVP</a></div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div>Join us for a vibrant evening to build the upcoming ART+TECH Festival 2024 #ESSENCE together! This unique event in San Francisco is your chance to mingle with&nbsp;ART+TECH enthusiasts.&nbsp;</div>\r\n<div>&nbsp;</div>\r\n<div>Artists, Volunteers, and Supporters, your ideas and feedback on the night will contribute directly to shaping the upcoming ART+TECH Festival&nbsp;2024 #ESSENCE. Share your excitement&nbsp;about emerging digital art formats &ndash; VR, AR, interactive installations, or something completely new. Let\'s bring CODAME and your vision to life.&nbsp;Use&nbsp;your skills and ideas to fit in executing&nbsp;the ART+TECH Festival&nbsp;with international impact.</div>\r\n<div>&nbsp;</div>\r\n<div style=\"text-align: center;\">Artists<br /><a href=\"/pages/call-for-proposals\">Submit Proposals</a></div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\">Volunteers<br /><a href=\"/pages/call-for-volunteers\">Join Us</a></div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\">Sponsors<br /><a href=\"/pages/support-art-tech\">Support ART+TECH</a></div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\">\r\n<div>Learn more about the Future of CODAME and Celebrating Humanity and ART+TECH around the world&nbsp;in this&nbsp;<a href=\"https://codame.substack.com/p/the-future-of-codame\">post</a></div>\r\n<div>&nbsp;</div>\r\n<div><a href=\"https://codame.substack.com/p/the-future-of-codame\"><img src=\"https://substackcdn.com/image/fetch/f_auto,q_auto:best,fl_progressive:steep/https%3A%2F%2Fcodame.substack.com%2Fapi%2Fv1%2Fpress_kit%2F137978756.jpg%3FaspectRatio%3Dsquare%26bgImage%3Dtrue%26hidePreviewText%3Dtrue%26isDraft%3Dfalse%26hash%3D-1222706315%26version%3D13\" alt=\"\" /></a></div>\r\n<div>&nbsp;<a href=\"https://codame.substack.com/p/the-future-of-codame%C2%A0\">https://codame.substack.com/p/the-future-of-codame</a></div>\r\n<div style=\"text-align: left;\">&nbsp;</div>\r\n<div style=\"text-align: left;\">Save the date on your calendar for Thursday, December 21th, 2023, from 6 to 9 pm, and RSVP now to secure your spot. This is your chance to influence the ART+TECH Festival 2024 #ESSENCE, to be a creator and a builder of an extraordinary experience!</div>\r\n<div style=\"text-align: left;\">\r\n<div>\r\n<p dir=\"ltr\">Homebrew encourages folks to BYO as a DIY space with some extra to share. CODAME will provide a relaxed atmosphere with light drinks and snacks.</p>\r\n<p dir=\"ltr\">Take into consideration that space is limited.&nbsp;<a href=\"https://app.tickettailor.com/events/codame/1072946?modal_widget=true\">RSVP now</a>&nbsp;if you don\'t want to miss this intimate gathering. We\'ll do our best to accommodate as many people as possible because we truly value your presence in our community.&nbsp;We can\'t wait to see you there and to celebrate the unique creativity and innovation that CODAME is known for.&nbsp;</p>\r\n</div>\r\n<div style=\"text-align: center;\"><a href=\"https://app.tickettailor.com/events/codame/1072946?modal_widget=true\">RSVP</a></div>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><strong>Learn about the&nbsp;Essence of the Next ART+TECH Festival <a href=\"https://codame.substack.com/p/the-essence-of-the-next-arttech-festival\">here</a></strong></div>\r\n</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\"><img src=\"https://substackcdn.com/image/fetch/f_auto,q_auto:best,fl_progressive:steep/https%3A%2F%2Fcodame.substack.com%2Fapi%2Fv1%2Fpress_kit%2F138874319.jpg%3FaspectRatio%3Dsquare%26bgImage%3Dtrue%26hidePreviewText%3Dtrue%26isDraft%3Dfalse%26hash%3D480270545%26version%3D13\" alt=\"\" /></div>\r\n<div style=\"text-align: center;\"><a href=\"https://codame.substack.com/p/the-essence-of-the-next-arttech-festival\">https://codame.substack.com/p/the-essence-of-the-next-arttech-festival</a></div>\r\n<div style=\"text-align: center;\">&nbsp;&nbsp;</div>\r\n<div><iframe title=\"W3Schools Free Online Web Tutorials\" src=\"https://www.tickettailor.com/checkout/view-event/id/3292520/chk/a73f\" width=\"300\" height=\"550\"></iframe>\r\n<p>///</p>\r\n<p>CODAME is a member of Gray Area, a nonprofit 501(c)(3) organization. All proceeds will be split with the participating artists. Thank you for the support for ART+TECH !!!&nbsp;</p>\r\n<p><a href=\"http://codame.com/pages/code-of-conduct\">Code of Conduct</a> for all attendees.&nbsp;</p>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<p style=\"text-align: center;\"><iframe style=\"border-style: solid; border-color: #eeeeee; background-image: initial; background-position: initial; background-repeat: initial; background-color: white;\" src=\"https://codame.substack.com/embed\" width=\"480\" height=\"320\" frameborder=\"0\" scrolling=\"no\"></iframe>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div>&nbsp;</div>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>', 'bruno-fonzi,jordan-gray', '', '', 'canvia-art', '', '', '0', 'event', 'https://app.tickettailor.com/events/codame/1072946?modal_widget=true', ''),
(190, 'Creators and Communities Hackathon', 'creators-and-communities-hackathon', '2021-05-14', 'http://codame.dreamhosters.com/uploaded_images/creators-and-communities-hackathon.jpeg', '<h2 style=\"text-align: center;\">Friday May 14th - Sunday June 6th</h2>\r\n<p>Get rewards for sharing ideas, pitching a deck, and recording a video demo<strong>&nbsp;</strong>(no code required). Over&nbsp;<strong>$100,000&nbsp;of bounties and prizes</strong> available for tracks like&nbsp;generative art, social tokens, governance, music, and VR!&nbsp;&nbsp;</p>\r\n<p><a style=\"text-decoration-line: none;\" href=\"/events/creators-and-communities-hackathon\">CODAME artists</a>&nbsp;have been comissioned for&nbsp;<strong>NFT Crypto Art drops</strong>, happening at key events throughout the conference. Log into the&nbsp;<a style=\"text-decoration-line: none;\" href=\"https://discord.gg/KGgwXNCekf\">NEAR discord</a>&nbsp;and keep your eyes peeled for collab.land bot notifications ðŸŽ¨ðŸ‘€ðŸ’œ</p>\r\n<p><strong>All backgrounds and skill sets are welcome to participate.</strong>&nbsp;No prior knowledge of blockchain is required! This is your shot to learn NFTs, DAOs, and social tokens on NEAR, a carbon neutral blockchain with the best usability and developer experience.</p>\r\n<p><a style=\"text-decoration-line: none;\" href=\"/events/creators-and-communities-hackathon\">#CreatorsAndCommunities Hackathon</a>&nbsp;kicks off with an all day conference featuring over 50 industry leaders, including a&nbsp;<strong>Rewarding Creativity to Supercharge Communities</strong>&nbsp;panel with CODAME Co-Founder Jordan Gray. Hacking continues through June 6th.&nbsp;</p>\r\n<h1 style=\"text-align: center;\"><a href=\"https://airtable.com/shrsL97Cl2U6VGTtE\" target=\"_blank\">Register Now</a></h1>\r\n<p style=\"text-align: center;\">Learn more:<br /><a href=\"http://summit.openweb.community/\" target=\"_blank\">Confrence</a>&nbsp;|&nbsp;<a href=\"https://createbase.community/hackathon/\" target=\"_blank\">Hackathon</a>&nbsp;</p>', 'jordan-gray,yiyue-chen,crystal-glass,max-zsol,rachelle-viola,avesta-hamidi,emanuele-pavarotti,whatshertoes', '', '', 'near-foundation', '', '', '0', 'event', '', '');
INSERT INTO `events` (`id`, `name`, `slug`, `date`, `pic`, `description`, `artists_array`, `projects_array`, `sponsors_array`, `partners_array`, `old_url`, `rsvp_url`, `hidden`, `event_type`, `shop_url`, `events_array`) VALUES
(191, 'ART+TECH Festival 2021 /// FRAMEWORLD', 'art-tech-festival-2021-frameworld', '2021-06-24', 'http://codame.dreamhosters.com/uploaded_images/frameworld.png', '<h2 style=\"text-align: center;\"><em>FRAMEWORLD</em></h2>\r\n<p style=\"text-align: center;\">Immerse yourself into FRAMEWORLD, join&nbsp;our online virtual&nbsp;<a href=\"http://gallery.codame.com/\" target=\"_blank\">gallery.codame.com</a>&nbsp;</p>\r\n<p style=\"text-align: center;\">hosted&nbsp;by New Art City</p>\r\n<p style=\"text-align: center;\">Art also available for sale on&nbsp;<a href=\"https://shop.codame.com/\">CODAME Shop</a>&nbsp;and collectible as&nbsp;<a href=\"https://nft.codame.com/\">NFTs</a>&nbsp;</p>\r\n<p style=\"text-align: center;\">&eth;&Yuml;&rsquo;&Yuml; &eth;&Yuml;&lsquo;&frac34; &eth;&Yuml;&rsquo;&oelig; &eth;&Yuml;&lsquo;&frac34; &eth;&Yuml;&rsquo;&Yuml;</p>\r\n<p dir=\"ltr\">FRAMEWORLD is web-specific group exhibition, curated by Ya&Auml;&Yuml;mur Uyan&Auml;&plusmn;k, that establishes a focus on the discourses around creating a multiplicity of locality, understanding of the new international and transcultural solidarity in the times of extreme precarity. The works in the show together critically engage with the present, embrace the notions of urgency, and propose alternative approaches to current disruptions, reflecting on what interconnectedness and new modes of collectivity look like now.&nbsp;</p>\r\n<p dir=\"ltr\">All exhibited works will have the opportunity to be for sale.&nbsp;Be the first to have access to the art by joining the&nbsp;FRAMEWORLD&nbsp;opening&nbsp;and meet&nbsp;the artists, curator, CODAME team, partners and other collectors and ART+TECH supporters</p>\r\n<p dir=\"ltr\"><span style=\"text-align: center;\">Immerse yourself into FRAMEWORLD, join&nbsp;our online virtual gallery show at&nbsp;<a href=\"https://newart.city/show/frameworld\">gallery.codame.com</a></span><span style=\"text-align: center;\">&nbsp;hosted&nbsp;by New Art City.</span></p>\r\n<p dir=\"ltr\" style=\"text-align: center;\"><a title=\"New Art City Codame Gallery\" href=\"/admin/gallery.codame.com\" target=\"_blank\"><img src=\"/uploaded_images/EnterFrameworld(m).gif\" alt=\"\" /></a><a href=\"/admin/gallery.codame.com\" target=\"_blank\">gallery.codame.com</a>&nbsp;</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">@ New Art City&nbsp;</p>\r\n<h2 style=\"text-align: left;\"><strong>[When]</strong></h2>\r\n<p style=\"text-align: left;\">Opening June 24th, 2021 @ 12pm (noon) (PST)&nbsp; - Opening day with meet the Artists&nbsp;event.</p>\r\n<p style=\"text-align: left;\">Closing Sept. 23th, 2021 - Closing&nbsp;FRAMEWORLD, auctions, and announcing new gallery event.</p>\r\n<h2 dir=\"ltr\" style=\"text-align: left;\"><strong>[</strong><strong>Where</strong><strong>]</strong></h2>\r\n<p dir=\"ltr\" style=\"text-align: left;\"><span style=\"text-align: center;\">Virtually online on&nbsp;</span><a style=\"text-align: center;\" href=\"/admin/gallery.codame.com\" target=\"_blank\">gallery.codame.com</a><span style=\"text-align: center;\">&nbsp;hosted&nbsp;by New Art City.</span></p>\r\n<h2 dir=\"ltr\" style=\"text-align: left;\"><strong>[</strong><strong>Who</strong><strong>]</strong></h2>\r\n<p dir=\"ltr\" style=\"text-align: left;\">Mirabelle Jones,&nbsp;Delta_Ark, Paula Levine, Pablo Salafurka, Snow Yunxue Fu, Andy Wauman, Jordan Gray, Jody Stillwater, Tarwin Stroh-Spijer, DC Spensley, Anabela Costa, Huili Chen, Quinn Keck and Tiare Ribeaux.</p>\r\n<h2 style=\"text-align: left;\"><strong>[</strong><strong>What</strong><strong>]</strong></h2>\r\n<p style=\"text-align: left;\">Also available for sale on&nbsp;the&nbsp;<a href=\"https://shop.codame.com/\">CODAME Shop</a>&nbsp;and as part of the&nbsp;<a href=\"https://nft.codame.com/\">CODAME&nbsp;NFT</a>&nbsp;Collection.</p>\r\n<h2 style=\"text-align: center;\">.&nbsp; .&nbsp; .</h2>\r\n<p dir=\"ltr\">In the light of the current global crises, this new initiation consolidates our commitment to creating space for our community to explore and reflect through creative, technological and critical means with a faster cadence.</p>\r\n<p dir=\"ltr\">This new initiative continues our commitment to creating spaces where our community can explore and reflect through creative, technological and critical means more effectively.</p>\r\n<p dir=\"ltr\">The first exhibition of the series is web-specific and establishes a focus on the discourses around creating a multiplicity of locality, understanding of the new international and transcultural solidarity in the times of extreme precarity. Let\'s explore the idea of hybrid embodiments while engaging with the continuity between digital and physical. &eth;&Yuml;&lsquo;&frac12;&acirc;&oelig;&uml;</p>\r\n<ul>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">How can we make use of the current concept of temporality to revisit the dominant narratives of progress, linear organizations of time, and ways of framing the world?&nbsp;</p>\r\n</li>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">How do we revisit the ideas of borders and boundaries and work together to find ways of renegotiating how one moves through the world?&nbsp;</p>\r\n</li>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">How do we reflect on closeness and proximity while investigating the intangible connections between the virtual and geographical nature of space?&nbsp;</p>\r\n</li>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">How can we explore common horizons and new forms of collectivity and solidarity to build frameworks for a world that has yet to exist?&nbsp;</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">Our open call invites works that critically engage with the present, embrace the notions of urgency, and propose alternative approaches to current disruptions, reflecting on what interconnectedness and new modes of collectivity look like now. We invite artists from all backgrounds, especially the ones who are new to the digital space, to submit works that leverage the potential of website specificity.</p>\r\n<p dir=\"ltr\"><strong>All exhibited works will be for sale.&nbsp;</strong></p>\r\n<p dir=\"ltr\">Be the first to have access to the art by joining the&nbsp;FRAMEWORLD&nbsp;opening&nbsp;to meet the artists, curator, CODAME team, partners and other&nbsp;collectors and ART+TECH supporters.&nbsp;<a href=\"https://www.tickettailor.com/events/codame/529180\">RSVP</a></p>\r\n<p><iframe style=\"display: block; margin-left: auto; margin-right: auto;\" title=\"YouTube video player\" src=\"https://www.youtube.com/embed/QdyDX0assr4\" width=\"797\" height=\"449\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">&nbsp;&eth;&Yuml;&rsquo;&Yuml; &eth;&Yuml;&lsquo;&frac34; &eth;&Yuml;&rsquo;&oelig; &eth;&Yuml;&lsquo;&frac34; &eth;&Yuml;&rsquo;&Yuml;</p>\r\n<p style=\"text-align: left;\">CODAME is a member of Intersection for the Arts a non profit 501(c)(3) organization. All proceeds will be split with the participating artists. Thank you for your support for ART&nbsp;&eth;&Yuml;&rsquo;&oelig;&nbsp;TECH !!!&nbsp;<a href=\"http://codame.com/pages/code-of-conduct\">Code of Conduct</a>&nbsp;for all attendees.</p>', 'mirabelle-jones,delta-ark,paula-levine,pablo-salafurka,snow-yunxue-fu,tiare-ribeaux,andy-wauman,jordan-gray,jody-stillwater,tarwin-stroh-spijer,dc-spensley,huili-chen,anabela-costa,yagmur-uyanik,quinn-keck', 'doomslug,embodying-the-algorithm,poetic-cosmicity,chandelier,certitude-162b2,thewall-theworld-2020,gevurah,avalanche,vibration-obfuscation-detritus-inheritance,dear-nostalgiabot,ia-manawa-n-at-this-time,howl-silhouette-of-sound,machine-of-perceptions', '', 'newart-city,mintbase,local-maker-mart', '', '', '0', 'event', 'https://app.tickettailor.com/events/codame/529180/#ticket_selection', ''),
(195, 'FRAMEWORLD at Local Maker Mart', 'frameworld-at-local-maker-mart', '2021-10-15', 'http://codame.dreamhosters.com/uploaded_images/frameworld-at-local-maker-mart.gif', '<h2 style=\"text-align: center;\">October 15th,</h2>\r\n<h2 style=\"text-align: center;\">5pm - 10pm (PST)</h2>\r\n<h2 style=\"text-align: center;\">580 Green St, SF&nbsp;</h2>\r\n<p style=\"text-align: center;\"><br /><span style=\"color: #00a4a7; font-family: Asap, helvetica, arial, sans-serif;\"><a style=\"box-sizing: border-box; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; text-align: start; background-color: #000000; color: #00a4a7 !important;\" href=\"https://www.tickettailor.com/events/codame/563159#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<h3 style=\"text-align: center;\">Every attendee will get a CODAME NFT art!</h3>\r\n<p style=\"text-align: center;\">This is a free event</p>\r\n<p style=\"text-align: center;\">We&nbsp;are&nbsp;kindly asking&nbsp;for&nbsp;donations&nbsp;to&nbsp;support the CODAME mission.</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<h3 style=\"text-align: left;\">Jordan Gray will present Decentralized Autonomous Organizations for Beginners. Learn how CODAME DAO and The Kin DAO are paving the way into a revolution that\'s putting power back in the hands of creators.</h3>\r\n<h3 style=\"text-align: left;\"><br />Then we\'ll visit an interactive FRAMEWORLD NewArt.City 3d Gallery and enjoy an immersive NFT installation by The Kin DAO. Join us for music by DJ Rendezhous while you relax at the Outdoor Cabanas. DJ Rendezhous will play from 7-9 pm!</h3>\r\n<h3 style=\"text-align: center;\">&nbsp;<img src=\"/uploaded_images/38.png\" alt=\"\" /></h3>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><a style=\"box-sizing: border-box; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; text-align: start; background-color: #000000; color: #00a4a7 !important;\" href=\"https://www.tickettailor.com/events/codame/563159#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\">FRAMEWORLD is a web-specific group exhibition, curated by YaÄŸmur UyanÄ±k, that establishes a focus on the discourses around creating a <strong>multiplicity of locality</strong>, understanding of the new international and <strong>transcultural solidarity</strong> in the times of extreme precarity. The works in the show together critically engage with the present, embrace the notions of urgency, and propose alternative approaches to current disruptions, reflecting on interconnectedness and <strong>new modes of collectivity</strong>.</p>\r\n<p dir=\"ltr\">All FRAMEWORLD works&nbsp;are also&nbsp;available for sale on&nbsp;the&nbsp;<a href=\"https://shop.codame.com/\">CODAME Shop</a>&nbsp;and as part of the&nbsp;<a href=\"https://nft.codame.com/\">CODAME&nbsp;NFT</a>&nbsp;Collection.</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">&nbsp;<span style=\"text-align: center;\">&nbsp;ðŸ’Ÿ ðŸ‘¾ ðŸ’œ ðŸ‘¾ ðŸ’Ÿ</span></p>\r\n<p>CODAME is a member of Intersection for the Arts a nonprofit 501(c)(3) organization. All proceeds will be split with the participating artists. Thank you for your support for ART&nbsp;ðŸ’œ&nbsp;TECH !!!&nbsp;<a href=\"http://codame.com/pages/code-of-conduct\">Code of Conduct</a>&nbsp;for all attendees.</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\"><a title=\"New Art City Codame Gallery\" href=\"/admin/gallery.codame.com\" target=\"_blank\"><img src=\"/uploaded_images/EnterFrameworld(m).gif\" alt=\"\" /></a><a href=\"/admin/gallery.codame.com\" target=\"_blank\">gallery.codame.com</a>&nbsp;<br />@ New Art City&nbsp;</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">Immerse yourself into FRAMEWORLD, join&nbsp;our online virtual gallery show at&nbsp;<a href=\"https://newart.city/show/frameworld\">gallery.codame.com</a>&nbsp;hosted&nbsp;by New Art City.</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">&nbsp;</p>\r\n<h2 style=\"text-align: left;\"><strong>[When]</strong></h2>\r\n<p>October 15th&nbsp;from 5pm&nbsp;to 10pm (PST)</p>\r\n<h2 dir=\"ltr\" style=\"text-align: left;\"><strong>[</strong><strong>Where</strong><strong>]</strong></h2>\r\n<p dir=\"ltr\" style=\"text-align: left;\"><span style=\"text-align: center;\">Physical interactive show at Local Maker Mart,&nbsp;</span>580 Green St, SF</p>\r\n<p dir=\"ltr\"><span style=\"text-align: center;\">+ Virtually online on&nbsp;</span><a style=\"text-align: center;\" href=\"/admin/gallery.codame.com\" target=\"_blank\">gallery.codame.com</a><span style=\"text-align: center;\">&nbsp;hosted&nbsp;by New Art City.&nbsp;</span>&nbsp;</p>\r\n<h2 dir=\"ltr\" style=\"text-align: left;\"><strong>[</strong><strong>Who</strong><strong>]</strong></h2>\r\n<p dir=\"ltr\" style=\"text-align: left;\">The Kin DAO, Mirabelle Jones,&nbsp;Delta_Ark, Paula Levine, Pablo Salafurka, Snow Yunxue Fu, Andy Wauman, Jordan Gray, Jody Stillwater, Tarwin Stroh-Spijer, DC Spensley, Anabela Costa, Huili Chen, Quinn Keck, and Tiare Ribeaux.</p>\r\n<h2 style=\"text-align: left;\"><strong>[</strong><strong>What</strong><strong>]</strong></h2>\r\n<p>FRAMEWORLD reception presented in collaboration with The Kin DAO and Local Maker Mart.&nbsp;</p>\r\n<p style=\"text-align: center;\">.&nbsp; .&nbsp; .</p>\r\n<p dir=\"ltr\"><strong>FRAMEWORLD</strong></p>\r\n<p dir=\"ltr\">In the light of the current global crises, this new initiation consolidates our commitment to creating space for our community to explore and reflect through creative, technological, and critical means with a faster cadence.</p>\r\n<p dir=\"ltr\">This new initiative continues our commitment to creating spaces where our community can explore and reflect through creative, technological, and critical means more effectively.</p>\r\n<p dir=\"ltr\">The first exhibition of the series is web-specific and establishes a focus on the discourses around creating a multiplicity of locality, understanding of the new international and transcultural solidarity in the times of extreme precarity. Let\'s explore the idea of hybrid embodiments while engaging with the continuity between digital and physical. ðŸ‘½âœ¨</p>\r\n<ul>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">How can we make use of the current concept of temporality to revisit the dominant narratives of progress, linear organizations of the time, and ways of framing the world?&nbsp;</p>\r\n</li>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">How do we revisit the ideas of borders and boundaries and work together to find ways of renegotiating how one moves through the world?&nbsp;</p>\r\n</li>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">How do we reflect on closeness and proximity while investigating the intangible connections between the virtual and geographical nature of space?&nbsp;</p>\r\n</li>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">How can we explore common horizons and new forms of collectivity and solidarity to build frameworks for a world that has yet to exist?&nbsp;</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\">Our open call invites works that critically engage with the present, embrace the notions of urgency, and propose alternative approaches to current disruptions, reflecting on what interconnectedness and new modes of collectivity look like now. We invite artists from all backgrounds, especially the ones who are new to the digital space, to submit works that leverage the potential of website specificity.</p>\r\n<p dir=\"ltr\"><strong>All FRAMEWORLD works&nbsp;are&nbsp;for sale.&nbsp;</strong></p>\r\n<p dir=\"ltr\">All FRAMEWORLD works&nbsp;are also&nbsp;available for sale on&nbsp;the&nbsp;<a href=\"https://shop.codame.com/\">CODAME Shop</a>&nbsp;and as part of the&nbsp;<a href=\"https://nft.codame.com/\">CODAME&nbsp;NFT</a>&nbsp;Collection.</p>\r\n<p><iframe style=\"display: block; margin-left: auto; margin-right: auto;\" title=\"YouTube video player\" src=\"https://www.youtube.com/embed/QdyDX0assr4\" width=\"797\" height=\"449\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">&nbsp;ðŸ’Ÿ ðŸ‘¾ ðŸ’œ ðŸ‘¾ ðŸ’Ÿ</p>\r\n<p style=\"text-align: left;\">CODAME is a member of Intersection for the Arts a nonprofit 501(c)(3) organization. All proceeds will be split with the participating artists. Thank you for your support for ART&nbsp;ðŸ’œ&nbsp;TECH !!!&nbsp;<a href=\"http://codame.com/pages/code-of-conduct\">Code of Conduct</a>&nbsp;for all attendees.</p>', 'delta-ark,jordan-gray,snow-yunxue-fu,mirabelle-jones,paula-levine,pablo-salafurka,andy-wauman,jody-stillwater,tarwin-stroh-spijer,dc-spensley,anabela-costa,huili-chen,tiare-ribeaux,quinn-keck,rendezhous', '', '', 'local-maker-mart,palacio,the-kin-dao', '', '', '0', 'event', 'https://app.tickettailor.com/events/codame/563159/#ticket_selection', ''),
(193, 'DOOMSLUG Auction', 'doomslug-auction', '2021-07-16', 'http://codame.dreamhosters.com/uploaded_images/doomslug-auction.jpg', '<h2><strong>WHEN?</strong></h2>\r\n<p>Friday July 16th, 1pm PT - 2pm PT.</p>\r\n<p>&nbsp;</p>\r\n<h2><strong>WHERE?</strong></h2>\r\n<p>It\'s on Telegram in the&nbsp;<a href=\"https://t.me/theAGAH\" target=\"_blank\">Art Gallery Auction House</a>, A live Auction house for the amazing artists and art community of the Crypto world!</p>\r\n<p>&nbsp;</p>\r\n<h2><strong>HOW TO BID?</strong></h2>\r\n<p>Get your NEAR ready, now available for exchange in USA at <a href=\"https://www.okcoin.com/join?channelId=600076687\" target=\"_blank\">OKCOIN</a>. Bidding is in real time via text/chat.</p>\r\n<p>&nbsp;</p>\r\n<h2><strong>AGAH DETAILS?</strong></h2>\r\n<p>ð‚ð®ð«ð«ðžð§ð­ ð€ð®ðœð­ð¢ð¨ð§:&nbsp;@staRpauSe</p>\r\n<p>ð€ð«ð­ð°ð¨ð«ð¤ ð“ð¢ð­ð¥ðž:&nbsp;DOOMSLUG</p>\r\n<p>ð’ð­ðšð«ð­ð¢ð§ð  ðð¢ð:&nbsp;20 $NEAR&nbsp;</p>\r\n<p>ð‘ðžð¬ðžð«ð¯ðž ðð¢ð: 30 $NEAR</p>\r\n<p>ð’ð®ð©ð©ð¥ð²/ð„ðð¢ð­ð¢ð¨ð§ð¬: 1/1</p>\r\n<p>ðð«ðžð¯ð¢ðžð° ð‹ð¢ð§ð¤:&nbsp;<a href=\"https://www.mintbase.io/thing/8Y2mQRT7B4t0m_qgaqvdry7XHbTEhIbDjnSdWKTFxw0:codame.mintbase1.near\" target=\"_blank\">codame.mintbase1.near</a></p>\r\n<p>ðƒðžð¬ðœð«ð¢ð©ð­ð¢ð¨ð§:</p>\r\n<p>NEAR relies on its own variant of BFT consensus, known as DOOMSLUG. It facilitates sub-second block production and recovers the network from malicious or unresponsive validators. ðŸ’ªðŸ˜ŽðŸ’¨</p>\r\n<p>DOOMSLUG is also a mascot that accompanies Spensa Nightshade in Skyward. She\'s known to replicate nearly any sound she hears. ðŸŒðŸŽ¶</p>\r\n<p>DOOMSLUG was first drawn on a 4x4 plot of pixelparty.pixeldapps.co. This design was captured by the original artist and is being immortalized as the CODAME genesis NFT on Mintbase; as an ode to the beauty of technology! ðŸŽ¨ðŸ‘©&zwj;ðŸ’»ðŸ‘¾</p>\r\n<p>&nbsp;</p>\r\n<p>ð–ð”ð“ð“ð€ $ðð„ð€ð‘:</p>\r\n<p>NEAR is an L1 gen3 blockchain with a trustless, permissionless bridge to ETH. Clean UX and pragmatic scaling has NEAR positioned to welcome the next billion users to web3! Hold ETH? Get a free ðš¢ðš˜ðšžðš›ðš—ðšŠðš–ðšŽ.ðš—ðšŽðšŠðš› wallet at <a href=\"http://faucet.paras.id/\" target=\"_blank\">faucet.paras.id</a>.&nbsp;Exchange $NEAR in US at <a href=\"https://www.okcoin.com/join?channelId=600076687\" target=\"_blank\">okcoin.com</a>&nbsp;(@staRpauSe ref link).</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>', 'jordan-gray', 'doomslug', '', 'mintbase,art-gallery-auction-house', '', '', '0', 'event', '', ''),
(194, 'FRAMEWORLD Panel ', 'frameworld-panel', '2021-07-28', 'http://codame.dreamhosters.com/uploaded_images/frameworld-panel.png', '<h2 style=\"text-align: center;\">9am on July 28th</h2>\r\n<h2 style=\"text-align: center;\">on Twitter Spaces&nbsp;</h2>\r\n<p style=\"text-align: center;\"><a href=\"https://twitter.com/starpause/status/1418576171197820932?s=20\" target=\"_blank\">RSVP / Reminder</a></p>\r\n<p>Join the FRAMEWORLD artists and crew in a Twitter Spaces conversation! There will be time for Q&amp;A as well.</p>\r\n<p>Visit the <a href=\"/nft\">CODAME NFT Art Collection</a>&nbsp;where you can buy original artwork from FRAMEWORLD.</p>\r\n<p><em>FRAMEWORLD establishes a focus on the discourses around creating a multiplicity of locality, understanding of the new international and transcultural solidarity in the times of extreme precarity. It centers around the idea of hybrid embodiments while engaging with the continuity between digital and physical.</em></p>\r\n<p><em>Works in the exhibition leverage the potential of website specificity while critically engaging with the present, embracing the notions of urgency, and proposing alternative approaches to current disruptions and reflecting on what interconnectedness and new modes of collectivity look like now.</em></p>', 'quinn-keck,jordan-gray,delta-ark,cindy-clark,snow-yunxue-fu', '', '', 'mintbase', '', '', '0', 'event', 'https://twitter.com/starpause/status/1418576171197820932?s=20', ''),
(196, 'FRAMEWORLD on Minecraft', 'frameworld-on-minecraft', '2021-09-05', 'http://codame.dreamhosters.com/uploaded_images/frameworld-on-minecraft.png', '<p style=\"text-align: center;\"><strong>Explore FRAMEWORLD on Minecraft</strong></p>\r\n<p style=\"text-align: center;\"><strong>Collect Art in a Live Online Auction</strong></p>\r\n<p style=\"text-align: center;\"><strong>+&nbsp;</strong></p>\r\n<p style=\"text-align: center;\"><strong>Build your own Art Gallery</strong></p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">Sun Sep&nbsp;5,&nbsp;2021&nbsp;11:00 AM&nbsp;-&nbsp;12:00 PM&nbsp;PD</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">with&nbsp;Hufo, CODAME Team, and&nbsp;FRAMEWORLD Featured Artists on Minecraft!</p>\r\n<p style=\"text-align: center;\"><br /><span style=\"color: #00a4a7; font-family: Asap, helvetica, arial, sans-serif;\"><a style=\"box-sizing: border-box; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; text-align: start; background-color: #000000; color: #00a4a7 !important;\" href=\"https://www.tickettailor.com/events/codame/461601#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></span></p>\r\n<h2>[What]</h2>\r\n<p>Come for a guided tour of FRAMEWORLD on the CODAME Minecraft server. Stay for an NFT auction or build your own art gallery!&nbsp;<strong>&nbsp;</strong></p>\r\n<h3 style=\"padding-left: 30px;\">1. Tour</h3>\r\n<p style=\"padding-left: 60px;\">Explore and learn more about the FRAMEWORLD Aret work over Minecraft with an online guided tour with the Artists, the CODAME crew, and Hufo, the Minecraft Gallery creator.</p>\r\n<h3 style=\"padding-left: 30px;\">2. Build</h3>\r\n<p style=\"padding-left: 60px;\"><span data-offset-key=\"7psm8-0-0\">Build your own</span>&nbsp;<span spellcheck=\"false\">virtual</span>&nbsp;<span spellcheck=\"false\">art gallery</span><span data-offset-key=\"7psm8-5-0\">&nbsp;in</span>&nbsp;<span spellcheck=\"false\">Minecraft</span><span data-offset-key=\"7psm8-8-0\">. No need to be a coder or a Minecraft expert,&nbsp;we will help you need to grasp some Minecraft foundations and basic commands to build your own virtual art gallery.&nbsp;</span><a href=\"https://www.tickettailor.com/events/codame/461601#ticket_selection\" target=\"_blank\">RSVP</a> to get access and instructions&nbsp;<a href=\"https://www.tickettailor.com/events/codame/461601\" target=\"_blank\">here</a></p>\r\n<h3 style=\"padding-left: 30px;\">3. Collect</h3>\r\n<p style=\"padding-left: 60px;\">Art auctions are done in real-time via chat on&nbsp;<a href=\"https://t.me/theAGAH\" target=\"_blank\">Telegram</a>&nbsp;with a human auctioneer tracking bids from collectors. It\'s a digital-native auction format with lots of excitement and gif battles ðŸ˜&nbsp;</p>\r\n<h2 dir=\"ltr\">[Where]</h2>\r\n<p>Virtually online on Zoom and Minecraft, get instructions and video conference link by registering&nbsp;<a href=\"https://www.tickettailor.com/events/codame/461601#ticket_selection\" target=\"_blank\">here<br /></a></p>\r\n<h2>[When]</h2>\r\n<p>Opening&nbsp;Sept.&nbsp;5th, 2021 @ 12pm (noon) (PST)</p>\r\n<h2 dir=\"ltr\">[Who]</h2>\r\n<p dir=\"ltr\"><span style=\"text-align: center;\">CODAME ART+TECH Curator YaÄŸmur UyanÄ±k&nbsp;</span><span style=\"text-align: center;\">and&nbsp;</span><span style=\"text-align: center;\">Featured Artists:</span></p>\r\n<p dir=\"ltr\">Mirabelle Jones,&nbsp;Delta_Ark, Paula Levine, Pablo Salafurka, Snow Yunxue Fu, Andy Wauman, Jordan Gray, Jody Stillwater, Tarwin Stroh-Spijer, DC Spensley, Anabela Costa, Huili Chen, Quinn Keck, and Tiare Ribeaux.</p>\r\n<h2>*Auction FAQ</h2>\r\n<p><strong>Where will the auction be?</strong></p>\r\n<p>The Art Gallery Auction House on <a href=\"https://t.me/theAGAH\" target=\"_blank\">Telegram</a>.&nbsp;</p>\r\n<p><strong>What crypto currency do I need to bid?</strong></p>\r\n<p>Bids will be in <a href=\"https://near.org/\" target=\"_blank\">$NEAR;</a>&nbsp;a carbon neutral blockchain with low fees, fast transactions, and a great user experience.</p>\r\n<p><strong>Can I bid with ETH or Paypal?</strong></p>\r\n<p>Sure, why not. You\'ll still need an account from <a href=\"htts://wallet.near.org\" target=\"_blank\">wallet.near.org</a> to store your&nbsp; NFT ðŸ˜‰</p>\r\n<p><strong>How long will the auctions last?</strong></p>\r\n<p>2 hours. Each auction will be 30 minutes and there are 4 pieces.&nbsp;</p>\r\n<h2>*Support</h2>\r\n<p>Art is available for sale on&nbsp;the&nbsp;<a href=\"https://shop.codame.com/\">CODAME Shop</a>&nbsp;and as part of the&nbsp;<a href=\"https://nft.codame.com/\">CODAME&nbsp;NFT</a>&nbsp;Collection.</p>\r\n<p>We&nbsp;are&nbsp;kindly asking&nbsp;for <a href=\"https://www.tickettailor.com/events/codame/461601#ticket_selection\" target=\"_blank\">donations</a> to&nbsp;keep our Minecraft server going.</p>\r\n<p style=\"text-align: center;\">ðŸ’Ÿ ðŸ‘¾ ðŸ’œ ðŸ‘¾ ðŸ’Ÿ</p>\r\n<p style=\"text-align: center;\"><a style=\"box-sizing: border-box; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; text-align: start; background-color: #000000; color: #00a4a7 !important;\" href=\"https://www.tickettailor.com/events/codame/461601#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p style=\"text-align: center;\">About&nbsp;<em>FRAMEWORLD</em></p>\r\n<p><a href=\"/events/frameworld\"><strong><img src=\"/uploaded_images/frameworld-1.png\" alt=\"\" width=\"801\" height=\"407\" /></strong></a></p>\r\n<p dir=\"ltr\">FRAMEWORLD is a web-specific group exhibition, curated by YaÄŸmur UyanÄ±k, that establishes a focus on the discourses around creating a multiplicity of locality, understanding of the new international and transcultural solidarity in the times of extreme precarity. The works in the show together critically engage with the present, embrace the notions of urgency, and propose alternative approaches to current disruptions, reflecting on what interconnectedness and new modes of collectivity look like now.&nbsp;</p>\r\n<p dir=\"ltr\">All exhibited works will have the opportunity to be for sale.&nbsp;Be the first to have access to the art by joining the&nbsp;FRAMEWORLD&nbsp;opening&nbsp;and meet&nbsp;the artists, curator, CODAME team, partners and other collectors, and ART+TECH supporters.</p>\r\n<p dir=\"ltr\">Learn more on&nbsp;<a href=\"/events/frameworld\">https://codame.com/events/frameworld</a></p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"color: #00a4a7; font-family: Asap, helvetica, arial, sans-serif;\"><span style=\"font-size: 15px; text-align: start; background-color: #000000; height: auto; margin-left: auto; margin-right: auto;\"><a style=\"box-sizing: border-box; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; text-align: start; background-color: #000000; color: #00a4a7 !important;\" href=\"https://www.tickettailor.com/events/codame/461601#ticket_selection\" target=\"_blank\"><img style=\"box-sizing: border-box; max-width: 100%; height: auto; display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></span></span></p>\r\n<p><span style=\"color: #00a4a7; font-family: Asap, helvetica, arial, sans-serif;\">&nbsp;</span></p>\r\n<p>&nbsp;</p>', 'hufo,mirabelle-jones,delta-ark,paula-levine,pablo-salafurka,yagmur-uyanik,snow-yunxue-fu,tiare-ribeaux,andy-wauman,jordan-gray,jody-stillwater,tarwin-stroh-spijer,dc-spensley,huili-chen,anabela-costa,quinn-keck', 'minecraft-art-tech-gallery,doomslug,embodying-the-algorithm,poetic-cosmicity,chandelier,certitude-162b2,thewall-theworld-2020,gevurah,avalanche,vibration-obfuscation-detritus-inheritance,dear-nostalgiabot,ia-manawa-n-at-this-time,howl-silhouette-of-sound,machine-of-perceptions', '', 'art-gallery-auction-house', '', '', '0', 'event', 'https://www.tickettailor.com/events/codame/461601#ticket_selection', ''),
(198, 'Create LED Patterns for Entwined 2.0', 'create-led-patterns-for-entwined-2-0', '2021-12-19', 'http://codame.dreamhosters.com/uploaded_images/create-led-patterns-for-entwined-2-0.png', '<center>Sunday,&nbsp;December&nbsp;19th @ <a href=\"https://time.is/11:00AM_19_December_2021_in_San_Francisco/New_York/Berlin/Hyderabad/Shanghai?CODAME\" target=\"_blank\">11:00AM (PST)</a></center><center></center><center></center><center></center><center></center>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/624089/#ticket_selection\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<h3><strong><span style=\"font-family: Roboto, RobotoDraft, Helvetica, Arial, sans-serif; font-size: 13px; white-space: pre-wrap;\">&nbsp;</span></strong></h3>\r\n<p class=\"graf graf--p\">The Entwined installation is back and will run until February 1, 2022, at the Golden Gate Park&rsquo;s Peacock Meadow.</p>\r\n<p class=\"graf graf--p\">CODAME is excited to run another workshop to build LED patterns to transform the Golden Gate Park into an enchanted forest of otherworldly shapes and ever-changing light.</p>\r\n<p class=\"graf graf--p\">Entwined is an installation by Charles Gadeken composed of 2000 LED lights decorating large metal trees and shrubs. Learn how to build patterns for this installation so that your signature style can be on display for all of San Francisco to enjoy!&nbsp;</p>\r\n<p class=\"graf graf--p\">Create a whimsical wonderland where visitors can explore twisting paths, colorful trees to sit under, large flowering clusters to run around and admire, and constantly changing vistas of light and magic. Inspired by nature, this interactive art installation will connect and enchant visitors of all ages.</p>\r\n<p class=\"graf graf--p\">In this workshop, we will teach you the foundations you&rsquo;ll need to be able to write LX Studio patterns for Entwined Meadows.</p>\r\n<p class=\"graf graf--p\">Some familiarity with Java or any object-oriented programming is required, as we&rsquo;ll be using Processing. You&rsquo;ll need is a computer with a stable internet connection, Chrome, and a Google login account. Get a head start by having some fun ideas of what you think would make some great patterns!</p>\r\n<p>&nbsp;</p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/624089/#ticket_selection/#ticket_selection\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p>&nbsp;</p>\r\n<h3>///SCHEDULE</h3>\r\n<ul>\r\n<li>Sun,&nbsp;Dec 19th, 2021</li>\r\n<li class=\"graf graf--li\">11&nbsp;am&nbsp;to 1 pm PT (2 hours)&nbsp;<a class=\"markup--anchor markup--li-anchor\" href=\"https://time.is/11:00AM_19_December_2021_in_San_Francisco/New_York/Berlin/Hyderabad/Shanghai?CODAME\" target=\"_blank\" rel=\"noopener\" data-href=\"https://time.is/1100AM_18_October_2020_in_San_Francisco/Berlin/Hyderabad/Shanghai?CODAME\">Check your timezone</a>&nbsp;</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h3>///SKILL LEVEL</h3>\r\n<ul>\r\n<li>Some basic understanding of Java or object-oriented programming is required.</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h3>///WORKSHOP OUTLINE</h3>\r\n<ol start=\"1\" type=\"1\">\r\n<li>Troubleshooting -- Making sure we\'re all starting on the same foot!</li>\r\n<li>Introductions (The Artist, The Sculpture)</li>\r\n<li>The Basics (UI Walkthrough, Creating simple patterns)</li>\r\n<li><em>Breakout: Exploring simple patterns</em></li>\r\n<li>The Advanced (More Advanced pattern techniques)<em><br /></em></li>\r\n<li><em>Breakout: Playing with what you know</em></li>\r\n<li>Show and Tell</li>\r\n<li>Instructor Q&amp;A</li>\r\n<li>How to get your pattern onto Entwined</li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<h3>///ATTENDEES BRING</h3>\r\n<ol>\r\n<li>Have <strong>Processing 4 </strong>installed and ready to go (documentation provided below)</li>\r\n<li>Have <strong>Entwined</strong> repo downloaded and ready (documentation provided below)</li>\r\n</ol>\r\n<ul>\r\n<li>Computer &amp; power/charger.</li>\r\n<li>Zoom installed ahead of time.</li>\r\n<li>Optional: 2nd monitor or screen so you can see the Zoom while working.</li>\r\n</ul>\r\n<p><br /><br /></p>\r\n<h3>///CODAME PROVIDES</h3>\r\n<ul>\r\n<li>Instructor Slides</li>\r\n<li>Documentation on getting set up,&nbsp;plus helpful information/instructions (<a href=\"https://docs.google.com/document/d/1Q-tmy1sxg6ZH_3IyOlrIx1kU09Mq2iiKhImZOlfE09Y/edit?usp=sharing\">click here!</a>)&nbsp;</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/624089/#ticket_selection\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\">&nbsp;<iframe title=\"YouTube video player\" src=\"https://www.youtube-nocookie.com/embed/r-U5ON3jWGU?controls=0\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>&nbsp;</p>\r\n<p>&atilde;&euro;Ž CODAME&nbsp;#CodeArtTogether Workshops &atilde;&euro;</p>\r\n<table style=\"height: 101px;\" width=\"100%\">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p dir=\"ltr\" style=\"line-height: 1.2; text-align: center; margin-top: 0pt; margin-bottom: 0pt;\"><span style=\"font-size: 36pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">&eth;&Yuml;&sect;&nbsp;&acirc;&oelig;&uml;</span>&nbsp;<span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"><br /></span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">Connect</span></p>\r\n</td>\r\n<td style=\"text-align: center;\"><span id=\"docs-internal-guid-81f37ba5-7fff-97be-c713-6edc787897a0\"><span style=\"font-size: 36pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">&eth;&Yuml;&scaron;&sect;&eth;&Yuml;Ž&uml;</span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"><br /></span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">Create</span></span></td>\r\n<td>\r\n<p dir=\"ltr\" style=\"line-height: 1.2; margin-top: 0pt; margin-bottom: 0pt; text-align: center;\"><span style=\"font-size: 36pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\">&eth;&Yuml;&curren;&copy;&eth;&Yuml;&rsquo;&not; </span><span style=\"font-size: 18pt; font-family: \'Source Serif Pro\', serif; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;\"><br /></span><span style=\"font-family: \'Source Serif Pro\', serif;\"><span style=\"font-size: 24px; white-space: pre-wrap;\">Celebrate</span></span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>Connecting, Creating, and Celebrating&nbsp;are pillars of the&nbsp;<a href=\"/projects/code-art-together\">CODAME #CodeArtTogether workshops</a>!&nbsp;</p>\r\n<p>Workshops are great for team building, remote or IRL. They cultivate space to play, which guides sense-making and sparks innovation. Attendees become featured artists with the option to show their workshop creations in CODAME galleries.&nbsp;<a href=\"/projects/code-art-together\">Learn more about this exciting offering</a><a href=\"https://www.tickettailor.com/checkout/view-event/id/486392/chk/4cfa/?modal_widget=true&amp;widget=true&amp;d\">!</a></p>\r\n<p>What topics grab your curiosity to learn or teach?&nbsp;Let us know through our&nbsp;<a href=\"/pages/call-for-workshops\">call for workshops</a>&nbsp;and&nbsp;<a href=\"/pages/join-us\">Join us</a>&nbsp;as a sponsor, volunteer, or workshop leader!&nbsp;<br />&nbsp;</p>\r\n<center>&eth;&Yuml;&rsquo;&Yuml; &eth;&Yuml;&lsquo;&frac34; &eth;&Yuml;&rsquo;&oelig; &eth;&Yuml;&lsquo;&frac34; &eth;&Yuml;&rsquo;&Yuml;</center>\r\n<p style=\"text-align: center;\">CODAME is a member of Intersection for the Arts&nbsp;<br />a non profit 501(c)(3)&nbsp;organization.</p>\r\n<p style=\"text-align: center;\">All proceeds will be split with the participating artists.</p>\r\n<p style=\"text-align: center;\"><a href=\"https://www.flipcause.com/secure/cause_pdetails/NjU0OA==\">Donations</a>&nbsp;are always welcome.</p>\r\n<p style=\"text-align: center;\">Thank you for your support for ART &hearts;&iuml;&cedil; TECH !!!</p>\r\n<p style=\"text-align: center;\"><a href=\"/pages/code-of-conduct\">Code of Conduct</a>&nbsp;for all attendees.&nbsp;<br /><br /><em>Flier Photo Courtesy San Francisco Recreation and Park Department.</em></p>\r\n<p style=\"text-align: center;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;<img src=\"/uploaded_images/entwined01.png\" alt=\"\" /></p>\r\n<p style=\"text-align: center;\"><img src=\"/uploaded_images/entwined02.png\" alt=\"\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;<img src=\"/uploaded_images/entwined03.png\" alt=\"\" /></p>\r\n<p style=\"text-align: center;\"><img src=\"/uploaded_images/entwined05.png\" alt=\"\" /></p>\r\n<p style=\"text-align: center;\">(Photos by Joey Yee)</p>\r\n<p style=\"text-align: center;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></p>', 'colin-hunt,charles-gadeken', '', '', '', '', '', '0', 'workshop', 'https://www.tickettailor.com/events/codame/624089/#ticket_selection', ''),
(199, 'Creative Build-A-Thon', 'creative-build-a-thon', '0000-00-00', 'http://codame.dreamhosters.com/uploaded_images/creative-build-a-thon.gif', '<h3>CODAME + Twilio invites you to participate in a two-day virtual Build-a-Thon event focused on creating art that incorporates communication technology&nbsp;as part of ã€Ž Rawthentic ã€2022 ART+TECH Festival<span style=\"font-size: 11px;\">.</span></h3>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/640765/#ticket_selection\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p>Twilio is a company that provides ways for artists and technologists to create communications experiences using code or low code tools. You can send SMS, MMS or WhatsApp messages, set up video calling, make phone calls, send emails, and more, integrated in your own systems or triggered by different events.</p>\r\n<p>RAWTHENTIC is a mantra of honest connection &amp; interaction. As facades fall away we have an opportunity to let shine the true colors of our inner flames. Our open call invites artists to present their purest sense of expression in any medium. By building up each others\' vulnerable, natural desires we forge sustainable, RAWTHENTIC bonds. Create deep wells of understanding and possibility with a sensitive unmasking of experiences. Join us for a gnarly ride of unfiltered vibes! Curated by Alissa Christine, CODAME is excited for your transparent exploration of physical and metaphysical realities. What inspiration can your deepest mysteries reveal?&nbsp;</p>\r\n<p>Anyone is welcome to participate, and you can sign up individually or as a team. When you register, you will receive invites to a matchmaking event where you can meet other artists, or find others to create a team. The two-day event will kick off on the 11th with an overview of what to expect, and some ideas on how to get started. For the first hour, we&rsquo;ll have Twilio experts available to help you figure out where to begin or clear any technical blockers.</p>\r\n<p>The event will culminate on the 12th with a demo where you can show what you created. A panel of judges will watch and offer their insights.</p>\r\n<p>Everyone will receive Twilio swag and a recording of their demo. The winners will receive a professionally edited video about their project and a feature on the Twilio blog. The artwork may be selected to be part of&nbsp;CODAME&nbsp;ART+TECH Festival 2022 and have their work showcased in art galleries around the world, online at our virtual&nbsp;<a href=\"http://gallery.codame.com\">gallery.codame.com </a>+ optionally available for sale on&nbsp;<a href=\"http://shop.codame.com/\">shop.codame.com</a>&nbsp;and as NFTs on&nbsp;<a href=\"http://codame.com/nft\">nft.codame.com</a>.</p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/640765/#ticket_selection\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<h2>When?</h2>\r\n<p><strong>Friday, February 11&nbsp;</strong></p>\r\n<p>Kickoff:&nbsp; 3-3:30pm PT&nbsp;</p>\r\n<p>Brainstorming: 3:30-4:30 PT</p>\r\n<p>Networking &amp; Movie Night: 4:30-6:30 PT</p>\r\n<p>Join us on Friday at 3pm to kick off the build-a-thon and hear from some talented artists about how they created their piece using Twilio. From there you and your team can start brainstorming what you&rsquo;d like to build. Twilio Engineers will be available to help you get started. Then, join the group for a time to network and optional time to watch a movie with everyone on Discord.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Saturday February 12</strong></p>\r\n<p>Building: 9am-2pm PT</p>\r\n<p>Demos: 2-3p PT</p>\r\n<p>On Saturday you can join your team and get to work. We&rsquo;ll convene at 2p PT where you&rsquo;ll have&nbsp; 5-7 minutes to demo your project to a panel of judges. The winners will receive a professionally edited video about their project and a feature on the Twilio blog.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<h2>Who?</h2>\r\n<p>Artists of all disciplines and artist levels are encouraged to participate. No previous knowledge of Twilio is required! You may register as a team, or if you\'d like to register solo you\'ll have an opportunity to find a team at the February 8 matchmaking event.</p>\r\n<p><strong>Looking for a Teammate?</strong></p>\r\n<p>If you are signing up solo but would like to join a team to work collaboratively, you can use this time to learn more about theã€Ž Rawthentic ã€ART+TECH Build-a-Thon, meet the organizers and ask questions, meet other participating hackers, builders, and artists,&nbsp;you might want to share what you&rsquo;d like to build and optionally&nbsp;match with other attendees to build&nbsp;a&nbsp;team&nbsp;to start planning to hack for the weekend.</p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/643850/\">Join</a>&nbsp;the&nbsp;Matchmaking event&nbsp;&nbsp;<a href=\"https://www.tickettailor.com/events/codame/643850/\">February 8&nbsp;</a></p>\r\n<p>&nbsp;</p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/640765/#ticket_selection\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p style=\"text-align: center;\">&nbsp;ðŸ’Ÿ ðŸ‘¾ ðŸ’œ ðŸ‘¾ ðŸ’Ÿ</p>\r\n<p style=\"text-align: center;\">CODAME is a member of Intersection for the Arts&nbsp;<br />a non profit 501(c)(3)&nbsp;organization.</p>\r\n<p style=\"text-align: center;\">All proceeds will be split with the participating artists.</p>\r\n<p style=\"text-align: center;\"><a href=\"https://www.flipcause.com/secure/cause_pdetails/NjU0OA==\">Donations</a>&nbsp;are always welcome.</p>\r\n<p style=\"text-align: center;\">Thank you for your support for ART &hearts;ï¸ TECH !!!</p>\r\n<p style=\"text-align: center;\"><a href=\"/pages/code-of-conduct\">Code of Conduct</a>&nbsp;for all attendees.&nbsp;</p>\r\n<p>&nbsp;</p>', '', '', 'twilio', '', '', '', '0', 'event', 'https://www.tickettailor.com/events/codame/640765/#ticket_selection', 'matchmaking-for-rawthentic-art-tech-build-a-thon');
INSERT INTO `events` (`id`, `name`, `slug`, `date`, `pic`, `description`, `artists_array`, `projects_array`, `sponsors_array`, `partners_array`, `old_url`, `rsvp_url`, `hidden`, `event_type`, `shop_url`, `events_array`) VALUES
(202, 'Rawthentic ART+TECH Build-A-Thon', 'rawthentic-art-tech-build-a-thon', '2022-02-11', 'http://codame.dreamhosters.com/uploaded_images/rawthentic-art-tech-build-a-thon.gif', '<h3>CODAME + Twilio invites you to participate in a two-day virtual creative Build-A-Thon event focused on creating art that incorporates communication technology&nbsp;as part of Rawthentic - 2022 ART+TECH Festival<span style=\"font-size: 11px;\">.</span></h3>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/640765/#ticket_selection\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p style=\"text-align: center;\"><a href=\"https://www.tickettailor.com/events/codame/640765/#ticket_selection\">February 11-12, 2022</a></p>\r\n<p>Twilio is a company that provides ways for artists and technologists to create communications experiences using code or low code tools. You can send SMS, MMS or WhatsApp messages, set up video calling, make phone calls, send emails, and more, integrated in your own systems or triggered by different events.</p>\r\n<p>RAWTHENTIC is a mantra of honest connection &amp; interaction. As facades fall away we have an opportunity to let shine the true colors of our inner flames. Our open call invites artists to present their purest sense of expression in any medium. By building up each others\' vulnerable, natural desires we forge sustainable, RAWTHENTIC bonds. Create deep wells of understanding and possibility with a sensitive unmasking of experiences. Join us for a gnarly ride of unfiltered vibes! Curated by Alissa Christine, CODAME is excited for your transparent exploration of physical and metaphysical realities. What inspiration can your deepest mysteries reveal?&nbsp;</p>\r\n<p>Anyone is welcome to participate, and you can sign up individually or as a team. When you register, you will receive invites to a matchmaking event where you can meet other artists, or find others to create a team. The two-day event will kick off on the 11th with an overview of what to expect, and some ideas on how to get started. For the first hour, we&rsquo;ll have Twilio experts available to help you figure out where to begin or clear any technical blockers.</p>\r\n<p>The event will culminate on the 12th with a demo where you can show what you created. A special panel of judges, and extraordinary Artists, will watch and offer their insights: Anouk Wipprecht, Amy Langer, Ezra Reaves, Quinn Keck + Alissa Christine from CODAME, and Gervis Cash from Twilio.&nbsp;</p>\r\n<p>Everyone will receive Twilio swag and a recording of their demo. The winners will receive a professionally edited video about their project and a feature on the Twilio blog. The artwork may be showcased in art galleries around the world, online in&nbsp;<a href=\"http://gallery.codame.com\">gallery.codame.com</a>. Optionally also available for sale&nbsp;on&nbsp;<a href=\"http://shop.codame.com\">shop.codame.com</a>&nbsp;and as NFTs on&nbsp;<a href=\"http://codame.com/nft\">nft.codame.com</a></p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/640765/#ticket_selection\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p>&nbsp;</p>\r\n<h2>When?</h2>\r\n<p><strong>Friday, February 11&nbsp;</strong></p>\r\n<p>Kickoff:&nbsp; 3-3:30pm PT&nbsp;</p>\r\n<p>Brainstorming: 3:30-4:30 PT</p>\r\n<p>Networking &amp; Movie Night: 4:30-6:30 PT</p>\r\n<p>Join us on Friday at 3pm to kick off the build-a-thon and hear from some talented artists about how they created their piece using Twilio. From there you and your team can start brainstorming what you&rsquo;d like to build. Twilio Engineers will be available to help you get started. Then, join the group for a time to network and optional time to watch a movie with everyone on Discord.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Saturday February 12</strong></p>\r\n<p>Building: 9am-2pm PT</p>\r\n<p>Demos: 2-3p PT</p>\r\n<p>On Saturday you can join your team and get to work. We&rsquo;ll convene at 2p PT where you&rsquo;ll have&nbsp; 5-7 minutes to demo your project to a panel of judges. The winners will receive a professionally edited video about their project and a feature on the Twilio blog.&nbsp;</p>\r\n<p>&nbsp;&nbsp;</p>\r\n<h2>Who?</h2>\r\n<p>Artists of all disciplines and artist levels are encouraged to participate. No previous knowledge of Twilio is required! You may register as a team, or if you\'d like to register solo you\'ll have an opportunity to find a team at the&nbsp;<a href=\"https://www.tickettailor.com/events/codame/643850/\">February 8 matchmaking</a>&nbsp;event.&nbsp;<a href=\"https://www.tickettailor.com/events/codame/643850/\">Join us</a>&nbsp;</p>\r\n<h2><strong>Looking for a Hack or </strong>Match?</h2>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/643850/\">Join</a>&nbsp;the&nbsp;Matchmaking event&nbsp;&nbsp;<a href=\"https://www.tickettailor.com/events/codame/643850/\">February 8</a></p>\r\n<p>If you are signing up solo but would like to join a team to work collaboratively, you can use this time to learn more about the&atilde;&euro;Ž Rawthentic &atilde;&euro;ART+TECH Build-a-Thon, meet the organizers and ask questions, meet other participating hackers, builders, and artists,&nbsp;you might want to share what you&rsquo;d like to build and optionally&nbsp;match with other attendees to build&nbsp;a&nbsp;team&nbsp;to start planning to hack for the weekend.</p>\r\n<p>&nbsp;&nbsp;&nbsp;</p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/640765/#ticket_selection\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p style=\"text-align: center;\">CODAME is a member of Intersection for the Arts&nbsp;<br />a non profit 501(c)(3)&nbsp;organization.</p>\r\n<p style=\"text-align: center;\">All proceeds will be split with the participating artists.</p>\r\n<p style=\"text-align: center;\"><a href=\"https://www.flipcause.com/secure/cause_pdetails/NjU0OA==\">Donations</a>&nbsp;are always welcome.</p>\r\n<p style=\"text-align: center;\">Thank you for your support for ART &hearts; TECH !!!</p>\r\n<p style=\"text-align: center;\"><a href=\"/pages/code-of-conduct\">Code of Conduct</a>&nbsp;for all attendees.&nbsp;</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p>&nbsp;</p>', 'anouk-wipprecht,amy-langer,ezra-reaves,quinn-keck,alissa-christine,gervis-cash,knits-for-life,fereshteh-toosi,lina-lopes,illest-preacha,joshua-reeves', 'art-tech-festival-2022-rawthentic,the-program,hola-oily,cat-calls,my-circulatory-system', 'twilio', '', '', '', '0', 'event', 'https://www.tickettailor.com/events/codame/640765/#ticket_selection', 'matchmaking-for-rawthentic-art-tech-build-a-thon'),
(200, 'Entwined 2.0 Live Demo of LED Patterns', 'entwined-2-0-live-demo-of-led-patterns', '2022-01-30', 'http://codame.dreamhosters.com/uploaded_images/entwined-2-0-live-demo-of-led-patterns.jpg', '<div style=\"text-align: center;\"><strong>Sunday January 30th&nbsp;&nbsp;</strong>from 6-8pm (PT)</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div>Get excited for a live pattern show of the work you all created for Entwined 2.0 at our workshop!&nbsp; We will be demonstrating what you created, including some awesome patterns from class alumnae Lindsay, Jason, Mattaniah, Sydney, and Quinn -- congrats!&nbsp; These new patterns have been quite a hit with the Entwined crew, so we\'re excited to show them off for the whole city to see!</div>\r\n<div>&nbsp;</div>\r\n<div>We\'ll have a controller so you can play around with the patterns live (even if you hadn\'t created one in the workshop ðŸ˜‰). The Sculpture is also interactive if you scan certain LED cubes with QR codes on them ðŸ‘€.&nbsp;Come chat with like-minded tech artists and LED enthusiasts.</div>\r\n<div><br />Meet Colin and the CODAME Team&nbsp;at the&nbsp;San Francisco&nbsp;Golden&nbsp;Gate Park,&nbsp;Peacock Meadow, underneath the main tree. Dress warmly: The meadow can get surprisingly chilly at night!</div>\r\n<div>&nbsp;</div>\r\n<div><em>Photo by Jason Chinn, courtesy of SF Parks Alliance</em></div>\r\n<div>&nbsp;</div>', 'colin-hunt', 'entwined-meadow', '', '', '', '', '0', 'event', '', ''),
(201, 'Matchmaking for Rawthentic  ART+TECH Build-A-Thon', 'matchmaking-for-rawthentic-art-tech-build-a-thon', '2022-02-08', 'http://codame.dreamhosters.com/uploaded_images/team-matchmaking-for-rawthentic-build-a-thon.gif', '<h2 style=\"text-align: center;\"><strong>February 8, 2022,&nbsp;</strong>4-5pm PT</h2>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/643850/\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p style=\"text-align: center;\">Team Matchmaking for Rawthentic ART+TECH Build-a-Thon</p>\r\n<p style=\"text-align: center;\"><a href=\"https://www.tickettailor.com/events/codame/643850/\">Join us</a>&nbsp;</p>\r\n<p style=\"text-align: left;\">If you are signing up solo but would like to join a team to work collaboratively, you can use this time to learn more about the Rawthentic ART+TECH Build-a-Thon, meet the organizers and ask questions, and meet other participating hackers, builders, and artists,&nbsp;you might want to share what you&rsquo;d like to build and optionally&nbsp;match with other attendees to build&nbsp;a&nbsp;team&nbsp;to start planning to hack for the weekend.</p>\r\n<p>Artists of all disciplines and artist levels are encouraged to participate. No previous knowledge of Twilio is required! You may register as a team, or if you\'d like to register solo you\'ll have an opportunity to find a team at the February 8 matchmaking event.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><strong>About the ART+TECH Build-A-Thon</strong></p>\r\n<p>CODAME + Twilio invites you to participate in a two-day virtual <a href=\"/events/rawthentic-art-tech-build-a-thon\">Build-A-Thon</a> event, February 11-12, focused on creating art that incorporates communication technology as part of <a href=\"/projects/art-tech-festival-2022-rawthentic\">Rawthentic 2022 ART+TECH Festival</a><span style=\"box-sizing: border-box;\">.</span></p>\r\n<p>Anyone is welcome to participate, and you can sign up individually or as a team. When you register, you will receive invites to a matchmaking event where you can meet other artists, or find others to create a team. The two-day event will kick off on the 11th with an overview of what to expect, and some ideas on how to get started. For the first hour, we&rsquo;ll have Twilio experts available to help you figure out where to begin or clear any technical blockers.</p>\r\n<p>The event will culminate on the 12th with a demo where you can show what you created. A panel of judges will watch and offer their insights.</p>\r\n<p>Everyone will receive Twilio swag and a recording of their demo. The winners will receive a professionally edited video about their project and a feature on the Twilio blog. The artwork may be selected to be part of&nbsp;CODAME&nbsp;ART+TECH Festival 2022 and have their work showcased in art galleries around the world, online at our virtual&nbsp;<a href=\"http://gallery.codame.com/\">gallery.codame.com&nbsp;</a>+ optionally available for sale on&nbsp;<a href=\"http://shop.codame.com/\">shop.codame.com</a>&nbsp;and as NFTs on&nbsp;<a href=\"http://codame.com/nft\">nft.codame.com</a>&nbsp;</p>\r\n<p style=\"text-align: center;\"><strong>About&atilde;&euro;Ž Rawthentic &atilde;&euro;&nbsp;</strong></p>\r\n<p><a href=\"/projects/art-tech-festival-2022-rawthentic\">RAWTHENTIC</a> is a mantra of honest connection &amp; interaction. As facades fall away we have an opportunity to let shine the true colors of our inner flames. Our open call invites artists to present their purest sense of expression in any medium. By building up each others\' vulnerable, natural desires we forge sustainable, RAWTHENTIC bonds. Create deep wells of understanding and possibility with a sensitive unmasking of experiences. Join us for a gnarly ride of unfiltered vibes! Curated by Alissa Christine, CODAME is excited for your transparent exploration of physical and metaphysical realities. What inspiration can your deepest mysteries reveal?&nbsp;</p>\r\n<p style=\"text-align: center;\"><strong>About&nbsp;Twilio</strong></p>\r\n<p>Twilio is a company that provides ways for artists and technologists to create communications experiences using code or low code tools. You can send SMS, MMS or WhatsApp messages, set up video calling, make phone calls, send emails, and more, integrated in your own systems or triggered by different events.</p>\r\n<p>&nbsp;&nbsp;</p>\r\n<p><a href=\"https://www.tickettailor.com/events/codame/643850/\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/button_(6).png\" alt=\"CODAME ART+TECH Get Tickets Button\" /></a></p>\r\n<p style=\"text-align: center;\">CODAME is a member of Intersection for the Arts&nbsp;<br />a non profit 501(c)(3)&nbsp;organization.</p>\r\n<p style=\"text-align: center;\">All proceeds will be split with the participating artists.</p>\r\n<p style=\"text-align: center;\"><a href=\"https://www.flipcause.com/secure/cause_pdetails/NjU0OA==\">Donations</a>&nbsp;are always welcome.</p>\r\n<p style=\"text-align: center;\">Thank you for your support for ART+TECH !!!</p>\r\n<p style=\"text-align: center;\"><a href=\"/pages/code-of-conduct\">Code of Conduct</a>&nbsp;for all attendees.&nbsp;</p>\r\n<p>&nbsp;</p>', 'anouk-wipprecht,amy-langer,ezra-reaves,quinn-keck,alissa-christine,gervis-cash', 'art-tech-festival-2022-rawthentic,the-program', 'twilio', '', '', '', '0', 'event', 'https://www.tickettailor.com/events/codame/643850/', 'rawthentic-art-tech-build-a-thon'),
(204, 'RAWTHENTIC at Mars Landing Galleries', 'rawthentic-at-mars-landing-galleries', '2022-07-23', 'http://codame.dreamhosters.com/uploaded_images/rawthentic-at-mars-landing-galleries.png', '<p><strong>MLGNFT Gallery Launch Summer 2022 </strong></p>\r\n<p>curated by Alissa Christine + Miryam Rojas</p>\r\n<p>This is an IRL NFT event as part of the CODAME ART+TECH Festival 2022 themed RAWTHENTIC<strong>&nbsp;</strong>in partnership with Mars Landing Galleries, showcasing 25 CODAME artists\' creations on screens... running the spectrum of 2D, 3D, interactive, immersive, augmented reality (AR) virtual reality (VR) works. There will be live VR paintings by LUVRworldwide, and guests are invited to step inside her metaverse in between the performances.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Theme: RAWTHENTIC</strong></p>\r\n<p>The mantra of authentic, honest connection &amp; interaction.</p>\r\n<p>As facades fall away, we have an opportunity to let the true colors of our inner flames shine. By building up each others\' vulnerable, natural desires we forge sustainable, RAWTHENTIC bonds. We can create deep wells of understanding and possibility with a sensitive unmasking of experiences. Artists were invited to present their purest sense of expression in any medium and encouraged to submit Augmented Reality Art made possible by Artivive.</p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"/uploaded_images/Mars_Landing_Galleries_21.jpg\" alt=\"\" /></p>\r\n<p><strong>The artwork is from emerging and established artists from both around the globe and in our own backyard:&nbsp;</strong></p>\r\n<p>Daryl Slaton, Edison Duran Lucena, ejthek, Fabio Cort&eacute;s, Hazel Griffiths, Judit Navratil, Layer ll, Lou Peralta, LUVRworldwide, Marcotic, Momentology, Melanie Clemmons + Zak Loyd collab, Moe Angelo (moestradamus), Natural Warp, odbol, Rui Zilh&atilde;o, Skip Rohde, Sof&iacute;a Maldonado, strayltd + plutonic mind collab, synwrks, The Art Of Cassandra Mark, Theo Goodman, where_you_are_is_home</p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"/uploaded_images/Mars_Landing_Galleries1.jpg\" alt=\"\" />&nbsp;</p>\r\n<p><strong>Physical items include:&nbsp;&nbsp;</strong></p>\r\n<p>Infinite Objects Video Frames. Prices vary (NFT included)</p>\r\n<p>AR Canvas prints. $400 each (NFT Not Included)</p>\r\n<p>Artwork in this gallery is minted by the artists themselves, and is currently in escrow for the duration of the exhibit in the MLGNFT crypto wallets, on Tezos and Ethereum Blockchains.</p>\r\n<p>NFT pricing ranges from approximately $20 - $6,000</p>\r\n<p>(variant upon the crypto coin price at the time of purchase.)</p>\r\n<p>&nbsp;</p>\r\n<p><strong>About Mars Landing Galleries</strong></p>\r\n<p>Mars Landing Galleries is a standout gallery for the works of artists and makers nestled in and around the Blue Ridge Mountains and beyond. Each exhibit space is curated to provide viewers ample space for contemplation, connection, and ultimate appreciation of exquisite works not readily displayed locally. It is a must-show location for working artists and makers looking for optimal exposure. And a must-see destination for both curious art lovers and those actively seeking to expand their own collections.</p>\r\n<p>Originally built in 1945 as a roller skating rink, Mars Landing boasts beautifully restored Southern Maple hardwood floors, high ceilings, and a tranquil location nestled one block off the historic Main Street of Mars Hill, NC.&nbsp; Known as the Jewel of the Blue Ridge, Madison County encompasses expansive rolling hills of picturesque tobacco barns, animal pastures, flower farms, river views, and hiking trails for the consummate Appalachian experience.</p>\r\n<p>Come and experience Mars Landing!&nbsp;</p>\r\n<p>Open Wednesday - Saturday 11 - 5 PM, or&nbsp;<a href=\"https://marslandinggalleries.com/contact\">by appointment</a></p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"/uploaded_images/Rawthentic.png\" alt=\"\" /></p>', 'alissa-christine,daryl-slaton,edison-duran-lucena,ejthek,fabio-cort-s,hazel-griffiths,judit-navratil,layer-ll,lou-peralta,melanie-clemmons,marcotic,moe-angelo,odbol,natural-warp,rui-zilh-o,skip-rohde,sof-a-maldonado,strayltd,plutonicmind,synwrks,cassandra-mark', 'art-tech-festival-2022-rawthentic', '', 'mars-landing-galleries,artivive', '', '', '0', 'event', 'https://marslandinggalleries.com/nft-gallery', ''),
(208, 'ART+TECH Reconnect', 'art-tech-reconnect', '2023-07-07', 'http://codame.dreamhosters.com/uploaded_images/xenoform-codame-mixer.jpg', '<div style=\"text-align: center;\">July 7th (Friday), 8-11pm</div>\r\n<div style=\"text-align: center;\">@&nbsp;</div>\r\n<div style=\"text-align: center;\">Xenoform Labs</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\"><a href=\"https://www.tickettailor.com/checkout/view-event/id/2706626/chk/252a/?modal_widget=true&amp;widget=true\">RSVP</a></div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\">Light refreshments provided</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div>Get ready for a cozy and intimate gathering! CODAME and Xenoform Labs are teaming up to bring our incredible ART+TECH community together for a down-to-earth evening about genuine connections and real conversations.<br />\r\n<p dir=\"ltr\">No formalities here, just a relaxed atmosphere where we can rebuild, revitalize, and have a great time exploring new possibilities post-pandemic. It\'s a chance to reconnect with old friends and discover new ways to collaborate and support each other.</p>\r\n<p dir=\"ltr\">You\'ll hear from CODAME and Xenoform Labs founders during a laid-back 20-minute presentation. They\'ll share their thoughts on the future of art and tech in the SF Bay Area, setting the stage for an inspiring evening. Plus, we\'ll introduce you to the talented Xenoform Labs residency artists Vincent Naples and Ivan DelSol. Get ready to be amazed by their incredible work!</p>\r\n<p dir=\"ltr\">Take into consideration that space is limited. Get on&nbsp;the <a href=\"https://www.tickettailor.com/checkout/view-event/id/2706626/chk/252a/?modal_widget=true&amp;widget=true\">waiting list</a> if you don\'t want to miss out on this intimate gathering. We\'ll do our best to accommodate as many people as possible because we truly value your presence in our community.</p>\r\n<p dir=\"ltr\">So, mark the date on your calendar, and come as you are for an authentic and meaningful event. Let\'s rebuild, reconnect, and inspire each other in a relaxed and intimate setting. We can\'t wait to share this special experience with you!</p>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div><a href=\"https://www.tickettailor.com/checkout/view-event/id/2706626/chk/252a/?modal_widget=true&amp;widget=true\">RSVP</a> to be added to the waiting list.</div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<p>///</p>\r\n<p>CODAME is a member of Gray Area, a nonprofit 501(c)(3) organization. All proceeds will be split with the participating artists. Thank you for the support for ART+TECH !!!&nbsp;<a href=\"http://codame.com/pages/code-of-conduct\">Code of Conduct</a> for all attendees.&nbsp;</p>\r\n</div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<p style=\"text-align: center;\"><iframe style=\"border-style: solid; border-color: #eeeeee; background-image: initial; background-position: initial; background-repeat: initial; background-color: white;\" src=\"https://codame.substack.com/embed\" width=\"480\" height=\"320\" frameborder=\"0\" scrolling=\"no\"></iframe>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div>&nbsp;</div>', 'scott-kildall,jordan-gray,bruno-fonzi,vincent-naples,ivan-delsol,cindy-clark,yiyue-chen-iota', '', '', 'xenoform-labs', '', '', '0', 'event', 'https://www.tickettailor.com/checkout/view-event/id/2706626/chk/252a/?modal_widget=true&widget=true', '');
INSERT INTO `headers` (`id`, `slug`, `pic`, `banner-link-url`, `banner_link_url`, `description`) VALUES
(1, 'homepage', 'http://codame.dreamhosters.com/uploaded_images/codame2012-logo-01-opacity95-1697408066.png', 'http://codame.com/events/intersections', 'https://codame.com/pages/join-us', '<blockquote>\r\n<h2 style=\"text-align: center;\">Subscribe to our ART+TECH&nbsp;<a href=\"https://codame.substack.com/\">Newsletter</a></h2>\r\n</blockquote>\r\n<pre style=\"text-align: center;\">&nbsp;<span style=\"font-family: \'.AppleSystemUIFontMonospaced\'; font-size: 12px;\">CODAME celebrates creativity through inspiring experiences </span><span style=\"font-family: \'.AppleSystemUIFontMonospaced\'; font-size: 12px;\">like our annual ART+TECH Festival, running since 2010. </span></pre>\r\n<pre style=\"text-align: center;\"><span style=\"font-family: \'.AppleSystemUIFontMonospaced\'; font-size: 12px;\">CODAME is a member of the Gray Area 501 (c)(3) non-profit in San Francisco.</span><br /><br /></pre>\r\n<p style=\"text-align: left;\">&nbsp;</p>'),
(2, 'sponsors', '', '', '', '<p dir=\"ltr\">Be recognized as the innovative and visionary organization, partner with us on:</p>\r\n<ul>\r\n<li>Make an in kind donation</li>\r\n<li>Bring a CODAME Artist installation or performance to your event or team offsite</li>\r\n<li>Sponsor a CODAME <a href=\"/events\">event</a></li>\r\n<li>Support an ART+TECH workshop</li>\r\n<li>Build a visionary <a href=\"/projects\">project</a> with us</li>\r\n</ul>\r\n<p><a href=\"/pages/support-art-tech\">Contact Us.</a></p>'),
(3, 'events', 'http://codame.dreamhosters.com/uploaded_images/dot-1615429820.png', '', '', '<p>Unique ART+TECH events, to inspire through experience.</p>'),
(4, 'projects', 'http://codame.dreamhosters.com/uploaded_images/codame-gallery-banner-1623199911.jpg', '', '', '<p>Be part of the <a href=\"/pages/codame-artist-collective\">CODAME Artist Collective</a>. If accepted, you will receive access&nbsp;to all future CODAME ART+TECH events. Submit your online or&nbsp;<span id=\"docs-internal-guid-73f5222a-7fff-3879-c672-7558cee95985\">physical&nbsp;</span>projects: workshops, installation&nbsp;experiences, performances, or artwork for the opportunity to be showcased at CODAME&nbsp;<a href=\"/events\">Events</a>,&nbsp;<a href=\"http://gallery.codame.com\">Galleries</a>,&nbsp;and/or have your artwork prints for sale&nbsp;in our&nbsp;<a href=\"https://shop.codame.com\">Shop</a>&nbsp;or&nbsp;as&nbsp;<a href=\"https://nft.codame.com\">NFTs</a></p>\r\n<p><span id=\"docs-internal-guid-1b82c33a-e394-61c3-97e1-44f6b3a1e7ce\">To&nbsp;apply:</span></p>\r\n<ol>\r\n<li>Read&nbsp;the CODAME Artists&nbsp;<a href=\"/pages/codame-artists-agreement\">Agreement</a></li>\r\n<li>Send us your project&nbsp;<a href=\"/pages/call-for-proposals\">Proposal</a></li>\r\n<li>Upload your artwork&nbsp;<a href=\"https://forms.gle/kj6cDdywq3dYHehe9\">Here</a></li>\r\n</ol>\r\n<p>Our curators will follow up with you&nbsp;with an acceptance letter or for further information.</p>\r\n<p><a href=\"mailto:art@codame.com\">Contact us</a>&nbsp;or join&nbsp;the CODAME&nbsp;<a href=\"https://discord.com/invite/pk3C8DB\">Discord</a>&nbsp;ART+TECH community&nbsp;for&nbsp;any questions you might have.</p>'),
(5, 'artists', '', '', '', '<p>Be part of the <a href=\"/pages/codame-artist-collective\">CODAME Artist Collective</a>. If accepted, you will receive access&nbsp;to all future CODAME ART+TECH events. Submit your online or&nbsp;<span id=\"docs-internal-guid-73f5222a-7fff-3879-c672-7558cee95985\">physical&nbsp;</span>projects: workshops, installation&nbsp;experiences, performances, or artwork for the opportunity to be showcased at CODAME&nbsp;<a href=\"/events\">Events</a>,&nbsp;<a href=\"http://gallery.codame.com\">Galleries</a>,&nbsp;and/or have your artwork prints for sale&nbsp;in our&nbsp;<a href=\"https://shop.codame.com\">Shop</a>&nbsp;or&nbsp;as&nbsp;<a href=\"https://nft.codame.com\">NFTs</a></p>\r\n<p><span id=\"docs-internal-guid-1b82c33a-e394-61c3-97e1-44f6b3a1e7ce\">To&nbsp;apply:</span></p>\r\n<ol>\r\n<li>Read&nbsp;the CODAME Artists&nbsp;<a href=\"/pages/codame-artists-agreement\">Agreement</a></li>\r\n<li>Send us your project&nbsp;<a href=\"/pages/call-for-proposals\">Proposal</a></li>\r\n<li>Upload your artwork&nbsp;<a href=\"https://forms.gle/kj6cDdywq3dYHehe9\">Here</a></li>\r\n</ol>\r\n<p>Our curators will follow up with you&nbsp;with an acceptance letter or for further information.</p>\r\n<p><a href=\"mailto:art@codame.com\">Contact us</a>&nbsp;or join&nbsp;the CODAME&nbsp;<a href=\"https://discord.com/invite/pk3C8DB\">Discord</a>&nbsp;ART+TECH community&nbsp;for&nbsp;any questions you might have.</p>'),
(6, 'workshops', 'http://codame.dreamhosters.com/uploaded_images/screen-shot-2020-12-13-at-3-1611045067.png', ' ', '', '<p>Playshops are the CODAME unique take on ART+TECH Workshops to Connect, Create, and Celebrate!&nbsp;</p>\r\n<p><a href=\"mailto:team@codame.com?subject=Playshop%20Booking%20for%20____YourTeamNameHere_;)____\">Contact us</a> to book an unforgettable inspiring experience for your team!</p>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\" type=\"mce-mce-mce-no/type\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\" type=\"mce-mce-mce-no/type\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\" type=\"mce-mce-no/type\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>\r\n<script id=\"xverse-wallet-provider\" src=\"chrome-extension://idnnbdplmphpflfnlkomgpfbpcgelopg/inpage.js\"></script>'),
(7, 'nft', 'http://codame.dreamhosters.com/uploaded_images/nft-header-1623111790.jpg', '', 'https://www.mintbase.io/store/codame.mintbase1.near', '<p>Be part of the&nbsp;<a href=\"/pages/codame-artist-collective\">CODAME Artist Collective</a>. If accepted, you will receive access&nbsp;to all future CODAME ART+TECH events. Submit your online or&nbsp;<span id=\"docs-internal-guid-73f5222a-7fff-3879-c672-7558cee95985\">physical&nbsp;</span>projects: workshops, installation&nbsp;experiences, performances, or artwork for the opportunity to be showcased at CODAME&nbsp;<a href=\"/events\">Events</a>,&nbsp;<a href=\"http://gallery.codame.com/\">Galleries</a>,&nbsp;and/or have your artwork prints for sale&nbsp;in our&nbsp;<a href=\"https://shop.codame.com/\">Shop</a>&nbsp;or&nbsp;as&nbsp;<a href=\"https://nft.codame.com/\">NFTs</a></p>\r\n<p><span id=\"docs-internal-guid-1b82c33a-e394-61c3-97e1-44f6b3a1e7ce\">To&nbsp;apply:</span></p>\r\n<ol>\r\n<li>Read&nbsp;the CODAME Artists&nbsp;<a href=\"/pages/codame-artists-agreement\">Agreement</a></li>\r\n<li>Send us your project&nbsp;<a href=\"/pages/call-for-proposals\">Proposal</a></li>\r\n<li>Upload your artwork&nbsp;<a href=\"https://forms.gle/kj6cDdywq3dYHehe9\">Here</a></li>\r\n</ol>\r\n<p>Our curators will follow up with you&nbsp;with an acceptance letter or for further information.</p>\r\n<p><a href=\"mailto:art@codame.com\">Contact us</a>&nbsp;or join&nbsp;the CODAME&nbsp;<a href=\"https://discord.com/invite/pk3C8DB\">Discord</a>&nbsp;ART+TECH community&nbsp;for&nbsp;any questions you might have.</p>');
INSERT INTO `pages` (`id`, `name`, `slug`, `pic`, `description`, `old_url`, `hidden`) VALUES
(1, 'Support ART+TECH', 'support-art-tech', '', '<p>Embrace innovation through creativity, play, and collaboration between artists and technologists and be recognized as an innovative and visionary company:</p>\r\n<ol>\r\n<li dir=\"ltr\">Public Events: Support or join our <a href=\"/events\">events</a>&nbsp;or&nbsp;<a href=\"/workshops\">workshops</a></li>\r\n<li dir=\"ltr\">Team Events: Inspire&nbsp;your&nbsp;team&nbsp;with ART+TECH</li>\r\n<li dir=\"ltr\">Newsletter: Become a sponsor of our <a href=\"https://codame.substack.com/\">Newsletter</a></li>\r\n</ol>\r\n<p>If you want an existing installation, choose your favorite&nbsp;CODAME <a href=\"/projects\">Project</a>&nbsp;and contact us!&nbsp;</p>\r\n<p>We accept&nbsp;tax-deductible&nbsp;<a href=\"https://buy.stripe.com/3cs6oSaydf0sfO8000\" target=\"_blank\">Donations</a>&nbsp;as a member of Gray Area Foundation, a 501(c)(3)&nbsp;non-profit organization supporting art and technology for social good in&nbsp;San Francisco, California.&nbsp;</p>\r\n<p>Big thanks to our <a href=\"/sponsors\">supporters</a>&nbsp;for their continued love and support for ART+TECH</p>\r\n<p><iframe src=\"https://docs.google.com/forms/d/1dHvD3v2gPvG--x9wlpR4EIMEcdjucVjmWCxcIGcFD7E/viewform?embedded=true\" width=\"100%\" height=\"2000\" frameborder=\"0\" marginwidth=\"0\" marginheight=\"0\">Loading...</iframe></p>', '', '0'),
(2, 'Donate', 'donate', '', '<p>Any PIXEL+BIT counts!</p>\r\n<p><a href=\"http://codame.eventbrite.com/\" target=\"_blank\"><img src=\"/wp-content/uploads/2013/12/insert_coin_to_continue_1400_x_810-w-hearts.png\" alt=\"insert_coin_to_continue_1400_x_810 w hearts\" width=\"625\" height=\"257\" /></a></p>\r\n<p>CODAME events are made possible thanks to&nbsp;<a href=\"/pages/call-for-volunteers\">volunteers</a>, event&nbsp;<a href=\"http://codame.eventbrite.com/\">donation</a>&nbsp;tickets and&nbsp;<a href=\"/sponsors\">sponsors</a>.&nbsp;We welcome the opportunity for you to join us in a collaborative relationship with support, either financial or in-kind, to continue raising the bar of what&rsquo;s possible at the nexus of ART+TECH.</p>\r\n<p>There are several ways to support CODAME,&nbsp;<a href=\"mailto:sponsor@codame.com\">Contact us</a>&nbsp;if you have questions or ideas.</p>\r\n<p><a href=\"http://www.theintersection.org/\" target=\"_blank\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/uploaded_images/Interesection-new-logo_copy2.png\" alt=\"\" /></a></p>\r\n<p>We can accept&nbsp;Nonprofit &ndash; Tax&nbsp;Deductible Donations: &nbsp;We are members of&nbsp;<a href=\"http://theintersection.org/\" target=\"_blank\">Intersection for the Arts</a>,&nbsp;a 501(c)(3) nonprofit organization.</p>\r\n<p><a href=\"https://donatenow.networkforgood.org/1442843\">Donate Now!</a>&nbsp;Make sure to select CODAME ART+TECH as the&nbsp;designated donation.</p>\r\n<p>&nbsp;</p>\r\n<div>&nbsp;</div>', '', '1'),
(34, 'Subscribe', 'subscribe', '', '<h2>Subscribe to our mailing list</h2>\r\n<p>Get notified about&nbsp;our next events and intitiatives!</p>\r\n<form accept-charset=\"utf-8\" action=\"http://codame.com/sendy/subscribe\" method=\"POST\">\r\n<p><label for=\"name\">Name</label><br /> <input id=\"name\" name=\"name\" type=\"text\" /> </p>\r\n<p><label for=\"email\">Email</label><br /> <input id=\"email\" name=\"email\" type=\"email\" /> </p>\r\n<div style=\"display: none;\"><label for=\"hp\">HP</label><br /> <input id=\"hp\" name=\"hp\" type=\"text\" /></div>\r\n<input name=\"list\" type=\"hidden\" value=\"763tulk9RS78oVNiyX0Au763vA\" /> <input name=\"subform\" type=\"hidden\" value=\"yes\" /> <input id=\"submit\" name=\"submit\" type=\"submit\" /></form>\r\n<h3>&nbsp;</h3>\r\n<p><iframe style=\"background-image: url(\'/admin/img/object.gif\');\" src=\"https://docs.google.com/presentation/d/1jEE4F1p1SRw6esYJ1P6Wq2t7DjKOQvsY9eCHcMvDyS8/embed?start=true&amp;loop=true&amp;delayms=5000\" width=\"600\" height=\"400\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', '', '0'),
(30, 'Feedback', 'feedback', '', '<p><iframe src=\"https://docs.google.com/forms/d/e/1FAIpQLSfmA7ZHBhn0hDk4HoSxO_f9pd4ar-M3qVJhogzKtKJtvAnTZA/viewform?embedded=true\" width=\"750\" height=\"1550\" frameborder=\"0\" marginwidth=\"0\" marginheight=\"0\">Loading...</iframe></p>', '', '1'),
(21, 'About', 'about', '', '<p><iframe src=\"https://docs.google.com/presentation/d/e/2PACX-1vTwHttiY2TI8VZLGi4rTcL-HBsT3TYqyuZUnvwRbp024gDPpwdAVmbJn6SWe4DcjuevdzsoQgaxG2Z6/embed?start=true&amp;loop=true&amp;delayms=3000\" width=\"800\" height=\"400\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>CODAME celebrates creativity through inspiring experiences with&nbsp;events, workshops, art galleries, performances, and installations. CODAME is most known for&nbsp;the annual&nbsp;ART+TECH Festival, which has been running since 2010.&nbsp;</p>\r\n<h2>HOW</h2>\r\n<article>\r\n<p>Leveraging technology for creativity requires cultivation. By valuing questions over answers, CODAME creates spaces encouraging exploration and discovery.</p>\r\n<p>Artists, entrepreneurs, innovators, makers, and leaders are welcome on our journey. Startups, corporations, non-profits, and collectives have participated in CODAME style way-finding!</p>\r\n</article>\r\n<article>CODAME:</article>\r\n<p style=\"padding-left: 30px;\"><strong>Drives&nbsp;</strong>innovation and engagement&nbsp;by embracing creativity&nbsp;&amp; exploration<br /><strong>Shares</strong> the value of art in the technology community&nbsp;<br /><strong>Demystifies</strong>&nbsp;and makes technology accessible to artists</p>\r\n<article>\r\n<h2>ORIGIN</h2>\r\n</article>\r\n<article></article>\r\n<article>The network of creative coders, designers, and artists our founders knew from around the world sparked CODAME to celebrate art and technology passionately. The CODAME brand of immersive, engaging, and out-of-the-ordinary experiences was coined at the inaugural CODAME ART+TECH Festival in 2010 on a foggy rooftop in downtown San Francisco.&nbsp;</article>\r\n<p>Since then, we have built...&nbsp;</p>\r\n<p style=\"padding-left: 30px;\"><strong>100+</strong> <a href=\"/events\">events</a>&nbsp;and <a href=\"/workshops\">workshops</a>, both public and private<br /><strong>200+</strong> <a href=\"/projects\">projects</a>,&nbsp;performances, and installations around the&nbsp;world<br /><strong>300+</strong> <a href=\"/artists\">artists</a>&nbsp;featured at our events<br /><strong>100,000+</strong> community of&nbsp;artists and technologists</p>\r\n<article>\r\n<h2>SUPPORT&nbsp;</h2>\r\n<p>Your support is what keeps us going!</p>\r\n<p>CODAME is a Gray Area Foundation for the Arts member,&nbsp;a 501(c)(3) non-profit organization supporting art and technology for social good in&nbsp;San Francisco, California.&nbsp;</p>\r\n<p>All proceeds will be split with the participating artists.&nbsp;<a href=\"https://www.flipcause.com/secure/cause_pdetails/NjU0OA==\">Donations</a>&nbsp;are always welcome. Thank you for your <a href=\"/pages/support-art-tech\">support</a> for ART &hearts; TECH</p>\r\n<p><a href=\"/pages/support-art-tech\">Contact Us</a>&nbsp;if you are interested in making an in-kind donation or buying art on <a href=\"/admin/shop.codame.com\">shop.codame.com</a></p>\r\n</article>\r\n<h2>TEAM</h2>\r\n<p><a href=\"/pages/join-us\">Join us</a>&nbsp;to continue the visionary celebration, running since 2010!</p>\r\n<p>We are a&nbsp;bunch of peeps with a thing for Art and Technology:</p>\r\n<article></article>\r\n<article></article>\r\n<article></article>\r\n<article></article>\r\n<article></article>\r\n<article></article>\r\n<article></article>\r\n<article style=\"padding-left: 30px;\">Bruno Fonzi @<a href=\"http://twitter.com/BrunoFonzi\" target=\"_blank\">BrunoFonzi</a>&nbsp;(Co-Founder)<br />Jordan Gray @<a href=\"http://twitter.com/Starpause\" target=\"_blank\">staRpauSe</a>&nbsp;(Co-Founder)<br />Hufo @<a href=\"https://twitter.com/hufo_me\">hufo_me</a>&nbsp;(Media Producer)</article>\r\n<article style=\"padding-left: 30px;\">Oskar (Gallery Maker)</article>\r\n<article style=\"padding-left: 30px;\">Sofia&nbsp;@<a href=\"https://twitter.com/pikioart\">pikioart</a>&nbsp;(Hack Designer)</article>\r\n<article style=\"padding-left: 30px;\">Yiyue Chen @<a href=\"https://twitter.com/IothaP\" target=\"_blank\">iothaP</a> (Community Engagement)</article>\r\n<article style=\"padding-left: 30px;\">Vicente Montelongo @<a href=\"http://twitter.com/mexist\" target=\"_blank\">Mexist</a>&nbsp;(Artistic Director)</article>\r\n<article style=\"padding-left: 30px;\">Eyvonne Hu (Code Ninja)</article>\r\n<article style=\"padding-left: 30px;\"></article>\r\n<article></article>\r\n<p>And infinite thanks to our friends and allies through the years: Enki-Ea Isaac, Alissia&nbsp;Christine, Nataliia Frank, Luna&nbsp;Yu, Quinn&nbsp;Keck, Lisa Kolb, Irene Kaoru, Amy Lee, Laura&nbsp;Lee, Vanessa Chang, Kevin Koechley,&nbsp;Donald Hanson,&nbsp;Kim Pham, Cindy Clark, Olia Pospelova,&nbsp;Josh Santangelo,&nbsp;Kimberly Mackoy, Alfred Dominquez, Irene&nbsp;Grossrubatscher,&nbsp;Dat Phan, Justin Kinder, Jaquie Bacich-Paratt, Valerie Alloix, Stefano Corazza, Kiri Rong, Vicky Chen, Karen Hsu,&nbsp;Nancy Garcia,&nbsp;Julie Goldsmith,&nbsp;Allen Ellison,&nbsp;Drew Clark,&nbsp;Tarwin Stroh-Spijer,&nbsp;Bernie Samson, Tiare&nbsp;Ribeaux, DC Spensley,&nbsp;Lauren Anderson,&nbsp;Michael Conover,&nbsp;Andrea Starr,&nbsp;Felipe Brahm, Hanna Regev, Jesse Fulton, Misaki C. Kido, Jonathan Wallraven, Julia&nbsp;Sun, Lauryn Porte, Kimmy Colombo... and more than 200 more amazing&nbsp;artists, technologists, and volunteers!</p>\r\n<p>&nbsp;<img src=\"https://web.archive.org/web/20150520143806im_/http://www.codame.com/wp-content/uploads/2013/10/the-CODAME-team-s.jpg\" alt=\"\" width=\"653\" height=\"495\" /></p>\r\n<h2>HOW TO&nbsp;SAY CODAME?</h2>\r\n<div>\r\n<p>CODA-ME? CO-DAME? C&Aring;-D&Eacute;&lsquo;-M&Eacute;&rsaquo;? An intentionally ambiguous collection of consonants and vowels, your way is the right way ;)</p>\r\n<p><span style=\"font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-size: 13px;\">Or c</span><span style=\"font-family: \'Helvetica Neue\', Helvetica, Arial, sans-serif; font-size: 13px;\">heck out this <a href=\"https://vimeo.com/22538718\">video</a> for some options ... <a href=\"https://vimeo.com/22538718\">https://vimeo.com/22538718</a></span></p>\r\n<iframe src=\"https://player.vimeo.com/video/22538718\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<h2>CODE OF CONDUCT&nbsp;</h2>\r\n</div>\r\n<div>CODAME&nbsp;<a href=\"/pages/code-of-conduct\">Code of Conduct</a> for all participants and attendees.</div>\r\n<div>&nbsp;</div>\r\n<p><iframe style=\"border: 1px solid #EEE; background: white;\" src=\"https://codame.substack.com/embed\" width=\"480\" height=\"320\" frameborder=\"0\" scrolling=\"no\"></iframe></p>', '', '0'),
(4, 'Media Kit', 'media-kit', '', '<h2>Logos</h2>\r\n<p>Download the&nbsp;<a href=\"/wp-content/uploads/2014/04/CODAME_LOGO_FULL_RESOLUTION.zip\" target=\"_blank\">full resolution logo assets (1.5mb)</a>. Includes full color version, black on transparent version &amp; white on transparent version as maximum quality PNG.</p>\r\n<p>Web optimized (full resolution with ImageAlpha/ImageOptim applied) PNG below.</p>\r\n<p><img src=\"/uploaded_images/codame-logo-alpha.png\" alt=\"\" /></p>\r\n<p>Full Color:</p>\r\n<p><a href=\"/wp-content/uploads/2014/04/Codame_Badge_Logo_08_web.png\"><img src=\"/wp-content/uploads/2014/04/Codame_Badge_Logo_08_web.png\" alt=\"Codame_Badge_Logo_08_web\" width=\"1442\" height=\"1049\" /></a></p>\r\n<p>Black only:</p>\r\n<p><a href=\"/wp-content/uploads/2014/04/Codame_Badge_Logo_08_black_web.png\"><img src=\"/wp-content/uploads/2014/04/Codame_Badge_Logo_08_black_web.png\" alt=\"Codame_Badge_Logo_08_black_web\" width=\"960\" height=\"815\" /></a></p>\r\n<p>White only:</p>\r\n<div><a href=\"/wp-content/uploads/2014/04/Codame_Badge_Logo_08_white_web.png\"><img src=\"/wp-content/uploads/2014/04/Codame_Badge_Logo_08_white_web.png\" alt=\"Codame_Badge_Logo_08_white_web\" width=\"960\" height=\"815\" /></a></div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<h2>Images</h2>\r\n<p><a href=\"https://photos.app.goo.gl/LS7aRJNC7fR3G7aw8\">https://photos.app.goo.gl/LS7aRJNC7fR3G7aw8</a></p>\r\n<p>(request access to specific event albums from events <em>&gt;at&gt;</em> codame <em>&lt;dot&lt;</em> com)</p>\r\n<p>&nbsp;</p>\r\n<h2 id=\"sizzles\">Sizzle Videos</h2>\r\n<p><strong>Events</strong></p>\r\n<p><a href=\"https://youtu.be/8JkL0wLwcLk\">SPACE 2019 Highlights</a></p>\r\n<p><a href=\"https://youtu.be/49PzKAvmxSQ\">SPACE 2019&nbsp;Trailer</a></p>\r\n<p><a href=\"https://youtu.be/Uu5_8upcW4s\">Artobots 2018 Trailer</a></p>\r\n<p><a class=\"in-cell-link\" href=\"https://vimeo.com/227759957\" target=\"_blank\">3D Web Fest 2017 Highlights</a></p>\r\n<p><a class=\"in-cell-link\" href=\"https://youtu.be/RIe2doFTctU\" target=\"_blank\">3D Web Fest 2016 Highlights</a></p>\r\n<p><a class=\"in-cell-link\" href=\"https://vimeo.com/207884332\" target=\"_blank\">MOVEMENT Festival Highlights</a></p>\r\n<p><a class=\"in-cell-link\" style=\"white-space: nowrap;\" href=\"https://vimeo.com/141838764\" target=\"_blank\">MOVEMENT Festival Teaser</a></p>\r\n<p><a class=\"in-cell-link\" href=\"https://www.youtube.com/watch?v=W0Xo1xVxpEQ\" target=\"_blank\">5enses Festival</a></p>\r\n<p><a class=\"in-cell-link\" href=\"https://vimeo.com/128102590\" target=\"_blank\">Adopt An Artist at Salesforce</a></p>\r\n<p><a class=\"in-cell-link\" href=\"https://vimeo.com/110418837\" target=\"_blank\">Ephemeral Vessels</a></p>\r\n<p><a class=\"in-cell-link\" href=\"https://vimeo.com/78994787\" target=\"_blank\">Rackspace Grand Opening</a></p>\r\n<p><strong>Projects</strong></p>\r\n<p><a class=\"in-cell-link\" style=\"white-space: nowrap;\" href=\"https://vimeo.com/205976218\" target=\"_blank\">Shybot</a></p>\r\n<p><a class=\"in-cell-link\" style=\"white-space: nowrap;\" href=\"https://vimeo.com/228847579\" target=\"_blank\">HoloShatter</a></p>\r\n<p><strong>Fun</strong></p>\r\n<p><a class=\"in-cell-link\" style=\"white-space: nowrap;\" href=\"https://vimeo.com/23732051\" target=\"_blank\">Riki Rocket</a></p>\r\n<p><a class=\"in-cell-link\" style=\"white-space: nowrap;\" href=\"https://vimeo.com/22538718\" target=\"_blank\">How To Say ;)</a></p>\r\n</div>', '', '1'),
(5, 'CODAME 2011 Impressions', 'codame-2011-impressions', 'http://codame.dreamhosters.com/uploaded_images/codame-2011-impressions.jpg', '\r\n						<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/9ad7a7d59d9079e5dbd1997a7f4c24e53.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/e73879ddd8d919a46a60ba59ac47b26e3.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/da89c55ca76e2a0e6fda438748dd851e3.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/43f6d79000e02a74159faa0b76fa15726.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/10ec9abf678b00c9d9e89b8566b406943.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/ecdcdbe58e267e1747a51028dd886d9a3.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/673b7c5a53c0374fee559673fbe929913.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/9de87cf1c2639d880be933a6632c4bc83.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/cbecf68868cc6cbb7a95f3695094209b3.jpg\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/43f6d79000e02a74159faa0b76fa15727.jpg\"></figure>\r\n</div>\r\n<p>CODAME 2011 <span>Impressions from </span><a href=\"http://www.flickr.com/photos/photonburst/with/5715176787/\" target=\"_blank\">photonburst</a></p>\r\n											', 'http://www.codame.com/post/portfolio/2011/', '1'),
(6, 'CODAME 2010 Impressions', 'codame-2010-impressions', 'http://codame.dreamhosters.com/uploaded_images/codame-2010-impressions.jpg', '<div class=\"figure\">\r\n<figure>&nbsp;</figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/02a10e12ca32b6533a16434bc304c1022.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/ab25b4eca3ea0570aa45d829585409562.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/e54462bc42b47b86fea2713254518ad12.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/0b0c9b1e0585fd2af30c2bf23e379d9a2.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/207d3a0f112243f56fa024be3a9dcd032.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/f46c57fe8da56823fe25ce7c658219682.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img src=\"/wp-content/uploads/2013/11/73ac30185b5f69637e4628aabfd05d002.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img class=\" alignnone\" src=\"/wp-content/uploads/2013/11/79b35fcd7d69997736b3c934a32742172.jpg\" alt=\"\" /></figure>\r\n</div>\r\n<p><img class=\" alignnone\" src=\"/wp-content/uploads/2013/11/d6e0d7a44965c3c56a52c797b5fc6ac92.jpg\" alt=\"\" />CODAME 2010 Impressions by&nbsp;<a href=\"http://www.flickr.com/photos/photonburst/with/4903271807/\" target=\"_blank\">photonburst</a></p>', 'http://www.codame.com/post/portfolio/2010/', '1'),
(7, 'CODAME ART+TECH Awards 2012', 'codame-art-tech-awards-2012', '', '<p><iframe src=\"http://player.vimeo.com/video/58048700\" width=\"400\" height=\"300\" frameborder=\"0\"></iframe></p>\r\n<div>\r\n<div>\r\n<p>More information on<br /><a href=\"http://codame.com/tagged/2012-awards\" target=\"_blank\" rel=\"nofollow\">codame.com/tagged/2012-awards</a></p>\r\n<p>And the winners are&hellip;</p>\r\n<p>Best Deep Dimension Award</p>\r\n<p>The winner of the deep dimension award goes to designer, and DJ&nbsp;<a href=\"http://www.circuit73.com/\" target=\"_blank\">Todd Kurnat</a>(aka circuit 73) for his 3D grid that really brought out the magic of chromadepth. &nbsp;A special thanks goes out to&nbsp;<a href=\"http://www.adobe.com/in/products/creativesuite/design-web-premium.html\" target=\"_blank\">Adobe Systems</a>&nbsp;for providing Todd with a copy of Creative Suite 6.</p>\r\n<p>Best Far-Out Feature Spirit Award</p>\r\n<p>Our award to the most &ldquo;far-out&rdquo; 3D drawing goes to illustrator&nbsp;<a href=\"http://www.bencollison.com/\" target=\"_blank\">Ben Collision</a>. &nbsp;His 3D lion creation was great to look at with normal light and eyes and became alive once you strapped on the 3D glasses. &nbsp;For Ben&rsquo;s work, he was awarded a new Android Tablet compliments of&nbsp;<a href=\"http://lanica.co/\" target=\"_blank\">Lanica, Inc</a>.</p>\r\n<p>Best ART+TECH Costume Award</p>\r\n<p>Lara is the owner of&nbsp;<a href=\"http://chartreusecircle.com/\" target=\"_blank\">Chartreuse Circle</a>, a company that specializes in draper/pattern drafting, design, and costume fabrication. Chartreuse Circle has developed and designed costumes for NASA, Victoria&rsquo;s Secret and a variety of clients from brides to world renown performers and regularly incorporates electronic materials in her designs.</p>\r\n<p><a href=\"http://chartreusecircle.com/Ruffletron\" target=\"_blank\">Ruffletron</a>&nbsp;is an example of her work that all you CODAME fans might dig.</p>\r\n<p>Lara was the proud winner of an Android tablet donated by our friends and CODAME supporters&nbsp;<a href=\"http://lanica.co/\" target=\"_blank\">Lanica, Inc.</a>&nbsp;the developers of Platino&trade;&nbsp;game engine for iOS and Android devices.</p>\r\n<p>Best Experience Award<br />As the recipient of the Best Experience award we have Mario from Human Creatives with his tower defense iOS game,&nbsp;<a href=\"https://itunes.apple.com/us/app/biotic-blitz/id568278576?mt=8\" target=\"_blank\">Biotic Blitz</a>. Mario will be receiving an Android tablet from&nbsp;<a href=\"http://lanica.co/\" target=\"_blank\">Lanica</a>.<br /><img src=\"http://codame.com/wp-content/uploads/2013/11/5a04b9e29e90e5f302cd011ec6eeeff15.png\" alt=\"image\" /></p>\r\n<p>Most Challenging Award<br />The winner of the Most Challenging award was&nbsp;<a href=\"http://ncannasse.fr/file/ld24/ld24.html\" target=\"_blank\">Evoland</a>, an incredibly challenging (hence the award) and creative take on a retro style adventure game (browser based) originally created as part of a 48 hour Ludum Dare event created by&nbsp;<a href=\"http://twitter.com/ncannasse\" target=\"_blank\">Nicolas Cannasse</a>&nbsp;of&nbsp;<a href=\"http://shirogames.com/\" target=\"_blank\">Shiro Games</a>. They will receive a 32GB PlayBook with a case, and a Bluetooth audio gateway for music courtesy of&nbsp;<a href=\"http://rim.com/\" target=\"_blank\">RIM</a>.<br /><img src=\"https://pbs.twimg.com/media/A8ZfBVZCcAAPIMj.png:large\" alt=\"\" width=\"851\" height=\"480\" /></p>\r\n<p>Most Creative Award<br />Our Most Creative award goes to&nbsp;<a href=\"http://bits.codame.com/\" target=\"_blank\">Bits</a>, which was created especially for CODAME by&nbsp;<a href=\"http://www.elisasassi.com/\" target=\"_blank\">Elisa Sassi</a>&nbsp;and Perry Chan. The game is colorful, cute and incredibly random, a quality that in this case only served to make the game more appealing. Elisa and Perry will receive a copy of Creative Suite&reg; 6 Design &amp; Web Premium from&nbsp;<a href=\"http://www.adobe.com/in/products/creativesuite/design-web-premium.html\" target=\"_blank\">Adobe Systems Inc</a><br /><img src=\"http://puu.sh/1ogDc\" alt=\"image\" /></p>\r\n<p>Most Collaborative Award<br />The winner of the Most Collaborative award was Draw Me to You, created by Tyler Bryant. This iOS app allows users to draw with others across multiple devices and collaborate in real time and is creative not only from an artistic standpoint but also because of the multi-user angle. Tyler will receive $300 worth of&nbsp;<a href=\"http://mixamo.com/\" target=\"_blank\">Mixamo</a>&nbsp;credits.<br /><img alt=\"image\" /></p>\r\n<p>Most Immersive Award<br /><a href=\"http://www.visitproteus.com/\" target=\"_blank\">Proteus</a>&nbsp;is the recipient of the Most Immersive award due to it&rsquo;s stunning yet incredibly retro (even blocky, but it works!) design and use of audio as a primary focus throughout the game. Creators Ed and David will receive a Flare3D Studio license from&nbsp;<a href=\"http://flare3d.com/product/license\" target=\"_blank\">Flare3D</a></p>\r\n<p><img src=\"http://codame.com/wp-content/uploads/2013/11/3bc2571e23b68b43b100926c6cdf3c725.png\" alt=\"image\" width=\"960\" height=\"600\" /></p>\r\n<p>Thanks to our Gaming Jury!</p>\r\n<ul>\r\n<li><a href=\"http://www.sdtimes.com/about/AlexHandy\" target=\"_blank\">Alex Handy</a>&nbsp;&ndash; Software Development Times at&nbsp;<a href=\"http://sdtimes.com/\" target=\"_blank\">BZ Media</a></li>\r\n<li><span id=\"ctl00_content_Placeholder_authorBio_Label\"><a href=\"https://twitter.com/nais\" target=\"_blank\">Ana&iuml;s Gragueb</a>&nbsp;&ndash;&nbsp;</span>Marketing and PR Manager at&nbsp;<a href=\"http://mixamo.com/\" target=\"_blank\">Mixamo</a></li>\r\n<li><a href=\"http://blogs.unity3d.com/author/caitlyn/\" target=\"_blank\">Caitlyn Meeks Ferragallo</a>&nbsp;&ndash;&nbsp;Asset Store Manager at&nbsp;<a>Unity</a></li>\r\n<li><a href=\"http://www.carlosicaza.com/about/\" target=\"_blank\">Carlos Icaza</a>&nbsp;&ndash; CEO and co-founder of&nbsp;<a href=\"http://lanica.co/\" target=\"_blank\">Lanica</a></li>\r\n<li><a href=\"http://www.joshuagranick.com/\" target=\"_blank\">Joshua Granick</a>&nbsp;&ndash;&nbsp;&nbsp;BlackBerry Developer Evangelist at&nbsp;<a href=\"http://rim.com/\" target=\"_blank\">RIM</a></li>\r\n<li><a href=\"http://tom.krcha.com/\" target=\"_blank\">Tom Krcha</a>&nbsp;&ndash; Developer Evangelism at&nbsp;<a href=\"http://adobe.com/\" target=\"_blank\">Adobe</a></li>\r\n</ul>\r\n<p>Special thanks to&nbsp;<a href=\"http://twitter.com/peachpellen\" target=\"_blank\">Peach Pellen</a>&nbsp;for leading this awesome gaming event.</p>\r\n<p>Credits:<br />Background music: Starpause<br />Video captured by Glowbl</p>\r\n</div>\r\n</div>', '', '1'),
(8, 'CODAME ART+TECH PROGRAM 2013', 'codame-art-tech-program-2013', 'http://codame.dreamhosters.com/uploaded_images/codame-art-tech-program-2013.png', '<p>2013 has been an amazing year, now looking&nbsp;forward to 2014 for some more ART+TECH love.</p>\r\n<p>We welcome&nbsp;<a href=\"http://codame.com/sponsors\" target=\"_blank\">sponsors</a>,&nbsp;<a href=\"http://codame.com/support\" target=\"_blank\">supporters</a>,&nbsp;<a href=\"http://codame.com/joinus\" target=\"_blank\">volunteers</a>. If you can help, any pixel or bit counts! Join our&nbsp;<a href=\"http://www.eventbrite.com/e/codame-adopt-an-artist-tickets-5482652762\" target=\"_blank\">Adopt an Artist</a>&nbsp;initiative&nbsp;<a target=\"_blank\">Contact us</a>.&nbsp;Or attend an event in person and donate by purchasing your&nbsp;<a href=\"http://codame.eventbite.com/\">ticket</a>.</p>\r\n<p>PLAY.CELEBRATE.INSPIRE.</p>\r\n<p>What&nbsp;s next&nbsp;&nbsp;(ART+TECH fun!)</p>\r\n<blockquote>\r\n<p>Check out our upcoming&nbsp;events&nbsp;<a href=\"http://codame.com/events/\">here</a></p>\r\n</blockquote>\r\n<p>Previous&nbsp;&nbsp;(that was fun!)</p>\r\n<blockquote><a href=\"http://newbohemianye.com\" target=\"_blank\">Dec 31st</a>: CODAME&nbsp;GIF BOOTH&nbsp;for the&nbsp;<a href=\"http://newbohemianye.com\" target=\"_blank\">New Bohemia NYE</a>&nbsp;@ The Armory<br /><a href=\"http://codame.com/post/67544184372/join-codame-to-play-celebrate-and-inspire-the\">Nov. 23rd</a>:&nbsp;Dissident Futures Art and Ideas Festival&nbsp;@&nbsp;<a href=\"http://dissidentfestival.tumblr.com/\">YBCA</a><br /><a href=\"http://codame.com/post/democratizing-the-arts-has-been-a-long-standing/\">Nov 19th</a>: CODAME&nbsp;DEBRIEF&nbsp;@&nbsp;<a href=\"http://bayarea.impacthub.net/event/artstech-meetup\" target=\"_blank\">Impact Hub</a>&nbsp;Berkeley&nbsp;<a href=\"http://bayarea.impacthub.net/event/artstech-meetup\" target=\"_blank\">ArtsTech</a>&nbsp;meetup<br /><a href=\"http://codame.com/post/democratizing-the-arts-has-been-a-long-standing/\">Nov 5th</a>: &nbsp;CODAME&nbsp;ART+TECH&nbsp;@&nbsp;<a href=\"http://Rackspace.com\" target=\"_blank\">Rackspace</a>&nbsp;Geekdom SF&nbsp;s Grand Opening<br /><a title=\"CODAME 2013 ART+TECH Festival\" href=\"http://codame.com/post/5enses/\" target=\"_blank\">Nov 1-2</a>:&nbsp;CODAME&nbsp;2013&nbsp;ART+TECH Festival&nbsp;&nbsp;&nbsp;5ENSES&nbsp;@&nbsp;<a href=\"http://geekdom.com\" target=\"_blank\">GeekdomSF</a><br /><a href=\"http://codame.com/post/60340678008/celebrate-data-visualization-art-tech-with-codame\">Oct 3nd</a>:&nbsp;CODAME&nbsp;DATAVIZ&nbsp;@&nbsp;<a href=\"http://geekdom.com\" target=\"_blank\">GeekdomSF</a>&nbsp;with&nbsp;<a href=\"http://chartio.com/\" target=\"_blank\">Chartio</a><br /><a href=\"http://codame.com/post/57762447664/codame-on-the-playa-burning-man-2013\">Aug 26th</a>: Gone to The Playa @ Burning Man<a href=\"http://codame.com/post/codame-games/\" target=\"_blank\">Aug 21th</a>: CODAME&nbsp;GAMES&nbsp;@&nbsp;<a href=\"http://adobe.com\" target=\"_blank\">Adobe</a><br /><a href=\"http://codame.com/post/experience-24hrs-of-codame-def-con-we-are-super/\" target=\"_blank\">Aug 1st</a>: CODAME&nbsp;ART+HACK&nbsp;@&nbsp;<a href=\"https://www.defcon.org/\" target=\"_blank\">DEFCON</a><br /><a href=\"http://codame.com/post/55072134917/join-codame-art-tech-in-honoring-the-art-by-code\" target=\"_blank\">July 14th</a>: CODAME&nbsp;ART by CODE&nbsp;@&nbsp;<a href=\"http://artbycode.eventbrite.com/\" target=\"_blank\">Roll Up Gallery</a><br /><a href=\"http://codame.com/post/anouk/\" target=\"_blank\">June 29th</a>:&nbsp;FASHIONTECH&nbsp;Masterclass w/ Anouk Wipprecht @&nbsp;<a href=\"http://chartio.com/\" target=\"_blank\">Chartio</a><br /><a href=\"http://codame.com/post/fashion/\" target=\"_blank\">June 26th</a>: CODAME&nbsp;FASHION+TECH&nbsp;@&nbsp;<a href=\"http://publicsf.com/\" target=\"_blank\">Public Works</a><br /><a href=\"http://codame.com/post/codame-cold-void-kk-los-angeles/\" target=\"_blank\">June 15th</a>: CODAME&nbsp;COLD VOID&nbsp;@&nbsp;<a title=\"KK L.A.\" href=\"http://www.kklosangeles.com/gallery\" target=\"_blank\">KK Los Angeles</a><br /><a href=\"http://codame.com/post/subzero2013/\" target=\"_blank\">June 7th</a>: CODAME&nbsp;PLAY&nbsp;@&nbsp;<a href=\"http://www.subzerofestival.com/\" target=\"_blank\">SubZERO</a><br /><a href=\"http://codame.com/post/codame-3d-printing-event/\" target=\"_blank\">May 1st</a>: CODAME&nbsp;3D PRINTING&nbsp;@&nbsp;<a href=\"http://adobe.com\" target=\"_blank\">Adobe</a><br /><a href=\"http://codame.com/post/38483946399/codame-the-future-imagined\" target=\"_blank\">Jan 10th</a>: CODAME&nbsp;DESIGN: The Future Imagined @&nbsp;<a href=\"http://theperformanceartinstitute.org/\" target=\"_blank\">PAI</a></blockquote>\r\n<blockquote>\r\n<div>&nbsp;</div>\r\n<div>&nbsp;</div>\r\n</blockquote>\r\n<blockquote>\r\n<p>&nbsp;</p>\r\n</blockquote>', '', '1'),
(9, 'Video Loops from CODAME Featured Artists', 'video-loops-from-codame-featured-artists', '', '<p><iframe src=\"http://player.vimeo.com/video/78140647\" width=\"400\" height=\"225\" frameborder=\"0\"></iframe></p>\r\n<p>/// VIDEO LOOPS</p>\r\n<p><a href=\"/post/64190650122/codame-featured-artist-ken-murphy-musician\" target=\"_blank\">Ken Murphy</a>,&nbsp;<a href=\"/post/65418970423/codame-featured-artist-s-timefly-timefly\" target=\"_blank\">TIMEFLY</a>,&nbsp;&nbsp;<a href=\"/post/32198383731/codame-featured-artist-david-oreilly-oreillys\" target=\"_blank\">David O&rsquo;reilly</a>,&nbsp; Andrew Benson,&nbsp;&nbsp;<a href=\"/post/codame-featured-artist-laturbo-avedon-laturbo/\" target=\"_blank\">Laturbo Avedon</a>,&nbsp;&nbsp;<a href=\"/post/56072636434/codame-featured-artist-from\" target=\"_blank\">Ben Mikrosopht</a>,&nbsp;&nbsp;<a href=\"/post/33126232247/cyriak-codame-featured-artist-codame-is-going\" target=\"_blank\">Cyriak</a>,&nbsp;&nbsp;<a href=\"/post/64649613988/codame-featured-artist-paul-clipson-paul-is-a\" target=\"_blank\">Paul Clipson</a>,&nbsp;&nbsp;<a href=\"/post/65415981829/codame-featured-artist-maria-renetta-rsitoy\" target=\"_blank\">Renetta Sitoy</a>&nbsp;Curated by&nbsp;<a href=\"/post/33137081697/ani-codame-featured-musician-ani-is-a-monster\" target=\"_blank\">Amy Lee</a>.</p>\r\n<p>See for yourself at the 5ENSES experience at the&nbsp;<a href=\"/festival\" target=\"_blank\">CODAME 2013 ART+TECH Festival (Nov 1-2)</a>.</p>', 'http://www.codame.com/post/portfolio/video-loopsken-murphytimeflydavid-oreilly-andrew-bensonlaturbo-', '1'),
(10, 'CODAME ART+TECH Festival (2013)', 'codame-art-tech-festival-2013-', 'http://codame.dreamhosters.com/uploaded_images/codame-art-tech-festival-2013-.jpg', '\r\n						<p>This year’s <strong>ART+TECH Festival</strong> was a curated experience into auditory, tactile, optical, taste and yes, olfactory installations called <strong>5ENSES</strong>.</p>\r\n<p>An exclusive, immersive  guided journey that subverted your perception and re-awaken your senses <a href=\"http://twitter.com/GeekdomSF\" target=\"_blank\">@GeekdomSF</a> startup co-working space from Rackspace San Francisco.</p>\r\n<p><iframe src=\"//www.youtube.com/embed/W0Xo1xVxpEQ?rel=0\" width=\"853\" height=\"480\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe><br>\r\nThanks to <a href=\"http://845a.co/codamearttechfestivalinfo2013\" target=\"_blank\">845a.co</a> for the great video footage!</p>\r\n<p>Check out the 2013 ART+TECH Festival program and participating artists <a href=\"http://codame.com/post/codame-2013-art-tech-festival/\"> here</a></p>\r\n											', 'http://www.codame.com/post/portfolio/2013-art-tech-festival/', '1'),
(11, '2013 Retrospective', '2013-retrospective', 'http://codame.dreamhosters.com/uploaded_images/2013-retrospective.jpeg', '<p>http://storify.com/BrunoFonzi/art-tech-2013-at-codame</p>', 'http://www.codame.com/post/portfolio/a-codame-arttech-2013-retrospective/', '1'),
(12, 'CODAME ART+TECH FILM FEST', 'codame-art-tech-film-fest', 'http://codame.dreamhosters.com/uploaded_images/call-for-entries-codame-art-tech-film-fest.jpg', '<p style=\"text-align: left;\"><strong>Call for films and performance+film hybrids for theï¿½CODAME ART+TECH FILM FEST</strong>.</p>\r\n<p>We are seeking animated, experimental, collaborative, and/or interactive films as well as performance+film hybrids.</p>\r\n<p>For the purposes of this event, a film is defined as any moving image that can be digitally projected in a theatre onto a screen in front of an audience. Any film may be submitted for consideration. However, preference will be given to animated, experimental, collaborative, and/or interactive films.</p>\r\n<p>Curated by <strong>Virtual Boy</strong>: <a href=\"/artists/jonathan-wallraven\" target=\"_blank\">Jonathan Tyler Skeleton Wallraven </a><a href=\"http://jtsw.tumblr.com/\" target=\"_blank\"><br /> </a></p>\r\n<p>Performance+film hybrids are strongly encouraged and will be given the highest preference.</p>\r\n<p>Requirements:</p>\r\n<ul>\r\n<li>SUBMISSION MUST BE A FILM AS DEFINED ABOVE</li>\r\n<li>FILM RUNNING TIME MUST BE &le; 33 MINUTES</li>\r\n</ul>\r\n<p>How to submit:</p>\r\n<ol>\r\n<li>Email your full name, contact information, and a brief description (200 words or less) of your project to <a href=\"mailto:FILMFEST@CODAME.COM\">FILMFEST@CODAME.COM</a>.</li>\r\n<li>Include instructions for viewing the submitted film, either through a video-sharing site (e.g., Vimeo) or a file hosting service (e.g., Dropbox).</li>\r\n</ol>\r\n<p>Important Dates:</p>\r\n<ul>\r\n<li>DEADLINE TO SUBMIT: On or before <strong>6/1/2014</strong></li>\r\n<li>CHOSEN PARTICIPANTS NOTIFIED: <strong>6/15/2014</strong></li>\r\n<li>EVENT: <strong>TBA</strong><a href=\"http://codame.com/post/playground/\"><br /> </a></li>\r\n</ul>', '', '1');
