INSERT INTO `projects` (`id`, `name`, `slug`, `description`, `pic`, `twitter`, `website`, `artists_array`, `old_url`, `hidden`, `edited`, `shop_url`, `partners_array`, `sponsors_array`, `is_nft`) VALUES
(1, 'ModBod 3D', 'modbod-3d', '<p style=\"text-align: center;\"><strong>#ModBod3D</strong></p>\r\n<p style=\"text-align: center;\"><strong>Full body scans for stylized identities&nbsp;<br /><a href=\"https://sketchfab.com/codame/collections\" target=\"_blank\">Over 700 assets remixable under CC BY 4.0</a><br /></strong></p>\r\n<p dir=\"ltr\">Take your event\'s photo opportunity to the next dimension with ModBod3D, a 3D scanning booth offering a unique and memorable experience!</p>\r\n<p dir=\"ltr\">Visitors are prompted to pick up a prop or strike a fun pose from an inspiring look book. The entire scanning process takes a few minutes and gets shown on a large display to demonstrate the satisfying interactive experience and attract a crowd.</p>\r\n<p dir=\"ltr\">The scans can be emailed to the participants or get posted on social media with the event hashtag or visitors handles. The WebGL viewer works on mobile phones for instant satisfaction and can be customized with a companies logo or background image.</p>\r\n<p dir=\"ltr\">The 3d models are a standard format that makes it possible to <a href=\"https://squareup.com/market/codame/modbod-d\">3D print yourself</a> or replicate your friends. An artist can be commissioned to further stylize the models, live at the event or as a follow up engagement. Take your selfie game up a notch with a virtual sculpture, animated GIF, or interactive web artwork!</p>\r\n<p dir=\"ltr\">From house parties to conferences, no crowd is too big or small for capture fun. If you can hold a pose for a few minutes, ModBod3D will capture it forever!&nbsp;</p>\r\n<p><iframe src=\"https://sketchfab.com/models/304a8900526b4995919672cc62f2b5d2/embed\" width=\"640\" height=\"480\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>See more&nbsp;<a href=\"https://sketchfab.com/codame/collections\">ModBod&nbsp;3D scans</a> in the CODAME ART+TECH collection!</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<div id=\"attachment_5194\"><a href=\"/wp-content/uploads/2014/08/20140825_095852-e1409097827524.jpg\"><img title=\"ModBod 3D Scans Printed Example\" src=\"/wp-content/uploads/2014/08/20140825_095852-168x300.jpg\" alt=\"ModBod3D Scans Printed Example\" width=\"302\" height=\"539\" /></a>&nbsp;&nbsp;<a href=\"/wp-content/uploads/2014/08/20140825_095852-e1409097827524.jpg\"><img src=\"/wp-content/uploads/2014/08/20140825_100100-168x300.jpg\" alt=\"ModBod3D Scans Printed Example\" width=\"303\" height=\"539\" /></a>&nbsp;</div>\r\n<div id=\"attachment_6325\"><a href=\"/wp-content/uploads/2015/03/base-cropped.jpg\"><img src=\"/wp-content/uploads/2015/03/base-cropped-300x188.jpg\" alt=\"ModBod3D Custom Branded Bases\" width=\"787\" height=\"492\" /></a>\r\n<p>Example 3d prints, customize the base!</p>\r\n<p>&nbsp;</p>\r\n<p><iframe title=\"vimeo-player\" src=\"https://player.vimeo.com/video/112596577\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\nScanning process video.</div>\r\n<div>&nbsp;</div>\r\n<div>\r\n<p dir=\"ltr\">Optionally, scans can be included in the public CODAME <a href=\"https://sketchfab.com/codame/collections\" target=\"_blank\">SketchFab Gallery</a>, where we have captured more than 500 model bodies.&nbsp;The 3d assets are downloadable under a <a href=\"http://creativecommons.org/licenses/by/3.0/\" target=\"_blank\">Creative Commons</a> license, so anything is possible.&nbsp;Some of the artists who have remixed the scans and used them in their projects include: <a href=\"/artists/mark-klink\">Mark Klink</a>, Boned Dancers, <a href=\"/projects/holoshatter\">HoloShatter</a>, <a href=\"/artists/jeremy-sachs\">Rezmason</a> and <a href=\"/artists/ami-wang\">Amiwang</a>.</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\"><img src=\"/uploaded_images/rezmod-modbod1.gif\" alt=\"\" width=\"700\" height=\"581\" />&nbsp;</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">&nbsp;<a href=\"/artists/jeremy-sachs\">Rezmason</a></p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">&nbsp;</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\"><img src=\"/uploaded_images/mark-klink-modbod.jpg\" alt=\"\" /></p>\r\n<p dir=\"ltr\" style=\"text-align: center;\"><a style=\"text-align: start;\" href=\"/artists/mark-klink\">Mark Klink</a></p>\r\n<p dir=\"ltr\" style=\"text-align: center;\">&nbsp;</p>\r\n<p dir=\"ltr\" style=\"text-align: center;\"><img src=\"/uploaded_images/ami-wang-modbod.jpg\" alt=\"\" /></p>\r\n</div>\r\n<div style=\"text-align: center;\"><a href=\"/artists/ami-wang\">Amiwang</a>&nbsp;</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\"><img src=\"/uploaded_images/holoshatter2.gif\" alt=\"\" width=\"766\" height=\"432\" /></div>\r\n<div style=\"text-align: center;\">&nbsp;</div>\r\n<div style=\"text-align: center;\"><span style=\"text-align: start;\">&nbsp;</span><a style=\"text-align: start;\" href=\"/projects/holoshatter\">HoloShatter</a>&nbsp;</div>\r\n<div style=\"text-align: center;\">&nbsp;</div>', 'http://codame.dreamhosters.com/uploaded_images/modbod3d.gif', 'https://twitter.com/search?q=%23modbod3d&src=typed_query', '', 'jordan-gray,donald-hanson,justin-kinder,bruno-fonzi,dat-phan,mark-klink,jeremy-sachs,ami-wang', '', '0', '1621963306', '', 'itseez3d,sketchfab', '', 'project'),
(59, 'Music Performance', 'music-performance', '<p>Set the right mood for your event with unique music from CODAME Featured Artists!&nbsp;</p>\r\n<p>Genres range from sophisticated avant garde to analytically palitable pop music.&nbsp;</p>\r\n<p>Performances range from environmental DJ vibes to riveting stage shows.&nbsp;</p>\r\n<p><a href=\"/pages/support-art-tech\">Let us know your goals</a> and we handle the rest! Or explore a selection of artists we\'ve featured at past events on the right/below.</p>\r\n<p><em>Photo by <a href=\"http://www.russlevi.com/\" target=\"_blank\">Russ Levi</a>.</em>&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/music-performance.jpg', '', '', 'jordan-gray,jefferson-shulgin,dj-dials,ani,manics,humanimal,odbol,alexandernaut,benito,bill-hsu-ollie-bown-raven,ccrma,c-rex,cdcm,crashfaster,doctor-popular,donald-hanson,enc,elia-vargas,exit-only,foxxy-newport,real-dj-heroes,f-kir-dream-shovel,harbour,ideomux,kool-skull,timeheater,moldover,keisuke-shingu-aka-vj-kska,lenny-kiser,nonagon,nullsleep,rhinostrich,rich-ddt,thisissami,sebastien-deux,spectrum-electric,tadashi,tim-thompson,total-unicorn,william-s-braintree,amy-warehouse,extent-of-the-jam,theuriah,x612,crystal-glass', '', '0', '1683701201', '', '', '', 'project'),
(57, 'Illy', 'illy', '<p><span class=\"s1\"><em>Illy is a Primitive Intelligence</em> is a semi-intelligent system powered by Web Audio API and WebGL. </span></p>\r\n<p>It understands what it is spoken to in a primitive way and responds to us in a primitive, emotional and simple way both sonically and visually. As opposed to the cutting edge AIs and interfaces like Siri, Alexa, Cortana, OK Google, <em>Illy</em> does not understand natural language, defined commands or even language at all.</p>\r\n<p>It does not respond using fine-tuned intonations to deliver the information gathered from the cloud, it is not integrated with any services. It does not show maps, or pictures about the topic. Instead, as an antithesis, it only tries to understand the sonic properties of the spoken language like the attack, loudness, roughness and pitch. And responds sonically, in a non-language, musical, psychoacoustical way: without the symbolic sounds that we call language but with tonal sounds, timbre, frequency, consonance and rhythm.</p>\r\n<p>Visually, it shapes the visuals focusing on size, speed and color determined by its understanding and creating an abstract visual. Ignoring the symbolic data, like an infant, Primitive Intelligence tries to understand the emotion in the human voice - free from symbols of the language - and responds you with your emotions like sonic mirror to the soul. The interactive experience brings questions about human sound and human-machine interface that we sometimes ignore in this age of information.</p>\r\n<p>Created with HTML, javascript, Web Audio API, Three.js and WebGL.</p>', 'http://codame.dreamhosters.com/uploaded_images/illy.gif', '', '', 'yagiz-mungan', '', '0', '1526572009', NULL, NULL, NULL, NULL),
(2, 'gifSlap', 'gifslap', '<p>gifSlap is VJ software for people who love GIFs.</p>\r\n<p>A great tool for creating strange and colorful patterns that loop and shimmer with the playback of GIFs. It was designed as a live visuals program to enhance electronic music shows, but it can also be used to create compelling compositions and net art.</p>\r\n<p><iframe style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"https://www.youtube.com/embed/GqUjP1OfUX4?rel=0\" width=\"300\" height=\"150\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>gifSlap has been used at several CODAME events as an interactive installation. There are a variety of control options, from any MIDI controller, USB gamepad, or other MIDI-emitting program to the basic keyboard and mouse setup. We&rsquo;ve used it to feature GIF artists at the GIF Happy Hours / CODAME ART+TECH Rendezvous.</p>\r\n<p>FAQ</p>\r\n<ul>\r\n<li>\r\n<p>Where do the GIFs come from?&nbsp;They come from you! When the program starts you&rsquo;re asked for the location of a folder of GIFs.</p>\r\n</li>\r\n<li>\r\n<p>What are the controls?&nbsp;There are hundreds of options to control! For instance the size, shape, rotation, opacity, movement speed, playback order, arrangement, foregrounds, midgrounds, backgrounds and other simultaneous options. The full list will be published with the documentation at<a href=\"http://gifslap.com/\">www.gifslap.com</a>.</p>\r\n</li>\r\n<li>\r\n<p>Where do I download the program?&nbsp;The software is sold at&nbsp;<a href=\"http://gifslap.com/\">www.gifslap.com</a>.</p>\r\n</li>\r\n<li>\r\n<p>Who made this?&nbsp;gifSlap is designed and developed by&nbsp;<a href=\"http://vcovault.com/\">VCO_Vault</a>, aka&nbsp;<a href=\"http://everythingihaveeverdone.com/\">Donald Hanson</a>.</p>\r\n</li>\r\n<li>\r\n<p>Can we get gifSlap at our event?&nbsp;Yes! gifSlap makes a great installation piece. With very versatile controls, the setup can be as complex or simple as needed, and always very fun! Contact&nbsp;<a href=\"mailto:adopt@codame.com\">adopt@codame.com</a></p>\r\n</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p><a href=\"/wp-content/uploads/2014/05/Screen-Shot-2014-05-05-at-7.36.09-PM.png\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/wp-content/uploads/2014/05/Screen-Shot-2014-05-05-at-7.36.09-PM-300x270.png\" alt=\"Screen Shot 2014-05-05 at 7.36.09 PM\" width=\"409\" height=\"366\" /></a><a href=\"/wp-content/uploads/2014/05/Screen-Shot-2014-05-05-at-7.36.37-PM.png\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/wp-content/uploads/2014/05/Screen-Shot-2014-05-05-at-7.36.37-PM-300x295.png\" alt=\"Screen Shot 2014-05-05 at 7.36.37 PM\" width=\"410\" height=\"403\" /></a><a href=\"/wp-content/uploads/2014/05/Screen-Shot-2014-05-05-at-7.37.00-PM.png\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/wp-content/uploads/2014/05/Screen-Shot-2014-05-05-at-7.37.00-PM-300x296.png\" alt=\"Screen Shot 2014-05-05 at 7.37.00 PM\" width=\"410\" height=\"407\" /></a></p>\r\n<p style=\"text-align: center;\">You can also have this project at your events!</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/gifslap.gif', 'https://twitter.com/gifslap', 'http://gifslap.com', 'd0n-xyz,vco-vault,erica-anderson', '', '0', '1595116276', NULL, NULL, NULL, NULL),
(5, 'CODAME Neon', 'codame-neon', '<p>The NEON has seen the first light at the CODAME&nbsp;&nbsp;ART+TECH Event, Oct. 31st, 2014, @&nbsp;Geekdom,&nbsp; San Francisco.</p>\r\n<div data-href=\"https://www.connect.facebook.com/media/set/?set=a.715616431848021.1073741896.121190041290666&amp;type=1\" data-width=\"600\"><iframe class=\"\" title=\"fb:post Facebook Social Plugin\" src=\"http://www.facebook.com/plugins/post.php?app_id=&amp;channel=http%3A%2F%2Fstatic.ak.facebook.com%2Fconnect%2Fxd_arbiter%2F7r8gQb8MIqE.js%3Fversion%3D41%23cb%3Df12ca688e%26domain%3Dwww.codame.com%26origin%3Dhttp%253A%252F%252Fwww.codame.com%252Ff3744095b%26relation%3Dparent.parent&amp;href=https%3A%2F%2Fwww.connect.facebook.com%2Fmedia%2Fset%2F%3Fset%3Da.715616431848021.1073741896.121190041290666%26type%3D1&amp;locale=en_US&amp;sdk=joey&amp;width=600\" name=\"f3a4b0d02\" width=\"600px\" height=\"1000px\" frameborder=\"0\" scrolling=\"no\"></iframe></div>\r\n<div data-href=\"https://www.connect.facebook.com/media/set/?set=a.715616431848021.1073741896.121190041290666&amp;type=1\" data-width=\"600\"><hr />\r\n<p><a href=\"http://www.codame.com/?p=1050\">Angat</a>&nbsp;is the&nbsp;Artist behind the CODAME&nbsp;commissioned project, created under the artistic vision and inspiration by&nbsp;Atari&nbsp;(Artist Canvas): Vicente Montelongo @<a href=\"http://twitter.com/mexist\" target=\"_blank\">Mexist</a>&nbsp;and spiritual&nbsp;support of&nbsp;Amiga&nbsp;(Guru Meditation Handler): Jordan Gray @<a href=\"http://twitter.com/Starpause\" target=\"_blank\">staRpauSe</a>.</p>\r\n</div>', 'http://codame.dreamhosters.com/uploaded_images/codame-neon.jpg', '', '', 'angat-gaada', 'http://www.codame.com/post/portfolio/codame-neon/', '0', '1436337974', NULL, NULL, NULL, NULL),
(3, 'IOIO Plotter', 'ioio-plotter', '<p>The IOIO (pronounced &ldquo;yo-yo&rdquo;) Plotter is a drawing robot created by&nbsp;Ytai Ben-Tsvi, an engineer, who became a CODAME artist by creating a robot to draw art for him.</p>\r\n<p>The homemade,&nbsp;<a href=\"https://github.com/ytai/ioio/wiki\">open-source</a>&nbsp;IOIO Plotter is controlled by a custom Android application using Ytai&rsquo;s own IOIO-OTG printed circuit board. It imports images then plots them onto paper in one of several unique styles. Images can be provided in advance, taken during the event or emailed by attendees.</p>\r\n<p>The IOIO Plotter is happy to share his work for free, however he is also very sensitive, depending on the his mood and inspiration, his output is always a unique masterpiece.</p>\r\n<p style=\"text-align: center;\">Have the IOIO Plotter draw at your events!</p>\r\n<p style=\"text-align: center;\"><a href=\"http://www.codame.com/support/\">Support Art and Technology!</a></p>\r\n<p><img src=\"http://www.codame.com/wp-content/uploads/2015/02/IMG_20140517_192939107.jpg\" alt=\"IOIO Plotter\" width=\"2967\" height=\"1911\" /></p>\r\n<p><iframe id=\"instagram-embed-0\" class=\"instagram-media instagram-media-rendered\" src=\"https://instagram.com/p/xp6Z2QAOoz/embed/captioned/?v=4\" width=\"300\" height=\"763\" frameborder=\"0\" scrolling=\"no\" data-instgrm-payload-id=\"instagram-media-payload-0\"></iframe></p>\r\n<div data-href=\"https://www.facebook.com/media/set/?set=a.790895950986735.1073741913.121190041290666&amp;type=1\" data-width=\"650\"><iframe class=\"\" title=\"fb:post Facebook Social Plugin\" src=\"http://www.facebook.com/plugins/post.php?app_id=&amp;channel=http%3A%2F%2Fstatic.ak.facebook.com%2Fconnect%2Fxd_arbiter%2FxRlIuTsSMoE.js%3Fversion%3D41%23cb%3Df3eeadd1a%26domain%3Dwww.codame.com%26origin%3Dhttp%253A%252F%252Fwww.codame.com%252Ff2eaaf0dd%26relation%3Dparent.parent&amp;container_width=676&amp;href=https%3A%2F%2Fwww.facebook.com%2Fmedia%2Fset%2F%3Fset%3Da.790895950986735.1073741913.121190041290666%26type%3D1&amp;locale=en_US&amp;sdk=joey&amp;width=650\" name=\"f3d413061\" width=\"650px\" height=\"1000px\" frameborder=\"0\" scrolling=\"no\" allowfullscreen=\"allowfullscreen\"></iframe></div>', 'http://codame.dreamhosters.com/uploaded_images/ioio-plotter.jpg', '', 'https://github.com/ytai/ioio/wiki', 'ytai-ben-tsvi', '', '0', '1489717542', NULL, NULL, NULL, NULL),
(4, 'Circuit Dancers', 'circuit-dancers', '<p>&ldquo;Circuit Dancers&rdquo; was inspired by the dual cultures of dance and technology. The original piece consisted of a grid made up of 6 interactive LED illuminated wooden boxes. Each box has a steel face plate which was CNC plasma cut with a silhouette of an individual dancer.</p>\r\n<p>Within each silhouette is a schematic of a circuit board. The audience can change the color and speed of the LED lights in each individual box. The installation was designed and shown the first time for the &ldquo;Friends and Family 2012 electronic music festival.</p>\r\n<p>Now for all of us to&nbsp;enjoy.</p>\r\n<p><img src=\"http://www.codame.com/wp-content/uploads/2015/05/MG_7511.jpg\" alt=\"_MG_7511\" width=\"500\" height=\"750\" /></p>', 'http://codame.dreamhosters.com/uploaded_images/circuit-dancers.jpg', '', '', 'victoria-mara-heilweil,phil-spitler', '', '0', '1478630826', NULL, NULL, NULL, NULL),
(77, 'ShyBot', 'shybot', '<p>ShyBot has been&nbsp;released in&nbsp;Coachella Valley Feb.25th, 2017 for the inaugural exhibition of <a href=\"/events/desert-x\">Desert X</a>&nbsp;biennial of art.</p>\r\n<p>Autonomous, solar-powered rover traversing the California desert, tracked in real time using GPS technology, curious viewers can revisit the whole journey on&nbsp;<a href=\"http://shybot.codame.com/\">shybot.codame.com</a></p>\r\n<p>The&nbsp;ShyBot\'s only objective&nbsp;is to stay as far away from human beings as possible, at all times.&nbsp;ShyBot&nbsp;roamed the Coachella Valley area and was able to successfully avoid everyone -- even the drones being used to track the experiment. GPS technology was used to track ShyBot in real time, and a camera on it transmitted its point of view <a href=\"/events/shybot-panel-and-exhibition\">@TheLabs</a>&nbsp;San Francisco art gallery.</p>\r\n<p>The ShyBot, equipped with a camera, transmits a live stream of its point-of-view &ndash; a view based on an algorithm designed precisely to evade the human perspective. This is Norma Jeane&rsquo;s fantasy of the desert sublime: the machine is let loose in the landscape, free of the human determinism that thus far framed its existence, and we, in turn, are free to imagine a world liberated from the indeterminacy of&nbsp;us.</p>\r\n<p><iframe src=\"https://player.vimeo.com/video/205976218\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>Shyness is considered a trait unique to the human condition &mdash; no animals, let alone machines, can be ever be shy. The story goes that shyness is a reflection of our self-consciousness, of our uncertainty about who we are in relationship to a world made up of other uncertain beings. As humans we arecondemned&nbsp;to be free: there are no moral supports, no justifications, and no algorithms on which we can base our decisions. We must make and remake our significance within that world, constantly and from moment to moment.</p>\r\n<p>This robot has no function in the traditional sense. It does not serve us; it probably will not enslave us (perhaps only our imagination). Instead, this robot is programmed to&nbsp;run. To run immediately, with nervous electric heartbeat, in the opposite direction as soon as it senses the presence of a human being.</p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"/uploaded_images/desertX_small.png\" alt=\"\" /></p>\r\n<p>Desert X is a site-specific show that will take place in the spring of 2017. Artists from different parts of the world will be invited to make work that responds to the unique conditions of Palm Springs and the surrounding Coachella Valley.</p>\r\n<p>The desert of Desert X is the blank canvas upon which contemporary artists - like the writers, architects,&nbsp;musicians and other before them &ndash;&nbsp;will be invited to project their vision and to create of the extraordinary natural and social history around them objects and experiences that reflect upon the matchless spectacle of the geologic epic, the radical abstraction of the surroundings and the singular incursions of man into the seemingly barren landscape.&nbsp;Unique in that it takes the landscape itself as its exhibition space, Desert X will offer the opportunity to explore both the familiar and the unknown through the eyes of others.</p>\r\n<p>If the desert is indeed God without man, then Desert X is art without constraint.&nbsp;</p>\r\n<h3>Shybot Keepsake now available</h3>\r\n<p>We have been so lonely since Shybot went missing. Maybe you\'ve had the same feeling? But no longer, here\'s a 3d modeled Shybot to print out for your very own!</p>\r\n<div class=\"sketchfab-embed-wrapper\"><iframe src=\"https://sketchfab.com/models/ad7c810cce4d4a42951cd8104417a59b/embed\" width=\"640\" height=\"480\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe>\r\n<p style=\"font-size: 13px; font-weight: normal; margin: 5px; color: #4a4a4a;\"><a style=\"font-weight: bold; color: #1caad9;\" href=\"https://sketchfab.com/models/ad7c810cce4d4a42951cd8104417a59b?utm_medium=embed&amp;utm_source=website&amp;utm_campain=share-popup\" target=\"_blank\">Shybot Keepsake</a> by <a style=\"font-weight: bold; color: #1caad9;\" href=\"https://sketchfab.com/codame?utm_medium=embed&amp;utm_source=website&amp;utm_campain=share-popup\" target=\"_blank\">CODAME</a> on <a style=\"font-weight: bold; color: #1caad9;\" href=\"https://sketchfab.com?utm_medium=embed&amp;utm_source=website&amp;utm_campain=share-popup\" target=\"_blank\">Sketchfab</a></p>\r\n</div>\r\n<p>&nbsp;</p>\r\n<h3>The Making of the ShyBot...</h3>\r\n<p><iframe src=\"https://player.vimeo.com/video/201505425\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>Our first Test Run of the&nbsp;<a href=\"https://vimeo.com/201505425\">ShyBot vs. DroneBot</a> from <a href=\"https://vimeo.com/codame\">CODAME</a> on <a href=\"https://vimeo.com\">Vimeo</a>.</p>\r\n<p><img src=\"/uploaded_images/Shybot-1.jpg\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/Shybot-3.jpg\" alt=\"\" /></p>\r\n<div data-post-id=\"acd7f869c826\" data-source=\"post_page\" data-collection-id=\"657069408f43\" data-tracking-context=\"postPage\" data-scroll=\"native\">\r\n<section>\r\n<h2 id=\"bf49\">Shybot&nbsp;in the <a href=\"https://medium.com/codame-art-tech/shybot-acd7f869c826\">news</a>&hellip;</h2>\r\n<table style=\"height: 214px;\" width=\"567\">\r\n<tbody>\r\n<tr>\r\n<td><a href=\"https://www.nytimes.com/2017/03/17/arts/design/desert-x-show-things-go-awry-shy-bot-disappears.html?_r=0\"><img src=\"https://cdn-images-1.medium.com/max/800/1*xpvTYXreXqI23GP5ky8Otw.jpeg\" alt=\"\" data-image-id=\"1*xpvTYXreXqI23GP5ky8Otw.jpeg\" data-width=\"100\" data-height=\"100\" data-pin-nopin=\"true\" /></a></td>\r\n<td><a href=\"http://www.kmir.com/clip/13186001/desert-x-development-search-for-shybot-and-installation-closure\"><img src=\"https://cdn-images-1.medium.com/max/800/1*yxn0BClgo9mLsXyG-xX9ig.jpeg\" alt=\"\" data-image-id=\"1*yxn0BClgo9mLsXyG-xX9ig.jpeg\" data-width=\"100\" data-height=\"100\" /></a></td>\r\n<td><a href=\"http://www.kesq.com/news/artists-say-desert-x-damage-part-of-the-experience/403859617\"><img src=\"https://cdn-images-1.medium.com/max/800/1*31yx_WHNb6XjgH6lOt8k2g.jpeg\" alt=\"\" data-image-id=\"1*31yx_WHNb6XjgH6lOt8k2g.jpeg\" data-width=\"100\" data-height=\"100\" /></a>&nbsp;</td>\r\n<td><a href=\"https://www.nytimes.com/2017/02/24/arts/desert-x-turns-an-arid-space-into-a-canvas.html\"><img src=\"https://cdn-images-1.medium.com/max/800/1*xpvTYXreXqI23GP5ky8Otw.jpeg\" alt=\"\" data-image-id=\"1*xpvTYXreXqI23GP5ky8Otw.jpeg\" data-width=\"100\" data-height=\"100\" /></a></td>\r\n</tr>\r\n<tr>\r\n<td><a href=\"https://www.engadget.com/2017/03/08/this-anti-social-robots-only-task-is-to-avoid-people/\"><img src=\"https://cdn-images-1.medium.com/max/800/1*srox8cW3M8vK3ek-dzQEFg.jpeg\" alt=\"\" data-image-id=\"1*srox8cW3M8vK3ek-dzQEFg.jpeg\" data-width=\"100\" data-height=\"100\" /></a></td>\r\n<td><a href=\"http://www.huffingtonpost.com/entry/shybot-california-art-project_us_58c3906fe4b0ed71826cede6\"><img src=\"https://cdn-images-1.medium.com/max/800/1*Nj5Q-93MAj7pkb8XDS1o5w.jpeg\" alt=\"\" data-image-id=\"1*Nj5Q-93MAj7pkb8XDS1o5w.jpeg\" data-width=\"100\" data-height=\"100\" /></a></td>\r\n<td><a href=\"http://www.popularmechanics.com/technology/design/a25598/shybot-runs-from-people/\"><img src=\"https://cdn-images-1.medium.com/max/800/1*YZLRfip-Qd3l6EbPoXZHiw.png\" alt=\"\" data-image-id=\"1*YZLRfip-Qd3l6EbPoXZHiw.png\" data-width=\"100\" data-height=\"100\" /></a></td>\r\n<td><a href=\"https://motherboard.vice.com/en_us/article/anti-social-shybot-rolls-around-the-sonoran-desert-running-away-from-humans\"><img src=\"https://cdn-images-1.medium.com/max/800/1*Ck9qGCN2Bk6nd3nK8-LSqw.png\" alt=\"\" data-image-id=\"1*Ck9qGCN2Bk6nd3nK8-LSqw.png\" data-width=\"100\" data-height=\"100\" /></a></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<figure id=\"74d4\">\r\n<div><br />&nbsp;</div>\r\n</figure>\r\n</section>\r\n<section>\r\n<figure id=\"35bf\">\r\n<div>&nbsp;</div>\r\n</figure>\r\n<figure id=\"77fd\">\r\n<div>\r\n<div>&nbsp;</div>\r\n</div>\r\n<figcaption></figcaption>&nbsp;</figure>\r\n</section>\r\n</div>\r\n<footer></footer>', 'http://codame.dreamhosters.com/uploaded_images/shybot.gif', '', '', 'norma-jeane,d0n-xyz,jordan-gray,bruno-fonzi,ben-lerchin,eric-hanson', '', '0', '1590773294', NULL, NULL, NULL, NULL),
(6, 'Collider', 'collider', '<p>A Psychedelic VR Trip Through the Large Hadron Collider.</p>\r\n<p>Collider&nbsp;is an audiovisual experience using the LEAP Motion (and&nbsp;Oculus Rift, optional) where you travel through a psychedelic supercollider use 3D motion controls and gestures to warp your face with generative visuals and dynamic sounds.</p>\r\n<p>A&nbsp;collaboration effort with&nbsp;<a href=\"http://www.codame.com/?p=5815\">Eddie Lee</a>&nbsp;and&nbsp;<a href=\"http://baiyon.com/english/\">Baiyon</a>, an award-winning Japanese multimedia artist based in Kyoto, Japan. He was responsible for the sound design as well as the music for this project.</p>\r\n<p><iframe src=\"http://www.youtube.com/embed/AlE9idYZBhY?rel=0\" width=\"853\" height=\"480\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>We played with Collider&nbsp;at CODAME&nbsp;<a href=\"http://www.codame.com/?p=5644\">ART+TECH Virtual Reality</a>&nbsp;Nov. 21st. 2014 @ Mozilla, San Francisco.</p>\r\n<p>Bring&nbsp;Collider to&nbsp;your event too!&nbsp;<a href=\"http://www.codame.com/support/\">Support ART+TECH</a></p>\r\n<p><img src=\"http://www.codame.com/wp-content/uploads/2014/11/girl.png\" alt=\"collider girl\" width=\"586\" height=\"688\" /></p>', 'http://codame.dreamhosters.com/uploaded_images/collider.png', '', '', 'eddie-lee', '', '0', '1462425067', NULL, NULL, NULL, NULL),
(55, 'CODAME App', 'codame-app', '<p>A&nbsp;video-game esque fantasy world app that would serve as the way to navigate past, current, and future CODAME ART+TECH events.</p>\r\n<p>Main Developer: Amy Lee</p>\r\n<p>Main Designer: Pei Leiw</p>\r\n<p>Creative Director: Vicente Montelongo</p>\r\n<p>Product Concept: Bruno Fonzi</p>\r\n<p><img src=\"/uploaded_images/static1.squarespace-1_.gif\" alt=\"\" /><img src=\"/uploaded_images/static1.squarespace-2_.gif\" alt=\"\" /><img src=\"/uploaded_images/static1.squarespace-3_.gif\" alt=\"\" /><img src=\"/uploaded_images/static1.squarespace-5_.gif\" alt=\"\" /><img src=\"/uploaded_images/static1.squarespace-4_.gif\" alt=\"\" /><img src=\"/uploaded_images/static1.squarespace-6_.gif\" alt=\"\" /><img src=\"/uploaded_images/static1.squarespace-7_.gif\" alt=\"\" /><img src=\"/uploaded_images/static1.squarespace-8_.gif\" alt=\"\" /><img src=\"/uploaded_images/static1.squarespace_.gif\" alt=\"\" /></p>', 'http://codame.dreamhosters.com/uploaded_images/codame-app.gif', '', '', '', '', '0', '1463867711', NULL, NULL, NULL, NULL),
(7, 'Metropulus::Drone', 'metropulus-drone', '<hr />\r\n<p>Second in the Metropolous series, an interactive installation bringing the dystopian future right into your very hands. Fly a spy drone through the streets of Metropulous, searching for core intel that may unlock the secret of Metropulous. Enemy drones are hunting you down, you must evade them with the clock ticking down! Drone is a kinect controlled immersive experience coded by <a href=\"http://www.codame.com/post/portfolio/vj-musashii/\">VJ Musashii</a> in Unity and HTML5, projected or using the Oculus Rift for display.</p>\r\n<p>Enjoy Metropolous::Drone at CODAME <a href=\"http://www.codame.com/?p=5644\">ART+TECH Virtual Reality</a> @ Mozilla, San Francisco, Friday Nov. 21st.</p>\r\n<p class=\"p1\" style=\"text-align: center;\"><strong>Adopt this project for your events!</strong></p>\r\n<p style=\"text-align: center;\"><a title=\"Adopt an Artist, Support ART+TECH\" href=\"/adopt\"><img class=\"alignnone size-full wp-image-3942\" src=\"http://www.codame.com/wp-content/uploads/2014/04/Codame_Badge_02_AdoptAnArtist_200px.png\" alt=\"Adopt an Artist\" width=\"200\" height=\"145\" /></a></p>\r\n<p style=\"text-align: center;\"><a href=\"http://www.codame.com/support/\">Support ART+TECH</a></p>', 'http://codame.dreamhosters.com/uploaded_images/metropulus-drone.png', '', '', '', '', '0', '1509686288', NULL, NULL, NULL, NULL),
(8, 'CODAME Art+Tech Festival Papercraft', 'codame-art-tech-festival-papercraft', '<div class=\"figure\">&nbsp;</div>\r\n<p>Our CODAME Flyers are off to print! Look around your hood for some!</p>\r\n<p>Happy ART+TECH Halloween everyone!</p>\r\n<p><img src=\"/wp-content/uploads/2013/11/e3be653955a3e4d298a55ec6675b52f73.jpg\" alt=\"\" /></p>\r\n<p>&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/codame-art-tech-festival-2012-papercraft.jpg', '', '', '', '', '0', '1472524947', NULL, NULL, NULL, NULL),
(9, 'Proteus', 'proteus', '\r\n						<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/68d44ea4f01de749a19a69796e1e6f392.jpg\"></figure>\r\n</div>\r\n<p class=\"MsoNormal\"><strong><a href=\"http://www.visitproteus.com/\" target=\"_blank\">Proteus</a> – CODAME Featured Game</strong></p>\r\n<p class=\"MsoNormal\">Proteus is what indie gaming is all about. Created by <a href=\"https://twitter.com/edclef\" target=\"_blank\">Ed Key</a> and <a href=\"https://twitter.com/dkanaga\" target=\"_blank\">David Kanaga</a>, Proteus pushing the boundaries of games. Set in a minimalist musical wilderness, your only mission while playing Proteus is to explore the environment, mixing sounds and creating music in the process. Proteus will be setup in the Indie Gaming Arcade at CODAME. Make sure you stop and play during CODAME.</p>\r\n											', 'http://codame.dreamhosters.com/uploaded_images/proteus.jpg', '', 'http://www.visitproteus.com/', '', 'http://www.codame.com/post/portfolio/proteus/', '0', '', NULL, NULL, NULL, NULL),
(10, 'Meshu', 'meshu', '<div class=\"figure\">&nbsp;</div>\r\n<div class=\"figure\">\r\n<p class=\"MsoNormal\"><strong><a href=\"http://meshu.io/\" target=\"_blank\">Meshu</a> </strong><strong>CODAME Featured&nbsp;Project</strong></p>\r\n<p class=\"MsoNormal\">Meshu creates jewelry that is unique to each wearer. Based on the movements of each individual, a unique piece is created. Laser cut or 3D-printed, each piece is based off the places every individual has been. The two-person team of Rachel Binx and Sha Hwang are the masterminds behind Meshu. They will have examples at CODAME and you will be able to map your piece right there.</p>\r\n<p class=\"MsoNormal\">See what your map looks like at the 2012 CODAME ART+TECH Festival on Oct. 27. <a href=\"/tickets\" target=\"_blank\">Grab a ticket</a></p>\r\n<p class=\"MsoNormal\"><img src=\"/wp-content/uploads/2013/11/c16885e9f1b56969b0c469f026ef277c2.png\" alt=\"\" width=\"531\" height=\"533\" /></p>\r\n<p class=\"MsoNormal\"><img src=\"/wp-content/uploads/2013/11/6726be23b6297a36be5b02eef7adec2b2.jpg\" alt=\"\" width=\"212\" height=\"319\" /><img src=\"/wp-content/uploads/2013/11/79c5edfbb8614b37d27ef904c7312bb12.png\" alt=\"\" width=\"320\" height=\"320\" /></p>\r\n</div>\r\n<p class=\"MsoNormal\">&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/meshu.png', '', 'http://meshu.io/', '', '', '0', '1455073799', NULL, NULL, NULL, NULL),
(11, 'naughtBothered', 'naughtbothered', '<h2>#naughtBothered is a generative new media piece randomly combining:</h2>\r\n<ul>\r\n<li>3d modeling by <a href=\"http://camaltamura.com/\" target=\"_blank\">Cam Altamura</a></li>\r\n<li>Analog video textures captured by Jordan Gray aka <a href=\"http://starpause.com/\" target=\"_blank\">starPause</a></li>\r\n<li>User-generated content farmed from Twitter</li>\r\n</ul>\r\n<p>To contribute, tweet the URLs for one or more GIFs and include the #naughtBothered tag. It can take a minute or two for your Twitter handle to appear in a thank you message &amp; thereafter your GIF selections will be featured in the upper left picture-in-picture area!</p>\r\n<p>#naughtBothered was developed with responsive web principles in mind: so it looks good tall, wide, or square. All of the code is executed client-side including JSONP calls to Twitter. <a href=\"https://github.com/starpause/NaughtBothered\" target=\"_blank\">Fork the CC-BY project on github</a> or <a href=\"http://gorehole.org/naughtbothered/naughtBothered.html\" target=\"_blank\">preview the work in your browser</a> (user: naught pass: bothered)!</p>\r\n<p><a href=\"http://www.linkedin.com/pub/cam-altamura/17/332/44\" target=\"_blank\">Cam Altamura</a> graduated from the Art institute of California, San Francisco with a bachelor\'s degree in graphic design.</p>\r\n<p><a href=\"http://www.linkedin.com/pub/jordan-starpause-gray/1/b9a/182/\" target=\"_blank\">Jordan Gray</a> graduated from the University of Minnesota, Twin Cities with a bachelor\'s degree emphasizing computer science, studio arts and journalism.</p>\r\n<p>#naughtBotehred was adopted at <a href=\"/defcon\" target=\"_blank\">DEF CON 21</a>&nbsp;August 1-4, Rio Hotel, Las Vegas!</p>\r\n<p style=\"color: #505050; text-align: center;\"><span style=\"font-weight: bold;\">Adopt this projectï¿½forï¿½your events too!</span></p>\r\n<p style=\"color: #505050; text-align: center;\"><a style=\"color: #00a4a7;\" title=\"Adopt an Artist, Support ART+TECH\" href=\"/adopt\"><img class=\"alignnone size-full wp-image-3942\" src=\"http://www.codame.com/wp-content/uploads/2014/04/Codame_Badge_02_AdoptAnArtist_200px.png\" alt=\"Adopt an Artist\" width=\"200\" height=\"145\" /></a></p>\r\n<p style=\"color: #505050; text-align: center;\"><a style=\"color: #00a4a7;\" href=\"http://www.codame.com/support/\">Support Art and Technology!</a></p>\r\n<p><img class=\"aligncenter\" src=\"/wp-content/uploads/2013/11/cc5e35c8e72aed9d30d7743c8e7a9c52.jpg\" alt=\"\" /></p>', 'http://codame.dreamhosters.com/uploaded_images/naughtbothered.jpg', '', 'https://github.com/starpause/NaughtBothered', 'cam-altamura,jordan-gray', '', '0', '1524511646', NULL, NULL, NULL, NULL),
(12, 'Eugene Houdin', 'eugene-houdin', '\r\n						<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"\"></figure>\r\n</div>\r\n<div class=\"figure\">\r\n<figure><img alt=\"\" src=\"http://codame.com/wp-content/uploads/2013/11/becace1fec3ef36346186f356abbc405.png\"></figure>\r\n</div>\r\n<p><strong>CODAME Featured Game: <a href=\"https://www.facebook.com/EugeneHoudinGAME\" target=\"_blank\">Eugene Houdin</a></strong></p>\r\n<p><em>With the <a title=\"CODAME Games\" href=\"http://www.eventbrite.com/event/5482598600\" target=\"_blank\">CODAME GAMES</a> showdown only days away, we thought we’d give you preview of the indie games that will be duking it out on August 21 for top bragging rights and a trip to the <a href=\"http://www.eventbrite.com/event/5482642732\" target=\"_blank\">ARTS+TECH Festival</a>.</em></p>\r\n<p><em>Up first is the stick-figure fighting game, <a href=\"https://www.facebook.com/EugeneHoudinGAME\" target=\"_blank\">Eugene Houdin</a>!</em></p>\r\n<hr>\r\n<p><strong>I’m digging the ‘notebook battle’ aesthetic of the game!<br>\r\nWhat platforms will you be releasing it on?</strong></p>\r\n<p><strong>Nick Smith (Game Director):  </strong><span>Right now, </span><em>Eugene Houdin </em><span>is being developed for mobile devices. However, there will be a Flash version as well. </span></p>\r\n<p><strong>Why should we drop whatever we’re doing and play it?</strong></p>\r\n<p><span>It’s a doodle animation fighting game. This is such a unique game that has an interactive element to it unlike any other fighting game made before. </span></p>\r\n<p><span>What makes the interactive ability to this game so unique and amazing is that however, you swipe your character will react. You swipe forward and up you will upper cut or if you wipe down you duck. You aren’t just clicking a button but really drawing out the path. </span></p>\r\n<p><strong>As a game creator, what was the hardest part about making <em>Eugene Houdin</em>?</strong></p>\r\n<p>The hands down biggest challenge in making this game was developing the game for nearly free.</p>\r\n<p>With a team of about 10 people, the game was created for next-to-nothing. Finding amazing talent that had not yet been discovered was hard to find. The solution to this is that — except for one person — everyone who worked on the game is a teenager.</p>\r\n<p><strong>Kids can make big visions come to life. They’re not jaded at all.<br>\r\nThanks for talking to us, Nick!</strong></p>\r\n<hr>\r\n<p><em><strong>Join <a title=\"CODAME Games\" href=\"http://www.eventbrite.com/event/5482598600\" target=\"_blank\">CODAME GAMES</a> on</strong><strong> <a href=\"http://www.eventbrite.com/event/5482598600\" target=\"_blank\">August 21st</a> t</strong><strong>o be inspired, learn, play and vote for your favorite <span class=\"vevent\"><span class=\"description\">Indie Game!</span></span></strong></em></p>\r\n											', 'http://codame.dreamhosters.com/uploaded_images/eugene-houdin.png', '', 'https://www.facebook.com/EugeneHoudinGAME', 'nick-smith', 'http://www.codame.com/post/portfolio/codame-featured-game-eugene-houdin-join-codame/', '0', '', NULL, NULL, NULL, NULL),
(13, 'Rad Raygun', 'rad-raygun', '<p><iframe src=\"http://www.youtube.com/embed/ygEWIXKDdLg?wmode=transparent&amp;autohide=1&amp;egm=0&amp;hd=1&amp;iv_load_policy=3&amp;modestbranding=1&amp;rel=0&amp;showinfo=0&amp;showsearch=0\" width=\"400\" height=\"225\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>CODAME Featured Game: &nbsp;<a href=\"https://www.facebook.com/EugeneHoudinGAME\" target=\"_blank\">Rad Raygun</a></p>\r\n<p>With the&nbsp;<a href=\"http://www.eventbrite.com/event/5482598600\" target=\"_blank\">CODAME GAMES</a>&nbsp;showdown only days away, we thought we&rsquo;d give you preview of the indie games that will be duking it out on August 21 for top bragging rights and a trip to the&nbsp;<a href=\"http://www.eventbrite.com/event/5482642732\" target=\"_blank\">ARTS+TECH Festival</a>.</p>\r\n<p>Next up is&nbsp;<a href=\"http://www.indiegamemag.com/rad-raygun-brings-a-slice-of-the-80s-to-xbox-360/\" target=\"_blank\">Rad Raygun</a>, currently available on&nbsp;<a href=\"http://marketplace.xbox.com/en-US/Games/XboxIndieGames/\" target=\"_blank\">Xbox Live Indie Games</a>.&nbsp;</p>\r\n<hr />\r\n<p>Based on its graphics,&nbsp;Rad Raygun&nbsp;has a significant retro vibe to it.</p>\r\n<p>Explain it to me in a way that takes me back to one of the most loathed times in human history.</p>\r\n<p><a href=\"https://twitter.com/trufun202\" target=\"_blank\">Chris Bryant</a>: &nbsp;The&nbsp;year is 198X. Big hair is hot, and the war with the Soviets is colder than a refreshing glass of New Coke.</p>\r\n<p>Rad Raygun must travel the world fighting communist robots and save the 1980&rsquo;s by shooting his way through 5 decade-spanning levels. Ultra-sharp 144p resolution graphics and 4 unique shades of monochrome off-green bring our game to life, as only 1980&rsquo;s mobile technology can!</p>\r\n<p>I&rsquo;m almost afraid to ask, but what&rsquo;s the&nbsp;single most memorable part of your game that you want people to never forget?</p>\r\n<p>Rad Raygun&nbsp;is our homage to the retro games of yesteryear.</p>\r\n<p>The characters and storylines are very tongue-in-cheek &mdash; nowhere else can you fight a material girl named &ldquo;Mad Donna&rdquo; or take down the Berlin Wall,&nbsp;<a href=\"http://en.wikipedia.org/wiki/Contra_(video_game)\" target=\"_blank\">Contra</a>-style! &nbsp;The unforgettable experience is designed to be a fun trip down memory lane.</p>\r\n<p>Oh, and&nbsp;Rad Raygun&nbsp;also comes&nbsp;with an original chiptune soundtrack by&nbsp;<a href=\"https://www.facebook.com/FantomenK\" target=\"_blank\">FantomenK</a>&nbsp;&mdash; so, crank up the volume!</p>\r\n<p>Aside from forcing yourself to relive the 80&rsquo;s, what was the most difficult aspect of creating&nbsp;Rad Raygun?</p>\r\n<p>Since the game is programmed in Microsoft&rsquo;s XNA framework, everything was developed and tested on the PC for the first year, and was going seemingly well. Finally, we got the first level up and running, it was time to test it on the Xbox 360.</p>\r\n<p>And, the result was a&nbsp;huge&nbsp;letdown!</p>\r\n<p>The game took nearly 5 minutes to load! &nbsp;It turns out that my tilemap code was extremely inefficient. &nbsp;Fixing this meant that I had to gut a large portion of my code and re-engineer it, which took weeks. &nbsp;And, since everything was in a new format, I had to write a conversion tool so that our maps wouldn&rsquo;t have to be rebuilt from scratch.</p>\r\n<p>Once this was fixed, the remainder of the project was smooth sailing&hellip; until&nbsp;one&nbsp;week before launch. &nbsp;Since the severe load times were fixed, I hadn&rsquo;t tested the game on the 360 in months. &nbsp;Instead, I was simply focusing on finishing the game on the PC. &nbsp;But when I got to the point where I considered the game &ldquo;done,&rdquo; I loaded it up on the 360 and hit the absolute lowest point in the project &mdash; for one, the long load times were back. &nbsp;We were now loading in larger maps, more graphics, and more sound. &nbsp;Once the game finally loaded, the framerate was atrocious! &nbsp;I was devastated.</p>\r\n<p>The Xbox 360 is indeed a powerhouse, but only when used correctly. &nbsp;The engine had serious memory management issues that weren&rsquo;t visible on the PC. &nbsp;I spent days tweaking and optimizing the engine in hopes of alleviating the issue. &nbsp;The results were only marginally successful and the framerate was still noticeably bad. &nbsp;This was the ultimate low for me. &nbsp;My team dedicated their nights and weekends to this project for over two years and, only two days from launch, I wasn&rsquo;t sure if it would ever see the light of day.</p>\r\n<p>Finally, while examining the game&rsquo;s memory usage for the 100th time, I noticed that the maps were allocating way more memory than they should (twice as much in some cases)! &nbsp;It turns out that there was a bug in the level editor and the maps were exported with a ton of extraneous data at the end of the files. &nbsp;I wrote a tool to clean up the extraneous data from the map files, reloaded the game on the 360, and all of my framerate issues were gone.</p>\r\n<p>This led to the ultimate high of launching the game on February 19th, 2013!</p>\r\n<p>You overcame bad hair, cheesy music, and a major memory leak to create a 1980&rsquo;s themed game for the most popular game console of the 2000&rsquo;s.</p>\r\n<p>Congrats! (I think)</p>\r\n<hr />\r\n<p>Join&nbsp;<a href=\"http://www.eventbrite.com/event/5482598600\" target=\"_blank\">CODAME GAMES</a>&nbsp;on&nbsp;<a href=\"http://www.eventbrite.com/event/5482598600\" target=\"_blank\">August 21st</a>&nbsp;to&nbsp;be inspired, learn, play and vote for your favorite&nbsp;Indie Game!</p>', 'http://codame.dreamhosters.com/uploaded_images/rad-raygun.png', 'https://twitter.com/trufun202', 'http://www.indiegamemag.com/rad-raygun-brings-a-slice-of-the-80s-to-xbox-360/', 'chris-bryant', 'http://www.codame.com/post/portfolio/codame-featured-game-rad-raygun-with-the-codame/', '0', '1436402700', NULL, NULL, NULL, NULL),
(75, 'Watercolor Walls', 'watercolor-walls', '<p>\"Watercolor Walls\" mixes basic tech tools and audience participation to give new life to your stodgy old silhouette.</p>\r\n<p>Mix infrared light, a camera, and open-source software and you get \"Watercolor Walls,\" a cool interactive art installation that visualizes how light bends to create your silhouette.</p>\r\n<p>When your silhouette comes in contact with one of the colors on the palette, it would change color, and bring that new color down into the rest of the screen. That new color would then interact with the differently colored silhouettes of others. That gives participants a unique ability to control both the on-screen colors and flow of the silhouettes.</p>', 'http://codame.dreamhosters.com/uploaded_images/watercolor-walls.jpg', '', '', 'anticlockwise-arts,rich-ddt', '', '0', '1490210044', NULL, NULL, NULL, NULL),
(56, 'Circles of Space', 'circles-of-space', '<p>An&nbsp;audiovisual installation, sensor based first version concept project collaboration between&nbsp;<a href=\"/artists/anouk-wipprecht\">Anouk Wipprecht</a>&nbsp;and <a href=\"/artists/donald-hanson\">Donald&nbsp;Hanson</a>, premiered&nbsp;at Salesforce&nbsp;San Francisco during a CODAME ART+TECH event. TAn interactive visualization of personal space using projections and wearable sensors.</p>\r\n<p>Anouk\'s work often deals with concepts around personal space, and many of her wearable pieces use microcontrollers to react when personal space is invaded. For this collaboration I created an audiovisual program that reacts to the proximity levels of approaching guests. Anouk created a sensor necklace worn by a model, and my program\'s output was projected down on the floor around the model.</p>\r\n<p>As for the technical side, the visualizations is created in with CSS and JavaScript in a Chromium browser, with NodeJS running to read serial data from the sensors. The&nbsp;NWJSframework is used to connect Node to Chromium.</p>\r\n<p><a href=\"http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/SPACES_PROXI_ANOUKWIPPRECHT.jpg\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/SPACES_PROXI_ANOUKWIPPRECHT-1024x1004.jpg\" sizes=\"(max-width: 640px) 100vw, 640px\" srcset=\"http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/SPACES_PROXI_ANOUKWIPPRECHT-1024x1004.jpg 1024w, http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/SPACES_PROXI_ANOUKWIPPRECHT-300x294.jpg 300w, http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/SPACES_PROXI_ANOUKWIPPRECHT.jpg 1203w\" alt=\"SPACES_PROXI_ANOUKWIPPRECHT\" width=\"640\" height=\"628\" /></a></p>\r\n<p style=\"text-align: center;\">The proposed concept to visualize.</p>\r\n<p style=\"text-align: center;\"><a href=\"http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/IMG_1991.jpg\"><img src=\"http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/IMG_1991-1024x768.jpg\" sizes=\"(max-width: 640px) 100vw, 640px\" srcset=\"http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/IMG_1991-1024x768.jpg 1024w, http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/IMG_1991-300x225.jpg 300w\" alt=\"IMG_1991\" width=\"640\" height=\"480\" /></a></p>\r\n<p style=\"text-align: center;\">Olia Pospelova and Cindy Clark testing the installation at Salesforce</p>\r\n<p style=\"text-align: center;\"><a href=\"http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/IMG_1989.jpg\"><img src=\"http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/IMG_1989-1024x768.jpg\" sizes=\"(max-width: 640px) 100vw, 640px\" srcset=\"http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/IMG_1989-1024x768.jpg 1024w, http://www.everythingihaveeverdone.com/wp-content/uploads/2015/05/IMG_1989-300x225.jpg 300w\" alt=\"IMG_1989\" width=\"640\" height=\"480\" /></a></p>\r\n<p style=\"text-align: center;\"><a href=\"/artists/bruno-fonzi\">Bruno Fonzi</a>\'s introduction, moments before the first demonstration.</p>', 'http://codame.dreamhosters.com/uploaded_images/circles-of-space.gif', '', '', 'anouk-wipprecht,d0n-xyz', '', '0', '1590773286', NULL, NULL, NULL, NULL),
(50, 'Gravity', 'gravity', '<p>Watch thousands of stars as they swirl and swell around your fingers. Gravity is a real-time physics simulation of dust particles that are gravitationally attracted to your finger. A sensor detects users hand and finger positions which drives both the center of gravitation in the simulation, as well as generative audio to match. By placing the physics of the simulation first and foremost, the piece invites users to focus on the core mechanics of how the universe around us works, while simultaneously showing the beauty that naturally arises from these rules.&nbsp;</p>\r\n<p>Gravity is an interactive installation by <a href=\"/artists/xiaohan-zhang\">Xiaohan Zhang</a> that will be featured at our <a href=\"/events/art-tech-festival-2015\">ART+TECH Festival MOVEMENT</a></p>', 'http://codame.dreamhosters.com/uploaded_images/gravity.png', '', '', 'xiaohan-zhang', '', '0', '1445220748', NULL, NULL, NULL, NULL);
