(221, 'Sick Seashore', 'sick-seashore', '<p>NFT available on blockchain&nbsp;<a href=\"https://knownorigin.io/edition/203275\">knownorigin</a>&nbsp;and as a print on&nbsp;<a href=\"https://shop.codame.com/collections/jordan-gray/products/jordan-gray-3\">shop.codame.com.</a></p>\r\n<p><span data-v-87108a8c=\"\">ð–™ð–ð–Šð–’ð–Š<br data-v-87108a8c=\"\" /></span><span data-v-87108a8c=\"\">Edges of rheality. Perception infantality. Wet incomprehendability.<br data-v-87108a8c=\"\" /></span><span data-v-87108a8c=\"\"><br data-v-87108a8c=\"\" /></span><span data-v-87108a8c=\"\">ð–™ð–Šð–ˆð–ð–“ð–Žð––ð–šð–Š<br data-v-87108a8c=\"\" /></span><span data-v-87108a8c=\"\">Analog video synthesis on a LXZ modular system. Captured via Matrox MX02 MiniMax.<br data-v-87108a8c=\"\" /></span><span data-v-87108a8c=\"\"><br data-v-87108a8c=\"\" /></span><span data-v-87108a8c=\"\">ð–™ð–—ð–†ð–“ð–˜ð–†ð–ˆð–™<br data-v-87108a8c=\"\" /></span><span data-v-87108a8c=\"\">Unique (1/1) 5x7 inch print available at shop.codame.com/products/jordan-gray-1<br data-v-87108a8c=\"\" /></span><span data-v-87108a8c=\"\"><br data-v-87108a8c=\"\" /></span><span data-v-87108a8c=\"\">ð–™ð–—ð–Žð–•ð–™ð–žð–ˆð–<br data-v-87108a8c=\"\" /></span><span data-v-87108a8c=\"\">1 of 3 in the \"Sick Seashore\" series, between \"Sick Seashore Top\" and \"Sick Seashore Bottom\"</span></p>\r\n<div data-v-87108a8c=\"\">&nbsp;</div>\r\n<div data-v-87108a8c=\"\">Additional detail</div>\r\n<div data-v-87108a8c=\"\">\r\n<div data-v-5ecd5357=\"\" data-v-87108a8c=\"\">\r\n<div title=\"The original artwork can easily be obtained once purchased\" data-v-5ecd5357=\"\">1861 x 1080 px (image/png)2 mb</div>\r\n</div>\r\n</div>\r\n<div data-v-87108a8c=\"\"><span data-v-c7067fda=\"\" data-v-87108a8c=\"\"><a href=\"https://erc721validator.org/?address=0xfbeef911dc5821886e1dda71586d90ed28174b7d\" target=\"_blank\" data-v-c7067fda=\"\">ERC721 standard</a></span></div>\r\n<div data-v-87108a8c=\"\"><span data-v-88d7a10e=\"\" data-v-87108a8c=\"\"><a href=\"https://ipfs.infura.io/ipfs/QmS2dnpGqENcg5fZ2A75AA1YjU8w2sjo98b9br27qvDth9\" target=\"_blank\" data-v-88d7a10e=\"\">IPFS hosted</a></span></div>\r\n<div data-v-87108a8c=\"\"><span data-v-2a427d28=\"\" data-v-87108a8c=\"\"><a href=\"https://etherscan.io/tx/0x40b4d72ff908f4fc5763a22c224f9ed55a2ec0eec86482c70b2ef829250c2a81\" target=\"_blank\" data-v-2a427d28=\"\">Creation</a></span></div>\r\n<div data-v-87108a8c=\"\">&nbsp;</div>\r\n<div data-v-87108a8c=\"\"><a href=\"https://etherscan.io/tx/0x40b4d72ff908f4fc5763a22c224f9ed55a2ec0eec86482c70b2ef829250c2a81\">Edition</a></div>', 'http://codame.dreamhosters.com/uploaded_images/sick-seashore.gif', '', 'https://shop.codame.com/collections/jordan-gray/products/jordan-gray-3', 'jordan-gray', '', '0', '1623214876', 'https://shop.codame.com/collections/jordan-gray/products/jordan-gray-3', '', '', 'nft'),
(222, 'LIGHT BARCODE', 'light-barcode', '<h2 style=\"text-align: center;\">&nbsp;</h2>\r\n<h2 style=\"text-align: center;\"><a href=\"https://superrare.co/starpause\">Buy Crypto Art NFT @ SuperRare</a> - <a href=\"https://superrare.co/artwork-v2/lightbarcodefront-13082\">Front</a>&nbsp;- <a href=\"https://superrare.co/artwork-v2/lightbarcodeback-13084\">Back</a></h2>\r\n<h2>&nbsp;</h2>\r\n<h2 style=\"text-align: center;\"><a href=\"https://shop.codame.com/collections/jordan-gray/products/jordan-gray-square-pillow\">Buy 14\" Square Pillow</a></h2>\r\n<h2>&nbsp;</h2>\r\n<p style=\"text-align: left;\">LoFi Uncanny (series) is Dakimakura Pillow Art for the AI Age. You\'re invited to a valley on the softer side of screens. Navigating uncertainty is our only path to progress, enjoy the weird vibes ride! More detail about this process and the tradition of rare Dakimakura collecting can be found here. Techniques used: Neural Style Transfer, ANSI Encoding, Video Animation.</p>\r\n<p style=\"text-align: left;\">Get lost exploring the vibrant blocks in a UHD PNG. Combine your collection of scrolling ANSI videos into an ambient art installation.&nbsp;</p>\r\n<p style=\"text-align: left;\">Exclusive to SuperRare. The first owner to possess both Light Barcode Front &amp; Back <strong>will receive the designs as a printed dakimakura cover (160x50cm, 2wt).</strong>&nbsp; A new design will drop every month, keeping pace with traditional circles releasing body pillow covers.</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><iframe title=\"vimeo-player\" src=\"https://player.vimeo.com/video/449535462\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe>&nbsp;</p>\r\n<p style=\"text-align: center;\"><a href=\"https://superrare.co/starpause\">Buy Crypto Art NFT @ SuperRare</a>&nbsp;-&nbsp;<a href=\"https://superrare.co/artwork-v2/lightbarcodefront-13082\">Front</a></p>\r\n<p style=\"text-align: center;\"><img src=\"/uploaded_images/b002b86e890acf9eff72d7184ae854e6_1024x1024@2x.jpg\" alt=\"\" /></p>\r\n<p style=\"text-align: center;\"><a href=\"https://shop.codame.com/collections/jordan-gray/products/jordan-gray-square-pillow\">Buy 14\" Square Pillow</a></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><iframe title=\"vimeo-player\" src=\"https://player.vimeo.com/video/449561298\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p style=\"text-align: center;\"><a href=\"https://superrare.co/starpause\">Buy Crypto Art NFT @ SuperRare</a>&nbsp;-&nbsp;<a href=\"https://superrare.co/artwork-v2/lightbarcodeback-13084\">Back</a></p>', 'http://codame.dreamhosters.com/uploaded_images/light-barcode.png', '', 'https://superrare.co/artwork-v2/light-barcode-14748', 'jordan-gray', '', '0', '1622645509', 'https://superrare.co/artwork-v2/light-barcode-14748', '', '', 'nft'),
(240, 'Acceptance', 'acceptance', '<p>Edition: 1/10<br />HahnemuÌˆhle Photo Rag Fine Art Print<br />Image&nbsp;5 x 8 in.&nbsp;<br />Unique</p>\r\n<p>&nbsp;</p>\r\n<p>NFT on the blockchain available soon on SuperRare</p>\r\n<p>- min. reserve price 1.5 ETH</p>', 'http://codame.dreamhosters.com/uploaded_images/acceptance.gif', '', '', 'janessa-robinson', '', '0', '1618947221', 'https://shop.codame.com/collections/janessa-robinson/products/janessa-robinson-print-1', '', '', 'nft'),
