(269, 'Giza Pyramid & Sphinx', 'giza-pyramid-sphinx', '<p>Fine point sharpie and watercolor.</p>\r\n<p>Sketched inside a JMB VL-3 plane.</p>\r\n<p>Minted on behalf of Micheal Scherotter as we shared work in the CODAME ART+TECH Happy Hour Voice Channel on Discord</p>', 'http://codame.dreamhosters.com/uploaded_images/giza-pyramid-sphinx.jpg', '', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/64565087924356982539408794320246414468607019910359975833310188528632586043393', 'michael-scherotter', '', '0', '1623366950', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/64565087924356982539408794320246414468607019910359975833310188528632586043393', '', '', 'nft'),
