(282, 'Selfie Olympics - Crystal Ball', 'selfie-olympics---crystal-ball', '<p>Thanks to <a style=\"box-sizing: inherit; color: #039be5; -webkit-tap-highlight-color: transparent; text-decoration-line: none; overflow: hidden; text-overflow: ellipsis; font-family: \'Avenir Next\', Avenir, \'Avenir Next Local\', sans-serif;\" href=\"/artists/samarth-gulati\" target=\"_blank\">Samarth</a> for his <a style=\"box-sizing: inherit; color: #039be5; -webkit-tap-highlight-color: transparent; text-decoration-line: none; overflow: hidden; text-overflow: ellipsis; font-family: \'Avenir Next\', Avenir, \'Avenir Next Local\', sans-serif;\" href=\"/events/stylize-selfies-with-hydra-blockly\" target=\"_blank\">Stylize Selfies with Hydra Blockly Workshop</a> at CODAME ART+TECH Festival 2020ã€Ž JOYNT ã€!</p>', 'http://codame.dreamhosters.com/uploaded_images/selfie-olympics---crystal-ball.jpeg', '', '', 'jordan-gray', '', '0', '1623364576', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/64565087924356982539408794320246414468607019910359975833310188533030632554497', '', '', 'nft'),
