(280, 'RIBBITY RIBBITY RAY', 'ribbity-ribbity-ray', '<p>#fresh air feels like #summer #love everyone is out and the people I know and saw were still wearing masks and being responsible about enjoying ðŸ¥° #sf #yayarea</p>', 'http://codame.dreamhosters.com/uploaded_images/ribbity-ribbity-ray.jpeg', '', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/64565087924356982539408794320246414468607019910359975833310188530831609298945', 'jordan-gray', '', '0', '1623364800', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/64565087924356982539408794320246414468607019910359975833310188530831609298945', '', '', 'nft'),
(281, 'Bonjour, Controller Giraffe!', 'bonjour-controller-giraffe', '<p>Created in JOYNT collaboration between Edith Viau, Mike Edwards, Nataliia Frank, Liz Reid, and Jordan Gray @ E-Lit Games (Playing With Words) during CODAME ART+TECH Festival 2020 JOYNT. Generate your own haiku @ https://nebula-scandalous-epoxy.glitch.me</p>', 'http://codame.dreamhosters.com/uploaded_images/bonjour-controller-giraffe.png', '', '', 'jordan-gray', '', '0', '1623364511', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/115057632871220388211095070235813184367894539740535270077387425175023309029377', '', '', 'nft'),
(283, 'Free as a Eagle', 'free-as-a-eagle', '', 'http://codame.dreamhosters.com/uploaded_images/free-as-a-e-a-g-l-e.png', '', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/67722600005193427097683426082186481512657765209996411579300368393883306950657', 'odbol', '', '0', '1683701125', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/67722600005193427097683426082186481512657765209996411579300368393883306950657', 'opensea', '', 'nft'),
(284, 'Ailes', 'ailes', '<p>\"Ailes\" in French means wings. Like a boat, even anchored / blocked at shore, the affirmation that we are confined now-here / nowhere close to the horizons of our aspirations is an illusion... Wherever we are, let us open our wings and set sail to Dreamspaces of Inner-inspiration from the Beyond, let us enter these inner worlds and higher levels of consciousness where time and space merge in a quantum field of creation, and then, thanks to the new digital online platforms and channels, let us share our works, spark dialogues and human connections where mind, hearts, souls connect, where new portals open, intertwine and invite all creative explorers to travel together beyond the initial foreseen horizons of our mental maps... We are winged creative beings. Let us set s-Ailes!</p>', 'http://codame.dreamhosters.com/uploaded_images/ailes.gif', '', '', '', '', '0', '1641352971', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/92195615554861820854949255920388613918252966720469255210099015442216651849729', '', '', 'nft'),
