(304, 'Grandma\'s Rules', 'grandma-s-rules', '<p><strong>\"Phangz\" Set Symbol remixed from CODAME branding by Vicente Montelongo</strong>&nbsp;https://www.vicentemontelongo.com/</p>\r\n<p><strong>3d Model</strong>&nbsp;https://sketchfab.com/3d-models/reading-with-grandma-30c32090087f4f1693be6db2e9fdf5f4</p>\r\n<p>**Card Template ** https://mtg.design/</p>', 'http://codame.dreamhosters.com/uploaded_images/grandma-s-rules.jpeg', '', '', '', '', '0', '1623366096', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/64565087924356982539408794320246414468607019910359975833310188527533074415617', '', '', 'nft'),
(305, 'COPYðŸŒˆLEFTðŸŒˆ', 'copy-left', '<p>: : multiply meaning \\ in the fruitful seed season // give the egg freedom</p>', 'http://codame.dreamhosters.com/uploaded_images/copy-left.png', '', '', '', '', '0', '1623366185', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/64565087924356982539408794320246414468607019910359975833310188524234539532289', '', '', 'nft'),
(306, 'Live Events at CODAME ART+TECH Festival 2020ã€Ž JOYNT ã€', 'live-events-at-codame-art-tech-festival-2020-joynt', '<p>10 days of online content including all live and anytime experiences:</p>\r\n<p><a style=\"box-sizing: inherit; background-color: transparent; color: #039be5; -webkit-tap-highlight-color: transparent; text-decoration-line: none; overflow: hidden; text-overflow: ellipsis;\" href=\"/events\" target=\"_blank\">Live Events</a>: Time specific happenings such as performances, meet-the-artist sessions, gallery tours, and community meetings.</p>\r\n<p><a style=\"box-sizing: inherit; background-color: transparent; color: #039be5; -webkit-tap-highlight-color: transparent; text-decoration-line: none; overflow: hidden; text-overflow: ellipsis;\" href=\"/projects\" target=\"_blank\">Anytime Experiences</a>: Interactive art and digital destinations you can browse at your own leisure.</p>\r\n<p><a style=\"box-sizing: inherit; background-color: transparent; color: #039be5; -webkit-tap-highlight-color: transparent; text-decoration-line: none; overflow: hidden; text-overflow: ellipsis;\" href=\"/workshops\" target=\"_blank\">Workshops</a>: 2-3 hour sessions where you\'ll create tangible outcomes. Then stay connected for future inspiration, collaborations, and critiques on the CODAME Discord! You can get tickets to&nbsp;<a style=\"box-sizing: inherit; background-color: transparent; color: #039be5; -webkit-tap-highlight-color: transparent; text-decoration-line: none; overflow: hidden; text-overflow: ellipsis;\" href=\"https://www.tickettailor.com/events/codame\" target=\"_blank\">individual workshops</a>&nbsp;or get an&nbsp;<a style=\"box-sizing: inherit; background-color: transparent; color: #039be5; -webkit-tap-highlight-color: transparent; text-decoration-line: none; overflow: hidden; text-overflow: ellipsis;\" href=\"https://www.tickettailor.com/events/codame/442122/#ticket_selection\" target=\"_blank\">All Access Pass</a>&nbsp;to attend them all!</p>', 'http://codame.dreamhosters.com/uploaded_images/live-events-at-codame-art-tech-festival-2020-joynt.pn', '', '', '', '', '0', '1626320628', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/115057632871220388211095070235813184367894539740535270077387425173923797401601', '', '', 'project'),
