(311, 'The Christmas Saint', 'the-christmas-saint', '<p>he has a list, your name, your family and everybody you know is on it.</p>', 'http://codame.dreamhosters.com/uploaded_images/the-christmas-saint.png', '', '', '', '', '0', '1623366835', 'https://opensea.io/assets/0x495f947276749ce646f68ac8c248420045cb7b5e/33271220540992826225097820539128178648770545811899996650803447163849185165313', '', '', 'nft'),
(312, 'Nexus I - Sprials', 'nexus-i---sprials', '<p>Nexus is a collaborative piece where a machine learning algorithm interprets viewer&rsquo;s inputs and creates images. Each participant submits answers to a short questionnaire, and an abstract personalized image is generated using machine learning labels that correspond to their answers. These labels allow viewers to interact with abstract art in concrete terms and images from users with similar responses to be visually similar. Individual personalized images are combined in one moving piece as a visual way for the participants to interact with another and viewers to witness responses.</p>', 'http://codame.dreamhosters.com/uploaded_images/nexus-i---sprials.gif', '', 'https://www.mintbase.io/thing/Qsmk2CHzfSDauXD_dXfsf_ecI-s-5oynn-1QnyG-wc4:codame.mintbase1.near', 'quinn-keck', '', '0', '1624399765', 'https://www.mintbase.io/thing/dOCJ_U7vHF2eaxaIg0sfi-8enPjeNHAAVDEp5ozY9ug:codame.mintbase1.near', '', '', 'nft'),
(313, 'Copy Planet', 'copy-planet', '<div style=\"color: #222222; font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"font-family: HelveticaNeue; color: #ffffff;\">Copy Planet is an ongoing Virtual Art Project / Module / Playground by Belgian Artist Andy Wauman. It is an explorative \'experimental\' adventure info finding new ways of creating and showing Art.</span></div>\r\n<div style=\"color: #222222; font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"color: #ffffff;\">&nbsp;</span></div>\r\n<div style=\"color: #222222; font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"color: #ffffff;\"><span style=\"font-family: HelveticaNeue;\">The motion piece: &rsquo;Howl Silhouette Of Sound&rsquo; is made in Touch Designer,&nbsp;</span><span style=\"font-family: HelveticaNeue;\">by collaboration with new media artist Pablo Salafurka, who is one of the team members of Copy Planet.&nbsp;</span></span></div>\r\n<div style=\"color: #222222; font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"color: #000000;\">&nbsp;</span></div>\r\n<div style=\"color: #222222; font-family: Arial, Helvetica, sans-serif; font-size: small;\"><span style=\"color: #ffffff;\"><span style=\"font-family: HelveticaNeue;\">Connect on IG:</span><span style=\"font-family: HelveticaNeue;\">&nbsp;@copyplanetdotxyz @andywauman @m_plo_koon&nbsp;</span></span></div>', 'http://codame.dreamhosters.com/uploaded_images/copy-planet.png', 'https://twitter.com/copyplanetdotx1', 'https://linktr.ee/copyplanetdotxyz', 'andy-wauman,pablo-salafurka', '', '0', '1623877038', '', '', '', 'project'),
(314, '', '', '', '', '', '', '', '', '0', '1624216906', NULL, '', '', 'project'),
(315, 'POETIC COSMICITY', 'poetic-cosmicity', '<p><span style=\"font-size: 10pt; font-family: Arial;\" hidden=\"\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">Cosmicity is the state of being a part of a Cosmos- a complex orderly system, an universe. For Greek philosophy there are Order, Harmony, Beauty, therefore there is Poetry. Between virtual, unreal, illusion.</span></p>\r\n<p><span style=\"font-size: 10pt; font-family: Arial;\" hidden=\"\" data-sheets-value=\"{\" data-sheets-userformat=\"{\"><br />INTERACTION</span></p>\r\n<p><span style=\"font-size: 10pt; font-family: Arial;\" hidden=\"\" data-sheets-value=\"{\" data-sheets-userformat=\"{\"><br />This installation allows the user to directly affect the sequence or environment or point of view by their own action thought an hidden interaction - his own look.</span></p>\r\n<p>\"Cosmicity is the state of being a part of a Cosmos- a complex orderly system, an universe. For Greek philosophy there are Order, Harmony, Beauty, therefore there is Poetry. Between virtual, unreal, illusion.</p>\r\n<p>&nbsp;INTERACTION</p>\r\n<p>This installation allows the user to directly affect the sequence or environment or point of view by their own action thought an hidden interaction - his own look\"</p>\r\n<p><span style=\"font-size: 10pt; font-family: Arial;\" hidden=\"\" data-sheets-value=\"{\" data-sheets-userformat=\"{\"><span style=\"font-size: 10pt;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">This VR interactive experimental animation video installation is a piece of art that can be in both spaces virtual and real one.<br />the build can be download <a href=\"https://mega.nz/file/DGRUUahT#fpxNQrXdvoDoEjd4-H9KWKWp5gwb-H1v2frQ7PYzFDM\">here</a>!&nbsp;</span></span></p>', 'http://codame.dreamhosters.com/uploaded_images/poetic-cosmicity.jpg', '', 'https://vimeo.com/286511648', 'anabela-costa', '', '0', '1625531523', 'https://codame.threadless.com/designs/poetic-cosmicity-anabela-costa', '', '', 'project'),
(316, 'Embodying the Algorithm', 'embodying-the-algorithm', '<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">Embodying the Algorithm is a series of performances composed by an artificial intelligence and performed by a group of human artists during COVID-19 quarantine conditions. In these performances, the artists who come from a variety of performance art practices, locations, and identities develop performances written by GPT-3: the largest language model in existence. OpenAI&rsquo;s GPT-3 is capable of composing texts which are difficult to distinguish from human writing. The language model was trained on an enormous dataset of articles, books, blog entries, and texts, many of which were sourced from the internet. As a result, however, GPT-3&rsquo;s text sometimes reflects the statements and ideas of the internet and its human authors including biases, prejudices, and sometimes hateful or toxic output. This has resulted in some controversy around GPT-3 adding to existing ethical concerns about artificial intelligence&rsquo;s increasing presence in our lives.<br /><br />This series of performances touches upon these issues of autonomy and individuality as well as the relationship between technology and the body, authorship and identity, and AI &ldquo;creativity&rdquo; vs. pattern matching or reproduction ultimately asking: what qualifies a work of performance art in consideration of human and non-human actors? What works of performance art might an artificial intelligence (help) generate? What can these performances tell us about ourselves and the human words and texts we immortalize online?</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\"><span style=\"text-decoration-line: underline; font-size: 10pt; text-decoration-skip-ink: none; color: #1155cc;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\" data-sheets-hyperlink=\"http://instagram.com/aiperformancespace\"><a class=\"in-cell-link\" href=\"http://instagram.com/aiperformancespace\" target=\"_blank\">instagram.com/aiperformancespace</a></span></span></p>', 'http://codame.dreamhosters.com/uploaded_images/embodying-the-algorithm.jpg', '', 'https://aiperformance.space/category/performances/', 'mirabelle-jones', '', '0', '1624555487', '', '', '', 'project'),
(317, 'Howl Silhouette Of Sound', 'howl-silhouette-of-sound', '<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">The motion piece &rsquo;Howl Silhouette Of Sound&rsquo; is the result of a collaboration between Artist Andy Wauman and New Media Artist Pablo Salafurka, as a part of the ongoing Virtual Art Project / Module / Playground \'Copy Planet\'. It was made in TouchDesigner.<br /></span></p>', 'http://codame.dreamhosters.com/uploaded_images/howl-silhouette-of-sound.jpg', '', 'http://copyplanet.xyz/', 'andy-wauman,pablo-salafurka', '', '0', '1629675133', '', '', '', 'project'),
(318, 'Chandelier', 'chandelier', '<p><span data-sheets-value=\"{\" data-sheets-userformat=\"{\">Simulated space becomes a human place when we experience it together. By their very nature, immersive environments like &ldquo;Chandelier&rdquo; transport the viewer outside their current narrative into another, in this case a celebration of space, volume, and comparative context. An immersive virtual world spans geographic, national, and ideological boundaries in that it is accessible from anywhere, in any time zone to anyone with the means to visit. In this way &ldquo;Chandelier&rdquo; and other similar immersives invert the relationship between time and space. Travel time is instantaneous, and space is reconfigured to invoke the quality of wonder as the viewer moves through the world. &ldquo;Chandelier&rdquo; is an illumniated telepresent dream space that is made real through sharing the experience together and facilitates a geography that persons separated by great distances might travel through together. What is better than immersion in a new world to provide the space for the visitor to reflect on the old one.</span></p>\r\n<p><iframe style=\"display: block; margin-left: auto; margin-right: auto;\" title=\"YouTube video player\" src=\"https://www.youtube.com/embed/9T58H14TD3g\" width=\"802\" height=\"451\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', 'http://codame.dreamhosters.com/uploaded_images/chandelier.jpeg', '', 'https://www.mintbase.io/thing/VMLWoKWDnjcUXM1er79_AONDL1C0MNzoafImbJW4viw:codame.mintbase1.near', 'dc-spensley', '', '0', '1625944981', 'https://www.mintbase.io/thing/VMLWoKWDnjcUXM1er79_AONDL1C0MNzoafImbJW4viw:codame.mintbase1.nea\\', '', '', 'nft'),
(326, 'Machine of Perceptions', 'machine-of-perceptions', '<p dir=\"ltr\">Machine of Perceptions is a collection of private performances that are photographed and filmed, moments of which are captured, combined, and minted as NFTs. In the ever-shifting realities arising in 2020, audiences no longer need to be in the same time or place as performance, and intimate spaces have become performance halls. The multi-framed moments are combined to create a new experience out of constructs of linear time.</p>\r\n<p dir=\"ltr\">This piece explores the framing of gender, the body, the artist, and performance in the context of our ever-shifting realities. By illuminating the identities projected upon the artist, the piece speaks to the ways society, the patriarchy, and capitalism fabricate identities as fixed absolute truths instead of the artificial social constructions they are. The projected visuals are created from participants in the Nexus project, and by projection of the images on the artist\'s form, the piece engages in a dialogue deconstructing perceptions of the subjective reality we live in.</p>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p dir=\"ltr\">On the blockchain:</p>\r\n<p dir=\"ltr\"><a href=\"https://www.mintbase.io/thing/pb766wu7k4-uTgkDdc2aqnelPS6I1FifvH7sjGkuHO4:codame.mintbase1.near\">Machine of Perceptions 2D</a></p>\r\n<p dir=\"ltr\"><a href=\"https://www.mintbase.io/thing/IQFFELbsvOEljOoCEX5gY91JMsxTwDibKv1DpW6e3iE:codame.mintbase1.near\">Machine of Perceptions 3D</a></p>\r\n<p dir=\"ltr\"><a href=\"https://www.mintbase.io/thing/J5YeOaJ3FF3UvNUs-tIim2QdjU-ZBxsWuAWw9v0OESo:codame.mintbase1.near\">Machine of Perceptions - View I</a></p>\r\n<p>&nbsp;</p>\r\n<p dir=\"ltr\">&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/machine-of-perceptions.png', '', 'https://www.mintbase.io/thing/IQFFELbsvOEljOoCEX5gY91JMsxTwDibKv1DpW6e3iE:codame.mintbase1.near', 'quinn-keck', '', '0', '1624509298', 'https://www.mintbase.io/thing/pb766wu7k4-uTgkDdc2aqnelPS6I1FifvH7sjGkuHO4:codame.mintbase1.near', '', '', 'nft'),
(319, 'Certitude // 162b2', 'certitude-162b2', '<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">This work is essentially a clock. It displays the binary counter the point at which it starts, and the time at which it will reach an encoding of the spike protein in the BioNTech/Pfizer BNT-162b2 vaccine.</span></p>\r\n<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\"><span style=\"font-size: 10pt;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">The work helps to show disconnect between science and reality. Between research and implementation. Between the seeming simplicity that comes from our complex and power hungry technology. Between the our binary and biological worlds.</span></span></p>', 'http://codame.dreamhosters.com/uploaded_images/certitude-162b2.png', '', 'https://www.hicetnunc.xyz/objkt/25122', 'tarwin-stroh-spijer', '', '0', '1624554900', 'https://www.hicetnunc.xyz/objkt/25122', '', '', 'project'),
(329, 'I DONâ€™T KNOW. LOOK AT IT. - III', 'i-don-t-know-look-at-it---iii', '<p>III/X <br /><br /> III is a quiet tempest. <br /><br /> From my &ldquo;I DON&rsquo;T KNOW. LOOK AT IT.&rdquo; gallery show with New Art City. The idea behind the show is based on 2020&rsquo;s current circumstances. We are all stuck in quarantine, and we can&rsquo;t leave our homes. But what if there was a place that&rsquo;s beyond ourselves? A purely digital realm that we can all go too, be in the presence of inter-dimensional creatures, and briefly see outside our current surroundings.</p>', 'http://codame.dreamhosters.com/uploaded_images/i-don-t-know-look-at-it---iii.png', '', 'https://knownorigin.io/gallery/250475-i-don-t-know-look-at-it-iii', 'erica-anderson', '', '0', '1625166543', 'https://knownorigin.io/gallery/250475-i-don-t-know-look-at-it-iii', '', '', 'nft'),
(320, 'TheWall-TheWorld (2020)', 'thewall-theworld-2020', '<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">What if the wall in the West Bank appeared elsewhere -- say, in your backyard?<br /><br />Using GPS, cartography and our rapidly evolving cartographic imagination to visualize the impact of distant events on local ground, this work aims to re-envision, radically alter and reframe of distant geopolitical events in local terms. It is part of a series called \"Shadows from another place.&rdquo;</span></p>\r\n<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">\"TheWall-TheWorld\" is a drone\'s-eye-view of the wall in the West Bank and, at the same time, in Manhattan, Berlin, San Francisco and Bern. This selected segment of the West Bank wall lies just east of Jerusalem, between Abu Dis in the south and Qalandiya in the north.<br /><br />Intially an interactive website (2011-2018), viewers explored the West Bank wall as a split screen, along with any city in the world the viewer chose. Changes in Google Earth\'s platform disabled functionality. This current work features footage from the original, with \"acamar,\" a composition by Frances-Marie Uitti (cellist/composer/performer) and Yota Morimoto (composer).<br /></span></p>\r\n<p><iframe title=\"YouTube video player\" src=\"https://www.youtube.com/embed/HUHUUIHTd4g\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', 'http://codame.dreamhosters.com/uploaded_images/thewall-theworld-2020.jpg', '', 'https://www.youtube.com/watch?v=HUHUUIHTd4g', 'paula-levine', '', '0', '1624555668', '', '', '', 'project'),
(333, 'I DONâ€™T KNOW. LOOK AT IT. - VII', 'i-don-t-know-look-at-it---vii', '<p>VII/X</p>\r\n<p>VII is static charged.</p>\r\n<p>From my &ldquo;I DON&rsquo;T KNOW. LOOK AT IT.&rdquo; gallery show with New Art City. The idea behind the show is based on 2020&rsquo;s current circumstances. We are all stuck in quarantine, and we can&rsquo;t leave our homes. But what if there was a place that&rsquo;s beyond ourselves? A purely digital realm that we can all go too, be in the presence of inter-dimensional creatures, and briefly see outside our current surroundings.</p>', 'http://codame.dreamhosters.com/uploaded_images/i-don-t-know-look-at-it---vii.png', '', 'https://knownorigin.io/gallery/253100-i-don-t-know-look-at-it-vii', 'erica-anderson', '', '0', '1625166930', 'https://knownorigin.io/gallery/253100-i-don-t-know-look-at-it-vii', '', '', 'nft');
INSERT INTO `projects` (`id`, `name`, `slug`, `description`, `pic`, `twitter`, `website`, `artists_array`, `old_url`, `hidden`, `edited`, `shop_url`, `partners_array`, `sponsors_array`, `is_nft`) VALUES
(321, 'Gevurah', 'gevurah', '<div id=\"block-yui_3_17_2_1_1623703188053_5988\" class=\"sqs-block video-block sqs-block-video\" style=\"position: relative; height: auto; padding: 0px 17px 17px; clear: both;\" title=\"\\\" data-block-json=\"{\">\r\n<h2 id=\"block-yui_3_17_2_1_1623703188053_5988\" title=\"\\\" data-block-json=\"{\">WEBXR (VR) HUMAN SWARM INTERACTION SIMULATOR &amp; CYBERNETICS POEM</h2>\r\n<div id=\"block-60c128510c2b63625bd01e8c\" data-block-type=\"2\">\r\n<h1><iframe id=\"yui_3_17_2_1_1625533920627_107\" title=\"Gevurah\" src=\"https://player.vimeo.com/video/424188787?app_id=122963\" width=\"764\" height=\"764\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></h1>\r\n<div id=\"yui_3_17_2_1_1625533920627_96\">Gevurah is a multiplayer vr robotics simulator and cybernetics poem. Players can log in and interact with complex swarms of virtual robots, while hunting for lore (texts) about the virtual world. Gevurah brings together various fields of emerging technology, as well as many poetic ideas about the future of humanity&rsquo;s relationship to data, algorithms and robots, in a compelling, fast-paced vr game format.</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624317156723_465355\" title=\"\\\" data-block-json=\"{\">\r\n<div id=\"yui_3_17_2_1_1625533920627_137\">&nbsp;</div>\r\n<div>\r\n<div><iframe id=\"yui_3_17_2_1_1625533920627_148\" title=\"Demo Full\" src=\"https://player.vimeo.com/video/569056833?app_id=122963\" width=\"761\" height=\"428\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624317156723_484024\" data-block-type=\"2\">\r\n<div>\r\n<h1>MULTI AGENT SYSTEMS ART</h1>\r\n<p>In the field of computer science, there is a subfield called &ldquo;<a href=\"https://en.wikipedia.org/wiki/Multi-agent_system\">multi-agent systems</a>&rdquo;; these are computer programs that simulate &ldquo;superorganisms&rdquo; composed of hundreds (or thousands) of &ldquo;artificial creatures&rdquo; (like in the video below). We often find superorganisms in nature; in an ant colony or bee colony, the intelligence of the entire system is far greater than any individual ant or bee, and the entire system can solve problems that its members can&rsquo;t alone.</p>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623959398265_35447\" class=\"\\\" title=\"\\\" data-block-json=\"{\"><br /><iframe src=\"//www.youtube.com/embed/JmyTJSYw77g?wmode=opaque\" width=\"758\" height=\"426\" frameborder=\"0\" scrolling=\"no\" allowfullscreen=\"allowfullscreen\"></iframe><br /><br />\r\n<div>\r\n<div>Within the computer science sub-field of multi-agent systems, there are two more unique sub-fields (a.) <a href=\"https://www.automate.org/blogs/how-swarm-bots-will-change-the-construction-industry\">swarm based construction</a> and (b.) <a href=\"https://journals.sagepub.com/doi/abs/10.1177/1541931214581307?journalCode=proe#:~:text=Human%2Dswarm%20interaction%20(HSI),humans%20interact%20with%20a%20swarm.\">human swarm interaction</a>. You can think of it again with its natural analogue: (a.) honeybees building a hive or (b.) a human that has trained a flock of crows. In nature, vast complex constructions are built by superorganisms, and we, as humans, often interact with them.</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623271512764_6940\" title=\"\\\" data-block-json=\"{\">\r\n<div id=\"yui_3_17_2_1_1625533920627_217\">&nbsp;</div>\r\n<div>\r\n<div><iframe id=\"yui_3_17_2_1_1625533920627_228\" title=\"swarm urbanism\" src=\"https://player.vimeo.com/video/73988468?app_id=122963\" width=\"779\" height=\"438\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623271512764_7019\" data-block-type=\"2\">\r\n<div>\r\n<h1>SWARM URBANISM</h1>\r\n<p>(a.) Observe <a href=\"https://player.vimeo.com/video/73988468\">this video</a> by Kenichi Kabeya above (particularly minute six on). In this example, a series of agents spread themselves throughout the city, forming a complex hive-like exo-architecture around the current buildings&rsquo; structures. These agents are able to smoothly adapt to local architectural (and geographic) conditions, producing an infinitely varied urban plan (each time this simulation is run), but with an overall stylistic similarity. This idea of &ldquo;swarm urbanism&rdquo; will be explored in great depth in Gevurah.</p>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623271512764_18823\" class=\"\\\" title=\"\\\" data-block-json=\"{\"><br /><br /><iframe src=\"//www.youtube.com/embed/_CpXa8K1BhI?wmode=opaque\" width=\"781\" height=\"439\" frameborder=\"0\" scrolling=\"no\" allowfullscreen=\"allowfullscreen\"></iframe><br />\r\n<div>&nbsp;</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623271512764_18901\" data-block-type=\"2\">\r\n<div>\r\n<h1>HUMAN SWARM INTERACTION</h1>\r\n<p>(b.) Swarms however don&rsquo;t just operate entirely on their own logic; they can be put into dialogue with human behavior. Think of a person standing in front of a building with FPOV goggles and a drone in front of them. Think of that drone flying through the city (or building); that&rsquo;s what&rsquo;s happening in the example above.</p>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623959398265_10398\" class=\"\\\" title=\"\\\" data-block-json=\"{\"><br /><iframe src=\"//www.youtube.com/embed/jU4wsxwM1No?wmode=opaque\" width=\"764\" height=\"429\" frameborder=\"0\" scrolling=\"no\" allowfullscreen=\"allowfullscreen\"></iframe><br />\r\n<div>\r\n<div>&nbsp;</div>\r\n<div>If a pilot is assigned &ldquo;a fleet of drones,&rdquo; they can&rsquo;t possibly control all of them, so the fleet has to have its own navigation logic (this is what&rsquo;s shown in the video above); nonetheless, the pilot still needs to have influence.</div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623959398265_21951\" data-block-type=\"2\">\r\n<p>Ultimately, for working with a flock of drones, there must be a partnership between the human being (&ldquo;pilot&rdquo;) and the superorganism (the &ldquo;drone fleet&rdquo;). This partnership, and its control mechanisms, will be explored at great length in Gevurah.&nbsp;</p>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623701773418_5303\" title=\"\\\" data-block-json=\"{\">\r\n<div>\r\n<div><iframe id=\"yui_3_17_2_1_1625533920627_349\" title=\"Gev_Desk_Cut.mp4\" src=\"https://player.vimeo.com/video/564798456?app_id=122963\" width=\"788\" height=\"443\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623701773418_5379\" data-block-type=\"2\">\r\n<div>\r\n<h1>SWARM URBANISM IN VR</h1>\r\n<p>In the above video clip from Gevurah, architect robots (the long red columns) infinitely construct and destruct the landscape. One column builds lakes. One column builds mountain ranges. One column builds &ldquo;apartment blocks.&rdquo; Three of the columns &ldquo;erase&rdquo; the work of the other robots. There is no predetermined plan to this city. The robots infinitely build it, and tear it apart; it evolves forever.</p>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624995166443_21047\" title=\"\\\" data-block-json=\"{\">\r\n<div id=\"yui_3_17_2_1_1625533920627_377\">&nbsp;</div>\r\n<div>\r\n<div><iframe id=\"yui_3_17_2_1_1625533920627_388\" title=\"Gev Throw.mp4\" src=\"https://player.vimeo.com/video/569056703?app_id=122963\" width=\"788\" height=\"443\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624995166443_21112\" data-block-type=\"2\">\r\n<div>\r\n<h1>HUMAN SWARM INTERACTION IN VR</h1>\r\n<p>When a player logs into Gevurah, they are assigned a fleet of robots. These robots operate by their own swarming algorithm; however, the player can set &ldquo;way-points&rdquo; for the flock, influencing their movement. The player above is &ldquo;throwing&rdquo; the &ldquo;anchor point&rdquo; to a location; then, telling his robot to go to that location.</p>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623701773418_27800\" title=\"\\\" data-block-json=\"{\">\r\n<div>\r\n<div><iframe id=\"yui_3_17_2_1_1625533920627_427\" title=\"Gev_Control_Cut\" src=\"https://player.vimeo.com/video/565871328?app_id=122963\" width=\"786\" height=\"442\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624995166443_17703\" data-block-type=\"2\">\r\n<div>\r\n<p>In the above video, the players &ldquo;calls&rdquo; their flock to them, &ldquo;releases&rdquo; the flock, then jumps into the POV (point of view) of different flock members, while controlling how close or how far away flock members are to each other.&nbsp;</p>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623703633826_17859\" title=\"\\\" data-block-json=\"{\">\r\n<div>\r\n<div><iframe id=\"yui_3_17_2_1_1625533920627_466\" title=\"Gev_Treasure_Cut\" src=\"https://player.vimeo.com/video/565871354?app_id=122963\" width=\"786\" height=\"442\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe>\\</div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1623703633826_17927\" data-block-type=\"2\">\r\n<div>\r\n<h1>GEVURAH&rsquo;S THREE POEMS</h1>\r\n<p>Gevurah contains three poems.</p>\r\n<p>(1.) In the first Gevurah video, above, before the player loads into VR, one can see a text being written in the bottom right hand corner. This text is about about &ldquo;swarms&rdquo; in daily life in Oakland California during 2020, e.g. swarms of crows, Covid-19, political gatherings, etc. It was written over the course of a year during the pandemic, as a kind of cybernetics diary.</p>\r\n<p>(2.) In the second video, you can see text flashing on the architecture robots. Periodically, the architecture robots will pause, allowing the player to see the texts. These texts are about robot consciousness and were written out of experiences with interviewing some of the world&rsquo;s most prominent multi-agent systems scientists.</p>\r\n<p>(3.) The final text is buried throughout the landscape (the black box, in the video above). To see it, the player must hunt for the text with their robot swarm; when the swarm turns blue, it means they have sensed the text and they can direct the player to its location. These hidden texts are about the transformation of human consciousness through its engagement with algorithms, and the resulting construction of &ldquo;a city of information.&rdquo;</p>\r\n<p>Together, these three texts form the &ldquo;lore&rdquo; (or literary backbone) of the Gevurah experience.</p>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1625104426604_18294\" title=\"\\\" data-block-json=\"{\">\r\n<div>\r\n<div><iframe id=\"yui_3_17_2_1_1625533920627_505\" title=\"Babylon.js sample code - Google Chrome 2021-06-30 18-38-32.mp4\" src=\"https://player.vimeo.com/video/569645128?app_id=122963\" width=\"782\" height=\"489\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></div>\r\n</div>\r\n</div>\r\n<div id=\"yui_3_17_2_1_1625533920627_576\">\r\n<div id=\"yui_3_17_2_1_1625533920627_575\">\r\n<div id=\"block-yui_3_17_2_1_1624317156723_40832\" data-block-type=\"5\">\r\n<div id=\"yui_3_17_2_1_1625533920627_574\">\r\n<div id=\"yui_3_17_2_1_1625533920627_573\" data-test=\"image-block-inline-outer-wrapper\">\r\n<figure id=\"yui_3_17_2_1_1625533920627_572\">\r\n<div id=\"yui_3_17_2_1_1625533920627_571\" data-animation-role=\"image\"><img src=\"https://images.squarespace-cdn.com/content/v1/57bfd87bb3db2bdb8923288b/1624317577582-LMICHV2BQNZ5CY935UWF/gev1.PNG?format=1000w\" alt=\"One of the stanzas of the poem&rsquo;s first section\" data-src=\"https://images.squarespace-cdn.com/content/v1/57bfd87bb3db2bdb8923288b/1624317577582-LMICHV2BQNZ5CY935UWF/gev1.PNG\" data-image=\"https://images.squarespace-cdn.com/content/v1/57bfd87bb3db2bdb8923288b/1624317577582-LMICHV2BQNZ5CY935UWF/gev1.PNG\" data-image-dimensions=\"482x85\" data-image-focal-point=\"0.5,0.5\" data-load=\"false\" data-image-id=\"60d11e89970ed564e38c3847\" data-type=\"image\" data-image-resolution=\"1000w\" /></div>\r\n<figcaption>\r\n<div>\r\n<p>One of the stanzas of the poem&rsquo;s first section</p>\r\n</div>\r\n</figcaption></figure>\r\n</div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624317156723_44590\" data-block-type=\"5\">\r\n<div id=\"yui_3_17_2_1_1625533920627_596\">\r\n<div id=\"yui_3_17_2_1_1625533920627_595\" data-test=\"image-block-inline-outer-wrapper\">\r\n<figure id=\"yui_3_17_2_1_1625533920627_594\">\r\n<div id=\"yui_3_17_2_1_1625533920627_593\" data-animation-role=\"image\"><img src=\"https://images.squarespace-cdn.com/content/v1/57bfd87bb3db2bdb8923288b/1624317689879-EMFZGJQRJNG0EQTQ114V/gev2.PNG?format=1000w\" alt=\"One of the stanzas of the poem&rsquo;s third section\" data-src=\"https://images.squarespace-cdn.com/content/v1/57bfd87bb3db2bdb8923288b/1624317689879-EMFZGJQRJNG0EQTQ114V/gev2.PNG\" data-image=\"https://images.squarespace-cdn.com/content/v1/57bfd87bb3db2bdb8923288b/1624317689879-EMFZGJQRJNG0EQTQ114V/gev2.PNG\" data-image-dimensions=\"488x84\" data-image-focal-point=\"0.5,0.5\" data-load=\"false\" data-image-id=\"60d11ef97b326624fd719563\" data-type=\"image\" data-image-resolution=\"1000w\" /></div>\r\n<figcaption>\r\n<div>\r\n<p>One of the stanzas of the poem&rsquo;s third section</p>\r\n</div>\r\n</figcaption></figure>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div id=\"yui_3_17_2_1_1625533920627_614\">\r\n<div id=\"block-yui_3_17_2_1_1623787966970_8604\" data-block-type=\"5\">\r\n<div id=\"yui_3_17_2_1_1625533920627_613\">\r\n<div id=\"yui_3_17_2_1_1625533920627_612\" data-test=\"image-block-inline-outer-wrapper\">\r\n<figure id=\"yui_3_17_2_1_1625533920627_611\">\r\n<div id=\"yui_3_17_2_1_1625533920627_610\" data-animation-role=\"image\"><img src=\"https://images.squarespace-cdn.com/content/v1/57bfd87bb3db2bdb8923288b/1623788018451-RK4ZFD8SAZVC5374L2DC/tomas.PNG?format=1500w\" alt=\"One of the stanzas of the poems&rsquo;s second section\" data-src=\"https://images.squarespace-cdn.com/content/v1/57bfd87bb3db2bdb8923288b/1623788018451-RK4ZFD8SAZVC5374L2DC/tomas.PNG\" data-image=\"https://images.squarespace-cdn.com/content/v1/57bfd87bb3db2bdb8923288b/1623788018451-RK4ZFD8SAZVC5374L2DC/tomas.PNG\" data-image-dimensions=\"655x210\" data-image-focal-point=\"0.5,0.5\" data-load=\"false\" data-image-id=\"60c909f2572261297695fb25\" data-type=\"image\" data-image-resolution=\"1500w\" /></div>\r\n<figcaption>\r\n<div>\r\n<p>One of the stanzas of the poems&rsquo;s second section</p>\r\n</div>\r\n</figcaption></figure>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624317156723_161559\" data-block-type=\"2\">\r\n<div>\r\n<h1>CYBER ALLEGORY</h1>\r\n<p>Ultimately, Gevurah is: (1.) an experience of hunting for lore (texts), (2.) using a complex cybernetic body (player + swarm), (3.) in an infinite machine-built city.</p>\r\n<p>The lore itself addresses: (1.) swarms in &ldquo;real life,&rdquo; (2.) robot &ldquo;consciousness,&rdquo; and (3.) &ldquo;a city of information.&rdquo;</p>\r\n<p>Together, this hybrid work of gamelike literature (or this literary game) speaks directly to our contemporary co-evolving relationship with algorithms and robots.</p>\r\n<p data-rte-preserve-empty=\"true\">&nbsp;</p>\r\n<p data-rte-preserve-empty=\"true\">&nbsp;</p>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624317156723_336074\" data-block-type=\"47\">\r\n<div><hr /></div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624317156723_338141\" data-block-type=\"2\">\r\n<div>\r\n<h3>TECHNICAL NOTES</h3>\r\n<p data-rte-preserve-empty=\"true\">Development log: 66% complete</p>\r\n<p>Gevurah is currently about two thirds complete. Within the next couple of months, the studio would like to finish the basic game-play mechanics and implement a collision system and more complex graphics. Afterwards, it&rsquo;s mostly polishing.</p>\r\n<p>thematic note: themes</p>\r\n<p>The collective text inside of Gevurah is forty pages; in this short description, it&rsquo;s difficult to summarize its themes. Important subthemes include: xenogenderism, swarm-politics, animal-machine-human interaction, algopolitics, transhumanism and jewish mysticism. Some of the texts were written in collaboration with GPT2 (a text-generation algorithm).</p>\r\n<p>framework note: webxr</p>\r\n<p>Gevurah is a VR experience built on <a href=\"https://developer.mozilla.org/en-US/docs/Web/API/WebXR_Device_API\">webxr</a>. Webxr is a new javascript standard for immersive media on the web, accessible via a browser on any device (phone, desktop, headset); all code developed in this project will be released open source.</p>\r\n<p>gameplay note: multiplayer</p>\r\n<p>Gevurah is multiplayer; currently, it mimics (loosely) the multiplayer dynamic from Dark Souls, wherein which players can see the &ldquo;ghostly outline&rdquo; of where other players are in the space. Ultimately, this mostly just delivers the &ldquo;felt presence&rdquo; of other players on the same journey, hunting down the lore of the world.</p>\r\n<p>music note: original soundtrack</p>\r\n<p>Gevurah&rsquo;s soundtrack has been composed by Delta_Ark; it is currently a work in progress. The original playlist below represents some &ldquo;musical sketches&rdquo; in the direction of the soundtrack for the work.</p>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624317156723_303803\" data-block-type=\"23\">\r\n<div><iframe src=\"https://w.soundcloud.com/player/?url=https%3A//api.soundcloud.com/playlists/1245454573&amp;color=%23ff5500&amp;auto_play=false&amp;hide_related=false&amp;show_comments=true&amp;show_user=true&amp;show_reposts=false&amp;show_teaser=true&amp;visual=true\" width=\"100%\" height=\"300\" frameborder=\"no\" scrolling=\"no\"></iframe>\r\n<div><a title=\"Delta_Ark\" href=\"https://soundcloud.com/delta_ark\" target=\"_blank\">Delta_Ark</a>&nbsp;&middot;&nbsp;<a title=\"Music for Gods\" href=\"https://soundcloud.com/delta_ark/sets/music-for-gods\" target=\"_blank\">Music for Gods</a></div>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624317156723_313641\" data-block-type=\"2\">\r\n<div>\r\n<p>graphics note: graphics complexity</p>\r\n<p>Gevurah&rsquo;s graphics are still actively in development. During this stage, where behaviors and mechanics are being focused upon, graphics are deliberately kept simple. In the final game, the graphics may be substantially different. Included below is a &ldquo;materials study&rdquo; of the kinds of complex effects that could possibly make their way into the game.</p>\r\n</div>\r\n</div>\r\n<div id=\"block-yui_3_17_2_1_1624317156723_13281\" title=\"\\\" data-block-json=\"{\">\r\n<div id=\"yui_3_17_2_1_1625533920627_533\">&nbsp;</div>\r\n<div>\r\n<div><iframe id=\"yui_3_17_2_1_1625533920627_544\" title=\"VID_107430219_134117_607\" src=\"https://player.vimeo.com/video/565851676?app_id=122963\" width=\"785\" height=\"442\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></div>\r\n</div>\r\n</div>', 'http://codame.dreamhosters.com/uploaded_images/gevurah.jpg', '', 'http://delta.center/gevurah', 'delta-ark', '', '0', '1625534529', '', '', '', 'project'),
(322, 'Avalanche', 'avalanche', '<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">Working with 3D scanned models and particle simulation effects of the snowfall, Avalanche is a multi-channel 3D moving image work that illustrates the digital imaging version of the concept of &ldquo;entropy&rdquo;, originally from Land Art.</span></p>\r\n<p><span style=\"font-size: 10pt; font-family: Arial;\" translate=\"\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">Working primarily with 3D software in a post-photographic framework, Fu creates scenes of experimental abstraction that translate the concept of liminality into the digital experience. Within the digital avalanche that is created within the piece, the viewers are offered an encounter to reflect on our response to the simultaneously beautiful and overwhelming artifice of the techno-sublime.</span></p>\r\n<p>&nbsp;</p>\r\n<p><iframe src=\"https://player.vimeo.com/video/490064482\" width=\"640\" height=\"360\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p><a href=\"https://vimeo.com/490064482\">Avalanche (one channel dual clips 18min version with sound)</a> from <a href=\"https://vimeo.com/snowfu\">Snow Yunxue Fu</a> on <a href=\"https://vimeo.com\">Vimeo</a>.</p>', 'http://codame.dreamhosters.com/uploaded_images/avalanche.jpg', '', 'https://vimeo.com/490064482', 'snow-yunxue-fu', '', '0', '1624553357', '', '', '', 'project'),
(323, 'Vibration, Obfuscation, Detritus & Inheritance', 'vibration-obfuscation-detritus-inheritance', '<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\" data-sheets-note=\"Responder updated this value.\">Presence, focus, attenuation.<br /><br />What creature sits beside you in the present, that your eye goes crossed looking towards, its blood running through your body, obscured, breaking its own prism? Can you look at yourself and allow seeing detritus, your own detritus and deterioration? Or every moment a glimmering force, a resonant bright strike that shines its echo through the hilt of a gem cosmos? A tree? A cooled river?<br /><br />This piece shows three generations of a human, flittering past each other, looking into themself, the weight of the biology and the matrix of the spirit that underlies super nature.<br /><br />Three layers of video intercut, jittery, my face, my daughter\'s face, her grandfather\'s face in bin-optic camera. We look into the camera, see two parts of myself, captured in the slice of time, the slice of reality.<br /><br />In the edit, a crystalline layer emerges, then a static layer, flattened on a plane.<br /><br />Another similar layer, but the shape of a face<br /><br />Another layer, a deep seated dark root, dark water, drifting, sparkling, crackling, we hear the sound of wood burning and then the sound of water flowing.<br /><br />A piercing multi-spectral light sears outwards, sending chroma through the layers, and the faces re-emerge, jittering, frenetically intercut, then cut together more slowly, then more slowly and the shot holds on the artist\'s face as a ringing frequency rises to presence.<br /></span></p>', 'http://codame.dreamhosters.com/uploaded_images/vibration-obfuscation-detritus-inheritance.jpg', '', '', 'jody-stillwater', '', '0', '1624557207', '', '', '', 'project'),
(334, 'I DONâ€™T KNOW. LOOK AT IT. - VIII', 'i-don-t-know-look-at-it---viii', '<p>VIII/X</p>\r\n<p>VIII is filled with eternal tears.</p>\r\n<p>From my &ldquo;I DON&rsquo;T KNOW. LOOK AT IT.&rdquo; gallery show with New Art City. The idea behind the show is based on 2020&rsquo;s current circumstances. We are all stuck in quarantine, and we can&rsquo;t leave our homes. But what if there was a place that&rsquo;s beyond ourselves? A purely digital realm that we can all go too, be in the presence of inter-dimensional creatures, and briefly see outside our current surroundings.</p>', 'http://codame.dreamhosters.com/uploaded_images/i-don-t-know-look-at-it---viii.png', '', 'https://knownorigin.io/gallery/253675-i-don-t-know-look-at-it-viii', 'erica-anderson', '', '0', '1625166996', 'https://knownorigin.io/gallery/253675-i-don-t-know-look-at-it-viii', '', '', 'nft'),
(335, 'I DONâ€™T KNOW. LOOK AT IT. - IX', 'i-don-t-know-look-at-it---ix', '<p>IX/X</p>\r\n<p>IX strikes down the fear.</p>\r\n<p>From my &ldquo;I DON&rsquo;T KNOW. LOOK AT IT.&rdquo; gallery show with New Art City. The idea behind the show is based on 2020&rsquo;s current circumstances. We are all stuck in quarantine, and we can&rsquo;t leave our homes. But what if there was a place that&rsquo;s beyond ourselves? A purely digital realm that we can all go too, be in the presence of inter-dimensional creatures, and briefly see outside our current surroundings.</p>', 'http://codame.dreamhosters.com/uploaded_images/i-don-t-know-look-at-it---ix.png', '', 'https://knownorigin.io/gallery/254225-i-don-t-know-look-at-it-ix', 'erica-anderson', '', '0', '1625167104', 'https://knownorigin.io/gallery/254225-i-don-t-know-look-at-it-ix', '', '', 'nft'),
(324, 'Dear NostalgiaBot', 'dear-nostalgiabot', '<p style=\"text-align: left;\">Dear NostalgiaBot, who are you, where did you come from, and where are you leading us? Centered around the three questions, this computational audiovisual artwork investigates the relationship between nostalgic contemplation and human connection, through a multi-sensory interactive experience with a robot storyteller NostalgiaBot.</p>\r\n<p style=\"text-align: left;\"><span data-sheets-value=\"{\" data-sheets-userformat=\"{\">We may wonder what the world will be like after the pandemic. Our vision of an ideal future is often associated with technological breakthroughs that resolve most pressing challenges in the world, as the world is often assumed to be progressive. What if our collective history tinted with our personal memories is like a lake of muddy water mingled with a few diamonds? Instead of inventing a solution to the future, can we plunge into the water for these diamonds that may hold the key to a bright future?<br /><br />NostalgiaBot shares its personal journey with us through auditory memories. To produce and share memories with us, it algorithmically picks, fuses, and mixes different everyday sounds stored in its &ldquo;hippocampus&rdquo;, ranging from rainforest thunderstorm to Chinese dragon dance. Tens of thousands of raw audio clips stored in its &ldquo;hippocampus&rdquo; were either uploaded directly by the viewers or crowdsourced from the Internet to echo the viewers&rsquo; social-emotional responses to its memories. Metaphorically, its memories come from other strangers who gently nourished its &ldquo;soul&rdquo; before. They grow if more are willing to share, or decay if without reciprocity.</span></p>\r\n<p><span data-sheets-value=\"{\" data-sheets-userformat=\"{\">NostalgiaBot creates an immersive audiovisual space for our spiritual contemplation on what makes us nostalgic, what memories we cherish the most, and more importantly, how nostalgia can be re-imagined as a homeward journey toward a flourishing future world. As the medium for facilitating our introspective and retrospective contemplation, the robot storyteller NostalgiaBot embodies the community we live in together and bridges individual&rsquo;s interior landscape and our collective identity together through its narrative voice, visual expressions and algorithmically produced auditory memories</span></p>\r\n<p style=\"text-align: center;\"><span data-sheets-value=\"{\" data-sheets-userformat=\"{\"><iframe title=\"YouTube video player\" src=\"https://www.youtube.com/embed/GFPa4HiR4T8\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></span></p>\r\n<p>&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/dear-nostalgiabot.jpg', '', 'https://huilichen25.github.io/Dear-NostalgiaBot-Web/nostalgiaBot-webgl/index.html', 'huili-chen', '', '0', '1629673862', '', '', '', 'project'),
(330, 'I DONâ€™T KNOW. LOOK AT IT. - IV', 'i-don-t-know-look-at-it---iv', '<p>IV/X <br /><br /> IV is a loud whisper. <br /><br /> From my &ldquo;I DON&rsquo;T KNOW. LOOK AT IT.&rdquo; gallery show with New Art City. The idea behind the show is based on 2020&rsquo;s current circumstances. We are all stuck in quarantine, and we can&rsquo;t leave our homes. But what if there was a place that&rsquo;s beyond ourselves? A purely digital realm that we can all go too, be in the presence of inter-dimensional creatures, and briefly see outside our current surroundings.</p>', 'http://codame.dreamhosters.com/uploaded_images/i-don-t-know-look-at-it---iv.png', '', '', 'erica-anderson', '', '0', '1625166617', 'https://knownorigin.io/gallery/251050-i-don-t-know-look-at-it-iv', '', '', 'nft'),
(331, 'I DONâ€™T KNOW. LOOK AT IT. - V', 'i-don-t-know-look-at-it---v', '<p>V/X <br /><br /> V is the ring leader. <br /><br /> From my &ldquo;I DON&rsquo;T KNOW. LOOK AT IT.&rdquo; gallery show with New Art City. The idea behind the show is based on 2020&rsquo;s current circumstances. We are all stuck in quarantine, and we can&rsquo;t leave our homes. But what if there was a place that&rsquo;s beyond ourselves? A purely digital realm that we can all go too, be in the presence of inter-dimensional creatures, and briefly see outside our current surroundings.</p>', 'http://codame.dreamhosters.com/uploaded_images/i-don-t-know-look-at-it---v.png', '', 'https://knownorigin.io/gallery/251600-i-don-t-know-look-at-it-v', 'erica-anderson', '', '0', '1625166714', 'https://knownorigin.io/gallery/251600-i-don-t-know-look-at-it-v', '', '', 'nft'),
(332, 'I DONâ€™T KNOW. LOOK AT IT. - VI', 'i-don-t-know-look-at-it---vi', '<p>VI/X</p>\r\n<p>VI can see your bluff.</p>\r\n<p>From my &ldquo;I DON&rsquo;T KNOW. LOOK AT IT.&rdquo; gallery show with New Art City. The idea behind the show is based on 2020&rsquo;s current circumstances. We are all stuck in quarantine, and we can&rsquo;t leave our homes. But what if there was a place that&rsquo;s beyond ourselves? A purely digital realm that we can all go too, be in the presence of inter-dimensional creatures, and briefly see outside our current surroundings.</p>', 'http://codame.dreamhosters.com/uploaded_images/i-don-t-know-look-at-it---vi.png', '', 'https://knownorigin.io/gallery/252550-i-don-t-know-look-at-it-vi', 'erica-anderson', '', '0', '1625166826', 'https://knownorigin.io/gallery/252550-i-don-t-know-look-at-it-vi', '', '', 'nft'),
(325, 'ia manawa nÅ (at this time)', 'ia-manawa-n-at-this-time', '<p><span style=\"font-size: 10pt; font-family: Arial;\" data-sheets-value=\"{\" data-sheets-userformat=\"{\">ia manawa nÅ (at this time) traces movements of hula remembered and performed in VR, captured as a 3D representation that bridges geographies and a spectrum of time. Hula is timeless - each time it is danced, it conveys a movement of the earth or an elemental force that continues to exist within each dancer as they are re-telling the story of that movement. The tracing of these movements into a form represents something beyond physical and temporal boundaries. At the core of these movements is a reconnection to heritage, origin, and elemental time.</span></p>', 'http://codame.dreamhosters.com/uploaded_images/ia-manawa-n-at-this-time.png', '', 'www.tiareribeaux.com', 'tiare-ribeaux', '', '0', '1624557617', '', '', '', 'project'),
(327, 'I DONâ€™T KNOW. LOOK AT IT. - I', 'i-don-t-know-look-at-it---i', '<p>I/X</p>\r\n<p><br /> I was the first to open the gate.</p>\r\n<p><br /> From my &ldquo;I DON&rsquo;T KNOW. LOOK AT IT.&rdquo; gallery show with New Art City. The idea behind the show is based on 2020&rsquo;s current circumstances. We are all stuck in quarantine, and we can&rsquo;t leave our homes. But what if there was a place that&rsquo;s beyond ourselves? A purely digital realm that we can all go too, be in the presence of inter-dimensional creatures, and briefly see outside our current surroundings.</p>', 'http://codame.dreamhosters.com/uploaded_images/i-don-t-know-look-at-it---i.png', '', 'https://knownorigin.io/gallery/249150-i-don-t-know-look-at-it-i', 'erica-anderson', '', '0', '1625166427', 'https://knownorigin.io/gallery/249150-i-don-t-know-look-at-it-i', '', '', 'nft'),
(328, 'I DONâ€™T KNOW. LOOK AT IT. - II', 'i-don-t-know-look-at-it---ii', '<p>II/X <br /><br /> II is the foundation. <br /><br /> From my &ldquo;I DON&rsquo;T KNOW. LOOK AT IT.&rdquo; gallery show with New Art City. The idea behind the show is based on 2020&rsquo;s current circumstances. We are all stuck in quarantine, and we can&rsquo;t leave our homes. But what if there was a place that&rsquo;s beyond ourselves? A purely digital realm that we can all go too, be in the presence of inter-dimensional creatures, and briefly see outside our current surroundings.</p>', 'http://codame.dreamhosters.com/uploaded_images/i-don-t-know-look-at-it---ii.png', '', 'https://knownorigin.io/gallery/249800-i-don-t-know-look-at-it-ii', 'erica-anderson', '', '0', '1625166404', 'https://knownorigin.io/gallery/249800-i-don-t-know-look-at-it-ii', '', '', 'nft'),
(336, 'I DONâ€™T KNOW. LOOK AT IT. - X', 'i-don-t-know-look-at-it---x', '<p>X/X</p>\r\n<p>X is fully realized.</p>\r\n<p>From my &ldquo;I DON&rsquo;T KNOW. LOOK AT IT.&rdquo; gallery show with New Art City. The idea behind the show is based on 2020&rsquo;s current circumstances. We are all stuck in quarantine, and we can&rsquo;t leave our homes. But what if there was a place that&rsquo;s beyond ourselves? A purely digital realm that we can all go too, be in the presence of inter-dimensional creatures, and briefly see outside our current surroundings.</p>', 'http://codame.dreamhosters.com/uploaded_images/i-don-t-know-look-at-it---x.png', '', 'https://knownorigin.io/gallery/254650-i-don-t-know-look-at-it-x', 'erica-anderson', '', '0', '1625167218', 'https://knownorigin.io/gallery/254650-i-don-t-know-look-at-it-x', '', '', 'nft'),
(337, 'Marker.', 'marker', '<p>A marker to show you how far you&rsquo;ve come.</p>\r\n<p>Originally posted on January 27th, 2021, as part of my daily GIF series, and remastered for KnownOrigin.</p>', 'http://codame.dreamhosters.com/uploaded_images/marker.png', '', 'https://knownorigin.io/gallery/306375-marker', 'erica-anderson', '', '0', '1625167286', 'https://knownorigin.io/gallery/306375-marker', '', '', 'nft'),
(340, 'ART+TECH FESTIVAL 2022 /// Rawthentic', 'art-tech-festival-2022-rawthentic', '<p dir=\"ltr\" style=\"text-align: left;\">The CODAME ART+TECH FESTIVAL 2022 is a multidisciplinary group exhibition and year-long mantra of honest connection &amp; interaction, codenamed this year RAWTHENTIC.</p>\r\n<p dir=\"ltr\" style=\"text-align: left;\">Held all year round with various events and locations,&nbsp;including online,&nbsp;<span id=\"docs-internal-guid-73f5222a-7fff-3879-c672-7558cee95985\">physical experiences</span>, workshops, art+tech hackathons, and performances. The artwork&nbsp;has been&nbsp;showcased in art galleries worldwide online at&nbsp;<a href=\"/admin/gallery.codame.com\">gallery.codame.com</a>. Optionally also available for sale&nbsp;on&nbsp;<a href=\"/admin/shop.codame.com\">shop.codame.com</a>&nbsp;and as NFTs on <a href=\"/nft\">nft.codame.com</a></p>\r\n<p dir=\"ltr\"><strong>/// RAWTHENTIC </strong></p>\r\n<p style=\"padding-left: 30px;\"><em>The mantra of honest connection &amp; interaction.</em></p>\r\n<p dir=\"ltr\" style=\"padding-left: 30px;\">As facades fall away, we can let the true colors of our inner flames shine. Our open call invites artists to present their purest sense of expression in any medium.&nbsp;</p>\r\n<p dir=\"ltr\" style=\"padding-left: 30px;\">By building up each others\' vulnerable, natural desires, we forge sustainable, RAWTHENTIC bonds. Create deep wells of understanding and possibility with a sensitive unmasking of experiences. Join us for a gnarly ride of unfiltered vibes!&nbsp;</p>\r\n<p dir=\"ltr\" style=\"padding-left: 30px;\">Curated by Alissa Christine, CODAME is excited about your transparent exploration of physical and metaphysical realities. What inspiration can your deepest mysteries reveal? Artists of all disciplines and artist levels are encouraged to apply.&nbsp;</p>\r\n<p dir=\"ltr\"><strong>///&nbsp;PROGRAM</strong></p>\r\n<ul>\r\n<li>February 8, 2022</li>\r\n</ul>\r\n<p style=\"padding-left: 60px;\"><a href=\"/events/matchmaking-for-rawthentic-art-tech-build-a-thon\">Matchmaking for Rawthentic&nbsp; ART+TECH Build-A-Thon</a><br />Team Matchmaking for Rawthentic ART+TECH Build-a-Thon</p>\r\n<ul>\r\n<li>February 11-12, 2022</li>\r\n</ul>\r\n<p style=\"padding-left: 60px;\"><a href=\"/events/rawthentic-art-tech-build-a-thon\">Rawthentic ART+TECH Build-A-Thon</a><br />Two-day virtual creative Build-A-Thon event focused on creating art that incorporates communication technology.</p>\r\n<ul>\r\n<li>July 6, 9, 13, 2022</li>\r\n</ul>\r\n<p style=\"padding-left: 60px;\"><a href=\"/events/nft-basics-blastoff\">NFT Basics Blastoff</a><br />Introductory course teaching Artists how to create, buy and sell NFTs with Alissa Christine</p>\r\n<ul>\r\n<li>Summer&nbsp;2022</li>\r\n</ul>\r\n<p style=\"padding-left: 60px;\"><a href=\"/events/rawthentic-at-mars-landing-galleries\">RAWTHENTIC at Mars Landing Galleries</a><br />2D, 3D, interactive, immersive, augmented reality (AR) virtual reality (VR) works.</p>\r\n<p><iframe title=\"YouTube video player\" src=\"https://www.youtube.com/embed/bOELE1h8ass?controls=0\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p dir=\"ltr\"><strong>/// STAY IN TOUCH</strong></p>\r\n<p dir=\"ltr\" style=\"padding-left: 30px;\">Here are some ways to stay in touch with us:</p>\r\n<p style=\"padding-left: 30px;\"><a href=\"https://codame.substack.com/\" target=\"_blank\">Sign-up</a>&nbsp;for our newsletter&nbsp;to be notified about&nbsp;our new events or initiatives, call for artists, and project proposals</p>\r\n<p style=\"padding-left: 30px;\"><a href=\"mailto:team@codame.com\">Contact us</a>&nbsp;for any inquiries&nbsp;or just to say hi!</p>\r\n<p style=\"padding-left: 30px;\">Social Media:</p>\r\n<p style=\"padding-left: 30px;\"><a href=\"https://www.facebook.com/CODAME.ART.TECH\" target=\"_blank\">Facebook</a>,&nbsp;<a href=\"/admin/twittter.com/codame\" target=\"_blank\">Twitter</a>,&nbsp;<a href=\"https://codame.substack.com/\" target=\"_blank\">Substack</a>,&nbsp;<a href=\"https://www.instagram.com/codame/\" target=\"_blank\">Instagram</a>,&nbsp;<a href=\"https://www.youtube.com/channel/UC-xKBSgGX4xfLS7-O3w9xBQ\">Youtube</a>,&nbsp;<a href=\"https://medium.com/codame-art-tech\">Medium</a>,&nbsp;<a href=\"https://www.linkedin.com/company/codame\">LinkedIn</a>,&nbsp;<a href=\"https://github.com/codame\">GitHub</a>,&nbsp;<a href=\"https://discord.com/invite/pk3C8DB\">Discord</a>&nbsp;&amp;&nbsp;<a href=\"http://codame.tumblr.com/\" target=\"_blank\">Tumblr</a></p>\r\n<p style=\"padding-left: 30px;\">&nbsp;</p>\r\n<p><strong>/// VOLUNTEERS</strong></p>\r\n<p style=\"padding-left: 30px;\">It&rsquo;s a fun and extremely rewarding experience as you learn new skills and pass your knowledge on to others. You&rsquo;ll meet like-minded people, make friends&nbsp;and build a network of people from all backgrounds who share a common passion for ART+TECH.</p>\r\n<p style=\"padding-left: 30px;\"><a href=\"/pages/call-for-volunteers\">Apply</a>&nbsp;to be part of the magic! We&rsquo;re looking for outstanding volunteers&nbsp;to support our ART+TECH initiatives.</p>\r\n<p style=\"padding-left: 30px;\">&nbsp;</p>\r\n<p><strong>///&nbsp;SPONSORS</strong></p>\r\n<p style=\"padding-left: 30px;\">Join our list of amazing&nbsp;<a href=\"/sponsors\">Sponsors</a>. Be recognized as an innovative and visionary organization, <a href=\"/pages/support-art-tech\">Contact us</a>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>&nbsp;///&nbsp;DONATIONS</strong></p>\r\n<p style=\"padding-left: 30px;\">We&nbsp;appreciate your support for ART&hearts;TECH</p>\r\n<p style=\"padding-left: 30px;\">CODAME is a member of Intersection for the Arts, a nonprofit 501(c)(3)&nbsp;organization.</p>\r\n<p style=\"padding-left: 30px;\">All proceeds will be split with the participating artists.&nbsp;<a href=\"https://www.flipcause.com/secure/cause_pdetails/NjU0OA==\">Donations</a>&nbsp;are always welcome.</p>\r\n<p style=\"padding-left: 30px;\"><a href=\"/pages/support-art-tech\">Contact us</a>&nbsp;if you are interested in making an in-kind donation.</p>\r\n<p>&nbsp;<img src=\"/uploaded_images/join-us2.png\" alt=\"\" width=\"767\" height=\"269\" /></p>\r\n<p>---</p>\r\n<p>Credits&nbsp;Flyer background&nbsp;art courtesy <a href=\"/artists/char-stiles\">Char Stiles</a></p>\r\n<p><a href=\"http://codame.com/pages/code-of-conduct\">Code of Conduct</a>&nbsp;for all attendees.</p>\r\n<p dir=\"ltr\">&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/art-tech-festival-2022-rawthentic.png', '', '', 'char-stiles,camille-baker,serge-bulat,blinkpopshift,arki,tim-thompson,sandrine-deumier,anabela-costa,moe-angelo,kuan-ju-wu,judit-navratil,grant-patterson,alissa-christine,snow-yunxue-fu,tiffany-trenda', '', '0', '1687190636', '', 'newart-city,near-protocol', 'twilio', 'project'),
(341, 'The Program', 'the-program', '<p>The Program, was conceived of, written, and produced during the COVID case spike in early 2021, which led to renewed quarantine policies across much of the US. The show was performed entirely over the phone: audience members called in to an automated line and were led down a telephonic wormhole into an absurd version of a corporate phone tree. Audience members called it &ldquo;the most unexpected 45 minutes of the last year,&rdquo; and &ldquo;the kind of connection-making, heart-growing theater the world needs.&rdquo;</p>\r\n<p>Founded by Amy Langer (she/her) and Ezra Reaves (they/them),&nbsp;Tarot &amp; Palm Theatre&nbsp;creates new performance work that challenges traditional modes of storytelling by pulling apart theatrical conventions to its base elements. We believe that theatre is fundamentally defined by moments of communion between the audience and performers, and so we embrace work that eschews the &ldquo;fourth wall&rdquo; present in much contemporary theatre.<span style=\"caret-color: #000000; font-family: Helvetica; font-size: 12px; text-size-adjust: auto;\"><br style=\"text-size-adjust: auto;\" /></span></p>', 'http://codame.dreamhosters.com/uploaded_images/the-program.jpg', '', 'https://www.tarotandpalmtheatre.com/', 'ezra-reaves,amy-langer', '', '0', '1643432997', '', '', '', 'project'),
(342, 'Cat Calls', 'cat-calls', '<p style=\"text-align: center;\">1st Prize winners of the&nbsp;<a href=\"/events/rawthentic-art-tech-build-a-thon\">Rawthentic&nbsp;ART+TECH Build-A-Thon</a></p>\r\n<p>An interactive yarn bombing escape room with a SMS component. 9 cat-themed yarn bombs in the physical world, including hashtag links to Instagram with more puzzle parts that combine to form a grand puzzle.</p>\r\n<p><iframe style=\"background-image: url(\'/admin/img/object.gif\');\" src=\"https://docs.google.com/presentation/d/e/2PACX-1vT5rFEIJCwW45Gs6DJMhUqrIlQ2Owxia_Bqlc5FUkDQ1_Nb4WjGvw6lhvgiQ7nwZqkeAZnoeHDSnY3r/embed?start=true&amp;loop=true&amp;delayms=3000\" width=\"960\" height=\"569\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/cat-calls.jpg', '', '', 'knits-for-life', '', '0', '1645408130', '', '', '', 'project'),
(343, 'My Circulatory System', 'my-circulatory-system', '<p style=\"text-align: center;\">2nd&nbsp;Prize winner (tie) of the&nbsp;<a href=\"/events/rawthentic-art-tech-build-a-thon\">Rawthentic&nbsp;ART+TECH Build-A-Thon</a></p>\r\n<p>My Circulatory System is a generative series of NFTs created by the biometry of the artist Lina Lopes. A wearable device in the earlobe can measure oxygen levels, visualizing the connections and capillaries of the human body.&nbsp;</p>\r\n<p><img src=\"/uploaded_images/images(s).gif\" alt=\"\" /></p>\r\n<p><img src=\"/uploaded_images/IMG_0841s.JPG\" alt=\"\" /><img src=\"/uploaded_images/IMG_0842s.JPG\" alt=\"\" /><img src=\"/uploaded_images/IMG_0844s.JPG\" alt=\"\" /></p>', 'http://codame.dreamhosters.com/uploaded_images/my-circulatory-system.gif', '', '', 'lina-lopes', '', '0', '1645585495', '', '', '', 'project'),
(344, 'Hola Oily', 'hola-oily', '<p style=\"text-align: center;\"><em><a href=\"/events/rawthentic-art-tech-build-a-thon\">Rawthentic&nbsp;ART+TECH Build-A-Thon</a></em></p>\r\n<p style=\"text-align: center;\"><em>2nd&nbsp;Prize winner (tie)</em></p>\r\n<p style=\"text-align: left;\">A first person quest that takes sci-fi elements and merged them with non-fiction to make a hybrid. So you are communicating with a being, or perhaps an oil spill, named Oily. This multi-media experience uses narrative, generated sound,&nbsp;and images to evoke climate grief and self-reflection.</p>', 'http://codame.dreamhosters.com/uploaded_images/hola-oily.gif', '', 'https://oilancestors.com/', 'fereshteh-toosi,joshua-reeves,illest-preacha', '', '0', '1645462947', '', '', '', 'project'),
(345, 'Matrix', 'matrix', '<p>A familiar code rain graphics demo. There are so many rubbish Matrix screensavers, Jeremy Sachs (aka&nbsp;Rezmason)&nbsp;wanted to do it right. Read the repo&rsquo;s readme file for more information. Two fun details: my knowledge of signed distance fields from Scourge (see below) was a big help, and&nbsp;he rebuilt the matrix font in Illustrator that some digital agency partially left&nbsp;in an old SWF&nbsp;by mistake.</p>\r\n<p>Jeremy has been featured at&nbsp;CODAME&nbsp;using Matrix by remixing the scans as part of&nbsp;<a href=\"/projects/modbod-3d\">modbod-3d</a>&nbsp;project.</p>\r\n<p>In 2020&nbsp;Jeremy migrated the project to&nbsp;regl, a functional WebGL wrapper that\'s a better fit for graphic effects like this one.</p>\r\n<p>In 2021, in anticipation of the latest installment in the movie franchise, Jeremy added a \"3D mode\", along with an expanded font painstakingly recovered from promotional material. I also migrated the project once again, to&nbsp;WebGPU, the web\'s next low-level graphics and GPU compute API.</p>\r\n<p>Additionally, Jeremy got my hands on a&nbsp;Looking Glass Portrait and worked out how to display this effect holographically, ie. by rendering the effect from multiple vantage points simultaneously.</p>\r\n<p>You can check the code on&nbsp;<a href=\"https://github.com/Rezmason/matrix\">https://github.com/Rezmason/matrix</a></p>\r\n<p>This project was&nbsp;<a href=\"https://www.vice.com/en/article/88qvn3/coder-makes-matrix-green-rain-simulator-that-lilly-wachowski-says-is-better-than-the-original\" rel=\"nofollow\">featured in Vice Motherboard</a>, along with insight into the effect from Lilly Wachowski.</p>\r\n<p style=\"text-align: center;\"><iframe title=\"Holographic Matrix code rain\" src=\"https://www.youtube.com/embed/gwA9hfq1Ing\" width=\"441\" height=\"784\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', 'http://codame.dreamhosters.com/uploaded_images/matrix.gif', '', 'https://rezmason.github.io/matrix/', 'jeremy-sachs', '', '0', '1669602919', NULL, '', '', 'project'),
(346, 'ART+TECH Newsletter', 'art-tech-newsletter', '<p>For 10+ years CODAME has promoted inspiring experiences to connect artists, collectors, curators, and organizations. Our newsletter connects a global network of ART+TECH enthusiasts with contemporary curation of the most relevant projects, events, and calls for participation. Subscribe and submit your announcement below.</p>\r\n<h1 style=\"text-align: center;\">Subscribe</h1>\r\n<p><iframe style=\"border: 1px solid #EEE; background: white;\" src=\"https://codame.substack.com/embed\" width=\"480\" height=\"320\" frameborder=\"0\" scrolling=\"no\"></iframe></p>\r\n<h1 style=\"text-align: center;\">Submit</h1>\r\n<p><iframe src=\"https://docs.google.com/forms/d/e/1FAIpQLSe0QABl6sEQJLDDwSRWzDwlgahURSYi_4ejA3T9RVAaIz0enA/viewform?embedded=true\" width=\"580\" height=\"1589\" frameborder=\"0\" marginwidth=\"0\" marginheight=\"0\">Loading…</iframe></p>\r\n<p>&nbsp;</p>\r\n<div style=\"box-sizing: border-box; color: #ffffff; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; background-color: #000000;\">&nbsp;</div>\r\n<h2>CODE OF CONDUCT&nbsp;</h2>\r\n<div>CODAME&nbsp;<a href=\"/pages/code-of-conduct\">Code of Conduct</a> for all participants and attendees.</div>', 'http://codame.dreamhosters.com/uploaded_images/art-tech-newsletter.jpg', 'https://twitter.com/codame', 'https://codame.substack.com/subscribe', 'jordan-gray,bruno-fonzi', '', '0', '1677177653', '', '', '', 'project');
INSERT INTO `projects` (`id`, `name`, `slug`, `description`, `pic`, `twitter`, `website`, `artists_array`, `old_url`, `hidden`, `edited`, `shop_url`, `partners_array`, `sponsors_array`, `is_nft`) VALUES
(347, 'Harry Styles - Watermelon Sugar (AI)', 'harry-styles---watermelon-sugar-ai', '<div>\r\n<div><span dir=\"ltr\">Christian Nielsen&nbsp;w</span><span dir=\"ltr\">orked on getting the&nbsp;AI to transform everyone into Harry Styles and add more watermelon,&nbsp;and&nbsp;we like it!</span></div>\r\n</div>\r\n<p><iframe title=\"YouTube video player\" src=\"https://www.youtube.com/embed/4tpJ3u_-fbE\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<div>\r\n<p>When the world was starved for human contact in the early days of the pandemic, Harry Styles dropped the \"Watermelon Sugar\" music video with a cheeky message: \"This video is dedicated to touching.\"</p>\r\n<p>Released on 18 May 2020, directed by Bradley &amp; Pablo and filmed in&nbsp;Malibu, California, it features Styles alongside&nbsp;</p>\r\n<p>The video oozes the song\'s warm, seductive, and playful vibe. Styles is surrounded by a plethora of people on the beach, surrounded by enough watermelon to feed a small army.</p>\r\n<p>Despite the video\'s saucy undertones, the intimacy between Styles and the actors held a special place in our hearts in 2020. The hand-holding, hair-stroking, and strawberry-feeding depicted in the video became the stuff of dreams for those starved for physical affection during the quarantine era. Styles\' original video served up a delicious, juicy taste of these longed-for sensations, reminding us all of the sheer joy of human touch during a time when it was most scarce.</p>\r\n<p>If you have not seen the original video, check it out!</p>\r\n</div>\r\n<p><iframe title=\"YouTube video player\" src=\"https://www.youtube.com/embed/E07s5ZYygMg\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>It\'s not the first time an Artist used AI to recreate Harry Styles\' &lsquo;Watermelon Sugar&rsquo; music video, and we can\'t wait to see more!</p>\r\n<p>Andr&eacute; R&ouml;hrig&nbsp;used&nbsp;AI&nbsp;to recreate Styles&rsquo; song using footage from&nbsp;the&nbsp;<a href=\"https://www.reaganfoundation.org/library-museum/\" target=\"_blank\">Reagan Presidential Library</a>.</p>\r\n<p>R&ouml;hrig said he got the idea for the project when he noticed that AI and machine learning often fail in interesting ways. Artist&nbsp;<a href=\"https://twitter.com/quasimondo?ref_src=twsrc%5Egoogle%7Ctwcamp%5Eserp%7Ctwgr%5Eauthor\" target=\"_blank\">Mario Klingemann</a>&nbsp;is also an inspiration, he said</p>\r\n<p><iframe title=\"YouTube video player\" src=\"https://www.youtube.com/embed/YESTcUCl6pc\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\r\n<p>The original music videos for both&nbsp;Watermelon Sugar&nbsp;and&nbsp;Video Games&nbsp;are nostalgia trips that copy the aesthetic style of the 1960s. According to&nbsp;Andr&eacute; R&ouml;hrig, this was important to help his AI&mdash;he designed and trained himself&mdash;understand how to make its music video.&nbsp;</p>\r\n<div data-component=\"BodyComponentRenderer\">\r\n<p>&ldquo;There are certain parameters like hard cuts and short scenes that are important for the process not to fail,&rdquo; he said. &ldquo;And the video footage the AI tries to replicate must be represented to a certain extent within the distribution of the archival footage. Otherwise, the results are not very satisfying. This is the case for these retro style videos I\'ve used here; the \'real\' Lana Del Rey video even uses lots of archival footage.&rdquo;</p>\r\n<p>According to R&ouml;hrig, creating the AI took about two weeks. Why the Reagan Library, though? After all, there are plenty of other sources of workable video, including the libraries of other American presidents. R&ouml;hrig said that it produced the best results.&nbsp;</p>\r\n<p>&ldquo;Initially, I was looking for footage in the public domain for practical reasons, so the videos don\'t get blocked because of copyright claims,&rdquo; he said. &ldquo;This is the case for these public domain presidential video collections. I\'ve tried other collections (Trump, Obama) and also other sources like old educational films produced by the U.S. Government. Still, I\'ve had the best results with the Reagan Library footage. The more recent presidential videos have much better production videos and more editing. In contrast, the Reagan videos are often just someone filming random people at campaign rallies for hours, which is great for a diverse data set vs. just lots of shots of the president.&rdquo;</p>\r\n<p>Other videos on R&ouml;hrig&rsquo;s channel show an AI trained to make abstract art using a&nbsp;Generative Adversarial Network&nbsp;(GAN), a common technique for&nbsp;creating artificial images.</p>\r\n<p>&ldquo;This animation of abstract images was created by an AI that was trained without any training data,&rdquo;<a href=\"https://www.youtube.com/watch?v=xXpSXJeZvCk\" target=\"_blank\">&nbsp;</a>R&ouml;hrig&nbsp;said&nbsp;in the video&rsquo;s description. &ldquo;Instead, an adversarial training process of different deep convolutional neural networks against each other was used to create \'pure\' abstract visuals.</p>\r\n<p><span data-component=\"TextBlock\">You read more about it on&nbsp;<a href=\"https://www.vice.com/en/article/4ad8ew/artist-uses-ai-to-recreate-watermelon-sugar-music-video-using-footage-of-ronald-reagan\">Vice Motherboard</a>,&nbsp;written by&nbsp;</span>Matthew Gault on February 17, 2021</p>\r\n<p>&nbsp;</p>\r\n<div>&nbsp;</div>\r\n</div>', 'http://codame.dreamhosters.com/uploaded_images/harry-styles---watermelon-sugar-ai.jpg', '', '', 'christian-nielsen,mario-klingemann,andre-roehrig', '', '0', '1679718837', '', '', '', 'project'),
(348, 'Sonic Runway', 'sonic-runway', '<p>Created by a team of artists, including lead artist Rob Jensen, and co-lead Warren Trezevant, and designed by Stockhausen, Sonic Runway is a light-art installation that visualizes the speed of sound. Live audio input is converted into intricate light patterns that beam through a corridor of 25 arches, stretching 432 feet at the speed of sound so that sound and lights are synchronized.</p>\r\n<p>In addition to providing an engaging experience for City Hall Plaza visitors, Sonic Runway will again serve as a canvas for arts and events such as live and recorded musical performances, fashion shows, video and photography, and will appear in countless selfies.</p>\r\n<blockquote>\r\n<p>&ldquo;Walking down the Sonic runway, you build a connection with all the other people and revel in this amazing shared experience. Wherever the Sonic Runway is installed, people call it the tunnel of smiles, because everyone&rsquo;s enjoying themselves so much.\"&nbsp;<span style=\"outline: 0px; box-sizing: border-box;\">&ndash; Rob &amp; Warren</span></p>\r\n</blockquote>\r\n<p>As part of the new version, the artist team has developed new state-of-the-art sound-responsive light patterns. It will regularly update the lighting and sound programming, enabling ongoing new experiences for the public to enjoy. The new design includes a professional quality sound system, increasing its attractiveness to multidisciplinary artists and the general public. The new design features audio inputs at both ends of the runway, enabling artists to plug in at either end and trigger the light patterns with their music in both directions. The City of San Jose Office of Economic Development and Cultural Affairs will produce activation events throughout Sonic Runway&rsquo;s installation at City Hall to showcase local creative talent and offer a unique art experience for artists and audiences.</p>', 'http://codame.dreamhosters.com/uploaded_images/sonic-runway.jpg', '', 'https://www.sanjose.org/events/sonic-runway', 'rob-jensen,warren-trezevant', '', '0', '1682368928', '', 'san-jose-cultural-affairs', '', 'project'),
(349, 'Ascension of the Builders', 'ascension-of-the-builders', '<p style=\"text-align: center;\">Artwork #3 in the dreamsynth series</p>\r\n<p>Their city consumed by flames of a dying star. The Builders looked back in reminiscent grace, their memories decaying. As the solar conflagration returned their blood to the dust beneath the streets, a curious force swept through their physical bodies, separating flesh and consciousness from their souls.</p>\r\n<p>Reborn as spheres of plasma energy, those who built the ancient city from sinew and steel begin to ascend. The mechatropolis receding quickly below them, their memories erased, The Ascended begin on their forever upward path toward new understandings of the oldest knowledge.</p>\r\n<p>An interactive musical instrument. Click the unmute button to hear the sound and play the instrument. Variations include the colors of the sculpture (single palette is rare) and the background music tracks (most are more ambient, but in rare cases, you will get more lively percussion and beats).</p>\r\n<p style=\"text-align: center;\">Medium: interactive generative musical instrument</p>\r\n<p style=\"text-align: center;\">Price: 20 TEZ</p>\r\n<p style=\"text-align: center;\">Edition: 4/20</p>', 'http://codame.dreamhosters.com/uploaded_images/ascension-of-the-builders.png', '', '', 'odbol', '', '0', '1683694320', '', '', '', 'nft'),
(350, 'Harvester - nightfall 1', 'harvester---nightfall-1', '<p>Science fiction themes offer an outlet for internal fears and trauma by projecting them onto infinite possible realities. In this piece, an unstoppable and unconscious harvester machine cuts deep scars in the planet beneath. It\'s night, and its work is silent and solitary. This is destruction, and yet also nature.</p>\r\n<p>Medium: Procedural 3D Animation</p>\r\n<p>Price:&nbsp;76&nbsp;TEZ</p>\r\n<p>Editions: 5</p>\r\n<p>&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/harvester---nightfall-1.jpg', '', '', 'synwrks', '', '0', '1683697007', 'https://objkt.com/asset/hicetnunc/571684', '', '', 'nft'),
(351, 'Sonata N.1', 'sonata-n-1', '<p>The first in a series of collages depicting the realms of The Wheel Of Samsara. The allegorical themes contained within The Wheel give guidance to decision making on all levels of existence from the mundane to the deep, spiritual struggles of life. The approach to collage and animation is intentionally naive, and by openly naming the source of the imagery for the collage, a playful subtext has been added to the motif.</p>\r\n<p>&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/sonata-n-1.jpg', '', '', 'plutonicmind', '', '0', '1683697417', 'https://knownorigin.io/gallery/13347000-the-wheel-of-samsara-i', '', '', 'project'),
(352, 'My heart is fueled by Trash', 'my-heart-is-fueled-by-trash', '<p>4 the Love of Trashart&nbsp;&nbsp;</p>\r\n<p>Medium: Blender 3D Animation</p>\r\n<p>Price: .2 ETH</p>\r\n<p>Edition: 1/1</p>\r\n<p>&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/my-heart-is-fueled-by-trash.jpg', '', '', 'marcotic', '', '0', '1683698434', 'https://rarible.com/token/0xb6ad7493979a54f8b4d015f6e007aad0a5435bd1:7?tab=details', '', '', 'project'),
(353, 'optimism_rebirthed', 'optimism-rebirthed', '<p>Abstract composition reflecting on the difficulties of life and the sadness that can overwhelm so easily &gt;&gt; but also a tribute to those who, out of spite, choose to face tomorrow with optimism.</p>\r\n<p>The artwork was birthed while contemplating sad news shared by a persevering friend. the skies at the time seemed to portray my inner emotions with their foreboding feel. i captured them as digital photographs and manipulated them into 2d abstract works, but they felt incomplete. eventually, i started experimenting with them in a 3d context and arrived at two final compositions, one reflecting the sadness, one reflecting an enduring optimism despite the circumstances. the async.art platform was chosen due to it&rsquo;s programmable nature allowing the states to cycle as our emotions and attitudes so often do.</p>\r\n<p>Medium: Digital + Programmable Art</p>\r\n<p>Price: 0.77 ETH</p>\r\n<p>Edition: 1/1</p>', 'http://codame.dreamhosters.com/uploaded_images/optimism-rebirthed.jpeg', '', '', 'ejthek', '', '0', '1683698789', '', '', '', 'project'),
(354, ' Forest Nymph #1', 'forest-nymph-1', '<p>The Appalachian mountains and forests have a spirit. They are among the oldest mountains in the world, and you can sense a presence when you walk in the woods away from civilization. Every season brings a different feeling to the hills and hollows. In early spring, for example, there is a sense of joy, excitement, and anticipation. The woods begin to dance with the promise of new life. YOU are invited to the dance as well. This series was created in the darkroom by hand and printed on Ilford warm-tone paper. This digital image is 2281 x 1489 pixels.</p>\r\n<p>Medium: Photography</p>\r\n<p>Price: 20 TEZ</p>\r\n<p>Editions: 20</p>\r\n<p>&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/forest-nymph-1.png', '', '', 'skip-rohde', '', '0', '1683699285', ' https://objkt.com/asset/KT1S9aZgWKAfZ8ZmR1DJk32Q5FaqvdohP8PB/2', '', '', 'project'),
(355, 'Moving Masses #023', 'moving-masses-023', '<p>Nothing is static, everything is spinning and moving. Light and darkness changing without leaving the space. Nothing is lost. What kind of Masses are making you move?</p>\r\n<p>Medium: MP4 1920 x 1080 px</p>', 'http://codame.dreamhosters.com/uploaded_images/moving-masses-023.jpg', '', '', 'rui-zilh-o', '', '0', '1683699706', '', '', '', 'project'),
(356, 'The Wheel Of Samsara', 'the-wheel-of-samsara', '<p>The first in a series of collages depicting the realms of The Wheel Of Samsara. The allegorical themes within The Wheel guide decision making on all levels of existence, from the mundane to the deep, spiritual struggles of life. The approach to collage and animation is intentionally naive, and by openly naming the source of the imagery for the collage, a playful subtext has been added to the motif.</p>\r\n<p>&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/the-wheel-of-samsara.gif', '', '', 'strayltd', '', '0', '1683700052', 'https://knownorigin.io/gallery/13347000-the-wheel-of-samsara-i', '', '', 'project'),
(357, 'Searching for Roots', 'searching-for-roots', '<p>Perhaps only a few things can leave you more vulnerable, presenting you the opportunity to be more honest with yourself than writing a poem and publishing it for the world to read. It opens the door to the depths of your soul and exposes yourself to perhaps not being understood.But it is also an act of liberation, where the chains are transformed into verses. \"Searching for roots\" is an immersive artwork that uses augmented reality to bring the spectator on a journey through the painting, revealing a lot more than the eyes can see.&nbsp;</p>\r\n<p>This piece 1 of 1 was created using as inspiration the poem in Spanish called \"Sirio\" where the author deals with the loss of guidance and the search for meaning.</p>\r\n<p>To experience the immersive dimension of the artwork, install the \"Artivive\" app on your phone and scan the main image.</p>\r\n<p>This is the \"opera prima\" of the author in the NFT world, and it belongs to a broader collection of immersive art based on poems called \"La Invocaci&oacute;n de los Ef&iacute;meros\", or</p>\r\n<p>The Summoning of the Ephemera, by Edison Duran Lucena, conformed by 21 poems and created in Ann Arbor, Michigan, while the author was studying for its Ph.D. in Astronomy and Astrophysics. This NFT includes the poem\'s page signed by the author.</p>\r\n<p>Medium: AI, Digital Painting, Poetry + Animation (AR)</p>\r\n<p>Price: .5 ETH&nbsp;</p>\r\n<p>Edition: 1/1</p>\r\n<p>AR: Download Artivive App. Scan image to see it come to life.<br />&nbsp;</p>\r\n<p>AR Canvas Print:&nbsp;20&rdquo;x20&rdquo; also available at Mars Landing Galleries: $400 (Edition: A/P)</p>\r\n<p>&nbsp;</p>', 'http://codame.dreamhosters.com/uploaded_images/searching-for-roots.png', '', '', 'edison-duran-lucena', '', '0', '1683700189', NULL, '', '', 'project'),
(358, 'Jakodi\'s Soothing Flight', 'jakodi-s-soothing-flight', '<p>Jakodi is an Earth Spirit (the name Jakodi is gaelic meaning \"descendant of the helpful one\"). Jakodi represents a magical, spiritual connection to nature and our world.</p>\r\n<p>Medium: Illustration + Animation (AR)</p>\r\n<p>Price: .35 ETH</p>\r\n<p>Edition: 1/1</p>\r\n<p>AR: Download Artivive App. Scan image to see it come to life.</p>\r\n<p>NFT link:&nbsp;</p>\r\n<p>AR Canvas Print: 20 x 15&rdquo; also available at Mars Landing Galleries: $400 (Edition: A/P)</p>', 'http://codame.dreamhosters.com/uploaded_images/jakodi-s-soothing-flight.jpg', '', '', 'daryl-slaton', '', '0', '1683700568', '', '', '', 'project'),
(359, 'Mazu (Liu Yifei)', 'mazu-liu-yifei', '<p>&ldquo;Sof&iacute;a y La Ninfaaa&rdquo;, es una exhibici&oacute;n f&iacute;sica y virtual realizada por Sofia Maldonado-Su&aacute;rez, curada por Abdiel Segarra en Espacio C&oacute;mplices, Madrid (2022). Esta primera colecci&oacute;n de NFTs se puede encontrar en el metaverso de OVER App, en la tierra digital, usando esta direcci&oacute;n: wallace.hayward.topic&nbsp;&nbsp;&nbsp;</p>\r\n<p>La propuesta ha sido creada en colaboraci&oacute;n con Norelys Rumbos (programadora) y Crysta Dominguez (social media strategist).</p>\r\n<p>Cada dibujo representa un ser mitol&oacute;gico representado por una figura pop: Atabey (Ivy Queen), Hecate (Megan Fox), Futakuchi-Onna (Rihanna), Mama Watta (Cardi B) y Mazu (Liu Yifei)</p>\r\n<p>Medium: Digital Painting + Photography</p>\r\n<p>Price: 3.33 ETH</p>\r\n<p>Edition: 1/1</p>', 'http://codame.dreamhosters.com/uploaded_images/mazu-liu-yifei.png', '', '', 'sof-a-maldonado', '', '0', '1683700726', 'https://foundation.app/@laninfaaa/ninfa22/6', '', '', 'nft'),
(360, 'DrumPants', 'drumpants', '<p>DrumPants are a wearable set of pants and gloves that enable the wearer to produce drum sounds by hitting various parts of the pants with his hands. The wearer thusly becomes a cyborg musician, his body assuming the roles of both player and instrument, allowing for spontaneous electric hambone solos or even collaborations with other musicians in a band setting.</p>\r\n<p><iframe src=\"https://www.youtube.com/embed/K0Luov_Sf1s\" width=\"793\" height=\"446\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>', 'http://codame.dreamhosters.com/uploaded_images/drumpants.gif', '', 'https://igg.me/at/drumpants/x#/', 'odbol', '', '0', '1683737386', '', '', '', 'project'),
(361, '#minacoding', 'minacoding', '<p>If you liked&nbsp;<a href=\"https://twitter.com/hashtag/genuary?src=hashtag_click\" target=\"_blank\" rel=\"noopener noreferrer nofollow\">#genuary</a>&nbsp;your should try&nbsp;<a href=\"https://twitter.com/hashtag/minacoding?src=hashtag_click\" target=\"_blank\" rel=\"noopener noreferrer nofollow\">#minacoding</a>, a super wholesome creative coding challenge for the month of June. Check out the&nbsp;<a href=\"https://twitter.com/ginzi_o/status/1661509012997935104\" target=\"_blank\" rel=\"noopener noreferrer nofollow\">prompts for daily inspiration</a>!</p>\r\n<p>Credits: OYASUMI by @imSunny55</p>\r\n<p>As announced in the <a href=\"/pages/art-tech-news---june-8th-2023\">ART+TECH News</a> on June 8th, 2023</p>\r\n<p style=\"box-sizing: border-box; color: #ffffff; font-family: Asap, helvetica, arial, sans-serif; font-size: 15px; background-color: #000000; text-align: center;\"><iframe style=\"box-sizing: border-box; max-width: 100%; width: 650px; min-height: 160px; border-style: solid; border-color: #eeeeee; background-image: initial; background-position: initial; background-repeat: initial; background-color: white;\" src=\"https://codame.substack.com/embed\" width=\"480\" height=\"320\" frameborder=\"0\" scrolling=\"no\"></iframe></p>', 'http://codame.dreamhosters.com/uploaded_images/art-tech-news---june-9th-2023.gif', 'https://twitter.com/hashtag/minacoding?src=hashtag_click', '', '', '', '0', '1686802064', '', '', '', 'project');
